# ========================================
# TRANSCRIPCIÓN FONÉTICA IPA (ESPAÑOL)
# ========================================
#
# Convierte texto ortográfico español a una secuencia de fonemas IPA con
# pesos de duración relativos basados en duraciones típicas del español.
#
# Devuelve data.frame con columnas:
#   phone  : símbolo IPA
#   peso   : duración relativa (vocal media = 1.0)
#   sonoro : TRUE si el fonema es sonoro (tiene F0 en contexto normal)
# ========================================
texto_a_ipa_es <- function(texto, variedad = "neutro") {
  # variedad "peninsular" → /θ/ para <c/z>; cualquier otro → /s/
  theta <- if (identical(variedad, "peninsular")) "\u03b8" else "s"

  # Tabla de pesos de duración (ms normalizados, vocal media = 1.00)
  # Fuente: Quilis (1981), Garrido (2010), Face & Prieto (2007) + estimaciones
  PESOS <- c(
    "a"=1.00, "e"=1.00, "i"=0.90, "o"=1.00, "u"=0.90,   # vocales
    "j"=0.45, "w"=0.45,                                    # semiconsonantes
    "\u03b2"=0.60, "\u00f0"=0.55, "\u0263"=0.55,          # fricativas sonoras (β ð ɣ)
    "\u027e"=0.25, "r"=0.90,                               # vibrante simple/múltiple
    "m"=0.75, "n"=0.70, "\u0272"=0.80, "\u014b"=0.70,    # nasales (m n ɲ ŋ)
    "l"=0.75, "\u028e"=0.85,                               # laterales (l ʎ)
    "f"=0.90, "s"=0.95, "x"=0.80, "\u03b8"=0.85,         # fricativas sordas
    "t\u0283"=0.95,                                        # africada (tʃ)
    "p"=0.70, "t"=0.70, "k"=0.75,                        # oclusivas sordas
    "b"=0.65, "d"=0.65, "g"=0.70                          # oclusivas sonoras
  )

  # Sonoridad: TRUE → el fonema es sonoro (tiene F0 en articulación normal)
  SONORO <- c(
    "a"=T,"e"=T,"i"=T,"o"=T,"u"=T,
    "j"=T,"w"=T,
    "\u03b2"=T,"\u00f0"=T,"\u0263"=T,
    "\u027e"=T,"r"=T,
    "m"=T,"n"=T,"\u0272"=T,"\u014b"=T,
    "l"=T,"\u028e"=T,
    "f"=F,"s"=F,"x"=F,"\u03b8"=F,
    "t\u0283"=F,
    "p"=F,"t"=F,"k"=F,
    "b"=T,"d"=T,"g"=T
  )

  txt <- tolower(trimws(as.character(texto)))
  # Normalización de acentos para lógica contextual
  txt_n <- chartr("\u00e1\u00e9\u00ed\u00f3\u00fa\u00fc", "aeiouu", txt)
  n <- nchar(txt_n)
  if (n == 0) return(data.frame(phone=character(0), peso=numeric(0), sonoro=logical(0),
                                stringsAsFactors=FALSE))

  phones <- character(0)
  pesos  <- numeric(0)
  sonoros <- logical(0)

  add <- function(p) {
    phones  <<- c(phones,  p)
    pesos   <<- c(pesos,   if (p %in% names(PESOS))  PESOS[p]  else 0.70)
    sonoros <<- c(sonoros, if (p %in% names(SONORO)) SONORO[p] else TRUE)
  }

  char_at <- function(pos) if (pos >= 1L && pos <= n) substr(txt_n, pos, pos) else ""
  char_orig_at <- function(pos) if (pos >= 1L && pos <= n) substr(txt, pos, pos) else ""
  is_voc   <- function(c) c %in% c("a","e","i","o","u")

  i <- 1L
  while (i <= n) {
    c1 <- char_at(i)
    c2 <- char_at(i + 1L)
    c3 <- char_at(i + 2L)
    co <- char_orig_at(i)   # original (con tilde para vocales acentuadas)
    prev <- char_at(i - 1L)

    # Ignorar no-letras y espacios
    if (!grepl("[a-z\u00e1\u00e9\u00ed\u00f3\u00fa\u00fc\u00f1]", c1, perl=TRUE)) {
      i <- i + 1L; next
    }

    # ── Díg rafos (procesar primero) ─────────────────────────────────────
    if (c1=="c" && c2=="h") { add("t\u0283"); i <- i+2L; next }
    if (c1=="l" && c2=="l") { add("\u028e");  i <- i+2L; next }
    if (c1=="r" && c2=="r") { add("r");       i <- i+2L; next }
    # <gu> + e/i → /g/ (la u es muda)
    if (c1=="g" && c2=="u" && c3 %in% c("e","i")) { add("g"); i <- i+3L; next }
    # <gü> + e/i → /gw/ (diéresis: u suena)
    if (char_orig_at(i)=="g" && char_orig_at(i+1L)=="\u00fc") {
      add("g"); add("w"); i <- i+2L; next
    }
    # <qu> + e/i → /k/
    if (c1=="q" && c2=="u" && c3 %in% c("e","i")) { add("k"); i <- i+3L; next }
    # <qu> + a/o (raro pero existe: quórum)
    if (c1=="q" && c2=="u") { add("k"); add("w"); i <- i+2L; next }

    # ── Caracteres individuales ──────────────────────────────────────────
    if (c1 %in% c("a","e","i","o","u")) {
      add(c1)
    } else if (co %in% c("\u00e1","\u00e9","\u00ed","\u00f3","\u00fa","\u00fa")) {
      # Vocal acentuada → misma vocal sin tilde
      add(c1)   # c1 ya es la versión normalizada
    } else if (c1 == "b" || c1 == "v") {
      if (is_voc(prev) && is_voc(c2)) add("\u03b2") else add("b")
    } else if (c1 == "c") {
      if (c2 %in% c("e","i")) add(theta) else add("k")
    } else if (c1 == "d") {
      if (is_voc(prev) && is_voc(c2)) add("\u00f0") else add("d")
    } else if (c1 == "f") {
      add("f")
    } else if (c1 == "g") {
      if (c2 %in% c("e","i")) {
        add("x")
      } else if (is_voc(prev) && is_voc(c2)) {
        add("\u0263")
      } else {
        add("g")
      }
    } else if (c1 == "h") {
      # <h> es muda en español; excepción: <ch> ya procesado arriba
    } else if (c1 == "j") {
      add("x")
    } else if (c1 == "k") {
      add("k")
    } else if (c1 == "l") {
      add("l")
    } else if (c1 == "m") {
      # Asimilación ante velar
      if (c2 %in% c("k","g","x","c","q")) add("\u014b") else add("m")
    } else if (c1 == "n") {
      if (c2 %in% c("k","g","x","c","q","j")) add("\u014b") else add("n")
    } else if (c1 == "\u00f1") {
      add("\u0272")
    } else if (c1 == "p") {
      add("p")
    } else if (c1 == "r") {
      # /r/ vibrante múltiple: inicio de palabra, tras n/l/s, o inicio de sílaba tónica
      if (i == 1L || prev %in% c("n","l","s")) add("r") else add("\u027e")
    } else if (c1 == "s") {
      add("s")
    } else if (c1 == "t") {
      add("t")
    } else if (c1 == "w") {
      add("w")
    } else if (c1 == "x") {
      # <x> intervocálica → /ks/; inicial → /s/ (variedad general)
      if (is_voc(prev) && is_voc(c2)) { add("k"); add("s") } else add("s")
    } else if (c1 == "y") {
      if (is_voc(c2)) add("j") else add("i")
    } else if (c1 == "z") {
      add(theta)
    }
    i <- i + 1L
  }

  data.frame(phone=phones, peso=pesos, sonoro=sonoros, stringsAsFactors=FALSE)
}

# ========================================
# EXTRACCIÓN DE F0 E INTENSIDAD EN R NATIVO
# (seewave + tuneR, intentando replicar Praat)
# ========================================
#
# La intensidad sigue la fórmula de Praat:
#   I(t) = 10 · log₁₀(mean(x²_ventana) / p₀²)
# donde p₀ = 2×10⁻⁵ Pa (umbral de audición) y la señal se normaliza
# a escala 1.0 = valor máximo del entero PCM (convención Praat).
# La ventana es Hanning de longitud ≈ 3.2 / pitch_floor segundos.
#
# El F0 se extrae con autocorrelación (seewave::autoc) con parámetros
# equivalentes a los de Praat: ventana ≈ 6.4/pitch_floor, umbral 0.45.
# ========================================
extraer_f0_int_r_nativo <- function(wav_path,
                                     pitch_floor    = 75,
                                     pitch_ceiling  = 500,
                                     time_step      = 0.01,
                                     intensity_min_pitch = 100) {
  if (!requireNamespace("tuneR",   quietly = TRUE)) stop("Instala el paquete 'tuneR'")
  if (!requireNamespace("seewave", quietly = TRUE)) stop("Instala el paquete 'seewave'")

  wav <- tuneR::readWave(wav_path)
  sr  <- wav@samp.rate
  bit <- wav@bit

  # Señal mono normalizada a [-1, 1]  (misma convención que Praat)
  x_int <- if (wav@stereo) (wav@left + wav@right) / 2L else wav@left
  x     <- as.numeric(x_int) / (2^(bit - 1L))

  dur_total <- length(x) / sr

  # ── F0 por autocorrelación (seewave::autoc) ──────────────────────────────
  # Ventana ≈ 6.4/pitch_floor (Praat usa este tamaño para la autocorrelación)
  wl_f0 <- 2L^ceiling(log2(6.4 / pitch_floor * sr))   # potencia de 2 más cercana
  wl_f0 <- max(wl_f0, 128L)
  # Solapamiento para conseguir el paso temporal deseado
  ovlp_f0 <- max(0L, min(99L, round(100L * (1 - time_step / (wl_f0 / sr)))))

  f0_mat <- tryCatch(
    seewave::autoc(wav,
                   wl        = wl_f0,
                   fmin      = pitch_floor,
                   fmax      = pitch_ceiling,
                   threshold = 45L,       # equivalente al 0.45 de Praat
                   ovlp      = ovlp_f0,
                   plot      = FALSE),
    error = function(e) NULL
  )

  pitch_df <- if (!is.null(f0_mat) && is.matrix(f0_mat) && ncol(f0_mat) >= 2L) {
    df <- data.frame(tiempo = f0_mat[, 1L], f0 = f0_mat[, 2L],
                     stringsAsFactors = FALSE)
    df[!is.na(df$f0) & df$f0 > 0, ]
  } else {
    data.frame(tiempo = numeric(0), f0 = numeric(0))
  }

  # ── Intensidad (réplica de la fórmula Praat) ─────────────────────────────
  # Ventana Hanning de longitud 3.2 / intensity_min_pitch (segundos)
  win_dur  <- 3.2 / intensity_min_pitch
  win_len  <- max(round(win_dur * sr), 32L)
  step_len <- max(round(time_step * sr), 1L)
  n        <- length(x)
  p0_sq    <- 4e-10   # p₀² = (2×10⁻⁵)²

  # Ventana Hanning normalizada (Praat normaliza para que ∫w²dt sea constante)
  hann     <- 0.5 - 0.5 * cos(2 * pi * seq(0L, win_len - 1L) / (win_len - 1L))
  hann_sq  <- sum(hann^2)

  starts   <- seq(1L, max(1L, n - win_len + 1L), by = step_len)
  int_vals <- vapply(starts, function(s) {
    seg <- x[s:min(s + win_len - 1L, n)]
    if (length(seg) < win_len)
      seg <- c(seg, rep(0, win_len - length(seg)))
    pw <- sum((seg * hann)^2) / hann_sq   # potencia media ponderada
    if (pw > 0) 10 * log10(pw / p0_sq) else NA_real_
  }, numeric(1L))

  int_df <- data.frame(
    tiempo     = (starts + win_len / 2L - 1L) / sr,
    intensidad = int_vals,
    stringsAsFactors = FALSE
  )
  int_df <- int_df[!is.na(int_df$intensidad), ]

  list(pitch = pitch_df, intensidad = int_df, duracion = dur_total)
}

