vocales <- "aeiouáéíóúàèìòùäëïöüAEIOUÁÉÍÓËÀÈÌÑÙÄËÏÖÜ"
vocales_con_acento_esp <- "áéíóúÁÉÍÓÚ"
vocales_con_acento_cat <- "àèéíòóúÀÈÉÍÒÓÚ"
vocales_con_acento_fra <- "àâéèêëîïôùûüÀÂÉÈÊËÎÏÔÙÛÜ"  # en francés los acentos no marcan posición tónica
vocales_con_acento_ita <- "àèéìíòóùúÀÈÉÌÍÒÓÙÚ"
vocales_con_acento_por <- "áàâãéêíóôõúÁÀÂÃÉÊÍÓÔÕÚ"
vocales_con_acento_deu <- ""  # el alemán no usa acentos gráficos para el acento léxico
vocales_con_acento_eng <- ""  # el inglés no usa acentos gráficos
vocales_con_acento_zho <- ""  # el chino usa diacríticos de tono, no de acento léxico

# ── Corrección automática de semitones (ref=1 en lugar de ref=100) ──────────────
# Offset exacto: 12*log2(100) ≈79.726 St
# Columnas con Hz equivalente -> recalculo exacto desde Hz
# Columnas sin Hz (f0_inicio_st, f0_fin_st, f0_pico_st, f0_media_grupo_st) -> suma del offset
# f0_rango_st es una diferencia -> el offset se cancela -> no se corrige
.ST_OFFSET <- 12 * log2(100)

corregir_semitones_si_necesario <- function(df) {
  if (nrow(df) == 0) return(df)
  all_st_cols <- grep("_st$", colnames(df), value = TRUE)
  if (length(all_st_cols) == 0) return(df)
  
  # Detectar valores negativos en columnas de F0 absoluta
  detector_cols <- intersect(c("f0_media_st", "f0_max_st", "f0_media_grupo_st",
                                "f0_inicio_st", "f0_fin_st", "f0_pico_st"), colnames(df))
  if (length(detector_cols) == 0) return(df)
  tiene_negativos <- any(sapply(detector_cols, function(col) any(df[[col]] < 0, na.rm = TRUE)))
  if (!tiene_negativos) return(df)
  
  # Grupo 1: con Hz equivalente -> recalcular exacto
  hz_map <- c(f0_media_st = "f0_media_hz", f0_max_st = "f0_max_hz", f0_min_st = "f0_min_hz")
  for (col_st in names(hz_map)) {
    col_hz <- hz_map[[col_st]]
    if (col_st %in% colnames(df) && col_hz %in% colnames(df)) {
      df[[col_st]] <- ifelse(is.na(df[[col_hz]]) | df[[col_hz]] <= 0, NA_real_,
                             12 * log2(df[[col_hz]] / 1))
    }
  }
  
  # Grupo 2: sin Hz equivalente -> aplicar offset (f0_rango_st excluido: es diferencia)
  offset_cols <- intersect(
    c("f0_inicio_st", "f0_fin_st", "f0_pico_st", "f0_media_grupo_st",
      grep("^q[1-4]_f0_(media|max|min)_st$", colnames(df), value = TRUE)),
    colnames(df)
  )
  for (col in offset_cols) {
    df[[col]] <- ifelse(is.na(df[[col]]), NA_real_, df[[col]] + .ST_OFFSET)
  }
  
  # Usar message() aquí (función global) — log_event vive en el server
  message("[ST_CORREGIDO] Corregidas: ",
    paste(c(intersect(names(hz_map), colnames(df)), offset_cols), collapse = ", "))
  if (exists("log_event", mode = "function")) {
    log_event("ST_CORREGIDO", paste0("Corregidas: ",
      paste(c(intersect(names(hz_map), colnames(df)), offset_cols), collapse = ", ")))
  }
  df
}

# ── Normalización de etiquetas de emoción acústica (emotion2vec) ───────────────
# emotion2vec+ devuelve etiquetas bilingües tipo "开心/happy". Los caracteres CJK
# provocan un segfault de textshaping/ragg (crash total de R) al dibujarse en
# cualquier plot (fallback de fuente en macOS), así que se conserva solo la parte
# inglesa tras la barra y se purga cualquier carácter fuera de Latin-1 residual.
normalizar_emocion_audio <- function(x) {
  if (is.null(x) || !is.character(x) || length(x) == 0) return(x)
  con_barra <- !is.na(x) & grepl("/", x, fixed = TRUE)
  x[con_barra] <- sub("^.*/", "", x[con_barra])
  limpio <- ifelse(is.na(x), NA_character_,
                   trimws(gsub("[^\\x{01}-\\x{FF}]", "", x, perl = TRUE)))
  # Si la etiqueta era 100% CJK (sin parte inglesa), no dejar cadena vacía
  ifelse(!is.na(x) & nzchar(x) & !nzchar(limpio), "unknown", limpio)
}

limpiar_emociones_cjk <- function(df) {
  if (is.data.frame(df) && "emocion_audio" %in% colnames(df))
    df$emocion_audio <- normalizar_emocion_audio(df$emocion_audio)
  df
}

es_vocal <- function(etiqueta) {
  if (is.na(etiqueta) || nchar(etiqueta) == 0) return(FALSE)
  primer_char <- substr(etiqueta, 1, 1)
  grepl(primer_char, vocales, fixed = TRUE)
}

es_vocal_vec <- function(etiquetas) {
  sapply(etiquetas, es_vocal, USE.NAMES = FALSE)
}

tiene_acento_grafico <- function(vocal, idioma) {
  tabla_acentos <- list(
    "Español"   = vocales_con_acento_esp,
    "Catalán"   = vocales_con_acento_cat,
    "Francés"   = vocales_con_acento_fra,
    "Italiano"  = vocales_con_acento_ita,
    "Portugués" = vocales_con_acento_por,
    "Alemán"    = vocales_con_acento_deu,
    "Inglés"    = vocales_con_acento_eng,
    "Chino"     = vocales_con_acento_zho
  )
  ref <- tabla_acentos[[idioma]]
  if (is.null(ref) || nchar(ref) == 0) return(FALSE)
  grepl(vocal, ref, fixed = TRUE)
}

quitar_acentos <- function(palabra) {
  resultado <- palabra
  resultado <- gsub("[áÁ]", "a", resultado)
  resultado <- gsub("[éÉ]", "e", resultado)
  resultado <- gsub("[íÍ]", "i", resultado)
  resultado <- gsub("[óÓ]", "o", resultado)
  resultado <- gsub("[úËüÜ]", "u", resultado)
  resultado <- gsub("[àÀ]", "a", resultado)
  resultado <- gsub("[èÈ]", "e", resultado)
  resultado <- gsub("[òÑ]", "o", resultado)
  resultado <- gsub("[ïÏ]", "i", resultado)
  return(resultado)
}

hz_to_semitones <- function(hz, ref = 1) {
  ifelse(is.na(hz) | hz <= 0, NA_real_, 12 * log2(hz / ref))
}

