palabras_atonas_zho <- c()  # el chino no tiene esta distinción morfológica

es_palabra_atona <- function(palabra, idioma = "Español") {
  if (is.na(palabra) || nchar(palabra) == 0) return(TRUE)
  palabra_lower <- tolower(palabra)
  lista <- switch(idioma,
    "Español"   = palabras_atonas_esp,
    "Catalán"   = palabras_atonas_cat,
    "Francés"   = palabras_atonas_fra,
    "Italiano"  = palabras_atonas_ita,
    "Portugués" = palabras_atonas_por,
    "Alemán"    = palabras_atonas_deu,
    "Inglés"    = palabras_atonas_eng,
    "Chino"     = palabras_atonas_zho,
    palabras_atonas_esp  # fallback
  )
  return(palabra_lower %in% lista)
}

determinar_acentuacion <- function(palabra, idioma = "Español") {
  if (is.na(palabra) || nchar(palabra) == 0) {
    return(list(tipo = "átona", posicion_tonica = 0))
  }
  if (es_palabra_atona(palabra, idioma)) {
    return(list(tipo = "átona", posicion_tonica = 0))
  }

  chars <- strsplit(palabra, "")[[1]]
  num_vocales <- sum(sapply(chars, function(c) grepl(c, vocales, fixed = TRUE)))

  if (num_vocales == 0) {
    return(list(tipo = "átona", posicion_tonica = 0))
  }

  # ── Chino: lengua tonal, cada sílaba es una unidad tónica ────────────────
  if (idioma == "Chino") {
    return(list(tipo = "aguda", posicion_tonica = 1))
  }

  # ── Francés: el acento recae siempre en la última sílaba del grupo rítmico;
  #    los acentos gráficos son ortográficos, no prosódicos ─────────────────
  if (idioma == "Francés") {
    return(list(tipo = "aguda", posicion_tonica = 1))
  }

  # ── Alemán e inglés: sin marcas gráficas de acento, regla por defecto ────
  if (idioma %in% c("Alemán", "Inglés")) {
    # Default: llana (penúltima sílaba), salvo monosílabos (aguda)
    tipo <- if (num_vocales == 1) "aguda" else "llana"
    posicion_tonica <- if (num_vocales == 1) 1L else 2L
    return(list(tipo = tipo, posicion_tonica = posicion_tonica))
  }

  # ── Español, Catalán, Italiano, Portugués: buscar acento gráfico ─────────
  tiene_acento <- FALSE
  posicion_acento <- 0
  vocal_count <- 0

  for (i in length(chars):1) {
    char <- chars[i]
    if (grepl(char, vocales, fixed = TRUE)) {
      vocal_count <- vocal_count + 1
      if (tiene_acento_grafico(char, idioma)) {
        tiene_acento <- TRUE
        posicion_acento <- vocal_count
        break
      }
    }
  }

  if (tiene_acento) {
    tipo <- if (posicion_acento == 1) "aguda"
            else if (posicion_acento == 2) "llana"
            else "esdrújula"
    return(list(tipo = tipo, posicion_tonica = posicion_acento))
  }

  # ── Regla por defecto según idioma cuando no hay acento gráfico ──────────
  palabra_sin_acento <- quitar_acentos(palabra)
  ultima_letra <- tolower(substr(palabra_sin_acento, nchar(palabra_sin_acento), nchar(palabra_sin_acento)))

  if (idioma %in% c("Español", "Catalán", "Portugués")) {
    # Llana si termina en vocal, n o s; aguda en el resto
    if (grepl(ultima_letra, "aeiou") || ultima_letra == "n" || ultima_letra == "s") {
      tipo <- "llana"; posicion_tonica <- 2L
    } else {
      tipo <- "aguda"; posicion_tonica <- 1L
    }
  } else if (idioma == "Italiano") {
    # Italiano: la mayoría son llanas (piano); las agudas llevan acento obligatorio
    tipo <- "llana"; posicion_tonica <- 2L
  } else {
    tipo <- "llana"; posicion_tonica <- 2L
  }

  posicion_tonica <- min(posicion_tonica, num_vocales)
  return(list(tipo = tipo, posicion_tonica = posicion_tonica))
}

# Funciones de normalización
normalizar_base100_primera <- function(valores) {
  primer_valor_valido <- valores[!is.na(valores)][1]
  if (is.na(primer_valor_valido) || primer_valor_valido == 0) return(rep(NA, length(valores)))
  return((valores / primer_valor_valido) * 100)
}

normalizar_base100_media <- function(valores, media_referencia) {
  if (is.na(media_referencia) || media_referencia == 0) return(rep(NA, length(valores)))
  return((valores / media_referencia) * 100)
}

normalizar_zscore <- function(valores) {
  media <- mean(valores, na.rm = TRUE)
  sd_val <- sd(valores, na.rm = TRUE)
  if (is.na(sd_val) || sd_val == 0) return(rep(0, length(valores)))
  return((valores - media) / sd_val)
}

normalizar_minmax <- function(valores) {
  min_val <- min(valores, na.rm = TRUE)
  max_val <- max(valores, na.rm = TRUE)
  if (is.na(min_val) || is.na(max_val) || min_val == max_val) return(rep(50, length(valores)))
  return(((valores - min_val) / (max_val - min_val)) * 100)
}

relativizar_tiempo_en_grupo <- function(tiempos, tiempo_inicio_grupo, tiempo_fin_grupo) {
  duracion_grupo <- tiempo_fin_grupo - tiempo_inicio_grupo
  if (duracion_grupo <= 0) return(rep(50, length(tiempos)))
  return(((tiempos - tiempo_inicio_grupo) / duracion_grupo) * 100)
}

# ========================================

# ========================================
# calcular_metricas_dt — versión vectorizada con foverlaps()
# Elimina el bucle for(i in 1:n) y los ~75.000 subsettings individuales.
# Estrategia:
#   1. foverlaps() une pitch_dt / intensity_dt con los intervalos de tier_dt de una vez
#   2. Agregación por vocal_id en una sola pasada
#   3. Interpolación de vecinos: roll join de data.table (O(log n) por vocal)
#   4. Cuartiles: expandir intervalos x4, misma foverlaps
# ========================================
calcular_metricas_dt <- function(tier_dt, pitch_dt, intensity_dt,
                                  filtrar_f0_outliers = FALSE,
                                  outlier_mad_k       = 3.0) {

  n <- nrow(tier_dt)
  if (n == 0) return(tier_dt)

  step_actual <- "inicio"
  tryCatch({

  # ── Preallocar columnas de salida ─────────────────────────────────────────
  cols_f0  <- c("f0_media_hz","f0_max_hz","f0_min_hz","f0_rango_hz",
                "f0_media_st","f0_max_st","f0_min_st","rango_f0_st")
  cols_int <- c("int_media","int_max","int_min","int_rango")
  for (col in c(cols_f0, cols_int)) tier_dt[, (col) := NA_real_]
  for (q in 1:4) {
    for (sfx in c("f0_media_hz","f0_max_hz","f0_min_hz","f0_rango_hz",
                  "f0_media_st","f0_max_st","f0_min_st","f0_rango_st",
                  "int_media","int_max","int_min","int_rango")) {
      tier_dt[, (paste0("q",q,"_",sfx)) := NA_real_]
    }
  }
  for (sfx in c("dif_q1_q2_st","dif_q1_q2_pct","dif_q2_q3_st","dif_q2_q3_pct",
                "dif_q3_q4_st","dif_q3_q4_pct","dif_q1_q4_st","dif_q1_q4_pct")) {
    tier_dt[, (sfx) := NA_real_]
  }

  # Índice de vocal para poder reagregar tras el join
  step_actual <- "vocal_id"
  tier_dt[, vocal_id := .I]

  # ── Preparar pitch_dt ─────────────────────────────────────────────────────
  # foverlaps requiere que el "query" tenga [start, end] y la "reference" también
  pd <- copy(pitch_dt)[!is.na(f0) & f0 > 0]
  pd[, t_end := tiempo]                    # intervalo puntual [tiempo, tiempo]
  setkey(pd, tiempo, t_end)

  # ── Helper vectorizado: foverlaps join + agregación ───────────────────────
  fov_agg_f0 <- function(intervals_dt) {
    # intervals_dt debe tener columnas: vocal_id, tmin, tmax
    q_dt <- copy(intervals_dt)[, .(vocal_id, tmin, tmax)]
    setkey(q_dt, tmin, tmax)
    joined <- foverlaps(pd, q_dt, by.x = c("tiempo","t_end"),
                        by.y = c("tmin","tmax"), nomatch = 0L)
    if (nrow(joined) == 0) return(NULL)

    # ── Filtrado de outliers de F0 por vocal (pre-agregación) ────────────────
    # Método MAD (Median Absolute Deviation): robusto a distribuciones no normales
    # y a la proporción outliers/normales, captura saltos de octava provocados
    # por silence_threshold y voicing_threshold bajos.
    #
    # Umbral = max(k * MAD,  0.20 * mediana):
    #   · k*MAD  → filtra outliers estadísticos generales
    #   · 0.20*med → fallback cuando todos los puntos son similares (MAD ≈ 0)
    #                garantiza que un salto de octava (ratio ≈ 5-6×) siempre se detecte
    # Si tras filtrar no queda ningún punto → se conservan todos para no perder
    # la vocal (quedará en missing_ids y recibirá LOCF).
    if (filtrar_f0_outliers) {
      joined <- joined[, {
        if (.N < 3L) {
          .SD   # menos de 3 puntos: sin info suficiente para detectar outliers
        } else {
          med    <- median(f0)
          mad    <- median(abs(f0 - med))
          umbral <- max(outlier_mad_k * mad, 0.20 * med)
          keep   <- abs(f0 - med) <= umbral
          if (sum(keep) == 0L) .SD else .SD[keep]  # no sobrefiltar nunca
        }
      }, by = vocal_id, .SDcols = names(joined)]
    }

    joined[, .(
      f0_media_hz = mean(f0),
      f0_max_hz   = max(f0),
      f0_min_hz   = min(f0),
      f0_rango_hz = max(f0) - min(f0),
      n_pts       = .N
    ), by = vocal_id]
  }

  # ── Helper: roll join para interpolar desde vecinos ───────────────────────
  # Para vocales sin puntos directos, tomamos el punto de pitch más cercano
  # dentro de una ventana de 0.2s (evita usar pitch de otro contexto lejano)
  ROLL_WINDOW <- 0.2

  interp_missing <- function(tier_ids, tmin_v, tmax_v) {
    centro <- (tmin_v + tmax_v) / 2
    q_roll <- data.table(vocal_id = tier_ids, t_query = centro)
    setkey(q_roll, t_query)
    pd_roll <- copy(pd)[, .(tiempo, f0)]
    setkey(pd_roll, tiempo)
    # roll join: resultado tiene columna 'tiempo' del pitch (el vecino encontrado)
    # y 't_query' del query — no existe 'i.tiempo', guardamos t_query explícitamente
    merged <- pd_roll[q_roll, on = .(tiempo = t_query), roll = "nearest",
                      rollends = c(TRUE, TRUE)]
    # 'tiempo' ahora es el tiempo del pitch encontrado; 'i.tiempo' no existe
    # Calculamos distancia comparando con t_query que está en q_roll
    merged[, t_query := q_roll$t_query[match(vocal_id, q_roll$vocal_id)]]
    merged[, dt := abs(tiempo - t_query)]
    merged[dt > ROLL_WINDOW, f0 := NA_real_]
    merged[, .(vocal_id, f0)]
  }

  # ── F0 global ────────────────────────────────────────────────────────────
  step_actual <- "fov_agg_f0"
  agg <- fov_agg_f0(tier_dt[, .(vocal_id, tmin, tmax)])

  if (!is.null(agg) && nrow(agg) > 0) {
    tier_dt[agg, on = "vocal_id", `:=`(
      f0_media_hz = i.f0_media_hz,
      f0_max_hz   = i.f0_max_hz,
      f0_min_hz   = i.f0_min_hz,
      f0_rango_hz = i.f0_rango_hz
    )]
  }

  # Vocales sin puntos directos: interpolar con vecino más cercano
  missing_ids <- tier_dt[is.na(f0_media_hz), vocal_id]
  if (length(missing_ids) > 0) {
    miss_dt <- tier_dt[vocal_id %in% missing_ids, .(vocal_id, tmin, tmax)]
    interp  <- interp_missing(miss_dt$vocal_id, miss_dt$tmin, miss_dt$tmax)
    interp  <- interp[!is.na(f0)]
    if (nrow(interp) > 0) {
      tier_dt[interp, on = "vocal_id", `:=`(
        f0_media_hz = i.f0,
        f0_max_hz   = i.f0,
        f0_min_hz   = i.f0,
        f0_rango_hz = 0
      )]
    }
  }

  # ── LOCF: vocales vaciadas por filtro de outliers heredan valor anterior ──
  # Si tras el filtrado + interpolación de vecinos una vocal sigue sin F0,
  # se aplica Last Observation Carried Forward (nafill type="locf"):
  # toma los valores tonales de la vocal inmediatamente anterior con F0 válido.
  if (filtrar_f0_outliers && any(is.na(tier_dt$f0_media_hz))) {
    tier_dt[order(tmin),
      `:=`(
        f0_media_hz = nafill(f0_media_hz, type = "locf"),
        f0_max_hz   = nafill(f0_max_hz,   type = "locf"),
        f0_min_hz   = nafill(f0_min_hz,   type = "locf"),
        f0_rango_hz = nafill(f0_rango_hz, type = "locf")
      )
    ]
  }

  # Convertir Hz -> St en una sola pasada vectorizada
  tier_dt[!is.na(f0_media_hz), `:=`(
    f0_media_st = hz_to_semitones(f0_media_hz),
    f0_max_st   = hz_to_semitones(f0_max_hz),
    f0_min_st   = hz_to_semitones(f0_min_hz),
    rango_f0_st = hz_to_semitones(f0_max_hz) - hz_to_semitones(f0_min_hz)
  )]

  # ── Intensidad global ─────────────────────────────────────────────────────
  id <- copy(intensity_dt)[!is.na(intensidad) & intensidad > 0]
  id[, t_end := tiempo]
  setkey(id, tiempo, t_end)

  fov_agg_int <- function(intervals_dt) {
    q_dt <- copy(intervals_dt)[, .(vocal_id, tmin, tmax)]
    setkey(q_dt, tmin, tmax)
    joined <- foverlaps(id, q_dt, by.x = c("tiempo","t_end"),
                        by.y = c("tmin","tmax"), nomatch = 0L)
    if (nrow(joined) == 0) return(NULL)
    joined[, .(
      int_media = mean(intensidad),
      int_max   = max(intensidad),
      int_min   = min(intensidad),
      int_rango = max(intensidad) - min(intensidad)
    ), by = vocal_id]
  }

  step_actual <- "fov_agg_int"
  agg_int <- fov_agg_int(tier_dt[, .(vocal_id, tmin, tmax)])
  if (!is.null(agg_int) && nrow(agg_int) > 0) {
    tier_dt[agg_int, on = "vocal_id", `:=`(
      int_media = i.int_media,
      int_max   = i.int_max,
      int_min   = i.int_min,
      int_rango = i.int_rango
    )]
  }

  # Intensidad para vocales sin puntos: roll vecino
  miss_int <- tier_dt[is.na(int_media), vocal_id]
  if (length(miss_int) > 0) {
    miss_dt_i <- tier_dt[vocal_id %in% miss_int, .(vocal_id, tmin, tmax)]
    centro_i  <- (miss_dt_i$tmin + miss_dt_i$tmax) / 2
    q_i <- data.table(vocal_id = miss_dt_i$vocal_id, t_query = centro_i)
    setkey(q_i, t_query)
    id_roll <- copy(id)[, .(tiempo, intensidad)]
    setkey(id_roll, tiempo)
    m_i <- id_roll[q_i, on = .(tiempo = t_query), roll = "nearest",
                   rollends = c(TRUE, TRUE)]
    m_i[, t_query := q_i$t_query[match(vocal_id, q_i$vocal_id)]]
    m_i[, dt := abs(tiempo - t_query)]
    m_i[dt > ROLL_WINDOW, intensidad := NA_real_]
    m_i <- m_i[!is.na(intensidad)]
    if (nrow(m_i) > 0) {
      tier_dt[m_i, on = "vocal_id", `:=`(
        int_media = i.intensidad, int_max = i.intensidad,
        int_min   = i.intensidad, int_rango = 0
      )]
    }
  }

  step_actual <- "cuartiles"
  # ── Cuartiles — expandir intervals x4, una sola foverlaps ─────────────────
  dur <- tier_dt$tmax - tier_dt$tmin
  # Construir tabla de 4 cuartiles por vocal en una sola operación
  qdt <- rbindlist(lapply(1:4, function(q) {
    data.table(
      vocal_id = tier_dt$vocal_id,
      q        = q,
      tmin     = tier_dt$tmin + (q-1)/4 * dur,
      tmax     = tier_dt$tmin + q/4     * dur
    )
  }))
  qdt[, qvocal_id := paste0(vocal_id, "_", q)]

  # F0 cuartiles
  q_agg_f0 <- {
    q_dt2 <- copy(qdt)[, .(vocal_id = qvocal_id, tmin, tmax)]
    setkey(q_dt2, tmin, tmax)
    joined2 <- foverlaps(pd, q_dt2, by.x = c("tiempo","t_end"),
                         by.y = c("tmin","tmax"), nomatch = 0L)
    if (nrow(joined2) > 0) {
      joined2[, .(
        f0_media_hz = mean(f0), f0_max_hz = max(f0),
        f0_min_hz   = min(f0),  f0_rango_hz = max(f0)-min(f0)
      ), by = vocal_id]
    } else NULL
  }

  if (!is.null(q_agg_f0)) {
    q_agg_f0[, c("vid","q") := tstrsplit(vocal_id, "_", fixed = TRUE, type.convert = TRUE)]
    q_agg_f0[, vid := as.integer(vid)]
    q_agg_f0[, q   := as.integer(q)]
    for (qq in 1:4) {
      sub <- q_agg_f0[q == qq]
      if (nrow(sub) == 0) next
      tier_dt[sub, on = c(vocal_id = "vid"), `:=`(
        tmp_fmh = i.f0_media_hz, tmp_fxh = i.f0_max_hz,
        tmp_fnh = i.f0_min_hz,   tmp_frh = i.f0_rango_hz
      )]
      tier_dt[!is.na(tmp_fmh), (paste0("q",qq,"_f0_media_hz")) := tmp_fmh]
      tier_dt[!is.na(tmp_fxh), (paste0("q",qq,"_f0_max_hz"))   := tmp_fxh]
      tier_dt[!is.na(tmp_fnh), (paste0("q",qq,"_f0_min_hz"))   := tmp_fnh]
      tier_dt[!is.na(tmp_frh), (paste0("q",qq,"_f0_rango_hz")) := tmp_frh]
      # St
      tier_dt[!is.na(tmp_fmh), (paste0("q",qq,"_f0_media_st")) := hz_to_semitones(tmp_fmh)]
      tier_dt[!is.na(tmp_fxh), (paste0("q",qq,"_f0_max_st"))   := hz_to_semitones(tmp_fxh)]
      tier_dt[!is.na(tmp_fnh), (paste0("q",qq,"_f0_min_st"))   := hz_to_semitones(tmp_fnh)]
      tier_dt[!is.na(tmp_fmh) & !is.na(tmp_fnh),
              (paste0("q",qq,"_f0_rango_st")) :=
                hz_to_semitones(tmp_fxh) - hz_to_semitones(tmp_fnh)]
      tier_dt[, c("tmp_fmh","tmp_fxh","tmp_fnh","tmp_frh") := NULL]
    }
  }

  # Intensidad cuartiles
  q_agg_int <- {
    q_dt3 <- copy(qdt)[, .(vocal_id = qvocal_id, tmin, tmax)]
    setkey(q_dt3, tmin, tmax)
    joined3 <- foverlaps(id, q_dt3, by.x = c("tiempo","t_end"),
                         by.y = c("tmin","tmax"), nomatch = 0L)
    if (nrow(joined3) > 0) {
      joined3[, .(
        int_media = mean(intensidad), int_max = max(intensidad),
        int_min   = min(intensidad),  int_rango = max(intensidad)-min(intensidad)
      ), by = vocal_id]
    } else NULL
  }

  if (!is.null(q_agg_int)) {
    q_agg_int[, c("vid","q") := tstrsplit(vocal_id, "_", fixed = TRUE, type.convert = TRUE)]
    q_agg_int[, vid := as.integer(vid)]
    q_agg_int[, q   := as.integer(q)]
    for (qq in 1:4) {
      sub <- q_agg_int[q == qq]
      if (nrow(sub) == 0) next
      tier_dt[sub, on = c(vocal_id = "vid"), `:=`(
        tmp_im = i.int_media, tmp_ix = i.int_max,
        tmp_in = i.int_min,   tmp_ir = i.int_rango
      )]
      tier_dt[!is.na(tmp_im), (paste0("q",qq,"_int_media")) := tmp_im]
      tier_dt[!is.na(tmp_ix), (paste0("q",qq,"_int_max"))   := tmp_ix]
      tier_dt[!is.na(tmp_in), (paste0("q",qq,"_int_min"))   := tmp_in]
      tier_dt[!is.na(tmp_ir), (paste0("q",qq,"_int_rango")) := tmp_ir]
      tier_dt[, c("tmp_im","tmp_ix","tmp_in","tmp_ir") := NULL]
    }
  }

  step_actual <- "dif_cuartiles"
  # ── Diferencias entre cuartiles (vectorizado) ─────────────────────────────
  tier_dt[, `:=`(
    dif_q1_q2_st  = q2_f0_media_st - q1_f0_media_st,
    dif_q2_q3_st  = q3_f0_media_st - q2_f0_media_st,
    dif_q3_q4_st  = q4_f0_media_st - q3_f0_media_st,
    dif_q1_q4_st  = q4_f0_media_st - q1_f0_media_st,
    dif_q1_q2_pct = fifelse(!is.na(q1_f0_media_hz) & q1_f0_media_hz > 0,
                            ((q2_f0_media_hz - q1_f0_media_hz) / q1_f0_media_hz) * 100, NA_real_),
    dif_q2_q3_pct = fifelse(!is.na(q2_f0_media_hz) & q2_f0_media_hz > 0,
                            ((q3_f0_media_hz - q2_f0_media_hz) / q2_f0_media_hz) * 100, NA_real_),
    dif_q3_q4_pct = fifelse(!is.na(q3_f0_media_hz) & q3_f0_media_hz > 0,
                            ((q4_f0_media_hz - q3_f0_media_hz) / q3_f0_media_hz) * 100, NA_real_),
    dif_q1_q4_pct = fifelse(!is.na(q1_f0_media_hz) & q1_f0_media_hz > 0,
                            ((q4_f0_media_hz - q1_f0_media_hz) / q1_f0_media_hz) * 100, NA_real_)
  )]

  # Limpiar columna auxiliar
  tier_dt[, vocal_id := NULL]

  return(tier_dt)
  }, error = function(e) {
    stop(paste0("[calcular_metricas_dt paso=", step_actual, "] ", e$message))
  })
}

# ========================================
# calcular_incrementos_dt — versión vectorizada con shift()
# Elimina el doble bucle for(idx) for(nn) usando desplazamientos de vectores
# ========================================
calcular_incrementos_dt <- function(tier_dt) {
  n <- nrow(tier_dt)
  if (n == 0) return(tier_dt)

  # Preallocar
  for (nn in 1:5) {
    tier_dt[, paste0("ant_inc_f0_",  nn, "_st")  := NA_real_]
    tier_dt[, paste0("ant_inc_f0_",  nn, "_pct") := NA_real_]
    tier_dt[, paste0("ant_inc_int_", nn, "_db")  := NA_real_]
    tier_dt[, paste0("post_inc_f0_", nn, "_st")  := NA_real_]
    tier_dt[, paste0("post_inc_f0_", nn, "_pct") := NA_real_]
    tier_dt[, paste0("post_inc_int_",nn, "_db")  := NA_real_]
  }

  f0_st <- tier_dt$f0_media_st
  f0_hz <- tier_dt$f0_media_hz
  int_m <- tier_dt$int_media

  for (nn in 1:5) {
    # shift(x, n, type="lag")  = valores n posiciones antes  (anteriores)
    # shift(x, n, type="lead") = valores n posiciones después (posteriores)
    f0_st_ant  <- shift(f0_st,  nn, type = "lag")
    f0_hz_ant  <- shift(f0_hz,  nn, type = "lag")
    int_ant    <- shift(int_m,  nn, type = "lag")
    f0_st_post <- shift(f0_st,  nn, type = "lead")
    f0_hz_post <- shift(f0_hz,  nn, type = "lead")
    int_post   <- shift(int_m,  nn, type = "lead")

    tier_dt[, (paste0("ant_inc_f0_",  nn, "_st"))  :=
              fifelse(!is.na(f0_st) & !is.na(f0_st_ant),
                      f0_st - f0_st_ant, NA_real_)]
    tier_dt[, (paste0("ant_inc_f0_",  nn, "_pct")) :=
              fifelse(!is.na(f0_hz) & !is.na(f0_hz_ant) & f0_hz_ant > 0,
                      ((f0_hz - f0_hz_ant) / f0_hz_ant) * 100, NA_real_)]
    tier_dt[, (paste0("ant_inc_int_", nn, "_db"))  :=
              fifelse(!is.na(int_m) & !is.na(int_ant),
                      int_m - int_ant, NA_real_)]
    tier_dt[, (paste0("post_inc_f0_", nn, "_st"))  :=
              fifelse(!is.na(f0_st) & !is.na(f0_st_post),
                      f0_st_post - f0_st, NA_real_)]
    tier_dt[, (paste0("post_inc_f0_", nn, "_pct")) :=
              fifelse(!is.na(f0_hz) & !is.na(f0_hz_post) & f0_hz > 0,
                      ((f0_hz_post - f0_hz) / f0_hz) * 100, NA_real_)]
    tier_dt[, (paste0("post_inc_int_",nn, "_db"))  :=
              fifelse(!is.na(int_m) & !is.na(int_post),
                      int_post - int_m, NA_real_)]
  }

  return(tier_dt)
}

# ========================================
# FUNCIONES DE ETIQUETADO TOBI Y AMH
# ========================================

UMBRAL_SIGNIFICATIVO_ST <- 1.5
UMBRAL_EXTRALTO_ST <- 6.0
UMBRAL_ANACRUSIS_MAX_PCT <- 40
UMBRAL_ENFASIS_PCT <- 30

calcular_tercio_rango <- function(valor, f0_min, f0_max, lim_bajo = 0.33, lim_alto = 0.66) {
  if (is.na(valor) || is.na(f0_min) || is.na(f0_max) || f0_max == f0_min) return(NA)
  rango <- f0_max - f0_min
  tercio <- (valor - f0_min) / rango
  if (tercio < lim_bajo) return("bajo")
  if (tercio < lim_alto) return("medio")
  return("alto")
}

etiquetar_tobi_vocal <- function(f0_pre, f0_tonica, f0_post, f0_min_rango, f0_max_rango,
                                  es_tonica = FALSE, es_ultima_tonica = FALSE) {
  if (is.na(f0_tonica)) return(list(tobi_fonetico = NA, tobi_fonologico = NA))
  
  mov_entrada <- ifelse(!is.na(f0_pre), f0_tonica - f0_pre, 0)
  mov_salida <- ifelse(!is.na(f0_post), f0_post - f0_tonica, 0)
  tercio <- calcular_tercio_rango(f0_tonica, f0_min_rango, f0_max_rango)
  
  tobi_fonetico <- ""
  tobi_fonologico <- ""
  
  if (es_tonica) {
    mov_significativo_entrada <- abs(mov_entrada) > UMBRAL_SIGNIFICATIVO_ST
    mov_significativo_salida <- abs(mov_salida) > UMBRAL_SIGNIFICATIVO_ST
    
    if (!mov_significativo_entrada && !mov_significativo_salida) {
      if (tercio == "alto") { tobi_fonetico <- "H*"; tobi_fonologico <- "H*"
      } else { tobi_fonetico <- "L*"; tobi_fonologico <- "L*" }
    } else if (mov_entrada > UMBRAL_SIGNIFICATIVO_ST && mov_salida < -UMBRAL_SIGNIFICATIVO_ST) {
      if (mov_entrada > UMBRAL_EXTRALTO_ST) { tobi_fonetico <- "L+¡H*"; tobi_fonologico <- "L+H*"
      } else { tobi_fonetico <- "L+H*"; tobi_fonologico <- "L+H*" }
    } else if (mov_entrada > UMBRAL_SIGNIFICATIVO_ST) {
      if (mov_salida > UMBRAL_SIGNIFICATIVO_ST) { tobi_fonetico <- "L*+H"; tobi_fonologico <- "L*+H"
      } else { tobi_fonetico <- "L+H*"; tobi_fonologico <- "L+H*" }
    } else if (mov_entrada < -UMBRAL_SIGNIFICATIVO_ST) {
      tobi_fonetico <- "H+L*"; tobi_fonologico <- "H+L*"
    } else if (mov_salida > UMBRAL_SIGNIFICATIVO_ST) {
      tobi_fonetico <- "L*+H"; tobi_fonologico <- "L*+H"
    } else if (mov_salida < -UMBRAL_SIGNIFICATIVO_ST) {
      if (tercio == "alto") { tobi_fonetico <- "H*+L"; tobi_fonologico <- "H*"
      } else { tobi_fonetico <- "!H*+L"; tobi_fonologico <- "L*" }
    } else {
      tobi_fonetico <- ifelse(tercio == "alto", "H*", "L*")
      tobi_fonologico <- tobi_fonetico
    }
  } else {
    if (tercio == "alto") tobi_fonetico <- "H"
    else if (tercio == "medio") tobi_fonetico <- "!H"
    else tobi_fonetico <- "L"
    tobi_fonologico <- tobi_fonetico
  }
  
  return(list(tobi_fonetico = tobi_fonetico, tobi_fonologico = tobi_fonologico))
}

etiquetar_tobi_frontera <- function(f0_ultima_tonica, f0_final, f0_penultima,
                                     f0_min_rango, f0_max_rango) {
  if (is.na(f0_final) || is.na(f0_ultima_tonica)) {
    return(list(tono_frontera = NA, tono_frontera_fonologico = NA))
  }
  
  mov_final <- f0_final - f0_ultima_tonica
  tercio_final <- calcular_tercio_rango(f0_final, f0_min_rango, f0_max_rango)
  
  mov_circunflejo <- FALSE
  if (!is.na(f0_penultima)) {
    mov_pre <- f0_penultima - f0_ultima_tonica
    if (sign(mov_pre) != sign(mov_final) &&
        abs(mov_pre) > UMBRAL_SIGNIFICATIVO_ST &&
        abs(mov_final) > UMBRAL_SIGNIFICATIVO_ST) {
      mov_circunflejo <- TRUE
    }
  }
  
  tono_frontera <- ""
  tono_frontera_fonologico <- ""
  
  if (mov_circunflejo) {
    if (mov_final > 0) { tono_frontera <- "LH%"; tono_frontera_fonologico <- "LH%" }
    else { tono_frontera <- "HL%"; tono_frontera_fonologico <- "HL%" }
  } else if (abs(mov_final) < UMBRAL_SIGNIFICATIVO_ST) {
    if (tercio_final == "medio") { tono_frontera <- "!H%"; tono_frontera_fonologico <- "M%" }
    else if (tercio_final == "alto") { tono_frontera <- "H%"; tono_frontera_fonologico <- "H%" }
    else { tono_frontera <- "L%"; tono_frontera_fonologico <- "L%" }
  } else if (mov_final > UMBRAL_SIGNIFICATIVO_ST) {
    if (mov_final > UMBRAL_EXTRALTO_ST) { tono_frontera <- "¡H%"; tono_frontera_fonologico <- "H%" }
    else if (tercio_final == "medio") { tono_frontera <- "!H%"; tono_frontera_fonologico <- "M%" }
    else { tono_frontera <- "H%"; tono_frontera_fonologico <- "H%" }
  } else {
    tono_frontera <- "L%"; tono_frontera_fonologico <- "L%"
  }
  
  return(list(tono_frontera = tono_frontera, tono_frontera_fonologico = tono_frontera_fonologico))
}

# ========================================
# ETIQUETADO AMH PARA GRUPO ENTONATIVO
# ========================================
etiquetar_amh_grupo <- function(vocales_grupo, n_palabras = NA,
                                 umbral_enfasis = UMBRAL_ENFASIS_PCT,
                                 amh_asc_fuerte = 70, amh_asc_moderado = 40,
                                 amh_asc_leve = 15, amh_asc_minimo = 10,
                                 amh_desc_moderado = -15, amh_desc_fuerte = -40) {
  resultado_vacio <- list(amh_patron = NA, amh_fonologico = NA, amh_rasgos = NA,
                          inflexion_final_tipo = NA, inflexion_final_pct = NA)
  
  if (is.null(vocales_grupo) || nrow(vocales_grupo) == 0) return(resultado_vacio)
  
  n_vocales <- nrow(vocales_grupo)
  
  if (n_vocales == 1 || (!is.na(n_palabras) && n_palabras == 1)) {
    return(list(amh_patron = "VIII", amh_fonologico = "/-int +enf -susp/",
                amh_rasgos = "énfasis_reducido", inflexion_final_tipo = "coincide_pico",
                inflexion_final_pct = 0))
  }
  
  if (!"seccion_ip" %in% colnames(vocales_grupo)) vocales_grupo$seccion_ip <- "cuerpo"
  
  anacrusis <- vocales_grupo[!is.na(vocales_grupo$seccion_ip) & vocales_grupo$seccion_ip == "anacrusis", ]
  cuerpo <- vocales_grupo[!is.na(vocales_grupo$seccion_ip) & vocales_grupo$seccion_ip == "cuerpo", ]
  tonema <- vocales_grupo[!is.na(vocales_grupo$seccion_ip) & vocales_grupo$seccion_ip == "tonema", ]
  
  primera_vocal <- vocales_grupo[1, ]
  
  if (!"tonica_gramatical" %in% colnames(vocales_grupo)) vocales_grupo$tonica_gramatical <- "no"
  tonicas <- vocales_grupo[!is.na(vocales_grupo$tonica_gramatical) & vocales_grupo$tonica_gramatical == "sí", ]
  
  primer_pico_f0 <- NA
  if (nrow(tonicas) > 0) primer_pico_f0 <- tonicas$f0_media_hz[1]
  
  ultima_vocal <- vocales_grupo[n_vocales, ]
  ultima_tonica <- if (nrow(tonicas) > 0) tonicas[nrow(tonicas), ] else ultima_vocal
  
  if_pct <- NA
  f0_ultima_tonica <- ultima_tonica$f0_media_hz
  f0_ultima_vocal <- ultima_vocal$f0_media_hz
  
  if (!is.na(f0_ultima_tonica) && !is.na(f0_ultima_vocal) &&
      !is.infinite(f0_ultima_tonica) && !is.infinite(f0_ultima_vocal) &&
      f0_ultima_tonica > 0) {
    if_pct <- ((f0_ultima_vocal - f0_ultima_tonica) / f0_ultima_tonica) * 100
  }

  # Detectar caso sin cola post-tónica: la última tónica ES la última vocal del grupo
  # (p.ej. palabras agudas en posición final como "trabajar" con acento L+H*).
  # En este caso if_pct = 0 por definición, lo que no captura el movimiento real.
  # Solución: medir el salto HACIA el acento nuclear desde la vocal inmediatamente anterior.
  idx_tonicas_pos <- which(!is.na(vocales_grupo$tonica_gramatical) &
                             vocales_grupo$tonica_gramatical == "s\u00ed")
  idx_ult_tonica_pos <- if (length(idx_tonicas_pos) > 0) max(idx_tonicas_pos) else n_vocales
  if (idx_ult_tonica_pos == n_vocales && idx_ult_tonica_pos > 1 && !is.na(if_pct) && abs(if_pct) < 1) {
    f0_prev_nuclear <- vocales_grupo$f0_media_hz[idx_ult_tonica_pos - 1]
    if (!is.na(f0_prev_nuclear) && !is.infinite(f0_prev_nuclear) && f0_prev_nuclear > 0 &&
        !is.na(f0_ultima_tonica) && !is.infinite(f0_ultima_tonica)) {
      if_pct <- ((f0_ultima_tonica - f0_prev_nuclear) / f0_prev_nuclear) * 100
    }
  }
  
  ascenso_anacrusis <- 0
  f0_primera_vocal <- primera_vocal$f0_media_hz
  if (nrow(anacrusis) > 0 && !is.na(primer_pico_f0) &&
      !is.na(f0_primera_vocal) && !is.infinite(f0_primera_vocal) && f0_primera_vocal > 0) {
    ascenso_anacrusis <- ((primer_pico_f0 - f0_primera_vocal) / f0_primera_vocal) * 100
  }
  
  primer_pico_desplazado <- FALSE
  if (nrow(tonicas) > 0 && nrow(cuerpo) > 0) {
    f0_primera_tonica <- tonicas$f0_media_hz[1]
    f0_max_cuerpo <- max(cuerpo$f0_media_hz, na.rm = TRUE)
    if (!is.na(f0_primera_tonica) && !is.na(f0_max_cuerpo) && is.finite(f0_max_cuerpo))
      primer_pico_desplazado <- f0_max_cuerpo > f0_primera_tonica * 1.05
  }
  
  declinacion_tipo <- "suave"
  if (nrow(cuerpo) >= 2) {
    f0_cuerpo <- cuerpo$f0_media_hz[!is.na(cuerpo$f0_media_hz)]
    if (length(f0_cuerpo) >= 2) {
      tendencia <- lm(f0_cuerpo ~ seq_along(f0_cuerpo))$coefficients[2]
      if (abs(tendencia) < 1) declinacion_tipo <- "plana"
      else if (tendencia < -3) declinacion_tipo <- "pronunciada"
      diffs <- diff(f0_cuerpo)
      cambios_signo <- sum(diff(sign(diffs)) != 0, na.rm = TRUE)
      if (cambios_signo >= 2) {
        declinacion_tipo <- if (declinacion_tipo == "plana") "zigzag_plana" else "zigzag_descendente"
      }
    }
  }
  
  enfasis_cuerpo <- FALSE
  if (nrow(cuerpo) >= 2) {
    for (i in 2:nrow(cuerpo)) {
      if (!is.na(cuerpo$f0_media_hz[i]) && !is.na(cuerpo$f0_media_hz[i-1]) && cuerpo$f0_media_hz[i-1] > 0) {
        cambio <- ((cuerpo$f0_media_hz[i] - cuerpo$f0_media_hz[i-1]) / cuerpo$f0_media_hz[i-1]) * 100
        if (cambio > umbral_enfasis) { enfasis_cuerpo <- TRUE; break }
      }
    }
  }
  
  if_circunfleja <- FALSE; if_circunfleja_tipo <- NA
  if (nrow(tonema) >= 2) {
    f0_tonema <- tonema$f0_media_hz[!is.na(tonema$f0_media_hz)]
    if (length(f0_tonema) >= 2) {
      diffs <- diff(f0_tonema)
      if (length(diffs) >= 2) {
        for (i in 2:length(diffs)) {
          if (sign(diffs[i]) != sign(diffs[i-1]) && sign(diffs[i]) != 0 && sign(diffs[i-1]) != 0) {
            if_circunfleja <- TRUE
            if_circunfleja_tipo <- if (diffs[1] > 0) "asc_desc" else "desc_asc"
            break
          }
        }
      }
    }
  }
  
  amh_patron <- "I"; amh_fonologico <- "/-int -enf -susp/"; amh_rasgos <- "neutro"
  inflexion_final_tipo <- "descendente"
  
  if (is.na(if_pct)) return(list(amh_patron=NA, amh_fonologico=NA, amh_rasgos=NA,
                                  inflexion_final_tipo=NA, inflexion_final_pct=NA))
  
  if (if_circunfleja) {
    inflexion_final_tipo <- if_circunfleja_tipo
    if (declinacion_tipo == "plana" && !primer_pico_desplazado) {
      amh_patron <- "IVb"; amh_fonologico <- "/+int -enf -susp/"; amh_rasgos <- "interrogativo_plano"
    } else if (primer_pico_desplazado) {
      if (enfasis_cuerpo || abs(if_pct) > 40) {
        if (if_circunfleja_tipo == "asc_desc") {
          amh_patron <- "Xa"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_circunflejo_asc_desc"
        } else {
          amh_patron <- "Xb"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_circunflejo_desc_asc"
        }
      } else {
        amh_patron <- "IVa"; amh_fonologico <- "/+int -enf -susp/"; amh_rasgos <- "interrogativo_circunflejo"
      }
    }
  } else if (if_pct >= amh_asc_fuerte) {
    inflexion_final_tipo <- "ascendente_fuerte"
    amh_patron <- "II"; amh_fonologico <- "/+int -enf -susp/"; amh_rasgos <- "interrogativo_fuerte"
  } else if (if_pct >= amh_asc_moderado && if_pct < amh_asc_fuerte) {
    inflexion_final_tipo <- "ascendente_moderada"
    if (primer_pico_desplazado) {
      amh_patron <- "III"; amh_fonologico <- "/+int -enf -susp/"; amh_rasgos <- "interrogativo_moderado"
    } else {
      amh_patron <- "VIa"; amh_fonologico <- "/-int -enf +susp/"; amh_rasgos <- "suspensión_ascendente"
    }
  } else if (if_pct >= amh_asc_leve && if_pct < amh_asc_moderado) {
    inflexion_final_tipo <- "ascendente_leve"
    if (primer_pico_desplazado) {
      amh_patron <- "VIb"; amh_fonologico <- "/-int -enf +susp/"; amh_rasgos <- "suspensión_pico_desplazado"
    } else {
      amh_patron <- "VIa"; amh_fonologico <- "/-int -enf +susp/"; amh_rasgos <- "suspensión_ascendente"
    }
  } else if (if_pct >= amh_asc_minimo && if_pct < amh_asc_leve) {
    inflexion_final_tipo <- "ascendente_minima"
    amh_patron <- "I"; amh_fonologico <- "/-int -enf -susp/"; amh_rasgos <- "neutro"
  } else if (if_pct >= amh_desc_moderado && if_pct < amh_asc_minimo) {
    inflexion_final_tipo <- "plana"
    if (nrow(anacrusis) == 0 && nrow(cuerpo) == 0) {
      amh_patron <- "V"; amh_fonologico <- "/-int -enf +susp/"; amh_rasgos <- "suspensión_neutra"
    } else {
      amh_patron <- "I"; amh_fonologico <- "/-int -enf -susp/"; amh_rasgos <- "neutro"
    }
  } else if (if_pct >= amh_desc_fuerte && if_pct < amh_desc_moderado) {
    inflexion_final_tipo <- "descendente_moderada"
    if (enfasis_cuerpo) {
      if (declinacion_tipo == "plana") { amh_patron <- "XIIa"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_plano" }
      else if (declinacion_tipo == "zigzag_plana") { amh_patron <- "XIIb"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_zigzag_plano" }
      else if (declinacion_tipo == "zigzag_descendente") { amh_patron <- "XIIc"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_zigzag_desc" }
      else { amh_patron <- "IX"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_descenso" }
    } else {
      amh_patron <- "I"; amh_fonologico <- "/-int -enf -susp/"; amh_rasgos <- "neutro"
    }
  } else if (if_pct < amh_desc_fuerte) {
    inflexion_final_tipo <- "descendente_fuerte"
    resituacion <- FALSE
    if (!is.na(primer_pico_f0) && !is.na(ultima_tonica$f0_media_hz)) {
      dif_nivel <- abs(ultima_tonica$f0_media_hz - primer_pico_f0) / primer_pico_f0 * 100
      resituacion <- dif_nivel < 15
    }
    if (resituacion && primer_pico_desplazado) {
      amh_patron <- "VII"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_resituación"
    } else {
      amh_patron <- "IX"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_descenso_fuerte"
    }
  }
  
  if (enfasis_cuerpo && if_pct > 60 && primer_pico_desplazado) {
    amh_patron <- "XI"; amh_fonologico <- "/-int +enf -susp/"; amh_rasgos <- "énfasis_pico_adicional"
  }
  
  return(list(amh_patron = amh_patron, amh_fonologico = amh_fonologico, amh_rasgos = amh_rasgos,
              inflexion_final_tipo = inflexion_final_tipo, inflexion_final_pct = round(if_pct, 2)))
}

# ========================================
# APLICAR ETIQUETADO COMPLETO
# ========================================
aplicar_etiquetado_completo <- function(phones_data, ips_resumen,
                                        tobi_sig = 1.5, tobi_ext = 6.0,
                                        tobi_bajo = 0.33, tobi_alto = 0.66,
                                        amh_enfasis = 30,
                                        amh_asc_fuerte = 70, amh_asc_moderado = 40,
                                        amh_asc_leve = 15, amh_asc_minimo = 10,
                                        amh_desc_moderado = -15, amh_desc_fuerte = -40) {
  if (is.null(phones_data) || nrow(phones_data) == 0) return(list(phones = phones_data, ips = ips_resumen))
  
  # Aplicar parámetros ToBI configurables como globales temporales
  UMBRAL_SIGNIFICATIVO_ST <<- tobi_sig
  UMBRAL_EXTRALTO_ST <<- tobi_ext
  
  phones_data$tobi_fonetico <- NA_character_
  phones_data$tobi_fonologico <- NA_character_
  phones_data$tono_frontera <- NA_character_
  phones_data$tono_frontera_fonologico <- NA_character_
  
  if (!is.null(ips_resumen) && nrow(ips_resumen) > 0) {
    ips_resumen$amh_patron <- NA_character_
    ips_resumen$amh_fonologico <- NA_character_
    ips_resumen$amh_rasgos <- NA_character_
    ips_resumen$inflexion_final_tipo <- NA_character_
    ips_resumen$inflexion_final_pct <- NA_real_
    ips_resumen$tobi_nuclear <- NA_character_
  }
  
  # Usar filename en la clave de grupo
  if ("filename" %in% colnames(phones_data)) {
    grupos <- unique(paste(phones_data$filename, phones_data$hablante,
                           phones_data$grupo_fonico, phones_data$grupo_entonativo, sep = "|||"))
  } else {
    grupos <- unique(paste(phones_data$hablante, phones_data$grupo_fonico,
                           phones_data$grupo_entonativo, sep = "|||"))
  }
  
  for (grupo_id in grupos) {
    partes <- strsplit(grupo_id, "|||", fixed = TRUE)[[1]]
    
    if ("filename" %in% colnames(phones_data)) {
      if (length(partes) < 4) next
      fn <- partes[1]; hablante <- partes[2]; gf <- as.numeric(partes[3]); ge <- as.numeric(partes[4])
      idx_grupo <- which(phones_data$filename == fn & phones_data$hablante == hablante &
                           phones_data$grupo_fonico == gf & phones_data$grupo_entonativo == ge)
    } else {
      if (length(partes) < 3) next
      hablante <- partes[1]; gf <- as.numeric(partes[2]); ge <- as.numeric(partes[3])
      idx_grupo <- which(phones_data$hablante == hablante &
                           phones_data$grupo_fonico == gf & phones_data$grupo_entonativo == ge)
    }
    
    if (length(idx_grupo) == 0) next
    
    vocales_grupo <- phones_data[idx_grupo, ]
    n_vocales <- nrow(vocales_grupo)
    
    f0_vals <- vocales_grupo$f0_media_st[!is.na(vocales_grupo$f0_media_st)]
    if (length(f0_vals) == 0) next
    
    f0_min_rango <- min(f0_vals)
    f0_max_rango <- max(f0_vals)
    
    palabras_validas <- vocales_grupo$palabra[!is.na(vocales_grupo$palabra) & vocales_grupo$palabra != ""]
    n_palabras <- length(unique(palabras_validas))
    
    amh_result <- tryCatch(etiquetar_amh_grupo(vocales_grupo, n_palabras,
                                                umbral_enfasis = amh_enfasis,
                                                amh_asc_fuerte = amh_asc_fuerte,
                                                amh_asc_moderado = amh_asc_moderado,
                                                amh_asc_leve = amh_asc_leve,
                                                amh_asc_minimo = amh_asc_minimo,
                                                amh_desc_moderado = amh_desc_moderado,
                                                amh_desc_fuerte = amh_desc_fuerte),
                            error = function(e) list(amh_patron=NA, amh_fonologico=NA, amh_rasgos=NA,
                                                     inflexion_final_tipo=NA, inflexion_final_pct=NA))
    
    if (!is.null(ips_resumen)) {
      if ("filename" %in% colnames(ips_resumen)) {
        idx_ip <- which(ips_resumen$filename == fn & ips_resumen$hablante == hablante &
                          ips_resumen$grupo_fonico == gf & ips_resumen$grupo_entonativo == ge)
      } else {
        idx_ip <- which(ips_resumen$hablante == hablante &
                          ips_resumen$grupo_fonico == gf & ips_resumen$grupo_entonativo == ge)
      }
      if (length(idx_ip) > 0) {
        ips_resumen$amh_patron[idx_ip] <- amh_result$amh_patron
        ips_resumen$amh_fonologico[idx_ip] <- amh_result$amh_fonologico
        ips_resumen$amh_rasgos[idx_ip] <- amh_result$amh_rasgos
        ips_resumen$inflexion_final_tipo[idx_ip] <- amh_result$inflexion_final_tipo
        ips_resumen$inflexion_final_pct[idx_ip] <- amh_result$inflexion_final_pct
      }
    }
    
    for (i in seq_along(idx_grupo)) {
      idx <- idx_grupo[i]
      f0_pre <- if (i > 1) phones_data$f0_media_st[idx_grupo[i-1]] else NA
      f0_actual <- phones_data$f0_media_st[idx]
      f0_post <- if (i < n_vocales) phones_data$f0_media_st[idx_grupo[i+1]] else NA
      
      tonica_val <- phones_data$tonica_gramatical[idx]
      es_tonica <- !is.na(tonica_val) && tonica_val == "sí"
      es_ultima_tonica <- FALSE
      
      tonicas_mask <- !is.na(phones_data$tonica_gramatical[idx_grupo]) &
                      phones_data$tonica_gramatical[idx_grupo] == "sí"
      tonicas_idx <- idx_grupo[tonicas_mask]
      if (length(tonicas_idx) > 0 && idx == max(tonicas_idx)) es_ultima_tonica <- TRUE
      
      tobi_result <- tryCatch(
        etiquetar_tobi_vocal(f0_pre, f0_actual, f0_post, f0_min_rango, f0_max_rango, es_tonica, es_ultima_tonica),
        error = function(e) list(tobi_fonetico = NA, tobi_fonologico = NA))
      
      phones_data$tobi_fonetico[idx] <- tobi_result$tobi_fonetico
      phones_data$tobi_fonologico[idx] <- tobi_result$tobi_fonologico
      
      if (i == n_vocales) {
        ultima_tonica_f0 <- NA; penultima_f0 <- NA
        if (length(tonicas_idx) > 0) ultima_tonica_f0 <- phones_data$f0_media_st[max(tonicas_idx)]
        if (i > 1) penultima_f0 <- phones_data$f0_media_st[idx_grupo[i-1]]
        
        frontera_result <- tryCatch(
          etiquetar_tobi_frontera(ultima_tonica_f0, f0_actual, penultima_f0, f0_min_rango, f0_max_rango),
          error = function(e) list(tono_frontera = NA, tono_frontera_fonologico = NA))
        
        phones_data$tono_frontera[idx] <- frontera_result$tono_frontera
        phones_data$tono_frontera_fonologico[idx] <- frontera_result$tono_frontera_fonologico
        
        if (!is.null(ips_resumen) && length(idx_ip) > 0) {
          if (length(tonicas_idx) > 0) {
            ultimo_acento <- phones_data$tobi_fonologico[max(tonicas_idx)]
            if (!is.na(ultimo_acento) && !is.na(frontera_result$tono_frontera_fonologico)) {
              ips_resumen$tobi_nuclear[idx_ip] <- paste0(ultimo_acento, " ", frontera_result$tono_frontera_fonologico)
            }
          }
        }
      }
    }
  }
  
  return(list(phones = phones_data, ips = ips_resumen))
}


