config_panel <- function() {
  div(id = "offcanvas-config",
    class = "offcanvas offcanvas-end",
    tabindex = "-1",
    `data-bs-scroll` = "true",
    style = "width: 380px;",
    div(class = "offcanvas-header",
      h5(class = "offcanvas-title", icon("sliders-h"), " Config. Avanzada"),
      tags$button(type = "button", class = "btn-close", `data-bs-dismiss` = "offcanvas")
    ),
    div(class = "offcanvas-body",
    tags$div(style = "padding: 15px;",
      h4(icon("sliders-h"), " Config. Avanzada"),
      
      tags$details(open = "open",
        tags$summary(style = "cursor: pointer; color: #ea580c; font-weight: bold;",
                     icon("layer-group"), " Grupos Fónicos y Outliers"),
        checkboxInput("utterances_son_gf", "Las líneas de words ya son GFs", value = FALSE),
        helpText("Si se activa, no se computarán GF por pausa: cada utterance es un GF."),
        hr(),
        h5("Filtrado de Outliers"),
        checkboxInput("filtrar_outliers", "Filtrar valores extremos F0/intensidad", value = TRUE),
        conditionalPanel(
          condition = "input.filtrar_outliers == true",
          numericInput("outlier_sd_factor", "Factor SD:", value = 3.0, min = 1.5, max = 7, step = 0.5),
          selectInput("outlier_metodo", "Método:",
                      choices = c("Winsorizar" = "winsorize", "Excluir (NA)" = "exclude", "Trimmed" = "trimmed"),
                      selected = "winsorize"),
          numericInput("outlier_trim_pct", "Percentil recorte (%):", value = 5, min = 1, max = 25, step = 1)
        ),
        tags$hr(style = "margin:4px 0;"),
        checkboxInput("filtrar_f0_frames_outliers",
          "Filtrar puntos tónicos erróneos por vocal (pre-agregación)",
          value = TRUE),
        helpText(style = "font-size:0.82em; color:#555;",
          icon("info-circle"),
          " Elimina puntos de F0 claramente erróneos dentro de cada vocal antes de calcular",
          " su media/máx/mín. Corrige saltos de octava causados por umbrales bajos de",
          " voicing/silence. Las vocales que queden vacías heredan el F0 de la vocal anterior."
        ),
        conditionalPanel(
          condition = "input.filtrar_f0_frames_outliers == true",
          numericInput("outlier_f0_mad_k",
            "Factor MAD (umbral = k \u00d7 MAD \u00f3 20% mediana):",
            value = 3.0, min = 1.5, max = 10, step = 0.5)
        )
      ),

      tags$details(
        tags$summary(style = "cursor: pointer; color: #17a2b8; font-weight: bold;",
                     icon("music"), " Parámetros ToBI"),
        numericInput("tobi_umbral_significativo", "Mov. significativo (St):", value = 1.5, min = 0.5, max = 5, step = 0.1),
        numericInput("tobi_umbral_extralto", "Extra-alto (St):", value = 6.0, min = 2, max = 12, step = 0.5),
        numericInput("tobi_tercio_bajo", "Tercio bajo:", value = 0.33, min = 0.1, max = 0.5, step = 0.01),
        numericInput("tobi_tercio_alto", "Tercio alto:", value = 0.66, min = 0.5, max = 0.9, step = 0.01)
      ),
      
      tags$details(
        tags$summary(style = "cursor: pointer; color: #ffc107; font-weight: bold;",
                     icon("chart-area"), " Parámetros AMH"),
        numericInput("amh_ascenso_fuerte", "Ascenso fuerte (\u2265%):", value = 70, min = 30, max = 100, step = 5),
        numericInput("amh_ascenso_moderado", "Ascenso moderado (\u2265%):", value = 40, min = 15, max = 80, step = 5),
        numericInput("amh_ascenso_leve", "Ascenso leve (\u2265%):", value = 15, min = 5, max = 40, step = 1),
        numericInput("amh_ascenso_minimo", "Ascenso mínimo (\u2265%):", value = 10, min = 2, max = 20, step = 1),
        numericInput("amh_descenso_moderado", "Desc. moderado (<%):", value = -15, min = -50, max = 0, step = 1),
        numericInput("amh_descenso_fuerte", "Desc. fuerte (<%):", value = -40, min = -80, max = -10, step = 5),
        hr(),
        numericInput("amh_enfasis_pct", "Énfasis cuerpo (%):", value = 30, min = 10, max = 60, step = 5),
        numericInput("amh_circunflejo_pct", "Circunflejo (%):", value = 20, min = 5, max = 50, step = 5)
      ),
      
      hr(),
      h5("Estado"),
      verbatimTextOutput("estado")
    )
    )
  )
}

