        .etiq-sidebar { max-height: calc(100vh - 80px); overflow-y: auto; }
        .etiq-emocion-label { font-size: 15px; font-weight: 600; color: #333; margin-top: 6px; display: block; }
        .etiq-emoji-row { display: flex; justify-content: center; flex-wrap: wrap; gap: 4px; margin: 6px 0; }
        .fila-actual { background-color: #dbeafe !important; font-weight: bold; }
        .fila-acto { background-color: #d4edda !important; }
        .likert-btn { width: 50px; height: 50px; font-size: 22px; margin: 3px; border-radius: 50%;
                      border: 2px solid #ccc; cursor: pointer; background: #f8f9fa; transition: all 0.2s; }
        .likert-btn:hover { background: #e2e6ea; }
        .likert-btn.selected { border-color: var(--slate-600); background: var(--slate-50); font-weight: bold; }
        .etiq-progreso { font-size: 14px; padding: 6px 12px; background: var(--slate-50); border-radius: 5px; }
        .acto-badge { display: inline-block; padding: 2px 8px; border-radius: 10px; font-size: 11px;
                      background: var(--slate-500); color: white; margin-left: 4px; }
        /* Prevent card/table overflow */
        .card-body { overflow-x: auto; }
        .dataTables_wrapper { overflow-x: auto; }
        .tab-content { overflow-x: auto; }

        /* ── Scroll fix ──────────────────────────────────────────────────
           Evita que overlays de Shiny (recalculating, busy) y widgets
           bloqueen el scroll de la página.
        ---------------------------------------------------------------- */
        html, body { overflow-y: auto !important; height: auto !important; }

        /* Solo los outputs individuales que recalculan bloquean eventos,
           NO toda la página (.shiny-busy en <html> bloqueaba todos los botones) */
        .shiny-html-output.recalculating    { pointer-events: none !important; }
        .shiny-output-error                 { pointer-events: none !important; }

        /* Iconos dentro de botones no deben absorber el clic (FA + svg) */
        .btn i, .btn svg, .btn .fa, .btn .fas, .btn .far,
        .btn .fab, .btn .fal, .btn span.sr-only { pointer-events: none; }

        /* Plotly/htmlwidgets: scroll del ratón va a la página, no al widget */
        .js-plotly-plot .plotly,
        .plotly .main-svg                   { pointer-events: auto; }
        .html-widget-static-bound           { pointer-events: auto; }

        /* El modal de Bootstrap no debe bloquear scroll del body al cerrarse */
        body.modal-open                     { overflow-y: auto !important; padding-right: 0 !important; }

        /* Scrollbar accent */
        ::-webkit-scrollbar-thumb { background: var(--slate-400); border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: var(--slate-600); }
        ::-webkit-scrollbar { width: 8px; height: 8px; }
      ")),
    # JS: restaurar scroll si queda bloqueado tras cerrar modal o actualizar plotly
