# ========================================
# SERVIDOR
# ========================================
server <- function(input, output, session) {
  options(shiny.maxRequestSize = 1000*1024^2)

  # ── Helper: ruta al Python del virtualenv bert-env (cross-platform) ──────────
  # Windows: Scripts\python.exe  |  Unix/Mac: bin/python3
  .python_venv_path <- local({
    home <- Sys.getenv("HOME")
    if (nchar(home) == 0) home <- Sys.getenv("USERPROFILE")  # Windows fallback
    if (.Platform$OS.type == "windows") {
      file.path(home, ".virtualenvs", "bert-env", "Scripts", "python.exe")
    } else {
      file.path(home, ".virtualenvs", "bert-env", "bin", "python3")
    }
  })
  # Candidatos adicionales de Python en Windows (python.exe vs python3)
  .python_sys_candidates <- if (.Platform$OS.type == "windows") {
    c(Sys.which("python3"), Sys.which("python"))
  } else {
    c(Sys.which("python3"), "/usr/local/bin/python3", "/usr/bin/python3")
  }

  # ── Panel diagnóstico Python ─────────────────────────────────────────────────
  rv_diagnostico <- reactiveVal(NULL)

  # Ejecutar diagnóstico al pulsar el botón o al arrancar (una sola vez)
  run_diagnostico <- function() {
    py_bin <- NA_character_
    for (py in c(.python_venv_path, .python_sys_candidates)) {
      if (nchar(py) > 0 && file.exists(py)) { py_bin <- py; break }
    }
    if (is.na(py_bin)) {
      # último intento: which python
      py_bin <- tryCatch(system("which python3 2>/dev/null || which python 2>/dev/null",
                                intern = TRUE)[1], error = function(e) NA_character_)
    }

    check_lib <- function(lib) {
      if (is.na(py_bin)) return("sin Python")
      ret <- system2(py_bin, args = c("-c", shQuote(paste0("import ", lib))),
                     stdout = FALSE, stderr = FALSE)
      if (ret == 0) "OK" else "NO"
    }

    ffmpeg_ok <- nchar(Sys.which("ffmpeg")) > 0

    list(
      py_bin     = if (!is.na(py_bin)) py_bin else "(no encontrado)",
      whisperx   = check_lib("whisperx"),
      pyannote   = check_lib("pyannote.audio"),
      parselmouth = check_lib("parselmouth"),
      pysentimiento = check_lib("pysentimiento"),
      funasr     = check_lib("funasr"),
      ffmpeg     = if (ffmpeg_ok) "OK" else "NO",
      ts         = format(Sys.time(), "%H:%M:%S")
    )
  }

  observeEvent(input$btn_diagnostico_python, {
    rv_diagnostico(NULL)  # spinner
    isolate({ rv_diagnostico(run_diagnostico()) })
  }, ignoreNULL = TRUE)

  # Ejecutar diagnóstico inicial al arrancar la sesión (sin bloquear UI)
  observe({
    req(is.null(rv_diagnostico()))
    later::later(function() {
      tryCatch(rv_diagnostico(run_diagnostico()), error = function(e) NULL)
    }, delay = 2)
  })

  # ── Handoff desde Etiquetador Oral ──────────────────────────────────────────
  etiquetador_handoff_rv <- reactiveVal(NULL)
  etiquetador_handoff_ok <- reactiveVal(FALSE)

  mostrar_modal_etiquetador <- function(bundle) {
    n_seg   <- if (!is.null(bundle$anotaciones)) nrow(bundle$anotaciones) else 0
    has_tg  <- isTRUE(!is.null(bundle$tg_path)   && file.exists(bundle$tg_path))
    has_pit <- isTRUE(!is.null(bundle$pitch_path) && file.exists(bundle$pitch_path))
    has_int <- isTRUE(!is.null(bundle$int_path)   && file.exists(bundle$int_path))
    # Pasar session explícitamente para funcionar dentro de later::later()
    showModal(
      modalDialog(
        title = tagList(icon("arrow-circle-right"), " Datos del Etiquetador Oral detectados"),
        p("Se ha encontrado un análisis del ", tags$strong("Etiquetador Oral"),
          " listo para importar:"),
        tags$ul(
          tags$li(tags$b("Archivo: "),
                  basename(if (!is.null(bundle$trans_name)) bundle$trans_name else "desconocido")),
          tags$li(tags$b("Segmentos anotados: "), n_seg),
          tags$li(tags$b("Método acústico: "), bundle$metodo),
          tags$li(tags$b("Pitch pre-computado: "), if (has_pit) "Sí" else "No"),
          tags$li(tags$b("Intensidad pre-computada: "), if (has_int) "Sí" else "No"),
          tags$li(tags$b("TextGrid disponible: "),
                  if (has_tg) "Sí" else "No (se puede añadir manualmente)")
        ),
        p(tags$em("Al aceptar, se cargarán el audio, el TextGrid (si existe), los datos acústicos ",
                  "pre-computados y las anotaciones discursivas (anot1–anot33).")),
        easyClose = FALSE,
        footer = tagList(
          actionButton("cargar_desde_etiquetador", "Sí, cargar y analizar",
                       icon = icon("check"), class = "btn-primary"),
          actionButton("rechazar_etiquetador", "No, continuar sin cargar",
                       class = "btn-default")
        )
      ),
      session = session   # explícito: evita fallo fuera del dominio reactivo
    )
  }

  # Detectar handoff al arrancar — dentro del observe (dominio reactivo correcto)
  # invalidateLater da el delay sin salir del contexto reactivo
  etiquetador_handoff_checked <- reactiveVal(FALSE)
  observe({
    req(!etiquetador_handoff_checked())
    etiquetador_handoff_checked(TRUE)
    invalidateLater(2500)  # esperar 2.5 s a que la UI esté lista
  })
  observe({
    req(etiquetador_handoff_checked())
    req(!etiquetador_handoff_ok())
    etiquetador_handoff_ok(TRUE)
    hf <- path.expand("~/.etiquetador_handoff.rds")
    if (file.exists(hf)) {
      bundle <- tryCatch(readRDS(hf), error = function(e) NULL)
      if (!is.null(bundle)) {
        etiquetador_handoff_rv(bundle)
        mostrar_modal_etiquetador(bundle)
      }
    }
  })

  # Botón manual de importación
  observeEvent(input$btn_importar_etiquetador, {
    hf <- path.expand("~/.etiquetador_handoff.rds")
    if (file.exists(hf)) {
      bundle <- tryCatch(readRDS(hf), error = function(e) NULL)
      if (!is.null(bundle)) {
        etiquetador_handoff_rv(bundle)
        mostrar_modal_etiquetador(bundle)
        return()
      }
    }
    showNotification("No hay datos pendientes del Etiquetador Oral.", type = "warning", duration = 4)
  })

  observeEvent(input$cargar_desde_etiquetador, {
    bundle <- etiquetador_handoff_rv()
    req(!is.null(bundle))
    removeModal()
    withProgress(message = "Cargando datos del Etiquetador Oral...", {
      tryCatch({
        base_name <- tools::file_path_sans_ext(
          basename(if (!is.null(bundle$trans_name)) bundle$trans_name else "etiquetador"))

        # 1. Audio: copiar a lasp_audios y registrar en datos_audio
        if (!is.null(bundle$wav_path) && file.exists(bundle$wav_path)) {
          incProgress(0.2, detail = "Audio...")
          wav_dest <- file.path(lasp_audios, paste0(base_name, ".wav"))
          file.copy(bundle$wav_path, wav_dest, overwrite = TRUE)
          datos_audio$wavs[[base_name]] <- wav_dest
        }

        # 2. TextGrid: copiar a lasp_textgrids y registrar en datos_textgrid + pm_archivos
        if (!is.null(bundle$tg_path) && file.exists(bundle$tg_path)) {
          incProgress(0.15, detail = "TextGrid...")
          tg_dest <- file.path(lasp_textgrids, paste0(base_name, ".TextGrid"))
          file.copy(bundle$tg_path, tg_dest, overwrite = TRUE)
          datos_textgrid$tgs[[base_name]] <- tg_dest
          pm_archivos$wavs[[base_name]]   <- if (!is.null(datos_audio$wavs[[base_name]]))
                                               datos_audio$wavs[[base_name]] else bundle$wav_path
          pm_archivos$tgs[[base_name]]    <- tg_dest
        }

        # 3. Pitch pre-computado (columna time → tiempo para esquema Oralstats)
        if (!is.null(bundle$pitch_path) && file.exists(bundle$pitch_path)) {
          incProgress(0.2, detail = "Pitch...")
          pd <- read.table(bundle$pitch_path, header = TRUE, sep = "\t",
                           stringsAsFactors = FALSE)
          if ("time" %in% names(pd)) names(pd)[names(pd) == "time"] <- "tiempo"
          datos$pitch <- pd
        }

        # 4. Intensidad pre-computada (time → tiempo, intensity → intensidad)
        if (!is.null(bundle$int_path) && file.exists(bundle$int_path)) {
          incProgress(0.1, detail = "Intensidad...")
          id_df <- read.table(bundle$int_path, header = TRUE, sep = "\t",
                              stringsAsFactors = FALSE)
          if ("time"      %in% names(id_df)) names(id_df)[names(id_df) == "time"]      <- "tiempo"
          if ("intensity" %in% names(id_df)) names(id_df)[names(id_df) == "intensity"] <- "intensidad"
          datos$intensidad <- id_df
        }

        # 5. Anotaciones discursivas (anot1–anot33 + start/end/speaker/label)
        if (!is.null(bundle$anotaciones)) {
          incProgress(0.1, detail = "Anotaciones...")
          datos$anotaciones <- bundle$anotaciones
        }

        incProgress(0.25, detail = "Listo")

        # Eliminar handoff para evitar recargas en próximas sesiones
        hf <- path.expand("~/.etiquetador_handoff.rds")
        if (file.exists(hf)) file.remove(hf)
        etiquetador_handoff_rv(NULL)

        n_seg <- if (!is.null(bundle$anotaciones)) nrow(bundle$anotaciones) else 0
        showNotification(
          sprintf(
            paste0("Etiquetador Oral cargado: %d segmentos. ",
                   "Audio: %s | TextGrid: %s | Pitch: %s | Anotaciones: %s. ",
                   "Pulsa 'Ejecutar Parselmouth' (o R nativo) para el análisis completo."),
            n_seg,
            if (!is.null(datos_audio$wavs[[base_name]])) "OK" else "no encontrado",
            if (!is.null(datos_textgrid$tgs[[base_name]])) "OK" else "no encontrado",
            if (!is.null(datos$pitch)) "pre-cargado" else "por calcular",
            if (!is.null(datos$anotaciones)) "cargadas" else "no"
          ),
          type = "message", duration = 12
        )
      }, error = function(e) {
        showNotification(paste("Error cargando datos del Etiquetador:", e$message),
                         type = "error", duration = 8)
      })
    })
  })

  observeEvent(input$rechazar_etiquetador, {
    removeModal()
    hf <- path.expand("~/.etiquetador_handoff.rds")
    if (file.exists(hf)) file.remove(hf)
    etiquetador_handoff_rv(NULL)
  })

  # ── Etiquetado manual: fileInput ─────────────────────────────────────────────

  # Reactive: datos del Etiquetador cargados via fileInput (tab Etiquetado manual)
  etiq_manual_rv  <- reactiveVal(NULL)   # data.frame raw del archivo
  etiq_manual_ge  <- reactiveVal(NULL)   # sólo filas de GE (speaker != words/phones)

  ETIQ_COLS_ACUSTICAS <- c("F0_mean","F0_range_st","F0_delta_st","F0_final_delta_st","F0_final_pattern",
                            "Int_mean","F0_ini_q1","F0_ini_q2","F0_ini_q3","F0_ini_q4",
                            "F0_fin_q1","F0_fin_q2","F0_fin_q3","F0_fin_q4",
                            "Int_ini_q1","Int_ini_q2","Int_ini_q3","Int_ini_q4",
                            "Int_fin_q1","Int_fin_q2","Int_fin_q3","Int_fin_q4")
  ETIQ_COLS_ANOT      <- paste0("anot", 1:33)

  observeEvent(input$etiq_manual_file, {
    req(input$etiq_manual_file)
    tryCatch({
      df <- read.table(input$etiq_manual_file$datapath,
                       sep = "\t", header = TRUE, stringsAsFactors = FALSE,
                       fileEncoding = "UTF-8", quote = "", na.strings = "")
      etiq_manual_rv(df)
      # Filtrar filas que son GEs (speaker no es tier sintético words/phones)
      if ("speaker" %in% names(df)) {
        ge_rows <- df[!df$speaker %in% c("words", "phones", "Words", "Phones"), , drop = FALSE]
        # TextGrids MFA de un solo hablante: el tier se llama "words" a secas y el
        # Etiquetador usa ese nombre como speaker de todas las IPs. En ese caso
        # todas las filas son GEs y no hay que descartar ninguna.
        if (nrow(ge_rows) == 0) ge_rows <- df
      } else {
        ge_rows <- df
      }
      etiq_manual_ge(ge_rows)
      shinyjs::enable("etiq_manual_vincular")
    }, error = function(e) {
      etiq_manual_rv(NULL); etiq_manual_ge(NULL)
      showNotification(paste("Error leyendo archivo:", e$message), type = "error", duration = 6)
    })
  })

