  output$etiq_manual_vincular_status <- renderUI({ NULL })

  observeEvent(input$etiq_manual_vincular, {
    ge  <- etiq_manual_ge()
    ips <- datos$ips_resumen
    req(ge, nrow(ge) > 0, !is.null(ips), nrow(ips) > 0)

    withProgress(message = "Vinculando con grupos entonativos...", value = 0, {
      incProgress(0.3)
      cols_unir <- intersect(c(ETIQ_COLS_ACUSTICAS, ETIQ_COLS_ANOT,
                                if ("observaciones" %in% names(ge)) "observaciones"),
                             names(ge))
      if (length(cols_unir) == 0) {
        output$etiq_manual_vincular_status <- renderUI(
          div(style = "color:#dc2626; font-size:0.82em; margin-top:6px;",
              icon("times-circle"), " No se encontraron columnas compatibles para vincular.")
        )
        return()
      }

      # Renombrar speaker → hablante, start → inicio, end → fin para el join
      ge_join <- ge
      if ("speaker" %in% names(ge_join)) ge_join$hablante_etiq <- ge_join$speaker
      if ("start"   %in% names(ge_join)) ge_join$inicio_etiq   <- as.numeric(ge_join$start)
      if ("end"     %in% names(ge_join)) ge_join$fin_etiq       <- as.numeric(ge_join$end)

      # Eliminar columnas previas del Etiquetador en ips para evitar duplicados
      ips_clean <- ips[, setdiff(names(ips), cols_unir), drop = FALSE]

      # Inicializar columnas vacías en ips (F0_final_pattern es texto: PDA/PPD...)
      for (col in cols_unir) {
        if (col %in% ETIQ_COLS_ACUSTICAS && col != "F0_final_pattern") {
          ips_clean[[col]] <- NA_real_
        } else {
          ips_clean[[col]] <- NA_character_
        }
      }

      # Si el nombre del archivo coincide con un filename de ips_resumen,
      # restringir el join a ese archivo (evita colisiones temporales entre archivos)
      idx_pool <- seq_len(nrow(ips_clean))
      if ("filename" %in% names(ips_clean) && !is.null(input$etiq_manual_file$name)) {
        base_etiq <- sub("^analisis_", "",
                         tools::file_path_sans_ext(basename(input$etiq_manual_file$name)))
        if (base_etiq %in% ips_clean$filename) idx_pool <- which(ips_clean$filename == base_etiq)
      }
      # Hablantes del Etiquetador que existen en Oralstats; si no hay ninguna
      # correspondencia (p. ej. tier MFA llamado "words"), se vincula solo por tiempo
      habl_os <- unique(as.character(ips_clean$hablante[idx_pool]))

      # Join por hablante + coincidencia temporal (tolerancia 0.05 s); si no hay
      # coincidencia exacta, se asigna al GE con mayor solapamiento temporal
      # (≥ 50 % del segmento más corto), porque las segmentaciones del Etiquetador
      # (pausas del tier words de MFA) y de Oralstats pueden diferir.
      TOL <- 0.05
      n_vinc <- 0L
      for (i in seq_len(nrow(ge_join))) {
        spk    <- ge_join$hablante_etiq[i]
        t_ini  <- ge_join$inicio_etiq[i]
        t_fin  <- ge_join$fin_etiq[i]
        if (is.na(t_ini) || is.na(t_fin)) next
        spk_ok <- if (is.na(spk) ||
                      !any(habl_os == spk | grepl(spk, habl_os, fixed = TRUE), na.rm = TRUE)) {
          rep(TRUE, length(idx_pool))
        } else {
          ips_clean$hablante[idx_pool] == spk |
            grepl(spk, ips_clean$hablante[idx_pool], fixed = TRUE)
        }
        cand <- idx_pool[!is.na(spk_ok) & spk_ok]
        if (length(cand) == 0) next
        idx <- cand[abs(ips_clean$inicio[cand] - t_ini) <= TOL &
                    abs(ips_clean$fin[cand]    - t_fin) <= TOL]
        if (length(idx) == 0) {
          ov      <- pmin(ips_clean$fin[cand], t_fin) - pmax(ips_clean$inicio[cand], t_ini)
          dur_min <- pmin(ips_clean$fin[cand] - ips_clean$inicio[cand], t_fin - t_ini)
          ok <- which(!is.na(ov) & ov > 0 & ov >= 0.5 * dur_min)
          if (length(ok) > 0) idx <- cand[ok[which.max(ov[ok])]]
        }
        if (length(idx) == 0) next
        for (col in cols_unir) {
          if (col %in% names(ge_join)) ips_clean[idx[1], col] <- ge_join[[col]][i]
        }
        n_vinc <- n_vinc + 1L
      }

      incProgress(0.7)
      datos$ips_resumen <- ips_clean
      output$etiq_manual_vincular_status <- renderUI(
        div(style = "background:#f0fdf4; border:1px solid #16a34a; border-radius:6px; padding:6px 10px; font-size:0.82em; margin-top:6px;",
            icon("check-circle", style = "color:#16a34a;"),
            sprintf(" %d GEs vinculados · %d variables añadidas a ips_resumen", n_vinc, length(cols_unir)))
      )
      showNotification(
        sprintf("Etiquetador vinculado: %d GEs · %d variables nuevas en el dataset.", n_vinc, length(cols_unir)),
        type = "message", duration = 6)
    })
  })

