  # ── Bienvenida: análisis recientes (carga diferida para no bloquear el inicio) ──
  # Función ligera: ordena por mtime del SO (sin leer RDS) y solo lee los N .meta.rds
  # más recientes, evitando escanear cientos de archivos.
  listar_recientes_rapido <- function(n = 4) {
    generos <- c("peliculas", "series", "interpretacion", "entrevistas", "conversaciones")
    # Recoger todos los .meta.rds con su mtime sin leerlos
    all_meta <- unlist(lapply(generos, function(gen) {
      d <- file.path(lasp_analisis, gen)
      if (!dir.exists(d)) return(character(0))
      list.files(d, pattern = "\\.meta\\.rds$", full.names = TRUE)
    }))
    if (length(all_meta) == 0) return(NULL)
    mtimes <- file.info(all_meta)$mtime
    # Ordenar por fecha desc y quedarnos solo con los N primeros
    top_idx  <- order(mtimes, decreasing = TRUE)[seq_len(min(n, length(all_meta)))]
    top_meta <- all_meta[top_idx]
    top_time <- mtimes[top_idx]
    rows <- lapply(seq_along(top_meta), function(i) {
      mf  <- top_meta[i]
      rds <- sub("\\.meta\\.rds$", ".rds", mf)
      tryCatch({
        obj  <- readRDS(mf)
        data.frame(
          Nombre        = tools::file_path_sans_ext(basename(rds)),
          Fecha         = format(top_time[i], "%d/%m/%Y %H:%M"),
          FechaNumerica = as.numeric(top_time[i]),
          N_IPs         = if (!is.null(obj$n_ips)) obj$n_ips else 0L,
          Ruta          = rds,
          stringsAsFactors = FALSE
        )
      }, error = function(e) NULL)
    })
    rows <- Filter(Negate(is.null), rows)
    if (length(rows) == 0) return(NULL)
    do.call(rbind, rows)
  }

  rv_recientes        <- reactiveVal(NULL)
  recientes_escaneado <- reactiveVal(FALSE)   # garantiza que el escaneo corra una sola vez
  preloader_oculto    <- reactiveVal(FALSE)

  # Oculta el preloader de arranque (idempotente): una vez la app está operativa.
  ocultar_preloader <- function() {
    if (!isTRUE(preloader_oculto())) {
      preloader_oculto(TRUE)
      tryCatch(waiter::waiter_hide(), error = function(e) NULL)
    }
  }

  # Salvaguarda: oculta el preloader a los ~20 s pase lo que pase, por si el
  # escaneo de inicio fallara, para no dejar la app bloqueada tras el overlay.
  app_arranque_t <- Sys.time()
  observe({
    if (isTRUE(preloader_oculto())) return()   # ya oculto: detener el timer
    invalidateLater(5000)                      # comprobar cada 5 s
    isolate({
      if (as.numeric(difftime(Sys.time(), app_arranque_t, units = "secs")) >= 20)
        ocultar_preloader()
    })
  })

  observe({
    if (isTRUE(recientes_escaneado())) return()   # ya escaneado: no repetir cada 50 ms
    invalidateLater(50)    # mínimo necesario para que la UI se pinte antes del escaneo
    isolate({
      # 1. Intentar caché local (~/.oralstats_recientes.rds) — instantáneo
      df <- tryCatch({
        if (file.exists(cache_recientes_path)) {
          cached <- readRDS(cache_recientes_path)
          if (is.data.frame(cached) && nrow(cached) > 0 &&
              all(c("Nombre","Fecha","FechaNumerica","N_IPs","Ruta") %in% colnames(cached)))
            cached
          else NULL
        } else NULL
      }, error = function(e) NULL)
      # 2. Fallback: escanear directorios (más lento, solo si no hay caché)
      if (is.null(df))
        df <- tryCatch(listar_recientes_rapido(4), error = function(e) NULL)
      rv_recientes(df)
      recientes_escaneado(TRUE)   # marca el escaneo como hecho → el observe deja de repetirse
      ocultar_preloader()         # la pantalla de inicio ya está poblada: retirar "Cargando…"
    })
  })

