  .nav_ge <- function(dir) {
    ips <- isolate(tryCatch(ips_filtrados(), error = function(e) NULL))
    if (is.null(ips) || nrow(ips) == 0) return()
    if (isTRUE(isolate(input$tipo_vista_grupo) == "entonativo")) {
      gf_sel   <- as.numeric(isolate(input$sel_gf))
      ips_gf   <- ips[ips$grupo_fonico == gf_sel, ]
      ges_disp <- sort(unique(ips_gf$grupo_entonativo))
      if (!length(ges_disp)) return()
      ge_cur <- as.numeric(isolate(input$sel_ge))
      idx    <- which(ges_disp == ge_cur); if (!length(idx)) idx <- 1L
      new_i  <- idx + if (dir == "next") 1L else -1L
      if (new_i < 1L) {
        gfs  <- sort(unique(ips$grupo_fonico))
        gi   <- which(gfs == gf_sel)
        if (gi > 1L) {
          ng <- gfs[gi - 1L]
          updateSelectInput(session, "sel_gf", selected = ng)
          Sys.sleep(0.05)
          ges_ng <- sort(unique(ips$grupo_entonativo[ips$grupo_fonico == ng]))
          if (length(ges_ng)) updateSelectInput(session, "sel_ge", selected = max(ges_ng))
        }
      } else if (new_i > length(ges_disp)) {
        gfs <- sort(unique(ips$grupo_fonico))
        gi  <- which(gfs == gf_sel)
        if (gi < length(gfs)) {
          ng <- gfs[gi + 1L]
          updateSelectInput(session, "sel_gf", selected = ng)
          Sys.sleep(0.05)
          ges_ng <- sort(unique(ips$grupo_entonativo[ips$grupo_fonico == ng]))
          if (length(ges_ng)) updateSelectInput(session, "sel_ge", selected = min(ges_ng))
        }
      } else {
        updateSelectInput(session, "sel_ge", selected = ges_disp[new_i])
      }
    } else {
      gfs <- sort(unique(ips$grupo_fonico))
      gi  <- which(gfs == as.numeric(isolate(input$sel_gf))); if (!length(gi)) gi <- 1L
      ni  <- max(1L, min(length(gfs), gi + if (dir=="next") 1L else -1L))
      updateSelectInput(session, "sel_gf", selected = gfs[ni])
    }
  }
  observeEvent(input$btn_ge_next, { .nav_ge("next") })
  observeEvent(input$btn_ge_prev, { .nav_ge("prev") })
  observeEvent(input$ge_nav_key,  { .nav_ge(input$ge_nav_key) }, ignoreNULL = TRUE)



  # ── Helper: estilo unificado para tablas DT ─────────────────────────
  lasp_dt <- function(df, page_len = 15, heatmap_cols = NULL, filter = "top") {
    if (is.null(df) || nrow(df) == 0)
      return(datatable(data.frame(Info = "Sin datos"), options = list(dom = "t")))
    # Redondear numéricas a 2 decimales
    nums <- names(df)[sapply(df, is.numeric)]
    df[nums] <- lapply(df[nums], function(x) round(x, 2))
    dt <- datatable(df,
      options = list(
        scrollX = TRUE, pageLength = page_len,
        dom = "ftipr",
        initComplete = JS(
          "function(settings,json){",
          "  $(this.api().table().header()).css({'background-color':'#0C447C','color':'#eff6ff','font-size':'12px'});",
          "}"
        )
      ),
      filter = filter, rownames = FALSE,
      class = "stripe hover compact"
    )
    # Heatmap automático en columnas de F0 e intensidad
    auto_heat <- intersect(c("f0_media_hz","f0_media_st","f0_media_grupo_st",
                              "int_media","intensidad_media_grupo",
                              "rango_f0_st","f0_rango_st","velocidad_habla",
                              "duracion","n_vocales"),
                           names(df))
    heat_cols <- unique(c(auto_heat, if (!is.null(heatmap_cols)) heatmap_cols))
    for (col in heat_cols) {
      v <- df[[col]]
      if (!is.numeric(v) || all(is.na(v)) || diff(range(v, na.rm=TRUE)) == 0) next
      dt <- dt |> formatStyle(col,
        background = styleColorBar(range(v, na.rm=TRUE), "#bfdbfe"),
        backgroundSize = "100% 70%", backgroundRepeat = "no-repeat",
        backgroundPosition = "center")
    }
    dt
  }


  
