    hablantes = data.frame(hablante = character(), edad = numeric(), sexo = character(),
                           nivel = character(), profesion = character(), l1 = character(),
                           origen = character(), edad_adq = numeric(), notas = character(),
                           stringsAsFactors = FALSE)
  )
  
  # Consenso inter-jueces
  consenso <- reactiveValues(
    jueces_data = list(),      # lista de data.frames de validacion por juez
    etiquetado_orig = NULL,    # etiquetado original del investigador (importado manualmente)
    evaluacion_base = NULL,    # muestra de la evaluacion (con emocion_original del investigador)
    resultados = NULL,         # resultados de acuerdo
    consenso_final = NULL      # etiquetas consensuadas
  )
  
  # reactiveValues para archivos WAV de sentimientos
  sent_wavs  <- reactiveValues(paths = list(), dir = NULL)
  # Estado del proceso Python de sentimientos (no bloqueante, sin pipes)
  sent_proc_rv <- reactiveValues(
    log_file     = NULL,   # salida Python (stdout+stderr) → fichero
    done_file    = NULL,   # fichero creado al terminar Python
    output_file  = NULL,   # TSV de resultados de pysentimiento
    output_lines = character(0),
    lines_read   = 0L,
    poll_active  = FALSE
  )
  
  # ========================================
  # ALMACENAMIENTO PERSISTENTE
  # ========================================
  
  # Directorios persistentes dentro del directorio de la app
  lasp_base <- file.path(getwd(), "lasp_datos")
  lasp_analisis <- file.path(lasp_base, "analisis")
  lasp_audios <- file.path(lasp_base, "audios")
  lasp_textgrids <- file.path(lasp_base, "textgrids")
  lasp_etiquetado <- file.path(lasp_base, "etiquetado")
  lasp_preprocesados <- file.path(lasp_base, "preprocesados")
      lasp_validaciones     <- file.path(lasp_base, "validaciones")
  lasp_val_evaluaciones <- file.path(lasp_validaciones, "evaluaciones")
lasp_val_jueces       <- file.path(lasp_validaciones, "jueces")

    lasp_logs <- file.path(lasp_base, "logs")

  dir.create(lasp_analisis, recursive = TRUE, showWarnings = FALSE)
  dir.create(lasp_audios, recursive = TRUE, showWarnings = FALSE)
  dir.create(lasp_textgrids, recursive = TRUE, showWarnings = FALSE)
  dir.create(lasp_etiquetado, recursive = TRUE, showWarnings = FALSE)
  dir.create(lasp_preprocesados, recursive = TRUE, showWarnings = FALSE)
  dir.create(lasp_logs, recursive = TRUE, showWarnings = FALSE)
dir.create(lasp_val_evaluaciones, recursive = TRUE, showWarnings = FALSE)
dir.create(lasp_val_jueces,       recursive = TRUE, showWarnings = FALSE)
  
  # ========================================
  # SESSION LOG SYSTEM
  # ========================================
  session_log <- reactiveValues(
    entries = character(0),
    file = file.path(lasp_logs, paste0("session_", format(Sys.time(), "%Y%m%d_%H%M%S"), ".log"))
  )
  
  log_event <- function(accion, detalle = "") {
    ts <- format(Sys.time(), "%H:%M:%S")
    entry <- if (nchar(detalle) > 0) paste0("[", ts, "] ", accion, " | ", detalle) else paste0("[", ts, "] ", accion)
    isolate({ session_log$entries <- c(session_log$entries, entry) })
    # Escribir a archivo
    tryCatch(cat(entry, "\n", file = isolate(session_log$file), append = TRUE), error = function(e) NULL)
  }
  
  log_event("SESION_INICIADA", paste("Usuario:", Sys.info()["user"], "| Dir:", getwd()))
  
  output$session_log_display <- renderUI({
    entries <- session_log$entries
    if (length(entries) == 0) return(tags$em("Sin actividad registrada"))
    # Mostrar últimas 50 entradas, más recientes arriba
    entries_show <- rev(tail(entries, 50))
    tags$pre(style = "margin: 0; white-space: pre-wrap;", paste(entries_show, collapse = "\n"))
  })
  
  output$descargar_log <- downloadHandler(
    filename = function() paste0("lasp_log_", format(Sys.time(), "%Y%m%d_%H%M%S"), ".txt"),
    content = function(file) writeLines(session_log$entries, file)
  )
  
  observeEvent(input$limpiar_log, {
    session_log$entries <- character(0)
    log_event("LOG_LIMPIADO")
  })
  
  # Estado breve para panel Crear
  output$estado_crear <- renderText({
    if (datos$calculado) {
      n_ph <- if (!is.null(datos$phones)) nrow(datos$phones) else 0
      n_ip <- if (!is.null(datos$ips_resumen)) nrow(datos$ips_resumen) else 0
      paste0("\u2714 ", n_ph, " vocales | ", n_ip, " GEs")
    } else {
      "Sin datos calculados"
    }
  })
  
  # ========================================
  # AUTO-SAVE: guardar automáticamente tras cada modificación
  # ========================================
  # ── Caché local de análisis recientes ──────────────────────────────────────
  # Guardado en home (~/.oralstats_recientes.rds), FUERA de iCloud,
  # para que el arranque sea instantáneo sin escanear directorios remotos.
  cache_recientes_path <- file.path(Sys.getenv("HOME"), ".oralstats_recientes.rds")

  actualizar_cache_recientes <- function(nombre, ruta, n_ips = 0L) {
    tryCatch({
      entrada <- data.frame(
        Nombre        = as.character(nombre),
        Fecha         = format(Sys.time(), "%d/%m/%Y %H:%M"),
        FechaNumerica = as.numeric(Sys.time()),
        N_IPs         = as.integer(n_ips),
        Ruta          = as.character(ruta),
        stringsAsFactors = FALSE
      )
      prev <- if (file.exists(cache_recientes_path))
                tryCatch(readRDS(cache_recientes_path), error = function(e) NULL)
              else NULL
      # Eliminar entradas anteriores del mismo archivo y añadir la nueva
      if (!is.null(prev) && is.data.frame(prev))
        prev <- prev[prev$Nombre != nombre, , drop = FALSE]
      combinado <- rbind(entrada, prev)
      # Conservar solo los 8 más recientes
      combinado <- combinado[order(combinado$FechaNumerica, decreasing = TRUE), ]
      combinado <- head(combinado, 8)
      saveRDS(combinado, cache_recientes_path)
    }, error = function(e) NULL)   # silencioso: no bloquear el guardado principal
  }

  auto_guardar <- function(motivo = "auto") {
    if (!datos$calculado) return()
    if (isTRUE(datos$cargado_desde_storage)) return()  # no re-guardar análisis cargados
    tryCatch({
      gen <- if (!is.null(datos$genero_discursivo)) datos$genero_discursivo else "entrevistas"
      fns_ag <- if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones))
                  sort(unique(datos$phones$filename)) else character(0)
      for (fn_ag in fns_ag) guardar_analisis_por_archivo(fn_ag, genero = gen, notificar = FALSE)
      if (length(fns_ag) > 0)
        showNotification(paste0("✔ Auto-guardado: ", length(fns_ag), " archivo(s)"), type = "message", duration = 2)
      log_event("AUTO_GUARDADO", paste0(motivo, " [", length(fns_ag), " archivos]"))
    }, error = function(e) {
      log_event("AUTO_GUARDADO_ERROR", e$message)
    })
  }
  
  # Crear subcarpetas por género
  for (gen in c("peliculas", "series", "interpretacion", "entrevistas", "conversaciones")) {
    dir.create(file.path(lasp_analisis, gen), showWarnings = FALSE)
  }
  
  # Función: guardar análisis a almacenamiento persistente
  # Helper: seleccionar índices de tiers phones/words para un hablante dado
  # Usa rPraat si disponible; si falla, construye nombres esperados directamente
  seleccionar_tiers_hablante <- function(tg_path, hablante = NULL) {
    tryCatch({
      tg <- rPraat::tg.read(tg_path, encoding = "UTF-8")
      tier_names <- rPraat::tg.listOfTiers(tg)
      message("[praatpicture] Tiers en TG: ", paste(tier_names, collapse = ", "))
      message("[praatpicture] Hablante buscado: ", hablante)

      # Identificar qu\u00e9 tiers son phones/words y a qu\u00e9 hablante pertenecen
      tier_type   <- rep(NA_character_, length(tier_names))
      tier_speaker <- rep(NA_character_, length(tier_names))

      for (i in seq_along(tier_names)) {
        tn <- tier_names[i]
        # Patr\u00f3n LASP est\u00e1ndar: "Speaker - phones" / "Speaker - words"
        if (grepl("\\s*[-_]\\s*(phones|words)\\s*$", tn, ignore.case = TRUE)) {
          tier_type[i]    <- sub(".*[-_]\\s*(phones|words)\\s*$", "\\1", tn, ignore.case = TRUE)
          tier_speaker[i] <- trimws(sub("\\s*[-_]\\s*(phones|words)\\s*$", "", tn, ignore.case = TRUE))
        }
        # Bare "phones" o "words" (sin prefijo de hablante)
        else if (grepl("^phones$", tn, ignore.case = TRUE)) {
          tier_type[i]    <- "phones"
          tier_speaker[i] <- ""
        }
        else if (grepl("^words$", tn, ignore.case = TRUE)) {
          tier_type[i]    <- "words"
          tier_speaker[i] <- ""
        }
        # Tambi\u00e9n reconocer "utterances" / "utterance"
        else if (grepl("^utterances?$", tn, ignore.case = TRUE)) {
          tier_type[i]    <- "words"
          tier_speaker[i] <- ""
        }
      }

      # \u00cdndices de tiers que son phones o words
      idx_pw <- which(!is.na(tier_type))

      if (length(idx_pw) == 0) {
        # No hay tiers phones/words reconocidos \u2014 fallback a todos
        message("[praatpicture] No se encontraron tiers phones/words \u2014 se muestran todos")
        return(tier_names)
      }

      if (!is.null(hablante) && nchar(trimws(hablante)) > 0) {
        spk <- trimws(hablante)
        # Buscar tiers phones/words cuyo speaker coincida con el hablante
        idx_spk <- idx_pw[tolower(tier_speaker[idx_pw]) == tolower(spk)]

        if (length(idx_spk) > 0) {
          # Encontrados tiers del hablante espec\u00edfico
          sel <- tier_names[idx_spk]
          message("[praatpicture] Tiers seleccionados (hablante '", spk, "'): ",
                  paste(sel, collapse = ", "))
          return(sel)
        }

        # Intentar match parcial (startsWith) para nombres largos
        idx_spk <- idx_pw[startsWith(tolower(tier_speaker[idx_pw]), tolower(spk)) |
                          startsWith(tolower(spk), tolower(tier_speaker[idx_pw]))]
        if (length(idx_spk) > 0) {
          sel <- tier_names[idx_spk]
          message("[praatpicture] Tiers seleccionados (match parcial '", spk, "'): ",
                  paste(sel, collapse = ", "))
          return(sel)
        }

        # Intentar match por contenci\u00f3n (el hablante puede ser parte del tier name o viceversa)
        idx_spk <- idx_pw[grepl(tolower(spk), tolower(tier_speaker[idx_pw]), fixed = TRUE) |
                          grepl(tolower(tier_speaker[idx_pw]), tolower(spk), fixed = TRUE)]
        idx_spk <- idx_spk[tier_speaker[idx_spk] != ""]  # excluir bare tiers de este match
        if (length(idx_spk) > 0) {
          sel <- tier_names[idx_spk]
          message("[praatpicture] Tiers seleccionados (match contenido '", spk, "'): ",
                  paste(sel, collapse = ", "))
          return(sel)
        }

        # Si hay tiers bare (sin prefijo hablante), usarlos como fallback
        idx_bare <- idx_pw[tier_speaker[idx_pw] == ""]
        if (length(idx_bare) > 0) {
          sel <- tier_names[idx_bare]
          message("[praatpicture] No se encontr\u00f3 hablante '", spk,
                  "' \u2014 usando tiers bare: ", paste(sel, collapse = ", "))
          return(sel)
        }

        # \u00daltimo recurso: si hay un solo hablante en los tiers, usar ese
        hablantes_unicos <- unique(tier_speaker[idx_pw][tier_speaker[idx_pw] != ""])
        if (length(hablantes_unicos) == 1) {
          sel <- tier_names[idx_pw]
          message("[praatpicture] Solo un hablante en TG ('", hablantes_unicos, "'), usando sus tiers")
          return(sel)
        }

        # Hablante especificado pero sin match \u2014 NO devolver todos, devolver solo phones/words sin speaker
        message("[praatpicture] Hablante '", spk, "' no encontrado entre ",
                paste(hablantes_unicos, collapse = ", "),
                " \u2014 mostrando todos los phones/words")
      }

      # Sin hablante especificado o sin match \u2192 devolver todos los phones/words
      sel <- tier_names[idx_pw]
      message("[praatpicture] Tiers seleccionados (todos phones/words): ",
              paste(sel, collapse = ", "))
      sel
    }, error = function(e) {
      message("[praatpicture] Error leyendo TG: ", e$message, " \u2014 se usar\u00e1n todos")
      NULL
    })
  }

  guardar_analisis_persistente <- function(nombre = NULL, genero = NULL) {
    if (!datos$calculado) return(invisible(NULL))
    # Si los datos vienen de cargar análisis previos (no de un nuevo cálculo),
    # no re-guardar automáticamente SALVO que haya un motivo explícito (nombre/genero)
    # o que haya etiquetado manual reciente que persistir.
    tiene_etiquetado <- !is.null(etiq$anotaciones) && 
                        "emocion_manual" %in% colnames(etiq$anotaciones) &&
                        any(etiq$anotaciones$emocion_manual != "neutro", na.rm = TRUE)
    if (isTRUE(datos$cargado_desde_storage) && is.null(nombre) && is.null(genero) && !tiene_etiquetado) {
      return(invisible(NULL))
    }
    if (!is.null(datos$ips_resumen))
      datos$ips_resumen <- corregir_semitones_si_necesario(datos$ips_resumen)
    
    gen <- if (!is.null(genero)) genero else if (!is.null(datos$genero_discursivo)) datos$genero_discursivo else "entrevistas"
    
    # Nombre basado en archivos procesados
    if (is.null(nombre)) {
      fns <- if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones)) {
        paste(sort(unique(datos$phones$filename)), collapse = "_")
      } else {
        format(Sys.time(), "%Y%m%d_%H%M%S")
      }
      nombre <- gsub("[^a-zA-Z0-9_áéíóúàèìòùñç-]", "_", fns)
      if (nchar(nombre) > 80) nombre <- substr(nombre, 1, 80)
    }
    
    obj <- list(
      phones = datos$phones, words = datos$words,
      ips_resumen = datos$ips_resumen, gfs_resumen = datos$gfs_resumen,
      vocales_por_ip = datos$vocales_por_ip, medias_hablante = datos$medias_hablante,
      sentimientos = datos$sentimientos, clausulas = datos$clausulas,
      actos_resumen = datos$actos_resumen,
      genero_discursivo = gen,
      metadatos_archivos = metadatos$archivos,
      metadatos_hablantes = metadatos$hablantes,
      fecha_guardado = Sys.time(),
      nombre_archivos = if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones)) sort(unique(datos$phones$filename)) else character(0),
      # Completeness tracking
      analisis_prosodia = datos$analisis_prosodia,
      analisis_sentimientos = datos$analisis_sentimientos,
      analisis_emociones_audio = datos$analisis_emociones_audio,
      analisis_morfosintactico = datos$analisis_morfosintactico,
      etiquetado_completado = datos$etiquetado_completado
    )
    
    rds_path <- file.path(lasp_analisis, gen, paste0(nombre, ".rds"))
    tryCatch({
      saveRDS(obj, rds_path)
      # Guardar metadatos ligeros para listado rápido
meta <- list(
  nombre_archivos     = obj$nombre_archivos,
  genero_discursivo   = gen,
  fecha_guardado      = obj$fecha_guardado,
  n_ips               = if (!is.null(obj$ips_resumen)) nrow(obj$ips_resumen) else 0L,
  analisis_prosodia   = obj$analisis_prosodia,
  analisis_sentimientos = obj$analisis_sentimientos,
  analisis_emociones_audio = obj$analisis_emociones_audio,
  analisis_morfosintactico = obj$analisis_morfosintactico,
  etiquetado_completado = obj$etiquetado_completado
)
meta_path <- sub("\\.rds$", ".meta.rds", rds_path)
saveRDS(meta, meta_path)
      showNotification(paste0("Análisis guardado: ", basename(rds_path)), type = "message", duration = 3)
    }, error = function(e) {
      showNotification(paste("Error guardando:", e$message), type = "warning")
    })
    
    invisible(rds_path)
  }
  
  # Función: guardar análisis de un único archivo por separado
  # Esto permite que cada archivo fuente tenga su propio RDS,
  # evitando sobreescribir 25k+ registros al cambiar un sentimiento.
  guardar_analisis_por_archivo <- function(fn, genero = NULL, notificar = TRUE) {
    if (is.null(datos$phones) || !datos$calculado) return(invisible(NULL))
    gen <- if (!is.null(genero)) genero else if (!is.null(datos$genero_discursivo)) datos$genero_discursivo else "entrevistas"

    # Filtrar datos de este archivo
    ph  <- if (!is.null(datos$phones))      datos$phones[datos$phones$filename == fn, ]      else NULL
    wd  <- if (!is.null(datos$words))       datos$words[datos$words$filename == fn, ]       else NULL
    ips <- if (!is.null(datos$ips_resumen)) datos$ips_resumen[datos$ips_resumen$filename == fn, ] else NULL
    gfs <- if (!is.null(datos$gfs_resumen)) datos$gfs_resumen[datos$gfs_resumen$filename == fn, ] else NULL
    # vocales_por_ip puede ser una lista nombrada o un data.frame
    voc <- NULL
    if (!is.null(datos$vocales_por_ip)) {
      if (is.data.frame(datos$vocales_por_ip)) {
        voc <- datos$vocales_por_ip[datos$vocales_por_ip$filename == fn, ]
      } else if (is.list(datos$vocales_por_ip)) {
        # Filtrar entradas de la lista cuyo nombre contiene el filename
        voc_keys <- names(datos$vocales_por_ip)
        voc_match <- voc_keys[grepl(paste0("^", gsub("([.+*?^${}()|\\[\\]])", "\\\\\\1", fn), "\\|\\|\\|"), voc_keys)]
        if (length(voc_match) > 0) voc <- datos$vocales_por_ip[voc_match]
      }
    }
    med <- if (!is.null(datos$medias_hablante) && "filename" %in% colnames(datos$medias_hablante))
             datos$medias_hablante[datos$medias_hablante$filename == fn, ] else datos$medias_hablante
    sen <- if (!is.null(datos$sentimientos) && "filename" %in% colnames(datos$sentimientos))
             datos$sentimientos[datos$sentimientos$filename == fn, ] else NULL
    cla <- if (!is.null(datos$clausulas) && "filename" %in% colnames(datos$clausulas))
             datos$clausulas[datos$clausulas$filename == fn, ] else NULL
    act <- if (!is.null(datos$actos_resumen) && "filename" %in% colnames(datos$actos_resumen))
             datos$actos_resumen[datos$actos_resumen$filename == fn, ] else NULL

    # Si no hay datos de este archivo, salir con aviso
    if (is.null(ph) || nrow(ph) == 0) {
      fn_class  <- if (!is.null(datos$phones)) class(datos$phones$filename) else "NULL"
      fn_vals   <- if (!is.null(datos$phones)) paste(head(unique(datos$phones$filename), 3), collapse=", ") else ""
      msg <- paste0("guardar_analisis_por_archivo: sin phones para fn='", fn,
                    "' (class=", fn_class, ", ejemplos: ", fn_vals, ")")
      showNotification(msg, type = "error", duration = 20)
      log_event("GUARDAR_SIN_PHONES", msg)
      return(invisible(NULL))
    }

    nombre_base <- gsub("[^a-zA-Z0-9_áéíóúàèìòùñç-]", "_", fn)
    if (nchar(nombre_base) > 80) nombre_base <- substr(nombre_base, 1, 80)

    udp <- if (!is.null(datos$udpipe_words) && "filename" %in% colnames(datos$udpipe_words))
             datos$udpipe_words[datos$udpipe_words$filename == fn, ] else NULL

    obj <- list(
      phones = ph, words = wd,
      ips_resumen = ips, gfs_resumen = gfs,
      vocales_por_ip = voc, medias_hablante = med,
      sentimientos = sen, clausulas = cla,
      actos_resumen = act,
      udpipe_words = udp,
      genero_discursivo = gen,
      metadatos_archivos = metadatos$archivos,
      metadatos_hablantes = metadatos$hablantes,
      fecha_guardado = Sys.time(),
      nombre_archivos = fn,
      analisis_prosodia = datos$analisis_prosodia,
      analisis_sentimientos = datos$analisis_sentimientos,
      analisis_emociones_audio = datos$analisis_emociones_audio,
      analisis_morfosintactico = datos$analisis_morfosintactico,
      etiquetado_completado = datos$etiquetado_completado
    )

    rds_path <- file.path(lasp_analisis, gen, paste0(nombre_base, ".rds"))
    dir.create(dirname(rds_path), recursive = TRUE, showWarnings = FALSE)
    tryCatch({
      saveRDS(obj, rds_path)
      # Guardar también CSV de los dataframes principales
      csv_dir <- file.path(lasp_analisis, gen, paste0(nombre_base, "_csv"))
      dir.create(csv_dir, recursive = TRUE, showWarnings = FALSE)
      if (!is.null(ph)  && nrow(ph)  > 0) tryCatch(write.csv(ph,  file.path(csv_dir, "phones.csv"),  row.names = FALSE), error = function(e) NULL)
      if (!is.null(wd)  && nrow(wd)  > 0) tryCatch(write.csv(wd,  file.path(csv_dir, "words.csv"),   row.names = FALSE), error = function(e) NULL)
      if (!is.null(ips) && nrow(ips) > 0) tryCatch(write.csv(ips, file.path(csv_dir, "ips.csv"),     row.names = FALSE), error = function(e) NULL)
      if (!is.null(gfs) && nrow(gfs) > 0) tryCatch(write.csv(gfs, file.path(csv_dir, "gfs.csv"),     row.names = FALSE), error = function(e) NULL)
      if (!is.null(cla) && nrow(cla) > 0) tryCatch(write.csv(cla, file.path(csv_dir, "clausulas.csv"), row.names = FALSE), error = function(e) NULL)
      if (!is.null(act) && nrow(act) > 0) tryCatch(write.csv(act, file.path(csv_dir, "actos.csv"),   row.names = FALSE), error = function(e) NULL)
      meta <- list(
        nombre_archivos     = fn,
        genero_discursivo   = gen,
        fecha_guardado      = obj$fecha_guardado,
        n_ips               = if (!is.null(ips)) nrow(ips) else 0L,
        analisis_prosodia   = obj$analisis_prosodia,
        analisis_sentimientos = obj$analisis_sentimientos,
        analisis_emociones_audio = obj$analisis_emociones_audio,
        analisis_morfosintactico = obj$analisis_morfosintactico,
        etiquetado_completado = obj$etiquetado_completado
      )
      saveRDS(meta, sub("\\.rds$", ".meta.rds", rds_path))
      # Actualizar caché local (fuera de iCloud) para arranque instantáneo
      actualizar_cache_recientes(
        nombre = tools::file_path_sans_ext(basename(rds_path)),
        ruta   = rds_path,
        n_ips  = meta$n_ips
      )
      if (notificar)
        showNotification(paste0("\u2714 Guardado: ", basename(rds_path)), type = "message", duration = 3)
      ts_guardado(Sys.time())
    }, error = function(e) {
      msg <- paste0("Error guardando '", fn, "': ", e$message,
                    " | path=", rds_path,
                    " | dir_ok=", dir.exists(dirname(rds_path)))
      showNotification(msg, type = "error", duration = 20)
      log_event("GUARDAR_ERROR", msg)
    })
    invisible(rds_path)
  }

  # Función: guardar todos los archivos cargados por separado
  guardar_todos_por_archivo <- function(genero = NULL, notificar_cada = TRUE, modal_final = FALSE) {
    if (is.null(datos$phones) || !datos$calculado) return(invisible(NULL))
    fns <- sort(unique(datos$phones$filename))
    gen <- if (!is.null(genero)) genero else if (!is.null(datos$genero_discursivo)) datos$genero_discursivo else "entrevistas"
    for (fn in fns) {
      guardar_analisis_por_archivo(fn, genero = gen, notificar = notificar_cada)
    }
    if (modal_final) {
      showModal(modalDialog(
        title = tagList(icon("save", class = "text-success"), " An\u00e1lisis guardado"),
        paste0("Guardados ", length(fns), " archivo(s) en el directorio de an\u00e1lisis."),
        easyClose = TRUE, footer = modalButton("Cerrar")
      ))
    }
    if (!notificar_cada)
      showNotification(paste0("✔ ", length(fns), " archivos guardados individualmente"), type = "message", duration = 4)
    invisible(fns)
  }

  # Función: guardar etiquetado a almacenamiento persistente
  guardar_etiquetado_persistente <- function() {
    if (is.null(etiq$anotaciones)) return(invisible(NULL))
    
    nombre <- if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones)) {
      paste(sort(unique(datos$phones$filename)), collapse = "_")
    } else "etiquetado"
    nombre <- gsub("[^a-zA-Z0-9_\u00e1\u00e9\u00ed\u00f3\u00fa\u00e0\u00e8\u00ec\u00f2\u00f9\u00f1\u00e7-]", "_", nombre)
    if (nchar(nombre) > 80) nombre <- substr(nombre, 1, 80)
    
    obj <- list(
      anotaciones  = etiq$anotaciones,
      acto_counter = etiq$acto_counter,
      pos_actual   = etiq$pos_actual,
      ips_resumen  = datos$ips_resumen,
      timestamp    = Sys.time()
    )
    
    rds_path <- file.path(lasp_etiquetado, paste0(nombre, ".rds"))
    tryCatch({
      saveRDS(obj, rds_path)
      log_event("ETIQUETADO_GUARDADO", paste0("pos=", etiq$pos_actual))
    }, error = function(e) log_event("ETIQUETADO_ERROR", e$message))

    # Guardar el archivo del GE actual en su RDS por-archivo.
    # IMPORTANTE: NO escribir datos$ips_resumen$emocion_manual aquí —
    # esa escritura invalida renderUI de etiq_selector_archivo y resetea la navegación.
    # La emoción se lee desde etiq$anotaciones al exportar/analizar.
    if (!is.null(datos$ips_resumen) && !is.null(etiq$anotaciones) &&
        nrow(etiq$anotaciones) == nrow(datos$ips_resumen)) {

      # Obtener filename del GE actual via fila_original (correcto con filtros activos)
      fn_actual <- tryCatch({
        ips_r     <- isolate(ips_etiq())
        pos       <- etiq$pos_actual
        if (!is.null(ips_r) && nrow(ips_r) > 0 && pos > 0 && pos <= nrow(ips_r)) {
          fila_orig <- ips_r$fila_original[pos]
          if (!is.null(fila_orig) && !is.na(fila_orig) && fila_orig > 0 &&
              fila_orig <= nrow(datos$ips_resumen))
            datos$ips_resumen$filename[fila_orig]
          else NULL
        } else NULL
      }, error = function(e) NULL)

      gen <- if (!is.null(datos$genero_discursivo)) datos$genero_discursivo else "entrevistas"

      # Sincronizar emocion_manual al ips_resumen del RDS usando isolate para
      # no disparar reactivos — leemos y escribimos en local, luego saveRDS
      tryCatch({
        ips_snapshot <- isolate(datos$ips_resumen)
        if ("emocion_manual" %in% colnames(etiq$anotaciones))
          ips_snapshot$emocion_manual <- etiq$anotaciones$emocion_manual
        fn_save <- if (!is.null(fn_actual) && nchar(fn_actual) > 0) fn_actual else NULL
        if (!is.null(fn_save)) {
          # Guardar solo el archivo relevante con ips_snapshot actualizado
          ph  <- datos$phones[datos$phones$filename == fn_save, ]
          if (!is.null(ph) && nrow(ph) > 0) {
            ips_fn <- ips_snapshot[ips_snapshot$filename == fn_save, ]
            obj_fn <- list(
              phones = ph,
              words  = if (!is.null(datos$words)) datos$words[datos$words$filename == fn_save, ] else NULL,
              ips_resumen = ips_fn,
              gfs_resumen = if (!is.null(datos$gfs_resumen)) datos$gfs_resumen[datos$gfs_resumen$filename == fn_save, ] else NULL,
              vocales_por_ip = {
                voc_tmp <- NULL
                if (!is.null(datos$vocales_por_ip)) {
                  if (is.data.frame(datos$vocales_por_ip)) {
                    voc_tmp <- datos$vocales_por_ip[datos$vocales_por_ip$filename == fn_save, ]
                  } else if (is.list(datos$vocales_por_ip)) {
                    voc_keys <- names(datos$vocales_por_ip)
                    voc_m <- voc_keys[grepl(paste0("^", gsub("([.+*?^${}()|\\[\\]])", "\\\\\\1", fn_save), "\\|\\|\\|"), voc_keys)]
                    if (length(voc_m) > 0) voc_tmp <- datos$vocales_por_ip[voc_m]
                  }
                }
                voc_tmp
              },
              medias_hablante = if (!is.null(datos$medias_hablante) && "filename" %in% colnames(datos$medias_hablante)) datos$medias_hablante[datos$medias_hablante$filename == fn_save, ] else datos$medias_hablante,
              sentimientos = if (!is.null(datos$sentimientos) && "filename" %in% colnames(datos$sentimientos)) datos$sentimientos[datos$sentimientos$filename == fn_save, ] else NULL,
              clausulas = if (!is.null(datos$clausulas) && "filename" %in% colnames(datos$clausulas)) datos$clausulas[datos$clausulas$filename == fn_save, ] else NULL,
              actos_resumen = if (!is.null(datos$actos_resumen) && "filename" %in% colnames(datos$actos_resumen)) datos$actos_resumen[datos$actos_resumen$filename == fn_save, ] else NULL,
              genero_discursivo = gen,
              metadatos_archivos = metadatos$archivos,
              metadatos_hablantes = metadatos$hablantes,
              fecha_guardado = Sys.time(),
              nombre_archivos = fn_save,
              analisis_prosodia = datos$analisis_prosodia,
              analisis_sentimientos = datos$analisis_sentimientos,
              analisis_emociones_audio = datos$analisis_emociones_audio,
              analisis_morfosintactico = datos$analisis_morfosintactico,
              etiquetado_completado = datos$etiquetado_completado
            )
            nombre_base <- gsub("[^a-zA-Z0-9_\u00e1\u00e9\u00ed\u00f3\u00fa\u00e0\u00e8\u00ec\u00f2\u00f9\u00f1\u00e7-]", "_", fn_save)
            if (nchar(nombre_base) > 80) nombre_base <- substr(nombre_base, 1, 80)
            rds_fn <- file.path(lasp_analisis, gen, paste0(nombre_base, ".rds"))
            saveRDS(obj_fn, rds_fn)
            showNotification(paste0("\u2714 Guardado: ", basename(rds_fn)), type = "message", duration = 3)
          }
        }
      }, error = function(e) log_event("ETIQUETADO_SAVE_ERROR", e$message))
    }

    invisible(rds_path)
  }
  
  # Función: copiar audio a almacenamiento persistente
  copiar_audio_persistente <- function(origen, nombre_archivo) {
    dest <- file.path(lasp_audios, nombre_archivo)
    if (file.exists(dest)) return(dest)  # ya existe
    tryCatch(file.copy(origen, dest, overwrite = FALSE), error = function(e) NULL)
    dest
  }
  
  # Función: copiar TextGrid a almacenamiento persistente
  copiar_textgrid_persistente <- function(origen, nombre_archivo) {
    dest <- file.path(lasp_textgrids, nombre_archivo)
    if (file.exists(dest)) return(dest)
    tryCatch(file.copy(origen, dest, overwrite = FALSE), error = function(e) NULL)
    dest
  }
  
  # Guardar archivos preprocesados individuales (texto, pitch, intensidad) por archivo
  guardar_preprocesados <- function() {
    tryCatch({
      n_saved <- 0
      
      # Guardar texto por archivo_origen (solo columnas esenciales del TextGrid)
      if (!is.null(datos$texto) && nrow(datos$texto) > 0 && "archivo_origen" %in% colnames(datos$texto)) {
        cols_texto <- intersect(c("tier","tmin","tmax","text"), colnames(datos$texto))
        for (fn in unique(datos$texto$archivo_origen)) {
          df_fn <- datos$texto[datos$texto$archivo_origen == fn, cols_texto, drop = FALSE]
          dest <- file.path(lasp_preprocesados, paste0(fn, "_texto.txt"))
          write.table(df_fn, dest, sep = "\t", row.names = FALSE, quote = FALSE)
          n_saved <- n_saved + 1
        }
      }
      
      # Guardar pitch por archivo_origen (solo tiempo y f0)
      if (!is.null(datos$pitch) && nrow(datos$pitch) > 0 && "archivo_origen" %in% colnames(datos$pitch)) {
        cols_pitch <- intersect(c("tiempo","f0"), colnames(datos$pitch))
        for (fn in unique(datos$pitch$archivo_origen)) {
          df_fn <- datos$pitch[datos$pitch$archivo_origen == fn, cols_pitch, drop = FALSE]
          dest <- file.path(lasp_preprocesados, paste0(fn, "_pitch.txt"))
          write.table(df_fn, dest, sep = "\t", row.names = FALSE, quote = FALSE)
          n_saved <- n_saved + 1
        }
      }
      
      # Guardar intensidad por archivo_origen (solo tiempo e intensidad)
      if (!is.null(datos$intensidad) && nrow(datos$intensidad) > 0 && "archivo_origen" %in% colnames(datos$intensidad)) {
        cols_int <- intersect(c("tiempo","intensidad"), colnames(datos$intensidad))
        for (fn in unique(datos$intensidad$archivo_origen)) {
          df_fn <- datos$intensidad[datos$intensidad$archivo_origen == fn, cols_int, drop = FALSE]
          dest <- file.path(lasp_preprocesados, paste0(fn, "_intensidad.txt"))
          write.table(df_fn, dest, sep = "\t", row.names = FALSE, quote = FALSE)
          n_saved <- n_saved + 1
        }
      }
      
      if (n_saved > 0) log_event("PREPROCESADOS_GUARDADOS", paste0(n_saved, " archivos en ", lasp_preprocesados))
      n_saved
    }, error = function(e) {
      log_event("PREPROCESADOS_ERROR", e$message)
      0
    })
  }
  
  # Función: listar análisis guardados
  listar_analisis_guardados <- function(genero_filtro = "todos", estado_filtro = "todos") {
    generos <- if (length(genero_filtro) == 0 || (length(genero_filtro) == 1 && genero_filtro == "todos")) {
      c("peliculas", "series", "interpretacion", "entrevistas", "conversaciones")
    } else genero_filtro
    
    resultados <- data.frame(
      Nombre = character(), Genero = character(), Fecha = character(),
      N_archivos = integer(), N_IPs = integer(),
      Prosodia = character(), Sentim. = character(), Emoc.Audio = character(),
      Morfosin. = character(), Etiquetado = character(),
      Completo = character(), Ruta = character(),
      stringsAsFactors = FALSE
    )
    
    for (gen in generos) {
  dir_gen <- file.path(lasp_analisis, gen)
  if (!dir.exists(dir_gen)) next
  
  # Primero intentar leer metadatos ligeros
  meta_files <- list.files(dir_gen, pattern = "\\.meta\\.rds$", full.names = TRUE)
rds_files <- grep("\\.meta\\.rds$", 
                  list.files(dir_gen, pattern = "\\.rds$", full.names = TRUE), 
                  value = TRUE, invert = TRUE)  
  # Archivos RDS sin .meta.rds correspondiente (legacy)
  legacy_files <- rds_files[!sub("\\.rds$", ".meta.rds", rds_files) %in% meta_files]
  
  # Generar .meta.rds para legacy (solo una vez, carga lenta)
  for (f in legacy_files) {
    tryCatch({
      obj <- readRDS(f)
      meta <- list(
        nombre_archivos          = obj$nombre_archivos,
        genero_discursivo        = gen,
        fecha_guardado           = obj$fecha_guardado,
        n_ips                    = if (!is.null(obj$ips_resumen)) nrow(obj$ips_resumen) else 0L,
        analisis_prosodia        = obj$analisis_prosodia,
        analisis_sentimientos    = obj$analisis_sentimientos,
        analisis_emociones_audio = obj$analisis_emociones_audio,
        analisis_morfosintactico = obj$analisis_morfosintactico,
        etiquetado_completado    = obj$etiquetado_completado
      )
      saveRDS(meta, sub("\\.rds$", ".meta.rds", f))
      meta_files <- c(meta_files, sub("\\.rds$", ".meta.rds", f))
    }, error = function(e) NULL)
  }
  
  # Leer solo metadatos ligeros
  for (mf in meta_files) {
    tryCatch({
      rds_f <- sub("\\.meta\\.rds$", ".rds", mf)
      info  <- file.info(rds_f)
      obj   <- readRDS(mf)  # ¡solo kilobytes!
      
      n_arch <- length(obj$nombre_archivos)
      n_ips  <- obj$n_ips
      pros   <- isTRUE(obj$analisis_prosodia)
      sent   <- isTRUE(obj$analisis_sentimientos)
      emoc   <- isTRUE(obj$analisis_emociones_audio)
      morf   <- isTRUE(obj$analisis_morfosintactico)
      etiq   <- isTRUE(obj$etiquetado_completado)
      completo_todo <- pros && sent && emoc && morf && etiq
      chk <- function(x) if (x) "\u2714" else "\u2718"
      
      resultados <- rbind(resultados, data.frame(
        Nombre        = tools::file_path_sans_ext(basename(rds_f)),
        Genero        = gen,
        Fecha         = format(info$mtime, "%d/%m/%Y %H:%M"),
        FechaNumerica = as.numeric(info$mtime),
        N_archivos = n_arch, N_IPs = n_ips,
        Prosodia   = chk(pros), Sentim.    = chk(sent),
        Emoc.Audio = chk(emoc), Morfosin.  = chk(morf),
        Etiquetado = chk(etiq), Completo   = chk(completo_todo),
        Ruta       = rds_f,
        stringsAsFactors = FALSE
      ))
    }, error = function(e) NULL)
  }
}
    # Filter by estado if requested
    if (estado_filtro == "completo" && nrow(resultados) > 0) {
      resultados <- resultados[resultados$Completo == "\u2714", ]
    } else if (estado_filtro == "incompleto" && nrow(resultados) > 0) {
      resultados <- resultados[resultados$Completo == "\u2718", ]
    }
    resultados
  }
  
  # (Modal de inicio eliminado: el investigador accede a análisis guardados desde el tab "Cargar análisis")
  
  # Tabla del modal de inicio
  modal_analisis_lista <- reactive({
    gen <- if (!is.null(input$modal_filtro_genero)) input$modal_filtro_genero else "todos"
    listar_analisis_guardados(gen)
  })
  
  output$modal_tabla_analisis <- renderDT({
    df <- modal_analisis_lista()
    if (nrow(df) == 0) return(datatable(data.frame(Mensaje = "No hay an\u00e1lisis guardados"), options = list(dom = "t")))
    df <- df[order(df$FechaNumerica, decreasing = TRUE), ]
    cols_show <- c("Nombre", "Genero", "Fecha", "N_archivos", "N_IPs", "FechaNumerica")
    datatable(df[, cols_show],
              selection = "multiple",
              rownames = FALSE,
              options = list(
                pageLength = 10, dom = "fip",
                order = list(list(5L, "desc")),
                columnDefs = list(list(visible = FALSE, targets = 5L))
              ),
              colnames = c("Nombre", "G\u00e9nero", "Fecha", "Archivos", "IPs", "FechaNumerica"))
  })
  
  # Cargar seleccionados desde modal
  observeEvent(input$modal_cargar, {
    df <- modal_analisis_lista()
    sel <- input$modal_tabla_analisis_rows_selected
    if (is.null(sel) || length(sel) == 0) {
      showNotification("Selecciona al menos un análisis", type = "warning")
      return()
    }
    cargar_analisis_desde_storage(df$Ruta[sel])
    removeModal()
  })
  
  # Cargar todos desde modal
  observeEvent(input$modal_cargar_todos, {
    df <- modal_analisis_lista()
    if (nrow(df) == 0) return()
    cargar_analisis_desde_storage(df$Ruta)
    removeModal()
  })
  
  # Eliminar seleccionados desde modal
  observeEvent(input$modal_eliminar, {
    df <- modal_analisis_lista()
    sel <- input$modal_tabla_analisis_rows_selected
    if (is.null(sel) || length(sel) == 0) {
      showNotification("Selecciona al menos un análisis para eliminar", type = "warning")
      return()
    }
    rutas <- df$Ruta[sel]
    n_ok <- 0
    for (ruta in rutas) {
      tryCatch({
        if (file.exists(ruta)) { file.remove(ruta); n_ok <- n_ok + 1 }
        meta_ruta <- sub("\\.rds$", ".meta.rds", ruta)
        if (file.exists(meta_ruta)) file.remove(meta_ruta)
      }, error = function(e) NULL)
    }
    showNotification(paste0("Eliminados ", n_ok, " análisis"), type = "message")
    # Refresh the modal table
    analisis_existentes <- listar_analisis_guardados()
    if (nrow(analisis_existentes) == 0) {
      removeModal()
    }
  })
  
  # ── Helper: filtrar obj cargado (anonimizar + truncado temporal) ─────────────
  filtrar_obj_cargado <- function(obj, excluir_anon = TRUE, max_s = 0) {
    tablas_df <- c("phones", "words", "ips_resumen", "gfs_resumen", "clausulas", "sentimientos")
    for (tabla in tablas_df) {
      df <- obj[[tabla]]
      if (!is.data.frame(df) || nrow(df) == 0) next
      # Excluir hablante anonimizar
      if (excluir_anon && "hablante" %in% colnames(df))
        df <- df[tolower(trimws(df$hablante)) != "anonimizar", ]
      # Truncar tiempo
      if (max_s > 0) {
        tcol <- if ("inicio" %in% colnames(df)) "inicio" else
                if ("tmin"   %in% colnames(df)) "tmin"   else
                if ("fin"    %in% colnames(df)) "fin"    else NULL
        if (!is.null(tcol)) df <- df[!is.na(df[[tcol]]) & df[[tcol]] < max_s, ]
      }
      obj[[tabla]] <- df
    }
    # vocales_por_ip: named list con claves "filename|||hablante|||gf|||ge"
    vpi <- obj$vocales_por_ip
    if (is.list(vpi) && length(vpi) > 0) {
      keep <- rep(TRUE, length(vpi))
      if (excluir_anon)
        keep <- keep & !grepl("\\|\\|\\|anonimizar\\|\\|\\|", names(vpi), ignore.case = TRUE)
      if (max_s > 0 && !is.null(obj$ips_resumen) && is.data.frame(obj$ips_resumen) &&
          all(c("filename","hablante","grupo_fonico","grupo_entonativo") %in% colnames(obj$ips_resumen))) {
        ips_ok <- obj$ips_resumen
        claves_ok <- paste0(ips_ok$filename, "|||", ips_ok$hablante, "|||",
                            ips_ok$grupo_fonico, "|||", ips_ok$grupo_entonativo)
        keep <- keep & (names(vpi) %in% claves_ok)
      }
      obj$vocales_por_ip <- vpi[keep]
    }
    obj
  }

  # Función: cargar uno o varios análisis desde storage
  cargar_analisis_desde_storage <- function(rutas) {
    if (length(rutas) == 0) return()

    excluir_anon <- isTRUE(input$cargar_excluir_anonimizar)
    max_min      <- if (!is.null(input$cargar_max_minutos) && !is.na(input$cargar_max_minutos) &&
                        input$cargar_max_minutos > 0) input$cargar_max_minutos else 0
    max_s        <- max_min * 60
    multiples    <- length(rutas) > 1   # en carga múltiple, suprimir notificación por archivo

    withProgress(message = "Cargando análisis...", value = 0, {
      all_phones <- data.frame(); all_words <- data.frame()
      all_ips <- data.frame(); all_gfs <- data.frame()
      all_vocales <- data.frame(); all_medias <- data.frame()
      all_sent <- data.frame(); all_clausulas <- data.frame()
      all_actos <- data.frame()
      all_udpipe <- data.frame()
      ultimo_gen <- NULL
      archivos_cargados <- character(0)
      # Flags de completitud recolectadas durante el primer loop (evita releer los RDS)
      any_prosodia <- FALSE; any_sent_f <- FALSE; any_emoc_f <- FALSE
      any_morf_f <- FALSE; any_etiq_f <- FALSE

      for (i in seq_along(rutas)) {
        fn_base <- tools::file_path_sans_ext(basename(rutas[i]))
        incProgress(1/length(rutas), detail = fn_base)
        tryCatch({
          obj <- readRDS(rutas[i])
          obj <- filtrar_obj_cargado(obj, excluir_anon = excluir_anon, max_s = max_s)
          # Recoger flags de completitud aquí (evita releer el RDS más abajo)
          if (isTRUE(obj$analisis_prosodia))        any_prosodia <- TRUE
          if (isTRUE(obj$analisis_sentimientos))    any_sent_f   <- TRUE
          if (isTRUE(obj$analisis_emociones_audio)) any_emoc_f   <- TRUE
          if (isTRUE(obj$analisis_morfosintactico) ||
              (!is.null(obj$udpipe_words) && is.data.frame(obj$udpipe_words) && nrow(obj$udpipe_words) > 0))
            any_morf_f <- TRUE
          if (isTRUE(obj$etiquetado_completado))    any_etiq_f   <- TRUE

          # ── Género ──────────────────────────────────────────────────────
          # Cada condición usa isTRUE() / longitud explícita para que un
          # NA en cualquier campo del RDS no dispare
          # "missing value where TRUE/FALSE needed"
          generos_validos <- c("peliculas","series","interpretacion","entrevistas","conversaciones")
          carpeta_padre   <- basename(dirname(rutas[i]))
          gen_obj <- if (isTRUE(carpeta_padre %in% generos_validos)) {
            carpeta_padre
          } else {
            gd        <- obj$genero_discursivo
            gd_limpio <- if (length(gd) == 1L && !is.na(gd) && is.character(gd)) trimws(gd) else ""
            if (nchar(gd_limpio) > 0 && gd_limpio %in% generos_validos) gd_limpio else "entrevistas"
          }

          # ── Helper inject_genero ─────────────────────────────────────────
          inject_genero <- function(df_obj) {
            if (is.null(df_obj) || !is.data.frame(df_obj) || isTRUE(nrow(df_obj) == 0)) return(df_obj)
            df_obj$genero <- gen_obj
            df_obj
          }

          # ── Merge data ───────────────────────────────────────────────────
          # isTRUE(is.data.frame()) en lugar de !is.null(): evita que un campo NA
          # (no NULL) pase al bind_rows y genere "missing value where TRUE/FALSE needed"
          if (isTRUE(is.data.frame(obj$phones)))         all_phones    <- bind_rows(all_phones,    inject_genero(obj$phones))
          if (isTRUE(is.data.frame(obj$words)))          all_words     <- bind_rows(all_words,     inject_genero(obj$words))
          if (isTRUE(is.data.frame(obj$ips_resumen)))    all_ips       <- bind_rows(all_ips,       inject_genero(obj$ips_resumen))
          if (isTRUE(is.data.frame(obj$gfs_resumen)))    all_gfs       <- bind_rows(all_gfs,       inject_genero(obj$gfs_resumen))
          if (isTRUE(is.data.frame(obj$vocales_por_ip))) all_vocales   <- bind_rows(all_vocales,   inject_genero(obj$vocales_por_ip))
          if (isTRUE(is.data.frame(obj$medias_hablante))) all_medias  <- bind_rows(all_medias,     inject_genero(obj$medias_hablante))
          if (isTRUE(is.data.frame(obj$sentimientos)))   all_sent      <- bind_rows(all_sent,      inject_genero(obj$sentimientos))
          if (isTRUE(is.data.frame(obj$clausulas)))      all_clausulas <- bind_rows(all_clausulas, inject_genero(obj$clausulas))
          if (isTRUE(is.data.frame(obj$actos_resumen)))  all_actos     <- bind_rows(all_actos,     inject_genero(obj$actos_resumen))

          # isTRUE() en las condiciones compuestas para evitar NA
          if (isTRUE(is.data.frame(obj$udpipe_words)) && isTRUE(nrow(obj$udpipe_words) > 0))
            all_udpipe <- bind_rows(all_udpipe, obj$udpipe_words)
          if (isTRUE(is.data.frame(obj$metadatos_archivos)) && isTRUE(nrow(obj$metadatos_archivos) > 0))
            metadatos$archivos  <- dplyr::distinct(bind_rows(metadatos$archivos,  obj$metadatos_archivos))
          if (isTRUE(is.data.frame(obj$metadatos_hablantes)) && isTRUE(nrow(obj$metadatos_hablantes) > 0))
            metadatos$hablantes <- dplyr::distinct(bind_rows(metadatos$hablantes, obj$metadatos_hablantes))

          ultimo_gen <- obj$genero_discursivo

          # ── Audios / TextGrids ───────────────────────────────────────────
          # Filtrar NAs y no-character antes de iterar
          fns_obj <- obj$nombre_archivos
          fns_validos <- if (is.character(fns_obj) && length(fns_obj) > 0)
            fns_obj[!is.na(fns_obj)] else character(0)

          fn_notif <- if (length(fns_validos) > 0) paste(fns_validos, collapse = ", ") else fn_base

          for (fn in fns_validos) {
            for (ext in c(".wav", ".flac", ".mp3", ".WAV")) {
              audio_path <- file.path(lasp_audios, paste0(fn, ext))
              if (isTRUE(file.exists(audio_path))) {   # isTRUE: file.exists(NA) devuelve NA
                datos_audio$wavs[[fn]] <- audio_path
                break
              }
            }
            tg_path <- file.path(lasp_textgrids, paste0(fn, ".TextGrid"))
            if (isTRUE(file.exists(tg_path))) datos_textgrid$tgs[[fn]] <- tg_path
          }

          n_ips_obj <- if (isTRUE(is.data.frame(obj$ips_resumen))) nrow(obj$ips_resumen) else 0L
          archivos_cargados <- c(archivos_cargados, paste0(fn_notif, " (", n_ips_obj, " GEs)"))
          if (!multiples)
            showNotification(paste0("\u2714 Cargado: ", fn_notif, " (", n_ips_obj, " GEs)"),
                             type = "message", duration = 3)
        }, error = function(e) {
          showNotification(paste("Error cargando", basename(rutas[i]), ":", e$message), type = "warning")
        })
      }
      if (multiples && length(archivos_cargados) > 0)
        showNotification(
          paste0("\u2714 ", length(archivos_cargados), " an\u00e1lisis cargados"),
          type = "message", duration = 5)
      
      if (is.data.frame(all_phones)  && nrow(all_phones)  > 0) datos$phones        <- all_phones
      if (is.data.frame(all_words)   && nrow(all_words)   > 0) datos$words         <- all_words
      if (is.data.frame(all_ips)     && nrow(all_ips)     > 0) {
        all_ips <- all_ips %>%
          dplyr::arrange(filename, inicio) %>%
          dplyr::group_by(filename) %>%
          dplyr::mutate(
            pausa_anterior  = ifelse(dplyr::row_number() == 1L, NA_real_,
                                     inicio - dplyr::lag(fin)),
            pausa_posterior = ifelse(dplyr::row_number() == dplyr::n(), NA_real_,
                                     dplyr::lead(inicio) - fin)
          ) %>%
          dplyr::ungroup()
        datos$ips_resumen <- limpiar_emociones_cjk(corregir_semitones_si_necesario(all_ips))
      }
      if (is.data.frame(all_gfs)     && nrow(all_gfs)     > 0) datos$gfs_resumen   <- all_gfs
      if (is.data.frame(all_vocales) && nrow(all_vocales) > 0) datos$vocales_por_ip <- all_vocales
      if (is.data.frame(all_medias)  && nrow(all_medias)  > 0) datos$medias_hablante <- all_medias
      if (is.data.frame(all_sent)    && nrow(all_sent)    > 0) datos$sentimientos   <- limpiar_emociones_cjk(all_sent)
      
      # Rebuild sentimientos from ips_resumen if sentimientos is missing but columns exist
      if (is.null(datos$sentimientos) && !is.null(datos$ips_resumen)) {
        sent_cols <- intersect(c("sentimiento", "emocion_texto", "emocion_audio",
                                  "prob_pos", "prob_neg", "prob_neu", "prob_emocion_texto", "prob_emocion_audio"),
                                colnames(datos$ips_resumen))
        if (length(sent_cols) > 0 && "sentimiento" %in% sent_cols && 
            any(datos$ips_resumen[["sentimiento"]] != "", na.rm = TRUE)) {
          id_cols <- intersect(c("filename", "hablante", "id_ge", "palabras_grupo"), colnames(datos$ips_resumen))
          datos$sentimientos <- datos$ips_resumen[, c(id_cols, sent_cols), drop = FALSE]
        }
      }
      
      if (nrow(all_clausulas) > 0) {
        # Ensure clausula_global_id exists (backward compat)
        if (!"clausula_global_id" %in% colnames(all_clausulas)) {
          all_clausulas$clausula_global_id <- paste0(all_clausulas$filename, "_", all_clausulas$hablante, "_CL", all_clausulas$clausula_id)
        }
        datos$clausulas <- all_clausulas
      }
      if (nrow(all_actos) > 0) datos$actos_resumen <- all_actos
      if (nrow(all_udpipe) > 0) datos$udpipe_words <- all_udpipe
      if (!is.null(ultimo_gen)) datos$genero_discursivo <- ultimo_gen
      datos$calculado <- TRUE
      datos$cargado_desde_storage <- TRUE   # impide re-guardar con género incorrecto
      datos$nombre_archivo <- paste(length(rutas), "análisis cargados")
      
      # Restore completeness flags — ya recolectadas durante el loop principal
      datos$analisis_prosodia        <- any_prosodia
      datos$analisis_sentimientos    <- any_sent_f
      datos$analisis_emociones_audio <- any_emoc_f
      datos$analisis_morfosintactico <- any_morf_f || nrow(all_udpipe) > 0
      datos$etiquetado_completado    <- any_etiq_f
      updateCheckboxInput(session, "etiq_completado_check", value = any_etiq_f)
      
      # Cargar etiquetado si existe
      for (ruta in rutas) {
        nombre_base <- tools::file_path_sans_ext(basename(ruta))
        etiq_path <- file.path(lasp_etiquetado, paste0(nombre_base, ".rds"))
        if (file.exists(etiq_path)) {
          tryCatch({
            obj_etiq <- readRDS(etiq_path)
            if (!is.null(obj_etiq$anotaciones)) {
              etiq$anotaciones <- obj_etiq$anotaciones
              etiq$acto_counter <- obj_etiq$acto_counter
              etiq$pos_actual <- obj_etiq$pos_actual
            }
          }, error = function(e) NULL)
        }
      }
    })
    
    showNotification(paste0("Cargados ", length(rutas), " análisis"), type = "message")
    log_event("ANALISIS_CARGADOS", paste0(length(rutas), " análisis: ", paste(basename(rutas), collapse = ", ")))
  }
  
  # ---- TAB CREAR/CARGAR: Server ----
  
  # Info condicional según modo de creación
  output$crear_info_modo <- renderUI({
    modo <- input$crear_modo
    msg <- switch(modo,
      "datos_propios" = tags$details(
        tags$summary(style = "cursor:pointer; color:#17a2b8; font-weight:bold; font-size:0.9em;",
          icon("info-circle"), " Ayuda: Datos propios"),
        tags$div(style = "font-size:0.85em; padding:6px; background:#fff7ed; border-radius:4px; margin-top:4px;",
          "Sube 3 archivos .txt + audio por grabaci\u00f3n:",
          tags$ul(style = "margin-bottom:4px;",
            tags$li(tags$code("nombre_texto.txt"), " \u2014 intervalos"),
            tags$li(tags$code("nombre_pitch.txt"), " \u2014 F0"),
            tags$li(tags$code("nombre_intensidad.txt"), " \u2014 intensidad"),
            tags$li(tags$code("nombre.wav/.flac/.mp3"), " \u2014 audio")
          ),
          tags$small("Mismo nombre base. Audio necesario para reproducci\u00f3n y emociones.")
        )
      ),
      "parselmouth" = tags$details(
        tags$summary(style = "cursor:pointer; color:#28a745; font-weight:bold; font-size:0.9em;",
          icon("info-circle"), " Ayuda: Parselmouth"),
        tags$div(style = "font-size:0.85em; padding:6px; background:#d4edda; border-radius:4px; margin-top:4px;",
          "Sube ", tags$code(".wav"), " y ", tags$code(".TextGrid"), " con mismo nombre base. ",
          "LASP extraer\u00e1 texto, pitch e intensidad autom\u00e1ticamente.", tags$br(),
          tags$em("Requiere: Python 3 con parselmouth y tgt.")
        )
      ),
      "script_praat" = tags$details(
        tags$summary(style = "cursor:pointer; color:#856404; font-weight:bold; font-size:0.9em;",
          icon("info-circle"), " Ayuda: Script Praat"),
        tags$div(style = "font-size:0.85em; padding:6px; background:#fff3cd; border-radius:4px; margin-top:4px;",
          "Sube ", tags$code(".wav"), " y ", tags$code(".TextGrid"), " con mismo nombre base. ",
          "LASP ejecutar\u00e1 un script Praat.", tags$br(),
          tags$em("Requiere: Praat en l\u00ednea de comandos.")
        )
      )
    )
    msg
  })
  
  # Tabla de análisis guardados (en tab Cargar)
  cargar_analisis_lista <- reactive({
    input$eliminar_seleccionados  # reactivity on delete
    input$cargar_refrescar        # reactivity on manual refresh
    gen <- if (!is.null(input$cargar_filtro_genero) && length(input$cargar_filtro_genero) > 0) input$cargar_filtro_genero else "todos"
    listar_analisis_guardados(gen)
  })

  # Actualizar lista manualmente
  observeEvent(input$cargar_refrescar, {
    showNotification("Lista actualizada", type = "message", duration = 2)
  })

  # ── Server: Tab "Completar análisis" ─────────────────────────────────────
  output$completar_estado_ui <- renderUI({
    if (!isTRUE(datos$calculado)) {
      div(class = "alert alert-warning",
        icon("exclamation-triangle"),
