    }
  })

  # Completar: UDPipe
  # Completar: UDPipe — ejecuta directamente sin depender de botón oculto
  observeEvent(input$completar_btn_udpipe, {
    if (!isTRUE(datos$calculado)) {
      showNotification("Carga un an\u00e1lisis primero.", type = "warning"); return()
    }
    if (!udpipe_disponible) {
      showNotification("Instala el paquete udpipe: install.packages('udpipe')", type = "error"); return()
    }
    if (is.null(datos$words)) {
      showNotification("No hay datos de palabras cargados.", type = "error"); return()
    }
    withProgress(message = "An\u00e1lisis UDPIPE...", value = 0, {
      tryCatch({
        library(udpipe)
        modelo_nombre <- switch(
          if (!is.null(input$idioma)) input$idioma else "Español",
          "Español"   = "spanish-ancora",
          "Catalán"   = "catalan-ancora",
          "Francés"   = "french-gsd",
          "Italiano"  = "italian-isdt",
          "Portugués" = "portuguese-bosque",
          "Alemán"    = "german-gsd",
          "Inglés"    = "english-ewt",
          "Chino"     = "chinese-gsd",
          "spanish-ancora"
        )
        modelo_lang <- sub("-.*", "", modelo_nombre)
        modelo_path <- list.files(pattern = paste0(modelo_nombre, ".*\\.udpipe$"), recursive = FALSE)
        if (length(modelo_path) == 0) {
          incProgress(0.1, detail = "Descargando modelo...")
          modelo_path <- udpipe_download_model(language = modelo_nombre, model_dir = ".")$file_model
        } else { modelo_path <- modelo_path[1] }
        incProgress(0.2, detail = "Cargando modelo...")
        udmodel <- udpipe_load_model(file = modelo_path)
        words <- datos$words
        grupos_texto <- unique(words[, c("hablante", "filename")])
        all_udpipe <- data.frame()
        for (i in 1:nrow(grupos_texto)) {
          spk <- grupos_texto$hablante[i]; fn <- grupos_texto$filename[i]
          words_spk <- words[words$hablante == spk & words$filename == fn, ]
          words_spk <- words_spk[order(words_spk$tmin), ]
          texto_raw <- paste(words_spk$etiqueta[!is.na(words_spk$etiqueta) & words_spk$etiqueta != ""], collapse = " ")
          if (nchar(texto_raw) == 0) next
          incProgress(0.3 / nrow(grupos_texto), detail = paste0("Procesando ", spk, "..."))
          ann <- udpipe_annotate(udmodel, x = texto_raw)
          ann_df <- as.data.frame(ann); ann_df$hablante <- spk; ann_df$filename <- fn
          all_udpipe <- bind_rows(all_udpipe, ann_df)
        }
        incProgress(0.2, detail = "Propagando...")
        datos$udpipe_words <- all_udpipe
        if (nrow(all_udpipe) > 0 && nrow(words) > 0) {
          words$upos <- NA_character_; words$xpos <- NA_character_
          words$feats <- NA_character_; words$dep_rel <- NA_character_; words$lemma <- NA_character_
          for (spk in unique(all_udpipe$hablante)) {
            for (fn in unique(all_udpipe$filename[all_udpipe$hablante == spk])) {
              udp_sub <- all_udpipe[all_udpipe$hablante == spk & all_udpipe$filename == fn, ]
              w_sub_idx <- which(words$hablante == spk & words$filename == fn)
              if (length(w_sub_idx) == 0 || nrow(udp_sub) == 0) next
              udp_tokens <- udp_sub[udp_sub$upos != "PUNCT", ]
              n_match <- min(nrow(udp_tokens), length(w_sub_idx))
              for (j in 1:n_match) {
                w_idx <- w_sub_idx[j]
                words$upos[w_idx] <- udp_tokens$upos[j]; words$xpos[w_idx] <- udp_tokens$xpos[j]
                words$feats[w_idx] <- udp_tokens$feats[j]; words$dep_rel[w_idx] <- udp_tokens$dep_rel[j]
                words$lemma[w_idx] <- udp_tokens$lemma[j]
              }
            }
          }
          datos$words <- words
          phones <- datos$phones
          if (!is.null(phones) && nrow(phones) > 0) {
            phones$upos <- NA_character_; phones$xpos <- NA_character_
            phones$feats <- NA_character_; phones$dep_rel <- NA_character_; phones$lemma <- NA_character_
            for (idx in 1:nrow(phones)) {
              pal <- phones$palabra[idx]; spk <- phones$hablante[idx]; fn <- phones$filename[idx]
              if (is.na(pal) || pal == "") next
              w_match <- which(words$etiqueta == pal & words$hablante == spk & words$filename == fn & !is.na(words$upos))
              if (length(w_match) > 0) {
                phones$upos[idx] <- words$upos[w_match[1]]; phones$xpos[idx] <- words$xpos[w_match[1]]
                phones$feats[idx] <- words$feats[w_match[1]]; phones$dep_rel[idx] <- words$dep_rel[w_match[1]]
                phones$lemma[idx] <- words$lemma[w_match[1]]
              }
            }
            datos$phones <- phones
          }
        }
        datos$analisis_morfosintactico <- TRUE
        log_event("UDPIPE_COMPLETADO", paste0(nrow(datos$udpipe_words), " tokens"))
        guardar_todos_por_archivo(notificar_cada = FALSE)
        showModal(modalDialog(
          title = tagList(icon("check-circle", class = "text-success"), " UDPipe completado"),
          paste0("An\u00e1lisis morfosint\u00e1ctico completado: ", nrow(datos$udpipe_words), " tokens. Guardado."),
          easyClose = TRUE, footer = modalButton("Cerrar")
        ))
      }, error = function(e) {
        showNotification(paste("Error UDPIPE:", e$message), type = "error")
      })
    })
  })

  # Completar: Sentimientos — dispatch to existing sentiment pipeline
  observeEvent(input$completar_btn_sent, {
    if (!isTRUE(datos$calculado)) {
      showNotification("Carga un an\u00e1lisis primero.", type = "warning"); return()
    }
    updateNavbarPage(session, "navbar_principal", selected = "tab_sentimientos")
    showNotification("Navega al tab Sentimientos y emociones y pulsa 'Analizar'. Los datos se guardar\u00e1n autom\u00e1ticamente al completar.", type = "message", duration = 6)
  })

  # Completar: Emociones audio — navigate to sentimientos tab
  observeEvent(input$completar_btn_audio, {
