      showNotification("Carga un an\u00e1lisis primero.", type = "warning"); return()
    }
    updateNavbarPage(session, "navbar_principal", selected = "tab_sentimientos")
    showNotification("Navega al tab Sentimientos y emociones, secci\u00f3n 'Emociones audio', y pulsa el bot\u00f3n de an\u00e1lisis. Los datos se guardar\u00e1n al completar.", type = "message", duration = 6)
