  # Completar: Cláusulas — recalculate with current thresholds
  observeEvent(input$completar_btn_clausulas, {
    req(datos$calculado, datos$ips_resumen)
    showNotification("Recalculando cl\u00e1usulas...", type = "message")
    tryCatch({
      # Use completar-specific thresholds if provided, else fallback to global
      umbral_cl  <- if (!is.null(input$completar_umbral_clausula)) input$completar_umbral_clausula else 0.5
      umbral_pit <- if (!is.null(input$completar_umbral_pitch_cl)) input$completar_umbral_pitch_cl else 30
      # Trigger via the existing recalc mechanism
      shinyjs::click("btn_recalc_ge")
      showNotification("Recalculando GEs y cl\u00e1usulas...", type = "message")
    }, error = function(e) {
      showNotification(paste("Error:", e$message), type = "error")
    })
  })
  
  output$cargar_tabla_analisis <- renderDT({
    df <- cargar_analisis_lista()
    if (nrow(df) == 0) return(datatable(data.frame(Mensaje = "No hay an\u00e1lisis guardados"), options = list(dom = "t")))
    # Pre-ordenar en R: más reciente primero
    df <- df[order(df$FechaNumerica, decreasing = TRUE), ]
    # Columnas a mostrar: FechaNumerica al final para ocultar por índice
    cols_show <- c("Nombre", "Genero", "Fecha", "N_archivos", "N_IPs", "FechaNumerica")
    # Con rownames=FALSE: col 0-based → Nombre=0, Genero=1, Fecha=2, N_archivos=3, N_IPs=4, FechaNumerica=5
    datatable(df[, cols_show],
              selection = "multiple",
              rownames = FALSE,
              options = list(
                pageLength = 10,
                dom = "fip",
                order = list(list(5L, "desc")),
                columnDefs = list(list(visible = FALSE, targets = 5L))
              ),
              colnames = c("Nombre", "G\u00e9nero", "Fecha", "Archivos", "IPs", "FechaNumerica"))
  })
  
  # Helper: df ordenado igual que la tabla DT (FechaNumerica desc)
  cargar_df_ordenado <- function() {
    df <- cargar_analisis_lista()
    if (nrow(df) > 0) df <- df[order(df$FechaNumerica, decreasing = TRUE), ]
    df
  }

  # Cargar seleccionados
  observeEvent(input$cargar_seleccionados, {
