    rutas <- df$Ruta[sel]
    nombres <- df$Nombre[sel]
    showModal(modalDialog(
      title = "Confirmar eliminación",
      tags$p("Se eliminarán ", tags$strong(length(rutas)), " análisis:"),
      tags$ul(lapply(nombres, tags$li)),
      tags$p(class = "text-danger", icon("exclamation-triangle"), " Esta acción no se puede deshacer."),
      footer = tagList(
        actionButton("confirmar_eliminar", "Eliminar", icon = icon("trash"), class = "btn-danger"),
        modalButton("Cancelar")
      )
    ))
  })
  
  observeEvent(input$confirmar_eliminar, {
    df <- cargar_df_ordenado()
    sel <- input$cargar_tabla_analisis_rows_selected
    if (!is.null(sel) && length(sel) > 0) {
      rutas <- df$Ruta[sel]
      n_ok <- 0
      for (ruta in rutas) {
        tryCatch({
          if (file.exists(ruta)) { file.remove(ruta); n_ok <- n_ok + 1 }
          meta_ruta <- sub("\\.rds$", ".meta.rds", ruta)
          if (file.exists(meta_ruta)) file.remove(meta_ruta)
        }, error = function(e) NULL)
      }
      showNotification(paste0("Eliminados ", n_ok, " análisis"), type = "message")
    }
    removeModal()
  })
  
  # ---- TAB ARCHIVOS: Server ----
  arch_lista <- reactiveVal(data.frame())

  # Cargar lista al inicio de la sesión
  observe({
    isolate({
      tryCatch({
        df_init <- listar_analisis_guardados("todos", "todos")
        if (nrow(df_init) > 0) arch_lista(df_init)
      }, error = function(e) NULL)
    })
  })

  observeEvent(list(input$arch_filtro_genero, input$arch_filtro_estado, input$arch_refrescar), {
    gen <- if (!is.null(input$arch_filtro_genero)) input$arch_filtro_genero else "todos"
    est <- if (!is.null(input$arch_filtro_estado)) input$arch_filtro_estado else "todos"
    arch_lista(listar_analisis_guardados(gen, est))
  }, ignoreNULL = FALSE, ignoreInit = FALSE)
  
  output$arch_tabla_analisis <- renderDT({
    df <- arch_lista()
    if (nrow(df) == 0) return(datatable(data.frame(Info = "No hay an\u00e1lisis guardados"), options = list(dom = 't')))
    df <- df[order(df$FechaNumerica, decreasing = TRUE), ]
    show_cols <- c("Nombre", "Genero", "Fecha", "N_archivos", "N_IPs",
                   "Prosodia", "Sentim.", "Emoc.Audio", "Morfosin.", "Etiquetado", "Completo", "FechaNumerica")
    # rownames=FALSE: col 0-based, FechaNumerica es la 11
    datatable(df[, show_cols],
              selection = "multiple",
              rownames = FALSE,
              options = list(pageLength = 15, dom = 'ftp', scrollX = TRUE,
                order = list(list(11L, "desc")),
                columnDefs = list(
                  list(className = 'dt-center', targets = 5:10),
                  list(visible = FALSE, targets = 11L)
                ))) %>%
      formatStyle("Completo", color = styleEqual(c("\u2714", "\u2718"), c("#28a745", "#dc3545"))) %>%
      formatStyle("Prosodia", color = styleEqual(c("\u2714", "\u2718"), c("#28a745", "#adb5bd"))) %>%
      formatStyle("Sentim.", color = styleEqual(c("\u2714", "\u2718"), c("#28a745", "#adb5bd"))) %>%
      formatStyle("Emoc.Audio", color = styleEqual(c("\u2714", "\u2718"), c("#28a745", "#adb5bd"))) %>%
      formatStyle("Morfosin.", color = styleEqual(c("\u2714", "\u2718"), c("#28a745", "#adb5bd"))) %>%
      formatStyle("Etiquetado", color = styleEqual(c("\u2714", "\u2718"), c("#28a745", "#adb5bd")))
  })
  
  output$arch_tabla_audios <- renderDT({
