    if (length(archivos) == 0) return(datatable(data.frame(Info = "No hay audios"), options = list(dom = 't')))
    info <- file.info(archivos)
    df <- data.frame(
      Nombre = basename(archivos),
      Tamaño = paste0(round(info$size / 1024^2, 1), " MB"),
      Fecha = format(info$mtime, "%d/%m/%Y"),
      stringsAsFactors = FALSE
    )
    datatable(df, selection = "multiple", options = list(pageLength = 10, dom = 'tip'))
  })
  
  output$arch_tabla_textgrids <- renderDT({
    input$arch_refrescar
    archivos <- list.files(lasp_textgrids, full.names = TRUE)
    if (length(archivos) == 0) return(datatable(data.frame(Info = "No hay TextGrids"), options = list(dom = 't')))
    info <- file.info(archivos)
    df <- data.frame(Nombre = basename(archivos), Fecha = format(info$mtime, "%d/%m/%Y"), stringsAsFactors = FALSE)
    datatable(df, selection = "multiple", options = list(pageLength = 10, dom = 'tip'))
  })
  
  output$arch_tabla_preprocesados <- renderDT({
    input$arch_refrescar
    input$arch_eliminar_preproc  # refresh on delete
    archivos <- list.files(lasp_preprocesados, pattern = "\\.(txt|csv)$", full.names = TRUE)
    if (length(archivos) == 0) return(datatable(data.frame(Info = "No hay archivos preprocesados"), options = list(dom = 't')))
    info <- file.info(archivos)
    nombres <- basename(archivos)
    # Categorizar: texto, pitch, intensidad
    tipo <- ifelse(grepl("_texto\\.", nombres), "texto",
              ifelse(grepl("_pitch\\.", nombres), "pitch",
                ifelse(grepl("_intensidad\\.", nombres), "intensidad", "otro")))
    df <- data.frame(
      Nombre = nombres, Tipo = tipo,
      Tamaño = paste0(round(info$size / 1024, 1), " KB"),
      Fecha = format(info$mtime, "%d/%m/%Y %H:%M"),
      stringsAsFactors = FALSE
    )
    datatable(df, selection = "multiple", options = list(pageLength = 15, dom = 'tip'))
  })
  
  observeEvent(input$arch_eliminar_preproc, {
    archivos <- list.files(lasp_preprocesados, pattern = "\\.(txt|csv)$", full.names = TRUE)
    sel <- input$arch_tabla_preprocesados_rows_selected
    if (is.null(sel) || length(sel) == 0) { showNotification("Selecciona archivos", type = "warning"); return() }
    for (i in sel) tryCatch(file.remove(archivos[i]), error = function(e) NULL)
    log_event("PREPROCESADOS_ELIMINADOS", paste0(length(sel), " archivos"))
    showNotification(paste(length(sel), "archivos eliminados"), type = "message")
  })
  
