    n_etiq <- length(list.files(lasp_etiquetado, pattern = "\\.rds$"))
    n_logs <- length(list.files(lasp_logs))
    size_total <- sum(file.info(list.files(lasp_base, recursive = TRUE, full.names = TRUE))$size, na.rm = TRUE)
