  # ---- DETECCIÓN DE DUPLICADOS ----
  # Reactivo que se activa antes de guardar
  comprobar_duplicado_y_guardar <- function(nombre, genero) {
    # Generate name if NULL
    if (is.null(nombre)) {
      fns <- if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones)) {
        paste(sort(unique(datos$phones$filename)), collapse = "_")
      } else {
        format(Sys.time(), "%Y%m%d_%H%M%S")
      }
      nombre <- gsub("[^a-zA-Z0-9_áéíóúàèìòùñç-]", "_", fns)
      if (nchar(nombre) > 80) nombre <- substr(nombre, 1, 80)
    }
    
    rds_path <- file.path(lasp_analisis, genero, paste0(nombre, ".rds"))
    if (file.exists(rds_path)) {
      showModal(modalDialog(
        title = "Archivo ya existe",
        tags$p("Ya existe un análisis con el nombre ", tags$strong(nombre), 
               " en el género ", tags$em(genero), "."),
        tags$p("¿Deseas sobrescribirlo?"),
        footer = tagList(
          actionButton("dup_sobrescribir", "Sobrescribir", class = "btn-warning"),
          modalButton("Cancelar")
        )
      ))
      # Guardar nombre/genero para usarlos en el observer
      datos$dup_nombre <- nombre
      datos$dup_genero <- genero
    } else {
      guardar_todos_por_archivo(genero = genero, notificar_cada = FALSE)
    }
  }
  
  observeEvent(input$dup_sobrescribir, {
    removeModal()
    if (!is.null(datos$dup_nombre)) {
      guardar_todos_por_archivo(genero = datos$dup_genero, notificar_cada = FALSE)
      datos$dup_nombre <- NULL
      datos$dup_genero <- NULL
    }
  })
  
  # Importar análisis previo (solo en Exportar/Importar)
  observeEvent(input$importar_rdata, {
    req(input$importar_rdata)
    tryCatch({
      env <- new.env()
      load(input$importar_rdata$datapath, envir = env)
      if (exists("analisis_prosodia", envir = env)) {
        analisis <- env$analisis_prosodia
        datos$phones <- analisis$phones; datos$words <- analisis$words
        datos$ips_resumen <- limpiar_emociones_cjk(corregir_semitones_si_necesario(analisis$ips_resumen)); datos$gfs_resumen <- analisis$gfs_resumen
        datos$vocales_por_ip <- analisis$vocales_por_ip; datos$medias_hablante <- analisis$medias_hablante
        datos$sentimientos <- if (!is.null(analisis$sentimientos)) limpiar_emociones_cjk(analisis$sentimientos) else NULL
        datos$analisis_sentimientos <- isTRUE(analisis$analisis_sentimientos)
        datos$analisis_emociones_audio <- isTRUE(analisis$analisis_emociones_audio)
        datos$calculado <- TRUE; datos$nombre_archivo <- input$importar_rdata$name
        
        # Rebuild sentimientos from ips_resumen if sentimientos df is missing but columns exist
        if (is.null(datos$sentimientos) && !is.null(datos$ips_resumen)) {
          sent_cols <- intersect(c("sentimiento", "emocion_texto", "emocion_audio", 
                                    "prob_pos", "prob_neg", "prob_neu", "prob_emocion_texto", "prob_emocion_audio"),
                                  colnames(datos$ips_resumen))
          if (length(sent_cols) > 0 && any(datos$ips_resumen[["sentimiento"]] != "", na.rm = TRUE)) {
            id_cols <- intersect(c("filename", "hablante", "id_ge", "palabras_grupo"), colnames(datos$ips_resumen))
            datos$sentimientos <- datos$ips_resumen[, c(id_cols, sent_cols), drop = FALSE]
            datos$analisis_sentimientos <- TRUE
          }
        }
        
        showNotification("Análisis importado correctamente", type = "message")
      } else { showNotification("Archivo no válido", type = "error") }
    }, error = function(e) showNotification(paste("Error:", e$message), type = "error"))
  })
  
  output$info_importacion <- renderText({
    if (!is.null(datos$nombre_archivo) && datos$calculado)
      paste0("✔ Archivo cargado: ", datos$nombre_archivo)
    else "No hay análisis importado"
  })
  
  # Cargar archivos múltiples
  # ========================================
  # DATOS PROPIOS: CARGAR DESDE CARPETA
  # ========================================
  
  # UI: listar archivos disponibles en lasp_preprocesados
  # DT de archivos preprocesados (reemplaza checkboxGroupInput para 1500+ archivos)
  dp_archivos_lista <- reactive({
    input$dp_cargar_desde_carpeta
    input$dp_refrescar_lista
    input$dp_aplicar_genero  # refresca tras asignar g\u00e9nero
    txt_files <- list.files(lasp_preprocesados, pattern = "_texto\\.txt$", full.names = FALSE)
    filenames  <- sub("_texto\\.txt$", "", txt_files)
    if (length(filenames) == 0) return(data.frame())

    # Intentar inferir g\u00e9nero desde el nombre del archivo o carpetas de an\u00e1lisis
    # Buscar si existe un .meta.rds correspondiente para leer el g\u00e9nero guardado
    # NOTA: los RDS se guardan con nombre saneado (gsub de caracteres especiales)
    generos <- sapply(filenames, function(fn) {
      nombre_base <- gsub("[^a-zA-Z0-9_\u00e1\u00e9\u00ed\u00f3\u00fa\u00e0\u00e8\u00ec\u00f2\u00f9\u00f1\u00e7-]", "_", fn)
      if (nchar(nombre_base) > 80) nombre_base <- substr(nombre_base, 1, 80)
      # Buscar meta en cualquier subcarpeta de g\u00e9neros
      gen_dirs <- c("peliculas","series","interpretacion","entrevistas","conversaciones")
      encontrado <- NA_character_
      for (gd in gen_dirs) {
        # Buscar con nombre saneado (como lo guarda guardar_analisis_por_archivo)
        meta_path <- file.path(lasp_analisis, gd, paste0(nombre_base, ".meta.rds"))
        if (file.exists(meta_path)) { encontrado <- gd; break }
        rds_path <- file.path(lasp_analisis, gd, paste0(nombre_base, ".rds"))
        if (file.exists(rds_path)) { encontrado <- gd; break }
        # Fallback: buscar tambi\u00e9n con nombre original (por si se guard\u00f3 sin sanear)
        meta_path_orig <- file.path(lasp_analisis, gd, paste0(fn, ".meta.rds"))
        if (file.exists(meta_path_orig)) { encontrado <- gd; break }
        rds_path_orig <- file.path(lasp_analisis, gd, paste0(fn, ".rds"))
        if (file.exists(rds_path_orig)) { encontrado <- gd; break }
      }
      encontrado
    }, USE.NAMES = FALSE)

    data.frame(
      Archivo    = filenames,
      Genero     = ifelse(is.na(generos), "?", generos),
      Texto      = file.exists(file.path(lasp_preprocesados, paste0(filenames, "_texto.txt"))),
      Pitch      = file.exists(file.path(lasp_preprocesados, paste0(filenames, "_pitch.txt"))),
      Intensidad = file.exists(file.path(lasp_preprocesados, paste0(filenames, "_intensidad.txt"))),
      Audio      = sapply(filenames, function(fn)
                     any(file.exists(file.path(lasp_audios, paste0(fn, c(".wav",".flac",".mp3",".WAV")))))),
      stringsAsFactors = FALSE
    )
  })

  # Filtrado reactivo según selectInput de género
  dp_archivos_filtrados <- reactive({
    df  <- dp_archivos_lista()
    gen <- if (!is.null(input$dp_filtro_genero)) input$dp_filtro_genero else "todos"
    if (gen != "todos" && nrow(df) > 0) df <- df[df$Genero == gen, ]
    df
  })

  output$dp_archivos_dt <- renderDT({
    df <- dp_archivos_filtrados()
    if (nrow(df) == 0) {
      return(datatable(data.frame(Mensaje = "No hay archivos preprocesados disponibles."),
                       options = list(dom = "t"), rownames = FALSE))
    }
    df_show <- df
    for (col in c("Texto","Pitch","Intensidad","Audio")) {
      df_show[[col]] <- ifelse(df[[col]],
        '<span style="color:#28a745">&#10003;</span>',
        '<span style="color:#dc3545">&#10007;</span>')
    }
    datatable(df_show,
      selection  = "multiple",
      escape     = FALSE,
      rownames   = FALSE,
      options    = list(
        pageLength = 50,
        dom        = "ftipr",
        scrollY    = "600px",
        scrollCollapse = TRUE,
        columnDefs = list(list(className = "dt-center", targets = 2:5))
      )
    )
  })

  # Seleccionar todos los filtrados
  observeEvent(input$dp_seleccionar_todos_filtrados, {
    df <- dp_archivos_filtrados()
    if (nrow(df) > 0) {
      proxy <- dataTableProxy("dp_archivos_dt")
      selectRows(proxy, seq_len(nrow(df)))
    }
  })

  # Botón: seleccionar todos los filtrados (actualizado)
  observeEvent(input$dp_seleccionar_filtrados, {
    df <- dp_archivos_filtrados()
    if (nrow(df) > 0) {
      proxy <- dataTableProxy("dp_archivos_dt")
      selectRows(proxy, seq_len(nrow(df)))
    }
