  # Botón: limpiar selección
  observeEvent(input$dp_deseleccionar_todos, {
    proxy <- dataTableProxy("dp_archivos_dt")
    selectRows(proxy, NULL)
  })

  # Bot\u00f3n: asignar g\u00e9nero a archivos seleccionados
  observeEvent(input$dp_aplicar_genero, {
    gen_nuevo <- input$dp_asignar_genero
    if (is.null(gen_nuevo) || gen_nuevo == "") {
      showNotification("Selecciona un g\u00e9nero para asignar.", type = "warning"); return()
    }
    df <- dp_archivos_filtrados()
    sel_idx <- input$dp_archivos_dt_rows_selected
    if (is.null(sel_idx) || length(sel_idx) == 0) {
      showNotification("Selecciona al menos un archivo en la tabla.", type = "warning"); return()
    }
    sel_fns <- df$Archivo[sel_idx]
    n_movidos <- 0
    gen_dirs <- c("peliculas","series","interpretacion","entrevistas","conversaciones")

    for (fn in sel_fns) {
      # Sanear nombre igual que guardar_analisis_por_archivo
      nombre_base <- gsub("[^a-zA-Z0-9_\u00e1\u00e9\u00ed\u00f3\u00fa\u00e0\u00e8\u00ec\u00f2\u00f9\u00f1\u00e7-]", "_", fn)
      if (nchar(nombre_base) > 80) nombre_base <- substr(nombre_base, 1, 80)

      # Buscar el RDS existente en cualquier carpeta de g\u00e9nero
      # Intentar con nombre saneado y con nombre original
      rds_orig <- NULL
      meta_orig <- NULL
      for (gd in gen_dirs) {
        # Nombre saneado (prioridad)
        rp <- file.path(lasp_analisis, gd, paste0(nombre_base, ".rds"))
        if (file.exists(rp)) {
          rds_orig <- rp
          mp <- file.path(lasp_analisis, gd, paste0(nombre_base, ".meta.rds"))
          if (file.exists(mp)) meta_orig <- mp
          break
        }
        # Nombre original (fallback)
        rp2 <- file.path(lasp_analisis, gd, paste0(fn, ".rds"))
        if (file.exists(rp2)) {
          rds_orig <- rp2
          mp2 <- file.path(lasp_analisis, gd, paste0(fn, ".meta.rds"))
          if (file.exists(mp2)) meta_orig <- mp2
          break
        }
      }

      # Destino siempre con nombre saneado
      rds_dest  <- file.path(lasp_analisis, gen_nuevo, paste0(nombre_base, ".rds"))
      meta_dest <- file.path(lasp_analisis, gen_nuevo, paste0(nombre_base, ".meta.rds"))
      dir.create(dirname(rds_dest), recursive = TRUE, showWarnings = FALSE)

      if (!is.null(rds_orig)) {
        if (normalizePath(rds_orig, mustWork = FALSE) != normalizePath(rds_dest, mustWork = FALSE)) {
          # Mover RDS a nueva carpeta
          file.rename(rds_orig, rds_dest)
          if (!is.null(meta_orig)) file.rename(meta_orig, meta_dest)
        }
        # Actualizar genero_discursivo dentro del RDS
        tryCatch({
          obj <- readRDS(rds_dest)
          obj$genero_discursivo <- gen_nuevo
          saveRDS(obj, rds_dest)
          # Actualizar meta
          meta <- if (file.exists(meta_dest)) readRDS(meta_dest) else list()
          meta$genero_discursivo <- gen_nuevo
          meta$nombre_archivos <- fn
          meta$fecha_guardado <- Sys.time()
          saveRDS(meta, meta_dest)
        }, error = function(e) {
          message("[dp_aplicar_genero] Error actualizando RDS para '", fn, "': ", e$message)
        })
        n_movidos <- n_movidos + 1
      } else {
        # No hay RDS a\u00fan \u2014 crear un .meta.rds marcador
        meta <- list(nombre_archivos = fn, genero_discursivo = gen_nuevo,
                     fecha_guardado = Sys.time())
        saveRDS(meta, meta_dest)
        n_movidos <- n_movidos + 1
      }
    }
    showNotification(paste0("\u2714 ", n_movidos, " archivo(s) asignados a '", gen_nuevo, "'"),
                     type = "message", duration = 4)
  })

  # ============================================================
  # CAMBIAR GÉNERO DISCURSIVO DEL ANÁLISIS YA CARGADO
