    gen_labels <- c("peliculas"="Películas","series"="Series","interpretacion"="Interpretación",
                    "entrevistas"="Entrevistas","conversaciones"="Conversaciones")
    gen_label  <- if (!is.na(gen_labels[gen_actual])) gen_labels[gen_actual] else gen_actual
    div(
      style = "margin-top:4px; padding:6px 8px; background:#f0f9ff; border:1px solid #bae6fd; border-radius:6px; font-size:0.85em;",
      tags$span(icon("tag"), " Género cargado: ", tags$strong(gen_label)),
      tags$br(),
      actionButton("btn_cambiar_genero_cargado",
        label = tagList(icon("pencil"), " Cambiar género"),
        class = "btn-outline-primary btn-sm",
        style = "margin-top:5px; width:100%;")
    )
  })

  # Abrir modal de cambio de género
  observeEvent(input$btn_cambiar_genero_cargado, {
    req(datos$calculado, !is.null(datos$ips_resumen))
    gen_actual  <- if (!is.null(datos$genero_discursivo)) datos$genero_discursivo else "entrevistas"
    fns_cargados <- sort(unique(as.character(datos$ips_resumen$filename)))
    opciones_fn  <- c("__todos__" = "— Todos los archivos cargados —", setNames(fns_cargados, fns_cargados))

    showModal(modalDialog(
      title = tagList(icon("pencil-alt"), " Cambiar género discursivo"),
      size  = "m",
      easyClose = FALSE,
      tagList(
        p(style = "font-size:0.9em; color:#555;",
          "Puedes cambiar el género discursivo del análisis actualmente cargado en memoria ",
          "y, opcionalmente, actualizar también los archivos RDS en disco."),
        fluidRow(
          column(6,
            selectInput("cg_nuevo_genero", "Nuevo género:",
              choices = c("Películas" = "peliculas", "Series" = "series",
                          "Interpretación" = "interpretacion",
                          "Entrevistas" = "entrevistas",
                          "Conversaciones" = "conversaciones"),
              selected = gen_actual)
          ),
          column(6,
            selectInput("cg_archivos", "Archivos afectados:",
              choices  = opciones_fn,
              selected = "__todos__",
              multiple = FALSE)
          )
        ),
        checkboxInput("cg_actualizar_disco", "Actualizar también en disco (archivos RDS)", value = FALSE),
        div(class = "alert alert-warning", style = "font-size:0.85em; margin-top:8px;",
          icon("exclamation-triangle"),
          " Si seleccionas un archivo concreto, solo se actualizará ese archivo. ",
          "El resto mantendrá su género original.")
      ),
      footer = tagList(
        modalButton("Cancelar"),
        actionButton("btn_confirmar_cambio_genero",
          label = tagList(icon("check"), " Confirmar cambio"),
          class = "btn-warning")
      )
    ))
  })

  # Aplicar el cambio de género al confirmar
  observeEvent(input$btn_confirmar_cambio_genero, {
    removeModal()
    req(datos$calculado, !is.null(datos$ips_resumen))

    gen_nuevo       <- input$cg_nuevo_genero
    archivo_sel     <- input$cg_archivos
    actualizar_disco <- isTRUE(input$cg_actualizar_disco)
    todos <- (is.null(archivo_sel) || archivo_sel == "__todos__")

    # Determinar qué filenames se modifican
    fns_todos <- sort(unique(as.character(datos$ips_resumen$filename)))
    fns_mod   <- if (todos) fns_todos else archivo_sel

    # ── Actualizar columna 'genero' en cada data.frame en memoria ──
    actualizar_col_genero <- function(df, fns) {
      if (is.null(df) || !is.data.frame(df)) return(df)
      col_fn <- if ("filename" %in% colnames(df)) "filename" else NULL
      if (is.null(col_fn)) {
        if (todos) df$genero <- gen_nuevo
        return(df)
      }
      df$genero[df[[col_fn]] %in% fns] <- gen_nuevo
      df
    }

    datos$phones        <- actualizar_col_genero(datos$phones,       fns_mod)
    datos$words         <- actualizar_col_genero(datos$words,        fns_mod)
    datos$ips_resumen   <- actualizar_col_genero(datos$ips_resumen,  fns_mod)
    datos$gfs_resumen   <- actualizar_col_genero(datos$gfs_resumen,  fns_mod)
    datos$clausulas     <- actualizar_col_genero(datos$clausulas,    fns_mod)
    datos$actos_resumen <- actualizar_col_genero(datos$actos_resumen, fns_mod)
    datos$sentimientos  <- actualizar_col_genero(datos$sentimientos,  fns_mod)

    # Actualizar genero_discursivo global solo si afecta a todos los archivos
    if (todos) datos$genero_discursivo <- gen_nuevo

    # Actualizar selector de género en la UI
    updateSelectInput(session, "genero_discursivo", selected = gen_nuevo)

    n_mod <- length(fns_mod)
    n_disco <- 0L

    # ── Actualizar RDS en disco (opcional) ──────────────────────────
    if (actualizar_disco) {
      generos_validos <- c("peliculas","series","interpretacion","entrevistas","conversaciones")
      for (fn in fns_mod) {
        rds_orig <- NULL
        for (gd in generos_validos) {
          rp <- file.path(lasp_analisis, gd, paste0(fn, ".rds"))
          if (file.exists(rp)) { rds_orig <- rp; break }
        }
        if (is.null(rds_orig)) next
        rds_dest  <- file.path(lasp_analisis, gen_nuevo, paste0(fn, ".rds"))
        meta_orig <- sub("\\.rds$", ".meta.rds", rds_orig)
        meta_dest <- file.path(lasp_analisis, gen_nuevo, paste0(fn, ".meta.rds"))
        dir.create(dirname(rds_dest), recursive = TRUE, showWarnings = FALSE)
        tryCatch({
          if (normalizePath(rds_orig, mustWork=FALSE) != normalizePath(rds_dest, mustWork=FALSE))
            file.rename(rds_orig, rds_dest)
          obj <- readRDS(rds_dest)
          obj$genero_discursivo <- gen_nuevo
          saveRDS(obj, rds_dest)
          if (file.exists(meta_orig)) {
            meta <- readRDS(meta_orig)
            meta$genero_discursivo <- gen_nuevo
            saveRDS(meta, meta_dest)
            if (normalizePath(meta_orig, mustWork=FALSE) != normalizePath(meta_dest, mustWork=FALSE))
              unlink(meta_orig)
          }
          n_disco <- n_disco + 1L
        }, error = function(e) {
          showNotification(paste0("Error actualizando '", fn, "': ", e$message),
                           type = "warning", duration = 6)
        })
      }
    }

    gen_labels <- c("peliculas"="Películas","series"="Series","interpretacion"="Interpretación",
                    "entrevistas"="Entrevistas","conversaciones"="Conversaciones")
    gen_label  <- if (!is.na(gen_labels[gen_nuevo])) gen_labels[gen_nuevo] else gen_nuevo
    msg <- paste0("\u2714 Género cambiado a '", gen_label, "' para ", n_mod, " archivo(s) en memoria")
    if (actualizar_disco) msg <- paste0(msg, " y ", n_disco, " en disco")
    showNotification(msg, type = "message", duration = 6)
    log_event("CAMBIO_GENERO", paste0(gen_nuevo, " | archivos: ", paste(fns_mod, collapse=", ")))
  })

  # Botón: cargar todos los filtrados (sin necesidad de seleccionarlos primero)
  observeEvent(input$dp_cargar_todos_filtrados, {
    df <- dp_archivos_filtrados()
    if (nrow(df) == 0) {
      showNotification("No hay archivos en la selecci\u00f3n actual.", type = "warning"); return()
    }
    sel_fns <- df$Archivo
    showNotification(paste0("Cargando ", length(sel_fns), " archivos..."), type = "message")
    # Seleccionar visualmente todas las filas en la DT
    proxy <- dataTableProxy("dp_archivos_dt")
    selectRows(proxy, seq_len(nrow(df)))
    # Disparar la carga usando el mismo mecanismo que dp_cargar_desde_carpeta
    # via un reactiveVal temporal
    etiq_dp_todos(etiq_dp_todos() + 1L)
  })

  etiq_dp_todos <- reactiveVal(0L)

  # Observer: cargar archivos seleccionados desde carpeta (usando DT)
  # También reacciona a dp_cargar_todos_filtrados vía etiq_dp_todos
  observeEvent(list(input$dp_cargar_desde_carpeta, etiq_dp_todos()), {
    # Determinar fuente: si vino de etiq_dp_todos, usar todos los filtrados
    desde_todos <- (etiq_dp_todos() > 0 &&
                    identical(isolate(input$dp_cargar_desde_carpeta), 0L))
    df_dp   <- dp_archivos_filtrados()
    if (desde_todos) {
      sel_fns <- df_dp$Archivo
    } else {
      sel_idx <- input$dp_archivos_dt_rows_selected
      if (is.null(sel_idx) || length(sel_idx) == 0) {
        showNotification("Selecciona al menos un archivo en la tabla.", type = "warning")
        return()
      }
      sel_fns <- df_dp$Archivo[sel_idx]
    }
    if (length(sel_fns) == 0) {
      showNotification("No hay archivos para cargar.", type = "warning"); return()
    }
    n_texto <- 0; n_pitch <- 0; n_int <- 0; n_audio <- 0
    errores <- character(0)
    
    tryCatch({
      withProgress(message = "Cargando preprocesados...", value = 0, {
        all_texto <- data.frame()
        all_pitch <- data.frame()
        all_int <- data.frame()
        
        for (i in seq_along(sel_fns)) {
          fn <- sel_fns[i]
          incProgress(1/length(sel_fns), detail = fn)
          
          # Texto
          txt_path <- file.path(lasp_preprocesados, paste0(fn, "_texto.txt"))
          if (file.exists(txt_path)) {
            tryCatch({
              df <- read.delim(txt_path, header = TRUE, stringsAsFactors = FALSE,
                               fileEncoding = "UTF-8", comment.char = "")
              colnames(df) <- tolower(trimws(colnames(df)))
              # Renombrar variantes comunes de columnas
              colnames(df) <- gsub("^xmin$", "tmin", colnames(df))
              colnames(df) <- gsub("^xmax$", "tmax", colnames(df))
              colnames(df) <- gsub("^label$|^text_$|^content$", "text", colnames(df))
              colnames(df) <- gsub("^interval$|^tier_name$", "tier", colnames(df))
              # Si aún no tiene 'tier', renombrar las 4 primeras columnas
              if (!"tier" %in% colnames(df) && ncol(df) >= 4) {
                colnames(df)[1:4] <- c("tier", "tmin", "tmax", "text")
              }
              # Verificar columnas mínimas
              if (!all(c("tier", "tmin", "tmax", "text") %in% colnames(df))) {
                errores <- c(errores, paste0(fn, "_texto: columnas incorrectas: ", paste(colnames(df), collapse=",")))
              } else {
                df$tmin <- as.numeric(df$tmin)
                df$tmax <- as.numeric(df$tmax)
                df <- df[!is.na(df$tmin) & !is.na(df$tmax), ]
                # Mantener solo columnas esenciales para evitar contaminación de análisis previos
                cols_keep <- intersect(c("tier","tmin","tmax","text"), colnames(df))
                df <- df[, cols_keep, drop = FALSE]
                df$archivo_origen <- fn
                all_texto <- bind_rows(all_texto, df)
                n_texto <- n_texto + 1
              }
            }, error = function(e) {
              errores <<- c(errores, paste0(fn, "_texto: ", e$message))
            })
          } else {
            errores <- c(errores, paste0(fn, "_texto.txt: no encontrado en ", lasp_preprocesados))
          }
          
          # Pitch
          pitch_path <- file.path(lasp_preprocesados, paste0(fn, "_pitch.txt"))
          if (file.exists(pitch_path)) {
            tryCatch({
              df <- read.delim(pitch_path, header = TRUE, stringsAsFactors = FALSE,
                               fileEncoding = "UTF-8", comment.char = "")
              colnames(df) <- tolower(trimws(colnames(df)))
              if (ncol(df) >= 2) colnames(df)[1:2] <- c("tiempo", "f0")
              df$f0 <- suppressWarnings(as.numeric(df$f0))
              df <- df[!is.na(df$f0) & df$f0 > 0, ]
              df$archivo_origen <- fn
              all_pitch <- bind_rows(all_pitch, df[, c("tiempo","f0","archivo_origen")])
              n_pitch <- n_pitch + 1
            }, error = function(e) {
              errores <<- c(errores, paste0(fn, "_pitch: ", e$message))
            })
          }
          
          # Intensidad
          int_path <- file.path(lasp_preprocesados, paste0(fn, "_intensidad.txt"))
          if (file.exists(int_path)) {
            tryCatch({
              df <- read.delim(int_path, header = TRUE, stringsAsFactors = FALSE,
                               fileEncoding = "UTF-8", comment.char = "")
              colnames(df) <- tolower(trimws(colnames(df)))
              if (ncol(df) >= 2) colnames(df)[1:2] <- c("tiempo", "intensidad")
              df$intensidad <- suppressWarnings(as.numeric(df$intensidad))
              df <- df[!is.na(df$intensidad) & df$intensidad > 0, ]
              df$archivo_origen <- fn
              all_int <- bind_rows(all_int, df[, c("tiempo","intensidad","archivo_origen")])
              n_int <- n_int + 1
            }, error = function(e) {
              errores <<- c(errores, paste0(fn, "_intensidad: ", e$message))
            })
          }
          
          # Audio (buscar en lasp_audios)
          for (ext in c(".wav", ".flac", ".mp3", ".WAV")) {
            audio_path <- file.path(lasp_audios, paste0(fn, ext))
            if (file.exists(audio_path)) {
              datos_audio$wavs[[fn]] <- audio_path
              n_audio <- n_audio + 1
              break
            }
          }
          
          # TextGrid (buscar en lasp_textgrids)
          tg_path <- file.path(lasp_textgrids, paste0(fn, ".TextGrid"))
          if (file.exists(tg_path)) {
            datos_textgrid$tgs[[fn]] <- tg_path
          }
        }
        
        if (nrow(all_texto) > 0) datos$texto <- all_texto
        if (nrow(all_pitch) > 0) datos$pitch <- all_pitch
        if (nrow(all_int) > 0) datos$intensidad <- all_int
      })
      
      resumen <- paste0("\u2714 Cargados desde carpeta: ",
                        n_texto, " texto (", nrow(datos$texto), " filas), ",
                        n_pitch, " pitch (", nrow(datos$pitch), " filas), ",
                        n_int, " intensidad (", nrow(datos$intensidad), " filas)",
                        if (n_audio > 0) paste0(", ", n_audio, " audio") else "")
      if (length(errores) > 0) {
        resumen <- paste0(resumen, "\n\u26a0 Errores: ", paste(errores, collapse = " | "))
        showNotification(paste("Errores al cargar:", paste(errores, collapse = "\n")), type = "warning", duration = 12)
      }
      output$dp_estado_carpeta <- renderText(resumen)
      showNotification(paste0("\u2714 Cargados: texto=", n_texto, " pitch=", n_pitch, " intens.=", n_int), type = "message", duration = 6)
      log_event("CARGAR_DESDE_CARPETA", paste0(length(sel_fns), " archivos: ", paste(sel_fns, collapse = ", "),
                if(length(errores)>0) paste0(" | ERRORES: ", paste(errores, collapse="; ")) else ""))
      
    }, error = function(e) {
      showNotification(paste("Error cargando:", e$message), type = "error")
    })
  })
  
  observeEvent(input$archivos_texto, {
