      guardar_preprocesados()
    }, error = function(e) showNotification(paste("Error:", e$message), type = "error"))
  })
  
  observeEvent(input$archivos_intensidad, {
    req(input$archivos_intensidad)
    tryCatch({
      all_int <- data.frame()
      for (i in 1:nrow(input$archivos_intensidad)) {
