        df <- df[!is.na(df$intensidad) & df$intensidad > 0, ]
        df$archivo_origen <- tools::file_path_sans_ext(archivo$name)
        all_int <- bind_rows(all_int, df)
      }
      datos$intensidad <- all_int
      log_event("ARCHIVOS_INTENSIDAD", paste0(nrow(input$archivos_intensidad), " archivo(s)"))
      showNotification(paste0("✔ ", nrow(input$archivos_intensidad), " archivo(s) de intensidad cargados"), type = "message")
      guardar_preprocesados()
    }, error = function(e) showNotification(paste("Error:", e$message), type = "error"))
  })
  
  # Audio upload para modo "Datos propios"
  observeEvent(input$archivos_audio_propios, {
    req(input$archivos_audio_propios)
