  output$sent_estado <- renderPrint({
    if (!is.null(datos$sentimientos) && nrow(datos$sentimientos) > 0) {
      n <- nrow(datos$sentimientos)
      has_sent <- any(datos$sentimientos$sentimiento != "", na.rm = TRUE)
      has_emo_txt <- any(datos$sentimientos$emocion_texto != "", na.rm = TRUE)
      has_emo_aud <- any(datos$sentimientos$emocion_audio != "" & 
                           datos$sentimientos$emocion_audio != "no_wav", na.rm = TRUE)
      
      cat(paste0(
        "\u2714 ", n, " grupos entonativos analizados\n",
        if (has_sent) "\u2714 Sentimiento textual: completado\n" else "",
        if (has_emo_txt) "\u2714 Emociones textuales: completado\n" else "",
        if (has_emo_aud) "\u2714 Emociones acústicas: completado\n" else ""
      ))
    } else if (datos$calculado) {
      cat("Listo para analizar. Pulse 'Analizar Sentimientos'.")
    } else {
      cat("Primero ejecute el análisis prosódico (Calcular).")
    }
  })
  
  # ========================================
  # FUNCIÓN PRINCIPAL DE CÁLCULO
  # ========================================
  observeEvent(input$calcular, {
    if (is.null(datos$texto) || is.null(datos$pitch) || is.null(datos$intensidad)) {
      showNotification("Carga los tres tipos de archivos", type = "error"); return()
    }
    
    withProgress(message = 'Analizando...', value = 0, {
      tryCatch({
        texto_data <- datos$texto
        pitch_data_all <- datos$pitch
        intensity_data_all <- datos$intensidad
        
        tiers_unicos <- unique(texto_data$tier)
        
        # ========================================
        # FASE 1: Recopilar todos los intervalos de todos los tiers
        # con su hablante y tipo, sin procesar aún
        # ========================================
        all_phones_raw <- data.frame()
        all_words_raw <- data.frame()
        all_utterances_raw <- data.frame()  # Separate collection for utterances tier
        words_lookup <- list()  # Para buscar palabras por hablante
        
        incProgress(0.05, detail = "Recopilando tiers...")
        
        # Crear combinaciones únicas de tier x archivo_origen para procesar por separado
        tier_archivo_combos <- unique(texto_data[, c("tier", "archivo_origen")])
        
        for (combo_idx in 1:nrow(tier_archivo_combos)) {
          tier_name <- tier_archivo_combos$tier[combo_idx]
          archivo_orig <- tier_archivo_combos$archivo_origen[combo_idx]
          
          # Detect tier type and speaker name
          # Pattern 1: "Speaker - phones" / "Speaker - words" (standard LASP)
          # Pattern 2: bare "phones" / "words" / "utterances" (e.g. Emofilm, no speaker prefix)
          speaker_name <- NULL
          tier_type <- NULL
          
          if (grepl(" - words$| - phones$", tier_name, ignore.case = TRUE)) {
            # Standard pattern: "A - phones", "B - words"
            speaker_name <- sub(" - (words|phones)$", "", tier_name, ignore.case = TRUE)
            tier_type <- if (grepl(" - words$", tier_name, ignore.case = TRUE)) "words" else "phones"
          } else if (grepl("^phones$", tier_name, ignore.case = TRUE)) {
            # Bare "phones" tier → speaker = filename
            speaker_name <- archivo_orig
            tier_type <- "phones"
          } else if (grepl("^words$", tier_name, ignore.case = TRUE)) {
            # Bare "words" tier → speaker = filename, type = words (actual words)
            speaker_name <- archivo_orig
            tier_type <- "words"
          } else if (grepl("^utterances?$", tier_name, ignore.case = TRUE)) {
            # Bare "utterances" tier → speaker = filename, type = utterances
            # These are full sentences, NOT individual words
            speaker_name <- archivo_orig
            tier_type <- "utterances"
          } else {
            next
          }
          
          tier_data <- texto_data[texto_data$tier == tier_name & texto_data$archivo_origen == archivo_orig, ]
          
          filename_val <- archivo_orig
          
          if (tier_type == "phones") {
            tier_data <- tier_data[sapply(tier_data$text, es_vocal), ]
          }
          tier_data <- tier_data[tier_data$text != "" & !is.na(tier_data$text), ]
          if (nrow(tier_data) == 0) next
          
          tier_data$duracion <- tier_data$tmax - tier_data$tmin
          tier_data$centro <- tier_data$tmin + tier_data$duracion / 2
          tier_data$hablante <- speaker_name
          tier_data$filename <- filename_val
          tier_data$etiqueta <- tier_data$text
          tier_data$inicio <- tier_data$tmin
          tier_data$fin <- tier_data$tmax
          
          if (tier_type == "phones") {
            all_phones_raw <- bind_rows(all_phones_raw, tier_data)
          } else if (tier_type == "words") {
            all_words_raw <- bind_rows(all_words_raw, tier_data)
            # Only actual words go into lookup (not full utterances)
            words_lookup[[paste0(filename_val, "|||", speaker_name)]] <- tier_data
          } else if (tier_type == "utterances") {
            # Utterances collected separately — only used as fallback
            all_utterances_raw <- bind_rows(all_utterances_raw, tier_data)
          }
        }
        
        # Fallback: for file+speaker combos with utterances but no words tier,
        # use utterances as words data and for palabra lookup
        if (nrow(all_utterances_raw) > 0) {
          utt_combos <- unique(all_utterances_raw[, c("filename", "hablante")])
          for (uc in seq_len(nrow(utt_combos))) {
            ufn <- utt_combos$filename[uc]; uspk <- utt_combos$hablante[uc]
            wkey <- paste0(ufn, "|||", uspk)
            has_words <- nrow(all_words_raw) > 0 && any(all_words_raw$filename == ufn & all_words_raw$hablante == uspk)
            if (!has_words) {
              # No words tier for this combo — use utterances as words fallback
              utt_data <- all_utterances_raw[all_utterances_raw$filename == ufn & all_utterances_raw$hablante == uspk, ]
              all_words_raw <- bind_rows(all_words_raw, utt_data)
              if (is.null(words_lookup[[wkey]])) words_lookup[[wkey]] <- utt_data
            }
          }
        }
        
        # ========================================
        # FASE 1.5: Completar phones faltantes con IPA aproximado
        #
        # Para cada combinación hablante+filename, detecta palabras de
        # all_words_raw que no tienen ningún phone (vocal) en all_phones_raw.
        # Genera phones IPA aproximados usando texto_a_ipa_es() y los añade
        # a all_phones_raw marcados como aproximados para que participen en
        # el cálculo de métricas y grupos (GF/GE).
        # Solo se conservan las vocales (consistente con el diseño actual:
        # el análisis acústico trabaja sobre vocales).
        # ========================================
        if (nrow(all_words_raw) > 0) {
          combos_w <- unique(all_words_raw[, c("hablante","filename")])
          phones_aprox_list <- vector("list", nrow(combos_w))

          for (ci in seq_len(nrow(combos_w))) {
            fn_c  <- combos_w$filename[ci]
            spk_c <- combos_w$hablante[ci]

            words_combo <- all_words_raw[
              all_words_raw$filename == fn_c & all_words_raw$hablante == spk_c, ]
            phones_combo <- if (nrow(all_phones_raw) > 0)
              all_phones_raw[all_phones_raw$filename == fn_c &
                               all_phones_raw$hablante == spk_c, ]
            else data.frame()

            # Pitch e intensidad filtrados al archivo
            pit_c <- if (nrow(pitch_data_all) > 0 &&
                           "archivo_origen" %in% colnames(pitch_data_all))
              pitch_data_all[pitch_data_all$archivo_origen == fn_c, ]
            else pitch_data_all
            int_c <- if (nrow(intensity_data_all) > 0 &&
                           "archivo_origen" %in% colnames(intensity_data_all))
              intensity_data_all[intensity_data_all$archivo_origen == fn_c, ]
            else intensity_data_all

            ph_nuevos <- list()
            ecol <- if ("etiqueta" %in% colnames(words_combo)) "etiqueta" else
              if ("text" %in% colnames(words_combo)) "text" else NA_character_
            if (is.na(ecol)) next

            for (wi in seq_len(nrow(words_combo))) {
              t1_w <- words_combo$tmin[wi]
              t2_w <- words_combo$tmax[wi]
              if (is.na(t1_w) || is.na(t2_w) || t2_w <= t1_w) next

              # ¿Ya hay alguna vocal en este rango?
              if (nrow(phones_combo) > 0) {
                overlap <- phones_combo[phones_combo$tmin < t2_w &
                                          phones_combo$tmax > t1_w, ]
                if (nrow(overlap) > 0) next
              }

              word_txt <- words_combo[[ecol]][wi]
              if (is.na(word_txt) || nchar(trimws(word_txt)) == 0) next

              # Transcripción IPA → solo vocales para el análisis
              ipa_df <- tryCatch(texto_a_ipa_es(word_txt),
                                 error = function(e) NULL)
              if (is.null(ipa_df) || nrow(ipa_df) == 0) next
              ipa_voc <- ipa_df[ipa_df$phone %in% c("a","e","i","o","u"), ]
              if (nrow(ipa_voc) == 0) next

              # Alinear con F0 si disponible
              pit_w <- if (!is.null(pit_c) && nrow(pit_c) > 0)
                pit_c[pit_c$tiempo >= t1_w & pit_c$tiempo <= t2_w, ] else NULL
              int_w <- if (!is.null(int_c) && nrow(int_c) > 0)
                int_c[int_c$tiempo >= t1_w & int_c$tiempo <= t2_w, ] else NULL

              ph_alineados <- tryCatch(
                alinear_phones_ipa(ipa_voc, t1_w, t2_w,
                                   pitch_fn = pit_w, int_fn = int_w),
                error = function(e) NULL)
              if (is.null(ph_alineados) || nrow(ph_alineados) == 0) next

              # Construir filas con el mismo esquema que all_phones_raw
              nueva_palabra_idx <- if ("palabra_idx" %in% colnames(words_combo))
                words_combo$palabra_idx[wi] else wi

              for (pi in seq_len(nrow(ph_alineados))) {
                t1_ph <- ph_alineados$inicio[pi]
                t2_ph <- ph_alineados$fin[pi]
                ph_nuevos[[length(ph_nuevos) + 1L]] <- data.frame(
                  tier            = if ("tier" %in% colnames(phones_combo) && nrow(phones_combo) > 0)
                    phones_combo$tier[1] else paste0(spk_c, " - phones"),
                  tmin            = t1_ph,
                  tmax            = t2_ph,
                  text            = ph_alineados$etiqueta[pi],
                  hablante        = spk_c,
                  filename        = fn_c,
                  etiqueta        = ph_alineados$etiqueta[pi],
                  inicio          = t1_ph,
                  fin             = t2_ph,
                  duracion        = t2_ph - t1_ph,
                  centro          = (t1_ph + t2_ph) / 2,
                  archivo_origen  = fn_c,
                  es_aprox        = TRUE,
                  stringsAsFactors = FALSE
                )
              }
            }

            if (length(ph_nuevos) > 0) {
              phones_aprox_list[[ci]] <- bind_rows(ph_nuevos)
            }
          }

          phones_aprox_all <- bind_rows(Filter(Negate(is.null), phones_aprox_list))
          if (!is.null(phones_aprox_all) && nrow(phones_aprox_all) > 0) {
            # Asegurar que las columnas de all_phones_raw existen en phones_aprox_all
            for (col_raw in colnames(all_phones_raw)) {
              if (!col_raw %in% colnames(phones_aprox_all))
                phones_aprox_all[[col_raw]] <- NA
            }
            all_phones_raw <- bind_rows(all_phones_raw, phones_aprox_all)
            all_phones_raw <- all_phones_raw[order(all_phones_raw$filename,
                                                    all_phones_raw$hablante,
                                                    all_phones_raw$tmin), ]
            n_aprox_global <- nrow(phones_aprox_all)
            showNotification(
              paste0(n_aprox_global,
                     " phone(s) aproximado(s) a\u00f1adido(s) para palabras sin cobertura.",
                     " Revise los grupos entonativos generados."),
              type = "warning", duration = 8)
          }
        }

        # ========================================
        # FASE 2: Procesar cada tier individualmente
        # Cada tier pertenece a un solo hablante.
        # La pausa entre intervalos consecutivos del mismo tier
        # es la pausa real (incluye consonantes, silencios, etc.)
        # Esto es idéntico al procesamiento del Praat script.
        # ========================================
        incProgress(0.05, detail = "Procesando tiers...")

        resultados_phones <- data.frame()
        resultados_words <- data.frame()
        
        pitch_dt <- as.data.table(pitch_data_all)
        int_dt <- as.data.table(intensity_data_all)
        
        # Contadores globales de GF por hablante+filename para IDs únicos
        gf_global_counter <- list()
        
        # --- PROCESAR PHONES ---
        phones_tiers <- unique(all_phones_raw$tier[!is.na(all_phones_raw$tier)])
        if (length(phones_tiers) == 0) {
          # Si no hay columna tier, agrupar por hablante+filename
          phones_tiers <- unique(paste0(all_phones_raw$hablante, "|||", all_phones_raw$filename))
        }
        
        for (spk in unique(all_phones_raw$hablante)) {
          for (fn in unique(all_phones_raw$filename[all_phones_raw$hablante == spk])) {
            
            spk_data <- all_phones_raw[all_phones_raw$hablante == spk & all_phones_raw$filename == fn, ]
            spk_data <- spk_data[order(spk_data$tmin), ]
            if (nrow(spk_data) == 0) next
            
            spk_data$interval_idx <- 1:nrow(spk_data)
            
            incProgress(0.05, detail = paste0(spk, " (", fn, ") - ", nrow(spk_data), " vocales"))
            
            tier_dt <- as.data.table(spk_data)
            
            # Filter pitch and intensity to same file to avoid cross-file contamination
            pitch_dt_fn <- if ("archivo_origen" %in% colnames(pitch_dt)) pitch_dt[archivo_origen == fn] else pitch_dt
            int_dt_fn <- if ("archivo_origen" %in% colnames(int_dt)) int_dt[archivo_origen == fn] else int_dt
            
            # Calcular métricas acústicas
            tier_dt <- calcular_metricas_dt(
              tier_dt, pitch_dt_fn, int_dt_fn,
              filtrar_f0_outliers = isTRUE(input$filtrar_f0_frames_outliers),
              outlier_mad_k       = if (!is.null(input$outlier_f0_mad_k)) input$outlier_f0_mad_k else 3.0
            )

            # Filtrado de outliers si está activado
            if (input$filtrar_outliers) {
              sd_factor <- input$outlier_sd_factor
              trim_pct <- input$outlier_trim_pct / 100
              metodo <- input$outlier_metodo
              
              for (col_name in c("f0_media_hz", "f0_max_hz", "f0_min_hz",
                                  "f0_media_st", "f0_max_st", "f0_min_st",
                                  "int_media", "int_max", "int_min")) {
                vals <- tier_dt[[col_name]]
                if (all(is.na(vals))) next
                mu <- mean(vals, na.rm = TRUE)
                sd_val <- sd(vals, na.rm = TRUE)
                if (is.na(sd_val) || sd_val == 0) next
                
                outlier_mask <- !is.na(vals) & (abs(vals - mu) > sd_factor * sd_val)
                if (!any(outlier_mask)) next
                
                if (metodo == "winsorize") {
                  p_low <- quantile(vals, trim_pct, na.rm = TRUE)
                  p_high <- quantile(vals, 1 - trim_pct, na.rm = TRUE)
                  vals[!is.na(vals) & vals < p_low] <- p_low
                  vals[!is.na(vals) & vals > p_high] <- p_high
                  tier_dt[[col_name]] <- vals
                } else if (metodo == "exclude") {
                  vals[outlier_mask] <- NA
                  tier_dt[[col_name]] <- vals
                } else if (metodo == "trimmed") {
                  # Recompute trimmed values
                  vals_clean <- vals[!is.na(vals)]
                  vals_trimmed <- vals_clean[vals_clean >= quantile(vals_clean, trim_pct) & 
                                              vals_clean <= quantile(vals_clean, 1 - trim_pct)]
                  trimmed_mean <- mean(vals_trimmed)
                  # Replace outliers with trimmed mean
                  vals[outlier_mask] <- trimmed_mean
                  tier_dt[[col_name]] <- vals
                }
              }
              # Recalculate derived columns
              tier_dt[, rango_f0_st := f0_max_st - f0_min_st]
              tier_dt[, f0_rango_hz := f0_max_hz - f0_min_hz]
              tier_dt[, int_rango := int_max - int_min]
            }
            
            tier_dt <- calcular_incrementos_dt(tier_dt)
            
            # Asignar palabras
            wkey <- paste0(fn, "|||", spk)
            words_data_tier <- words_lookup[[wkey]]
            
            tier_dt[, palabra := ""]
            tier_dt[, palabra_idx := NA_integer_]
            tier_dt[, es_primera_vocal_palabra := FALSE]
            tier_dt[, es_ultima_vocal_palabra := FALSE]
            
            if (!is.null(words_data_tier) && nrow(words_data_tier) > 0) {
              for (idx in 1:nrow(tier_dt)) {
                centro_val <- tier_dt$centro[idx]
                palabra_match <- which(words_data_tier$tmin <= centro_val & words_data_tier$tmax >= centro_val)
                if (length(palabra_match) > 0) {
                  p_idx <- palabra_match[1]
                  set(tier_dt, idx, "palabra", words_data_tier$text[p_idx])
                  set(tier_dt, idx, "palabra_idx", as.integer(p_idx))
                }
              }
              for (p_idx in unique(tier_dt$palabra_idx[!is.na(tier_dt$palabra_idx)])) {
                vocales_pal <- which(tier_dt$palabra_idx == p_idx)
                if (length(vocales_pal) > 0) {
                  set(tier_dt, vocales_pal, "es_primera_vocal_palabra", FALSE)
                  set(tier_dt, vocales_pal, "es_ultima_vocal_palabra", FALSE)
                  set(tier_dt, min(vocales_pal), "es_primera_vocal_palabra", TRUE)
                  set(tier_dt, max(vocales_pal), "es_ultima_vocal_palabra", TRUE)
                }
              }
            }
            
            # ========================================
            # Grupos fónicos y entonativos
            # Si utterances_son_gf: cada palabra (utterance) = 1 GF
            # Si no: pausa >= umbral → nuevo GF
            # Dentro de cada GF, se computan GEs
            # ========================================
            tier_dt[, grupo_fonico := 0L]
            tier_dt[, grupo_entonativo := 0L]
            tier_dt[, pausa_anterior := 0]
            tier_dt[, tiempo_transicion_anterior := NA_real_]
            tier_dt[, tiempo_transicion_posterior := NA_real_]
            tier_dt[, es_inicio_ge := FALSE]
            tier_dt[, f0_cambio_pct := NA_real_]
            tier_dt[, f0_referencia := NA_real_]
            tier_dt[, palabra_referencia := ""]
            
            n_rows <- nrow(tier_dt)
            
            if (input$utterances_son_gf) {
              # Cada palabra (utterance del tier words) es un GF
              # Asignar GF según palabra_idx
              palabras_orden <- unique(tier_dt$palabra_idx[!is.na(tier_dt$palabra_idx)])
              gf_map <- setNames(seq_along(palabras_orden), as.character(palabras_orden))
              
              for (idx in 1:n_rows) {
                pi <- as.character(tier_dt$palabra_idx[idx])
                if (!is.na(pi) && pi %in% names(gf_map)) {
                  set(tier_dt, idx, "grupo_fonico", as.integer(gf_map[pi]))
                } else {
                  # Vocal sin palabra asignada: usar GF de la vocal anterior
                  if (idx > 1) set(tier_dt, idx, "grupo_fonico", tier_dt$grupo_fonico[idx - 1])
                  else set(tier_dt, idx, "grupo_fonico", 1L)
                }
                
                if (idx > 1) {
                  set(tier_dt, idx, "pausa_anterior", tier_dt$tmin[idx] - tier_dt$tmax[idx - 1])
                  set(tier_dt, idx, "tiempo_transicion_anterior", tier_dt$centro[idx] - tier_dt$centro[idx - 1])
                }
              }
              
              # Ahora computar GEs dentro de cada GF
              for (gf_val in unique(tier_dt$grupo_fonico)) {
                idx_gf <- which(tier_dt$grupo_fonico == gf_val)
                if (length(idx_gf) == 0) next
                ge <- 1L
                set(tier_dt, idx_gf[1], "grupo_entonativo", ge)
                set(tier_dt, idx_gf[1], "es_inicio_ge", TRUE)
                
                if (length(idx_gf) > 1) {
                  for (pos in 2:length(idx_gf)) {
                    idx <- idx_gf[pos]
                    nuevo_ge <- FALSE
                    
                    # Criterios GE en modo utterances_son_gf
                    pausa_act <- tier_dt$tmin[idx] - tier_dt$tmax[idx - 1]
                    pausa_ge_min <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[1] else 0.1
                    pausa_ge_max <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[2] else 0.29
                    pausa_en_rango <- pausa_ge_max > 0 && !is.na(pausa_act) &&
                                      pausa_act >= pausa_ge_min && pausa_act <= pausa_ge_max
                    ge_operador <- if (!is.null(input$ge_criterios_operador)) input$ge_criterios_operador else "AND"

                    crit_reajuste_u <- FALSE
                    if (tier_dt$es_primera_vocal_palabra[idx]) {
                      pal_idx_act <- tier_dt$palabra_idx[idx]
                      if (!is.na(pal_idx_act)) {
                        idx_comp <- NA_integer_
                        for (k in (pos-1):1) {
                          ki <- idx_gf[k]
                          if (!is.na(tier_dt$palabra_idx[ki]) && tier_dt$palabra_idx[ki] != pal_idx_act && tier_dt$es_ultima_vocal_palabra[ki]) {
                            idx_comp <- ki; break
                          }
                        }
                        if (!is.na(idx_comp)) {
                          set(tier_dt, idx, "f0_referencia", tier_dt$f0_media_hz[idx_comp])
                          set(tier_dt, idx, "palabra_referencia", tier_dt$palabra[idx_comp])
                          if (!is.na(tier_dt$f0_media_hz[idx]) && !is.na(tier_dt$f0_media_hz[idx_comp]) && tier_dt$f0_media_hz[idx_comp] > 0) {
                            inc_p <- ((tier_dt$f0_media_hz[idx] - tier_dt$f0_media_hz[idx_comp]) / tier_dt$f0_media_hz[idx_comp]) * 100
                            set(tier_dt, idx, "f0_cambio_pct", inc_p)
                            crit_reajuste_u <- abs(inc_p) > input$umbral_pitch_ge
                          }
                        }
                      }
                    }
                    umbral_int_u <- if (!is.null(input$umbral_int_ge)) input$umbral_int_ge else 5
                    crit_int_u <- FALSE
                    if ("int_media" %in% colnames(tier_dt) && idx > 1) {
                      dif_int_u <- tier_dt$int_media[idx - 1] - tier_dt$int_media[idx]
                      crit_int_u <- !is.na(dif_int_u) && dif_int_u >= umbral_int_u
                    }
                    if (ge_operador == "OR") {
                      nuevo_ge <- pausa_en_rango || crit_reajuste_u || crit_int_u
                    } else {
                      nuevo_ge <- pausa_en_rango && crit_reajuste_u && crit_int_u
                    }
                    
                    if (nuevo_ge) {
                      ge <- ge + 1L
                      set(tier_dt, idx, "es_inicio_ge", TRUE)
                    }
                    set(tier_dt, idx, "grupo_entonativo", ge)
                  }
                }
              }
              
            } else {
              # Modo normal: GF por pausa
              gf <- 1L; ge <- 1L
            
            for (idx in 1:n_rows) {
              if (idx == 1) {
                set(tier_dt, idx, "grupo_fonico", gf)
                set(tier_dt, idx, "grupo_entonativo", ge)
                set(tier_dt, idx, "es_inicio_ge", TRUE)
              } else {
                pausa <- tier_dt$tmin[idx] - tier_dt$tmax[idx - 1]
                set(tier_dt, idx, "pausa_anterior", pausa)
                set(tier_dt, idx, "tiempo_transicion_anterior", tier_dt$centro[idx] - tier_dt$centro[idx - 1])
                
                if (pausa >= input$umbral_pausa_gf) {
                  gf <- gf + 1L; ge <- 1L
                  set(tier_dt, idx, "es_inicio_ge", TRUE)
                } else {
                  nuevo_ge <- FALSE
                  ge_operador <- if (!is.null(input$ge_criterios_operador)) input$ge_criterios_operador else "AND"

                  # Criterio 1: pausa interna en rango
                  pausa_ge_min <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[1] else 0.1
                  pausa_ge_max <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[2] else 0.29
                  pausa_en_rango <- pausa_ge_max > 0 && !is.na(pausa) &&
                                    pausa >= pausa_ge_min && pausa <= pausa_ge_max

                  # Criterio 2: reajuste tonal
                  crit_reajuste <- FALSE
                  if (tier_dt$es_primera_vocal_palabra[idx]) {
                    pal_idx_act <- tier_dt$palabra_idx[idx]
                    if (!is.na(pal_idx_act)) {
                      idx_comp <- NA_integer_
                      for (k in (idx-1):1) {
                        if (!is.na(tier_dt$palabra_idx[k]) && tier_dt$palabra_idx[k] != pal_idx_act && tier_dt$es_ultima_vocal_palabra[k]) {
                          idx_comp <- k; break
                        }
                      }
                      if (!is.na(idx_comp)) {
                        set(tier_dt, idx, "f0_referencia", tier_dt$f0_media_hz[idx_comp])
                        set(tier_dt, idx, "palabra_referencia", tier_dt$palabra[idx_comp])
                        if (!is.na(tier_dt$f0_media_hz[idx]) && !is.na(tier_dt$f0_media_hz[idx_comp]) && tier_dt$f0_media_hz[idx_comp] > 0) {
                          inc_p <- ((tier_dt$f0_media_hz[idx] - tier_dt$f0_media_hz[idx_comp]) / tier_dt$f0_media_hz[idx_comp]) * 100
                          set(tier_dt, idx, "f0_cambio_pct", inc_p)
                          crit_reajuste <- abs(inc_p) > input$umbral_pitch_ge
                        }
                      }
                    }
                  }

                  # Criterio 3: intensidad
                  umbral_int <- if (!is.null(input$umbral_int_ge)) input$umbral_int_ge else 5
                  crit_intensidad <- FALSE
                  if ("int_media" %in% colnames(tier_dt) && idx > 1) {
                    dif_int <- tier_dt$int_media[idx - 1] - tier_dt$int_media[idx]
                    crit_intensidad <- !is.na(dif_int) && dif_int >= umbral_int
                  }

                  # Combinar criterios según operador
                  if (ge_operador == "OR") {
                    nuevo_ge <- pausa_en_rango || crit_reajuste || crit_intensidad
                  } else {
                    # AND por defecto
                    nuevo_ge <- pausa_en_rango && crit_reajuste && crit_intensidad
                  }

                  if (nuevo_ge) {
                    ge <- ge + 1L
                    set(tier_dt, idx, "es_inicio_ge", TRUE)
                  }
                }
                
                set(tier_dt, idx, "grupo_fonico", gf)
                set(tier_dt, idx, "grupo_entonativo", ge)
              }
              
              # Transición posterior
              if (idx < n_rows) {
                set(tier_dt, idx, "tiempo_transicion_posterior", tier_dt$centro[idx + 1] - tier_dt$centro[idx])
              }
            }
            } # fin else (modo normal GF por pausa)
            
            # Transiciones para modo utterances_son_gf (ya computadas inline arriba)
            # Asegurar transiciones posteriores en todos los modos
            if (input$utterances_son_gf) {
              for (idx in 1:(n_rows - 1)) {
                set(tier_dt, idx, "tiempo_transicion_posterior", tier_dt$centro[idx + 1] - tier_dt$centro[idx])
              }
            }

            # Resetear tiempo_transicion_anterior a NA para la primera vocal de cada GE.
            # La transición desde el grupo anterior no es relevante para el análisis
            # prosódico interno del grupo: la 1ª vocal no tiene vocal previa dentro del GE.
            # La relativización base-100 usará la 2ª vocal (primera transición real) como base.
            tier_dt[es_inicio_ge == TRUE, tiempo_transicion_anterior := NA_real_]

            # ========================================
            # Propiedades: tónica, pico tonal, secciones
            # ========================================
            
            # Estructura interna de la vocal (basada en cuartiles F0)
            tier_dt[, estructura_vocal := "plana"]
            tier_dt[, circunflejo_vocal := "no"]
            tier_dt[, vocal_punto_central := FALSE]
            
            umbral_dif_cuartil <- 0.5  # St mínimo para considerar diferencia entre cuartiles
            
            for (idx in 1:nrow(tier_dt)) {
              q1 <- tier_dt$q1_f0_media_st[idx]
              q2 <- tier_dt$q2_f0_media_st[idx]
              q3 <- tier_dt$q3_f0_media_st[idx]
              q4 <- tier_dt$q4_f0_media_st[idx]
              
              if (is.na(q1) || is.na(q2) || is.na(q3) || is.na(q4)) {
                set(tier_dt, idx, "vocal_punto_central", TRUE)
                next
              }
              
              # Determinar H/L para cada cuartil relativo a la media de la vocal
              f0_media_vocal <- tier_dt$f0_media_st[idx]
              if (is.na(f0_media_vocal)) {
                set(tier_dt, idx, "vocal_punto_central", TRUE)
                next
              }
              
              # Verificar si hay diferencias significativas entre cuartiles consecutivos
              dif12 <- abs(q2 - q1)
              dif23 <- abs(q3 - q2)
              dif34 <- abs(q4 - q3)
              
              hay_movimiento <- (dif12 > umbral_dif_cuartil) || (dif23 > umbral_dif_cuartil) || (dif34 > umbral_dif_cuartil)
              
              if (!hay_movimiento) {
                # Vocal plana: solo tomar punto central
                set(tier_dt, idx, "estructura_vocal", "plana")
                set(tier_dt, idx, "vocal_punto_central", TRUE)
              } else {
                # Determinar patrón H/L por cuartil
                patron <- paste0(
                  ifelse(q1 >= f0_media_vocal, "H", "L"),
                  ifelse(q2 >= f0_media_vocal, "H", "L"),
                  ifelse(q3 >= f0_media_vocal, "H", "L"),
                  ifelse(q4 >= f0_media_vocal, "H", "L")
                )
                set(tier_dt, idx, "estructura_vocal", patron)
                set(tier_dt, idx, "vocal_punto_central", FALSE)
                
                # Circunflejo: hay al menos un cambio de dirección
                # (subida seguida de bajada o viceversa)
                dir12 <- sign(q2 - q1)
                dir23 <- sign(q3 - q2)
                dir34 <- sign(q4 - q3)
                dirs <- c(dir12, dir23, dir34)
                dirs <- dirs[dirs != 0]  # quitar tramos planos
                
                if (length(dirs) >= 2) {
                  cambios_dir <- sum(diff(dirs) != 0)
                  if (cambios_dir >= 1) {
                    set(tier_dt, idx, "circunflejo_vocal", "sí")
                  }
                }
              }
            }
            
            tier_dt[, tonica_gramatical := "no"]
            tier_dt[, estructura_palabra := ""]
            tier_dt[, es_pico_grupo := FALSE]
            tier_dt[, es_pico_palabra := FALSE]
            tier_dt[, primer_pico := FALSE]
            tier_dt[, pico_ascendente_20 := FALSE]
            tier_dt[, pico_descendente_20 := FALSE]
            tier_dt[, posicion_en_grupo := NA_integer_]
            tier_dt[, total_vocales_grupo := NA_integer_]
            tier_dt[, distancia_a_final := NA_integer_]
            tier_dt[, seccion_ip := "cuerpo"]
            tier_dt[, vocales_hasta_fin_ge := NA_integer_]
            tier_dt[, vocales_hasta_fin_gf := NA_integer_]
            
            # Tónica gramatical
            for (p_idx in unique(tier_dt$palabra_idx[!is.na(tier_dt$palabra_idx)])) {
              vocales_pal <- which(tier_dt$palabra_idx == p_idx)
              if (length(vocales_pal) == 0) next
              palabra_val <- tier_dt$palabra[vocales_pal[1]]
              acentuacion <- determinar_acentuacion(palabra_val, input$idioma)
              set(tier_dt, vocales_pal, "estructura_palabra", acentuacion$tipo)
              if (acentuacion$posicion_tonica > 0 && length(vocales_pal) >= acentuacion$posicion_tonica) {
                idx_tonica <- vocales_pal[length(vocales_pal) - acentuacion$posicion_tonica + 1]
                set(tier_dt, idx_tonica, "tonica_gramatical", "sí")
              }
            }
            
            # Pico tonal, posiciones, secciones por GF/GE
            for (gf_val in unique(tier_dt$grupo_fonico)) {
              for (ge_val in unique(tier_dt$grupo_entonativo[tier_dt$grupo_fonico == gf_val])) {
                idx_ge <- which(tier_dt$grupo_fonico == gf_val & tier_dt$grupo_entonativo == ge_val)
                if (length(idx_ge) == 0) next
                n_ge <- length(idx_ge)
                
                for (pos in seq_along(idx_ge)) {
                  set(tier_dt, idx_ge[pos], "posicion_en_grupo", as.integer(pos))
                  set(tier_dt, idx_ge[pos], "total_vocales_grupo", as.integer(n_ge))
                  set(tier_dt, idx_ge[pos], "distancia_a_final", as.integer(n_ge - pos))
                  set(tier_dt, idx_ge[pos], "vocales_hasta_fin_ge", as.integer(n_ge - pos))
                }
                
                # Pico tonal del grupo
                f0_ge <- tier_dt$f0_media_hz[idx_ge]
                if (any(!is.na(f0_ge))) {
                  max_f0_ge <- max(f0_ge, na.rm = TRUE)
                  pico_idx_ge <- idx_ge[which(f0_ge == max_f0_ge)[1]]
                  set(tier_dt, pico_idx_ge, "es_pico_grupo", TRUE)
                }
                
                # Pico tonal por palabra
                palabras_en_ge <- unique(tier_dt$palabra_idx[idx_ge])
                palabras_en_ge <- palabras_en_ge[!is.na(palabras_en_ge)]
                for (pal_id in palabras_en_ge) {
                  idx_pal <- intersect(idx_ge, which(tier_dt$palabra_idx == pal_id))
                  if (length(idx_pal) == 0) next
                  f0_pal <- tier_dt$f0_media_hz[idx_pal]
                  if (any(!is.na(f0_pal))) {
                    max_f0_pal <- max(f0_pal, na.rm = TRUE)
                    pico_idx_pal <- idx_pal[which(f0_pal == max_f0_pal)[1]]
                    set(tier_dt, pico_idx_pal, "es_pico_palabra", TRUE)
                  }
                }
                
                # Primer pico
                tonicas_ge <- idx_ge[tier_dt$tonica_gramatical[idx_ge] == "sí"]
                if (length(tonicas_ge) > 0) set(tier_dt, tonicas_ge[1], "primer_pico", TRUE)
                
                # Pico ascendente/descendente 20%
                for (pos in seq_along(idx_ge)) {
                  ii <- idx_ge[pos]
                  if (tier_dt$es_pico_grupo[ii] || tier_dt$es_pico_palabra[ii]) {
                    if (pos > 1 && !is.na(tier_dt$f0_media_hz[ii]) && !is.na(tier_dt$f0_media_hz[idx_ge[pos-1]]) && tier_dt$f0_media_hz[idx_ge[pos-1]] > 0) {
                      inc_pre <- ((tier_dt$f0_media_hz[ii] - tier_dt$f0_media_hz[idx_ge[pos-1]]) / tier_dt$f0_media_hz[idx_ge[pos-1]]) * 100
                      if (inc_pre >= 20) set(tier_dt, ii, "pico_ascendente_20", TRUE)
                    }
                    if (pos < n_ge && !is.na(tier_dt$f0_media_hz[ii]) && !is.na(tier_dt$f0_media_hz[idx_ge[pos+1]]) && tier_dt$f0_media_hz[ii] > 0) {
                      inc_post <- ((tier_dt$f0_media_hz[idx_ge[pos+1]] - tier_dt$f0_media_hz[ii]) / tier_dt$f0_media_hz[ii]) * 100
                      if (inc_post <= -20) set(tier_dt, ii, "pico_descendente_20", TRUE)
                    }
                  }
                }
                
                # Secciones prosódicas
                tonicas_idx_ge <- which(tier_dt$tonica_gramatical[idx_ge] == "sí")
                if (length(tonicas_idx_ge) > 0) {
                  primera_tonica_pos <- min(tonicas_idx_ge)
                  ultima_tonica_pos <- max(tonicas_idx_ge)
                  for (pos in seq_along(idx_ge)) {
                    if (pos < primera_tonica_pos) set(tier_dt, idx_ge[pos], "seccion_ip", "anacrusis")
                    else if (pos >= ultima_tonica_pos) set(tier_dt, idx_ge[pos], "seccion_ip", "tonema")
                    else set(tier_dt, idx_ge[pos], "seccion_ip", "cuerpo")
                  }
                }
              }
              
              # vocales_hasta_fin_gf
              idx_gf <- which(tier_dt$grupo_fonico == gf_val)
              n_gf <- length(idx_gf)
              for (pos in seq_along(idx_gf)) {
                set(tier_dt, idx_gf[pos], "vocales_hasta_fin_gf", as.integer(n_gf - pos))
              }
            }
            
            # Construir resultado
            result_df <- as.data.frame(tier_dt)
            result_df$tier_tipo <- "phones"
            
            resultados_phones <- bind_rows(resultados_phones, result_df)
          } # fin for fn (filename)
        } # fin for spk (hablante) phones
        
        # --- PROCESAR WORDS ---
        if (nrow(all_words_raw) > 0) {
          incProgress(0.05, detail = "Procesando words...")
          
          for (spk in unique(all_words_raw$hablante)) {
            for (fn in unique(all_words_raw$filename[all_words_raw$hablante == spk])) {
              
              spk_data <- all_words_raw[all_words_raw$hablante == spk & all_words_raw$filename == fn, ]
              spk_data <- spk_data[order(spk_data$tmin), ]
              if (nrow(spk_data) == 0) next
              
              spk_data$interval_idx <- 1:nrow(spk_data)
              
              tier_dt <- as.data.table(spk_data)
              
              # Filter pitch and intensity to same file
              pitch_dt_fn <- if ("archivo_origen" %in% colnames(pitch_dt)) pitch_dt[archivo_origen == fn] else pitch_dt
              int_dt_fn <- if ("archivo_origen" %in% colnames(int_dt)) int_dt[archivo_origen == fn] else int_dt
              
              tier_dt <- calcular_metricas_dt(
                tier_dt, pitch_dt_fn, int_dt_fn,
                filtrar_f0_outliers = isTRUE(input$filtrar_f0_frames_outliers),
                outlier_mad_k       = if (!is.null(input$outlier_f0_mad_k)) input$outlier_f0_mad_k else 3.0
              )
              tier_dt <- calcular_incrementos_dt(tier_dt)
              
              # Grupos fónicos/entonativos para words
              tier_dt[, grupo_fonico := 0L]
              tier_dt[, grupo_entonativo := 0L]
              
              gf <- 1L; ge <- 1L
              for (idx in 1:nrow(tier_dt)) {
                if (idx == 1) {
                  set(tier_dt, idx, "grupo_fonico", gf)
                  set(tier_dt, idx, "grupo_entonativo", ge)
                } else {
                  pausa <- tier_dt$tmin[idx] - tier_dt$tmax[idx - 1]
                  if (!is.na(pausa) && pausa >= input$umbral_pausa_gf) {
                    gf <- gf + 1L; ge <- 1L
                  } else {
                    nuevo_ge_w <- FALSE
                    pausa_ge_min_w <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[1] else 0
                    pausa_ge_max_w <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[2] else 0
                    pausa_en_rango_w <- pausa_ge_max_w > 0 && !is.na(pausa) &&
                                        pausa >= pausa_ge_min_w && pausa <= pausa_ge_max_w
                    if (!is.na(tier_dt$f0_media_hz[idx]) && !is.na(tier_dt$f0_media_hz[idx-1]) && tier_dt$f0_media_hz[idx-1] > 0) {
                      inc_p <- ((tier_dt$f0_media_hz[idx] - tier_dt$f0_media_hz[idx-1]) / tier_dt$f0_media_hz[idx-1]) * 100
                      if (inc_p > input$umbral_pitch_ge && (pausa_en_rango_w || pausa_ge_max_w == 0)) nuevo_ge_w <- TRUE
                    }
                    if (nuevo_ge_w) ge <- ge + 1L
                  }
                  set(tier_dt, idx, "grupo_fonico", gf)
                  set(tier_dt, idx, "grupo_entonativo", ge)
                }
              }
              
              result_df <- as.data.frame(tier_dt)
              result_df$tier_tipo <- "words"
              resultados_words <- bind_rows(resultados_words, result_df)
            }
          }
        }
        
        incProgress(0.1, detail = "Procesando resultados...")
        
        # ========================================
        # Propagar info de phones a words (FIX columnas vacías en words)
        # ========================================
        if (nrow(resultados_words) > 0 && nrow(resultados_phones) > 0) {
          # Para cada palabra en words, buscar sus vocales en phones y propagar info
          resultados_words$es_pico_grupo <- FALSE
          resultados_words$primer_pico <- FALSE
          resultados_words$tonica_gramatical <- ""
          resultados_words$pico_ascendente_20 <- FALSE
          resultados_words$pico_descendente_20 <- FALSE
          resultados_words$seccion_ip <- ""
          resultados_words$vocales_hasta_fin_ge <- NA_integer_
          resultados_words$vocales_hasta_fin_gf <- NA_integer_
          resultados_words$palabra <- resultados_words$etiqueta
          resultados_words$f0_referencia <- NA_real_
          resultados_words$palabra_referencia <- ""
          resultados_words$f0_cambio_pct <- NA_real_
          resultados_words$es_atona <- ""
          resultados_words$estructura_palabra <- ""
          resultados_words$estructuras_vocales <- ""
          resultados_words$tiene_circunflejo_vocal <- "no"
          
          for (w_idx in 1:nrow(resultados_words)) {
            w <- resultados_words[w_idx, ]
            # Buscar vocales de esta palabra
            phones_match <- resultados_phones[
              resultados_phones$hablante == w$hablante &
              resultados_phones$filename == w$filename &
              resultados_phones$inicio >= w$inicio & resultados_phones$fin <= w$fin, ]
            
            if (nrow(phones_match) > 0) {
              resultados_words$es_pico_grupo[w_idx] <- any(phones_match$es_pico_grupo, na.rm = TRUE)
              resultados_words$primer_pico[w_idx] <- any(phones_match$primer_pico, na.rm = TRUE)
              if (any(phones_match$tonica_gramatical == "sí", na.rm = TRUE)) {
                resultados_words$tonica_gramatical[w_idx] <- "sí"
              }
              resultados_words$pico_ascendente_20[w_idx] <- any(phones_match$pico_ascendente_20, na.rm = TRUE)
              resultados_words$pico_descendente_20[w_idx] <- any(phones_match$pico_descendente_20, na.rm = TRUE)
              # Sección: usar la de la última vocal de la palabra
              last_phone <- phones_match[nrow(phones_match), ]
              resultados_words$seccion_ip[w_idx] <- last_phone$seccion_ip
              resultados_words$vocales_hasta_fin_ge[w_idx] <- last_phone$vocales_hasta_fin_ge
              resultados_words$vocales_hasta_fin_gf[w_idx] <- last_phone$vocales_hasta_fin_gf
              resultados_words$grupo_fonico[w_idx] <- last_phone$grupo_fonico
              resultados_words$grupo_entonativo[w_idx] <- last_phone$grupo_entonativo
              
              # Estructura vocal: resumen de las vocales de esta palabra
              if ("estructura_vocal" %in% colnames(phones_match)) {
                estr_vocs <- phones_match$estructura_vocal[!is.na(phones_match$estructura_vocal)]
                resultados_words$estructuras_vocales[w_idx] <- paste(estr_vocs, collapse = "|")
                if ("circunflejo_vocal" %in% colnames(phones_match)) {
                  if (any(phones_match$circunflejo_vocal == "sí", na.rm = TRUE)) {
                    resultados_words$tiene_circunflejo_vocal[w_idx] <- "sí"
                  }
                }
              }
            }
            
            # Estructura y atonía
            pal_texto <- resultados_words$etiqueta[w_idx]
            acent <- determinar_acentuacion(pal_texto, input$idioma)
            resultados_words$estructura_palabra[w_idx] <- acent$tipo
            resultados_words$es_atona[w_idx] <- ifelse(es_palabra_atona(pal_texto, input$idioma), "sí", "no")
            
            # f0_referencia: incremento respecto a palabra anterior
            if (w_idx > 1 && resultados_words$hablante[w_idx] == resultados_words$hablante[w_idx-1] &&
                resultados_words$filename[w_idx] == resultados_words$filename[w_idx-1]) {
              f0_prev <- resultados_words$f0_media_hz[w_idx - 1]
              f0_curr <- resultados_words$f0_media_hz[w_idx]
              if (!is.na(f0_prev) && !is.na(f0_curr) && f0_prev > 0) {
                resultados_words$f0_referencia[w_idx] <- f0_prev
                resultados_words$palabra_referencia[w_idx] <- resultados_words$etiqueta[w_idx - 1]
                resultados_words$f0_cambio_pct[w_idx] <- ((f0_curr - f0_prev) / f0_prev) * 100
              }
            }
          }
        }
        
        # ========================================
        # Generar IDs con filename
        # ========================================
        if (nrow(resultados_phones) > 0) {
          resultados_phones$id_grupo <- paste0(resultados_phones$filename, "_", resultados_phones$hablante,
                                                "_GF", resultados_phones$grupo_fonico, 
                                                "_GE", resultados_phones$grupo_entonativo)
          resultados_phones$id_completo <- paste0(resultados_phones$id_grupo, "_V", resultados_phones$posicion_en_grupo)
        }
        
        if (nrow(resultados_words) > 0) {
          resultados_words$id_grupo <- paste0(resultados_words$filename, "_", resultados_words$hablante,
                                               "_GF", resultados_words$grupo_fonico,
                                               "_GE", resultados_words$grupo_entonativo)
        }
        
        # ========================================
        # Crear resumen de IPs (grupos entonativos)
        # ========================================
        ips_resumen <- data.frame()
        
        if (nrow(resultados_phones) > 0) {
          incProgress(0.1, detail = "Resumen de grupos entonativos...")
          
          for (fn in unique(resultados_phones$filename)) {
            for (spk in unique(resultados_phones$hablante[resultados_phones$filename == fn])) {
              phones_spk <- resultados_phones[resultados_phones$filename == fn & resultados_phones$hablante == spk, ]
              
              for (gf_val in unique(phones_spk$grupo_fonico)) {
                for (ge_val in unique(phones_spk$grupo_entonativo[phones_spk$grupo_fonico == gf_val])) {
                  vocales_ge <- phones_spk[phones_spk$grupo_fonico == gf_val & phones_spk$grupo_entonativo == ge_val, ]
                  if (nrow(vocales_ge) == 0) next
                  
                  f0_vals <- vocales_ge$f0_media_st[!is.na(vocales_ge$f0_media_st)]
                  
                  # Palabras del grupo — preservar orden y repeticiones
                  # Usar palabra_idx para obtener una palabra por índice, en orden
                  if ("palabra_idx" %in% colnames(vocales_ge)) {
                    pal_idx <- vocales_ge$palabra_idx[!is.na(vocales_ge$palabra_idx)]
                    pal_text <- vocales_ge$palabra[!is.na(vocales_ge$palabra_idx)]
                    if (length(pal_idx) > 0) {
                      # Keep first occurrence of each palabra_idx, preserving order
                      pal_df <- data.frame(idx = pal_idx, txt = pal_text, stringsAsFactors = FALSE)
                      pal_df <- pal_df[!duplicated(pal_df$idx), ]
                      pal_df <- pal_df[order(pal_df$idx), ]
                      palabras_ordered <- pal_df$txt[pal_df$txt != ""]
                    } else {
                      palabras_ordered <- character(0)
                    }
                  } else {
                    # Fallback: use word text but preserve order (no unique)
                    pals_raw <- vocales_ge$palabra[!is.na(vocales_ge$palabra) & vocales_ge$palabra != ""]
                    # Deduplicate consecutive identical words only (not globally)
                    palabras_ordered <- if (length(pals_raw) > 0) pals_raw[c(TRUE, pals_raw[-1] != pals_raw[-length(pals_raw)])] else character(0)
                  }
                  n_palabras <- length(palabras_ordered)
                  
                  ip_row <- data.frame(
                    filename = fn,
                    hablante = spk,
                    grupo_fonico = gf_val,
                    grupo_entonativo = ge_val,
                    id_ge = paste0(fn, "_", spk, "_GF", gf_val, "_GE", ge_val),
                    inicio = min(vocales_ge$inicio, na.rm = TRUE),
                    fin = max(vocales_ge$fin, na.rm = TRUE),
                    duracion = max(vocales_ge$fin, na.rm = TRUE) - min(vocales_ge$inicio, na.rm = TRUE),
                    num_vocales = nrow(vocales_ge),
                    num_palabras = n_palabras,
                    velocidad_habla = if ((max(vocales_ge$fin, na.rm = TRUE) - min(vocales_ge$inicio, na.rm = TRUE)) > 0)
                      nrow(vocales_ge) / (max(vocales_ge$fin, na.rm = TRUE) - min(vocales_ge$inicio, na.rm = TRUE)) else NA_real_,
                    f0_inicio_st = if (length(f0_vals) > 0) f0_vals[1] else NA,
                    f0_pico_st = if (length(f0_vals) > 0) max(f0_vals) else NA,
                    f0_fin_st = if (length(f0_vals) > 0) f0_vals[length(f0_vals)] else NA,
                    f0_media_grupo_st = if (length(f0_vals) > 0) mean(f0_vals) else NA,
                    rango_f0_grupo_st = if (length(f0_vals) > 1) max(f0_vals) - min(f0_vals) else 0,
                    intensidad_media_grupo = if ("int_media" %in% colnames(vocales_ge)) mean(vocales_ge$int_media, na.rm = TRUE) else NA_real_,
                    transicion_media = if ("tiempo_transicion_anterior" %in% colnames(vocales_ge)) 
                      mean(vocales_ge$tiempo_transicion_anterior, na.rm = TRUE) else NA_real_,
                    posicion_pico_rel = NA,
                    palabras_grupo = paste(palabras_ordered, collapse = " "),
                    stringsAsFactors = FALSE
                  )
                  
                  # Posición relativa del pico
                  if (any(vocales_ge$es_pico_grupo, na.rm = TRUE)) {
                    pico_pos <- which(vocales_ge$es_pico_grupo)[1]
                    ip_row$posicion_pico_rel <- pico_pos / nrow(vocales_ge)
                  }
                  
                  # Estructura vocal: resumen para el GE
                  if ("estructura_vocal" %in% colnames(vocales_ge)) {
                    estr_vals <- vocales_ge$estructura_vocal[!is.na(vocales_ge$estructura_vocal)]
                    ip_row$n_vocales_planas <- sum(estr_vals == "plana")
                    ip_row$n_vocales_con_movimiento <- sum(estr_vals != "plana")
                    ip_row$n_vocales_circunflejo <- if ("circunflejo_vocal" %in% colnames(vocales_ge))
                      sum(vocales_ge$circunflejo_vocal == "sí", na.rm = TRUE) else 0L
                    ip_row$estructuras_vocales_ge <- paste(estr_vals, collapse = "|")
                  }
                  
                  ips_resumen <- bind_rows(ips_resumen, ip_row)
                }
              }
            }
          }
        }

        # ── Pausa anterior y posterior para cada GE ──────────────────────────
        # Ordenado solo por tiempo dentro del archivo: la pausa es con el GE
        # temporalmente adyacente, sea del mismo hablante o de otro (conversación).
        # Positivo = silencio; negativo = solapamiento.
        if (nrow(ips_resumen) > 0) {
          ips_resumen <- ips_resumen %>%
            dplyr::arrange(filename, inicio) %>%
            dplyr::group_by(filename) %>%
            dplyr::mutate(
              pausa_anterior  = ifelse(dplyr::row_number() == 1L, NA_real_,
                                       inicio - dplyr::lag(fin)),
              pausa_posterior = ifelse(dplyr::row_number() == dplyr::n(), NA_real_,
                                       dplyr::lead(inicio) - fin)
            ) %>%
            dplyr::ungroup()
        }

        # ========================================
        # Crear resumen de GFs (grupos fónicos)
        # ========================================
        gfs_resumen <- data.frame()
        
        if (nrow(resultados_phones) > 0) {
          incProgress(0.1, detail = "Resumen de grupos fónicos...")
          
          for (fn in unique(resultados_phones$filename)) {
            for (spk in unique(resultados_phones$hablante[resultados_phones$filename == fn])) {
              phones_spk <- resultados_phones[resultados_phones$filename == fn & resultados_phones$hablante == spk, ]
              
              for (gf_val in unique(phones_spk$grupo_fonico)) {
                vocales_gf <- phones_spk[phones_spk$grupo_fonico == gf_val, ]
                if (nrow(vocales_gf) == 0) next
                
                f0_vals <- vocales_gf$f0_media_st[!is.na(vocales_gf$f0_media_st)]
                # Palabras del GF — preservar orden y repeticiones
                if ("palabra_idx" %in% colnames(vocales_gf)) {
                  pal_idx <- vocales_gf$palabra_idx[!is.na(vocales_gf$palabra_idx)]
                  pal_text <- vocales_gf$palabra[!is.na(vocales_gf$palabra_idx)]
                  if (length(pal_idx) > 0) {
                    pal_df <- data.frame(idx = pal_idx, txt = pal_text, stringsAsFactors = FALSE)
                    pal_df <- pal_df[!duplicated(pal_df$idx), ]
                    pal_df <- pal_df[order(pal_df$idx), ]
                    palabras_gf_ordered <- pal_df$txt[pal_df$txt != ""]
                  } else {
                    palabras_gf_ordered <- character(0)
                  }
                } else {
                  pals_raw <- vocales_gf$palabra[!is.na(vocales_gf$palabra) & vocales_gf$palabra != ""]
                  palabras_gf_ordered <- if (length(pals_raw) > 0) pals_raw[c(TRUE, pals_raw[-1] != pals_raw[-length(pals_raw)])] else character(0)
                }
                n_palabras_gf <- length(palabras_gf_ordered)
                n_ges <- length(unique(vocales_gf$grupo_entonativo))
                
                gf_row <- data.frame(
                  filename = fn,
                  hablante = spk,
                  grupo_fonico = gf_val,
                  id_gf = paste0(fn, "_", spk, "_GF", gf_val),
                  inicio = min(vocales_gf$inicio, na.rm = TRUE),
                  fin = max(vocales_gf$fin, na.rm = TRUE),
                  duracion = max(vocales_gf$fin, na.rm = TRUE) - min(vocales_gf$inicio, na.rm = TRUE),
                  num_vocales = nrow(vocales_gf),
                  num_palabras = n_palabras_gf,
                  num_ges = n_ges,
                  f0_media_gf_st = if (length(f0_vals) > 0) mean(f0_vals) else NA,
                  f0_min_gf_st = if (length(f0_vals) > 0) min(f0_vals) else NA,
                  f0_max_gf_st = if (length(f0_vals) > 0) max(f0_vals) else NA,
                  rango_f0_gf_st = if (length(f0_vals) > 1) max(f0_vals) - min(f0_vals) else 0,
                  intensidad_media_gf = if ("int_media" %in% colnames(vocales_gf)) mean(vocales_gf$int_media, na.rm = TRUE) else NA_real_,
                  transicion_media = if ("tiempo_transicion_anterior" %in% colnames(vocales_gf))
                    mean(vocales_gf$tiempo_transicion_anterior, na.rm = TRUE) else NA_real_,
                  velocidad_habla = {
                    dur_gf <- max(vocales_gf$fin, na.rm = TRUE) - min(vocales_gf$inicio, na.rm = TRUE)
                    if (dur_gf > 0) nrow(vocales_gf) / dur_gf else NA_real_
                  },
                  palabras_gf = paste(palabras_gf_ordered, collapse = " "),
                  stringsAsFactors = FALSE
                )
                
                # Estructura vocal: resumen para el GF
                if ("estructura_vocal" %in% colnames(vocales_gf)) {
                  estr_vals <- vocales_gf$estructura_vocal[!is.na(vocales_gf$estructura_vocal)]
                  gf_row$n_vocales_planas <- sum(estr_vals == "plana")
                  gf_row$n_vocales_con_movimiento <- sum(estr_vals != "plana")
                  gf_row$n_vocales_circunflejo <- if ("circunflejo_vocal" %in% colnames(vocales_gf))
                    sum(vocales_gf$circunflejo_vocal == "sí", na.rm = TRUE) else 0L
                }
                
                gfs_resumen <- bind_rows(gfs_resumen, gf_row)
              }
            }
          }
        }
        
        # ========================================
        # Etiquetado ToBI y AMH
        # ========================================
        incProgress(0.1, detail = "Etiquetado ToBI y AMH...")
        
        etiquetado_result <- aplicar_etiquetado_completo(resultados_phones, ips_resumen,
          tobi_sig = input$tobi_umbral_significativo,
          tobi_ext = input$tobi_umbral_extralto,
          tobi_bajo = input$tobi_tercio_bajo,
          tobi_alto = input$tobi_tercio_alto,
          amh_enfasis = input$amh_enfasis_pct,
          amh_asc_fuerte = input$amh_ascenso_fuerte,
          amh_asc_moderado = input$amh_ascenso_moderado,
          amh_asc_leve = input$amh_ascenso_leve,
          amh_asc_minimo = input$amh_ascenso_minimo,
          amh_desc_moderado = input$amh_descenso_moderado,
          amh_desc_fuerte = input$amh_descenso_fuerte)
        resultados_phones <- etiquetado_result$phones
        ips_resumen <- etiquetado_result$ips
        
        # ========================================
        # Medias del hablante para normalización
        # ========================================
        medias_hablante <- data.frame()
        if (nrow(resultados_phones) > 0) {
          medias_hablante <- resultados_phones %>%
            group_by(filename, hablante) %>%
            summarise(
              f0_media_st_hablante = mean(f0_media_st, na.rm = TRUE),
              f0_media_hz_hablante = mean(f0_media_hz, na.rm = TRUE),
              int_media_hablante = mean(int_media, na.rm = TRUE),
              .groups = "drop"
            )
        }
        
        # ========================================
        # Vocales por IP para gráficos
        # ========================================
        vocales_por_ip <- list()
        if (nrow(resultados_phones) > 0) {
          for (fn in unique(resultados_phones$filename)) {
            for (spk in unique(resultados_phones$hablante[resultados_phones$filename == fn])) {
              phones_spk <- resultados_phones[resultados_phones$filename == fn & resultados_phones$hablante == spk, ]
              for (gf_val in unique(phones_spk$grupo_fonico)) {
                for (ge_val in unique(phones_spk$grupo_entonativo[phones_spk$grupo_fonico == gf_val])) {
                  vocales_ge <- phones_spk[phones_spk$grupo_fonico == gf_val & phones_spk$grupo_entonativo == ge_val, ]
                  key <- paste0(fn, "|||", spk, "|||", gf_val, "|||", ge_val)
                  vocales_por_ip[[key]] <- vocales_ge
                }
              }
            }
          }
        }
        
        # ========================================
        # Guardar resultados
        # ========================================
        # Limpiar valores negativos de intensidad (artefactos de silencio)
        if ("int_media" %in% colnames(resultados_phones)) {
          resultados_phones$int_media[resultados_phones$int_media <= 0 & !is.na(resultados_phones$int_media)] <- NA_real_
          resultados_phones$int_max[resultados_phones$int_max <= 0 & !is.na(resultados_phones$int_max)] <- NA_real_
          resultados_phones$int_min[resultados_phones$int_min <= 0 & !is.na(resultados_phones$int_min)] <- NA_real_
        }
        
        datos$phones <- as.data.frame(resultados_phones)
        datos$words <- as.data.frame(resultados_words)
        datos$ips_resumen <- corregir_semitones_si_necesario(as.data.frame(ips_resumen))
        datos$gfs_resumen <- gfs_resumen
        datos$vocales_por_ip <- vocales_por_ip
        datos$medias_hablante <- medias_hablante
        datos$genero_discursivo <- input$genero_discursivo
        datos$calculado <- TRUE
        datos$cargado_desde_storage <- FALSE  # datos calculados en esta sesión, sí se pueden guardar
        
        # ========================================
        # PRECALCULAR acento_final para cada IP
        # (evita bucle fila-a-fila en Exportar Gráficos)
        # ========================================
        tryCatch({
          if (nrow(datos$ips_resumen) > 0 && nrow(resultados_phones) > 0) {
            phones_dt <- resultados_phones
            acento_vec <- vapply(seq_len(nrow(datos$ips_resumen)), function(i) {
              ip <- datos$ips_resumen[i, ]
              vocales_ge <- phones_dt[
                phones_dt$filename == ip$filename &
                phones_dt$hablante == ip$hablante &
                phones_dt$grupo_entonativo == ip$grupo_entonativo, ]
              palabras <- vocales_ge$palabra[!is.na(vocales_ge$palabra) & vocales_ge$palabra != ""]
              if (length(palabras) == 0) return("desconocida")
              ultima_pal <- tail(palabras, 1)
              tryCatch(
                determinar_acentuacion(ultima_pal, "es")$tipo,
                error = function(e) "desconocida"
              )
            }, character(1))
            datos$ips_resumen$acento_final <- acento_vec
          }
        }, error = function(e) {
          message("[acento_final] Error en precálculo: ", e$message)
        })
        
        # Propagar género y metadatos a dataframes
        if (!is.null(input$genero_discursivo)) {
          if (nrow(resultados_phones) > 0 && !"genero" %in% colnames(resultados_phones))
            datos$phones$genero <- input$genero_discursivo
          if (nrow(resultados_words) > 0 && !"genero" %in% colnames(resultados_words))
            datos$words$genero <- input$genero_discursivo
          if (nrow(ips_resumen) > 0 && !"genero" %in% colnames(ips_resumen))
            datos$ips_resumen$genero <- input$genero_discursivo
          if (nrow(gfs_resumen) > 0 && !"genero" %in% colnames(gfs_resumen))
            datos$gfs_resumen$genero <- input$genero_discursivo
        }
        
        incProgress(0.8, detail = "\u00a1An\u00e1lisis pros\u00f3dico completado!")
        showNotification("\u2714 An\u00e1lisis pros\u00f3dico completado", type = "message")
        
        n_ph <- if (!is.null(datos$phones)) nrow(datos$phones) else 0
        n_ip <- if (!is.null(datos$ips_resumen)) nrow(datos$ips_resumen) else 0
        n_gf <- if (!is.null(datos$gfs_resumen)) nrow(datos$gfs_resumen) else 0
        datos$analisis_prosodia <- TRUE
        log_event("CALCULO_COMPLETADO", paste0(n_ph, " vocales, ", n_ip, " GEs, ", n_gf, " GFs"))
        
        # Computar cl\u00e1usulas ANTES de guardar (para que los RDS incluyan clausulas)
        tryCatch({
          incProgress(0.05, detail = "Computando cl\u00e1usulas...")
          computar_clausulas()
        }, error = function(e) {
          log_event("CLAUSULAS_ERROR", e$message)
          showNotification(paste("Error cl\u00e1usulas:", e$message), type = "warning")
        })
        
        # Auto-guardar: un RDS por archivo, archivo por archivo
        tryCatch({
          gen <- if (!is.null(input$genero_discursivo)) input$genero_discursivo else "entrevistas"
          ph_save <- datos$phones
          if (!is.data.frame(ph_save)) {
            showNotification(paste0("\u26a0 datos$phones no es data.frame: ", class(ph_save)), type = "error", duration = 20)
            ph_save <- as.data.frame(ph_save)
          }
          fns_calc <- if (!is.null(ph_save) && "filename" %in% colnames(ph_save))
                        sort(unique(as.character(ph_save$filename))) else character(0)
          if (length(fns_calc) == 0) {
            showNotification("\u26a0 Auto-guardado: sin archivos en datos$phones", type = "warning", duration = 10)
          }
          n_guardados <- 0L
          for (fn_i in fns_calc) {
            incProgress(0.15 / max(length(fns_calc), 1),
                        detail = paste0("Guardando ", fn_i, " (", n_guardados + 1, "/", length(fns_calc), ")"))
            guardar_analisis_por_archivo(fn_i, genero = gen, notificar = FALSE)
            n_guardados <- n_guardados + 1L
          }
          showNotification(paste0("\u2714 ", n_guardados, " archivos guardados (con cl\u00e1usulas)"), type = "message", duration = 4)
          log_event("AUTO_GUARDADO", paste0("Post-c\u00e1lculo: ", n_guardados, " archivos (incl. cl\u00e1usulas)"))
          showModal(modalDialog(
            title = tagList(icon("check-circle", class = "text-success"), " An\u00e1lisis completado y guardado"),
            tagList(
              tags$p(paste0("\u2714 ", n_guardados, " archivo(s) guardados correctamente.")),
              tags$p(paste0("GEs: ", n_ip, " | GFs: ", n_gf, " | Vocales: ", n_ph))
            ),
            easyClose = TRUE, footer = modalButton("Cerrar")
          ))
        }, error = function(e) {
          showNotification(paste0("Error auto-guardado: ", e$message), type = "error", duration = 20)
          log_event("AUTO_GUARDADO_ERROR", e$message)
        })
        
      }, error = function(e) {
        showNotification(paste("Error en el cálculo:", e$message), type = "error")
        print(paste("Error:", e$message))
        print(traceback())
      })
    })
  })
  
  # ========================================
  # OBSERVER: ANÁLISIS DE SENTIMIENTOS
  # ========================================
  
  observeEvent(input$btn_sentimientos, {

    if (!datos$calculado || is.null(datos$ips_resumen)) {
      showNotification("Primero debe ejecutar el análisis prosódico (botón Calcular)", type = "error")
      return()
    }

    # ── Mostrar modal INMEDIATAMENTE al pulsar el botón ──────────────────
    showModal(modalDialog(
      title = "Analizando sentimientos y emociones",
      tags$div(style = "text-align: center; padding: 20px;",
        tags$div(class = "spinner-border text-info", role = "status",
                 style = "width: 3rem; height: 3rem;",
                 tags$span(class = "sr-only", "Cargando...")),
        tags$br(), tags$br(),
        tags$p(id = "sent_modal_msg", style = "font-size: 16px;",
               "Buscando intérprete Python y librerías..."),
        tags$p(style = "font-size: 12px; color: #666;",
               "El modelo BERT se cargará la primera vez (puede tardar más).")
      ),
      footer = NULL,
      easyClose = FALSE
    ))

    # Buscar Python con pysentimiento: probar virtualenv bert-env, luego PATH
    python_bin <- NULL
    python_candidates <- c(.python_venv_path, .python_sys_candidates)
    
    for (py in python_candidates) {
      if (nchar(py) > 0 && file.exists(py)) {
        # Verificar que este Python tiene pysentimiento
        check <- tryCatch({
          system2(py, c("-c", shQuote("import pysentimiento; print('OK')")),
                  stdout = TRUE, stderr = TRUE)
        }, error = function(e) "")
        if (any(grepl("OK", check))) {
          python_bin <- py
          break
        }
      }
    }
    
    if (is.null(python_bin)) {
      removeModal()
      showNotification(
        paste0("pysentimiento no encontrado en ningún Python.\n",
               "Instale con: pip install pysentimiento\n",
               "Buscados: ", paste(python_candidates[nchar(python_candidates) > 0], collapse = ", ")),
        type = "error", duration = 15
      )
      return()
    }
    
    cat("Usando Python:", python_bin, "\n")
    
    # Verificar funasr (solo si se pidió análisis de audio)
    if (input$sent_analizar_audio) {
      # Construir directorio de WAVs desde audios ya disponibles
      wav_dir_tmp <- file.path(tempdir(), "sent_wavs_auto")
      dir.create(wav_dir_tmp, recursive = TRUE, showWarnings = FALSE)
      
      fns <- unique(datos$ips_resumen$filename)
      wavs_encontrados <- 0
      for (fn in fns) {
        wav_found <- buscar_wav(fn)
        if (!is.null(wav_found) && file.exists(wav_found)) {
          dest <- file.path(wav_dir_tmp, paste0(fn, ".", tools::file_ext(wav_found)))
          if (dest == wav_found || file.exists(dest)) { wavs_encontrados <- wavs_encontrados + 1; next }
          tryCatch(file.copy(wav_found, dest, overwrite = TRUE), error = function(e) NULL)
          if (file.exists(dest)) wavs_encontrados <- wavs_encontrados + 1
        }
      }
      
      # Si también hay wavs subidos directamente en la sesión
      if (!is.null(sent_wavs$dir) && dir.exists(sent_wavs$dir)) {
        for (f in list.files(sent_wavs$dir, full.names = TRUE)) {
          file.copy(f, file.path(wav_dir_tmp, basename(f)), overwrite = FALSE)
        }
      }
      
      sent_wavs$dir <- wav_dir_tmp
      
      if (wavs_encontrados == 0 && length(list.files(wav_dir_tmp)) == 0) {
        showNotification("No se encontraron archivos de audio. Suba WAVs en la pestaña Sentimientos o procesando con Praat/Parselmouth.", type = "warning")
      }
      
      py_check2 <- tryCatch({
        system2(python_bin, c("-c", shQuote("import funasr; print('OK')")),
                stdout = TRUE, stderr = TRUE)
      }, error = function(e) "")
      if (!any(grepl("OK", py_check2))) {
        removeModal()
        showNotification("funasr no instalado en el Python detectado. Ejecute: pip install funasr soundfile", type = "error")
        return()
      }
    }
    
    # ── Preparar TSV de entrada ───────────────────────────────────────────────
    tryCatch({
      tmp_dir    <- tempdir()
      ips_file   <- file.path(tmp_dir, "ips_para_sentimiento.tsv")
      output_file <- file.path(tmp_dir, "resultados_sentimiento.tsv")

      ips_export <- datos$ips_resumen
      col_map <- c("inicio" = "tmin_ip", "fin" = "tmax_ip", "palabras_grupo" = "palabras")
      for (old_name in names(col_map)) {
        new_name <- col_map[old_name]
        if (old_name %in% colnames(ips_export) && !new_name %in% colnames(ips_export))
          colnames(ips_export)[colnames(ips_export) == old_name] <- new_name
      }
      if (!"archivo_origen" %in% colnames(ips_export) && "filename" %in% colnames(ips_export))
        ips_export$archivo_origen <- ips_export$filename
      write.table(ips_export, ips_file, sep = "\t", row.names = FALSE, quote = TRUE)

      # ── Buscar script ─────────────────────────────────────────────────────
      script_name <- "analyze_sentiment_emotion.py"
      script_path <- NULL
      search_paths <- c(file.path(getwd(), script_name), file.path(".", script_name))
      app_dir <- tryCatch(dirname(rstudioapi::getSourceEditorContext()$path), error = function(e) NULL)
      if (!is.null(app_dir)) search_paths <- c(file.path(app_dir, script_name), search_paths)
      for (sp in search_paths) {
        if (!is.null(sp) && file.exists(sp)) { script_path <- normalizePath(sp); break }
      }
      if (is.null(script_path)) {
        removeModal()
        showNotification(paste("No se encontró", script_name, "- Colóquelo junto a app.R"), type = "error")
        return()
      }

      # ── Lanzar Python de forma NO bloqueante (processx) ──────────────────
      py_args <- c(
        script_path,
        "--ips_file",    ips_file,
        "--output_file", output_file,
        "--lang", switch(input$idioma,
                    "Catalán"="ca","Inglés"="en","es")
      )
      if (input$sent_analizar_audio && !is.null(sent_wavs$dir) && dir.exists(sent_wavs$dir)) {
        py_args <- c(py_args, "--wav_dir", sent_wavs$dir, "--model_audio", input$sent_modelo_audio)
      } else {
        py_args <- c(py_args, "--no_audio")
      }

      proc <- processx::process$new(
        command = python_bin,
        args    = py_args,
        stdout  = "|",
        stderr  = "|"
      )
      sent_proc_rv$process      <- proc
      sent_proc_rv$output_file  <- output_file
      sent_proc_rv$output_lines <- character(0)
      sent_proc_rv$poll_active  <- TRUE
      cat("Sentimientos: proceso Python lanzado (PID", proc$get_pid(), ")\n")

    }, error = function(e) {
      removeModal()
      showNotification(paste("Error preparando análisis:", e$message), type = "error")
      cat("Error en sentimientos (setup):", e$message, "\n")
    })
  })

  # ── Polling no bloqueante: comprueba el proceso Python cada 500 ms ────────
  observe({
    if (!isTRUE(sent_proc_rv$poll_active)) return()
    invalidateLater(500)

    proc <- sent_proc_rv$process
    if (is.null(proc)) { sent_proc_rv$poll_active <- FALSE; return() }

    # Leer stdout + stderr disponibles sin bloquear
    new_out <- tryCatch(proc$read_output_lines(), error = function(e) character(0))
    new_err <- tryCatch(proc$read_error_lines(),  error = function(e) character(0))
    new_lines <- c(new_out, new_err)

    if (length(new_lines) > 0) {
      sent_proc_rv$output_lines <- c(sent_proc_rv$output_lines, new_lines)
      status_lines <- grep("^STATUS:", new_lines, value = TRUE)
      if (length(status_lines) > 0) {
        last_msg <- sub("^STATUS:", "", tail(status_lines, 1))
        shinyjs::html("sent_modal_msg", last_msg)
      }
      warn_lines <- grep("^WARNING:", new_lines, value = TRUE)
      for (wl in warn_lines)
        showNotification(sub("^WARNING:", "", wl), type = "warning", duration = 5)
    }

    if (proc$is_alive()) return()   # todavía ejecutando → esperar siguiente tick

    # ── Proceso terminado: recoger resultado ─────────────────────────────────
    sent_proc_rv$poll_active <- FALSE
    sent_proc_rv$process     <- NULL
    output_lines <- sent_proc_rv$output_lines
    output_file  <- sent_proc_rv$output_file
    sent_proc_rv$output_lines <- character(0)

    cat("=== Sentimientos: output Python ===\n")
    for (line in output_lines) cat(line, "\n")
    cat("=== Fin output ===\n")

    if (!is.null(output_file) && file.exists(output_file)) {
      resultados <- tryCatch(
        read.delim(output_file, sep = "\t", stringsAsFactors = FALSE),
        error = function(e) NULL
      )
      if (!is.null(resultados)) {
        resultados <- limpiar_emociones_cjk(resultados)
        datos$sentimientos <- resultados
        if (!is.null(datos$ips_resumen) && nrow(datos$ips_resumen) > 0 &&
            nrow(resultados) == nrow(datos$ips_resumen)) {
          cols_sent <- c("sentimiento","prob_pos","prob_neg","prob_neu",
                         "emocion_texto","prob_emocion_texto",
                         "emocion_audio","prob_emocion_audio")
          for (col in cols_sent)
            if (col %in% colnames(resultados)) datos$ips_resumen[[col]] <- resultados[[col]]
        }
        json_lines <- grep("^RESULT_JSON:", output_lines, value = TRUE)
        if (length(json_lines) > 0) {
          resumen <- tryCatch(jsonlite::fromJSON(sub("^RESULT_JSON:", "", json_lines[1])),
                              error = function(e) NULL)
          if (!is.null(resumen)) {
            msg_parts <- character(0)
            if (isTRUE(resumen$sentimiento_completado))  { datos$analisis_sentimientos <- TRUE;  msg_parts <- c(msg_parts, "sentimiento textual") }
            if (isTRUE(resumen$emocion_texto_completado)) { datos$analisis_sentimientos <- TRUE;  msg_parts <- c(msg_parts, "emociones textuales") }
            if (isTRUE(resumen$emocion_audio_completado)) { datos$analisis_emociones_audio <- TRUE; msg_parts <- c(msg_parts, "emociones acústicas") }
            showNotification(
              paste0("✔ Completado: ", paste(msg_parts, collapse = ", "),
                     " (", resumen$n_ips, " GEs)"),
              type = "message", duration = 10)
          }
        }
      }
    } else {
      showNotification("Error: no se generó el archivo de resultados", type = "error")
      err_lines <- grep("^(ERROR|Traceback|File |ModuleNotFoundError)", output_lines, value = TRUE)
      if (length(err_lines) > 0)
        showNotification(paste(head(err_lines, 5), collapse = "\n"), type = "error", duration = 15)
      else if (length(output_lines) > 0)
        showNotification(paste("Output Python:", paste(tail(output_lines, 5), collapse = "\n")),
                         type = "error", duration = 15)
    }

    removeModal()

    # Auto-guardar
    tryCatch({
      gen   <- if (!is.null(datos$genero_discursivo)) datos$genero_discursivo else "entrevistas"
      fns_s <- if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones))
                 sort(unique(datos$phones$filename)) else character(0)
      for (fn_s in fns_s) guardar_analisis_por_archivo(fn_s, genero = gen, notificar = FALSE)
      if (length(fns_s) > 0)
        showNotification(paste0("✔ Sentimientos guardados (", length(fns_s), " archivos)"),
                         type = "message", duration = 3)
      log_event("SENTIMIENTOS_COMPLETADOS", paste0("Guardados ", length(fns_s), " archivos"))
    }, error = function(e) log_event("AUTO_GUARDADO_ERROR", e$message))
  })
  
