      group_by(filename) %>%
      summarise(
        Hablantes = n_distinct(hablante),
        GEs = n(),
        Dur_media_GE = round(mean(duracion, na.rm = TRUE), 2),
        F0_media_st = if ("f0_media_grupo_st" %in% colnames(ips)) round(mean(f0_media_grupo_st, na.rm = TRUE), 1) else NA_real_,
        .groups = "drop"
      )
    
    if (!is.null(datos$words) && "filename" %in% colnames(datos$words)) {
      words_arch <- datos$words %>% group_by(filename) %>% summarise(Palabras = n(), .groups = "drop")
      resumen <- left_join(resumen, words_arch, by = "filename")
    }
    if (!is.null(datos$gfs_resumen) && "filename" %in% colnames(datos$gfs_resumen)) {
      gfs_arch <- datos$gfs_resumen %>% group_by(filename) %>% summarise(GFs = n(), .groups = "drop")
      resumen <- left_join(resumen, gfs_arch, by = "filename")
    }
    if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones)) {
      phones_arch <- datos$phones %>% group_by(filename) %>% summarise(Vocales = n(), .groups = "drop")
      resumen <- left_join(resumen, phones_arch, by = "filename")
    }
    
    # Añadir género si disponible
    if ("genero" %in% colnames(ips)) {
      gen_arch <- ips %>% group_by(filename) %>% summarise(Genero = first(genero), .groups = "drop")
      resumen <- left_join(gen_arch, resumen, by = "filename")
    }
    
    # Fila total
    total <- resumen %>% summarise(across(where(is.numeric), ~sum(.x, na.rm = TRUE)))
    total$Dur_media_GE <- round(mean(ips$duracion, na.rm = TRUE), 2)
    if ("f0_media_grupo_st" %in% colnames(ips)) total$F0_media_st <- round(mean(ips$f0_media_grupo_st, na.rm = TRUE), 1)
    total_row <- bind_cols(tibble(!!colnames(resumen)[1] := "TOTAL"), total)
    # Fill character columns
    for (cn in colnames(resumen)) {
      if (is.character(resumen[[cn]]) && !cn %in% colnames(total_row)) total_row[[cn]] <- ""
    }
    resumen <- bind_rows(resumen, total_row[, colnames(resumen)])
    
    colnames(resumen)[colnames(resumen) == "filename"] <- "Archivo"
    datatable(resumen, options = list(dom = 'tip', pageLength = 25, scrollX = TRUE), rownames = FALSE)
  })
  
  # Desglose por hablante
  output$resumen_tabla_hablantes <- renderDT({
    req(datos$calculado, datos$ips_resumen)
    ips <- datos$ips_resumen
    
    # Group by hablante+filename (1 hablante = 1 archivo, but names may repeat across files)
    resumen <- ips %>%
      group_by(hablante, filename) %>%
      summarise(
        GEs = n(),
        Dur_total = round(sum(duracion, na.rm = TRUE), 1),
        Dur_media_GE = round(mean(duracion, na.rm = TRUE), 2),
        F0_media_st = if ("f0_media_grupo_st" %in% colnames(ips)) round(mean(f0_media_grupo_st, na.rm = TRUE), 1) else NA_real_,
        F0_sd_st = if ("f0_media_grupo_st" %in% colnames(ips)) round(sd(f0_media_grupo_st, na.rm = TRUE), 1) else NA_real_,
        .groups = "drop"
      )
    
    # Add intensity from phones if available (per-vowel level)
    if (!is.null(datos$phones) && "int_media" %in% colnames(datos$phones) && "hablante" %in% colnames(datos$phones)) {
      int_hab <- datos$phones %>% group_by(hablante, filename) %>% 
        summarise(Int_media_dB = round(mean(int_media, na.rm = TRUE), 1), .groups = "drop")
      resumen <- left_join(resumen, int_hab, by = c("hablante", "filename"))
    }
    
    if (!is.null(datos$words) && "hablante" %in% colnames(datos$words)) {
      words_hab <- datos$words %>% group_by(hablante, filename) %>% summarise(Palabras = n(), .groups = "drop")
      resumen <- left_join(resumen, words_hab, by = c("hablante", "filename"))
    }
    if (!is.null(datos$gfs_resumen) && "hablante" %in% colnames(datos$gfs_resumen)) {
      gfs_hab <- datos$gfs_resumen %>% group_by(hablante, filename) %>% summarise(GFs = n(), .groups = "drop")
      resumen <- left_join(resumen, gfs_hab, by = c("hablante", "filename"))
    }
    if (!is.null(datos$phones) && "hablante" %in% colnames(datos$phones)) {
      phones_hab <- datos$phones %>% group_by(hablante, filename) %>% summarise(Vocales = n(), .groups = "drop")
      resumen <- left_join(resumen, phones_hab, by = c("hablante", "filename"))
    }
    
    # N° cláusulas si disponible
    if (!is.null(datos$clausulas) && "hablante" %in% colnames(datos$clausulas)) {
      cl_hab <- datos$clausulas %>% group_by(hablante, filename) %>% summarise(Clausulas = n(), .groups = "drop")
      resumen <- left_join(resumen, cl_hab, by = c("hablante", "filename"))
    }
    
    # Añadir género si disponible
    if ("genero" %in% colnames(ips)) {
      gen_hab <- ips %>% group_by(hablante, filename) %>% summarise(Genero = first(genero), .groups = "drop")
      resumen <- left_join(gen_hab, resumen, by = c("hablante", "filename"))
    }
    
    # Fila total: means for averages, sums for counts
    total <- resumen %>% summarise(across(where(is.numeric), ~sum(.x, na.rm = TRUE)))
    total$Dur_media_GE <- round(mean(ips$duracion, na.rm = TRUE), 2)
    if ("f0_media_grupo_st" %in% colnames(ips)) {
      total$F0_media_st <- round(mean(ips$f0_media_grupo_st, na.rm = TRUE), 1)
      total$F0_sd_st <- round(sd(ips$f0_media_grupo_st, na.rm = TRUE), 1)
    }
    if ("Int_media_dB" %in% colnames(resumen) && !is.null(datos$phones) && "int_media" %in% colnames(datos$phones)) {
      total$Int_media_dB <- round(mean(datos$phones$int_media, na.rm = TRUE), 1)
    }
    total_row <- bind_cols(tibble(hablante = "TOTAL", filename = ""), total)
    for (cn in colnames(resumen)) {
      if (is.character(resumen[[cn]]) && !cn %in% colnames(total_row)) total_row[[cn]] <- ""
    }
    resumen <- bind_rows(resumen, total_row[, colnames(resumen)])
    
    colnames(resumen)[colnames(resumen) == "hablante"] <- "Hablante"
    colnames(resumen)[colnames(resumen) == "filename"] <- "Archivo"
    datatable(resumen, options = list(dom = 'tip', pageLength = 50, scrollX = TRUE), rownames = FALSE)
  })
  
