  # ========================================
  # RECÁLCULO SELECTIVO DE GEs
  # ========================================

  observeEvent(input$btn_recalc_ge, {
    req(datos$calculado, datos$phones)

    # Guardar snapshot ANTES de recalcular para detectar cambios
    if (!is.null(datos$ips_resumen)) {
      snap <- datos$ips_resumen %>%
        mutate(ge_key = paste(filename, hablante,
                              as.character(grupo_fonico),
                              as.character(grupo_entonativo), sep = "|||")) %>%
        select(ge_key, inicio, fin, any_of("palabras_grupo"))
      ge_snapshot(snap)
    }

    showNotification("⏳ Recalculando grupos entonativos desde datos en memoria...",
                     id = "notif_ge_recalc", duration = NULL, type = "message")
    tryCatch({
      recalcular_ges_desde_phones(
        recalc_clausulas = isTRUE(input$ge_recalc_incl_clausulas)
      )
    }, error = function(e) {
      showNotification(paste("❌ Error al recalcular GEs:", e$message),
                       id = "notif_ge_recalc", type = "error", duration = 12)
    })
    removeNotification("notif_ge_recalc")
  })

  # Detectar cambios en GEs después de cada recálculo y actualizar ge_changed_ids
  observeEvent(datos$ips_resumen, {
    snap <- ge_snapshot()
    # Solo comparar si hay un snapshot explícito (tomado justo antes de recalcular)
    if (is.null(snap) || is.null(datos$ips_resumen)) return()
    if (nrow(snap) == 0 || nrow(datos$ips_resumen) == 0) return()

    nuevo <- datos$ips_resumen %>%
      mutate(ge_key = paste(filename, hablante,
                            as.character(grupo_fonico),
                            as.character(grupo_entonativo), sep = "|||"))

    # snap ya tiene ge_key, inicio, fin, palabras_grupo (guardados con esos nombres)
    joined <- inner_join(
      snap %>% select(ge_key, inicio, fin,
                      any_of("palabras_grupo")) %>%
               rename(ini_old = inicio, fin_old = fin,
                      any_of(c(pal_old = "palabras_grupo"))),
      nuevo %>% select(ge_key, inicio, fin,
                       any_of("palabras_grupo")) %>%
               rename(ini_new = inicio, fin_new = fin,
                      any_of(c(pal_new = "palabras_grupo"))),
      by = "ge_key"
    )

    cambiados <- joined %>% filter(
      abs(ini_new - ini_old) > 0.05 |
      abs(fin_new - fin_old) > 0.05 |
      (exists("pal_new", where = ., inherits = FALSE) &
       exists("pal_old", where = ., inherits = FALSE) &
       !is.na(pal_new) & !is.na(pal_old) & pal_new != pal_old)
    ) %>% pull(ge_key)

    nuevos_ge <- setdiff(nuevo$ge_key, snap$ge_key)
    todos_cambiados <- unique(c(cambiados, nuevos_ge))

    if (length(todos_cambiados) > 0) {
      ge_changed_ids(todos_cambiados)
    }

    # Limpiar snapshot para que no se vuelva a disparar en cambios futuros no intencionales
    ge_snapshot(NULL)
  }, ignoreNULL = TRUE)

  # UI: mostrar badge de cambios y botón de recálculo selectivo de emociones
  output$ge_cambios_ui <- renderUI({
    ids <- ge_changed_ids()
    if (is.null(ids) || length(ids) == 0) return(NULL)
    n_ch <- length(ids)
    tagList(
      span(style = "color:#e67e22; font-size:0.88em;",
        icon("exclamation-triangle"),
        paste0(" ", n_ch, " GE", if (n_ch != 1) "s" else "", " modificado", if (n_ch != 1) "s" else "")
      ),
      br(),
      actionButton("btn_recalc_emo_selectivo", "Recalcular emociones (solo modificados)",
        icon = icon("brain"), class = "btn-xs btn-outline-warning",
        style = "margin-top:4px; font-size:0.82em;"),
      actionButton("btn_recalc_emo_todos", "Recalcular emociones (todos)",
        icon = icon("redo"), class = "btn-xs btn-outline-danger",
        style = "margin-top:4px; margin-left:4px; font-size:0.82em;")
    )
  })

  # Observer: recalcular emociones solo para GEs cambiados
  observeEvent(input$btn_recalc_emo_selectivo, {
    req(datos$calculado, datos$ips_resumen)
    ids_mod <- ge_changed_ids()
    if (is.null(ids_mod) || length(ids_mod) == 0) {
      showNotification("No hay GEs modificados detectados.", type = "warning")
      return()
    }

    # Filtrar ips_resumen solo a los GEs cambiados
    ips_mod <- datos$ips_resumen %>%
      mutate(ge_key_tmp = paste(filename, hablante,
                                as.character(grupo_fonico),
                                as.character(grupo_entonativo), sep = "|||")) %>%
      filter(ge_key_tmp %in% ids_mod) %>%
      select(-ge_key_tmp)

    n_mod <- nrow(ips_mod)
    showNotification(
      paste0("⏳ Recalculando emociones para ", n_mod, " GEs modificados..."),
      id = "notif_emo_sel", duration = NULL, type = "message"
    )

    # Reusar la lógica del observer de btn_sentimientos pero con ips filtrado
    tryCatch({
      # Guardar ips completo temporalmente, sustituir por el filtrado para que el script solo procese esos GEs
      ips_backup <- datos$ips_resumen
      datos$ips_resumen <- ips_mod  # script Python recibirá solo los GEs modificados

      # Lanzar el análisis (reutilizamos shinyjs::click o un flag para disparar btn_sentimientos)
      # Como no podemos hacer click programático fácilmente, construimos el proceso inline:
      python_bin <- NULL
      for (py in c(.python_venv_path, .python_sys_candidates)) {
        if (nchar(py) > 0 && file.exists(py)) {
          chk <- tryCatch(system2(py, c("-c", shQuote("import pysentimiento; print('OK')")),
                                  stdout = TRUE, stderr = TRUE), error = function(e) "")
          if (any(grepl("OK", chk))) { python_bin <- py; break }
        }
      }

      datos$ips_resumen <- ips_backup  # restaurar inmediatamente

      if (is.null(python_bin)) {
        removeNotification("notif_emo_sel")
        showNotification("pysentimiento no encontrado. Ver configuración de Python.", type = "error")
        return()
      }

      tmp_dir    <- tempdir()
      ips_file   <- file.path(tmp_dir, "ips_selectivo.tsv")
      out_file   <- file.path(tmp_dir, "resultados_selectivo.tsv")

      ips_exp <- ips_mod
      for (old_n in c("inicio","fin","palabras_grupo")) {
        new_n <- c("tmin_ip","tmax_ip","palabras")[c("inicio","fin","palabras_grupo") == old_n]
        if (old_n %in% colnames(ips_exp) && !new_n %in% colnames(ips_exp))
          colnames(ips_exp)[colnames(ips_exp) == old_n] <- new_n
      }
      if (!"archivo_origen" %in% colnames(ips_exp) && "filename" %in% colnames(ips_exp))
        ips_exp$archivo_origen <- ips_exp$filename

      write.table(ips_exp, ips_file, sep = "\t", row.names = FALSE, quote = TRUE)

      script_name <- "analyze_sentiment_emotion.py"
      script_path <- NULL
      for (sp in c(file.path(getwd(), script_name), file.path(".", script_name))) {
        if (!is.null(sp) && file.exists(sp)) { script_path <- normalizePath(sp); break }
      }
      if (is.null(script_path)) {
        removeNotification("notif_emo_sel")
        showNotification(paste("No se encontró", script_name), type = "error")
        return()
      }

      cmd_args <- c(shQuote(script_path),
                    "--ips_file", shQuote(ips_file),
                    "--output_file", shQuote(out_file),
                    "--lang", switch(input$idioma, "Catalán"="ca","Inglés"="en","es"),
                    "--no_audio")
      full_cmd <- paste(shQuote(python_bin), paste(cmd_args, collapse = " "), "2>&1")
      system(full_cmd, intern = TRUE)

      if (file.exists(out_file)) {
        res_sel <- limpiar_emociones_cjk(read.delim(out_file, sep = "\t", stringsAsFactors = FALSE))
        # Propagar resultados de vuelta a ips_resumen solo para los GEs modificados
        cols_sent <- intersect(c("sentimiento","prob_pos","prob_neg","prob_neu",
                                  "emocion_texto","prob_emocion_texto",
                                  "emocion_audio","prob_emocion_audio"),
                                colnames(res_sel))
        if (length(cols_sent) > 0 && nrow(res_sel) == n_mod) {
          # join por posición — los GEs están en el mismo orden
          idx_mod <- which(
            paste(datos$ips_resumen$filename, datos$ips_resumen$hablante,
                  datos$ips_resumen$grupo_fonico, datos$ips_resumen$grupo_entonativo,
                  sep = "|||") %in% ids_mod
          )
          for (col in cols_sent) {
            if (length(idx_mod) == nrow(res_sel))
              datos$ips_resumen[[col]][idx_mod] <- res_sel[[col]]
          }
        }
        ge_changed_ids(NULL)  # limpiar badge
        removeNotification("notif_emo_sel")
        showNotification(
          paste0("✔ Emociones actualizadas para ", n_mod, " GEs modificados."),
          type = "message", duration = 8
        )
      } else {
        removeNotification("notif_emo_sel")
        showNotification("Error: no se generó resultado del análisis selectivo.", type = "error")
      }
    }, error = function(e) {
      removeNotification("notif_emo_sel")
      showNotification(paste("Error en recálculo selectivo:", e$message), type = "error")
    })
  })

  # Observer: recalcular emociones para todos (limpia badge y lanza análisis completo)
  observeEvent(input$btn_recalc_emo_todos, {
    ge_changed_ids(NULL)
    # Disparar el análisis completo reutilizando el botón principal
    shinyjs::click("btn_sentimientos")
  })

  # Recomputar cláusulas
observeEvent(input$clausula_recomputar_todos, {
  showNotification("⏳ Computando cláusulas para todos los archivos...", 
                   id = "notif_cl", duration = NULL, type = "message")
  tryCatch({
    computar_clausulas()  # leerá los inputs directamente dentro de la función
  }, error = function(e) {
    showNotification(paste("❌ Error:", e$message),
                     id = "notif_cl", type = "error", duration = 10)
  })
  removeNotification("notif_cl")
})

observeEvent(input$clausula_recomputar_archivo, {
  req(input$clausula_filtro_archivo)
  fn_sel <- input$clausula_filtro_archivo
  showNotification(paste0("⏳ Computando cláusulas para: ", fn_sel, "..."),
                   id = "notif_cl", duration = NULL, type = "message")
  tryCatch({
    computar_clausulas(solo_archivo = fn_sel)
  }, error = function(e) {
    showNotification(paste("❌ Error:", e$message),
                     id = "notif_cl", type = "error", duration = 10)
  })
  removeNotification("notif_cl")
})
  
  # Helper: filtrar IPs por selección de cláusulas (siempre por archivo)
  clausula_ips_filtrados <- reactive({
  req(datos$calculado, datos$ips_resumen,
      "clausula_id" %in% colnames(datos$ips_resumen),
      input$clausula_filtro_archivo)

  ips <- datos$ips_resumen %>%
    filter(
      !is.na(clausula_id),
      !is.na(f0_primera_hz),
      filename == input$clausula_filtro_archivo  # ya filtra por archivo
    )

  if (!is.null(input$clausula_filtro_hablante) &&
      input$clausula_filtro_hablante != "__todos__") {
    ips <- ips %>% filter(hablante == input$clausula_filtro_hablante)
  }

  # Crear ID compuesto para evitar colisiones entre archivos
  ips <- ips %>%
    mutate(
      hablante_archivo_id = paste0(filename, "|||", hablante),
      clausula_label       = paste0("CL", clausula_id,
                                    " [", hablante, "]")
    )
  ips
})
  
  # Gráfico PLOTLY de cláusulas — sin leyenda, hover para info
  output$plot_clausulas <- renderPlotly({
    ips <- clausula_ips_filtrados()
    req(nrow(ips) > 0)

    # Variable Y
    y_var   <- if (!is.null(input$clausula_y_var) && input$clausula_y_var == "f0_st") "f0_media_grupo_st" else "f0_primera_hz"
    y_label <- if (y_var == "f0_media_grupo_st") "F0 media GE (St)" else "F0 primera vocal (Hz)"

    ips <- ips %>% arrange(filename, inicio)
    ips$y_val <- ips[[y_var]]
    ips <- ips %>% filter(!is.na(y_val))

    # Etiqueta única por hablante + cláusula (evita mezclar CL1 de H1 con CL1 de H2)
    ips$clausula_label <- paste0("CL", ips$clausula_id, " [", ips$hablante, "]")

    # Colores por cláusula-hablante
    cls_unique <- unique(ips$clausula_label)
    n_cl <- length(cls_unique)
    paleta <- rep(c("#E74C3C", "#3498DB", "#2ECC71", "#F39C12", "#9B59B6",
                    "#1ABC9C", "#E67E22", "#34495E", "#16A085", "#C0392B"), length.out = n_cl)

    fig <- plot_ly()

    for (i in seq_along(cls_unique)) {
      cl_lab <- cls_unique[i]
      voc_cl <- ips[ips$clausula_label == cl_lab, ]
      voc_cl <- voc_cl %>% arrange(inicio)

      # ── Romper línea cuando otro hablante interviene entre GEs consecutivos ──
      # Insertar filas NA entre pares de GEs separados por un turno ajeno
      if (nrow(voc_cl) > 1) {
        hab_cl <- voc_cl$hablante[1]
        fn_cl  <- voc_cl$filename[1]
        # GEs de otros hablantes en este archivo, en orden temporal
        otros <- ips[ips$filename == fn_cl & ips$hablante != hab_cl, c("inicio", "fin")]
        rows_out <- list()
        for (j in seq_len(nrow(voc_cl))) {
          rows_out[[length(rows_out) + 1L]] <- voc_cl[j, ]
          if (j < nrow(voc_cl)) {
            prev_fin    <- voc_cl$fin[j]
            next_inicio <- voc_cl$inicio[j + 1L]
            if (!is.na(prev_fin) && !is.na(next_inicio) && nrow(otros) > 0) {
              interrumpido <- any(otros$inicio >= prev_fin & otros$inicio < next_inicio)
              if (interrumpido) {
                na_row <- voc_cl[j, ]
                na_row$y_val  <- NA_real_
                na_row$inicio <- (prev_fin + next_inicio) / 2
                rows_out[[length(rows_out) + 1L]] <- na_row
              }
            }
          }
        }
        voc_cl <- do.call(rbind, rows_out)
      }

      voc_cl$hover <- ifelse(
        is.na(voc_cl$y_val), NA_character_,
        paste0(
          "<b>", cl_lab, "</b> (pos ", voc_cl$clausula_posicion, ")<br>",
          "GF", voc_cl$grupo_fonico, " / GE", voc_cl$grupo_entonativo, "<br>",
          "t=", round(voc_cl$inicio, 2), "s<br>",
          "F0: ", round(voc_cl$f0_primera_hz, 1), " Hz",
          if ("f0_media_grupo_st" %in% colnames(voc_cl))
            paste0(" / ", round(voc_cl$f0_media_grupo_st, 1), " St") else "",
          "<br>", substr(voc_cl$palabras_grupo, 1, 60)
        )
      )

      fig <- fig %>% add_trace(
        data = voc_cl, x = ~inicio, y = ~y_val,
        type = "scatter", mode = "lines+markers",
        line   = list(color = paleta[i], width = 2),
        marker = list(color = paleta[i], size = 7),
        text = ~hover, hoverinfo = "text",
        name = cl_lab, showlegend = FALSE
      )

      # Tendencia solo sobre puntos reales (sin NAs)
      voc_real <- voc_cl[!is.na(voc_cl$y_val), ]
      if (nrow(voc_real) > 1) {
        fit <- lm(y_val ~ inicio, data = voc_real)
        voc_real$trend <- predict(fit)
        fig <- fig %>% add_trace(
          data = voc_real, x = ~inicio, y = ~trend,
          type = "scatter", mode = "lines",
          line = list(color = paleta[i], width = 1.5, dash = "dash"),
          hoverinfo = "skip", showlegend = FALSE
        )
      }
    }

    # Separadores verticales en el inicio de cada nueva cláusula
    cl_starts <- ips %>%
      filter(clausula_posicion == 1) %>%
      arrange(inicio) %>%
      slice(-1)   # quitar la primera (no hay frontera antes)
    shapes_list <- lapply(cl_starts$inicio, function(bx) {
      list(type = "line", x0 = bx, x1 = bx, y0 = 0, y1 = 1,
           xref = "x", yref = "paper",
           line = list(color = "gray50", width = 1, dash = "dot"))
    })

    fig %>% layout(
      title  = list(text = paste0("Trayectoria F0 por GE — ", n_cl, " cl\u00e1usulas detectadas"),
                    font = list(size = 14)),
      xaxis  = list(title = "Tiempo (s)"),
      yaxis  = list(title = y_label),
      shapes = shapes_list,
      hovermode = "closest"
    )
  })
  
  # Tabla resumen de cláusulas (Análisis)
  output$tabla_clausulas_resumen <- renderDT({
    req(datos$clausulas, nrow(datos$clausulas) > 0, input$clausula_filtro_archivo)
    
    cl <- datos$clausulas %>% filter(filename == input$clausula_filtro_archivo)
    
    if (!is.null(input$clausula_filtro_hablante) && input$clausula_filtro_hablante != "__todos__") {
      cl <- cl %>% filter(hablante == input$clausula_filtro_hablante)
    }
    
    # Backward compat: add missing columns for old saved data
    if (!"n_vocales" %in% colnames(cl)) cl$n_vocales <- NA_integer_
    if (!"f0_inicio_st" %in% colnames(cl)) cl$f0_inicio_st <- NA_real_
    if (!"f0_fin_st" %in% colnames(cl)) cl$f0_fin_st <- NA_real_
    if (!"dif_global_st" %in% colnames(cl)) cl$dif_global_st <- NA_real_
    if (!"slope_st" %in% colnames(cl)) cl$slope_st <- NA_real_
    
    cl_show <- cl %>% select(
      Cláusula = clausula_id, Archivo = filename, Hablante = hablante,
      GEs = n_ge, GFs = n_gf, Vocales = n_vocales, Duración = duracion,
      F0_inicio_Hz = f0_inicio_hz, F0_fin_Hz = f0_fin_hz,
      F0_inicio_St = f0_inicio_st, F0_fin_St = f0_fin_st,
      Dif_St = dif_global_st, Slope_St = slope_st,
      Tipo = tipo, Texto = palabras
    )
    
    datatable(cl_show, options = list(dom = 'tip', pageLength = 20, scrollX = TRUE), rownames = FALSE) %>%
      formatStyle("Tipo", color = styleEqual(
        c("ascendente", "descendente", "plana"), 
        c("#E74C3C", "#3498DB", "#7f8c8d")
      ))
  })

output$corolario_metricas_ui <- renderUI({
  ips <- clausula_ips_filtrados()
  cl_data <- datos$clausulas
  req(nrow(ips) > 0, !is.null(cl_data))
  
  fn_sel <- input$clausula_filtro_archivo
  cl_fn <- cl_data[cl_data$filename == fn_sel, ]
  if (!is.null(input$clausula_filtro_hablante) && input$clausula_filtro_hablante != "__todos__") {
    cl_fn <- cl_fn[cl_fn$hablante == input$clausula_filtro_hablante, ]
  }
  
  req(nrow(cl_fn) > 0)
  
  # Principio 1: Recursividad — hay cláusulas supraentonativas (siempre cumplido si hay >1 cláusula)
  n_cl <- nrow(cl_fn)
  p_recursividad <- if (n_cl > 1) 100 else 0
  
  # Principio 2: Jerarquía — cláusulas con >1 GE (subordinación tonal)
  cl_con_jerarquia <- sum(cl_fn$n_ge > 1, na.rm = TRUE)
  p_jerarquia <- round(cl_con_jerarquia / n_cl * 100, 1)
  
  # Principio 3: Declinación — cláusulas con contorno descendente
  if ("tipo" %in% colnames(cl_fn)) {
    n_desc <- sum(cl_fn$tipo == "descendente", na.rm = TRUE)
    n_asc  <- sum(cl_fn$tipo == "ascendente",  na.rm = TRUE)
    n_plan <- sum(cl_fn$tipo == "plana",        na.rm = TRUE)
    p_decl <- round(n_desc / n_cl * 100, 1)
    p_incl <- round(n_asc  / n_cl * 100, 1)
  } else {
    n_desc <- n_asc <- n_plan <- 0; p_decl <- p_incl <- NA
  }
  
  color_badge <- function(pct) {
    if (is.na(pct)) return("secondary")
    if (pct >= 70) "success" else if (pct >= 40) "warning" else "danger"
  }
  
  div(style = "background:#f8f9fa; border-left:4px solid #3498DB; padding:12px; border-radius:6px; margin-bottom:8px;",
    tags$b(icon("info-circle"), " Corolario de Hidalgo Navarro — cumplimiento"),
    br(), br(),
    fluidRow(
      column(4, div(style = "text-align:center;",
        tags$span(class = paste0("badge badge-", color_badge(p_recursividad)),
                  style = "font-size:1.2em; padding:6px 12px;",
                  paste0(p_recursividad, "%")),
        br(),
        tags$b("Recursividad"),
        br(),
        tags$small(paste0(n_cl, " cláusula(s) detectada(s)"))
      )),
      column(4, div(style = "text-align:center;",
        tags$span(class = paste0("badge badge-", color_badge(p_jerarquia)),
                  style = "font-size:1.2em; padding:6px 12px;",
                  paste0(p_jerarquia, "%")),
        br(),
        tags$b("Jerarquía"),
        br(),
        tags$small(paste0(cl_con_jerarquia, "/", n_cl, " cláusulas con >1 GE"))
      )),
      column(4, div(style = "text-align:center;",
        tags$span(class = paste0("badge badge-", color_badge(p_decl)),
                  style = "font-size:1.2em; padding:6px 12px;",
                  paste0(p_decl, "%")),
        br(),
        tags$b("Declinación"),
        br(),
        tags$small(paste0(n_desc, " desc. / ", n_asc, " asc. / ", n_plan, " plana"))
      ))
    )
  )
})

  
  # Tabla cláusulas datos (pestaña Datos)
  output$tabla_clausulas_datos <- renderDT({
    req(datos$clausulas, nrow(datos$clausulas) > 0)
    cl <- datos$clausulas
    nums <- sapply(cl, is.numeric)
    cl[nums] <- lapply(cl[nums], function(x) round(x, 3))
    datatable(cl, options = list(scrollX = TRUE, pageLength = 20), filter = "top")
  })
  
  output$descargar_clausulas <- downloadHandler(
    filename = function() paste0("clausulas_", Sys.Date(), ".csv"),
    content = function(file) {
      req(datos$clausulas)
      write.csv(datos$clausulas, file, row.names = FALSE)
    }
  )
  
  # ========================================
  # DETALLE CLÁUSULA — Selectores
  # ========================================
  
  observe({
    req(datos$calculado)
    # Usar clausulas si están disponibles, si no ips_resumen como fallback
    src <- if (!is.null(datos$clausulas) && nrow(datos$clausulas) > 0) datos$clausulas else datos$ips_resumen
    req(!is.null(src))
    fns <- sort(unique(src$filename))
    updateSelectInput(session, "det_cl_archivo", choices = fns, selected = fns[1])
  })
  
  observe({
    req(datos$calculado, input$det_cl_archivo)
    src <- if (!is.null(datos$clausulas) && nrow(datos$clausulas) > 0) datos$clausulas else datos$ips_resumen
    req(!is.null(src))
    habs <- sort(unique(src$hablante[src$filename == input$det_cl_archivo]))
    updateSelectInput(session, "det_cl_hablante", choices = c("Todos" = "__todos__", habs), 
                      selected = if (length(habs) == 1) habs[1] else "__todos__")
  })
  
  # Update clausula selectors based on file/hablante filter + lógica mismo hablante
 observe({
  req(datos$clausulas, nrow(datos$clausulas) > 0, input$det_cl_archivo)
  
  cl <- datos$clausulas %>% filter(filename == input$det_cl_archivo)
  
  if (!is.null(input$det_cl_hablante) && input$det_cl_hablante != "__todos__")
    cl <- cl %>% filter(hablante == input$det_cl_hablante)
  
  if (nrow(cl) == 0) {
    updateSelectInput(session, "det_cl_sel1", choices = c("Sin cl\u00e1usulas" = ""), selected = "")
    updateSelectInput(session, "det_cl_sel2", choices = c("Ninguna" = "__none__"), selected = "__none__")
    return()
  }
  
  cl <- cl %>% arrange(inicio, hablante, clausula_id)
  cl$clausula_global_id <- paste0(cl$filename, "|||", cl$hablante, "|||CL", cl$clausula_id)
  
  opts <- setNames(
    cl$clausula_global_id,
    paste0("CL", cl$clausula_id, " [", cl$hablante, "] (",
           cl$tipo, ", ", cl$n_ge, " GEs, ",
           round(cl$inicio, 2), "s) \u2014 ",
           substr(cl$palabras, 1, 40))
  )
  
  updateSelectInput(session, "det_cl_sel1", choices = opts, selected = opts[1])
  # Cl2: solo la inmediatamente siguiente (se actualiza en observer separado)
})

  # Observer: actualizar Cláusula 2 según Cláusula 1 seleccionada
  observe({
    req(datos$clausulas, input$det_cl_sel1, input$det_cl_sel1 != "")
    cl_all <- datos$clausulas
    if (!"clausula_global_id" %in% colnames(cl_all))
      cl_all$clausula_global_id <- paste0(cl_all$filename, "|||", cl_all$hablante, "|||CL", cl_all$clausula_id)
    cl_all <- cl_all %>% arrange(inicio, hablante, clausula_id)
    cl_all$clausula_global_id <- paste0(cl_all$filename, "|||", cl_all$hablante, "|||CL", cl_all$clausula_id)

    # Filtrar por archivo
    fn <- input$det_cl_archivo
    if (!is.null(fn)) cl_all <- cl_all %>% filter(filename == fn)

    idx_sel1 <- which(cl_all$clausula_global_id == input$det_cl_sel1)
    if (length(idx_sel1) == 0) {
      updateSelectInput(session, "det_cl_sel2", choices = c("Ninguna" = "__none__"), selected = "__none__")
      return()
    }

    mismo_hablante <- isTRUE(input$det_cl_mismo_hablante)
    hab_sel1 <- cl_all$hablante[idx_sel1[1]]

    # La cláusula inmediatamente siguiente por tiempo (independientemente del hablante)
    candidatos <- cl_all[(idx_sel1[1] + 1L):nrow(cl_all), , drop = FALSE]
    if (nrow(candidatos) == 0) {
      updateSelectInput(session, "det_cl_sel2", choices = c("Ninguna" = "__none__"), selected = "__none__")
      return()
    }

    if (mismo_hablante) {
      # La siguiente cláusula por tiempo debe ser del mismo hablante;
      # si es de otro hablante hay interrupción y no se ofrece ninguna opción
      siguiente <- candidatos[1, ]
      if (siguiente$hablante != hab_sel1) {
        updateSelectInput(session, "det_cl_sel2",
          choices = c("Cl\u00e1usula interrumpida por otro hablante" = "__none__"),
          selected = "__none__")
        return()
      }
      next_cl <- siguiente
    } else {
      next_cl <- candidatos[1, ]
    }
    opts2 <- setNames(
      next_cl$clausula_global_id,
      paste0("CL", next_cl$clausula_id, " [", next_cl$hablante, "] (",
             next_cl$tipo, ", ", next_cl$n_ge, " GEs, ",
             round(next_cl$inicio, 2), "s) \u2014 ",
             substr(next_cl$palabras, 1, 40))
    )
    updateSelectInput(session, "det_cl_sel2",
      choices = c("Ninguna" = "__none__", opts2),
      selected = "__none__")
  })
  
  # ========================================
  # DETALLE CLÁUSULA — Gráfico AMH-style
  # ========================================
  output$plot_detalle_clausula <- renderPlotly({
    req(datos$clausulas, datos$phones, input$det_cl_sel1, input$det_cl_sel1 != "")
    
    # Ensure clausula_global_id exists
    cl_all <- datos$clausulas
    cl_all$clausula_global_id <- paste0(cl_all$filename, "|||", cl_all$hablante, "|||CL", cl_all$clausula_id)

    
    # Resolve global IDs to clausula metadata
    gl_ids <- input$det_cl_sel1
    if (!is.null(input$det_cl_sel2) && input$det_cl_sel2 != "__none__")
      gl_ids <- c(gl_ids, input$det_cl_sel2)
    
    cl_meta <- cl_all[cl_all$clausula_global_id %in% gl_ids, ]
    req(nrow(cl_meta) > 0)
    
    # Build filter: match by filename + hablante + clausula_id
    cl_ids_local <- cl_meta$clausula_id
    cl_fns <- cl_meta$filename
    cl_spks <- cl_meta$hablante
    
    nivel <- if (!is.null(input$det_cl_nivel)) input$det_cl_nivel else "vocal"
    escala <- if (!is.null(input$det_cl_escala)) input$det_cl_escala else "hz"
    
    if (nivel == "vocal") {
      ph <- datos$phones
      req("clausula_id" %in% colnames(ph))
      # Filter by matching file+speaker+clausula_id combos
      ph <- ph %>% inner_join(cl_meta %>% select(filename, hablante, clausula_id), 
                               by = c("filename", "hablante", "clausula_id")) %>%
        arrange(filename, hablante, inicio)
      req(nrow(ph) > 0)
      
      y_col <- if (escala == "st") "f0_media_st" else "f0_media_hz"
      y_lab <- if (escala == "st") "F0 (St)" else "F0 (Hz)"
      ph$y_val <- ph[[y_col]]
      ph <- ph %>% filter(!is.na(y_val))
      # Build global label for each vocal's clausula
ph$cl_global <- paste0(ph$filename, "|||", ph$hablante, "|||CL", ph$clausula_id)
      ph$cl_label <- paste0("CL", ph$clausula_id, " [", ph$hablante, "]")
      ph$pos <- seq_len(nrow(ph))
      ph$label <- ifelse(!is.na(ph$palabra) & ph$palabra != "",
                         paste0(ph$etiqueta, " (", ph$palabra, ")"),
                         ph$etiqueta)
      ph$hover_text <- paste0(
        "<b>", ph$label, "</b><br>",
        ph$cl_label, " | GF", ph$grupo_fonico, " GE", ph$grupo_entonativo, "<br>",
        "F0: ", round(ph$f0_media_hz, 1), " Hz / ", round(ph$f0_media_st, 1), " St<br>",
        if ("int_media" %in% colnames(ph)) paste0("Int: ", round(ph$int_media, 1), " dB<br>") else "",
        "Dur: ", round(ph$duracion, 3), " s"
      )
      
      df_plot <- ph
      x_labels <- ph$label
      title_text <- "Detalle vocal por vocal"
      
    } else {
      req(!is.null(datos$words), !is.null(datos$phones))
      ph_cl <- datos$phones %>%
        inner_join(cl_meta %>% select(filename, hablante, clausula_id),
                   by = c("filename", "hablante", "clausula_id"))
      req(nrow(ph_cl) > 0)
      wd <- do.call(rbind, lapply(seq_len(nrow(cl_meta)), function(i) {
        cm <- cl_meta[i, ]
        ph_sub <- ph_cl %>% filter(filename == cm$filename, hablante == cm$hablante,
                                    clausula_id == cm$clausula_id)
        t_ini <- min(ph_sub$inicio, na.rm = TRUE) - 0.01
        t_fin <- max(ph_sub$fin,   na.rm = TRUE) + 0.01
        datos$words %>%
          filter(filename == cm$filename, hablante == cm$hablante,
                 inicio >= t_ini, fin <= t_fin) %>%
          mutate(clausula_id = cm$clausula_id)
      }))
      req(!is.null(wd) && nrow(wd) > 0)
      wd <- wd %>% arrange(filename, hablante, clausula_id, inicio)

      # Recuperar F0 desde phones para palabras sin F0 directo
      # Para cada palabra, calcular la media F0 de sus vocales (phones dentro de su rango temporal)
      ph_valid <- datos$phones %>%
        filter(!is.na(f0_media_hz), f0_media_hz > 0) %>%
        select(filename, hablante, inicio_ph = inicio, fin_ph = fin,
               f0_media_hz_ph = f0_media_hz, f0_media_st_ph = f0_media_st)

      for (wi in seq_len(nrow(wd))) {
        if (is.na(wd$f0_media_hz[wi]) || wd$f0_media_hz[wi] == 0) {
          ph_match <- ph_valid %>%
            filter(filename == wd$filename[wi],
                   hablante == wd$hablante[wi],
                   inicio_ph >= wd$inicio[wi] - 0.01,
                   fin_ph <= wd$fin[wi] + 0.01)
          if (nrow(ph_match) > 0) {
            wd$f0_media_hz[wi] <- mean(ph_match$f0_media_hz_ph, na.rm = TRUE)
            if ("f0_media_st" %in% colnames(wd))
              wd$f0_media_st[wi] <- mean(ph_match$f0_media_st_ph, na.rm = TRUE)
          }
        }
      }

      # Filtrar palabras vacías o sin etiqueta
      wd <- wd %>% filter(!is.na(etiqueta), trimws(etiqueta) != "")

      y_col <- if (escala == "st") "f0_media_st" else "f0_media_hz"
      y_lab <- if (escala == "st") "F0 (St)" else "F0 (Hz)"
      wd$y_val <- wd[[y_col]]
      wd <- wd %>% filter(!is.na(y_val))
      req(nrow(wd) > 0)

      # Ordenar por clausula y tiempo
      wd <- wd %>% arrange(filename, hablante, clausula_id, inicio)

wd$cl_global <- paste0(wd$filename, "|||", wd$hablante, "|||CL", wd$clausula_id)
      wd$cl_label <- paste0("CL", wd$clausula_id, " [", wd$hablante, "]")
      wd$pos <- seq_len(nrow(wd))
      wd$label <- wd$etiqueta
      wd$hover_text <- paste0(
        "<b>", wd$etiqueta, "</b><br>",
        wd$cl_label, " | GF", wd$grupo_fonico, " GE", wd$grupo_entonativo, "<br>",
        "F0: ", round(wd$f0_media_hz, 1), " Hz / ",
        if ("f0_media_st" %in% colnames(wd)) paste0(round(wd$f0_media_st, 1), " St") else "—", "<br>",
        if ("int_media" %in% colnames(wd)) paste0("Int: ", round(wd$int_media, 1), " dB<br>") else "",
        "Dur: ", round(wd$duracion, 3), " s"
      )
      
      df_plot <- wd
      x_labels <- wd$label
      title_text <- "Detalle palabra por palabra"
    }
    
    req(nrow(df_plot) > 0)
    
    # Colores por cláusula (using global id for uniqueness)
    cls_u <- unique(df_plot$cl_global)
    colores <- c("#E74C3C", "#3498DB", "#2ECC71", "#F39C12")[seq_along(cls_u)]
    names(colores) <- cls_u
    # Labels for legend
    cl_labels <- unique(df_plot[, c("cl_global", "cl_label")])
    
    fig <- plot_ly()
    
    for (i in seq_along(cls_u)) {
      gl <- cls_u[i]
      sub_df <- df_plot[df_plot$cl_global == gl, ]
      leg_label <- cl_labels$cl_label[cl_labels$cl_global == gl][1]
      
      fig <- fig %>% add_trace(
        data = sub_df, x = ~pos, y = ~y_val,
        type = "scatter", mode = "lines+markers+text",
        line = list(color = colores[gl], width = 2),
        marker = list(color = colores[gl], size = 9),
        text = ~label, textposition = "top center", textfont = list(size = 11),
        hovertext = ~hover_text, hoverinfo = "text",
        name = leg_label
      )
      
      # Trend line
      if (isTRUE(input$det_cl_tendencia) && nrow(sub_df) > 1) {
        fit <- lm(y_val ~ pos, data = sub_df)
        sub_df$trend <- predict(fit)
        
        fig <- fig %>% add_trace(
          data = sub_df, x = ~pos, y = ~trend,
          type = "scatter", mode = "lines",
          line = list(color = colores[gl], width = 1.5, dash = "dash"),
          hoverinfo = "skip", showlegend = FALSE
        )
      }
    }
    
    # Boundary between clausulas
    if (length(cls_u) == 2) {
      boundary_pos <- min(df_plot$pos[df_plot$cl_global == cls_u[2]]) - 0.5
      shapes <- list(list(type = "line", x0 = boundary_pos, x1 = boundary_pos,
                          y0 = 0, y1 = 1, xref = "x", yref = "paper",
                          line = list(color = "gray40", width = 2, dash = "dot")))
    } else {
      shapes <- list()
    }
    
    # Subtitle with clausula info
    sub_parts <- sapply(seq_along(gl_ids), function(i) {
      cm <- cl_meta[cl_meta$clausula_global_id == gl_ids[i], ]
      if (nrow(cm) > 0) {
        dif_txt <- if ("dif_global_st" %in% colnames(cm) && !is.na(cm$dif_global_st[1])) paste0("dif=", round(cm$dif_global_st[1], 1), " St") else ""
        sl_txt <- if ("slope_st" %in% colnames(cm) && !is.na(cm$slope_st[1])) paste0("slope=", round(cm$slope_st[1], 3), " St/vocal") else ""
        info_parts <- c(dif_txt, sl_txt)
        info_parts <- info_parts[info_parts != ""]
        paste0("CL", cm$clausula_id[1], " [", cm$hablante[1], "]: ", cm$tipo[1],
               if (length(info_parts) > 0) paste0(" (", paste(info_parts, collapse = ", "), ")") else "")
      } else ""
    })
    subtitle <- paste(sub_parts, collapse = "  |  ")
    
    fig %>% layout(
      title = list(text = paste0(title_text, "<br><sub>", subtitle, "</sub>"), font = list(size = 14)),
      xaxis = list(title = if (nivel == "vocal") "Vocal (secuencial)" else "Palabra (secuencial)",
                   tickvals = df_plot$pos, ticktext = x_labels,
                   tickangle = -45, tickfont = list(size = 9)),
      yaxis = list(title = y_lab),
      shapes = shapes,
      hovermode = "closest",
      legend = list(orientation = "h", y = -0.2)
    )
  })
  
  # Tabla detalle cláusula
  output$tabla_detalle_clausula <- renderDT({
    req(datos$clausulas, input$det_cl_sel1, input$det_cl_sel1 != "")
    
    cl_all <- datos$clausulas
    
cl_all$clausula_global_id <- paste0(cl_all$filename, "|||", cl_all$hablante, "|||CL", cl_all$clausula_id)
    
    gl_ids <- input$det_cl_sel1
    if (!is.null(input$det_cl_sel2) && input$det_cl_sel2 != "__none__")
      gl_ids <- c(gl_ids, input$det_cl_sel2)
    
    cl_meta <- cl_all[cl_all$clausula_global_id %in% gl_ids, ]
    req(nrow(cl_meta) > 0)
    
    nivel <- if (!is.null(input$det_cl_nivel)) input$det_cl_nivel else "vocal"
    
    if (nivel == "vocal" && !is.null(datos$phones) && "clausula_id" %in% colnames(datos$phones)) {
      ph <- datos$phones %>% 
        inner_join(cl_meta %>% select(filename, hablante, clausula_id), 
                   by = c("filename", "hablante", "clausula_id")) %>%
        arrange(inicio)
      cols <- intersect(c("clausula_id","etiqueta","palabra","f0_media_hz","f0_media_st",
                          "int_media","duracion","grupo_fonico","grupo_entonativo",
                          "seccion_ip","es_pico_grupo","hablante","filename"), colnames(ph))
      df_show <- ph[, cols]
    } else if (!is.null(datos$words) && !is.null(datos$phones)) {
      ph_cl <- datos$phones %>%
        inner_join(cl_meta %>% select(filename, hablante, clausula_id),
                   by = c("filename", "hablante", "clausula_id"))
      req(nrow(ph_cl) > 0)
      wd <- do.call(rbind, lapply(seq_len(nrow(cl_meta)), function(i) {
        cm <- cl_meta[i, ]
        ph_sub <- ph_cl %>% filter(filename == cm$filename, hablante == cm$hablante,
                                    clausula_id == cm$clausula_id)
        t_ini <- min(ph_sub$inicio, na.rm = TRUE) - 0.01
        t_fin <- max(ph_sub$fin,   na.rm = TRUE) + 0.01
        datos$words %>%
          filter(filename == cm$filename, hablante == cm$hablante,
                 inicio >= t_ini, fin <= t_fin,
                 !is.na(etiqueta), trimws(etiqueta) != "") %>%
          mutate(clausula_id = cm$clausula_id)
      }))
      req(!is.null(wd) && nrow(wd) > 0)
      wd <- wd %>% arrange(clausula_id, inicio)
      cols <- intersect(c("clausula_id","etiqueta","inicio","fin","f0_media_hz","f0_media_st",
                          "int_media","duracion","grupo_fonico","grupo_entonativo",
                          "estructura_palabra","es_atona","hablante","filename"), colnames(wd))
      df_show <- wd[, cols]
    } else {
      return(NULL)
    }
    
    nums <- sapply(df_show, is.numeric)
    df_show[nums] <- lapply(df_show[nums], function(x) round(x, 2))
    datatable(df_show, options = list(scrollX = TRUE, pageLength = 20), filter = "top")
  })
  
