  sent_audios_disponibles <- reactive({
    if (!datos$calculado || is.null(datos$ips_resumen)) return(FALSE)
    fns <- unique(datos$ips_resumen$filename)
    audios_en_storage <- list.files(lasp_audios)
    audios_en_mem <- names(datos_audio$wavs)
    todas_cubiertas <- all(sapply(fns, function(fn) {
      any(grepl(fn, audios_en_storage, fixed = TRUE)) || fn %in% audios_en_mem
    }))
    todas_cubiertas
  })
  
