  output$estado <- renderText({
    if (datos$calculado) "✔ Análisis completo"
    else if (!is.null(datos$texto)) paste("Archivos cargados. Pulsa Calcular.")
    else "Esperando archivos..."
  })
  
  # Timestamp del último guardado (reactiveVal global del servidor)
  ts_guardado <- reactiveVal(NULL)

  output$estado_header <- renderText({
    if (datos$calculado) {
      n_ip <- if (!is.null(datos$ips_resumen)) nrow(datos$ips_resumen) else 0
      ts   <- ts_guardado()
      saved_txt <- if (!is.null(ts)) {
        mins <- as.numeric(difftime(Sys.time(), ts, units = "mins"))
        if (mins < 1)       " \u2022 guardado"
        else if (mins < 60) paste0(" \u2022 hace ", round(mins), " min")
        else                paste0(" \u2022 hace ", round(mins / 60, 1), " h")
      } else ""
      paste0(n_ip, " GEs", saved_txt)
