          n_words <- nrow(datos$words[datos$words$filename == fn, ])
        }
        n_phones <- 0
        if (!is.null(datos$phones) && "filename" %in% colnames(datos$phones)) {
          n_phones <- nrow(datos$phones[datos$phones$filename == fn, ])
        }
        n_gfs <- 0
        if (!is.null(datos$gfs_resumen) && "filename" %in% colnames(datos$gfs_resumen)) {
          n_gfs <- nrow(datos$gfs_resumen[datos$gfs_resumen$filename == fn, ])
