})
  
  # ---- Función compartida: construir actos_resumen desde ips_resumen + etiquetado ----
  construir_actos_resumen <- function() {
    ips <- datos$ips_resumen
    if (is.null(ips) || nrow(ips) == 0) return(NULL)
    anot <- etiq$anotaciones
    
    # Default: each GE is its own act
    if (is.null(anot) || nrow(anot) != nrow(ips)) {
      ips$acto_id <- seq_len(nrow(ips))
      ips$emocion_manual <- "neutro"
    } else {
      ips$acto_id <- anot$acto_id
      ips$emocion_manual <- anot$emocion_manual
    }
    
    actos_list <- split(ips, ips$acto_id)
    actos_df <- do.call(rbind, lapply(actos_list, function(act) {
      dur <- if (all(c("inicio", "fin") %in% colnames(act))) 
        max(act$fin, na.rm = TRUE) - min(act$inicio, na.rm = TRUE) 
      else if ("duracion" %in% colnames(act)) sum(act$duracion, na.rm = TRUE) else NA_real_
      nv <- if ("num_vocales" %in% colnames(act)) sum(act$num_vocales, na.rm = TRUE) else 0
      
      data.frame(
        acto_id = act$acto_id[1],
        filename = act$filename[1],
        hablante = act$hablante[1],
        genero = if ("genero" %in% colnames(act)) act$genero[1] else NA_character_,
        n_grupos_entonativos = nrow(act),
        n_grupos_fonicos = if ("grupo_fonico" %in% colnames(act)) length(unique(act$grupo_fonico)) else nrow(act),
        n_palabras = if ("num_palabras" %in% colnames(act)) sum(act$num_palabras, na.rm = TRUE) else NA_integer_,
        num_vocales = nv,
        duracion = dur,
        velocidad_habla = if (!is.na(dur) && dur > 0) nv / dur else NA_real_,
        f0_media_grupo_st = if ("f0_media_grupo_st" %in% colnames(act)) mean(act$f0_media_grupo_st, na.rm = TRUE) else NA_real_,
        rango_f0_grupo_st = if ("rango_f0_grupo_st" %in% colnames(act)) {
          if (all(c("f0_pico_st", "f0_inicio_st", "f0_fin_st") %in% colnames(act)))
            max(act$f0_pico_st, na.rm = TRUE) - min(c(act$f0_inicio_st, act$f0_fin_st), na.rm = TRUE)
          else max(act$rango_f0_grupo_st, na.rm = TRUE)
        } else NA_real_,
        intensidad_media_grupo = if ("intensidad_media_grupo" %in% colnames(act)) mean(act$intensidad_media_grupo, na.rm = TRUE)
          else if ("int_media" %in% colnames(act)) mean(act$int_media, na.rm = TRUE) else NA_real_,
        inflexion_final_pct = if ("inflexion_final_pct" %in% colnames(act)) act$inflexion_final_pct[nrow(act)] else NA_real_,
        transicion_media = if ("transicion_media" %in% colnames(act)) mean(act$transicion_media, na.rm = TRUE) else NA_real_,
        texto = if ("palabras_grupo" %in% colnames(act)) paste(act$palabras_grupo, collapse = " ") else "",
        emocion_manual = act$emocion_manual[1],
        sentimiento = if ("sentimiento" %in% colnames(act)) act$sentimiento[1] else NA_character_,
        emocion_texto = if ("emocion_texto" %in% colnames(act)) act$emocion_texto[1] else NA_character_,
        emocion_audio = if ("emocion_audio" %in% colnames(act)) act$emocion_audio[1] else NA_character_,
        amh_patron = if ("amh_patron" %in% colnames(act)) paste(unique(na.omit(act$amh_patron)), collapse = "+") else NA_character_,
        stringsAsFactors = FALSE
      )
    }))
    rownames(actos_df) <- NULL
    actos_df
  }
  
  # Recomputar actos
  observeEvent(input$actos_recomputar, {
    req(datos$calculado, datos$ips_resumen)
    datos$actos_resumen <- construir_actos_resumen()
    showNotification(paste0("Actos recomputados: ", nrow(datos$actos_resumen), " actos"), type = "message")
    auto_guardar("Actos recomputados")

  })
  
  # Auto-compute actos when data is available
  observe({
    req(datos$calculado, datos$ips_resumen)
    if (is.null(datos$actos_resumen)) {
      datos$actos_resumen <- construir_actos_resumen()
    }
  })
  
  output$tabla_actos_datos <- renderDT({
    req(datos$actos_resumen)
    df_show <- datos$actos_resumen
    nums <- sapply(df_show, is.numeric)
    df_show[nums] <- lapply(df_show[nums], function(x) round(x, 2))
    datatable(df_show, options = list(scrollX = TRUE, pageLength = 15), filter = "top")
  })
  
  output$descargar_actos <- downloadHandler(
    filename = function() paste0("actos_resumen_", Sys.Date(), ".csv"),
    content = function(file) {
      req(datos$actos_resumen)
      write.csv(datos$actos_resumen, file, row.names = FALSE)
    }
  )
  
  output$preview_texto <- renderDT({
    req(datos$texto)
    datatable(head(datos$texto, 100), options = list(scrollX = TRUE))
  })
  
  output$info_tiers <- renderPrint({
    req(datos$texto)
    tiers <- unique(datos$texto$tier)
    cat("Tiers detectados:\n")
    for (t in tiers) cat(" -", t, "\n")
  })
  
  # Distribuciones
  # ========================================
  # GRÁFICOS DE SENTIMIENTOS Y EMOCIONES
  # ========================================
  
  colores_sentimiento <- c("POS" = "#4CAF50", "NEG" = "#F44336", "NEU" = "#9E9E9E", "ERROR" = "#000000")
  
  colores_ekman <- c(
    "joy" = "#FFD700", "anger" = "#FF4444", "sadness" = "#4488FF",
    "fear" = "#9B59B6", "disgust" = "#2ECC71", "surprise" = "#FF8C00",
    "others" = "#95A5A6",
    "happy" = "#FFD700", "angry" = "#FF4444", "sad" = "#4488FF",
    "fearful" = "#9B59B6", "disgusted" = "#2ECC71", "surprised" = "#FF8C00",
    "neutral" = "#95A5A6", "other" = "#CCCCCC", "unknown" = "#666666",
    "no_wav" = "#EEEEEE", "too_short" = "#DDDDDD", "ERROR" = "#000000"
  )
  
  output$plot_sentimientos <- renderPlot({
    df <- sent_datos_filtrados()
    req(nrow(df) > 0, any(df$sentimiento != "", na.rm = TRUE))
    
    vals <- df$sentimiento[df$sentimiento != ""]
    excluir <- isTRUE(input$sent_excluir_neutro)
    if (excluir) vals <- vals[!tolower(vals) %in% c("neu", "neutral", "neutro")]
    req(length(vals) > 0)
    
    freq <- as.data.frame(table(vals))
    colnames(freq) <- c("Sentimiento", "Frecuencia")
    freq$Porcentaje <- round(freq$Frecuencia / sum(freq$Frecuencia) * 100, 1)
    freq$Color <- colores_sentimiento[as.character(freq$Sentimiento)]
    freq$Color[is.na(freq$Color)] <- "#999999"
    
    modo <- if (!is.null(input$sent_modo_grafico)) input$sent_modo_grafico else "pct"
    y_var <- if (modo == "pct") "Porcentaje" else "Frecuencia"
    y_lab <- if (modo == "pct") "%" else "N\u00ba GEs"
    
    ggplot(freq, aes(x = reorder(Sentimiento, -get(y_var)), y = get(y_var), fill = Sentimiento)) +
      geom_col(show.legend = FALSE) +
      scale_fill_manual(values = setNames(freq$Color, freq$Sentimiento)) +
      labs(x = "Sentimiento", y = y_lab) +
      theme_minimal(base_size = 14) +
      theme(axis.text.x = element_text(size = 14, face = "bold"))
  })
  
  output$plot_emociones_texto <- renderPlot({
    df <- sent_datos_filtrados()
    req(nrow(df) > 0, any(df$emocion_texto != "", na.rm = TRUE))
    
    vals <- df$emocion_texto[df$emocion_texto != ""]
    excluir <- isTRUE(input$sent_excluir_neutro)
    if (excluir) vals <- vals[!tolower(vals) %in% c("others", "neutro", "neutral")]
    req(length(vals) > 0)
    
    freq <- as.data.frame(table(vals))
    colnames(freq) <- c("Emocion", "Frecuencia")
    freq$Porcentaje <- round(freq$Frecuencia / sum(freq$Frecuencia) * 100, 1)
    freq$Color <- colores_ekman[as.character(freq$Emocion)]
    freq$Color[is.na(freq$Color)] <- "#999999"
    
    modo <- if (!is.null(input$sent_modo_grafico)) input$sent_modo_grafico else "pct"
    y_var <- if (modo == "pct") "Porcentaje" else "Frecuencia"
    y_lab <- if (modo == "pct") "%" else "N\u00ba GEs"
    
    ggplot(freq, aes(x = reorder(Emocion, -get(y_var)), y = get(y_var), fill = Emocion)) +
      geom_col(show.legend = FALSE) +
      scale_fill_manual(values = setNames(freq$Color, freq$Emocion)) +
      labs(x = "Emoci\u00f3n", y = y_lab) +
      theme_minimal(base_size = 14) +
      theme(axis.text.x = element_text(angle = 45, hjust = 1, size = 12))
  })
  
  output$plot_emociones_audio <- renderPlot({
    df <- sent_datos_filtrados()
    req(nrow(df) > 0)
    emo_audio <- df$emocion_audio[!df$emocion_audio %in% c("", "no_wav", "too_short", "ERROR")]
    
    excluir <- isTRUE(input$sent_excluir_neutro)
    if (excluir) emo_audio <- emo_audio[!tolower(emo_audio) %in% c("neutral", "neutro")]
    
    if (length(emo_audio) == 0) {
      plot.new()
      text(0.5, 0.5, "No hay emociones ac\u00fasticas analizadas", cex = 1.5)
      return()
    }
    
    freq <- as.data.frame(table(emo_audio))
    colnames(freq) <- c("Emocion", "Frecuencia")
    freq$Porcentaje <- round(freq$Frecuencia / sum(freq$Frecuencia) * 100, 1)
    freq$Color <- colores_ekman[as.character(freq$Emocion)]
    freq$Color[is.na(freq$Color)] <- "#999999"
    
    modo <- if (!is.null(input$sent_modo_grafico)) input$sent_modo_grafico else "pct"
    y_var <- if (modo == "pct") "Porcentaje" else "Frecuencia"
    y_lab <- if (modo == "pct") "%" else "N\u00ba GEs"
    
    ggplot(freq, aes(x = reorder(Emocion, -get(y_var)), y = get(y_var), fill = Emocion)) +
      geom_col(show.legend = FALSE) +
      scale_fill_manual(values = setNames(freq$Color, freq$Emocion)) +
      labs(x = "Emoci\u00f3n ac\u00fastica", y = y_lab) +
      theme_minimal(base_size = 14) +
      theme(axis.text.x = element_text(angle = 45, hjust = 1, size = 12))
  })
  
  output$plot_sent_vs_emo <- renderPlot({
    df <- sent_datos_filtrados()
    req(nrow(df) > 0)
    
    excluir <- isTRUE(input$sent_excluir_neutro)
    df_valid <- df[df$sentimiento != "" & df$emocion_texto != "", ]
    if (excluir) {
      df_valid <- df_valid[!tolower(df_valid$sentimiento) %in% c("neu", "neutral", "neutro"), ]
      df_valid <- df_valid[!tolower(df_valid$emocion_texto) %in% c("others", "neutro", "neutral"), ]
    }
    
    if (nrow(df_valid) == 0) {
      plot.new()
      text(0.5, 0.5, "No hay datos de sentimiento+emoci\u00f3n", cex = 1.5)
      return()
    }
    
    freq <- as.data.frame(table(df_valid$sentimiento, df_valid$emocion_texto))
    colnames(freq) <- c("Sentimiento", "Emocion", "Frecuencia")
    freq <- freq[freq$Frecuencia > 0, ]
    
    ggplot(freq, aes(x = Sentimiento, y = Emocion, size = Frecuencia, color = Sentimiento)) +
      geom_point(alpha = 0.7) +
      scale_size_continuous(range = c(3, 15)) +
      scale_color_manual(values = colores_sentimiento) +
      labs(title = "Relaci\u00f3n Sentimiento - Emoci\u00f3n", x = "Sentimiento", y = "Emoci\u00f3n") +
      theme_minimal(base_size = 14) +
      theme(axis.text.x = element_text(size = 12, face = "bold"),
            axis.text.y = element_text(size = 12))
  })

