# ── 3. Helper: construye el ggplot base según variable ────────────────────────
# Helper: añade columna run_id para segmentar líneas por hablante y gaps temporales
.add_run_id <- function(df, col_time = "centro", col_group = "hablante", gap_s = 2.0) {
  if (nrow(df) == 0) return(df)
  df <- df[order(df[[col_time]]), ]
  grp <- as.character(df[[col_group]])
  t   <- df[[col_time]]
  run <- integer(nrow(df))
  id  <- 1L
  for (i in seq_len(nrow(df))) {
    if (i == 1L) { run[i] <- id; next }
    if (grp[i] != grp[i-1L] || (!is.na(t[i]) && !is.na(t[i-1L]) && (t[i] - t[i-1L]) > gap_s)) id <- id + 1L
    run[i] <- id
  }
  df$.run_id <- run
  df
}

build_plot_base <- function(phones, tipo) {
  # Añadir run_id para segmentar líneas por hablante y gaps
  phones <- .add_run_id(phones)
  p <- switch(tipo,
    pitch_hz = ggplot(phones[!is.na(phones$f0_media_hz), ],
                  aes(x = centro, y = f0_media_hz, color = hablante, group = .run_id)) +
               geom_line(alpha = 0.6) + geom_point(size = 1) +
               labs(title = "Evolución temporal del Pitch (F0 Hz)",
                    x = "Tiempo (s)", y = "F0 media (Hz)"),

    pitch_st = ggplot(phones[!is.na(phones$f0_media_st), ],
                  aes(x = centro, y = f0_media_st, color = hablante, group = .run_id)) +
               geom_line(alpha = 0.6) + geom_point(size = 1) +
               labs(title = "Evolución temporal del Pitch (F0 St)",
                    x = "Tiempo (s)", y = "F0 media (St)"),

    intensidad = {
      ph <- .add_run_id(phones[!is.na(phones$int_media) & phones$int_media > 0, ])
      ggplot(ph, aes(x = centro, y = int_media, color = hablante, group = .run_id)) +
        geom_line(alpha = 0.6) + geom_point(size = 1) +
        labs(title = "Evolución temporal de Intensidad",
             x = "Tiempo (s)", y = "Intensidad media (dB)",
             caption = "Nota: valores \u2264 0 dB excluidos")
    },

    inc_f0_pct = ggplot(phones[!is.na(phones$ant_inc_f0_1_pct), ],
                    aes(x = centro, y = ant_inc_f0_1_pct, color = hablante, group = .run_id)) +
                 geom_col(alpha = 0.6, width = 0.01) +
                 geom_hline(yintercept = 0, linetype = "dashed") +
                 labs(title = "Incremento % F0 respecto a vocal anterior",
                      x = "Tiempo (s)", y = "Incremento F0 (%)"),

    inc_f0_st = ggplot(phones[!is.na(phones$ant_inc_f0_1_st), ],
                   aes(x = centro, y = ant_inc_f0_1_st, color = hablante, group = .run_id)) +
                geom_col(alpha = 0.6, width = 0.01) +
                geom_hline(yintercept = 0, linetype = "dashed") +
                labs(title = "Incremento St F0 respecto a vocal anterior",
                     x = "Tiempo (s)", y = "Incremento F0 (St)"),

    inc_int_db = ggplot(phones[!is.na(phones$ant_inc_int_1_db), ],
                    aes(x = centro, y = ant_inc_int_1_db, color = hablante, group = .run_id)) +
                 geom_col(alpha = 0.6, width = 0.01) +
                 geom_hline(yintercept = 0, linetype = "dashed") +
                 labs(title = "Incremento Intensidad respecto a vocal anterior",
                      x = "Tiempo (s)", y = "Incremento Int (dB)"),

    transiciones = {
      ph <- .add_run_id(phones[!is.na(phones$tiempo_transicion_anterior), ])
      ggplot(ph, aes(x = centro, y = tiempo_transicion_anterior, color = hablante, group = .run_id)) +
        geom_line(alpha = 0.6) + geom_point(size = 1) +
        labs(title = "Transiciones entre centros vocálicos",
             x = "Tiempo (s)", y = "Tiempo transición (s)")
    },

    duracion = ggplot(.add_run_id(phones),
                  aes(x = centro, y = duracion, color = hablante, group = .run_id)) +
               geom_line(alpha = 0.6) + geom_point(size = 1) +
               labs(title = "Duración vocálica",
                    x = "Tiempo (s)", y = "Duración (s)")
  )
  p + theme_minimal()
}

# Helper seguro para ggplotly
safe_ggplotly <- function(p) {
  tryCatch(ggplotly(p),
    error = function(e)
      tryCatch(ggplotly(p, dynamicTicks = FALSE),
        error = function(e2)
          plotly::plot_ly() %>% plotly::layout(title = paste("Error:", e$message))
      )
  )
}

