output$plot_general_variable <- renderPlotly({
  req(datos$calculado, datos$phones, input$grafico_archivos_sel)

  phones    <- datos$phones
  tipo      <- input$grafico_general_tipo
  archivos  <- input$grafico_archivos_sel
  superponer <- superponer_activo()

  # Filtrar por archivos seleccionados
  phones_sel <- phones[phones$filename %in% archivos, ]

  if (length(archivos) == 1 || !superponer) {
    # ── Modo faceta: un panel por archivo ──────────────────────────────────
    p <- build_plot_base(phones_sel, tipo)

    if (length(archivos) > 1) {
      # Añadir etiqueta de archivo al color/aes no es posible directamente,
      # usamos faceta pero diferenciando con linetype o simplemente faceta libre
      p <- p + facet_wrap(~filename, scales = "free_x", ncol = 1)
    }
    # Con un solo archivo no hay faceta → más rápido
    safe_ggplotly(p)

  } else {
    # ── Modo superposición: todos los archivos en el mismo panel ───────────
    # Añadir filename al color para distinguir archivos
    phones_sel$serie <- paste(phones_sel$filename, phones_sel$hablante, sep = " · ")

    p <- switch(tipo,
      pitch_hz = ggplot(phones_sel[!is.na(phones_sel$f0_media_hz), ],
                    aes(x = centro, y = f0_media_hz, color = serie)) +
                 geom_line(alpha = 0.6) + geom_point(size = 1) +
                 labs(title = "Comparación: Pitch (F0 Hz)",
                      x = "Tiempo (s)", y = "F0 media (Hz)"),

      pitch_st = ggplot(phones_sel[!is.na(phones_sel$f0_media_st), ],
                    aes(x = centro, y = f0_media_st, color = serie)) +
                 geom_line(alpha = 0.6) + geom_point(size = 1) +
                 labs(title = "Comparación: Pitch (F0 St)",
                      x = "Tiempo (s)", y = "F0 media (St)"),

      intensidad = {
        ph <- phones_sel[!is.na(phones_sel$int_media) & phones_sel$int_media > 0, ]
        ggplot(ph, aes(x = centro, y = int_media, color = serie)) +
          geom_line(alpha = 0.6) + geom_point(size = 1) +
          labs(title = "Comparación: Intensidad (dB)",
               x = "Tiempo (s)", y = "Intensidad media (dB)")
      },

      inc_f0_pct = ggplot(phones_sel[!is.na(phones_sel$ant_inc_f0_1_pct), ],
                      aes(x = centro, y = ant_inc_f0_1_pct, color = serie)) +
                   geom_col(alpha = 0.5, width = 0.01, position = "identity") +
                   geom_hline(yintercept = 0, linetype = "dashed") +
                   labs(title = "Comparación: Incremento % F0",
                        x = "Tiempo (s)", y = "Incremento F0 (%)"),

      inc_f0_st = ggplot(phones_sel[!is.na(phones_sel$ant_inc_f0_1_st), ],
                     aes(x = centro, y = ant_inc_f0_1_st, color = serie)) +
                  geom_col(alpha = 0.5, width = 0.01, position = "identity") +
                  geom_hline(yintercept = 0, linetype = "dashed") +
                  labs(title = "Comparación: Incremento St F0",
                       x = "Tiempo (s)", y = "Incremento F0 (St)"),

      inc_int_db = ggplot(phones_sel[!is.na(phones_sel$ant_inc_int_1_db), ],
                      aes(x = centro, y = ant_inc_int_1_db, color = serie)) +
                   geom_col(alpha = 0.5, width = 0.01, position = "identity") +
                   geom_hline(yintercept = 0, linetype = "dashed") +
                   labs(title = "Comparación: Incremento Intensidad",
                        x = "Tiempo (s)", y = "Incremento Int (dB)"),

      transiciones = ggplot(phones_sel[!is.na(phones_sel$tiempo_transicion_anterior), ],
                        aes(x = centro, y = tiempo_transicion_anterior, color = serie)) +
                     geom_line(alpha = 0.6) + geom_point(size = 1) +
                     labs(title = "Comparación: Transiciones vocálicas",
                          x = "Tiempo (s)", y = "Tiempo transición (s)"),

      duracion = ggplot(phones_sel,
                    aes(x = centro, y = duracion, color = serie)) +
                 geom_line(alpha = 0.6) + geom_point(size = 1) +
                 labs(title = "Comparación: Duración vocálica",
                      x = "Tiempo (s)", y = "Duración (s)")
    )

    p <- p + theme_minimal()
    safe_ggplotly(p)
  }
})
  
