    selectInput("sel_filename_cm", "Archivo:", choices = archivos, selected = archivos[1])
  })

  # Hablantes filtrados al archivo seleccionado
  output$selector_hablante_cm <- renderUI({
    req(datos$calculado, datos$ips_resumen, input$sel_filename_cm)
    ips_arch <- datos$ips_resumen[datos$ips_resumen$filename == input$sel_filename_cm, ]
    hablantes <- sort(unique(ips_arch$hablante))
    selectInput("sel_hablante_cm", "Hablante:", choices = hablantes, selected = hablantes[1])
  })

  # ips filtrados por filename + hablante (+ patrón AMH/ToBI)
  # Actualizar choices de filtros AMH fonetico/fonologico según datos
  observe({
    req(datos$calculado, datos$ips_resumen)
    ips_all <- datos$ips_resumen
    if ("amh_patron" %in% colnames(ips_all)) {
      vals <- sort(unique(ips_all$amh_patron[!is.na(ips_all$amh_patron)]))
      updateSelectInput(session, "filtro_ge_patron_amh_fonetico",
        choices = c("Cualquiera" = "todos", setNames(vals, vals)))
      updateSelectInput(session, "filtro_ge_patron_amh_fonologico",
        choices = c("Cualquiera" = "todos", setNames(vals, vals)))
    }
  })

  # Reactivo de filtros de GE extra (se activa solo al pulsar "Aplicar")
  filtros_ge_extra <- reactiveValues(
    min_palabras = 0, max_palabras = 0,
    acento_final = "todos",
    patron_amh_fonetico = "todos",
    patron_amh_fonologico = "todos"
  )
  observeEvent(input$filtro_ge_aplicar, {
    filtros_ge_extra$min_palabras          <- input$filtro_ge_min_palabras
    filtros_ge_extra$max_palabras          <- input$filtro_ge_max_palabras
    filtros_ge_extra$acento_final          <- input$filtro_ge_acento_final
    filtros_ge_extra$patron_amh_fonetico   <- input$filtro_ge_patron_amh_fonetico
    filtros_ge_extra$patron_amh_fonologico <- input$filtro_ge_patron_amh_fonologico
  })

  ips_filtrados <- reactive({
    req(datos$calculado, datos$ips_resumen, input$sel_filename_cm, input$sel_hablante_cm)
    ips <- datos$ips_resumen[
      datos$ips_resumen$filename == input$sel_filename_cm &
      datos$ips_resumen$hablante == input$sel_hablante_cm, ]

    filtro <- input$filtro_patron
    if (!is.null(filtro) && filtro != "todos" && filtro != "") {
      if (startsWith(filtro, "amh_")) {
        patron <- sub("^amh_", "", filtro)
        ips <- ips[!is.na(ips$amh_patron) & ips$amh_patron == patron, ]
      } else if (startsWith(filtro, "tobi_")) {
        patron <- sub("^tobi_", "", filtro)
        ips <- ips[!is.na(ips$tobi_nuclear) & ips$tobi_nuclear == patron, ]
      }
    }

    # Filtros de características adicionales
    min_pal <- filtros_ge_extra$min_palabras
    max_pal <- filtros_ge_extra$max_palabras
    if (!is.null(min_pal) && min_pal > 0 && "n_palabras" %in% colnames(ips))
      ips <- ips[!is.na(ips$n_palabras) & ips$n_palabras >= min_pal, ]
    if (!is.null(max_pal) && max_pal > 0 && "n_palabras" %in% colnames(ips))
      ips <- ips[!is.na(ips$n_palabras) & ips$n_palabras <= max_pal, ]
    acento_f <- filtros_ge_extra$acento_final
    if (!is.null(acento_f) && acento_f != "todos" && "acento_ultima_palabra" %in% colnames(ips))
      ips <- ips[!is.na(ips$acento_ultima_palabra) & ips$acento_ultima_palabra == acento_f, ]
    amh_fon <- filtros_ge_extra$patron_amh_fonetico
    if (!is.null(amh_fon) && amh_fon != "todos" && "amh_patron" %in% colnames(ips))
      ips <- ips[!is.na(ips$amh_patron) & ips$amh_patron == amh_fon, ]
    amh_fonol <- filtros_ge_extra$patron_amh_fonologico
    if (!is.null(amh_fonol) && amh_fonol != "todos" && "amh_patron_fonologico" %in% colnames(ips))
      ips <- ips[!is.na(ips$amh_patron_fonologico) & ips$amh_patron_fonologico == amh_fonol, ]

    # Filtro de texto: buscar palabras en palabras_grupo
    buscar <- if (!is.null(input$buscar_palabras_ge)) trimws(input$buscar_palabras_ge) else ""
    if (nchar(buscar) > 0 && "palabras_grupo" %in% colnames(ips)) {
      ips <- ips[grepl(buscar, ips$palabras_grupo, ignore.case = TRUE), ]
    }

    ips
  })

  output$selector_gf <- renderUI({
    req(datos$calculado)
    ips <- ips_filtrados()
    if (is.null(ips) || nrow(ips) == 0) return(helpText("No hay grupos con ese filtro"))
    gfs_disp <- sort(unique(ips$grupo_fonico))
    selectInput("sel_gf", "Grupo Fónico:", choices = gfs_disp, selected = gfs_disp[1])
  })

  output$selector_ge <- renderUI({
    req(datos$calculado, input$sel_gf)
    ips <- ips_filtrados()
    gf_sel <- as.numeric(input$sel_gf)
    ips_gf <- ips[ips$grupo_fonico == gf_sel, ]
    if (nrow(ips_gf) == 0) return(helpText("Sin GEs"))
    ges_disp <- sort(unique(ips_gf$grupo_entonativo))
    labels <- paste0("GE ", ges_disp)
    if ("amh_patron" %in% colnames(ips_gf)) {
      for (i in seq_along(ges_disp)) {
        ip <- ips_gf[ips_gf$grupo_entonativo == ges_disp[i], ]
        if (nrow(ip) > 0 && !is.na(ip$amh_patron[1])) {
          patron <- ip$amh_patron[1]
          amh_names <- c(I="Neutro",II="Interrogativo",III="Interrogativo mod.",
            IVa="Circunflejo",IVb="Plano desc.",V="Suspensi\u00f3n",
            VIa="Susp. ascendente",VIb="Susp. pico",VII="\u00c9nfasis res.",
            VIII="\u00c9nfasis red.",IX="\u00c9nfasis desc.",
            Xa="Circ. asc-desc",Xb="Circ. desc-asc",XI="Pico adicional",
            XIIa="Plano",XIIb="Zigzag plano",XIIc="Zigzag desc.")
          desc <- if (!is.na(amh_names[patron])) amh_names[[patron]] else patron
          labels[i] <- paste0("GE ", ges_disp[i], " \u2014 ", patron, " (", desc, ")")
        }
      }
    }
    names(ges_disp) <- labels
    selectInput("sel_ge", "Grupo Entonativo:", choices = ges_disp, selected = ges_disp[1])
  })

  # ========================================
  # INFO GRUPO DETALLE
  # ========================================
  grupo_actual <- reactive({
    req(datos$calculado, input$sel_gf, input$sel_hablante_cm, input$sel_filename_cm)
    gf_sel  <- as.numeric(input$sel_gf)
    hab_sel <- input$sel_hablante_cm
    fn_sel  <- input$sel_filename_cm

    if (input$tipo_vista_grupo == "entonativo") {
      req(input$sel_ge)
      ge_sel <- as.numeric(input$sel_ge)
      ips <- ips_filtrados()
      ip  <- ips[ips$grupo_fonico == gf_sel & ips$grupo_entonativo == ge_sel, ]
      return(ip)
    } else {
      gfs <- datos$gfs_resumen[
        datos$gfs_resumen$hablante == hab_sel &
        datos$gfs_resumen$filename  == fn_sel, ]
      gf  <- gfs[gfs$grupo_fonico == gf_sel, ]
      return(gf)
    }
  })

  vocales_grupo_actual <- reactive({
    req(datos$calculado, datos$phones, input$sel_gf,
        input$sel_hablante_cm, input$sel_filename_cm)
    gf_sel  <- as.numeric(input$sel_gf)
    hab_sel <- input$sel_hablante_cm
    fn_sel  <- input$sel_filename_cm

    # Filtrar siempre por filename + hablante para evitar mezclas
    phones <- datos$phones[
      datos$phones$hablante == hab_sel &
      datos$phones$filename  == fn_sel, ]

    if (input$tipo_vista_grupo == "entonativo") {
      req(input$sel_ge)
      ge_sel <- as.numeric(input$sel_ge)
      vocales <- phones[phones$grupo_fonico == gf_sel & phones$grupo_entonativo == ge_sel, ]
    } else {
      vocales <- phones[phones$grupo_fonico == gf_sel, ]
    }
    vocales
  })

  output$info_grupo_detalle <- renderPrint({
    ga <- grupo_actual()
    if (is.null(ga) || nrow(ga) == 0) { cat("Sin datos"); return() }
    g <- ga[1, ]

    if (input$tipo_vista_grupo == "entonativo") {
      cat("Archivo:", input$sel_filename_cm, "\n")
      cat("GF:", g$grupo_fonico, "| GE:", g$grupo_entonativo, "\n")
      cat("Inicio:", round(g$inicio, 3), "s | Fin:", round(g$fin, 3), "s\n")
      cat("Duración:", round(g$duracion, 3), "s\n")
      cat("Vocales:", g$num_vocales, "| Palabras:", g$num_palabras, "\n")
      if ("amh_patron"        %in% colnames(g)) cat("AMH:", g$amh_patron, "-", g$amh_fonologico, "\n")
      if ("tobi_nuclear"      %in% colnames(g)) cat("ToBI Nuclear:", g$tobi_nuclear, "\n")
      if ("inflexion_final_pct" %in% colnames(g)) cat("Inflexión final:", round(g$inflexion_final_pct, 1), "%\n")
    } else {
      cat("Archivo:", input$sel_filename_cm, "\n")
      cat("GF:", g$grupo_fonico, "\n")
      cat("Inicio:", round(g$inicio, 3), "s | Fin:", round(g$fin, 3), "s\n")
      cat("Duración:", round(g$duracion, 3), "s\n")
      cat("Vocales:", g$num_vocales, "| Palabras:", g$num_palabras, "\n")
      cat("GEs en este GF:", g$num_ges, "\n")
    }
  })

  output$amh_grupo_actual <- renderText({
    ga <- grupo_actual()
    if (is.null(ga) || nrow(ga) == 0 || !"amh_patron" %in% colnames(ga)) return("-")
    patron <- ga$amh_patron[1]
    if (is.na(patron)) return("-")
    amh_names <- c(I="Neutro",II="Interrogativo fuerte",III="Interrogativo moderado",
      IVa="Circunflejo (asc-desc)",IVb="Plano descendente",V="Suspensi\u00f3n ascendente",
      VIa="Susp. con ascenso final",VIb="Susp. pico desplazado",
      VII="\u00c9nfasis resituado",VIII="\u00c9nfasis reducido",IX="\u00c9nfasis descendente",
      Xa="Circunflejo asc-desc",Xb="Circunflejo desc-asc",XI="Pico tonal adicional",
      XIIa="Plano",XIIb="Zigzag plano",XIIc="Zigzag descendente")
    desc <- if (!is.na(amh_names[patron])) amh_names[[patron]] else ""
    if (nchar(desc) > 0) paste0(patron, " \u2014 ", desc) else patron
  })

  output$tobi_grupo_actual <- renderText({
    ga <- grupo_actual()
    if (is.null(ga) || nrow(ga) == 0 || !"tobi_nuclear" %in% colnames(ga)) return("-")
    ga$tobi_nuclear[1]
  })

  output$palabras_grupo_inline <- renderText({
    ga <- grupo_actual()
    if (is.null(ga) || nrow(ga) == 0) return("")
    if ("palabras_grupo" %in% colnames(ga)) ga$palabras_grupo[1]
    else if ("palabras_gf"  %in% colnames(ga)) ga$palabras_gf[1]
    else ""
  })

  # ── Cache de figuras Plotly para descarga PNG ────────────────────────────────
  rv_plot_normalizado <- reactiveVal(NULL)
  rv_plot_bruto       <- reactiveVal(NULL)

  # ── Cache del TextGrid del GE actual para praatpicture ───────────────────────
  # Almacena: $path (TextGrid recortado), $wav_path (WAV recortado),
  #           $dur (duración del segmento), $key (ID único del GE)
  ge_tg_cached <- reactiveVal(list(path=NULL, wav_path=NULL, dur=NULL, key=NULL))

  # ========================================
  # GRÁFICOS CONF. MELÓDICA (corregidos)
  # ========================================
  output$plot_config_melodica_normalizado <- renderPlotly({
    vocales <- vocales_grupo_actual()
    req(nrow(vocales) > 0)

    vocales <- vocales[order(vocales$inicio), ]
    vocales$pos <- 1:nrow(vocales)

    # Redondear a 2 decimales para tooltips
    vocales$f0_media_hz_r <- round(vocales$f0_media_hz, 2)
    vocales$f0_media_st_r <- round(vocales$f0_media_st, 2)
    vocales$int_media_r   <- round(vocales$int_media, 2)
    vocales$duracion_r    <- round(vocales$duracion, 2)

    # Etiqueta compuesta: vocal (palabra)
    vocales$etiq_completa <- ifelse(!is.na(vocales$palabra) & vocales$palabra != "",
                                    paste0(vocales$etiqueta, " (", vocales$palabra, ")"),
                                    vocales$etiqueta)

    # Normalización — usa norm_tipo_grupo si existe, si no cae en tipo_normalizacion global
    tipo_norm_local <- if (!is.null(input$norm_tipo_grupo)) {
      switch(input$norm_tipo_grupo,
        "primera_vocal"  = "base100_primera",
        "media_hablante" = "base100_media",
        "base100_primera"
      )
    } else {
      input$tipo_normalizacion
    }
    tipo_norm <- tipo_norm_local

    if (tipo_norm == "base100_primera") {
      vocales$f0_norm   <- normalizar_base100_primera(vocales$f0_media_hz)
      vocales$int_norm  <- normalizar_base100_primera(vocales$int_media)
      vocales$trans_norm <- normalizar_base100_primera(vocales$tiempo_transicion_anterior)
      y_label <- "Valor normalizado (base 100 = primera vocal)"
    } else if (tipo_norm == "base100_media") {
      media_hab <- datos$medias_hablante
      if (!is.null(media_hab) && nrow(media_hab) > 0) {
        hab <- vocales$hablante[1]; fn <- vocales$filename[1]
        ref <- media_hab[media_hab$hablante == hab & media_hab$filename == fn, ]
        if (nrow(ref) > 0) {
          vocales$f0_norm   <- normalizar_base100_media(vocales$f0_media_hz, ref$f0_media_hz_hablante[1])
          vocales$int_norm  <- normalizar_base100_media(vocales$int_media,    ref$int_media_hablante[1])
          trans_ref          <- mean(vocales$tiempo_transicion_anterior, na.rm = TRUE)
          vocales$trans_norm <- normalizar_base100_media(vocales$tiempo_transicion_anterior, trans_ref)
        } else {
          vocales$f0_norm   <- normalizar_base100_primera(vocales$f0_media_hz)
          vocales$int_norm  <- normalizar_base100_primera(vocales$int_media)
          vocales$trans_norm <- normalizar_base100_primera(vocales$tiempo_transicion_anterior)
        }
      } else {
        vocales$f0_norm   <- normalizar_base100_primera(vocales$f0_media_hz)
        vocales$int_norm  <- normalizar_base100_primera(vocales$int_media)
        vocales$trans_norm <- normalizar_base100_primera(vocales$tiempo_transicion_anterior)
      }
      y_label <- "Valor normalizado (base 100 = media hablante)"
    } else if (tipo_norm == "zscore") {
      vocales$f0_norm   <- normalizar_zscore(vocales$f0_media_hz)
      vocales$int_norm  <- normalizar_zscore(vocales$int_media)
      vocales$trans_norm <- normalizar_zscore(vocales$tiempo_transicion_anterior)
      y_label <- "Z-score"
    } else {
      vocales$f0_norm   <- normalizar_minmax(vocales$f0_media_hz)
      vocales$int_norm  <- normalizar_minmax(vocales$int_media)
      vocales$trans_norm <- normalizar_minmax(vocales$tiempo_transicion_anterior)
      y_label <- "Valor normalizado (Min-Max 0-100)"
    }

    vocales$f0_norm_r  <- round(vocales$f0_norm,  2)
    vocales$int_norm_r <- round(vocales$int_norm,  2)
    vocales$trans_norm_r <- round(vocales$trans_norm, 2)
    vocales$trans_r    <- round(vocales$tiempo_transicion_anterior, 2)

    # Guardar referencia de normalización para cuartiles
    norm_ref <- list(tipo = tipo_norm)
    if (tipo_norm == "base100_primera") {
      norm_ref$primera_hz <- vocales$f0_media_hz[!is.na(vocales$f0_media_hz)][1]
    } else if (tipo_norm == "base100_media") {
      media_hab_ref <- datos$medias_hablante
      if (!is.null(media_hab_ref) && nrow(media_hab_ref) > 0) {
        hab_r <- vocales$hablante[1]; fn_r <- vocales$filename[1]
        ref_tmp <- media_hab_ref[media_hab_ref$hablante == hab_r & media_hab_ref$filename == fn_r, ]
        norm_ref$media_hz <- if (nrow(ref_tmp) > 0) ref_tmp$f0_media_hz_hablante[1] else vocales$f0_media_hz[!is.na(vocales$f0_media_hz)][1]
      } else {
        norm_ref$media_hz <- vocales$f0_media_hz[!is.na(vocales$f0_media_hz)][1]
      }
    } else if (tipo_norm == "zscore") {
      norm_ref$f0_mean <- mean(vocales$f0_media_hz, na.rm = TRUE)
      norm_ref$f0_sd   <- sd(vocales$f0_media_hz,   na.rm = TRUE)
    } else {
      norm_ref$f0_min <- min(vocales$f0_media_hz, na.rm = TRUE)
      norm_ref$f0_max <- max(vocales$f0_media_hz, na.rm = TRUE)
    }

    # Función local para normalizar un valor Hz individual con la misma referencia
    norm_hz_val <- function(hz_val) {
      if (is.na(hz_val)) return(NA_real_)
      if (norm_ref$tipo == "base100_primera") {
        ref_v <- norm_ref$primera_hz
        if (is.na(ref_v) || ref_v == 0) return(NA_real_)
        return((hz_val / ref_v) * 100)
      } else if (norm_ref$tipo == "base100_media") {
        ref_v <- norm_ref$media_hz
        if (is.na(ref_v) || ref_v == 0) return(NA_real_)
        return((hz_val / ref_v) * 100)
      } else if (norm_ref$tipo == "zscore") {
        if (is.na(norm_ref$f0_sd) || norm_ref$f0_sd == 0) return(0)
        return((hz_val - norm_ref$f0_mean) / norm_ref$f0_sd)
      } else {
        rng <- norm_ref$f0_max - norm_ref$f0_min
        if (is.na(rng) || rng == 0) return(50)
        return(((hz_val - norm_ref$f0_min) / rng) * 100)
      }
    }

    criterios <- input$criterios_proyectar
    vista_gf  <- (input$tipo_vista_grupo == "fonico")

    fig <- plot_ly()

    # Secciones de fondo
    shapes_list <- list()
    if (input$mostrar_secciones && "seccion_ip" %in% colnames(vocales)) {
      colores_seccion <- c(anacrusis = "rgba(255, 193, 7, 0.20)",
                           cuerpo    = "rgba(40, 167, 69, 0.15)",
                           tonema    = "rgba(220, 53, 69, 0.20)")
      secciones <- rle(vocales$seccion_ip)
      pos_fin   <- cumsum(secciones$lengths) + 0.5
      pos_ini   <- c(0.5, pos_fin[-length(pos_fin)])
      for (s in seq_along(secciones$values)) {
        sec_name <- secciones$values[s]
        col <- colores_seccion[sec_name]
        if (!is.na(col)) {
          shapes_list[[length(shapes_list) + 1]] <- list(
            type = "rect", x0 = pos_ini[s], x1 = pos_fin[s],
            y0 = 0, y1 = 1, xref = "x", yref = "paper",
            fillcolor = col, line = list(width = 0), layer = "below"
          )
        }
      }
    }

    # Vista GF: colorear por grupo entonativo
    if (vista_gf && input$colorear_ges && "grupo_entonativo" %in% colnames(vocales)) {
      ge_vals   <- unique(vocales$grupo_entonativo)
      paleta_ge <- RColorBrewer::brewer.pal(max(3, min(length(ge_vals), 8)), "Set2")

      for (i in seq_along(ge_vals)) {
        ge_v     <- ge_vals[i]
        voc_ge   <- vocales[vocales$grupo_entonativo == ge_v, ]
        color_ge <- paleta_ge[((i - 1) %% length(paleta_ge)) + 1]

        if ("pitch" %in% criterios) {
          fig <- fig %>% add_trace(data = voc_ge, x = ~pos, y = ~f0_norm_r,
                                    type = "scatter", mode = "lines+markers",
                                    line   = list(color = color_ge, width = 2),
                                    marker = list(color = color_ge, size = 7),
                                    text = ~paste0(etiq_completa, "\nF0: ", f0_media_hz_r, " Hz (",
                                                   f0_media_st_r, " St)\nInt: ", int_media_r, " dB\nNorm: ", f0_norm_r),
                                    hoverinfo = "text",
                                    name = paste0("GE", ge_v, " - Pitch"),
                                    legendgroup = paste0("ge", ge_v))
        }
        if ("intensidad" %in% criterios) {
          fig <- fig %>% add_trace(data = voc_ge, x = ~pos, y = ~int_norm_r,
                                    type = "scatter", mode = "lines+markers",
                                    line   = list(color = color_ge, width = 1, dash = "dash"),
                                    marker = list(color = color_ge, size = 4, symbol = "diamond"),
                                    text = ~paste0(etiq_completa, "\nInt: ", int_media_r, " dB\nNorm: ", int_norm_r),
                                    hoverinfo = "text",
                                    name = paste0("GE", ge_v, " - Int"),
                                    legendgroup = paste0("ge", ge_v),
                                    showlegend = !("pitch" %in% criterios))
        }
      }
    } else {
      # Vista normal — con opción de colorear por palabra
      colorear_palabras <- isTRUE(input$norm_colorear_palabras) && "palabra" %in% colnames(vocales)

      if (colorear_palabras) {
        palabras_unicas <- unique(vocales$palabra[!is.na(vocales$palabra) & vocales$palabra != ""])
        n_uni <- length(palabras_unicas)
        # Set1 da como mucho 9 colores: interpolar para no dejar palabras sin color (NA)
        paleta_pal <- colorRampPalette(
          RColorBrewer::brewer.pal(min(8L, max(3L, n_uni)), "Set1"))(max(1L, n_uni))
        pal_map <- setNames(paleta_pal[seq_along(palabras_unicas)], palabras_unicas)

        for (pw in palabras_unicas) {
          voc_pw    <- vocales[!is.na(vocales$palabra) & vocales$palabra == pw, ]
          color_pw  <- pal_map[[pw]]
          if ("pitch" %in% criterios) {
            fig <- fig %>% add_trace(data = voc_pw, x = ~pos, y = ~f0_norm_r,
                                      type = "scatter", mode = "lines+markers",
                                      line   = list(color = color_pw, width = 2),
                                      marker = list(color = color_pw, size = 7),
                                      text = ~paste0(etiq_completa, "\nF0: ", f0_media_hz_r, " Hz (",
                                                     f0_media_st_r, " St)\nNorm: ", f0_norm_r),
                                      hoverinfo = "text",
                                      name = paste0("Pitch — ", pw),
                                      legendgroup = pw)
          }
          if ("intensidad" %in% criterios) {
            fig <- fig %>% add_trace(data = voc_pw, x = ~pos, y = ~int_norm_r,
                                      type = "scatter", mode = "lines+markers",
                                      line   = list(color = color_pw, width = 1.5, dash = "dash"),
                                      marker = list(color = color_pw, size = 4, symbol = "diamond"),
                                      text = ~paste0(etiq_completa, "\nInt: ", int_media_r, " dB\nNorm: ", int_norm_r),
                                      hoverinfo = "text",
                                      name = paste0("Int — ", pw),
                                      legendgroup = pw,
                                      showlegend = !("pitch" %in% criterios))
          }
        }
      } else {
        if ("pitch" %in% criterios) {
          fig <- fig %>% add_trace(data = vocales, x = ~pos, y = ~f0_norm_r,
                                    type = "scatter", mode = "lines+markers",
                                    line   = list(color = "blue", width = 2),
                                    marker = list(color = "blue", size = 7),
                                    text = ~paste0(etiq_completa, "\nF0: ", f0_media_hz_r, " Hz (",
                                                   f0_media_st_r, " St)\nInt: ", int_media_r, " dB\nDur: ", duracion_r, "s\nNorm: ", f0_norm_r),
                                    hoverinfo = "text",
                                    name = "Pitch (F0)")
        }
        if ("intensidad" %in% criterios) {
          fig <- fig %>% add_trace(data = vocales, x = ~pos, y = ~int_norm_r,
                                    type = "scatter", mode = "lines+markers",
                                    line   = list(color = "red", width = 1.5, dash = "dash"),
                                    marker = list(color = "red", size = 5, symbol = "diamond"),
                                    text = ~paste0(etiq_completa, "\nInt: ", int_media_r, " dB\nNorm: ", int_norm_r),
                                    hoverinfo = "text",
                                    name = "Intensidad")
        }
      }
    }

    # Transiciones como barras
    if ("transicion" %in% criterios && "tiempo_transicion_anterior" %in% colnames(vocales)) {
      voc_trans <- vocales[!is.na(vocales$trans_norm), ]
      if (nrow(voc_trans) > 0) {
        fig <- fig %>% add_trace(data = voc_trans, x = ~pos, y = ~trans_norm_r,
                                  type = "bar",
                                  marker = list(color = "rgba(70, 130, 180, 0.45)",
                                                line = list(color = "rgba(70, 130, 180, 0.8)", width = 1)),
                                  text = ~paste0(etiq_completa, "\nTransición: ", trans_r, " s\nNorm: ", trans_norm_r),
                                  hoverinfo = "text",
                                  textposition = "none",
                                  name = "Transición vocálica",
                                  width = 0.4)
      }
    }

    # Estructura interna de vocales con movimiento > 1.5 St
    if (input$mostrar_estructura_vocal && "pitch" %in% criterios &&
        all(c("q1_f0_media_hz", "q2_f0_media_hz", "q3_f0_media_hz", "q4_f0_media_hz",
               "dif_q1_q2_st", "dif_q2_q3_st", "dif_q3_q4_st") %in% colnames(vocales))) {

      umbral_mov <- 1.5
      q_points   <- data.frame(x = numeric(0), y = numeric(0), q_label = character(0),
                                vocal_etiq = character(0), hz_val = numeric(0),
                                estructura = character(0), stringsAsFactors = FALSE)
      q_lines <- list()

      for (i in 1:nrow(vocales)) {
        d12 <- abs(vocales$dif_q1_q2_st[i]); d23 <- abs(vocales$dif_q2_q3_st[i])
        d34 <- abs(vocales$dif_q3_q4_st[i])
        if (is.na(d12)) d12 <- 0; if (is.na(d23)) d23 <- 0; if (is.na(d34)) d34 <- 0

        if (d12 > umbral_mov || d23 > umbral_mov || d34 > umbral_mov) {
          q1h <- vocales$q1_f0_media_hz[i]; q2h <- vocales$q2_f0_media_hz[i]
          q3h <- vocales$q3_f0_media_hz[i]; q4h <- vocales$q4_f0_media_hz[i]
          if (any(is.na(c(q1h, q2h, q3h, q4h)))) next

          base_x  <- vocales$pos[i]
          offsets <- c(-0.3, -0.1, 0.1, 0.3)
          hz_vals <- c(q1h, q2h, q3h, q4h)
          q_labels <- c("Q1", "Q2", "Q3", "Q4")
          estr <- if ("estructura_vocal" %in% colnames(vocales)) vocales$estructura_vocal[i] else ""

          for (qi in 1:4) {
            y_norm <- norm_hz_val(hz_vals[qi])
            if (!is.na(y_norm)) {
              q_points <- rbind(q_points, data.frame(
                x = base_x + offsets[qi], y = round(y_norm, 2),
                q_label = q_labels[qi], vocal_etiq = vocales$etiq_completa[i],
                hz_val = round(hz_vals[qi], 1), estructura = estr,
                stringsAsFactors = FALSE))
            }
          }

          y_norms <- sapply(hz_vals, norm_hz_val)
          if (!any(is.na(y_norms))) {
            for (seg in 1:3) {
              q_lines[[length(q_lines) + 1]] <- list(
                type = "line",
                x0 = base_x + offsets[seg], x1 = base_x + offsets[seg + 1],
                y0 = round(y_norms[seg], 2), y1 = round(y_norms[seg + 1], 2),
                xref = "x", yref = "y",
                line = list(color = "rgba(150, 50, 200, 0.4)", width = 1.5, dash = "dot"),
                layer = "above"
              )
            }
          }
        }
      }

      if (nrow(q_points) > 0) {
        fig <- fig %>% add_trace(data = q_points, x = ~x, y = ~y,
                                  type = "scatter", mode = "markers",
                                  marker = list(color = "rgba(150, 50, 200, 0.7)", size = 8,
                                                symbol = "circle",
                                                line = list(color = "rgba(100, 20, 160, 0.9)", width = 1)),
                                  text = ~paste0(vocal_etiq, "\n", q_label, ": ", hz_val, " Hz\nNorm: ", y,
                                                 "\nEstructura: ", estructura),
                                  hoverinfo = "text",
                                  name = "Estructura interna vocal")
        shapes_list <- c(shapes_list, q_lines)
      }
    }

    # Marcadores tónicas
    if (input$mostrar_tonicas && "tonica_gramatical" %in% colnames(vocales) && "pitch" %in% criterios) {
      tonicas <- vocales[!is.na(vocales$tonica_gramatical) & vocales$tonica_gramatical == "sí", ]
      if (nrow(tonicas) > 0) {
        fig <- fig %>% add_trace(data = tonicas, x = ~pos, y = ~f0_norm_r,
                                  type = "scatter", mode = "markers",
                                  marker = list(color = "gold", size = 12, symbol = "triangle-up",
                                                line = list(color = "black", width = 1.5)),
                                  text = ~paste0("TÓNICA: ", etiq_completa),
                                  hoverinfo = "text",
                                  name = "Tónica gramatical")
      }
    }

    # Marcadores picos
    if (input$mostrar_picos && "pitch" %in% criterios) {
      picos_grupo <- vocales[!is.na(vocales$es_pico_grupo) & vocales$es_pico_grupo, ]
      if (nrow(picos_grupo) > 0) {
        fig <- fig %>% add_trace(data = picos_grupo, x = ~pos, y = ~f0_norm_r,
                                  type = "scatter", mode = "markers",
                                  marker = list(color = "darkred", size = 14, symbol = "star"),
                                  text = ~paste0("PICO GRUPO: ", etiq_completa, "\nF0: ", f0_media_hz_r, " Hz"),
                                  hoverinfo = "text",
                                  name = "Pico tonal (grupo)")
      }
      picos_palabra <- vocales[!is.na(vocales$es_pico_palabra) & vocales$es_pico_palabra &
                                 !(vocales$es_pico_grupo %in% TRUE), ]
      if (nrow(picos_palabra) > 0) {
        fig <- fig %>% add_trace(data = picos_palabra, x = ~pos, y = ~f0_norm_r,
                                  type = "scatter", mode = "markers",
                                  marker = list(color = "orange", size = 10, symbol = "x"),
                                  text = ~paste0("PICO PALABRA: ", etiq_completa, "\nF0: ", f0_media_hz_r, " Hz"),
                                  hoverinfo = "text",
                                  name = "Pico tonal (palabra)")
      }
    }

    # Etiquetas ToBI como anotaciones
    annotations_list <- list()
    if (input$mostrar_tobi && "pitch" %in% criterios) {
      col_tobi <- if (input$tipo_tobi_mostrar == "fonetico") "tobi_fonetico" else "tobi_fonologico"
      if (col_tobi %in% colnames(vocales)) {
        for (i in 1:nrow(vocales)) {
          lbl <- vocales[[col_tobi]][i]
          if (!is.na(lbl) && lbl != "") {
            annotations_list[[length(annotations_list) + 1]] <- list(
              x = vocales$pos[i], y = vocales$f0_norm_r[i],
              text = lbl, showarrow = FALSE,
              yshift = 18, font = list(color = "purple", size = 11)
            )
          }
        }
      }
      if ("tono_frontera" %in% colnames(vocales)) {
        col_fr <- if (input$tipo_tobi_mostrar == "fonetico") "tono_frontera" else "tono_frontera_fonologico"
        for (i in 1:nrow(vocales)) {
          lbl <- vocales[[col_fr]][i]
          if (!is.na(lbl) && lbl != "") {
            annotations_list[[length(annotations_list) + 1]] <- list(
              x = vocales$pos[i], y = vocales$f0_norm_r[i],
              text = paste0("<b>", lbl, "</b>"), showarrow = FALSE,
              yshift = -18, font = list(color = "darkgreen", size = 11)
            )
          }
        }
      }
    }

    # Título dinámico
    titulo <- "Configuración melódica normalizada"
    if (vista_gf) titulo <- paste0(titulo, " — ", input$sel_filename_cm, " | GF", input$sel_gf)
    else          titulo <- paste0(titulo, " — ", input$sel_filename_cm, " | GF", input$sel_gf, " / GE", input$sel_ge)

    fig <- fig %>% layout(
      title = list(text = titulo, font = list(size = 14)),
      xaxis = list(title = "Vocal (palabra)", tickmode = "array",
                   tickvals = vocales$pos, ticktext = vocales$etiq_completa,
                   tickangle = -30, tickfont = list(size = 10)),
      yaxis  = list(title = y_label),
      shapes = shapes_list,
      annotations = annotations_list,
      barmode = "overlay",
      legend = list(orientation = "h", y = -0.25, x = 0.5, xanchor = "center"),
      hovermode = "closest",
      margin = list(b = 120)
    )

    rv_plot_normalizado(fig)
    fig
  })

  output$plot_config_melodica_bruto <- renderPlotly({
    vocales <- vocales_grupo_actual()
    req(nrow(vocales) > 0)
    vocales <- vocales[order(vocales$inicio), ]

    vocales$f0_media_hz_r <- round(vocales$f0_media_hz, 2)
    vocales$f0_media_st_r <- round(vocales$f0_media_st, 2)
    vocales$int_media_r   <- round(vocales$int_media, 2)
    vocales$centro_r      <- round(vocales$centro, 2)
    vocales$etiq_completa <- ifelse(!is.na(vocales$palabra) & vocales$palabra != "",
                                    paste0(vocales$etiqueta, " (", vocales$palabra, ")"),
                                    vocales$etiqueta)

    vista_gf <- (input$tipo_vista_grupo == "fonico")
    fig <- plot_ly()

    if (vista_gf && input$colorear_ges && "grupo_entonativo" %in% colnames(vocales)) {
      ge_vals   <- unique(vocales$grupo_entonativo)
      paleta_ge <- RColorBrewer::brewer.pal(max(3, min(length(ge_vals), 8)), "Set2")
      for (i in seq_along(ge_vals)) {
        ge_v     <- ge_vals[i]
        voc_ge   <- vocales[vocales$grupo_entonativo == ge_v, ]
        color_ge <- paleta_ge[((i - 1) %% length(paleta_ge)) + 1]
        fig <- fig %>% add_trace(data = voc_ge, x = ~centro_r, y = ~f0_media_hz_r,
                                  type = "scatter", mode = "lines+markers",
                                  line   = list(color = color_ge, width = 2),
                                  marker = list(color = color_ge, size = 7),
                                  text = ~paste0(etiq_completa, "\nF0: ", f0_media_hz_r, " Hz (",
                                                 f0_media_st_r, " St)\nInt: ", int_media_r, " dB\nt=", centro_r, "s"),
                                  hoverinfo = "text",
                                  name = paste0("GE", ge_v))
      }
    } else {
      fig <- fig %>% add_trace(data = vocales, x = ~centro_r, y = ~f0_media_hz_r,
                                type = "scatter", mode = "lines+markers",
                                line   = list(color = "blue", width = 2),
                                marker = list(color = "blue", size = 7),
                                text = ~paste0(etiq_completa, "\nF0: ", f0_media_hz_r, " Hz (",
                                               f0_media_st_r, " St)\nInt: ", int_media_r, " dB\nt=", centro_r, "s"),
                                hoverinfo = "text",
                                name = "Pitch (F0 Hz)")
    }

    titulo_bruto <- "Pitch en tiempo real"
    if (vista_gf) titulo_bruto <- paste0(titulo_bruto, " — ", input$sel_filename_cm, " | GF", input$sel_gf)

    fig <- fig %>% layout(
      title  = list(text = titulo_bruto, font = list(size = 14)),
      xaxis  = list(title = "Tiempo (s)"),
      yaxis  = list(title = "F0 media (Hz)"),
      legend = list(orientation = "h", y = -0.2, x = 0.5, xanchor = "center"),
      hovermode = "closest"
    )

    rv_plot_bruto(fig)
    fig
  })

  # ── Auto-cargar audios desde lasp_datos/audios cuando cambia datos$calculado ──
  # Reactivo a datos$calculado (y a las tablas de datos), pero NO a datos_audio$wavs
  # para evitar bucles de invalidación.
  observeEvent(list(datos$calculado, datos$ips_resumen, datos$phones, datos$words), {
    if (!isTRUE(datos$calculado)) return()
    wavs_en_disco <- list.files(lasp_audios, pattern = "\\.(wav|WAV|flac|mp3)$", full.names = TRUE)
    if (length(wavs_en_disco) == 0) return()
    fns_analisis <- isolate(unique(c(
      if (!is.null(datos$ips_resumen)  && "filename" %in% colnames(datos$ips_resumen))  datos$ips_resumen$filename  else character(0),
      if (!is.null(datos$phones)       && "filename" %in% colnames(datos$phones))        datos$phones$filename        else character(0),
      if (!is.null(datos$words)        && "filename" %in% colnames(datos$words))         datos$words$filename         else character(0)
    )))
    wavs_actuales <- isolate(names(datos_audio$wavs))
    for (wp in wavs_en_disco) {
      base_wp <- tools::file_path_sans_ext(basename(wp))
      if (base_wp %in% wavs_actuales) next
      coincide <- length(fns_analisis) == 0 ||
        any(sapply(fns_analisis, function(fn) {
          grepl(base_wp, fn, fixed = TRUE) || grepl(fn, base_wp, fixed = TRUE) ||
          base_wp == tools::file_path_sans_ext(basename(fn))
        }))
      if (coincide) {
        isolate(datos_audio$wavs[[base_wp]] <- wp)
        wavs_actuales <- c(wavs_actuales, base_wp)
      }
    }
  }, ignoreNULL = FALSE, ignoreInit = FALSE)

  # ── Helpers: Praat pitch con parámetros coherentes con el análisis ────────────
  # praatpicture usa wrassp::ksvF0 por defecto (algoritmo KSV, diferente de Praat).
  # Para coherencia con el análisis (voicing_threshold=0.15, silence_threshold=0.01
  # del script analisis_prosodico_v3_1_6.praat), pre-calculamos el pitch con Praat
  # y lo pasamos via pitch_ssff, que praatpicture acepta como AsspDataObj.
  .praat_bin_cached <- local({
    val <- NULL
    function() {
      if (!is.null(val)) return(val)
      bin <- Sys.which("praat")
      if (nchar(bin) == 0 || !file.exists(bin)) {
        for (pc in c(
          "/Applications/Praat.app/Contents/MacOS/Praat",
          "/usr/bin/praat", "/usr/local/bin/praat",
          "C:/Program Files/Praat/Praat.exe",
          "C:/Program Files (x86)/Praat/Praat.exe"
        )) { if (file.exists(pc)) { bin <- pc; break } }
      }
      val <<- if (nchar(bin) > 0 && file.exists(bin)) bin else NULL
      val
    }
  })

  pp_compute_pitch_ssff <- function(wav_path,
                                     pitch_floor   = 75,
                                     pitch_ceiling = 600,
                                     voicing_thr   = 0.15,
                                     silence_thr   = 0.01,
                                     time_step     = 0.01) {
    praat_bin <- .praat_bin_cached()
    if (is.null(praat_bin) || !file.exists(wav_path)) return(NULL)

    # Praat acepta paths con / en todas las plataformas
    wav_safe <- gsub("\\\\", "/", wav_path)
    out_f    <- tempfile(fileext = ".txt")
    out_safe <- gsub("\\\\", "/", out_f)
    scr_f    <- tempfile(fileext = ".praat")

    fmt <- function(x) formatC(x, format = "f", digits = 6, big.mark = "")

    praat_script <- paste0(
      'sound = Read from file: "', wav_safe, '"\n',
      'selectObject: sound\n',
      'pitch = To Pitch (ac): ', fmt(time_step), ', ', fmt(pitch_floor),
      ', 15, "no", ', fmt(silence_thr), ', ', fmt(voicing_thr),
      ', 0.010000, 0.350000, 0.140000, ', fmt(pitch_ceiling), '\n',
      'nf = Get number of frames\n',
      'writeFileLine: "', out_safe, '", "time", tab$, "f0"\n',
      'for i from 1 to nf\n',
      '  t = Get time from frame: i\n',
      '  v = Get value in frame: i, "Hertz"\n',
      '  if v = undefined\n',
      '    appendFileLine: "', out_safe, '", fixed$(t, 6), tab$, "0"\n',
      '  else\n',
      '    appendFileLine: "', out_safe, '", fixed$(t, 6), tab$, fixed$(v, 4)\n',
      '  endif\n',
      'endfor\n',
      'selectObject: pitch\nRemove\n',
      'selectObject: sound\nRemove\n'
    )

    tryCatch({
      writeLines(praat_script, scr_f)
      system2(praat_bin, args = c("--run", shQuote(scr_f)),
              stdout = FALSE, stderr = FALSE, wait = TRUE)

      if (!file.exists(out_f)) return(NULL)
      df <- tryCatch(
        read.table(out_f, header = TRUE, sep = "\t",
                   col.names = c("time", "f0"), stringsAsFactors = FALSE),
        error = function(e) NULL
      )
      if (is.null(df) || nrow(df) == 0) return(NULL)

      # Construir AsspDataObj compatible con praatpicture
      # t = seq(startRecord/sampleRate, endRecord/sampleRate, by=1/sampleRate)
      rate_hz   <- as.integer(round(1 / time_step))
      start_rec <- as.integer(max(1L, round(df$time[1] * rate_hz)))
      end_rec   <- as.integer(start_rec + nrow(df) - 1L)

      obj <- list(F0 = matrix(as.numeric(df$f0), ncol = 1))
      attr(obj, "sampleRate")   <- rate_hz
      attr(obj, "startTime")    <- df$time[1]
      attr(obj, "startRecord")  <- start_rec
      attr(obj, "endRecord")    <- end_rec
      attr(obj, "trackFormats") <- "REAL32"
      attr(obj, "fileInfo")     <- c(20L, 2L)
      attr(obj, "filePath")     <- ""
      attr(obj, "origFreq")     <- 0L
      class(obj) <- "AsspDataObj"
      obj
    }, error = function(e) NULL,
    finally = { try(unlink(c(scr_f, out_f)), silent = TRUE) })
  }

  # Flag para conditionalPanel de praatpicture
  output$praatpicture_disponible_flag <- reactive({
    if (!praatpicture_disponible) return(FALSE)
    vocales <- vocales_grupo_actual()
    if (is.null(vocales) || nrow(vocales) == 0) return(FALSE)
    fn <- vocales$filename[1]
    # Solo se necesita WAV; el TextGrid se genera internamente del corte del GE
    wav_ok <- FALSE
    for (nombre in names(datos_audio$wavs)) {
      if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) { wav_ok <- TRUE; break }
    }
    if (!wav_ok && length(datos_audio$wavs) == 1) wav_ok <- TRUE
    return(wav_ok)
  })
  outputOptions(output, "praatpicture_disponible_flag", suspendWhenHidden = FALSE)

  # ── Observer: pre-generar TextGrid y WAV recortados cuando cambia el GE ───────
  # Crea un TextGrid con SOLO words y phones del hablante responsable,
  # recortado al intervalo del GE (más margen). Lo almacena en ge_tg_cached
  # para que renderPlot y los download handlers lo reutilicen sin regenerar.
  observe({
    vocales <- vocales_grupo_actual()
    if (is.null(vocales) || nrow(vocales) == 0) return()
    if (!datos$calculado) return()
    tryCatch({

    fn      <- vocales$filename[1]
    hab     <- if ("hablante" %in% colnames(vocales)) vocales$hablante[1] else NULL
    margin_s <- isolate(if (!is.null(input$praatpicture_margin_s)) input$praatpicture_margin_s else 0.05)
    t_ini_ge <- min(vocales$inicio, na.rm = TRUE)
    t_fin_ge <- max(vocales$fin,    na.rm = TRUE)
    t_ini    <- max(0, t_ini_ge - margin_s)
    t_fin    <- t_fin_ge + margin_s
    dur      <- t_fin - t_ini

    # Clave única del GE actual (evita regenerar si no ha cambiado)
    key_nuevo <- paste(fn, hab, round(t_ini, 4), round(t_fin, 4), sep = "|")
    if (!is.null(ge_tg_cached()$key) && ge_tg_cached()$key == key_nuevo) return()

    # Localizar WAV
    wav_orig <- NULL
    for (nm in names(datos_audio$wavs)) {
      if (grepl(nm, fn, fixed=TRUE) || grepl(fn, nm, fixed=TRUE)) {
        wav_orig <- datos_audio$wavs[[nm]]; break
      }
    }
    if (is.null(wav_orig) && length(datos_audio$wavs) == 1)
      wav_orig <- datos_audio$wavs[[1]]
    if (is.null(wav_orig)) return()

    # Directorio de caché persistente (se reutiliza entre renders)
    cache_dir <- file.path(tempdir(), "ge_tg_cache")
    dir.create(cache_dir, showWarnings = FALSE, recursive = TRUE)
    tmp_wav <- file.path(cache_dir, "ge_audio.wav")
    tmp_tg  <- file.path(cache_dir, "ge_audio.TextGrid")

    # ── 1. Cortar WAV ──────────────────────────────────────────────────────
    audio_ok <- tryCatch({
      if (tuneR_disponible && seewave_disponible) {
        library(tuneR); library(seewave)
        w  <- readWave(wav_orig)
        sr <- w@samp.rate
        s1 <- max(1L, round(t_ini * sr))
        s2 <- min(length(w@left), round(t_fin * sr))
        if (s1 >= s2) stop("segmento de duración cero: s1 >= s2")
        writeWave(extractWave(w, from = s1, to = s2, xunit = "samples"), tmp_wav)
        rm(w); gc(verbose = FALSE)
      } else {
        file.copy(wav_orig, tmp_wav, overwrite = TRUE)
      }
      TRUE
    }, error = function(e) {
      file.copy(wav_orig, tmp_wav, overwrite = TRUE)
      FALSE
    })

    # ── 2. Generar TextGrid desde datos$words + datos$phones ──────────────
    tg_ok <- tryCatch({
      # Filtrar words y phones del hablante y rango temporal
      w_sel <- if (!is.null(datos$words) && nrow(datos$words) > 0)
        datos$words[datos$words$filename == fn &
                      (is.null(hab) | datos$words$hablante == hab) &
                      datos$words$inicio < t_fin &
                      datos$words$fin    > t_ini, ]
      else data.frame()

      p_sel <- if (!is.null(datos$phones) && nrow(datos$phones) > 0)
        datos$phones[datos$phones$filename == fn &
                       (is.null(hab) | datos$phones$hablante == hab) &
                       datos$phones$inicio < t_fin &
                       datos$phones$fin    > t_ini, ]
      else data.frame()

      # Offset: si el WAV fue cortado, los tiempos del TG son relativos a t_ini
      off <- if (audio_ok && tuneR_disponible && seewave_disponible) t_ini else 0
      tg_dur <- if (audio_ok && tuneR_disponible && seewave_disponible) dur else t_fin

      # Helper de escritura de tier — rellena huecos con intervalos vacíos
      # para producir un TextGrid válido (Praat exige cobertura continua).
      wt <- function(idx, name, xmins, xmaxs, labels, tmax) {
        xmins <- pmax(0, xmins); xmaxs <- pmin(tmax, xmaxs)
        # Ordenar por tiempo de inicio
        if (length(xmins) > 0) {
          ord <- order(xmins)
          xmins <- xmins[ord]; xmaxs <- xmaxs[ord]; labels <- labels[ord]
        }
        # Construir secuencia completa de intervalos (con huecos vacíos)
        iv_min <- numeric(0); iv_max <- numeric(0); iv_lbl <- character(0)
        cursor <- 0
        for (j in seq_along(xmins)) {
          x0 <- max(xmins[j], cursor)   # recortar inicio si solapa con anterior
          x1 <- xmaxs[j]
          if (x0 >= x1) next            # intervalo vacío tras recorte: saltar
          if (x0 > cursor + 1e-9) {     # hay hueco antes
            iv_min <- c(iv_min, cursor)
            iv_max <- c(iv_max, x0)
            iv_lbl <- c(iv_lbl, "")
          }
          iv_min <- c(iv_min, x0)
          iv_max <- c(iv_max, x1)
          iv_lbl <- c(iv_lbl, as.character(labels[j]))
          cursor <- x1
        }
        if (cursor < tmax - 1e-9) {                # hueco final hasta tmax
          iv_min <- c(iv_min, cursor)
          iv_max <- c(iv_max, tmax)
          iv_lbl <- c(iv_lbl, "")
        }
        if (length(iv_min) == 0) {                 # tier completamente vacío
          iv_min <- 0; iv_max <- tmax; iv_lbl <- ""
        }
        n <- length(iv_min)
        l <- c(paste0('    item [', idx, ']:'),
               '        class = "IntervalTier"',
               paste0('        name = "', name, '"'),
               '        xmin = 0',
               paste0('        xmax = ', tmax),
               paste0('        intervals: size = ', n))
        for (j in seq_len(n))
          l <- c(l, paste0('        intervals [', j, ']:'),
                 paste0('            xmin = ', iv_min[j]),
                 paste0('            xmax = ', iv_max[j]),
                 paste0('            text = "',
                        gsub('"', '\\"', iv_lbl[j], fixed = TRUE), '"'))
        l
      }

      # Detectar columna de etiqueta — probar todos los nombres habituales
      encontrar_col_etiqueta <- function(df) {
        candidatos <- c("etiqueta", "text", "label", "palabra", "tier_label", "annotation")
        for (cn in candidatos)
          if (cn %in% colnames(df) && any(!is.na(df[[cn]]) & nchar(as.character(df[[cn]])) > 0))
            return(cn)
        # Si ninguno tiene valores, devolver el primero que exista aunque esté vacío
        for (cn in candidatos) if (cn %in% colnames(df)) return(cn)
        NULL
      }
      ecol_w <- encontrar_col_etiqueta(w_sel)
      ecol_p <- encontrar_col_etiqueta(p_sel)

      w_xmin <- if (nrow(w_sel) > 0) w_sel$inicio - off else numeric(0)
      w_xmax <- if (nrow(w_sel) > 0) w_sel$fin    - off else numeric(0)
      w_lbl  <- if (nrow(w_sel) > 0 && !is.null(ecol_w)) as.character(w_sel[[ecol_w]]) else character(0)

      p_xmin <- if (nrow(p_sel) > 0) p_sel$inicio - off else numeric(0)
      p_xmax <- if (nrow(p_sel) > 0) p_sel$fin    - off else numeric(0)
      p_lbl  <- if (nrow(p_sel) > 0 && !is.null(ecol_p)) as.character(p_sel[[ecol_p]]) else character(0)

      hdr <- c('File type = "ooTextFile"', 'Object class = "TextGrid"', '',
               'xmin = 0', paste0('xmax = ', tg_dur),
               'tiers? <exists>', 'size = 2', 'item []:')
      writeLines(c(hdr,
                   wt(1L, "words",  w_xmin, w_xmax, w_lbl,  tg_dur),
                   wt(2L, "phones", p_xmin, p_xmax, p_lbl,  tg_dur)),
                 tmp_tg)
      TRUE
    }, error = function(e) FALSE)

    ge_tg_cached(list(
      path     = if (tg_ok) tmp_tg else NULL,
      wav_path = tmp_wav,
      dur      = dur,
      t_ini    = t_ini,
      t_fin    = t_fin,
      key      = key_nuevo
    ))

    # Diagnóstico temporal — eliminar cuando funcione
    if (tg_ok) {
      tg_lines <- readLines(tmp_tg, warn = FALSE)
      n_texto_novacios <- sum(grepl('text = "(?!")[^"]', tg_lines, perl = TRUE))
      showNotification(
        paste0("TG generado: ", length(tg_lines), " líneas, ",
               n_texto_novacios, " etiquetas no vacías"),
        type = "message", duration = 5
      )
    }

    }, error = function(e) {
      warning("ge_tg_cached observer: ", conditionMessage(e))
    })
  })

  # UI informativa del GE en praatpicture
  output$praatpicture_ge_info_ui <- renderUI({
    vocales <- vocales_grupo_actual()
    if (is.null(vocales) || nrow(vocales) == 0) return(NULL)
    t_ini <- round(min(vocales$inicio, na.rm = TRUE), 3)
    t_fin <- round(max(vocales$fin,    na.rm = TRUE), 3)
    fn    <- vocales$filename[1]
    hab   <- if ("hablante" %in% colnames(vocales)) vocales$hablante[1] else "?"
    tagList(
      tags$small(tags$b("Archivo:"), " ", fn), tags$br(),
      tags$small(tags$b("Hablante:"), " ", hab), tags$br(),
      tags$small(tags$b("Intervalo:"), " ", t_ini, " – ", t_fin, " s")
    )
  })

  output$plot_config_praatpicture <- renderPlot({
    req(praatpicture_disponible)
    vocales <- vocales_grupo_actual()
    req(nrow(vocales) > 0)

    margin_s <- if (!is.null(input$praatpicture_margin_s)) input$praatpicture_margin_s else 0.05
    t_inicio_ge <- min(vocales$inicio, na.rm = TRUE)
    t_fin_ge    <- max(vocales$fin,    na.rm = TRUE)
    t_inicio    <- max(0, t_inicio_ge - margin_s)
    t_fin       <- t_fin_ge + margin_s
    fn          <- vocales$filename[1]

    # Localizar WAV
    wav_path <- NULL
    for (nombre in names(datos_audio$wavs)) {
      if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
        wav_path <- datos_audio$wavs[[nombre]]; break
      }
    }
    if (is.null(wav_path) && length(datos_audio$wavs) == 1) wav_path <- datos_audio$wavs[[1]]
    req(wav_path)

    # Localizar TextGrid original
    tg_path_orig <- NULL
    for (nombre in names(datos_textgrid$tgs)) {
      if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
        tg_path_orig <- datos_textgrid$tgs[[nombre]]; break
      }
    }
    if (is.null(tg_path_orig) && length(datos_textgrid$tgs) == 1) tg_path_orig <- datos_textgrid$tgs[[1]]

    hablante_ge <- if (!is.null(vocales$hablante) && length(vocales$hablante) > 0) vocales$hablante[1] else NULL
    vista_gf    <- (input$tipo_vista_grupo == "fonico")
    ge_label    <- if (vista_gf) paste0("GF", input$sel_gf) else paste0("GE", input$sel_ge)
    titulo      <- paste0("Praatpicture \u2014 ", fn, " | ", ge_label)

    # ── Usar TextGrid y WAV pre-generados por el observer ge_tg_cached ───────
    cached <- ge_tg_cached()
    tmp_wav <- if (!is.null(cached$wav_path) && file.exists(cached$wav_path)) {
      cached$wav_path
    } else {
      wav_path  # fallback: WAV completo
    }
    tmp_tg      <- if (!is.null(cached$path) && file.exists(cached$path)) cached$path else NULL
    audio_cortado <- !is.null(cached$wav_path) && file.exists(cached$wav_path)
    dur_seg       <- if (!is.null(cached$dur)) cached$dur else (t_fin - t_inicio)

    # ── Calcular rango pitch en semitonos ─────────────────────────────────────
    f0_hz_vals <- vocales$f0_media_hz[!is.na(vocales$f0_media_hz) & vocales$f0_media_hz > 0]
    if (length(f0_hz_vals) == 0) f0_hz_vals <- c(100, 300)
    pitch_min <- floor(12 * log2(min(f0_hz_vals) / 1)) - 3
    pitch_max <- ceiling(12 * log2(max(f0_hz_vals) / 1)) + 3

    # ── Frames a mostrar ──────────────────────────────────────────────────────
    show_frames <- "sound"
    show_props  <- 25L
    if (isTRUE(input$praatpicture_show_spectrogram)) { show_frames <- c(show_frames, "spectrogram"); show_props <- c(show_props, 35L) }
    if (isTRUE(input$praatpicture_show_pitch))       { show_frames <- c(show_frames, "pitch");       show_props <- c(show_props, 15L) }
    if (isTRUE(input$praatpicture_show_intensity))   { show_frames <- c(show_frames, "intensity");   show_props <- c(show_props, 15L) }
    if (!is.null(tmp_tg) && file.exists(tmp_tg))     { show_frames <- c(show_frames, "TextGrid");    show_props <- c(show_props, 20L) }
    show_props <- as.integer(round(show_props / sum(show_props) * 100))

    tryCatch({
      t_plot_ini <- if (audio_cortado) 0        else t_inicio
      t_plot_fin <- if (audio_cortado) dur_seg  else t_fin
      call_args <- list(
        sound = tmp_wav, start = t_plot_ini, end = t_plot_fin,
        frames = show_frames, proportion = show_props,
        pitch_plotType = "draw", pitch_scale = "semitones",
        pitch_semitonesRe = 1, pitch_freqRange = c(pitch_min, pitch_max),
        pitch_color = "steelblue", mainTitle = titulo
      )
      if (!is.null(tmp_tg) && file.exists(tmp_tg)) {
        call_args$tg_file      <- tmp_tg
        call_args$tg_tiers     <- c("words", "phones")
        call_args$tg_focusTier <- "words"
      }
      do.call(praatpicture::praatpicture, call_args)
    }, error = function(e) {
      plot.new()
      text(0.5, 0.5, paste("Error en praatpicture:\n", e$message), cex = 1.2, col = "red")
    })
  })

  # ── ggplot2 curva F0 en semitonos (ref = 1 Hz, escala Praat) ─────────────────
  output$plot_config_st_gg <- renderPlot({
    tryCatch({
    vocales <- vocales_grupo_actual()
    req(nrow(vocales) > 0)

    ref_hz  <- if (!is.null(input$gg_st_ref) && input$gg_st_ref > 0) input$gg_st_ref else 1
    mostrar_palabras <- isTRUE(input$gg_st_mostrar_palabras)
    mostrar_tonicas  <- isTRUE(input$gg_st_mostrar_tonicas)
    colorear_ge      <- isTRUE(input$gg_st_mostrar_ge)

    # Calcular F0 en semitonos con ref = ref_hz
    vocales$f0_st_plot <- ifelse(
      is.na(vocales$f0_media_hz) | vocales$f0_media_hz <= 0, NA_real_,
      12 * log2(vocales$f0_media_hz / ref_hz)
    )

    # Centro temporal relativo al inicio del grupo
    t0 <- min(vocales$inicio, na.rm = TRUE)
    vocales$t_rel <- vocales$inicio + (vocales$fin - vocales$inicio) / 2 - t0

    vista_gf <- (!is.null(input$tipo_vista_grupo) && input$tipo_vista_grupo == "fonico")
    titulo_st <- if (vista_gf)
      paste0("F0 (semitonos, ref=", ref_hz, " Hz) \u2014 ", input$sel_filename_cm, " | GF", input$sel_gf)
    else
      paste0("F0 (semitonos, ref=", ref_hz, " Hz) \u2014 ", input$sel_filename_cm, " | GE", input$sel_ge)

    vocales_plot <- vocales[!is.na(vocales$f0_st_plot), ]
    if (nrow(vocales_plot) == 0) {
      return(ggplot() + geom_blank() +
               ggtitle("Sin datos F0 disponibles para este grupo") +
               theme_minimal())
    }

    # Rango Y con margen para etiquetas de palabras
    st_vals  <- vocales_plot$f0_st_plot
    y_rango  <- diff(range(st_vals, na.rm = TRUE))
    if (y_rango == 0) y_rango <- 2   # grupo con un solo valor: expandir eje ±1
    y_min    <- min(st_vals, na.rm = TRUE) - y_rango * 0.05
    y_max    <- max(st_vals, na.rm = TRUE) + y_rango * 0.18   # margen superior para labels

    if (colorear_ge && "grupo_entonativo" %in% colnames(vocales_plot)) {
      vocales_plot$ge_factor <- factor(vocales_plot$grupo_entonativo)
      p <- ggplot(vocales_plot, aes(x = t_rel, y = f0_st_plot,
                                    color = ge_factor, group = ge_factor)) +
        geom_line(linewidth = 1.2) +
        geom_point(size = 3) +
        labs(color = "Grupo entonativo")
    } else {
      p <- ggplot(vocales_plot, aes(x = t_rel, y = f0_st_plot, group = 1L)) +
        geom_line(color = "steelblue", linewidth = 1.2) +
        geom_point(color = "steelblue", size = 3)
    }

    p <- p +
      scale_x_continuous("Tiempo relativo (s)") +
      scale_y_continuous(paste0("F0 (St, ref=", ref_hz, " Hz)")) +
      coord_cartesian(ylim = c(y_min, y_max)) +
      ggtitle(titulo_st) +
      theme_minimal(base_size = 13) +
      theme(legend.position = if (colorear_ge) "bottom" else "none",
            plot.title = element_text(size = 11, face = "bold"),
            panel.grid.minor = element_blank())

    # Marcar t\u00f3nicas
    if (mostrar_tonicas && "tonica_gramatical" %in% colnames(vocales_plot)) {
      tonicas <- vocales_plot[!is.na(vocales_plot$f0_st_plot) &
                              !is.na(vocales_plot$tonica_gramatical) &
                              vocales_plot$tonica_gramatical == "s\u00ed", ]
      if (nrow(tonicas) > 0) {
        p <- p + geom_point(data = tonicas, aes(x = t_rel, y = f0_st_plot),
                            color = "red", shape = 17, size = 4.5, inherit.aes = FALSE)
      }
    }

    # L\u00edneas de frontera de palabras + etiquetas
    if (mostrar_palabras && "palabra" %in% colnames(vocales_plot)) {
      palabras_unicas <- vocales_plot[!duplicated(vocales_plot$palabra), ]
      if (nrow(palabras_unicas) > 1) {
        t_fronteras <- palabras_unicas$t_rel[-1]
        p <- p + geom_vline(xintercept = t_fronteras,
                            linetype = "dashed", color = "gray60", linewidth = 0.5)
        mid_palabras <- tapply(vocales_plot$t_rel, vocales_plot$palabra, mean, na.rm = TRUE)
        lab_y <- max(st_vals, na.rm = TRUE) + y_rango * 0.10
        lab_df <- data.frame(
          t_rel   = as.numeric(mid_palabras),
          palabra = names(mid_palabras),
          y       = lab_y
        )
        p <- p + geom_text(data = lab_df, aes(x = t_rel, y = y, label = palabra),
                           size = 3.2, color = "gray30", inherit.aes = FALSE, vjust = 0)
      }
    }

    p
    }, error = function(e) {
      ggplot() + geom_blank() +
        labs(title = paste("Error en gráfico F0:", conditionMessage(e))) +
        theme_minimal()
    })
  })

  output$gg_st_descargar <- downloadHandler(
    filename = function() paste0("f0_st_", format(Sys.time(), "%Y%m%d_%H%M"), ".png"),
    content  = function(file) {
      p_plot <- tryCatch(
        local({
          vocales <- vocales_grupo_actual()
          req(nrow(vocales) > 0)
          ref_hz <- if (!is.null(input$gg_st_ref) && input$gg_st_ref > 0) input$gg_st_ref else 1
          vocales$f0_st_plot <- ifelse(is.na(vocales$f0_media_hz) | vocales$f0_media_hz <= 0,
                                       NA_real_, 12 * log2(vocales$f0_media_hz / ref_hz))
          t0 <- min(vocales$inicio, na.rm = TRUE)
          vocales$t_rel <- vocales$inicio + (vocales$fin - vocales$inicio) / 2 - t0
          ggplot(vocales[!is.na(vocales$f0_st_plot), ],
                 aes(x = t_rel, y = f0_st_plot)) +
            geom_line(color = "steelblue", linewidth = 1.2) +
            geom_point(color = "steelblue", size = 3) +
            scale_x_continuous("Tiempo relativo (s)") +
            scale_y_continuous(paste0("F0 (St, ref=", ref_hz, " Hz)")) +
            ggtitle(paste0("F0 en semitonos — ref=", ref_hz, " Hz")) +
            theme_minimal(base_size = 14)
        }),
        error = function(e) ggplot() + geom_blank() + ggtitle(paste("Error:", e$message))
      )
      ggplot2::ggsave(file, plot = p_plot, width = 10, height = 5, dpi = 300)
    }
  )

  # ── Helper interno: exportar widget Plotly a PNG via webshot2 ────────────────
  .export_plotly_png <- function(fig, file, width = 1200, height = 600) {
    tmp_html <- tempfile(fileext = ".html")
    on.exit(unlink(tmp_html), add = TRUE)
    htmlwidgets::saveWidget(fig, tmp_html, selfcontained = TRUE)
    webshot2::webshot(tmp_html, file = file, vwidth = width, vheight = height,
                      delay = 0.5, zoom = 1.5)
  }

