  # ── Descargar PNG de Praatpicture ────────────────────────────────────────────
  output$praatpicture_descargar_png <- downloadHandler(
    filename = function() paste0("praatpicture_", format(Sys.time(), "%Y%m%d_%H%M"), ".png"),
    content  = function(file) {
      tryCatch({
        vocales <- vocales_grupo_actual()
        req(nrow(vocales) > 0)
        cached  <- ge_tg_cached()
        wav_path <- if (!is.null(cached$wav_path) && file.exists(cached$wav_path)) {
          cached$wav_path
        } else {
          fn <- vocales$filename[1]
          wp <- NULL
          for (nombre in names(datos_audio$wavs)) {
            if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
              wp <- datos_audio$wavs[[nombre]]; break
            }
          }
          if (is.null(wp) && length(datos_audio$wavs) == 1) wp <- datos_audio$wavs[[1]]
          wp
        }
        req(wav_path)
        dur_seg <- if (!is.null(cached$dur)) cached$dur else NULL
        t_ini_p <- 0
        t_fin_p <- if (!is.null(dur_seg)) dur_seg else {
          margin_s <- if (!is.null(input$praatpicture_margin_s)) input$praatpicture_margin_s else 0.05
          max(vocales$fin, na.rm = TRUE) - max(0, min(vocales$inicio, na.rm = TRUE) - margin_s) + margin_s
        }
        tmp_tg <- if (!is.null(cached$path) && file.exists(cached$path)) cached$path else NULL

        f0_hz_vals <- vocales$f0_media_hz[!is.na(vocales$f0_media_hz) & vocales$f0_media_hz > 0]
        if (length(f0_hz_vals) == 0) f0_hz_vals <- c(100, 300)
        pitch_min <- floor(12 * log2(min(f0_hz_vals) / 1)) - 3
        pitch_max <- ceiling(12 * log2(max(f0_hz_vals) / 1)) + 3

        show_frames <- "sound"
        show_props  <- 25L
        if (isTRUE(input$praatpicture_show_spectrogram)) { show_frames <- c(show_frames, "spectrogram"); show_props <- c(show_props, 35L) }
        if (isTRUE(input$praatpicture_show_pitch))       { show_frames <- c(show_frames, "pitch");       show_props <- c(show_props, 15L) }
        if (isTRUE(input$praatpicture_show_intensity))   { show_frames <- c(show_frames, "intensity");   show_props <- c(show_props, 15L) }
        if (!is.null(tmp_tg) && file.exists(tmp_tg))     { show_frames <- c(show_frames, "TextGrid");    show_props <- c(show_props, 20L) }
        show_props <- as.integer(round(show_props / sum(show_props) * 100))

        call_args <- list(
          sound = wav_path, start = t_ini_p, end = t_fin_p,
          frames = show_frames, proportion = show_props,
          pitch_plotType = "draw", pitch_scale = "semitones",
          pitch_semitonesRe = 1, pitch_freqRange = c(pitch_min, pitch_max),
          pitch_color = "steelblue"
        )
        if (!is.null(tmp_tg) && file.exists(tmp_tg)) {
          call_args$tg_file      <- tmp_tg
          call_args$tg_tiers     <- c("words", "phones")
          call_args$tg_focusTier <- "words"
        }
        png(file, width = 1200, height = 700, res = 150)
        do.call(praatpicture::praatpicture, call_args)
        dev.off()
      }, error = function(e) {
        png(file, width = 800, height = 400)
        plot.new(); text(0.5, 0.5, paste("Error:", e$message), cex = 1.2, col = "red")
        dev.off()
      })
    }
  )

  # ── Descargar TextGrid del GE actual (words + phones del hablante) ────────────
  output$praatpicture_descargar_tg <- downloadHandler(
    filename = function() paste0("ge_", format(Sys.time(), "%Y%m%d_%H%M"), ".TextGrid"),
    content  = function(file) {
      cached <- ge_tg_cached()
      if (!is.null(cached$path) && file.exists(cached$path)) {
        file.copy(cached$path, file, overwrite = TRUE)
      } else {
        writeLines("# TextGrid no disponible: visualiza el grupo primero.", file)
      }
    }
  )

  # ── Descargar audio cortado de Praatpicture ──────────────────────────────────
  output$praatpicture_descargar_audio <- downloadHandler(
    filename = function() paste0("audio_ge_", format(Sys.time(), "%Y%m%d_%H%M"), ".wav"),
    content  = function(file) {
      tryCatch({
        vocales <- vocales_grupo_actual()
        req(nrow(vocales) > 0)
        margin_s <- if (!is.null(input$praatpicture_margin_s)) input$praatpicture_margin_s else 0.05
        t_inicio <- max(0, min(vocales$inicio, na.rm = TRUE) - margin_s)
        t_fin    <- max(vocales$fin, na.rm = TRUE) + margin_s
        fn       <- vocales$filename[1]
        wav_path <- NULL
        for (nombre in names(datos_audio$wavs)) {
          if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
            wav_path <- datos_audio$wavs[[nombre]]; break
          }
        }
        if (is.null(wav_path) && length(datos_audio$wavs) == 1) wav_path <- datos_audio$wavs[[1]]
        req(wav_path)
        if (tuneR_disponible && seewave_disponible) {
          library(tuneR); library(seewave)
          w_full <- readWave(wav_path)
          sr     <- w_full@samp.rate
          s_ini  <- max(1L, round(t_inicio * sr))
          s_fin  <- min(length(w_full@left), round(t_fin * sr))
          w_cut  <- extractWave(w_full, from = s_ini, to = s_fin, xunit = "samples")
          writeWave(w_cut, file)
        } else {
          file.copy(wav_path, file, overwrite = TRUE)
        }
      }, error = function(e) {
        writeLines(paste("Error:", e$message), file)
      })
    }
  )

  tabla_vocales_df <- reactiveVal(NULL)

  output$tabla_vocales_grupo <- renderDT({
    vocales <- vocales_grupo_actual()
    req(nrow(vocales) > 0)
    # Columnas base siempre visibles
    cols_base <- c("etiqueta","palabra","inicio","fin","duracion",
                   "f0_media_hz","int_media",
                   "tonica_gramatical","es_pico_grupo","es_pico_palabra","seccion_ip",
                   "tobi_fonetico","tobi_fonologico")
    # Columnas extra seleccionadas por el usuario
    cols_extra <- if (!is.null(input$vocales_grupo_cols_extra)) input$vocales_grupo_cols_extra else character(0)
    cols_sel <- unique(c(cols_base, cols_extra))
    cols_sel <- intersect(cols_sel, colnames(vocales))
    # amh_patron vive en ips_resumen (nivel GE), no en phones (nivel vocal)
    # Lo unimos manualmente cuando el usuario lo solicita
    if ("amh_patron" %in% cols_extra && !is.null(datos$ips_resumen)) {
      fn_sel   <- input$sel_filename_cm
      hab_sel  <- input$sel_hablante_cm
      gf_sel   <- as.numeric(input$sel_gf)
      ge_sel   <- if (input$tipo_vista_grupo == "entonativo") as.numeric(input$sel_ge) else NULL
      ip_row <- datos$ips_resumen[
        datos$ips_resumen$filename         == fn_sel  &
        datos$ips_resumen$hablante         == hab_sel &
        datos$ips_resumen$grupo_fonico     == gf_sel,
      ]
      if (!is.null(ge_sel)) ip_row <- ip_row[ip_row$grupo_entonativo == ge_sel, ]
      patron_val <- if (nrow(ip_row) > 0 && "amh_patron" %in% colnames(ip_row))
                      as.character(ip_row$amh_patron[1]) else NA_character_
      # Añadir como columna repetida (igual para todas las vocales del GE)
      vocales$amh_patron <- patron_val
      cols_sel <- unique(c(cols_sel, "amh_patron"))
    }
    df_show <- vocales[, cols_sel, drop = FALSE]
    # Añadir columnas de relativización sobre 100 (base = primera vocal)
    if (isTRUE(input$vocales_grupo_rel100)) {
      rel100 <- function(v) {
        ref <- v[!is.na(v) & v > 0][1]
        if (is.na(ref) || ref == 0) return(rep(NA_real_, length(v)))
        round((v / ref) * 100, 1)
      }
      if ("f0_media_hz" %in% colnames(df_show)) {
        pos_f0 <- which(colnames(df_show) == "f0_media_hz")
        df_show <- cbind(
          df_show[, seq_len(pos_f0), drop = FALSE],
          f0_rel_100 = rel100(df_show$f0_media_hz),
          df_show[, if (pos_f0 < ncol(df_show)) seq(pos_f0 + 1, ncol(df_show)) else integer(0), drop = FALSE]
        )
      }
      if ("int_media" %in% colnames(df_show)) {
        pos_int <- which(colnames(df_show) == "int_media")
        df_show <- cbind(
          df_show[, seq_len(pos_int), drop = FALSE],
          int_rel_100 = rel100(df_show$int_media),
          df_show[, if (pos_int < ncol(df_show)) seq(pos_int + 1, ncol(df_show)) else integer(0), drop = FALSE]
        )
      }
      if ("tiempo_transicion_anterior" %in% colnames(df_show)) {
        pos_tr <- which(colnames(df_show) == "tiempo_transicion_anterior")
        df_show <- cbind(
          df_show[, seq_len(pos_tr), drop = FALSE],
          trans_rel_100 = rel100(df_show$tiempo_transicion_anterior),
          df_show[, if (pos_tr < ncol(df_show)) seq(pos_tr + 1, ncol(df_show)) else integer(0), drop = FALSE]
        )
      }
    }
    nums <- sapply(df_show, is.numeric)
    df_show[nums] <- lapply(df_show[nums], function(x) round(x, 3))
    tabla_vocales_df(df_show)
    # Columnas editables: tonica_gramatical, seccion_ip, tobi_fonetico, tobi_fonologico, amh_patron
    editable_cols <- intersect(
      c("tonica_gramatical", "seccion_ip", "tobi_fonetico", "tobi_fonologico", "amh_patron"),
      colnames(df_show)
    )
    editable_idx <- which(colnames(df_show) %in% editable_cols) - 1L  # DT usa índice 0-based
    non_edit_idx <- setdiff(seq_len(ncol(df_show)) - 1L, editable_idx)
    datatable(df_show,
      editable = list(target = "cell", disable = list(columns = non_edit_idx)),
      options  = list(scrollX = TRUE, pageLength = 20)
    )
  })

  # ── Guardar ediciones de la tabla de vocales ─────────────────────────────
  observeEvent(input$tabla_vocales_grupo_cell_edit, {
    info <- input$tabla_vocales_grupo_cell_edit
    df   <- tabla_vocales_df()
    req(!is.null(df), nrow(df) > 0)

    row_idx <- info$row
    col_nm  <- colnames(df)[info$col + 1L]  # DT usa índice 0-based para col
    new_val <- info$value

    # Validar que la columna es editable
    editable_cols_edit <- c("tonica_gramatical", "seccion_ip",
                            "tobi_fonetico", "tobi_fonologico", "amh_patron")
    if (!col_nm %in% editable_cols_edit) return()

    fn_sel  <- input$sel_filename_cm
    hab_sel <- input$sel_hablante_cm
    gf_sel  <- as.numeric(input$sel_gf)
    ge_sel  <- if (!is.null(input$sel_ge)) as.numeric(input$sel_ge) else NA_real_

    if (col_nm == "amh_patron") {
      # amh_patron vive en ips_resumen (nivel GE)
      req(!is.null(datos$ips_resumen))
      mask <- datos$ips_resumen$filename == fn_sel &
              datos$ips_resumen$hablante  == hab_sel &
              datos$ips_resumen$grupo_fonico == gf_sel
      if (!is.na(ge_sel)) mask <- mask & datos$ips_resumen$grupo_entonativo == ge_sel
      datos$ips_resumen$amh_patron[mask] <- as.character(new_val)
      guardar_analisis_por_archivo(fn_sel)
      showNotification(paste0("amh_patron actualizado → '", new_val, "'"), type = "message", duration = 3)

    } else {
      # El resto vive en phones (nivel vocal)
      req(!is.null(datos$phones))
      # Identificar la vocal por su posición dentro del GE actual
      ph_ge <- datos$phones[
        datos$phones$filename         == fn_sel  &
        datos$phones$hablante         == hab_sel &
        datos$phones$grupo_fonico     == gf_sel,
      ]
      if (!is.na(ge_sel)) ph_ge <- ph_ge[ph_ge$grupo_entonativo == ge_sel, ]
      ph_ge <- ph_ge[order(ph_ge$inicio), ]

      if (row_idx < 1 || row_idx > nrow(ph_ge)) return()
      target_row <- rownames(ph_ge)[row_idx]

      # Actualizar valor
      old_val <- datos$phones[target_row, col_nm]
      datos$phones[target_row, col_nm] <- if (col_nm == "tonica_gramatical")
        as.logical(new_val) else as.character(new_val)

      needs_recalc <- col_nm %in% c("tonica_gramatical", "seccion_ip")
      if (needs_recalc) {
        # Recalcular GE/GF/palabras/cláusula desde phones
        recalcular_ges_desde_phones(solo_archivo = fn_sel, recalc_clausulas = TRUE)
        showNotification(paste0(col_nm, " actualizado → GEs recalculados"), type = "message", duration = 4)
      } else {
        guardar_analisis_por_archivo(fn_sel)
        showNotification(paste0(col_nm, " actualizado → '", new_val, "'"), type = "message", duration = 3)
      }
    }
  })

  # Comparativo GFs
  observe({
  req(datos$calculado, datos$gfs_resumen)
  fns <- sort(unique(datos$gfs_resumen$filename))
  updateSelectInput(session, "gfs_filtro_archivo", choices = fns, selected = fns[1])
})

observe({
  req(datos$calculado, datos$gfs_resumen, input$gfs_filtro_archivo)
  habs <- sort(unique(datos$gfs_resumen$hablante[
    datos$gfs_resumen$filename == input$gfs_filtro_archivo
  ]))
  updateSelectInput(session, "gfs_filtro_hablante",
                    choices = c("Todos" = "__todos__", habs),
                    selected = if (length(habs) == 1) habs[1] else "__todos__")
})

output$plot_comparativo_gfs <- renderPlotly({
  req(datos$calculado, datos$gfs_resumen, input$gfs_filtro_archivo)

  gfs <- datos$gfs_resumen %>%
    filter(filename == input$gfs_filtro_archivo)

  if (!is.null(input$gfs_filtro_hablante) &&
      input$gfs_filtro_hablante != "__todos__") {
    gfs <- gfs %>% filter(hablante == input$gfs_filtro_hablante)
  }

  if (nrow(gfs) == 0) return(NULL)

  gfs$id_label <- paste0("GF", gfs$grupo_fonico, " [", gfs$hablante, "]")

  p <- ggplot(gfs, aes(x = id_label, y = f0_media_gf_st, fill = hablante)) +
    geom_col(alpha = 0.7) +
    geom_errorbar(aes(ymin = f0_min_gf_st, ymax = f0_max_gf_st), width = 0.3) +
    labs(x = "Grupo Fónico", y = "F0 media (St)",
         title = paste0("Comparativa GFs — ", input$gfs_filtro_archivo)) +
    theme_minimal() +
    theme(axis.text.x = element_text(angle = 45, hjust = 1))

  ggplotly(p)
})
  
