  output$descargar_phones <- downloadHandler(
    filename = function() paste0("phones_", Sys.Date(), ".csv"),
    content = function(file) {
      df <- datos$phones; nums <- sapply(df, is.numeric)
      df[nums] <- lapply(df[nums], function(x) round(x, 2))
      write.csv(df, file, row.names = FALSE)
    }
