  # ========================================
  # UDPIPE: ANÁLISIS MORFOSINTÁCTICO
  # ========================================
  output$udpipe_realizado <- reactive({ !is.null(datos$udpipe_words) })
  outputOptions(output, "udpipe_realizado", suspendWhenHidden = FALSE)

  # Shared UDPipe runner — called from checkbox, from tab "Completar", or legacy btn_udpipe
  ejecutar_udpipe <- function() {
    if (!datos$calculado || is.null(datos$words)) {
      showNotification("Primero calcula o carga un an\u00e1lisis.", type = "warning"); return()
    }
    if (!udpipe_disponible) {
      showNotification("Instala el paquete udpipe: install.packages('udpipe')", type = "error"); return()
    }
    # Delegate to the existing btn_udpipe observeEvent body by simulating its code inline
    isolate({
      tryCatch(
        withProgress(message = "Lanzando UDPipe...", value = 0, {
          # Body identical to btn_udpipe observeEvent below — kept DRY via this wrapper
          # The actual heavy logic stays in the btn_udpipe observer for backwards compat
          session$sendCustomMessage("lasp_run_udpipe", list())
        }),
        error = function(e) showNotification(paste("Error UDPipe:", e$message), type = "error")
      )
    })
  }

  # Checkbox: run after calcular completes
  observeEvent(input$usar_udpipe, {
    if (isTRUE(input$usar_udpipe) && isTRUE(datos$calculado)) ejecutar_udpipe()
  })

  observeEvent(input$btn_udpipe, {
    req(datos$calculado, datos$words)
    if (!udpipe_disponible) {
      showNotification("Instala el paquete udpipe: install.packages('udpipe')", type = "error")
      return()
    }
    
    withProgress(message = 'Análisis UDPIPE...', value = 0, {
      tryCatch({
        library(udpipe)
        
        # Determinar modelo según idioma
        modelo_lang <- if (input$idioma == "Español") "spanish" else "catalan"
        modelo_nombre <- if (input$idioma == "Español") "spanish-ancora" else "catalan-ancora"
        
        # Buscar o descargar modelo
        modelo_path <- list.files(pattern = paste0(modelo_nombre, ".*\\.udpipe$"), recursive = FALSE)
        if (length(modelo_path) == 0) {
          incProgress(0.1, detail = "Descargando modelo...")
          modelo_path <- udpipe_download_model(language = modelo_nombre, model_dir = ".")$file_model
        } else {
          modelo_path <- modelo_path[1]
        }
        
        incProgress(0.2, detail = "Cargando modelo...")
        udmodel <- udpipe_load_model(file = modelo_path)
        
        # Obtener textos únicos por hablante
        words <- datos$words
        
        # Construir texto por hablante+filename para procesamiento eficiente
        grupos_texto <- unique(words[, c("hablante", "filename")])
        
        all_udpipe <- data.frame()
        
        for (i in 1:nrow(grupos_texto)) {
          spk <- grupos_texto$hablante[i]
          fn <- grupos_texto$filename[i]
          
          words_spk <- words[words$hablante == spk & words$filename == fn, ]
          words_spk <- words_spk[order(words_spk$tmin), ]
          
          # Texto continuo
          texto_raw <- paste(words_spk$etiqueta[!is.na(words_spk$etiqueta) & words_spk$etiqueta != ""], collapse = " ")
          
          if (nchar(texto_raw) == 0) next
          
          incProgress(0.3 / nrow(grupos_texto), detail = paste0("Procesando ", spk, "..."))
          
          ann <- udpipe_annotate(udmodel, x = texto_raw)
          ann_df <- as.data.frame(ann)
          
          ann_df$hablante <- spk
          ann_df$filename <- fn
          
          all_udpipe <- bind_rows(all_udpipe, ann_df)
        }
        
        incProgress(0.2, detail = "Propagando a phones y words...")
        
        # Guardar resultado UDPIPE
        datos$udpipe_words <- all_udpipe
        
        # Propagar a words: match por token (palabra)
        if (nrow(all_udpipe) > 0 && nrow(words) > 0) {
          words$upos <- NA_character_
          words$xpos <- NA_character_
          words$feats <- NA_character_
          words$dep_rel <- NA_character_
          words$lemma <- NA_character_
          
          for (spk in unique(all_udpipe$hablante)) {
            for (fn in unique(all_udpipe$filename[all_udpipe$hablante == spk])) {
              udp_sub <- all_udpipe[all_udpipe$hablante == spk & all_udpipe$filename == fn, ]
              w_sub_idx <- which(words$hablante == spk & words$filename == fn)
              
              if (length(w_sub_idx) == 0 || nrow(udp_sub) == 0) next
              
              # Match secuencial: las palabras en words y en udpipe deberían estar en el mismo orden
              udp_tokens <- udp_sub[udp_sub$upos != "PUNCT", ]
              w_palabras <- words$etiqueta[w_sub_idx]
              
              # Intentar match posicional (suele funcionar si el tokenizer no divide palabras)
              n_match <- min(nrow(udp_tokens), length(w_palabras))
              for (j in 1:n_match) {
                w_idx <- w_sub_idx[j]
                words$upos[w_idx] <- udp_tokens$upos[j]
                words$xpos[w_idx] <- udp_tokens$xpos[j]
                words$feats[w_idx] <- udp_tokens$feats[j]
                words$dep_rel[w_idx] <- udp_tokens$dep_rel[j]
                words$lemma[w_idx] <- udp_tokens$lemma[j]
              }
            }
          }
          
          datos$words <- words
          
          # Propagar a phones
          phones <- datos$phones
          if (!is.null(phones) && nrow(phones) > 0) {
            phones$upos <- NA_character_
            phones$xpos <- NA_character_
            phones$feats <- NA_character_
            phones$dep_rel <- NA_character_
            phones$lemma <- NA_character_
            
            for (idx in 1:nrow(phones)) {
              pal <- phones$palabra[idx]
              spk <- phones$hablante[idx]
              fn <- phones$filename[idx]
              if (is.na(pal) || pal == "") next
              
              # Buscar la palabra en words
              w_match <- which(words$etiqueta == pal & words$hablante == spk & 
                                 words$filename == fn & !is.na(words$upos))
              if (length(w_match) > 0) {
                phones$upos[idx] <- words$upos[w_match[1]]
                phones$xpos[idx] <- words$xpos[w_match[1]]
                phones$feats[idx] <- words$feats[w_match[1]]
                phones$dep_rel[idx] <- words$dep_rel[w_match[1]]
                phones$lemma[idx] <- words$lemma[w_match[1]]
              }
            }
            
            datos$phones <- phones
          }
          
          # Propagar a IPs y GFs
          if (!is.null(datos$ips_resumen) && nrow(datos$ips_resumen) > 0) {
            ips <- datos$ips_resumen
            ips$categorias_upos <- NA_character_
            
            for (i in 1:nrow(ips)) {
              spk <- ips$hablante[i]
              fn <- ips$filename[i]
              gf_v <- ips$grupo_fonico[i]
              ge_v <- ips$grupo_entonativo[i]
              
              ph_ge <- phones[phones$hablante == spk & phones$filename == fn &
                                phones$grupo_fonico == gf_v & phones$grupo_entonativo == ge_v, ]
              upos_vals <- unique(ph_ge$upos[!is.na(ph_ge$upos)])
              ips$categorias_upos[i] <- paste(upos_vals, collapse = ", ")
            }
            datos$ips_resumen <- corregir_semitones_si_necesario(ips)
          }
        }
        
        incProgress(0.1, detail = "Completado")
        
        # Computar densidad UPOS en grupos automáticamente
        computar_upos_densidad()

        datos$analisis_morfosintactico <- TRUE
        log_event("UDPIPE_COMPLETADO", paste0(nrow(datos$udpipe_words), " tokens"))
        guardar_todos_por_archivo(notificar_cada = FALSE)
        showModal(modalDialog(
          title = tagList(icon("check-circle", class = "text-success"), " UDPipe completado"),
          paste0("An\u00e1lisis morfosint\u00e1ctico completado: ",
                 nrow(datos$udpipe_words), " tokens. Datos guardados."),
          easyClose = TRUE, footer = modalButton("Cerrar")
        ))
        
      }, error = function(e) {
        showNotification(paste("Error UDPIPE:", e$message), type = "error")
      })
    })
  })
  
  output$tabla_udpipe <- DT::renderDT({
    req(datos$udpipe_words)
    df <- datos$udpipe_words[, c("sentence_id", "token", "lemma", "upos", "xpos", "feats", "dep_rel", "hablante", "filename")]
    DT::datatable(df, options = list(pageLength = 25, scrollX = TRUE), filter = "top")
  })
  
  output$plot_pos_dist <- renderPlotly({
    req(datos$udpipe_words)
    df <- datos$udpipe_words
    conteo <- as.data.frame(table(df$upos, df$hablante))
    names(conteo) <- c("UPOS", "Hablante", "Freq")
    p <- ggplot(conteo[conteo$Freq > 0, ], aes(x = reorder(UPOS, -Freq), y = Freq, fill = Hablante)) +
      geom_col(position = "dodge") +
      labs(title = "Distribución de categorías gramaticales (UPOS)", x = "Categoría", y = "Frecuencia") +
      theme_minimal() + theme(axis.text.x = element_text(angle = 45, hjust = 1))
    ggplotly(p)
  })
  
  output$tabla_phones_udpipe <- DT::renderDT({
    req(datos$phones, datos$udpipe_words)
    ph <- datos$phones
    if (!"upos" %in% colnames(ph)) return(NULL)
    cols <- c("filename", "hablante", "etiqueta", "palabra", "upos", "xpos", "lemma", "dep_rel",
              "f0_media_hz", "f0_media_st", "int_media", "grupo_fonico", "grupo_entonativo")
    cols <- intersect(cols, colnames(ph))
    DT::datatable(ph[, cols], options = list(pageLength = 25, scrollX = TRUE), filter = "top")
  })
  
  # ========================================
  # AUDIO: Carga y reproducción de segmentos
  # ========================================
  datos_audio <- reactiveValues(wavs = list())
  datos_textgrid <- reactiveValues(tgs = list())
  
  observeEvent(input$archivos_audio, {
    req(input$archivos_audio)
    archivos <- input$archivos_audio
    for (i in 1:nrow(archivos)) {
      nombre <- tools::file_path_sans_ext(archivos$name[i])
      datos_audio$wavs[[nombre]] <- archivos$datapath[i]
      # Copiar a almacenamiento persistente
      copiar_audio_persistente(archivos$datapath[i], archivos$name[i])
    }
    showNotification(paste(nrow(archivos), "archivo(s) de audio cargados y almacenados"), type = "message")
  })
  
  observeEvent(input$archivos_textgrid, {
    req(input$archivos_textgrid)
    archivos <- input$archivos_textgrid
    for (i in 1:nrow(archivos)) {
      nombre <- tools::file_path_sans_ext(archivos$name[i])
      datos_textgrid$tgs[[nombre]] <- archivos$datapath[i]
      # Copiar a almacenamiento persistente
      copiar_textgrid_persistente(archivos$datapath[i], archivos$name[i])
    }
    showNotification(paste(nrow(archivos), "TextGrid(s) cargados y almacenados"), type = "message")
  })
  
  # ========================================
  # PRAAT: Preprocesado automático desde wav + TextGrid
  # ========================================
  praat_archivos <- reactiveValues(wavs = list(), tgs = list())
  
  observeEvent(input$praat_wav_files, {
    req(input$praat_wav_files)
    archivos <- input$praat_wav_files
    for (i in 1:nrow(archivos)) {
      nombre <- tools::file_path_sans_ext(archivos$name[i])
      praat_archivos$wavs[[nombre]] <- archivos$datapath[i]
      copiar_audio_persistente(archivos$datapath[i], archivos$name[i])
    }
    showNotification(paste(nrow(archivos), "WAV cargado(s) para Praat"), type = "message")
  })
  
  observeEvent(input$praat_tg_files, {
    req(input$praat_tg_files)
    archivos <- input$praat_tg_files
    for (i in 1:nrow(archivos)) {
      nombre <- tools::file_path_sans_ext(archivos$name[i])
      praat_archivos$tgs[[nombre]] <- archivos$datapath[i]
      copiar_textgrid_persistente(archivos$datapath[i], archivos$name[i])
    }
    showNotification(paste(nrow(archivos), "TextGrid cargado(s) para Praat"), type = "message")
  })
  
  output$praat_estado <- renderPrint({
    n_wav <- length(praat_archivos$wavs)
    n_tg <- length(praat_archivos$tgs)
    if (n_wav == 0 && n_tg == 0) {
      cat("Sube archivos .wav y .TextGrid con el mismo nombre base.\n")
    } else {
      cat(n_wav, "WAV y", n_tg, "TextGrid cargados.\n")
      comunes <- intersect(names(praat_archivos$wavs), names(praat_archivos$tgs))
      if (length(comunes) > 0) {
        cat("Pares detectados:", paste(comunes, collapse = ", "), "\n")
      } else {
        cat("⚠ No se encontraron pares coincidentes.\n")
      }
    }
  })
  
  observeEvent(input$btn_praat_procesar, {
    comunes <- intersect(names(praat_archivos$wavs), names(praat_archivos$tgs))
    if (length(comunes) == 0) {
      showNotification("No hay pares wav/TextGrid con el mismo nombre", type = "error")
      return()
    }
    
    # Detectar Praat
    praat_bin <- Sys.which("praat")
    if (praat_bin == "") {
      # Buscar en ubicaciones comunes
      praat_candidates <- c(
        "/usr/bin/praat", "/usr/local/bin/praat",
        "/Applications/Praat.app/Contents/MacOS/Praat",
        "C:/Program Files/Praat/Praat.exe",
        file.path(Sys.getenv("HOME"), "Praat")
      )
      for (pc in praat_candidates) {
        if (file.exists(pc)) { praat_bin <- pc; break }
      }
    }
    
    if (praat_bin == "" || !file.exists(praat_bin)) {
      showNotification("No se encontró Praat. Asegúrate de que está instalado y en el PATH.", type = "error", duration = 10)
      return()
    }
    
    withProgress(message = "Ejecutando Praat...", value = 0, {
      tmpdir <- tempdir()
      out_dir <- file.path(tmpdir, "praat_output")
      dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
      
      # Generar script Praat
      script_content <- sprintf('
# Script generado por LASP
for i from 1 to number_of_files
  selectObject: list_wav
  fileName$ = Get string: i
  baseName$ = fileName$ - ".wav"
  
  sound = Read from file: dirInput$ + "/" + fileName$
  
  # Pitch
  selectObject: sound
  pitch = To Pitch (ac): %f, %f, 15, "no", 0.03, 0.45, 0.01, 0.35, 0.14, %f
  nFramesP = Get number of frames
  outPitch$ = dirOutput$ + "/" + baseName$ + "_pitch.txt"
  writeFileLine: outPitch$, "Tiempo(s)", tab$, "F0(Hz)"
  for p from 1 to nFramesP
    valF0 = Get value in frame: p, "Hertz"
    if valF0 <> undefined
      timeP = Get time from frame: p
      appendFileLine: outPitch$, fixed$(timeP, 4), tab$, fixed$(valF0, 2)
    endif
  endfor
  selectObject: pitch
  Remove
  
  # Intensidad
  selectObject: sound
  intensity = To Intensity: %f, %f, "yes"
  nFramesI = Get number of frames
  outInt$ = dirOutput$ + "/" + baseName$ + "_intensidad.txt"
  writeFileLine: outInt$, "Tiempo(s)", tab$, "Intensidad(dB)"
  for k from 1 to nFramesI
    valInt = Get value in frame: k
    timeI = Get time from frame: k
    if valInt <> undefined
      appendFileLine: outInt$, fixed$(timeI, 4), tab$, fixed$(valInt, 2)
    endif
  endfor
  selectObject: intensity
  Remove
  
  # TextGrid
  tgFile$ = dirInput$ + "/" + baseName$ + ".TextGrid"
  if fileReadable(tgFile$)
    tg = Read from file: tgFile$
    nTiers = Get number of tiers
    outTG$ = dirOutput$ + "/" + baseName$ + "_texto.txt"
    writeFileLine: outTG$, "tier", tab$, "tmin", tab$, "tmax", tab$, "text"
    for t from 1 to nTiers
      tierName$ = Get tier name: t
      isInterval = Is interval tier: t
      if isInterval
        nInt = Get number of intervals: t
        for j from 1 to nInt
          label$ = Get label of interval: t, j
          if label$ <> ""
            tmin = Get start time of interval: t, j
            tmax = Get end time of interval: t, j
            appendFileLine: outTG$, tierName$, tab$, fixed$(tmin, 4), tab$, fixed$(tmax, 4), tab$, label$
          endif
        endfor
      else
        nPoints = Get number of points: t
        for j from 1 to nPoints
          label$ = Get label of point: t, j
          if label$ <> ""
            tpoint = Get time of point: t, j
            appendFileLine: outTG$, tierName$, tab$, fixed$(tpoint, 4), tab$, "--", tab$, label$
          endif
        endfor
      endif
    endfor
    selectObject: tg
    Remove
  endif
  
  selectObject: sound
  Remove
endfor
',
        input$praat_step, input$praat_pitch_min, input$praat_pitch_max,
        input$praat_int_min, input$praat_step)
      
      # Para cada par, copiar wav y tg al directorio de entrada y ejecutar
      in_dir <- file.path(tmpdir, "praat_input")
      dir.create(in_dir, recursive = TRUE, showWarnings = FALSE)
      
      for (nm in comunes) {
        file.copy(praat_archivos$wavs[[nm]], file.path(in_dir, paste0(nm, ".wav")), overwrite = TRUE)
        file.copy(praat_archivos$tgs[[nm]], file.path(in_dir, paste0(nm, ".TextGrid")), overwrite = TRUE)
      }
      
      # Script wrapper que define directorios y lista archivos
      wrapper_script <- sprintf('
dirInput$ = "%s"
dirOutput$ = "%s"
list_wav = Create Strings as file list: "list", dirInput$ + "/*.wav"
number_of_files = Get number of strings
%s
selectObject: list_wav
Remove
', gsub("\\\\", "/", in_dir), gsub("\\\\", "/", out_dir), script_content)
      
      script_path <- file.path(tmpdir, "lasp_praat_script.praat")
      writeLines(wrapper_script, script_path)
      
      incProgress(0.2, detail = "Ejecutando script Praat...")
      
      # Ejecutar Praat
      result <- tryCatch({
        if (Sys.info()["sysname"] == "Windows") {
          system2(praat_bin, args = c("--run", shQuote(script_path)), 
                  stdout = TRUE, stderr = TRUE, timeout = 300)
        } else {
          system2(praat_bin, args = c("--run", script_path), 
                  stdout = TRUE, stderr = TRUE, timeout = 300)
        }
      }, error = function(e) {
        showNotification(paste("Error ejecutando Praat:", e$message), type = "error", duration = 10)
        return(NULL)
      })
      
      incProgress(0.6, detail = "Cargando resultados...")
      
      if (is.null(result)) return()
      
      # Verificar archivos generados y cargarlos como si fueran uploads
      archivos_texto <- list.files(out_dir, pattern = "_texto\\.txt$", full.names = TRUE)
      archivos_pitch <- list.files(out_dir, pattern = "_pitch\\.txt$", full.names = TRUE)
      archivos_intensidad <- list.files(out_dir, pattern = "_intensidad\\.txt$", full.names = TRUE)
      
      n_generados <- length(archivos_texto) + length(archivos_pitch) + length(archivos_intensidad)
      
      if (n_generados == 0) {
        showNotification("Praat no generó archivos de salida. Revisa la consola.", type = "error")
        return()
      }
      
      # Simular upload: cargar archivos generados como si fueran subidos
      all_texto <- data.frame()
      for (f in archivos_texto) {
        df <- tryCatch(read.delim(f, header = TRUE, stringsAsFactors = FALSE), error = function(e) NULL)
        if (!is.null(df) && nrow(df) > 0) {
          colnames(df) <- tolower(colnames(df))
          if (!"tier" %in% colnames(df)) colnames(df) <- c("tier", "tmin", "tmax", "text")
          nm <- sub("_texto$", "", tools::file_path_sans_ext(basename(f)))
          df$archivo_origen <- nm
          all_texto <- bind_rows(all_texto, df)
        }
      }
      if (nrow(all_texto) > 0) datos$texto <- all_texto
      
      all_pitch <- data.frame()
      for (f in archivos_pitch) {
        df <- tryCatch(read.delim(f, header = TRUE, stringsAsFactors = FALSE), error = function(e) NULL)
        if (!is.null(df) && ncol(df) >= 2) {
          colnames(df)[1:2] <- c("tiempo", "f0")
          df$f0 <- as.numeric(df$f0)
          df <- df[!is.na(df$f0) & df$f0 > 0, ]
          nm <- sub("_pitch$", "", tools::file_path_sans_ext(basename(f)))
          df$archivo_origen <- nm
          all_pitch <- bind_rows(all_pitch, df)
        }
      }
      if (nrow(all_pitch) > 0) datos$pitch <- all_pitch
      
      all_int <- data.frame()
      for (f in archivos_intensidad) {
        df <- tryCatch(read.delim(f, header = TRUE, stringsAsFactors = FALSE), error = function(e) NULL)
        if (!is.null(df) && ncol(df) >= 2) {
          colnames(df)[1:2] <- c("tiempo", "intensidad")
          df$intensidad <- as.numeric(df$intensidad)
          df <- df[!is.na(df$intensidad), ]
          nm <- sub("_intensidad$", "", tools::file_path_sans_ext(basename(f)))
          df$archivo_origen <- nm
          all_int <- bind_rows(all_int, df)
        }
      }
      if (nrow(all_int) > 0) datos$intensidad <- all_int
      
      # Guardar archivos preprocesados individuales
      guardar_preprocesados()
      log_event("PRAAT_COMPLETADO", paste0(length(comunes), " archivo(s) procesados"))
      
      # También copiar wavs y textgrids para audio/praatpicture
      for (nm in comunes) {
        datos_audio$wavs[[nm]] <- file.path(in_dir, paste0(nm, ".wav"))
        datos_textgrid$tgs[[nm]] <- file.path(in_dir, paste0(nm, ".TextGrid"))
        # Auto-copiar a almacenamiento persistente
        tryCatch({
          copiar_audio_persistente(file.path(in_dir, paste0(nm, ".wav")), paste0(nm, ".wav"))
          copiar_textgrid_persistente(file.path(in_dir, paste0(nm, ".TextGrid")), paste0(nm, ".TextGrid"))
        }, error = function(e) NULL)
      }
      
      incProgress(0.2, detail = "Completado")
      
      showNotification(
        paste0("✔ Praat generó ", length(archivos_texto), " texto, ", 
               length(archivos_pitch), " pitch, ", length(archivos_intensidad), " intensidad. ",
               "Ahora pulsa 'Calcular'."),
        type = "message", duration = 10)
    })
  })
  
