  # ── Leer un TextGrid → data.frame(tier, tmin, tmax, text) ──────────────────
  leer_textgrid <- function(tg_path) {
    tg <- rPraat::tg.read(tg_path, encoding = "UTF-8")
    n_tiers <- rPraat::tg.getNumberOfTiers(tg)
    rows <- lapply(seq_len(n_tiers), function(ti) {
      if (!rPraat::tg.isIntervalTier(tg, ti)) return(NULL)
      tier_name <- tryCatch(rPraat::tg.getTierName(tg, ti),
                            error = function(e) paste0("Tier_", ti))
      n_int <- rPraat::tg.getNumberOfIntervals(tg, ti)
      data.frame(
        tier = rep(as.character(tier_name), n_int),
        tmin = sapply(seq_len(n_int), function(j) rPraat::tg.getIntervalStartTime(tg, ti, j)),
        tmax = sapply(seq_len(n_int), function(j) rPraat::tg.getIntervalEndTime(tg, ti, j)),
        text = sapply(seq_len(n_int), function(j) rPraat::tg.getLabel(tg, ti, j)),
        stringsAsFactors = FALSE
      )
    })
    rows <- Filter(Negate(is.null), rows)
    if (length(rows) == 0) return(data.frame(tier=character(), tmin=numeric(),
                                              tmax=numeric(), text=character()))
    df <- do.call(rbind, rows)
    df <- df[nzchar(trimws(df$text)), ]   # descartar intervalos vacíos
    df
  }

  output$rn_estado <- renderPrint({
    n_wav <- length(rn_archivos$wavs)
    n_tg  <- length(rn_archivos$tgs)
    if (n_wav == 0 && n_tg == 0) {
      cat("Sube archivos .wav y .TextGrid con el mismo nombre base.\n")
    } else {
      wav_names <- names(rn_archivos$wavs)
      tg_names  <- names(rn_archivos$tgs)
      pares <- intersect(wav_names, tg_names)
      cat("WAVs:", n_wav, "| TextGrids:", n_tg, "| Pares:", length(pares), "\n")
      if (length(pares) > 0) {
        cat("Listos para procesar:", paste(pares, collapse=", "), "\n")
      }
      sin_par_wav <- setdiff(wav_names, tg_names)
      sin_par_tg  <- setdiff(tg_names, wav_names)
      if (length(sin_par_wav) > 0) cat("WAV sin TextGrid:", paste(sin_par_wav, collapse=", "), "\n")
      if (length(sin_par_tg)  > 0) cat("TextGrid sin WAV:", paste(sin_par_tg,  collapse=", "), "\n")
    }
  })

  observeEvent(input$btn_rn_procesar, {
    pares <- intersect(names(rn_archivos$wavs), names(rn_archivos$tgs))
    if (length(pares) == 0) {
      showNotification("No hay pares WAV+TextGrid con el mismo nombre base.", type = "error")
      return()
    }
    if (!requireNamespace("tuneR",   quietly=TRUE) ||
        !requireNamespace("seewave", quietly=TRUE)) {
      showNotification(
        "Instala los paquetes necesarios: install.packages(c('tuneR','seewave'))",
        type = "error", duration = 10)
      return()
    }

    pitch_floor    <- input$rn_pitch_floor
    pitch_ceiling  <- input$rn_pitch_ceiling
    time_step      <- input$rn_time_step
    int_min_pitch  <- input$rn_int_min_pitch

    withProgress(message = "Extrayendo F0 e intensidad (R nativo)...", value = 0, {
      all_texto  <- data.frame()
      all_pitch  <- data.frame()
      all_int    <- data.frame()
      errores    <- character(0)

      for (ki in seq_along(pares)) {
        fn      <- pares[ki]
        wav_p   <- rn_archivos$wavs[[fn]]
        tg_p    <- rn_archivos$tgs[[fn]]
        incProgress(ki / length(pares), detail = fn)

        tryCatch({
          # ── Leer TextGrid (reutilizamos la misma función de lectura que
          #    usan los otros modos) ───────────────────────────────────────
          tg_raw <- leer_textgrid(tg_p)   # función ya definida en la app
          tg_raw$archivo_origen <- fn
          all_texto <- bind_rows(all_texto, tg_raw)

          # ── Extraer F0 e intensidad con seewave/tuneR ─────────────────
          res <- extraer_f0_int_r_nativo(
            wav_path           = wav_p,
            pitch_floor        = pitch_floor,
            pitch_ceiling      = pitch_ceiling,
            time_step          = time_step,
            intensity_min_pitch = int_min_pitch
          )

          if (nrow(res$pitch) > 0) {
            res$pitch$archivo_origen <- fn
            all_pitch <- bind_rows(all_pitch, res$pitch)
          }
          if (nrow(res$intensidad) > 0) {
            res$intensidad$archivo_origen <- fn
            all_int <- bind_rows(all_int, res$intensidad)
          }

          # ── Guardar audio persistente ──────────────────────────────────
          datos_audio$wavs[[fn]] <- wav_p

        }, error = function(e) {
          errores <<- c(errores, paste0(fn, ": ", e$message))
        })
      }

      if (nrow(all_texto) > 0) datos$texto     <- all_texto
      if (nrow(all_pitch) > 0) datos$pitch      <- all_pitch
      if (nrow(all_int)   > 0) datos$intensidad <- all_int

      if (nrow(all_texto) > 0 && nrow(all_pitch) > 0) {
        showNotification(
          paste0("R nativo completado: ", length(pares), " archivo(s). ",
                 nrow(all_pitch), " puntos F0, ",
                 nrow(all_int), " puntos intensidad."),
          type = "message", duration = 8)
        if (length(errores) > 0)
          showNotification(paste("Errores:", paste(errores, collapse="; ")),
                           type = "warning", duration = 10)
        # Lanzar análisis prosódico (igual que Parselmouth/Praat)
        shinyjs::click("btn_calcular")
      } else {
        msg <- if (length(errores) > 0) paste(errores, collapse="\n") else
          "No se obtuvieron datos. Comprueba los archivos."
        showNotification(msg, type = "error", duration = 10)
      }
    })
  })

  # Función auxiliar: generar gráfico praatpicture para un grupo entonativo
  generar_praatpicture_ge <- function(wav_path, tg_path, t_inicio, t_fin,
                                       titulo = "", output_file = NULL,
                                       ancho = 10, alto = 6,
                                       pitch_freqRange = NULL,
                                       hablante = NULL) {
    if (!praatpicture_disponible) {
      warning("Paquete praatpicture no disponible")
      return(invisible(NULL))
    }
    if (is.null(output_file)) {
      warning("output_file es NULL")
      return(invisible(NULL))
    }
    
    if (is.null(pitch_freqRange)) {
      pitch_freqRange <- c(-5, 15)
    }
    
    # praatpicture requiere archivos con extensiones correctas
    tmp_dir <- tempfile(pattern = "praatpic_")
    dir.create(tmp_dir, showWarnings = FALSE)
    
    tmp_wav <- file.path(tmp_dir, "audio.wav")
    tmp_tg <- file.path(tmp_dir, "audio.TextGrid")
    file.copy(wav_path, tmp_wav, overwrite = TRUE)
    file.copy(tg_path, tmp_tg, overwrite = TRUE)
    
    if (!file.exists(tmp_wav) || file.size(tmp_wav) == 0 ||
        !file.exists(tmp_tg) || file.size(tmp_tg) == 0) {
      warning("No se pudieron copiar archivos wav/TextGrid")
      unlink(tmp_dir, recursive = TRUE)
      return(invisible(NULL))
    }
    
    ext <- tolower(tools::file_ext(output_file))
    if (ext == "png") {
      png(output_file, width = ancho, height = alto, units = "in", res = 150)
    } else if (ext == "pdf") {
      pdf(output_file, width = ancho, height = alto)
    } else if (ext == "svg") {
      svg(output_file, width = ancho, height = alto)
    } else {
      png(output_file, width = ancho, height = alto, units = "in", res = 150)
    }
    
    # Determinar qué tiers mostrar: solo phones y words del hablante del GE
    tiers_sel <- seleccionar_tiers_hablante(tmp_tg, hablante)
    
    tryCatch({
      call_args <- list(
        sound = tmp_wav,
        start = t_inicio,
        end = t_fin,
        frames = c("sound", "spectrogram", "pitch", "TextGrid"),
        proportion = c(25, 40, 15, 20),
        tg_file = tmp_tg,
        pitch_plotType = "draw",
        pitch_scale = "semitones",
        pitch_semitonesRe = 1,
        pitch_freqRange = pitch_freqRange,
        pitch_color = "blue",
        mainTitle = titulo
      )
      if (!is.null(tiers_sel) && length(tiers_sel) > 0) {
        call_args$tg_tiers     <- tiers_sel
        call_args$tg_focusTier <- tiers_sel[1]
      }
      do.call(praatpicture::praatpicture, call_args)
    }, error = function(e) {
      warning("Error en praatpicture: ", e$message)
    }, finally = {
      dev.off()
    })
    
    unlink(tmp_dir, recursive = TRUE)
    return(invisible(output_file))
  }
  
  observeEvent(input$btn_play_grupo, {
    req(datos$calculado)
    vocales <- vocales_grupo_actual()
    if (is.null(vocales) || nrow(vocales) == 0) {
      showNotification("No hay vocales en este grupo", type = "warning")
      return()
    }
    
    t_inicio <- min(vocales$inicio, na.rm = TRUE) - 0.1
    t_fin <- max(vocales$fin, na.rm = TRUE) + 0.1
    t_inicio <- max(0, t_inicio)
    fn <- vocales$filename[1]
    
    # Buscar archivo de audio correspondiente
    wav_path <- NULL
    for (nombre in names(datos_audio$wavs)) {
      if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
        wav_path <- datos_audio$wavs[[nombre]]
        break
      }
    }
    # Si no hay match exacto, usar el primero disponible
    if (is.null(wav_path) && length(datos_audio$wavs) == 1) {
      wav_path <- datos_audio$wavs[[1]]
    }
    
    if (is.null(wav_path)) {
      showNotification("No se encontró archivo de audio. Sube archivos .wav con nombre similar al TextGrid.", type = "warning")
      return()
    }
    
    if (!tuneR_disponible) {
      showNotification("Instala el paquete tuneR: install.packages('tuneR')", type = "error")
      return()
    }
    
    tryCatch({
      library(tuneR)
      wav <- readWave(wav_path)
      sr <- wav@samp.rate
      
      # Cortar segmento
      from_sample <- max(1, round(t_inicio * sr))
      to_sample <- min(length(wav@left), round(t_fin * sr))
      
      if (wav@stereo) {
        segment <- Wave(left = wav@left[from_sample:to_sample],
                        right = wav@right[from_sample:to_sample],
                        samp.rate = sr, bit = wav@bit)
      } else {
        segment <- Wave(left = wav@left[from_sample:to_sample],
                        samp.rate = sr, bit = wav@bit)
      }
      
      # Guardar como archivo temporal
      tmp_file <- tempfile(fileext = ".wav")
      writeWave(segment, tmp_file)
      
      # Codificar en base64 para reproducción en el navegador
      raw_bytes <- readBin(tmp_file, "raw", file.info(tmp_file)$size)
      b64 <- base64enc::base64encode(raw_bytes)
      
      output$audio_player_grupo <- renderUI({
        tags$div(
          tags$audio(
            src = paste0("data:audio/wav;base64,", b64),
            type = "audio/wav",
            controls = TRUE,
            autoplay = TRUE,
            style = "width: 100%; margin-top: 8px;"
          ),
          tags$small(paste0("Segmento: ", round(t_inicio, 2), "s - ", round(t_fin, 2), "s"))
        )
      })
      
      file.remove(tmp_file)
    }, error = function(e) {
      showNotification(paste("Error al reproducir:", e$message), type = "error")
    })
  })
  
  # ========================================
  # EXPORTAR GRÁFICOS: Navegación y selección
  # ========================================
  
  export_state <- reactiveValues(
    current_idx = 1,
    selected_ids = character(0)  # IDs de GEs seleccionados para exportar
  )
  
  # Lista de todos los IPs que coinciden con los patrones seleccionados
  export_ips_lista <- reactive({
    req(datos$calculado, datos$ips_resumen, input$export_patrones_sel)
    ips <- datos$ips_resumen
    col_patron <- if (input$export_tipo_patron == "amh") "amh_patron" else "tobi_nuclear"
    
    ips_filtrados <- ips[!is.na(ips[[col_patron]]) & ips[[col_patron]] %in% input$export_patrones_sel, ]
    ips_filtrados
  })
  
  # Reset navegación cuando cambian patrones (pero NO limpiar selección automáticamente)
  observeEvent(c(input$export_patrones_sel, input$export_tipo_patron), {
    export_state$current_idx <- 1
  })
  
  # Botones de navegación
  observeEvent(input$export_prev, {
    ips <- export_ips_lista()
    if (is.null(ips) || nrow(ips) == 0) return()
    new_idx <- export_state$current_idx - 1
    if (new_idx < 1) new_idx <- nrow(ips)
    export_state$current_idx <- new_idx
  })
  
  observeEvent(input$export_next, {
    ips <- export_ips_lista()
    if (is.null(ips) || nrow(ips) == 0) return()
    new_idx <- export_state$current_idx + 1
    if (new_idx > nrow(ips)) new_idx <- 1
    export_state$current_idx <- new_idx
  })
  
  # Botón AÑADIR a selección
  observeEvent(input$export_toggle_sel, {
    ips <- export_ips_lista()
    if (is.null(ips) || nrow(ips) == 0) return()
    idx <- min(export_state$current_idx, nrow(ips))
    ge_id <- ips$id_ge[idx]
    
    if (!(ge_id %in% export_state$selected_ids)) {
      export_state$selected_ids <- c(export_state$selected_ids, ge_id)
      showNotification(paste0("✔ Añadido: ", ge_id), type = "message", duration = 2)
    } else {
      showNotification(paste0("Ya estaba seleccionado: ", ge_id), type = "warning", duration = 2)
    }
  })
  
  # Botón QUITAR de selección
  observeEvent(input$export_quitar_sel, {
    ips <- export_ips_lista()
    if (is.null(ips) || nrow(ips) == 0) return()
    idx <- min(export_state$current_idx, nrow(ips))
    ge_id <- ips$id_ge[idx]
    
    if (ge_id %in% export_state$selected_ids) {
      export_state$selected_ids <- setdiff(export_state$selected_ids, ge_id)
      showNotification(paste0("✖ Quitado: ", ge_id), type = "message", duration = 2)
    }
  })
  
  # Botón LIMPIAR selección
  observeEvent(input$export_limpiar_sel, {
    export_state$selected_ids <- character(0)
    showNotification("Selección limpiada", type = "message", duration = 2)
  })
  
  # ========================================
  # MODO N POR PATRÓN CON FILTROS
  # ========================================
  observeEvent(input$export_generar_por_patron, {
    req(datos$calculado, datos$ips_resumen, input$export_patrones_sel)
    
    ips_all <- datos$ips_resumen
    col_patron <- if (input$export_tipo_patron == "amh") "amh_patron" else "tobi_nuclear"
    patrones_sel <- input$export_patrones_sel
    phones <- datos$phones
    if (is.null(phones) || nrow(phones) == 0) return()
    
    n_por_patron <- input$export_n_por_patron
    total_added <- 0
    resumen_patrones <- c()
    
    for (pat in patrones_sel) {
      # Filtrar IPs de este patrón
      ips <- ips_all[!is.na(ips_all[[col_patron]]) & ips_all[[col_patron]] == pat, ]
      if (nrow(ips) == 0) next
      
      # Aplicar filtro de duración
      dur_min <- input$export_dur_min
      dur_max <- input$export_dur_max
      if (!is.null(dur_min) && !is.null(dur_max) && "duracion" %in% colnames(ips)) {
        ips <- ips[!is.na(ips$duracion) & ips$duracion >= dur_min & ips$duracion <= dur_max, ]
      }
      
      # Aplicar filtro de número mínimo de vocales
      min_voc <- input$export_min_vocales
      if (!is.null(min_voc) && "num_vocales" %in% colnames(ips)) {
        ips <- ips[!is.na(ips$num_vocales) & ips$num_vocales >= min_voc, ]
      }
      
      # Aplicar filtro de acento de la última palabra
      # OPTIMIZADO: usa columna precalculada acento_final si existe (evita bucle fila-a-fila)
      filtro_acento <- input$export_filtro_acento
      if (!is.null(filtro_acento) && filtro_acento != "todos" && nrow(ips) > 0) {
        tipos_ok <- switch(filtro_acento,
          "llana"     = "llana",
          "aguda"     = "aguda",
          "esdrujula" = c("esdrújula", "sobresdrújula"),
          character(0)
        )
        if ("acento_final" %in% colnames(ips)) {
          # Camino rápido: columna precalculada al analizar
          ips <- ips[!is.na(ips$acento_final) & ips$acento_final %in% tipos_ok, ]
        } else {
          # Camino de respaldo: batch con vapply (más rápido que bucle for)
          acento_vec <- vapply(seq_len(nrow(ips)), function(i) {
            ip <- ips[i, ]
            vocales_ge <- phones[phones$filename == ip$filename & phones$hablante == ip$hablante &
                                   phones$grupo_entonativo == ip$grupo_entonativo, ]
            if (nrow(vocales_ge) == 0) return("desconocida")
            palabras <- vocales_ge$palabra[!is.na(vocales_ge$palabra) & vocales_ge$palabra != ""]
            if (length(palabras) == 0) return("desconocida")
            tryCatch(
              determinar_acentuacion(tail(palabras, 1), "es")$tipo,
              error = function(e) "desconocida"
            )
          }, character(1))
          ips <- ips[acento_vec %in% tipos_ok, ]
        }
      }
      
      if (nrow(ips) == 0) {
        resumen_patrones <- c(resumen_patrones, paste0(pat, ": 0 (sin candidatos)"))
        next
      }
      
      # Excluir los ya seleccionados para este patrón
      ips_nuevos <- ips[!(ips$id_ge %in% export_state$selected_ids), ]
      
      n_sel <- min(n_por_patron, nrow(ips_nuevos))
      if (n_sel > 0) {
        sel_rows <- sample(1:nrow(ips_nuevos), n_sel)
        nuevos_ids <- ips_nuevos$id_ge[sel_rows]
        export_state$selected_ids <- unique(c(export_state$selected_ids, nuevos_ids))
        total_added <- total_added + n_sel
      }
      resumen_patrones <- c(resumen_patrones, paste0(pat, ": ", n_sel, "/", nrow(ips), " candidatos"))
    }
    
    showNotification(
      paste0("✔ ", total_added, " grupos seleccionados:\n", paste(resumen_patrones, collapse = "\n")), 
      type = "message", duration = 8)
  })
  
  # IP actual de la navegación
  export_ip_actual <- reactive({
    ips <- export_ips_lista()
    if (is.null(ips) || nrow(ips) == 0) return(NULL)
    idx <- min(export_state$current_idx, nrow(ips))
    ips[idx, , drop = FALSE]
  })
  
  # Vocales del grupo actual en exportación
  export_vocales_actual <- reactive({
    ip <- export_ip_actual()
    if (is.null(ip) || nrow(ip) == 0) return(NULL)
    phones <- datos$phones
    vocales <- phones[phones$filename == ip$filename[1] & phones$hablante == ip$hablante[1] &
                        phones$grupo_fonico == ip$grupo_fonico[1] & phones$grupo_entonativo == ip$grupo_entonativo[1], ]
    vocales
  })
  
  # Textos de navegación
  output$export_nav_info <- renderText({
    ips <- export_ips_lista()
    if (is.null(ips) || nrow(ips) == 0) return("Sin grupos")
    idx <- min(export_state$current_idx, nrow(ips))
    paste0("Grupo ", idx, " de ", nrow(ips))
  })
  
  output$export_nav_patron_info <- renderText({
    ip <- export_ip_actual()
    if (is.null(ip)) return("")
    col_patron <- if (input$export_tipo_patron == "amh") "amh_patron" else "tobi_nuclear"
    paste0(ip$id_ge[1], " — Patrón: ", ip[[col_patron]][1])
  })
  
  output$export_amh_actual <- renderText({
    ip <- export_ip_actual()
    if (is.null(ip) || !"amh_patron" %in% colnames(ip)) return("-")
