    if ("amh_fonologico" %in% colnames(ip) && !is.na(ip$amh_fonologico[1])) {
      amh_txt <- paste0(amh_txt, " (", ip$amh_fonologico[1], ")")
    }
    amh_txt
  })
  
  output$export_tobi_actual <- renderText({
