  })
  
  output$export_dur_actual <- renderText({
    ip <- export_ip_actual()
    if (is.null(ip) || !"duracion" %in% colnames(ip)) return("-")
    paste0(round(ip$duracion[1], 2), " s (", ip$num_vocales[1], " vocales)")
  })
  
  output$export_palabras_inline <- renderText({
    ip <- export_ip_actual()
    if (is.null(ip) || !"palabras_grupo" %in% colnames(ip)) return("")
    ip$palabras_grupo[1]
  })
  
  # Estado de selección del grupo actual
  output$export_estado_sel <- renderText({
    ip <- export_ip_actual()
    if (is.null(ip)) return("")
    ge_id <- ip$id_ge[1]
    if (ge_id %in% export_state$selected_ids) {
      "✔ SELECCIONADO"
    } else {
      "— no seleccionado"
    }
  })
  
  output$export_seleccion_resumen <- renderPrint({
    sel <- export_state$selected_ids
    if (length(sel) == 0) {
      cat("Ningún grupo seleccionado.\n")
      cat("Usa los botones de selección manual o genera una selección aleatoria.\n")
    } else {
      cat(length(sel), "grupo(s) seleccionado(s):\n")
      for (id in sel) cat("  ✔", id, "\n")
    }
  })
  output$selector_patron_export <- renderUI({
    req(datos$calculado, datos$ips_resumen)
    ips <- datos$ips_resumen
    
    if (input$export_tipo_patron == "amh") {
      patrones <- unique(ips$amh_patron[!is.na(ips$amh_patron) & ips$amh_patron != ""])
    } else {
      patrones <- unique(ips$tobi_nuclear[!is.na(ips$tobi_nuclear) & ips$tobi_nuclear != ""])
    }
    
    if (length(patrones) == 0) return(helpText("No hay patrones etiquetados. Calcula primero."))
    
    checkboxGroupInput("export_patrones_sel", "Patrones a exportar:",
                       choices = sort(patrones), selected = sort(patrones))
  })
  
  # Función auxiliar: generar gráfico ggplot de un GE para exportación
  # Acepta las mismas opciones de visualización que la vista previa
  generar_grafico_ge <- function(vocales_ge, titulo_extra = "", normalizado = FALSE, medias_hab = NULL,
                                  criterios = c("pitch", "intensidad", "transicion"),
                                  mostrar_tonicas = TRUE, mostrar_picos = TRUE,
                                  mostrar_secciones = TRUE, mostrar_tobi = FALSE,
                                  mostrar_estructura_vocal = FALSE,
                                  tipo_norm = "base100_primera", medias_hablante_df = NULL) {
    if (is.null(vocales_ge) || nrow(vocales_ge) == 0) return(NULL)
    
    vocales_ge <- vocales_ge[order(vocales_ge$tmin), ]
    vocales_ge$x_pos <- 1:nrow(vocales_ge)
    etiq <- paste0(vocales_ge$etiqueta, " (", vocales_ge$palabra, ")")
    
    # Normalización
    if (normalizado) {
      if (tipo_norm == "base100_primera") {
        vocales_ge$f0_norm <- normalizar_base100_primera(vocales_ge$f0_media_hz)
        vocales_ge$int_norm <- normalizar_base100_primera(vocales_ge$int_media)
        vocales_ge$trans_norm <- normalizar_base100_primera(vocales_ge$tiempo_transicion_anterior)
        y_lab <- "Valor normalizado (base 100 = primera vocal)"
      } else if (tipo_norm == "base100_media") {
        if (!is.null(medias_hablante_df) && nrow(medias_hablante_df) > 0) {
          hab <- vocales_ge$hablante[1]; fn <- vocales_ge$filename[1]
          ref <- medias_hablante_df[medias_hablante_df$hablante == hab & medias_hablante_df$filename == fn, ]
          if (nrow(ref) > 0) {
            vocales_ge$f0_norm <- normalizar_base100_media(vocales_ge$f0_media_hz, ref$f0_media_hz_hablante[1])
            vocales_ge$int_norm <- normalizar_base100_media(vocales_ge$int_media, ref$int_media_hablante[1])
            trans_ref <- mean(vocales_ge$tiempo_transicion_anterior, na.rm = TRUE)
            vocales_ge$trans_norm <- normalizar_base100_media(vocales_ge$tiempo_transicion_anterior, trans_ref)
          } else {
            vocales_ge$f0_norm <- normalizar_base100_primera(vocales_ge$f0_media_hz)
            vocales_ge$int_norm <- normalizar_base100_primera(vocales_ge$int_media)
            vocales_ge$trans_norm <- normalizar_base100_primera(vocales_ge$tiempo_transicion_anterior)
          }
        } else {
          vocales_ge$f0_norm <- normalizar_base100_primera(vocales_ge$f0_media_hz)
          vocales_ge$int_norm <- normalizar_base100_primera(vocales_ge$int_media)
          vocales_ge$trans_norm <- normalizar_base100_primera(vocales_ge$tiempo_transicion_anterior)
        }
        y_lab <- "Valor normalizado (base 100 = media hablante)"
      } else if (tipo_norm == "zscore") {
        vocales_ge$f0_norm <- normalizar_zscore(vocales_ge$f0_media_hz)
        vocales_ge$int_norm <- normalizar_zscore(vocales_ge$int_media)
        vocales_ge$trans_norm <- normalizar_zscore(vocales_ge$tiempo_transicion_anterior)
        y_lab <- "Z-score"
      } else {
        vocales_ge$f0_norm <- normalizar_minmax(vocales_ge$f0_media_hz)
        vocales_ge$int_norm <- normalizar_minmax(vocales_ge$int_media)
        vocales_ge$trans_norm <- normalizar_minmax(vocales_ge$tiempo_transicion_anterior)
        y_lab <- "Valor normalizado (Min-Max 0-100)"
      }
      f0_y <- "f0_norm"; int_y <- "int_norm"; trans_y <- "trans_norm"
    } else {
      f0_y <- "f0_media_st"; int_y <- "int_media"
      # Para bruto, transición en escala original no se mezcla bien; normalizar igualmente
      vocales_ge$trans_norm <- normalizar_base100_primera(vocales_ge$tiempo_transicion_anterior)
      trans_y <- "trans_norm"
      y_lab <- "F0 (St) / Int (dB)"
    }
    
    p <- ggplot(vocales_ge, aes(x = x_pos)) +
      scale_x_continuous(breaks = 1:nrow(vocales_ge), labels = etiq) +
      labs(title = paste0(vocales_ge$id_grupo[1], " ", titulo_extra),
           subtitle = paste0("Palabras: ", {
             if ("palabra_idx" %in% colnames(vocales_ge)) {
               pi <- vocales_ge$palabra_idx[!is.na(vocales_ge$palabra_idx)]
               pt <- vocales_ge$palabra[!is.na(vocales_ge$palabra_idx)]
               if (length(pi) > 0) {
                 pdf <- data.frame(i=pi, t=pt, stringsAsFactors=FALSE)
                 pdf <- pdf[!duplicated(pdf$i), ]; pdf <- pdf[order(pdf$i), ]
                 paste(pdf$t[pdf$t != ""], collapse = " ")
               } else paste(unique(vocales_ge$palabra[vocales_ge$palabra != ""]), collapse = " ")
             } else {
               pals <- vocales_ge$palabra[!is.na(vocales_ge$palabra) & vocales_ge$palabra != ""]
               if (length(pals) > 0) paste(pals[c(TRUE, pals[-1] != pals[-length(pals)])], collapse = " ") else ""
             }
           }),
           x = "", y = y_lab) +
      theme_minimal() +
      theme(axis.text.x = element_text(angle = 45, hjust = 1, size = 10),
            plot.title = element_text(size = 13, face = "bold"))
    
    # Secciones de fondo
    if (mostrar_secciones && "seccion_ip" %in% colnames(vocales_ge)) {
      secciones <- rle(vocales_ge$seccion_ip)
      pos_fin <- cumsum(secciones$lengths) + 0.5
      pos_ini <- c(0.5, head(pos_fin, -1))
      colores_sec <- c("anacrusis" = "#FFFF0030", "cuerpo" = "#00FF0020", "tonema" = "#FF000030")
      for (s in seq_along(secciones$values)) {
        sec <- secciones$values[s]
        if (sec %in% names(colores_sec)) {
          p <- p + annotate("rect", xmin = pos_ini[s], xmax = pos_fin[s],
                            ymin = -Inf, ymax = Inf, fill = colores_sec[sec])
        }
      }
    }
    
    # Transición como barras (detrás de las líneas)
    if ("transicion" %in% criterios && trans_y %in% colnames(vocales_ge)) {
      voc_trans <- vocales_ge[!is.na(vocales_ge[[trans_y]]), ]
      if (nrow(voc_trans) > 0) {
        p <- p + geom_col(data = voc_trans, aes_string(x = "x_pos", y = trans_y),
                          fill = "#4CAF5080", color = "#4CAF50CC", width = 0.4)
      }
    }
    
    # Pitch (línea + puntos)
    if ("pitch" %in% criterios) {
      p <- p + geom_line(aes_string(y = f0_y), color = "steelblue", linewidth = 1.2) +
        geom_point(aes_string(y = f0_y), color = "steelblue", size = 3)
    }
    
    # Intensidad (línea discontinua + puntos diamante)
    if ("intensidad" %in% criterios && int_y %in% colnames(vocales_ge)) {
      p <- p + geom_line(aes_string(y = int_y), color = "red", linewidth = 0.8, linetype = "dashed") +
        geom_point(aes_string(y = int_y), color = "red", size = 2.5, shape = 18)
    }
    
    # Tónicas
    if (mostrar_tonicas && "pitch" %in% criterios && "tonica_gramatical" %in% colnames(vocales_ge)) {
      tonicas_idx <- which(vocales_ge$tonica_gramatical == "sí")
      if (length(tonicas_idx) > 0) {
        p <- p + geom_point(data = vocales_ge[tonicas_idx, ],
                            aes_string(x = "x_pos", y = f0_y),
                            shape = 17, size = 4, color = "gold3")
      }
    }
    
    # Picos
    if (mostrar_picos && "pitch" %in% criterios) {
      pico_idx <- which(vocales_ge$es_pico_grupo)
      if (length(pico_idx) > 0) {
        p <- p + geom_point(data = vocales_ge[pico_idx, ],
                            aes_string(x = "x_pos", y = f0_y),
                            shape = 8, size = 5, color = "darkred")
      }
    }
    
    # ToBI etiquetas
    if (mostrar_tobi && "pitch" %in% criterios && "tobi_fonologico" %in% colnames(vocales_ge)) {
      for (i in 1:nrow(vocales_ge)) {
        lbl <- vocales_ge$tobi_fonologico[i]
        if (!is.na(lbl) && lbl != "") {
          p <- p + annotate("text", x = vocales_ge$x_pos[i],
                            y = vocales_ge[[f0_y]][i],
                            label = lbl, vjust = -1.5, color = "purple", size = 3.5)
        }
        if ("tono_frontera_fonologico" %in% colnames(vocales_ge)) {
          fr_lbl <- vocales_ge$tono_frontera_fonologico[i]
          if (!is.na(fr_lbl) && fr_lbl != "") {
            p <- p + annotate("text", x = vocales_ge$x_pos[i],
                              y = vocales_ge[[f0_y]][i],
                              label = fr_lbl, vjust = 2.5, color = "darkgreen", size = 3.5, fontface = "bold")
          }
        }
      }
    }
    
    # Estructura interna de vocales con movimiento > 1.5 St
    if (mostrar_estructura_vocal && "pitch" %in% criterios &&
        all(c("q1_f0_media_hz", "q2_f0_media_hz", "q3_f0_media_hz", "q4_f0_media_hz",
               "dif_q1_q2_st", "dif_q2_q3_st", "dif_q3_q4_st") %in% colnames(vocales_ge))) {
      
      # Construir función de normalización Hz según el mismo método
      norm_gg_hz <- function(hz_val) {
        if (is.na(hz_val)) return(NA_real_)
        if (normalizado) {
          if (tipo_norm == "base100_primera") {
            ref_v <- vocales_ge$f0_media_hz[!is.na(vocales_ge$f0_media_hz)][1]
            if (is.na(ref_v) || ref_v == 0) return(NA_real_)
            return((hz_val / ref_v) * 100)
          } else if (tipo_norm == "base100_media") {
            if (!is.null(medias_hablante_df) && nrow(medias_hablante_df) > 0) {
              hab2 <- vocales_ge$hablante[1]; fn2 <- vocales_ge$filename[1]
              ref2 <- medias_hablante_df[medias_hablante_df$hablante == hab2 & medias_hablante_df$filename == fn2, ]
              ref_v <- if (nrow(ref2) > 0) ref2$f0_media_hz_hablante[1] else vocales_ge$f0_media_hz[!is.na(vocales_ge$f0_media_hz)][1]
            } else {
              ref_v <- vocales_ge$f0_media_hz[!is.na(vocales_ge$f0_media_hz)][1]
            }
            if (is.na(ref_v) || ref_v == 0) return(NA_real_)
            return((hz_val / ref_v) * 100)
          } else if (tipo_norm == "zscore") {
            m <- mean(vocales_ge$f0_media_hz, na.rm = TRUE)
            s <- sd(vocales_ge$f0_media_hz, na.rm = TRUE)
            if (is.na(s) || s == 0) return(0)
            return((hz_val - m) / s)
          } else {
            mn <- min(vocales_ge$f0_media_hz, na.rm = TRUE)
            mx <- max(vocales_ge$f0_media_hz, na.rm = TRUE)
            if (is.na(mn) || is.na(mx) || mn == mx) return(50)
            return(((hz_val - mn) / (mx - mn)) * 100)
          }
        } else {
          # Bruto: usar St directamente; convertir Hz a St re 1Hz = 12*log2(Hz/1)
          # Pero para consistencia, usar el f0_media_st scale
          return(12 * log2(hz_val / 1))  # St re 1 Hz
        }
      }
      
      umbral_mov <- 1.5
      q_data <- data.frame(x = numeric(0), y = numeric(0), q_label = character(0), stringsAsFactors = FALSE)
      q_seg_data <- data.frame(x = numeric(0), xend = numeric(0), y = numeric(0), yend = numeric(0), stringsAsFactors = FALSE)
      
      for (i in 1:nrow(vocales_ge)) {
        d12 <- abs(vocales_ge$dif_q1_q2_st[i]); d23 <- abs(vocales_ge$dif_q2_q3_st[i]); d34 <- abs(vocales_ge$dif_q3_q4_st[i])
        if (is.na(d12)) d12 <- 0; if (is.na(d23)) d23 <- 0; if (is.na(d34)) d34 <- 0
        
        if (d12 > umbral_mov || d23 > umbral_mov || d34 > umbral_mov) {
          q1h <- vocales_ge$q1_f0_media_hz[i]; q2h <- vocales_ge$q2_f0_media_hz[i]
          q3h <- vocales_ge$q3_f0_media_hz[i]; q4h <- vocales_ge$q4_f0_media_hz[i]
          if (any(is.na(c(q1h, q2h, q3h, q4h)))) next
          
          base_x <- vocales_ge$x_pos[i]
          offsets <- c(-0.3, -0.1, 0.1, 0.3)
          hz_vals <- c(q1h, q2h, q3h, q4h)
          y_vals <- sapply(hz_vals, norm_gg_hz)
          
          if (any(is.na(y_vals))) next
          
          for (qi in 1:4) {
            q_data <- rbind(q_data, data.frame(x = base_x + offsets[qi], y = y_vals[qi],
                                                q_label = paste0("Q", qi), stringsAsFactors = FALSE))
          }
          for (seg in 1:3) {
            q_seg_data <- rbind(q_seg_data, data.frame(
              x = base_x + offsets[seg], xend = base_x + offsets[seg + 1],
              y = y_vals[seg], yend = y_vals[seg + 1], stringsAsFactors = FALSE))
          }
        }
      }
      
      if (nrow(q_data) > 0) {
        p <- p + geom_segment(data = q_seg_data, aes(x = x, xend = xend, y = y, yend = yend),
                              color = "#9632C8", linewidth = 0.8, linetype = "dotted", alpha = 0.5) +
          geom_point(data = q_data, aes(x = x, y = y),
                     color = "#9632C8", size = 2.5, shape = 16, alpha = 0.7)
      }
    }
    
    return(p)
  }
  
  output$preview_grafico_export <- renderPlotly({
    vocales <- export_vocales_actual()
    if (is.null(vocales) || nrow(vocales) == 0) return(NULL)
    ip <- export_ip_actual()
    if (is.null(ip)) return(NULL)
    
    vocales <- vocales[order(vocales$inicio), ]
    vocales$pos <- 1:nrow(vocales)
    
    vocales$f0_media_hz_r <- round(vocales$f0_media_hz, 2)
    vocales$f0_media_st_r <- round(vocales$f0_media_st, 2)
    vocales$int_media_r <- round(vocales$int_media, 2)
    vocales$duracion_r <- round(vocales$duracion, 2)
    
    vocales$etiq_completa <- ifelse(!is.na(vocales$palabra) & vocales$palabra != "",
                                    paste0(vocales$etiqueta, " (", vocales$palabra, ")"),
                                    vocales$etiqueta)
    
    # Normalización igual que en Conf. Melódica
    tipo_norm <- input$tipo_normalizacion
    
    if (tipo_norm == "base100_primera") {
      vocales$f0_norm <- normalizar_base100_primera(vocales$f0_media_hz)
      vocales$int_norm <- normalizar_base100_primera(vocales$int_media)
      vocales$trans_norm <- normalizar_base100_primera(vocales$tiempo_transicion_anterior)
      y_label <- "Valor normalizado (base 100 = primera vocal)"
    } else if (tipo_norm == "base100_media") {
      media_hab <- datos$medias_hablante
      if (!is.null(media_hab) && nrow(media_hab) > 0) {
        hab <- vocales$hablante[1]; fn <- vocales$filename[1]
        ref <- media_hab[media_hab$hablante == hab & media_hab$filename == fn, ]
        if (nrow(ref) > 0) {
          vocales$f0_norm <- normalizar_base100_media(vocales$f0_media_hz, ref$f0_media_hz_hablante[1])
          vocales$int_norm <- normalizar_base100_media(vocales$int_media, ref$int_media_hablante[1])
          trans_ref <- mean(vocales$tiempo_transicion_anterior, na.rm = TRUE)
          vocales$trans_norm <- normalizar_base100_media(vocales$tiempo_transicion_anterior, trans_ref)
        } else {
          vocales$f0_norm <- normalizar_base100_primera(vocales$f0_media_hz)
          vocales$int_norm <- normalizar_base100_primera(vocales$int_media)
          vocales$trans_norm <- normalizar_base100_primera(vocales$tiempo_transicion_anterior)
        }
      } else {
        vocales$f0_norm <- normalizar_base100_primera(vocales$f0_media_hz)
        vocales$int_norm <- normalizar_base100_primera(vocales$int_media)
        vocales$trans_norm <- normalizar_base100_primera(vocales$tiempo_transicion_anterior)
      }
      y_label <- "Valor normalizado (base 100 = media hablante)"
    } else if (tipo_norm == "zscore") {
      vocales$f0_norm <- normalizar_zscore(vocales$f0_media_hz)
      vocales$int_norm <- normalizar_zscore(vocales$int_media)
      vocales$trans_norm <- normalizar_zscore(vocales$tiempo_transicion_anterior)
      y_label <- "Z-score"
    } else {
      vocales$f0_norm <- normalizar_minmax(vocales$f0_media_hz)
      vocales$int_norm <- normalizar_minmax(vocales$int_media)
      vocales$trans_norm <- normalizar_minmax(vocales$tiempo_transicion_anterior)
      y_label <- "Valor normalizado (Min-Max 0-100)"
    }
    
    vocales$f0_norm_r <- round(vocales$f0_norm, 2)
    vocales$int_norm_r <- round(vocales$int_norm, 2)
    vocales$trans_norm_r <- round(vocales$trans_norm, 2)
    vocales$trans_r <- round(vocales$tiempo_transicion_anterior, 2)
    
    # Referencia de normalización para cuartiles
    norm_ref_exp <- list(tipo = tipo_norm)
    if (tipo_norm == "base100_primera") {
      norm_ref_exp$primera_hz <- vocales$f0_media_hz[!is.na(vocales$f0_media_hz)][1]
    } else if (tipo_norm == "base100_media") {
      media_hab_r2 <- datos$medias_hablante
      if (!is.null(media_hab_r2) && nrow(media_hab_r2) > 0) {
        hab_r2 <- vocales$hablante[1]; fn_r2 <- vocales$filename[1]
        ref_t2 <- media_hab_r2[media_hab_r2$hablante == hab_r2 & media_hab_r2$filename == fn_r2, ]
        norm_ref_exp$media_hz <- if (nrow(ref_t2) > 0) ref_t2$f0_media_hz_hablante[1] else vocales$f0_media_hz[!is.na(vocales$f0_media_hz)][1]
      } else {
        norm_ref_exp$media_hz <- vocales$f0_media_hz[!is.na(vocales$f0_media_hz)][1]
      }
    } else if (tipo_norm == "zscore") {
      norm_ref_exp$f0_mean <- mean(vocales$f0_media_hz, na.rm = TRUE)
      norm_ref_exp$f0_sd <- sd(vocales$f0_media_hz, na.rm = TRUE)
    } else {
      norm_ref_exp$f0_min <- min(vocales$f0_media_hz, na.rm = TRUE)
      norm_ref_exp$f0_max <- max(vocales$f0_media_hz, na.rm = TRUE)
    }
    
    norm_hz_val_exp <- function(hz_val) {
      if (is.na(hz_val)) return(NA_real_)
      if (norm_ref_exp$tipo == "base100_primera") {
        ref_v <- norm_ref_exp$primera_hz
        if (is.na(ref_v) || ref_v == 0) return(NA_real_)
        return((hz_val / ref_v) * 100)
      } else if (norm_ref_exp$tipo == "base100_media") {
        ref_v <- norm_ref_exp$media_hz
        if (is.na(ref_v) || ref_v == 0) return(NA_real_)
        return((hz_val / ref_v) * 100)
      } else if (norm_ref_exp$tipo == "zscore") {
        if (is.na(norm_ref_exp$f0_sd) || norm_ref_exp$f0_sd == 0) return(0)
        return((hz_val - norm_ref_exp$f0_mean) / norm_ref_exp$f0_sd)
      } else {
        rng <- norm_ref_exp$f0_max - norm_ref_exp$f0_min
        if (is.na(rng) || rng == 0) return(50)
        return(((hz_val - norm_ref_exp$f0_min) / rng) * 100)
      }
    }
    
    criterios <- input$export_criterios
    fig <- plot_ly()
    
    # Secciones de fondo
    shapes_list <- list()
    if (input$export_mostrar_secciones && "seccion_ip" %in% colnames(vocales)) {
      colores_seccion <- c(anacrusis = "rgba(255, 193, 7, 0.20)",
                           cuerpo = "rgba(40, 167, 69, 0.15)",
                           tonema = "rgba(220, 53, 69, 0.20)")
      secciones <- rle(vocales$seccion_ip)
      pos_fin <- cumsum(secciones$lengths) + 0.5
      pos_ini <- c(0.5, pos_fin[-length(pos_fin)])
      for (s in seq_along(secciones$values)) {
        sec_name <- secciones$values[s]
        col <- colores_seccion[sec_name]
        if (!is.na(col)) {
          shapes_list[[length(shapes_list) + 1]] <- list(
            type = "rect", x0 = pos_ini[s], x1 = pos_fin[s],
            y0 = 0, y1 = 1, xref = "x", yref = "paper",
            fillcolor = col, line = list(width = 0), layer = "below"
          )
        }
      }
    }
    
    # Pitch
    if ("pitch" %in% criterios) {
      fig <- fig %>% add_trace(data = vocales, x = ~pos, y = ~f0_norm_r,
                                type = "scatter", mode = "lines+markers",
                                line = list(color = "blue", width = 2),
                                marker = list(color = "blue", size = 7),
                                text = ~paste0(etiq_completa, "\nF0: ", f0_media_hz_r, " Hz\nNorm: ", f0_norm_r),
                                hoverinfo = "text", name = "Pitch (F0)")
    }
    
    # Intensidad
    if ("intensidad" %in% criterios) {
      fig <- fig %>% add_trace(data = vocales, x = ~pos, y = ~int_norm_r,
                                type = "scatter", mode = "lines+markers",
                                line = list(color = "red", width = 1.5, dash = "dash"),
                                marker = list(color = "red", size = 5, symbol = "diamond"),
                                text = ~paste0(etiq_completa, "\nInt: ", int_media_r, " dB\nNorm: ", int_norm_r),
                                hoverinfo = "text", name = "Intensidad")
    }
    
    # Transición como barras (modelo AMH)
    if ("transicion" %in% criterios && "tiempo_transicion_anterior" %in% colnames(vocales)) {
      voc_trans <- vocales[!is.na(vocales$trans_norm), ]
      if (nrow(voc_trans) > 0) {
        fig <- fig %>% add_trace(data = voc_trans, x = ~pos, y = ~trans_norm_r,
                                  type = "bar",
                                  marker = list(color = "rgba(70, 130, 180, 0.45)",
                                                line = list(color = "rgba(70, 130, 180, 0.8)", width = 1)),
                                  text = ~paste0(etiq_completa, "\nTransición: ", trans_r, " s\nNorm: ", trans_norm_r),
                                  hoverinfo = "text", name = "Transición vocálica",
                                  width = 0.4)
      }
    }
    
    # Estructura interna de vocales con movimiento > 1.5 St
    if (input$export_mostrar_estructura_vocal && "pitch" %in% criterios &&
        all(c("q1_f0_media_hz", "q2_f0_media_hz", "q3_f0_media_hz", "q4_f0_media_hz",
               "dif_q1_q2_st", "dif_q2_q3_st", "dif_q3_q4_st") %in% colnames(vocales))) {
      
      umbral_mov <- 1.5
      q_pts <- data.frame(x = numeric(0), y = numeric(0), q_label = character(0),
                           vocal_etiq = character(0), hz_val = numeric(0),
                           estructura = character(0), stringsAsFactors = FALSE)
      q_segs <- list()
      
      for (i in 1:nrow(vocales)) {
        d12 <- abs(vocales$dif_q1_q2_st[i]); d23 <- abs(vocales$dif_q2_q3_st[i]); d34 <- abs(vocales$dif_q3_q4_st[i])
        if (is.na(d12)) d12 <- 0; if (is.na(d23)) d23 <- 0; if (is.na(d34)) d34 <- 0
        
        if (d12 > umbral_mov || d23 > umbral_mov || d34 > umbral_mov) {
          q1h <- vocales$q1_f0_media_hz[i]; q2h <- vocales$q2_f0_media_hz[i]
          q3h <- vocales$q3_f0_media_hz[i]; q4h <- vocales$q4_f0_media_hz[i]
          if (any(is.na(c(q1h, q2h, q3h, q4h)))) next
          
          base_x <- vocales$pos[i]
          offsets <- c(-0.3, -0.1, 0.1, 0.3)
          hz_vals <- c(q1h, q2h, q3h, q4h)
          q_labels <- c("Q1", "Q2", "Q3", "Q4")
          estr <- if ("estructura_vocal" %in% colnames(vocales)) vocales$estructura_vocal[i] else ""
          
          for (qi in 1:4) {
            y_n <- norm_hz_val_exp(hz_vals[qi])
            if (!is.na(y_n)) {
              q_pts <- rbind(q_pts, data.frame(x = base_x + offsets[qi], y = round(y_n, 2),
                q_label = q_labels[qi], vocal_etiq = vocales$etiq_completa[i],
                hz_val = round(hz_vals[qi], 1), estructura = estr, stringsAsFactors = FALSE))
            }
          }
          
          y_norms <- sapply(hz_vals, norm_hz_val_exp)
          if (!any(is.na(y_norms))) {
            for (seg in 1:3) {
              q_segs[[length(q_segs) + 1]] <- list(
                type = "line", x0 = base_x + offsets[seg], x1 = base_x + offsets[seg + 1],
                y0 = round(y_norms[seg], 2), y1 = round(y_norms[seg + 1], 2),
                xref = "x", yref = "y",
                line = list(color = "rgba(150, 50, 200, 0.4)", width = 1.5, dash = "dot"),
                layer = "above")
            }
          }
        }
      }
      
      if (nrow(q_pts) > 0) {
        fig <- fig %>% add_trace(data = q_pts, x = ~x, y = ~y,
                                  type = "scatter", mode = "markers",
                                  marker = list(color = "rgba(150, 50, 200, 0.7)", size = 8,
                                                symbol = "circle",
                                                line = list(color = "rgba(100, 20, 160, 0.9)", width = 1)),
                                  text = ~paste0(vocal_etiq, "\n", q_label, ": ", hz_val, " Hz\nNorm: ", y,
                                                 "\nEstructura: ", estructura),
                                  hoverinfo = "text", name = "Estructura interna vocal")
        shapes_list <- c(shapes_list, q_segs)
      }
    }
    if (input$export_mostrar_tonicas && "tonica_gramatical" %in% colnames(vocales) && "pitch" %in% criterios) {
      tonicas <- vocales[!is.na(vocales$tonica_gramatical) & vocales$tonica_gramatical == "sí", ]
      if (nrow(tonicas) > 0) {
        fig <- fig %>% add_trace(data = tonicas, x = ~pos, y = ~f0_norm_r,
                                  type = "scatter", mode = "markers",
                                  marker = list(color = "gold", size = 12, symbol = "triangle-up",
                                                line = list(color = "black", width = 1.5)),
                                  text = ~paste0("TÓNICA: ", etiq_completa),
                                  hoverinfo = "text", name = "Tónica")
      }
    }
    
    # Picos
    if (input$export_mostrar_picos && "pitch" %in% criterios) {
      picos_grupo <- vocales[!is.na(vocales$es_pico_grupo) & vocales$es_pico_grupo, ]
      if (nrow(picos_grupo) > 0) {
        fig <- fig %>% add_trace(data = picos_grupo, x = ~pos, y = ~f0_norm_r,
                                  type = "scatter", mode = "markers",
                                  marker = list(color = "darkred", size = 14, symbol = "star"),
                                  text = ~paste0("PICO: ", etiq_completa),
                                  hoverinfo = "text", name = "Pico tonal")
      }
    }
    
    # ToBI annotations
    annotations_list <- list()
    if (input$export_mostrar_tobi && "pitch" %in% criterios && "tobi_fonologico" %in% colnames(vocales)) {
      for (i in 1:nrow(vocales)) {
        lbl <- vocales$tobi_fonologico[i]
        if (!is.na(lbl) && lbl != "") {
          annotations_list[[length(annotations_list) + 1]] <- list(
            x = vocales$pos[i], y = vocales$f0_norm_r[i],
            text = lbl, showarrow = FALSE,
            yshift = 18, font = list(color = "purple", size = 11))
        }
      }
      if ("tono_frontera_fonologico" %in% colnames(vocales)) {
        for (i in 1:nrow(vocales)) {
          lbl <- vocales$tono_frontera_fonologico[i]
          if (!is.na(lbl) && lbl != "") {
            annotations_list[[length(annotations_list) + 1]] <- list(
              x = vocales$pos[i], y = vocales$f0_norm_r[i],
              text = paste0("<b>", lbl, "</b>"), showarrow = FALSE,
              yshift = -18, font = list(color = "darkgreen", size = 11))
          }
        }
      }
    }
    
    col_patron <- if (input$export_tipo_patron == "amh") "amh_patron" else "tobi_nuclear"
    titulo <- paste0(ip$id_ge[1], " — ", col_patron, ": ", ip[[col_patron]][1])
    
    fig <- fig %>% layout(
      title = list(text = titulo, font = list(size = 14)),
      xaxis = list(title = "Vocal (palabra)", tickmode = "array",
                   tickvals = vocales$pos, ticktext = vocales$etiq_completa,
                   tickangle = -30, tickfont = list(size = 10)),
      yaxis = list(title = y_label),
      shapes = shapes_list,
      annotations = annotations_list,
      barmode = "overlay",
      legend = list(orientation = "h", y = -0.25, x = 0.5, xanchor = "center"),
      hovermode = "closest",
      margin = list(b = 120)
    )
    
    fig
  })
  
  output$info_export_graficos <- renderPrint({
    req(datos$calculado, datos$ips_resumen)
    ips <- datos$ips_resumen
    col_patron <- if (input$export_tipo_patron == "amh") "amh_patron" else "tobi_nuclear"
    
    cat("=== Resumen de patrones disponibles ===\n\n")
    tabla <- table(ips[[col_patron]])
    tabla <- sort(tabla, decreasing = TRUE)
    for (p in names(tabla)) {
      cat(sprintf("  %-25s : %d grupos\n", p, tabla[p]))
    }
    
    sel <- export_state$selected_ids
    if (length(sel) > 0) {
      n_versiones <- 1 + as.integer(input$export_normalizado) + as.integer(input$export_praatpicture)
      n_graficos <- length(sel) * n_versiones
      versiones_txt <- paste0(c("bruto",
                                if (input$export_normalizado) "normalizado",
                                if (input$export_praatpicture) "praatpicture"), collapse = " + ")
      cat(sprintf("\n--- Se generarán %d gráficos (%d grupos × %s) ---\n",
                  n_graficos, length(sel), versiones_txt))
    } else {
      cat("\n--- Selecciona grupos navegando con las flechas ---\n")
    }
  })
  
  output$descargar_graficos_batch <- downloadHandler(
    filename = function() {
      paste0("graficos_", input$export_tipo_patron, "_", Sys.Date(), ".zip")
    },
    content = function(file) {
      req(datos$calculado, datos$ips_resumen, datos$phones)
      
      sel_ids <- export_state$selected_ids
      if (length(sel_ids) == 0) {
        showNotification("No hay grupos seleccionados para exportar", type = "warning")
        return()
      }
      
      withProgress(message = 'Generando gráficos...', value = 0, {
        ips <- datos$ips_resumen
        phones <- datos$phones
        col_patron <- if (input$export_tipo_patron == "amh") "amh_patron" else "tobi_nuclear"
        
        tmpdir <- tempdir()
        graficos_dir <- file.path(tmpdir, "graficos_export")
        if (dir.exists(graficos_dir)) unlink(graficos_dir, recursive = TRUE)
        dir.create(graficos_dir, recursive = TRUE)
        
        # Medias por hablante para normalización
        medias_list <- list()
        for (spk in unique(phones$hablante)) {
          ph_spk <- phones[phones$hablante == spk, ]
          medias_list[[spk]] <- list(
            f0_media_st = mean(ph_spk$f0_media_st, na.rm = TRUE),
            f0_sd_st = sd(ph_spk$f0_media_st, na.rm = TRUE)
          )
        }
        
        formato <- input$export_formato
        ancho <- input$export_ancho / 96
        alto <- input$export_alto / 96
        
        total_plots <- 0
        
        # Exportar solo los grupos seleccionados
        ips_sel <- ips[ips$id_ge %in% sel_ids, ]
        
        for (j in 1:nrow(ips_sel)) {
          ip <- ips_sel[j, ]
          vocales_ge <- phones[phones$filename == ip$filename & phones$hablante == ip$hablante &
                                 phones$grupo_fonico == ip$grupo_fonico & phones$grupo_entonativo == ip$grupo_entonativo, ]
          
          if (nrow(vocales_ge) == 0) next
          
          patron <- ip[[col_patron]]
          if (is.na(patron)) patron <- "sin_patron"
          patron_clean <- gsub("[^a-zA-Z0-9_-]", "_", patron)
          patron_dir <- file.path(graficos_dir, patron_clean)
          dir.create(patron_dir, showWarnings = FALSE)
          
          base_name <- gsub("[^a-zA-Z0-9_-]", "_", ip$id_ge)
          
          # Opciones de visualización del panel de exportación
          exp_criterios <- input$export_criterios
          exp_tonicas <- input$export_mostrar_tonicas
          exp_picos <- input$export_mostrar_picos
          exp_secciones <- input$export_mostrar_secciones
          exp_tobi <- input$export_mostrar_tobi
          exp_estructura_vocal <- input$export_mostrar_estructura_vocal
          exp_tipo_norm <- input$tipo_normalizacion
          
          # Gráfico bruto
          p_bruto <- generar_grafico_ge(vocales_ge, titulo_extra = paste0("[", patron, "] (bruto)"),
                                         normalizado = FALSE,
                                         criterios = exp_criterios,
                                         mostrar_tonicas = exp_tonicas, mostrar_picos = exp_picos,
                                         mostrar_secciones = exp_secciones, mostrar_tobi = exp_tobi,
                                         mostrar_estructura_vocal = exp_estructura_vocal)
          if (!is.null(p_bruto)) {
            ggsave(file.path(patron_dir, paste0(base_name, "_bruto.", formato)),
                   p_bruto, width = ancho, height = alto, dpi = 300)
            total_plots <- total_plots + 1
          }
          
          # Gráfico normalizado
          if (input$export_normalizado) {
            p_norm <- generar_grafico_ge(vocales_ge, 
                                         titulo_extra = paste0("[", patron, "] (normalizado)"),
                                         normalizado = TRUE,
                                         criterios = exp_criterios,
                                         mostrar_tonicas = exp_tonicas, mostrar_picos = exp_picos,
                                         mostrar_secciones = exp_secciones, mostrar_tobi = exp_tobi,
                                         mostrar_estructura_vocal = exp_estructura_vocal,
                                         tipo_norm = exp_tipo_norm,
                                         medias_hablante_df = datos$medias_hablante)
            if (!is.null(p_norm)) {
              ggsave(file.path(patron_dir, paste0(base_name, "_norm.", formato)),
                     p_norm, width = ancho, height = alto, dpi = 300)
              total_plots <- total_plots + 1
            }
          }
          
          # Gráfico praatpicture
          if (input$export_praatpicture && praatpicture_disponible) {
            fn <- ip$filename
            wav_path <- NULL; tg_path <- NULL
            
            for (nombre in names(datos_audio$wavs)) {
              if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
                wav_path <- datos_audio$wavs[[nombre]]; break
              }
            }
            if (is.null(wav_path) && length(datos_audio$wavs) == 1) wav_path <- datos_audio$wavs[[1]]
            
            for (nombre in names(datos_textgrid$tgs)) {
              if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
                tg_path <- datos_textgrid$tgs[[nombre]]; break
              }
            }
            if (is.null(tg_path) && length(datos_textgrid$tgs) == 1) tg_path <- datos_textgrid$tgs[[1]]
            
            if (!is.null(wav_path) && !is.null(tg_path) &&
                file.exists(wav_path) && file.exists(tg_path)) {
              t_ini_pp <- max(0, min(vocales_ge$inicio, na.rm = TRUE) - 0.15)
              t_fin_pp <- max(vocales_ge$fin, na.rm = TRUE) + 0.15
              pp_file <- file.path(patron_dir, paste0(base_name, "_praatpicture.", formato))
              
              f0_vals <- vocales_ge$f0_media_st[!is.na(vocales_ge$f0_media_st)]
              if (length(f0_vals) > 0) {
                f0_min_pp <- min(f0_vals); f0_max_pp <- max(f0_vals)
                margen <- max(1, (f0_max_pp - f0_min_pp) * 0.3)
                pitch_range <- c(floor(f0_min_pp - margen), ceiling(f0_max_pp + margen))
              } else { pitch_range <- c(-5, 15) }
              
              tryCatch({
                generar_praatpicture_ge(
                  wav_path = wav_path, tg_path = tg_path,
                  t_inicio = t_ini_pp, t_fin = t_fin_pp,
                  titulo = paste0(ip$id_ge, " [", patron, "]"),
                  output_file = pp_file, ancho = ancho, alto = alto,
                  pitch_freqRange = pitch_range,
                  hablante = ip$hablante)
                if (file.exists(pp_file) && file.size(pp_file) > 0) total_plots <- total_plots + 1
              }, error = function(e) {
                warning("Error praatpicture para ", base_name, ": ", e$message)
              })
            }
          }
          
          # Compute clip time offset (shared by audio clip and TextGrid)
          t_ini_clip <- max(0, min(vocales_ge$tmin, na.rm = TRUE) - 0.1)
          t_fin_clip <- max(vocales_ge$tmax, na.rm = TRUE) + 0.1
          
          # Audio clip export
          if (input$export_audio_clip && tuneR_disponible) {
            fn <- ip$filename
            wav_path_exp <- NULL
            for (nombre in names(datos_audio$wavs)) {
              if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
                wav_path_exp <- datos_audio$wavs[[nombre]]; break
              }
            }
            if (is.null(wav_path_exp) && length(datos_audio$wavs) == 1) wav_path_exp <- datos_audio$wavs[[1]]
            
            if (!is.null(wav_path_exp) && file.exists(wav_path_exp)) {
              tryCatch({
                library(tuneR)
                wav <- readWave(wav_path_exp)
                sr <- wav@samp.rate
                from_s <- max(1, round(t_ini_clip * sr))
                to_s <- min(length(wav@left), round(t_fin_clip * sr))
                
                if (wav@stereo) {
                  segment <- Wave(left = wav@left[from_s:to_s], right = wav@right[from_s:to_s],
                                  samp.rate = sr, bit = wav@bit)
                } else {
                  segment <- Wave(left = wav@left[from_s:to_s], samp.rate = sr, bit = wav@bit)
                }
                writeWave(segment, file.path(patron_dir, paste0(base_name, ".wav")))
              }, error = function(e) warning("Error audio clip para ", base_name, ": ", e$message))
            }
          }
          
          # TextGrid export - tiempos relativos al inicio del clip (t_ini_clip = 0)
          if (input$export_textgrid_clip) {
            tryCatch({
              # Offset: restar t_ini_clip a todos los tiempos para sincronizar con el audio recortado
              tg_offset <- t_ini_clip
              t_ini_tg <- 0
              t_fin_tg <- t_fin_clip - tg_offset
              
              # Tier 1: vocales (phones) - ordenar por tmin
              vocales_sorted <- vocales_ge[order(vocales_ge$tmin), ]
              
              # Tier 2: words - derivar límites de las vocales agrupadas por palabra_idx
              palabras_list <- data.frame(
                palabra = character(0), w_tmin = numeric(0), w_tmax = numeric(0),
                stringsAsFactors = FALSE
              )
              if ("palabra_idx" %in% colnames(vocales_sorted)) {
                pal_idxs <- unique(vocales_sorted$palabra_idx[!is.na(vocales_sorted$palabra_idx)])
                for (pi in sort(pal_idxs)) {
                  voc_pal <- vocales_sorted[!is.na(vocales_sorted$palabra_idx) & vocales_sorted$palabra_idx == pi, ]
                  if (nrow(voc_pal) > 0 && any(voc_pal$palabra != "")) {
                    palabras_list <- rbind(palabras_list, data.frame(
                      palabra = voc_pal$palabra[1],
                      w_tmin = min(voc_pal$tmin, na.rm = TRUE),
                      w_tmax = max(voc_pal$tmax, na.rm = TRUE),
                      stringsAsFactors = FALSE
                    ))
                  }
                }
              } else {
                # Fallback: group by consecutive runs of same word text
                pals_raw <- vocales_sorted$palabra[!is.na(vocales_sorted$palabra) & vocales_sorted$palabra != ""]
                if (length(pals_raw) > 0) {
                  # Use run-length encoding to group consecutive same-word vowels
                  rle_pals <- rle(vocales_sorted$palabra)
                  end_idx <- cumsum(rle_pals$lengths)
                  start_idx <- c(1, head(end_idx, -1) + 1)
                  for (ri in seq_along(rle_pals$values)) {
                    pal_text <- rle_pals$values[ri]
                    if (is.na(pal_text) || pal_text == "") next
                    voc_run <- vocales_sorted[start_idx[ri]:end_idx[ri], ]
                    palabras_list <- rbind(palabras_list, data.frame(
                      palabra = pal_text,
                      w_tmin = min(voc_run$tmin, na.rm = TRUE),
                      w_tmax = max(voc_run$tmax, na.rm = TRUE),
                      stringsAsFactors = FALSE
                    ))
                  }
                }
              }
              
              # Generar archivo TextGrid
              n_tiers <- 3
              tg_content <- paste0(
                "File type = \"ooTextFile\"\n",
                "Object class = \"TextGrid\"\n\n",
                "xmin = ", format(t_ini_tg, scientific = FALSE), "\n",
                "xmax = ", format(t_fin_tg, scientific = FALSE), "\n",
                "tiers? <exists>\n",
                "size = ", n_tiers, "\n",
                "item []:\n"
              )
              
              # Tier 1: Vocales
              tg_content <- paste0(tg_content,
                "    item [1]:\n",
                "        class = \"IntervalTier\"\n",
                "        name = \"vocales\"\n",
                "        xmin = ", format(t_ini_tg, scientific = FALSE), "\n",
                "        xmax = ", format(t_fin_tg, scientific = FALSE), "\n",
                "        intervals: size = ", nrow(vocales_sorted), "\n")
              for (vi in 1:nrow(vocales_sorted)) {
                tg_content <- paste0(tg_content,
                  "        intervals [", vi, "]:\n",
                  "            xmin = ", format(vocales_sorted$tmin[vi] - tg_offset, scientific = FALSE), "\n",
                  "            xmax = ", format(vocales_sorted$tmax[vi] - tg_offset, scientific = FALSE), "\n",
                  "            text = \"", vocales_sorted$etiqueta[vi], "\"\n")
              }
              
              # Tier 2: Palabras
              if (nrow(palabras_list) > 0) {
                tg_content <- paste0(tg_content,
                  "    item [2]:\n",
                  "        class = \"IntervalTier\"\n",
                  "        name = \"words\"\n",
                  "        xmin = ", format(t_ini_tg, scientific = FALSE), "\n",
                  "        xmax = ", format(t_fin_tg, scientific = FALSE), "\n",
                  "        intervals: size = ", nrow(palabras_list), "\n")
                for (wi in 1:nrow(palabras_list)) {
                  tg_content <- paste0(tg_content,
                    "        intervals [", wi, "]:\n",
                    "            xmin = ", format(palabras_list$w_tmin[wi] - tg_offset, scientific = FALSE), "\n",
                    "            xmax = ", format(palabras_list$w_tmax[wi] - tg_offset, scientific = FALSE), "\n",
                    "            text = \"", palabras_list$palabra[wi], "\"\n")
                }
              } else {
                tg_content <- paste0(tg_content,
                  "    item [2]:\n",
                  "        class = \"IntervalTier\"\n",
                  "        name = \"words\"\n",
                  "        xmin = ", format(t_ini_tg, scientific = FALSE), "\n",
                  "        xmax = ", format(t_fin_tg, scientific = FALSE), "\n",
                  "        intervals: size = 1\n",
                  "        intervals [1]:\n",
                  "            xmin = ", format(t_ini_tg, scientific = FALSE), "\n",
                  "            xmax = ", format(t_fin_tg, scientific = FALSE), "\n",
                  "            text = \"\"\n")
              }
              
              # Tier 3: grupo entonativo (un solo intervalo)
              patron_label <- paste0(patron, " | ", ip$id_ge)
              tg_content <- paste0(tg_content,
                "    item [3]:\n",
                "        class = \"IntervalTier\"\n",
                "        name = \"grupo_entonativo\"\n",
                "        xmin = ", format(t_ini_tg, scientific = FALSE), "\n",
                "        xmax = ", format(t_fin_tg, scientific = FALSE), "\n",
                "        intervals: size = 1\n",
                "        intervals [1]:\n",
                "            xmin = ", format(t_ini_tg, scientific = FALSE), "\n",
                "            xmax = ", format(t_fin_tg, scientific = FALSE), "\n",
                "            text = \"", patron_label, "\"\n")
              
              writeLines(tg_content, file.path(patron_dir, paste0(base_name, ".TextGrid")))
            }, error = function(e) warning("Error TextGrid para ", base_name, ": ", e$message))
          }
          
          incProgress(1 / nrow(ips_sel), detail = paste0(ip$id_ge, " (", j, "/", nrow(ips_sel), ")"))
        }
        
        # Comprimir
        old_wd <- setwd(tmpdir)
        zip(file, files = list.files("graficos_export", recursive = TRUE, full.names = TRUE))
        setwd(old_wd)
        
        showNotification(paste(total_plots, "gráficos exportados"), type = "message")
      })
    }
  )
  
  # ========================================
  # UPOS DENSITY: Computar densidad de categorías gramaticales en GEs y GFs
  # Se ejecuta automáticamente cuando hay datos UDPIPE disponibles
  # ========================================
  computar_upos_densidad <- function() {
    req(datos$calculado, datos$phones)
    
    phones <- datos$phones
    if (!"upos" %in% colnames(phones)) return()
    
    tryCatch({
      upos_cats <- unique(phones$upos[!is.na(phones$upos)])
      
      # Densidad en IPs
      ips <- datos$ips_resumen
      if (!is.null(ips) && nrow(ips) > 0) {
        for (cat in upos_cats) {
          ips[[paste0("upos_", cat, "_n")]] <- 0L
          ips[[paste0("upos_", cat, "_dens")]] <- 0
        }
        
        for (i in 1:nrow(ips)) {
          ph_ge <- phones[phones$hablante == ips$hablante[i] & phones$filename == ips$filename[i] &
                            phones$grupo_fonico == ips$grupo_fonico[i] & phones$grupo_entonativo == ips$grupo_entonativo[i], ]
          dur <- ips$duracion[i]
          if (is.na(dur) || dur <= 0) dur <- 1
          
          # Contar UPOS por palabra única (evitar contar múltiples vocales de la misma palabra)
          palabras_unicas <- ph_ge[!duplicated(ph_ge$palabra_idx) & !is.na(ph_ge$upos), ]
          for (cat in upos_cats) {
            n_cat <- sum(palabras_unicas$upos == cat, na.rm = TRUE)
            ips[[paste0("upos_", cat, "_n")]][i] <- n_cat
            ips[[paste0("upos_", cat, "_dens")]][i] <- round(n_cat / dur, 2)
          }
        }
        datos$ips_resumen <- corregir_semitones_si_necesario(ips)
      }
      
      # Densidad en GFs
      gfs <- datos$gfs_resumen
      if (!is.null(gfs) && nrow(gfs) > 0) {
        for (cat in upos_cats) {
          gfs[[paste0("upos_", cat, "_n")]] <- 0L
          gfs[[paste0("upos_", cat, "_dens")]] <- 0
        }
        
        for (i in 1:nrow(gfs)) {
          ph_gf <- phones[phones$hablante == gfs$hablante[i] & phones$filename == gfs$filename[i] &
                            phones$grupo_fonico == gfs$grupo_fonico[i], ]
          dur <- gfs$duracion[i]
          if (is.na(dur) || dur <= 0) dur <- 1
          
          palabras_unicas <- ph_gf[!duplicated(ph_gf$palabra_idx) & !is.na(ph_gf$upos), ]
          for (cat in upos_cats) {
            n_cat <- sum(palabras_unicas$upos == cat, na.rm = TRUE)
            gfs[[paste0("upos_", cat, "_n")]][i] <- n_cat
            gfs[[paste0("upos_", cat, "_dens")]][i] <- round(n_cat / dur, 2)
          }
        }
        datos$gfs_resumen <- gfs
      }
      
      showNotification("Densidad UPOS computada en GEs y GFs", type = "message")
    }, error = function(e) {
      showNotification(paste("Error UPOS:", e$message), type = "warning")
    })
  }


  # ========================================
  # CLÁUSULAS — COROLARIO DE HIDALGO NAVARRO
  # Unidad supraentonativa: secuencia de GEs con declinación/inclinación
  # Cambio de cláusula: >30% cambio en F0 de la primera vocal del GE
  # ========================================

  # -----------------------------------------------------------------------
  # recalcular_ges_desde_phones()
  # Reasigna grupo_fonico y grupo_entonativo en datos$phones / datos$words
  # usando los umbrales actuales del input, SIN necesitar los archivos de
  # audio originales. Luego reconstruye datos$ips_resumen y opcionalmente
  # las cláusulas. Las emociones preexistentes se conservan por defecto.
  # -----------------------------------------------------------------------
  recalcular_ges_desde_phones <- function(solo_archivo = NULL, recalc_clausulas = TRUE) {
    req(datos$calculado, datos$phones)

    umbral_gf       <- if (!is.null(input$umbral_pausa_gf))       input$umbral_pausa_gf       else 0.3
    umbral_pitch    <- if (!is.null(input$umbral_pitch_ge))        input$umbral_pitch_ge       else 45
    pausa_ge_min    <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[1] else 0
    pausa_ge_max    <- if (!is.null(input$umbral_pausa_ge_interna)) input$umbral_pausa_ge_interna[2] else 0

    ph_all <- datos$phones
    if (is.null(ph_all) || nrow(ph_all) == 0) {
      showNotification("No hay datos de phones en memoria. Ejecuta el análisis completo primero.", type = "error")
      return(invisible(NULL))
    }

    # Guardar emociones previas antes de reconstruir ips_resumen
    cols_emo <- intersect(c("sentimiento","prob_pos","prob_neg","prob_neu",
                             "emocion_texto","prob_emocion_texto",
                             "emocion_audio","prob_emocion_audio","emocion_manual"),
                           colnames(datos$ips_resumen))
    emo_backup <- if (length(cols_emo) > 0 && !is.null(datos$ips_resumen)) {
      datos$ips_resumen %>%
        select(filename, hablante, inicio, fin, all_of(cols_emo))
    } else NULL

    # Filtrar a solo_archivo si aplica
    if (!is.null(solo_archivo)) {
      ph_otros <- ph_all[ph_all$filename != solo_archivo, ]
      ph_sel   <- ph_all[ph_all$filename == solo_archivo, ]
    } else {
      ph_otros <- data.frame()
      ph_sel   <- ph_all
    }

    if (nrow(ph_sel) == 0) {
      showNotification(paste0("No hay phones para: ", solo_archivo), type = "warning")
      return(invisible(NULL))
    }

    # ── Reasignar GF y GE por hablante+archivo ────────────────────────────
    combos <- unique(ph_sel[, c("filename","hablante")])
    ph_sel_new <- ph_sel  # copia que modificaremos

    for (ci in seq_len(nrow(combos))) {
      fn  <- combos$filename[ci]
      spk <- combos$hablante[ci]
      idx_combo <- which(ph_sel_new$filename == fn & ph_sel_new$hablante == spk)
      if (length(idx_combo) == 0) next
      ph_sub <- ph_sel_new[idx_combo, ]
      ph_sub <- ph_sub[order(ph_sub$inicio), ]
      n_rows <- nrow(ph_sub)

      gf <- 1L; ge <- 1L
      ph_sub$grupo_fonico    <- NA_integer_
      ph_sub$grupo_entonativo <- NA_integer_
      if ("es_inicio_ge" %in% colnames(ph_sub)) ph_sub$es_inicio_ge <- FALSE
      if ("f0_cambio_pct" %in% colnames(ph_sub)) ph_sub$f0_cambio_pct <- NA_real_

      for (i in seq_len(n_rows)) {
        if (i == 1) {
          ph_sub$grupo_fonico[i]    <- gf
          ph_sub$grupo_entonativo[i] <- ge
          if ("es_inicio_ge" %in% colnames(ph_sub)) ph_sub$es_inicio_ge[i] <- TRUE
          if ("pausa_anterior" %in% colnames(ph_sub)) ph_sub$pausa_anterior[i] <- NA_real_
        } else {
          pausa <- ph_sub$tmin[i] - ph_sub$tmax[i - 1]
          if (is.null(ph_sub$tmin)) pausa <- ph_sub$inicio[i] - ph_sub$fin[i - 1]
          if ("pausa_anterior" %in% colnames(ph_sub)) ph_sub$pausa_anterior[i] <- pausa

          if (!is.na(pausa) && pausa >= umbral_gf) {
            # Nueva pausa larga → nuevo GF y nuevo GE
            gf <- gf + 1L; ge <- 1L
            if ("es_inicio_ge" %in% colnames(ph_sub)) ph_sub$es_inicio_ge[i] <- TRUE
          } else {
            nuevo_ge <- FALSE

            # Criterio combinado (AND): pausa en rango + reajuste tonal
            if (pausa_ge_max > 0 && !is.na(pausa) &&
                pausa >= pausa_ge_min && pausa <= pausa_ge_max) {
              # pausa en rango — ahora también necesita reajuste tonal (se evalúa abajo)
              pausa_en_rango_local <- TRUE
            } else {
              pausa_en_rango_local <- FALSE
            }

            # Criterio de reajuste tonal (primera vocal de palabra)
            if ("es_primera_vocal_palabra" %in% colnames(ph_sub) &&
                isTRUE(ph_sub$es_primera_vocal_palabra[i]) &&
                "palabra_idx" %in% colnames(ph_sub)) {
              pal_act <- ph_sub$palabra_idx[i]
              if (!is.na(pal_act)) {
                idx_comp <- NA_integer_
                for (k in (i-1):1) {
                  if (!is.na(ph_sub$palabra_idx[k]) &&
                      ph_sub$palabra_idx[k] != pal_act &&
                      isTRUE(ph_sub$es_ultima_vocal_palabra[k])) {
                    idx_comp <- k; break
                  }
                }
                if (!is.na(idx_comp) &&
                    !is.na(ph_sub$f0_media_hz[i]) &&
                    !is.na(ph_sub$f0_media_hz[idx_comp]) &&
                    ph_sub$f0_media_hz[idx_comp] > 0) {
                  inc_p <- ((ph_sub$f0_media_hz[i] - ph_sub$f0_media_hz[idx_comp]) /
                             ph_sub$f0_media_hz[idx_comp]) * 100
                  if ("f0_cambio_pct" %in% colnames(ph_sub)) ph_sub$f0_cambio_pct[i] <- inc_p
                  # AND: reajuste + pausa en rango; si pausa_ge_max == 0: solo reajuste
                  if (inc_p > umbral_pitch && (pausa_en_rango_local || pausa_ge_max == 0)) {
                    nuevo_ge <- TRUE
                  }
                }
              }
            }

            if (nuevo_ge) {
              ge <- ge + 1L
              if ("es_inicio_ge" %in% colnames(ph_sub)) ph_sub$es_inicio_ge[i] <- TRUE
            }
          }
          ph_sub$grupo_fonico[i]    <- gf
          ph_sub$grupo_entonativo[i] <- ge
        }
      }
      ph_sel_new[idx_combo, ] <- ph_sub[match(ph_sel_new$inicio[idx_combo], ph_sub$inicio), ]
    }

    # ── Reconstruir ips_resumen desde phones actualizados ─────────────────
    ph_combined <- if (nrow(ph_otros) > 0) bind_rows(ph_otros, ph_sel_new) else ph_sel_new

    ips_nuevo <- data.frame()
    for (fn in unique(ph_combined$filename)) {
      for (spk in unique(ph_combined$hablante[ph_combined$filename == fn])) {
        phones_spk <- ph_combined[ph_combined$filename == fn & ph_combined$hablante == spk, ]
        for (gf_val in unique(phones_spk$grupo_fonico)) {
          for (ge_val in unique(phones_spk$grupo_entonativo[phones_spk$grupo_fonico == gf_val])) {
            vocales_ge <- phones_spk[phones_spk$grupo_fonico == gf_val &
                                     phones_spk$grupo_entonativo == ge_val, ]
            if (nrow(vocales_ge) == 0) next
            f0_vals <- vocales_ge$f0_media_st[!is.na(vocales_ge$f0_media_st)]
            # Palabras
            if ("palabra_idx" %in% colnames(vocales_ge)) {
              pal_df <- data.frame(
                idx = vocales_ge$palabra_idx[!is.na(vocales_ge$palabra_idx)],
                txt = vocales_ge$palabra[!is.na(vocales_ge$palabra_idx)],
                stringsAsFactors = FALSE)
              if (nrow(pal_df) > 0) {
                pal_df <- pal_df[!duplicated(pal_df$idx), ]
                pal_df <- pal_df[order(pal_df$idx), ]
                palabras_ordered <- pal_df$txt[pal_df$txt != ""]
              } else palabras_ordered <- character(0)
            } else {
              pals_raw <- vocales_ge$palabra[!is.na(vocales_ge$palabra) & vocales_ge$palabra != ""]
              palabras_ordered <- if (length(pals_raw) > 0)
                pals_raw[c(TRUE, pals_raw[-1] != pals_raw[-length(pals_raw)])] else character(0)
            }
            ip_row <- data.frame(
              filename         = fn,
              hablante         = spk,
              grupo_fonico     = gf_val,
              grupo_entonativo = ge_val,
              id_ge            = paste0(fn,"_",spk,"_GF",gf_val,"_GE",ge_val),
              inicio           = min(vocales_ge$inicio, na.rm = TRUE),
              fin              = max(vocales_ge$fin, na.rm = TRUE),
              duracion         = max(vocales_ge$fin, na.rm = TRUE) - min(vocales_ge$inicio, na.rm = TRUE),
              num_vocales      = nrow(vocales_ge),
              num_palabras     = length(palabras_ordered),
              velocidad_habla  = if ((max(vocales_ge$fin, na.rm=TRUE)-min(vocales_ge$inicio, na.rm=TRUE))>0)
                nrow(vocales_ge)/(max(vocales_ge$fin, na.rm=TRUE)-min(vocales_ge$inicio, na.rm=TRUE)) else NA_real_,
              f0_inicio_st     = if (length(f0_vals)>0) f0_vals[1] else NA,
              f0_pico_st       = if (length(f0_vals)>0) max(f0_vals) else NA,
              f0_fin_st        = if (length(f0_vals)>0) f0_vals[length(f0_vals)] else NA,
              f0_media_grupo_st= if (length(f0_vals)>0) mean(f0_vals) else NA,
              rango_f0_grupo_st= if (length(f0_vals)>1) max(f0_vals)-min(f0_vals) else 0,
              intensidad_media_grupo = if ("int_media" %in% colnames(vocales_ge))
                mean(vocales_ge$int_media, na.rm=TRUE) else NA_real_,
              transicion_media = if ("tiempo_transicion_anterior" %in% colnames(vocales_ge))
                mean(vocales_ge$tiempo_transicion_anterior, na.rm=TRUE) else NA_real_,
              posicion_pico_rel= NA_real_,
              palabras_grupo   = paste(palabras_ordered, collapse=" "),
              stringsAsFactors = FALSE
            )
            if (any(vocales_ge$es_pico_grupo, na.rm=TRUE))
              ip_row$posicion_pico_rel <- which(vocales_ge$es_pico_grupo)[1] / nrow(vocales_ge)
            ips_nuevo <- bind_rows(ips_nuevo, ip_row)
          }
        }
      }
    }

    # ── Restaurar emociones previas por solapamiento temporal (inicio+fin) ─
    if (!is.null(emo_backup) && nrow(ips_nuevo) > 0 && nrow(emo_backup) > 0) {
      ips_nuevo <- left_join(ips_nuevo,
        emo_backup %>% select(filename, hablante, inicio, fin, all_of(cols_emo)),
        by = c("filename","hablante","inicio","fin"))
    }

    # ── Copiar columnas adicionales que ya existían en ips_resumen ──────────
    if (!is.null(datos$ips_resumen)) {
      cols_extra <- setdiff(colnames(datos$ips_resumen),
                            c(colnames(ips_nuevo), cols_emo, "inicio","fin"))
      if (length(cols_extra) > 0) {
        join_key <- c("filename","hablante","inicio","fin")
        join_key <- intersect(join_key, colnames(datos$ips_resumen))
        extra_df <- datos$ips_resumen %>% select(all_of(c(join_key, cols_extra)))
        ips_nuevo <- left_join(ips_nuevo, extra_df, by = join_key)
      }
    }

    # ── Recalcular pausas anterior/posterior (orden temporal por archivo) ──
    if (nrow(ips_nuevo) > 0) {
      ips_nuevo <- ips_nuevo %>%
        dplyr::arrange(filename, inicio) %>%
        dplyr::group_by(filename) %>%
        dplyr::mutate(
          pausa_anterior  = ifelse(dplyr::row_number() == 1L, NA_real_,
                                   inicio - dplyr::lag(fin)),
          pausa_posterior = ifelse(dplyr::row_number() == dplyr::n(), NA_real_,
                                   dplyr::lead(inicio) - fin)
        ) %>%
        dplyr::ungroup()
    }

    datos$phones      <- ph_combined
    datos$ips_resumen <- corregir_semitones_si_necesario(ips_nuevo)

    # Propagar GEs a words si existen
    if (!is.null(datos$words) && nrow(datos$words) > 0) {
      ph_lookup <- ph_combined %>%
        select(filename, hablante, inicio, fin, grupo_fonico, grupo_entonativo) %>%
        distinct()
      datos$words <- datos$words %>%
        select(-any_of(c("grupo_fonico","grupo_entonativo"))) %>%
        left_join(ph_lookup, by = c("filename","hablante","inicio","fin"))
    }

    showNotification(
      paste0("✔ GEs recalculados: ",
             nrow(ips_nuevo), " grupos entonativos en ", n_distinct(ips_nuevo$filename), " archivo(s)."),
      type = "message", duration = 8
    )

    if (recalc_clausulas && !is.null(datos$clausulas)) {
      computar_clausulas()
      showNotification("✔ Cláusulas recalculadas.", type = "message", duration = 5)
    }

    invisible(TRUE)
  }

computar_clausulas <- function(umbral_pct = NULL, umbral_dif_st = NULL,
                               umbral_slope_st = NULL, umbral_pausa_gf_cl = NULL,
                               solo_archivo = NULL) {
  # Leer parámetros del input si no se pasan explícitamente
  umbral_pct      <- if (!is.null(umbral_pct))      umbral_pct      else
                       (if (!is.null(input$cl_umbral_f0_pct))          input$cl_umbral_f0_pct / 100  else 0.30)
  umbral_dif_st   <- if (!is.null(umbral_dif_st))   umbral_dif_st   else
                       (if (!is.null(input$cl_umbral_dif_st))          input$cl_umbral_dif_st        else 1.5)
  umbral_slope_st <- if (!is.null(umbral_slope_st)) umbral_slope_st else
                       (if (!is.null(input$cl_umbral_slope_st))        input$cl_umbral_slope_st      else 0.3)
  umbral_pausa_gf_cl <- if (!is.null(umbral_pausa_gf_cl)) umbral_pausa_gf_cl else
                       (if (!is.null(input$cl_umbral_pausa_gf_clausula)) input$cl_umbral_pausa_gf_clausula else 0)
  tryCatch({
    req(datos$ips_resumen, datos$phones)
    ips    <- datos$ips_resumen
    phones <- datos$phones

    # ── Coerción de tipos ────────────────────────────────────────────────────
    for (jcol in c("filename", "hablante")) {
      if (jcol %in% colnames(phones)) phones[[jcol]] <- as.character(phones[[jcol]])
      if (jcol %in% colnames(ips))    ips[[jcol]]    <- as.character(ips[[jcol]])
    }
    for (jcol in c("grupo_fonico", "grupo_entonativo")) {
      if (jcol %in% colnames(phones)) phones[[jcol]] <- as.integer(phones[[jcol]])
      if (jcol %in% colnames(ips))    ips[[jcol]]    <- as.integer(ips[[jcol]])
    }

    if (!"f0_media_hz" %in% colnames(phones)) {
      showNotification("Cláusulas: columna f0_media_hz no encontrada en phones", type = "warning")
      return(invisible(NULL))
    }

    # ── Si solo_archivo: separar datos del archivo del resto ─────────────────
    if (!is.null(solo_archivo)) {
      ips_otros    <- ips[ips$filename != solo_archivo, ]
      phones_otros <- phones[phones$filename != solo_archivo, ]
      ips          <- ips[ips$filename == solo_archivo, ]
      phones       <- phones[phones$filename == solo_archivo, ]

      if (nrow(ips) == 0) {
        showNotification(paste0("No se encontraron datos para: ", solo_archivo), type = "warning")
        return(invisible(NULL))
      }
    }

    # ── F0 primera vocal por GE ──────────────────────────────────────────────
    primera_vocal <- phones %>%
      filter(!is.na(f0_media_hz), f0_media_hz > 0) %>%
      group_by(filename, hablante, grupo_fonico, grupo_entonativo) %>%
      arrange(inicio) %>%
      slice(1) %>%
      ungroup() %>%
      select(filename, hablante, grupo_fonico, grupo_entonativo,
             f0_primera_hz = f0_media_hz)

    if (nrow(primera_vocal) == 0) {
      showNotification("Cláusulas: no se encontraron vocales con F0 válido", type = "warning")
      return(invisible(NULL))
    }

    # ── Limpiar columnas previas en ips ──────────────────────────────────────
    ips$f0_primera_hz     <- NULL
    ips$clausula_id       <- NULL
    ips$clausula_posicion <- NULL

    # Asegurar que primera_vocal es única por clave (evita duplicar filas en left_join)
    primera_vocal <- primera_vocal %>%
      group_by(filename, hablante, grupo_fonico, grupo_entonativo) %>%
      slice(1) %>%
      ungroup()

    n_ips_antes <- nrow(ips)
    ips <- left_join(ips, primera_vocal,
                     by = c("filename", "hablante", "grupo_fonico", "grupo_entonativo"))
    ips <- as.data.frame(ips)
    if (nrow(ips) != n_ips_antes) {
      # El join multiplicó filas — tomar solo la primera ocurrencia por fila original
      ips <- ips %>%
        group_by(filename, hablante, grupo_fonico, grupo_entonativo) %>%
        slice(1) %>%
        ungroup() %>%
        as.data.frame()
    }
    ips <- ips %>% arrange(filename, hablante, inicio)
    ips$clausula_id       <- NA_integer_
    ips$clausula_posicion <- NA_integer_

    clausula_df <- list()

    # ── Iterar por combinación archivo+hablante ──────────────────────────────
    combos <- unique(data.frame(
      filename = ips$filename,
      hablante = ips$hablante,
      stringsAsFactors = FALSE
    ))

    for (ci in seq_len(nrow(combos))) {
      fn  <- combos$filename[ci]
      spk <- combos$hablante[ci]

      idx <- which(ips$filename == fn & ips$hablante == spk)
      if (length(idx) == 0) next

      cl_num     <- 1L
      cl_pos     <- 1L
      prev_f0_hz <- NA_real_

      # GEs de otros hablantes en este archivo (para detectar interrupciones)
      ips_otros_hablantes <- ips[ips$filename == fn & ips$hablante != spk, ]

      for (i in seq_along(idx)) {
        r          <- idx[i]
        curr_f0_hz <- ips$f0_primera_hz[r]

        if (i == 1) {
          prev_f0_hz <- curr_f0_hz
        } else {
          prev_r <- idx[i - 1]
          prev_fin    <- ips$fin[prev_r]
          curr_inicio <- ips$inicio[r]

          # Criterio 0: otro hablante intervino entre el GE anterior y el actual
          # → siempre inicia nueva cláusula (independientemente del F0)
          nueva_cl_interrupcion <- FALSE
          if (!is.na(prev_fin) && !is.na(curr_inicio) && nrow(ips_otros_hablantes) > 0) {
            nueva_cl_interrupcion <- any(
              ips_otros_hablantes$inicio >= prev_fin &
              ips_otros_hablantes$inicio <  curr_inicio
            )
          }

          if (nueva_cl_interrupcion) {
            cl_num <- cl_num + 1L
            cl_pos <- 1L
            prev_f0_hz <- curr_f0_hz
          } else if (!is.na(curr_f0_hz) && !is.na(prev_f0_hz) && prev_f0_hz > 0) {
            pct_change <- abs(curr_f0_hz - prev_f0_hz) / prev_f0_hz
            # Criterio 1: cambio de F0 entre primera vocal de GEs consecutivos
            nueva_cl_f0 <- pct_change > umbral_pct
            # Criterio 2: pausa entre GFs (si umbral > 0)
            nueva_cl_pausa <- FALSE
            if (umbral_pausa_gf_cl > 0) {
              curr_gf  <- ips$grupo_fonico[r]
              prev_gf  <- ips$grupo_fonico[prev_r]
              if (!is.na(curr_gf) && !is.na(prev_gf) && curr_gf != prev_gf) {
                pausa_entre <- ips$inicio[r] - ips$fin[prev_r]
                if (!is.na(pausa_entre) && pausa_entre > umbral_pausa_gf_cl) nueva_cl_pausa <- TRUE
              }
            }
            if (nueva_cl_f0 || nueva_cl_pausa) {
              cl_num <- cl_num + 1L
              cl_pos <- 1L
            }
          }
        }

        ips$clausula_id[r]       <- cl_num
        ips$clausula_posicion[r] <- cl_pos
        cl_pos <- cl_pos + 1L
        if (!is.na(curr_f0_hz) && curr_f0_hz > 0) prev_f0_hz <- curr_f0_hz
      }

      # ── Resumen por cláusula ───────────────────────────────────────────────
      cls_en_combo <- sort(unique(ips$clausula_id[idx]))

      for (cl in cls_en_combo) {
        cl_idx    <- idx[ips$clausula_id[idx] == cl]
        cl_ips    <- ips[cl_idx, ]

        ge_key <- function(df) paste(
          as.character(df$filename),
          as.character(df$hablante),
          as.character(df$grupo_fonico),
          as.character(df$grupo_entonativo),
          sep = "|||"
        )

        cl_phones <- phones[ge_key(phones) %in% ge_key(cl_ips), ]
        cl_phones <- cl_phones[order(cl_phones$inicio), ]

        # Fallback por rango temporal
        if (nrow(cl_phones) == 0 && nrow(cl_ips) > 0) {
          t_start   <- min(cl_ips$inicio, na.rm = TRUE) - 0.01
          t_end     <- max(cl_ips$fin,   na.rm = TRUE)  + 0.01
          cl_phones <- phones[
            phones$filename == fn & phones$hablante == spk &
            phones$centro >= t_start & phones$centro <= t_end, ]
          cl_phones <- cl_phones[order(cl_phones$inicio), ]
        }

        f0_all_st <- cl_phones$f0_media_st[!is.na(cl_phones$f0_media_st)]
        f0_all_hz <- cl_phones$f0_media_hz[
          !is.na(cl_phones$f0_media_hz) & cl_phones$f0_media_hz > 0]

        # Fallback a ips_resumen
        if (length(f0_all_st) == 0 && "f0_media_grupo_st" %in% colnames(cl_ips)) {
          f0_all_st <- cl_ips$f0_media_grupo_st[!is.na(cl_ips$f0_media_grupo_st)]
        }
        if (length(f0_all_hz) == 0) {
          f0_all_hz <- cl_ips$f0_primera_hz[
            !is.na(cl_ips$f0_primera_hz) & cl_ips$f0_primera_hz > 0]
        }

        # ── Clasificación contorno ─────────────────────────────────────────
        slope_st <- NA_real_
        slope_hz <- NA_real_
        tipo     <- "plana"

        if (length(f0_all_st) >= 2) {
          fit_st   <- lm(f0_all_st ~ seq_along(f0_all_st))
          slope_st <- coef(fit_st)[2]
          dif_st   <- f0_all_st[length(f0_all_st)] - f0_all_st[1]
          rango_st <- max(f0_all_st) - min(f0_all_st)

          tipo <- if      (dif_st >  umbral_dif_st && slope_st >  0)  "ascendente"
                  else if (dif_st < -umbral_dif_st && slope_st <  0)  "descendente"
                  else if (abs(dif_st) > umbral_dif_st)               if (dif_st > 0) "ascendente" else "descendente"
                  else if (abs(slope_st) > umbral_slope_st)           if (slope_st > 0) "ascendente" else "descendente"
                  else if (rango_st > 3)                              if (dif_st > 0) "ascendente" else if (dif_st < 0) "descendente" else "plana"
                  else "plana"
        }

        if (length(f0_all_hz) >= 2) {
          fit_hz   <- lm(f0_all_hz ~ seq_along(f0_all_hz))
          slope_hz <- coef(fit_hz)[2]
        }

        clausula_df[[length(clausula_df) + 1]] <- data.frame(
          clausula_id        = cl,
          filename           = fn,
          hablante           = spk,
          clausula_global_id = paste0(fn, "|||", spk, "|||CL", cl),
          n_ge               = nrow(cl_ips),
          n_gf               = n_distinct(cl_ips$grupo_fonico),
          n_vocales          = nrow(cl_phones),
          inicio             = min(cl_ips$inicio, na.rm = TRUE),
          fin                = max(cl_ips$fin,    na.rm = TRUE),
          duracion           = round(max(cl_ips$fin, na.rm = TRUE) -
                                     min(cl_ips$inicio, na.rm = TRUE), 3),
          velocidad_habla    = {
            dur_cl <- max(cl_ips$fin, na.rm = TRUE) - min(cl_ips$inicio, na.rm = TRUE)
            if (dur_cl > 0) nrow(cl_phones) / dur_cl else NA_real_
          },
          intensidad_media   = if ("int_media" %in% colnames(cl_phones))
                                 round(mean(cl_phones$int_media, na.rm = TRUE), 2) else NA_real_,
          transicion_media   = if ("tiempo_transicion_anterior" %in% colnames(cl_phones))
                                 round(mean(cl_phones$tiempo_transicion_anterior, na.rm = TRUE), 4) else NA_real_,
          f0_inicio_hz       = if (length(f0_all_hz) > 0) round(f0_all_hz[1], 1) else NA_real_,
          f0_fin_hz          = if (length(f0_all_hz) > 0) round(f0_all_hz[length(f0_all_hz)], 1) else NA_real_,
          f0_inicio_st       = if (length(f0_all_st) > 0) round(f0_all_st[1], 2) else NA_real_,
          f0_fin_st          = if (length(f0_all_st) > 0) round(f0_all_st[length(f0_all_st)], 2) else NA_real_,
          dif_global_st      = if (length(f0_all_st) >= 2)
                                 round(f0_all_st[length(f0_all_st)] - f0_all_st[1], 2) else NA_real_,
          rango_global_st    = if (length(f0_all_st) >= 2)
                                 round(max(f0_all_st) - min(f0_all_st), 2) else NA_real_,
          slope_hz           = round(slope_hz, 3),
          slope_st           = round(slope_st, 4),
          tipo               = tipo,
          n_vocales_clasif   = length(f0_all_st),
          palabras           = paste(
            cl_ips$palabras_grupo[!is.na(cl_ips$palabras_grupo)],
            collapse = " / "),
          stringsAsFactors   = FALSE
        )
      }
    }

    # ── Consolidar resultados ────────────────────────────────────────────────
    clausula_df_final <- bind_rows(clausula_df)

    # ── Helper: propagar clausula_id a words por solapamiento temporal ──────
    # (más fiable que join por GF/GE, cuyos números pueden diferir entre tiers)
    propagar_clausula_words_temporal <- function(wd, cl_df) {
      if (is.null(wd) || nrow(wd) == 0) return(wd)
      if (is.null(cl_df) || nrow(cl_df) == 0) return(wd)
      if (!all(c("inicio", "fin") %in% colnames(wd))) return(wd)
      if (!all(c("inicio", "fin", "clausula_id", "filename", "hablante") %in% colnames(cl_df))) return(wd)
      wd$clausula_id       <- NA_integer_
      wd$clausula_posicion <- NA_character_
      for (wi in seq_len(nrow(wd))) {
        centro_w <- (wd$inicio[wi] + wd$fin[wi]) / 2
        fn_w     <- wd$filename[wi]
        spk_w    <- wd$hablante[wi]
        candidates <- cl_df[cl_df$filename == fn_w & cl_df$hablante == spk_w &
                              cl_df$inicio <= centro_w + 0.02 & cl_df$fin >= centro_w - 0.02, ]
        if (nrow(candidates) > 0) {
          best <- which.min(abs(((candidates$inicio + candidates$fin) / 2) - centro_w))
          wd$clausula_id[wi] <- candidates$clausula_id[best]
          if ("clausula_posicion" %in% colnames(candidates))
            wd$clausula_posicion[wi] <- candidates$clausula_posicion[best]
        }
      }
      wd
    }

    # ── Lookup para propagar clausula_id ────────────────────────────────────
    cl_lookup <- ips %>%
      select(filename, hablante, grupo_fonico, grupo_entonativo,
             clausula_id, clausula_posicion)

    if (!is.null(solo_archivo)) {
      # ── Modo archivo único: combinar con resultados previos ──────────────

      # ips_resumen
      datos$ips_resumen <- corregir_semitones_si_necesario(as.data.frame(bind_rows(ips_otros, ips)))

      # clausulas
      clausulas_otros <- if (!is.null(datos$clausulas) && nrow(datos$clausulas) > 0)
        datos$clausulas[datos$clausulas$filename != solo_archivo, ]
      else
        data.frame()
      datos$clausulas <- bind_rows(clausulas_otros, clausula_df_final)

      # phones
      if (!is.null(datos$phones) && nrow(datos$phones) > 0) {
        ph_otros <- datos$phones[datos$phones$filename != solo_archivo, ]
        ph_sel   <- datos$phones[datos$phones$filename == solo_archivo, ]
        ph_sel$clausula_id       <- NULL
        ph_sel$clausula_posicion <- NULL
        ph_sel <- left_join(ph_sel, cl_lookup,
                            by = c("filename", "hablante", "grupo_fonico", "grupo_entonativo"))
        datos$phones <- bind_rows(ph_otros, ph_sel)
      }

      # words (por tiempo, más fiable que join por GF/GE)
      if (!is.null(datos$words) && nrow(datos$words) > 0) {
        wd_otros <- datos$words[datos$words$filename != solo_archivo, ]
        wd_sel   <- datos$words[datos$words$filename == solo_archivo, ]
        wd_sel   <- propagar_clausula_words_temporal(wd_sel, clausula_df_final)
        datos$words <- bind_rows(wd_otros, wd_sel)
      }

      # gfs_resumen
      if (!is.null(datos$gfs_resumen) && nrow(datos$gfs_resumen) > 0) {
        gf_cl <- ips %>%
          group_by(filename, hablante, grupo_fonico) %>%
          arrange(grupo_entonativo) %>%
          summarise(clausula_id = first(clausula_id), .groups = "drop")
        gf_otros <- datos$gfs_resumen[datos$gfs_resumen$filename != solo_archivo, ]
        gf_sel   <- datos$gfs_resumen[datos$gfs_resumen$filename == solo_archivo, ]
        gf_sel$clausula_id <- NULL
        gf_sel <- left_join(gf_sel, gf_cl,
                            by = c("filename", "hablante", "grupo_fonico"))
        datos$gfs_resumen <- bind_rows(gf_otros, gf_sel)
      }

    } else {
      # ── Modo completo: reemplazar todo ───────────────────────────────────
      datos$ips_resumen <- corregir_semitones_si_necesario(as.data.frame(ips))
      datos$clausulas   <- clausula_df_final

      if (!is.null(datos$phones) && nrow(datos$phones) > 0) {
        ph <- datos$phones
        ph$clausula_id       <- NULL
        ph$clausula_posicion <- NULL
        datos$phones <- left_join(ph, cl_lookup,
                                  by = c("filename", "hablante", "grupo_fonico", "grupo_entonativo"))
      }

      # words (por tiempo, más fiable que join por GF/GE)
      if (!is.null(datos$words) && nrow(datos$words) > 0) {
        datos$words <- propagar_clausula_words_temporal(datos$words, clausula_df_final)
      }

      if (!is.null(datos$gfs_resumen) && nrow(datos$gfs_resumen) > 0) {
        gf_cl <- ips %>%
          group_by(filename, hablante, grupo_fonico) %>%
          arrange(grupo_entonativo) %>%
          summarise(clausula_id = first(clausula_id), .groups = "drop")
        gf <- datos$gfs_resumen
        gf$clausula_id <- NULL
        datos$gfs_resumen <- left_join(gf, gf_cl,
                                       by = c("filename", "hablante", "grupo_fonico"))
      }
    }

    n_cl   <- nrow(clausula_df_final)
    n_asc  <- sum(clausula_df_final$tipo == "ascendente",  na.rm = TRUE)
    n_desc <- sum(clausula_df_final$tipo == "descendente", na.rm = TRUE)
    n_plna <- sum(clausula_df_final$tipo == "plana",       na.rm = TRUE)
    archivo_txt <- if (!is.null(solo_archivo)) paste0(" [", solo_archivo, "]") else ""
    showNotification(
      paste0("✔ ", n_cl, " cláusulas computadas", archivo_txt, " (",
             n_asc, " asc. / ", n_desc, " desc. / ", n_plna, " plana)"),
      type = "message")
    log_event("CLAUSULAS_COMPUTADAS",
              paste("N:", n_cl, "| Umbral:", umbral_pct * 100, "%",
                    if (!is.null(solo_archivo)) paste("| Archivo:", solo_archivo) else ""))
    guardar_todos_por_archivo(notificar_cada = FALSE)
    showModal(modalDialog(
      title = tagList(icon("check-circle", class = "text-success"), " Cl\u00e1usulas calculadas y guardadas"),
      paste0("\u2714 ", n_cl, " cl\u00e1usulas", archivo_txt, " (", n_asc, " asc. / ",
             n_desc, " desc. / ", n_plna, " plana). Guardado en disco."),
      easyClose = TRUE, footer = modalButton("Cerrar")
    ))
  }, error = function(e) {
    showNotification(paste("Error cláusulas:", e$message), type = "warning")
  })
}

 pm_archivos <- reactiveValues(wavs = list(), tgs = list())

  observeEvent(input$pm_wav_files, {
    req(input$pm_wav_files)
    for (i in 1:nrow(input$pm_wav_files)) {
      nombre <- tools::file_path_sans_ext(input$pm_wav_files$name[i])
      pm_archivos$wavs[[nombre]] <- input$pm_wav_files$datapath[i]
      # Copiar a almacenamiento persistente
      copiar_audio_persistente(input$pm_wav_files$datapath[i], input$pm_wav_files$name[i])
    }
    showNotification(paste(nrow(input$pm_wav_files), "WAV cargado(s) para Parselmouth"), type = "message")
  })

  observeEvent(input$pm_tg_files, {
    req(input$pm_tg_files)
    for (i in 1:nrow(input$pm_tg_files)) {
      nombre <- tools::file_path_sans_ext(input$pm_tg_files$name[i])
      pm_archivos$tgs[[nombre]] <- input$pm_tg_files$datapath[i]
      # Copiar a almacenamiento persistente
      copiar_textgrid_persistente(input$pm_tg_files$datapath[i], input$pm_tg_files$name[i])
    }
    showNotification(paste(nrow(input$pm_tg_files), "TextGrid cargado(s) para Parselmouth"), type = "message")
  })

  output$pm_estado <- renderPrint({
    n_wav <- length(pm_archivos$wavs)
    n_tg <- length(pm_archivos$tgs)
    if (n_wav == 0 && n_tg == 0) {
      cat("Sube archivos .wav y .TextGrid con el mismo nombre base.\n")
    } else {
      cat(n_wav, "WAV y", n_tg, "TextGrid cargados.\n")
      comunes <- intersect(names(pm_archivos$wavs), names(pm_archivos$tgs))
      if (length(comunes) > 0) {
        cat("Pares detectados:", paste(comunes, collapse = ", "), "\n")
      } else {
        cat("\u26A0 No se encontraron pares coincidentes.\n")
      }
    }
  })

  observeEvent(input$btn_pm_procesar, {
    comunes <- intersect(names(pm_archivos$wavs), names(pm_archivos$tgs))
    if (length(comunes) == 0) {
      showNotification("No hay pares wav/TextGrid con el mismo nombre", type = "error")
      return()
    }

    withProgress(message = "Ejecutando Parselmouth...", value = 0, {
      tryCatch({
        tmpdir <- tempdir()
        in_dir <- file.path(tmpdir, "pm_input")
        out_dir <- file.path(tmpdir, "pm_output")
        dir.create(in_dir, recursive = TRUE, showWarnings = FALSE)
        dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)

        # Limpiar directorio de entrada
        old_files <- list.files(in_dir, full.names = TRUE)
        if (length(old_files) > 0) file.remove(old_files)

        incProgress(0.1, detail = "Copiando archivos...")

        # Copiar archivos con nombres originales
        for (nm in comunes) {
          # WAV
          wav_src <- pm_archivos$wavs[[nm]]
          wav_ext <- if (!is.null(input$pm_wav_files))
            tools::file_ext(input$pm_wav_files$name[
              match(nm, tools::file_path_sans_ext(input$pm_wav_files$name))])
          else character(0)
          if (length(wav_ext) == 0 || is.na(wav_ext) || wav_ext == "") wav_ext <- "wav"
          file.copy(wav_src, file.path(in_dir, paste0(nm, ".", wav_ext)), overwrite = TRUE)

          # TextGrid
          tg_src <- pm_archivos$tgs[[nm]]
          file.copy(tg_src, file.path(in_dir, paste0(nm, ".TextGrid")), overwrite = TRUE)
        }

        incProgress(0.2, detail = paste0("Procesando ", length(comunes), " par(es)..."))

        # Buscar script Python
        script_path <- file.path(getwd(), "extract_with_parselmouth.py")
        if (!file.exists(script_path)) {
          # Intentar en directorio de la app
          possible_dirs <- c(
            dirname(sys.frame(1)$ofile %||% "."),
            system.file(package = "shiny"),
            "."
          )
          for (d in possible_dirs) {
            candidate <- file.path(d, "extract_with_parselmouth.py")
            if (file.exists(candidate)) { script_path <- candidate; break }
          }
        }

        if (!file.exists(script_path)) {
          showNotification(
            "No se encontró extract_with_parselmouth.py. Colócalo junto a app.R.",
            type = "error", duration = 10)
          return()
        }

        # Construir comando (python_bin: cross-platform, prefiere venv)
        py_pm <- Filter(function(p) nchar(p) > 0 && file.exists(p),
                        c(.python_venv_path, .python_sys_candidates))[1]
        if (is.na(py_pm) || is.null(py_pm)) py_pm <- "python3"
        cmd <- paste(
          shQuote(py_pm), shQuote(script_path),
          "--input_dir", shQuote(in_dir),
          "--output_dir", shQuote(out_dir),
          "--pitch_floor", input$pm_pitch_floor,
          "--pitch_ceiling", input$pm_pitch_ceiling,
          "--time_step_pitch", input$pm_step_pitch,
          "--time_step_intensity", input$pm_step_int,
          "--voicing_threshold", if (!is.null(input$pm_voicing_threshold)) input$pm_voicing_threshold else 0.15,
          "--silence_threshold", if (!is.null(input$pm_silence_threshold)) input$pm_silence_threshold else 0.01
        )

        incProgress(0.3, detail = "Ejecutando parselmouth...")

        result <- system(cmd, intern = TRUE, ignore.stderr = FALSE)

        incProgress(0.7, detail = "Leyendo resultados...")

        # Verificar archivos de salida
        text_file <- file.path(out_dir, "text_combined.txt")
        pitch_file <- file.path(out_dir, "pitch_combined.txt")
        int_file <- file.path(out_dir, "intensity_combined.txt")

        if (!file.exists(text_file) || !file.exists(pitch_file) || !file.exists(int_file)) {
          showNotification(
            paste("Parselmouth no generó los archivos esperados.\nSalida:",
                  paste(result, collapse = "\n")),
            type = "error", duration = 10)
          return()
        }

        # Cargar archivos generados
        all_texto <- read.delim(text_file, header = TRUE, stringsAsFactors = FALSE)
        all_pitch <- read.delim(pitch_file, header = TRUE, stringsAsFactors = FALSE)
        all_int <- read.delim(int_file, header = TRUE, stringsAsFactors = FALSE)

        # Asegurar tipos
        all_pitch$f0 <- as.numeric(all_pitch$f0)
        all_pitch$tiempo <- as.numeric(all_pitch$tiempo)
        all_pitch <- all_pitch[!is.na(all_pitch$f0) & all_pitch$f0 > 0, ]

        all_int$intensidad <- as.numeric(all_int$intensidad)
        all_int$tiempo <- as.numeric(all_int$tiempo)
        all_int <- all_int[!is.na(all_int$intensidad), ]

        all_texto$tmin <- as.numeric(all_texto$tmin)
        all_texto$tmax <- as.numeric(all_texto$tmax)

        # Almacenar en datos reactivos (misma estructura que modo Praat y txt)
        datos$texto <- all_texto
        datos$pitch <- all_pitch
        datos$intensidad <- all_int
        
        # Guardar archivos preprocesados individuales
        guardar_preprocesados()
        log_event("PARSELMOUTH_COMPLETADO", paste0(length(comunes), " archivo(s) procesados"))

        # También registrar wavs y textgrids para audio/praatpicture
        for (nm in comunes) {
          wav_ext2 <- if (!is.null(input$pm_wav_files))
            tools::file_ext(input$pm_wav_files$name[
              match(nm, tools::file_path_sans_ext(input$pm_wav_files$name))])
          else character(0)
          if (length(wav_ext2) == 0 || is.na(wav_ext2) || wav_ext2 == "") wav_ext2 <- "wav"
          datos_audio$wavs[[nm]] <- file.path(in_dir, paste0(nm, ".", wav_ext2))
          datos_textgrid$tgs[[nm]] <- file.path(in_dir, paste0(nm, ".TextGrid"))
          # Auto-copiar a almacenamiento persistente
          tryCatch({
            copiar_audio_persistente(file.path(in_dir, paste0(nm, ".", wav_ext2)), paste0(nm, ".", wav_ext2))
            copiar_textgrid_persistente(file.path(in_dir, paste0(nm, ".TextGrid")), paste0(nm, ".TextGrid"))
          }, error = function(e) NULL)
        }

        incProgress(1.0, detail = "¡Completado!")

        # Parsear resumen JSON
        json_line <- tail(result, 1)
        resumen <- tryCatch({
          info <- fromJSON(json_line)
          paste0(
            "\u2714 Parselmouth: ", info$archivos_procesados, " archivo(s)",
            if (info$archivos_omitidos > 0) paste0(" (", info$archivos_omitidos, " omitidos)") else "",
            "\n  Texto: ", info$total_intervalos_texto, " intervalos",
            "\n  Pitch: ", info$total_frames_pitch, " frames",
            "\n  Intensidad: ", info$total_frames_intensidad, " frames",
            "\n\n¡Ahora pulsa 'Calcular'!")
        }, error = function(e) {
          paste0("\u2714 Datos extraídos. Pulsa 'Calcular'.")
        })

        showNotification(resumen, type = "message", duration = 10)

      }, error = function(e) {
        showNotification(paste("Error Parselmouth:", e$message), type = "error", duration = 10)
      })
    })
  }) 

  # ========================================
  # ETIQUETADO MANUAL DE EMOCIONES
  # ========================================
  
  etiq <- reactiveValues(
    anotaciones = NULL,   # data.frame con: fila_ip, id_ge, acto_id, acto_tipo, emocion_manual
    pos_actual = 1,       # posición actual en ips_resumen
    acto_counter = 0,     # contador de actos
    ultimo_guardado = NULL,
    backup_dir = NULL
  )
  
  # Helper: buscar wav para un filename
  buscar_wav <- function(fn) {
    wav_path <- NULL
    # Buscar en datos_audio$wavs (cargados en sesión)
    for (nombre in names(datos_audio$wavs)) {
      if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
        wav_path <- datos_audio$wavs[[nombre]]; break
      }
    }
    if (is.null(wav_path) && length(datos_audio$wavs) == 1) wav_path <- datos_audio$wavs[[1]]
    # Si no, buscar en almacenamiento persistente
    if (is.null(wav_path) || !file.exists(wav_path)) {
      for (ext in c(".wav", ".WAV", ".flac", ".mp3")) {
        candidate <- file.path(lasp_audios, paste0(fn, ext))
        if (file.exists(candidate)) { wav_path <- candidate; break }
      }
      if (is.null(wav_path) || !file.exists(wav_path)) {
        audios_storage <- list.files(lasp_audios, full.names = TRUE)
        for (ap in audios_storage) {
          if (grepl(fn, basename(ap), fixed = TRUE) || grepl(tools::file_path_sans_ext(basename(ap)), fn, fixed = TRUE)) {
            wav_path <- ap; break
          }
        }
      }
    }
    wav_path
  }
  
  buscar_tg <- function(fn) {
    tg_path <- NULL
    for (nombre in names(datos_textgrid$tgs)) {
      if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
        tg_path <- datos_textgrid$tgs[[nombre]]; break
      }
    }
    if (is.null(tg_path) && length(datos_textgrid$tgs) == 1) tg_path <- datos_textgrid$tgs[[1]]
    # Buscar en almacenamiento persistente
    if (is.null(tg_path) || !file.exists(tg_path)) {
      candidate <- file.path(lasp_textgrids, paste0(fn, ".TextGrid"))
      if (file.exists(candidate)) tg_path <- candidate
      if (is.null(tg_path) || !file.exists(tg_path)) {
        tgs_storage <- list.files(lasp_textgrids, full.names = TRUE)
        for (tp in tgs_storage) {
          if (grepl(fn, basename(tp), fixed = TRUE) || grepl(tools::file_path_sans_ext(basename(tp)), fn, fixed = TRUE)) {
            tg_path <- tp; break
          }
        }
      }
    }
    tg_path
  }
  
  # Helper: generar audio base64 para un rango temporal
  generar_audio_b64 <- function(wav_path, t_inicio, t_fin) {
    if (is.null(wav_path) || !tuneR_disponible || !base64enc_disponible) return(NULL)
    tryCatch({
      # Usar from/to de readWave para leer solo el segmento necesario
      # (evita cargar el archivo entero en memoria)
      wav_header <- tuneR::readWave(wav_path, header = TRUE)
      sr <- wav_header$sample.rate
      from_s <- max(1, round(t_inicio * sr))
      to_s   <- min(wav_header$samples, round(t_fin * sr))
      seg <- tuneR::readWave(wav_path, from = from_s, to = to_s)
      tmp <- tempfile(fileext = ".wav")
      tuneR::writeWave(seg, tmp)
      raw_b <- readBin(tmp, "raw", file.info(tmp)$size)
      b64 <- base64enc::base64encode(raw_b)
      file.remove(tmp)
      b64
    }, error = function(e) {
      message("[generar_audio_b64] Error: ", e$message)
      NULL
    })
  }
  
  # Helper: guardar segmento wav a disco
  guardar_segmento_wav <- function(wav_path, t_inicio, t_fin, output_path) {
    if (is.null(wav_path) || !tuneR_disponible) return(FALSE)
    tryCatch({
      wav <- tuneR::readWave(wav_path)
      sr <- wav@samp.rate
      from_s <- max(1, round(t_inicio * sr))
      to_s <- min(length(wav@left), round(t_fin * sr))
      if (wav@stereo) {
        seg <- tuneR::Wave(left = wav@left[from_s:to_s], right = wav@right[from_s:to_s], samp.rate = sr, bit = wav@bit)
      } else {
        seg <- tuneR::Wave(left = wav@left[from_s:to_s], samp.rate = sr, bit = wav@bit)
      }
      tuneR::writeWave(seg, output_path)
      TRUE
    }, error = function(e) FALSE)
  }
  
  # Inicializar anotaciones cuando se calculan datos
  observeEvent(datos$calculado, {
    req(datos$calculado, datos$ips_resumen, nrow(datos$ips_resumen) > 0)
    if (is.null(etiq$anotaciones) || nrow(etiq$anotaciones) != nrow(datos$ips_resumen)) {
      n <- nrow(datos$ips_resumen)
      id_ge_col <- if ("id_ge" %in% colnames(datos$ips_resumen) && length(datos$ips_resumen$id_ge) == n) {
        datos$ips_resumen$id_ge
      } else {
        paste0("GE_", seq_len(n))
      }
      etiq$anotaciones <- data.frame(
        fila_ip = seq_len(n),
        id_ge = id_ge_col,
        acto_id = seq_len(n),
        acto_tipo = rep("único", n),
        emocion_manual = rep("neutro", n),
        stringsAsFactors = FALSE
      )
      etiq$pos_actual <- 1
      etiq$acto_counter <- n
    }
  })
  
  # Cargar anotaciones previas
  observeEvent(input$etiq_cargar_rds, {
    req(input$etiq_cargar_rds)
    tryCatch({
      obj <- readRDS(input$etiq_cargar_rds$datapath)
      if ("anotaciones" %in% names(obj)) {
        etiq$anotaciones <- obj$anotaciones
        etiq$acto_counter <- obj$acto_counter
        etiq$pos_actual <- min(obj$pos_actual, nrow(etiq$anotaciones))
        showNotification("Anotaciones cargadas correctamente", type = "message")
      } else {
        showNotification("Archivo no válido", type = "error")
      }
    }, error = function(e) showNotification(paste("Error:", e$message), type = "error"))
  })
  
  # Selector archivo — updateSelectInput preserva el valor seleccionado al contrario de renderUI
  # Solo reacciona cuando cambia la lista de archivos (no cuando se escribe emocion_manual)
  observeEvent(
    if (!is.null(datos$ips_resumen)) paste(sort(unique(datos$ips_resumen$filename)), collapse = "|") else NULL,
    {
      req(datos$calculado, datos$ips_resumen)
      fns <- sort(unique(datos$ips_resumen$filename))
      choices_arch <- c("Todos" = "__todos__", setNames(fns, fns))
      sel <- isolate(input$etiq_archivo)
      if (is.null(sel) || !sel %in% c("__todos__", fns)) sel <- "__todos__"
      updateSelectInput(session, "etiq_archivo", choices = choices_arch, selected = sel)
    },
    ignoreNULL = TRUE, ignoreInit = FALSE
  )

  # Selector hablante — actualiza cuando cambia el archivo seleccionado o la lista de archivos
  observeEvent(
    list(
      if (!is.null(datos$ips_resumen)) paste(sort(unique(datos$ips_resumen$filename)), collapse = "|") else NULL,
      input$etiq_archivo
    ),
    {
      req(datos$calculado, datos$ips_resumen)
      ips_h <- datos$ips_resumen
      arch  <- isolate(input$etiq_archivo)
      if (!is.null(arch) && arch != "__todos__") ips_h <- ips_h[ips_h$filename == arch, ]
      habs <- sort(unique(ips_h$hablante))
      choices_hab <- c("Todos" = "__todos__", setNames(habs, habs))
      sel <- isolate(input$etiq_hablante)
      if (is.null(sel) || !sel %in% c("__todos__", habs)) sel <- "__todos__"
      updateSelectInput(session, "etiq_hablante", choices = choices_hab, selected = sel)
    },
    ignoreNULL = TRUE, ignoreInit = FALSE
  )
  
  # IPs filtrados para etiquetado
  ips_etiq <- reactive({
  req(datos$calculado, datos$ips_resumen)
  ips <- datos$ips_resumen
  
  # Excluir tier "anonimizar" (entrevistas)
  if ("hablante" %in% colnames(ips)) {
    ips <- ips[tolower(trimws(ips$hablante)) != "anonimizar", ]
  }
  
  if (!is.null(input$etiq_archivo) && input$etiq_archivo != "__todos__") {
    ips <- ips[ips$filename == input$etiq_archivo, ]
  }
  if (!is.null(input$etiq_hablante) && input$etiq_hablante != "__todos__") {
    ips <- ips[ips$hablante == input$etiq_hablante, ]
  }
  if (nrow(ips) == 0) return(ips)
  
  # Ordenar por filename e inicio para que la navegación sea secuencial
  if ("inicio" %in% colnames(ips)) {
    ips <- ips[order(ips$filename, ips$inicio), ]
  }
  
  ips$fila_original <- match(ips$id_ge, datos$ips_resumen$id_ge)
  if (all(is.na(ips$fila_original))) {
    ips$fila_original <- which(datos$ips_resumen$filename %in% ips$filename &
                                 datos$ips_resumen$hablante %in% ips$hablante)[seq_len(nrow(ips))]
  }
  ips
})
  
  # Navegación
  observeEvent(input$etiq_archivo, { etiq$pos_actual <- 1 }, ignoreInit = TRUE)
  observeEvent(input$etiq_hablante, { etiq$pos_actual <- 1 }, ignoreInit = TRUE)
  
  observeEvent(input$etiq_next, {
    ips <- ips_etiq()
    if (etiq$pos_actual < nrow(ips)) etiq$pos_actual <- etiq$pos_actual + 1
  })
  
  observeEvent(input$etiq_prev, {
    if (etiq$pos_actual > 1) etiq$pos_actual <- etiq$pos_actual - 1
  })
  
  output$etiq_posicion_txt <- renderText({
    ips <- ips_etiq()
    paste0(etiq$pos_actual, " / ", nrow(ips))
  })
  
  output$etiq_resumen_progreso <- renderText({
    req(etiq$anotaciones)
    n_etiq <- sum(!is.na(etiq$anotaciones$acto_id))
    n_total <- nrow(etiq$anotaciones)
    n_actos <- length(unique(na.omit(etiq$anotaciones$acto_id)))
    paste0("Etiquetados: ", n_etiq, "/", n_total, " GEs | ", n_actos, " actos creados")
  })
  
  # Tabla de contexto: fila actual ± 5, filtrado por mismo archivo
  # Texto grande del GE actual para el panel central
  output$etiq_texto_ge_ui <- renderUI({
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
    r <- ips[etiq$pos_actual, ]
    palabras <- if ("palabras_grupo" %in% colnames(r)) r$palabras_grupo else "(sin texto)"
    hablante  <- if (!is.null(r$hablante)) r$hablante else ""
    amh       <- if ("amh_patron" %in% colnames(r) && !is.na(r$amh_patron) && nchar(r$amh_patron) > 0)
                   paste0("  • ", r$amh_patron) else ""
    t_ini <- if ("inicio" %in% colnames(r) && !is.na(r$inicio))
               paste0(floor(r$inicio/60), ":", sprintf("%05.2f", r$inicio %% 60)) else ""
    tags$div(
      tags$div(style = "font-size: 11px; color: #888; margin-bottom: 4px;",
        paste0(hablante, "  |  ", t_ini, amh)),
      tags$div(style = "font-size: 22px; font-weight: 700; line-height: 1.35;", palabras)
    )
  })

  output$etiq_tabla_contexto <- renderUI({
  ips <- ips_etiq()
  req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
  pos <- etiq$pos_actual
  current_fn <- ips$filename[pos]
  
  # Índices del mismo archivo, ordenados por inicio
  same_file_idx <- which(ips$filename == current_fn)
  if ("inicio" %in% colnames(ips)) {
    same_file_idx <- same_file_idx[order(ips$inicio[same_file_idx])]
  }
  
  # Posición del GE actual dentro del orden temporal
  pos_in_file <- which(same_file_idx == pos)
  if (length(pos_in_file) == 0) {
    same_file_idx <- pos
    pos_in_file   <- 1
  }
  
  # Ventana ±5 en orden temporal
  rango_local <- max(1, pos_in_file - 5):min(length(same_file_idx), pos_in_file + 5)
  rango    <- same_file_idx[rango_local]
  sub_ips  <- ips[rango, ]
  
  # Construir tabla HTML
  filas_html <- lapply(seq_len(nrow(sub_ips)), function(i) {
    r        <- sub_ips[i, ]
    fila_orig <- r$fila_original
    es_actual <- (rango[i] == pos)
    
    anot <- etiq$anotaciones[fila_orig, ]
    acto_badge <- ""
    if (!is.na(anot$acto_id)) {
      acto_badge <- paste0('<span class="acto-badge">Acto ', anot$acto_id,
                           ' (', anot$acto_tipo, ')</span>')
    }
    
    emo_icon <- switch(anot$emocion_manual,
      "alegría"  = "\U0001F603", "tristeza" = "\U0001F622", "ira"      = "\U0001F621",
      "miedo"    = "\U0001F628", "asco"     = "\U0001F922", "sorpresa" = "\U0001F632",
      "\U0001F610")
    
    clase    <- if (es_actual) "fila-actual" else if (!is.na(anot$acto_id)) "fila-acto" else ""
    palabras <- if ("palabras_grupo" %in% colnames(r)) r$palabras_grupo else ""
    amh      <- if ("amh_patron"     %in% colnames(r)) r$amh_patron     else ""
    
    # Timestamp para orientación temporal
    t_ini <- if ("inicio" %in% colnames(r) && !is.na(r$inicio))
      paste0(floor(r$inicio / 60), ":", sprintf("%05.2f", r$inicio %% 60))
    else ""
    
    tags$tr(class = clase,
      tags$td(style = "padding:4px 8px; white-space:nowrap; font-size:11px; color:#999;", t_ini),
      tags$td(style = "padding:4px 8px; white-space:nowrap;",
              paste0("GF", r$grupo_fonico, "/GE", r$grupo_entonativo)),
      tags$td(style = "padding:4px 8px;", r$hablante),
      tags$td(style = "padding:4px 8px; max-width:300px;", palabras),
      tags$td(style = "padding:4px 8px; text-align:center;", amh),
      tags$td(style = "padding:4px 8px; text-align:center; font-size:20px;", emo_icon),
      tags$td(style = "padding:4px 8px;", HTML(acto_badge))
    )
  })
  
  tags$div(
    tags$small(class = "text-muted", paste0("Archivo: ", current_fn)),
    tags$table(class = "table table-sm table-bordered", style = "font-size:13px;",
      tags$thead(tags$tr(
        tags$th("Tiempo"), tags$th("GF/GE"), tags$th("Hablante"),
        tags$th("Palabras"), tags$th("AMH"), tags$th("Emo"), tags$th("Acto")
      )),
      tags$tbody(filas_html)
    )
  )
})
  

  # Curva melódica del GE actual en la pestaña de etiquetado
  output$etiq_curva_melodica <- renderPlotly({
    req(datos$phones, etiq$anotaciones)
    ips <- ips_etiq()
    req(is.data.frame(ips), nrow(ips) > 0)
    pos_actual <- etiq$pos_actual
    if (is.null(pos_actual) || pos_actual < 1 || pos_actual > nrow(ips)) return(plotly::plot_ly())
    r <- as.list(ips[pos_actual, ])

    fn_c  <- as.character(if (!is.null(r$filename)) r$filename else "")
    spk_c <- as.character(if (!is.null(r$hablante)) r$hablante else "")
    gf_c  <- suppressWarnings(as.integer(if (!is.null(r$grupo_fonico)) r$grupo_fonico else NA))
    ge_c  <- suppressWarnings(as.integer(if (!is.null(r$grupo_entonativo)) r$grupo_entonativo else NA))
    if (fn_c == "" || is.na(gf_c) || is.na(ge_c))
      return(plotly::plot_ly() %>% plotly::layout(title = "Sin datos de GE"))

    ph <- datos$phones
    cols_ok <- all(c("filename","hablante","grupo_fonico","grupo_entonativo") %in% colnames(ph))
    if (!cols_ok) return(plotly::plot_ly() %>% plotly::layout(title = "Sin columnas requeridas en phones"))

    ph_ge <- ph[ph$filename == fn_c & ph$hablante == spk_c &
                as.integer(ph$grupo_fonico) == gf_c & as.integer(ph$grupo_entonativo) == ge_c, ]
    if (nrow(ph_ge) == 0 && !is.null(r$inicio) && !is.null(r$fin) && "centro" %in% colnames(ph)) {
      t0 <- as.numeric(r$inicio); t1 <- as.numeric(r$fin)
      ph_ge <- ph[ph$filename == fn_c & ph$hablante == spk_c &
                  ph$centro >= t0 - 0.01 & ph$centro <= t1 + 0.01, ]
    }
    if (nrow(ph_ge) < 1)
      return(plotly::plot_ly() %>% plotly::layout(
        annotations = list(list(text = "Este GE no tiene datos de phones.",
          x=0.5, y=0.5, xref="paper", yref="paper", showarrow=FALSE,
          font=list(size=13, color="grey")))
      ))
    ph_ge <- ph_ge[order(ph_ge$inicio), ]

    # Etiquetas del eje X
    lbl_x <- if ("vocal" %in% colnames(ph_ge)) as.character(ph_ge$vocal) else
              if ("etiqueta" %in% colnames(ph_ge)) as.character(ph_ge$etiqueta) else as.character(seq_len(nrow(ph_ge)))
    lbl_x[is.na(lbl_x) | lbl_x == ""] <- as.character(seq_len(nrow(ph_ge)))[is.na(lbl_x) | lbl_x == ""]
    ph_ge$pos   <- seq_len(nrow(ph_ge))
    ph_ge$lbl_x <- lbl_x

    metrica <- if (!is.null(input$etiq_curva_metrica)) input$etiq_curva_metrica else "f0"

    palabras_raw <- r$palabras_grupo
    titulo_ge <- if (!is.null(palabras_raw) && length(palabras_raw)==1 && !is.na(palabras_raw) && nchar(as.character(palabras_raw))>0)
                   as.character(palabras_raw) else paste0("GF", gf_c, "/GE", ge_c)

    empty_msg <- function(msg) plotly::plot_ly() %>% plotly::layout(
      annotations = list(list(text=msg, x=0.5, y=0.5, xref="paper", yref="paper",
                              showarrow=FALSE, font=list(size=13, color="grey"))))

    # Helper: relativizar a 100 en la primera vocal con valor válido
    rel100 <- function(v) {
      v <- as.numeric(v)
      base <- v[which(!is.na(v) & v != 0)[1]]
      if (length(base) == 0 || is.na(base) || base == 0) return(rep(NA_real_, length(v)))
      round(v / base * 100, 2)
    }
    usar_rel <- isTRUE(input$etiq_curva_rel100) && metrica != "todos_amh"

    # ---- F0 ----
    if (metrica == "f0") {
      f0_col <- if ("f0_media_hz" %in% colnames(ph_ge)) "f0_media_hz" else
                if ("f0_media_st" %in% colnames(ph_ge)) "f0_media_st" else NULL
      if (is.null(f0_col)) return(empty_msg("Sin columna F0 en phones."))
      ph_plot <- ph_ge[!is.na(ph_ge[[f0_col]]) & ph_ge[[f0_col]] > 0, ]
      if (nrow(ph_plot) < 2) return(empty_msg("Sin valores F0 v\u00e1lidos."))
      y_raw  <- as.numeric(ph_plot[[f0_col]])
      y_vals <- if (usar_rel) rel100(y_raw) else y_raw
      y_lab  <- if (usar_rel) "F0 (base=100)" else if (f0_col == "f0_media_hz") "F0 (Hz)" else "F0 (St)"
      color_line <- "#1565C0"

      tonicas_idx <- if ("tonica_gramatical" %in% colnames(ph_plot))
        which(!is.na(ph_plot$tonica_gramatical) & ph_plot$tonica_gramatical == "s\u00ed") else integer(0)
      picos_idx <- if ("es_pico_grupo" %in% colnames(ph_plot))
        which(!is.na(ph_plot$es_pico_grupo) & ph_plot$es_pico_grupo == TRUE) else integer(0)

      p <- plotly::plot_ly() %>%
        plotly::add_trace(x=ph_plot$pos, y=y_vals, type="scatter", mode="lines+markers",
          line=list(color=color_line, width=2.5), marker=list(color=color_line, size=7),
          text=ph_plot$lbl_x, hovertemplate="%{text}: %{y:.1f}<extra></extra>", name=y_lab)
      if (length(tonicas_idx)>0)
        p <- p %>% plotly::add_trace(x=ph_plot$pos[tonicas_idx], y=y_vals[tonicas_idx],
          type="scatter", mode="markers",
          marker=list(symbol="triangle-up", color="gold", size=12, line=list(color="black",width=1.5)),
          text=ph_plot$lbl_x[tonicas_idx], hovertemplate="%{text}<extra>T\u00f3nica</extra>", name="T\u00f3nica")
      if (length(picos_idx)>0)
        p <- p %>% plotly::add_trace(x=ph_plot$pos[picos_idx], y=y_vals[picos_idx],
          type="scatter", mode="markers",
          marker=list(symbol="circle-open", color="darkred", size=12, line=list(color="darkred",width=2)),
          text=ph_plot$lbl_x[picos_idx], hovertemplate="%{text}<extra>Pico</extra>", name="Pico")
      if (usar_rel)
        p <- p %>% plotly::add_segments(
          x=min(ph_plot$pos)-0.3, xend=max(ph_plot$pos)+0.3, y=100, yend=100,
          line=list(color="grey", width=1, dash="dot"), showlegend=FALSE, hoverinfo="skip")

    # ---- Intensidad ----
    } else if (metrica == "intensidad") {
      int_col <- if ("int_media" %in% colnames(ph_ge)) "int_media" else NULL
      if (is.null(int_col)) return(empty_msg("Sin columna de intensidad (int_media) en phones."))
      ph_plot <- ph_ge[!is.na(ph_ge[[int_col]]) & ph_ge[[int_col]] > 0, ]
      if (nrow(ph_plot) < 2) return(empty_msg("Sin valores de intensidad v\u00e1lidos."))
      y_raw  <- as.numeric(ph_plot[[int_col]])
      y_vals <- if (usar_rel) rel100(y_raw) else y_raw
      y_lab  <- if (usar_rel) "Intensidad (base=100)" else "Intensidad (dB)"
      color_line <- "#2E7D32"
      p <- plotly::plot_ly() %>%
        plotly::add_trace(x=ph_plot$pos, y=y_vals, type="scatter", mode="lines+markers",
          line=list(color=color_line, width=2.5), marker=list(color=color_line, size=7),
          text=ph_plot$lbl_x, hovertemplate="%{text}: %{y:.1f}<extra></extra>", name=y_lab)
      if (usar_rel)
        p <- p %>% plotly::add_segments(
          x=min(ph_plot$pos)-0.3, xend=max(ph_plot$pos)+0.3, y=100, yend=100,
          line=list(color="grey", width=1, dash="dot"), showlegend=FALSE, hoverinfo="skip")

    # ---- Transicion ----
    } else if (metrica == "transicion") {
      if ("tiempo_transicion_anterior" %in% colnames(ph_ge) &&
          any(!is.na(ph_ge$tiempo_transicion_anterior))) {
        trans_col <- "tiempo_transicion_anterior"
        y_lab_base <- "Transici\u00f3n anterior"
      } else if ("tiempo_transicion_posterior" %in% colnames(ph_ge) &&
                 any(!is.na(ph_ge$tiempo_transicion_posterior))) {
        trans_col <- "tiempo_transicion_posterior"
        y_lab_base <- "Transici\u00f3n posterior"
      } else if ("centro" %in% colnames(ph_ge) && nrow(ph_ge) >= 2) {
        ph_ge$tiempo_transicion_calculada <- c(NA, diff(as.numeric(ph_ge$centro)))
        trans_col <- "tiempo_transicion_calculada"
        y_lab_base <- "Intervalo entre centros"
      } else {
        return(empty_msg("Sin datos de transici\u00f3n entre vocales."))
      }
      ph_plot <- ph_ge[!is.na(ph_ge[[trans_col]]), ]
      if (nrow(ph_plot) < 2) return(empty_msg("Insuficientes datos de transici\u00f3n."))
      y_raw  <- as.numeric(ph_plot[[trans_col]]) * 1000
      y_vals <- if (usar_rel) rel100(y_raw) else y_raw
      y_lab  <- if (usar_rel) paste0(y_lab_base, " (base=100)") else paste0(y_lab_base, " (ms)")
      color_line <- "#6A1B9A"
      p <- plotly::plot_ly() %>%
        plotly::add_trace(x=ph_plot$pos, y=y_vals, type="bar",
          marker=list(color=color_line, opacity=0.75),
          text=ph_plot$lbl_x, hovertemplate="%{text}: %{y:.1f}<extra></extra>", name=y_lab)
      if (usar_rel)
        p <- p %>% plotly::add_segments(
          x=min(ph_plot$pos)-0.3, xend=max(ph_plot$pos)+0.3, y=100, yend=100,
          line=list(color="grey", width=1, dash="dot"), showlegend=FALSE, hoverinfo="skip")

    # ---- Todos (AMH): F0 + Intensidad + Transicion relativizados a 100 en vocal 1 ----
    } else {
      f0_col <- if ("f0_media_hz" %in% colnames(ph_ge)) "f0_media_hz" else
                if ("f0_media_st" %in% colnames(ph_ge)) "f0_media_st" else NULL
      f0_rel  <- if (!is.null(f0_col)) rel100(ph_ge[[f0_col]]) else rep(NA_real_, nrow(ph_ge))
      f0_lab  <- if (!is.null(f0_col) && f0_col == "f0_media_hz") "F0 Hz" else "F0 St"
      int_rel <- if ("int_media" %in% colnames(ph_ge)) rel100(ph_ge$int_media) else rep(NA_real_, nrow(ph_ge))
      # Usar tiempo_transicion_anterior: tiene valor en la última vocal (transición desde la anterior)
      # La primera vocal queda sin barra (sin vocal previa), que es lo correcto
      trans_raw <- if ("tiempo_transicion_anterior" %in% colnames(ph_ge) &&
                       any(!is.na(ph_ge$tiempo_transicion_anterior)))
                     ph_ge$tiempo_transicion_anterior * 1000
                   else if ("tiempo_transicion_posterior" %in% colnames(ph_ge) &&
                            any(!is.na(ph_ge$tiempo_transicion_posterior))) {
                     v <- ph_ge$tiempo_transicion_posterior * 1000
                     v[length(v)] <- NA  # última vocal no tiene siguiente
                     v
                   } else if ("centro" %in% colnames(ph_ge) && nrow(ph_ge) >= 2)
                     c(NA, diff(as.numeric(ph_ge$centro))) * 1000  # anterior
                   else rep(NA_real_, nrow(ph_ge))
      trans_raw[!is.na(trans_raw) & trans_raw <= 0] <- NA
      trans_rel <- rel100(trans_raw)
      trans_rel[!is.na(trans_rel) & trans_rel > 400] <- NA
      if (all(is.na(f0_rel)) && all(is.na(int_rel)) && all(is.na(trans_rel)))
        return(empty_msg("Sin datos disponibles para vista AMH."))
      xs   <- ph_ge$pos
      lbls <- ph_ge$lbl_x
      tonicas_idx <- if ("tonica_gramatical" %in% colnames(ph_ge))
        which(!is.na(ph_ge$tonica_gramatical) & ph_ge$tonica_gramatical == "s\u00ed") else integer(0)
      picos_idx <- if ("es_pico_grupo" %in% colnames(ph_ge))
        which(!is.na(ph_ge$es_pico_grupo) & ph_ge$es_pico_grupo == TRUE) else integer(0)
      p <- plotly::plot_ly()
      if (!all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(
          x=xs, y=f0_rel, type="scatter", mode="lines+markers", name=f0_lab,
          line=list(color="#1565C0", width=2.5), marker=list(color="#1565C0", size=7),
          text=lbls, hovertemplate=paste0("%{text} \u2014 ", f0_lab, ": %{y:.1f}<extra></extra>"))
      if (length(tonicas_idx) > 0 && !all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(
          x=xs[tonicas_idx], y=f0_rel[tonicas_idx], type="scatter", mode="markers", name="T\u00f3nica",
          marker=list(symbol="triangle-up", color="gold", size=13, line=list(color="#333",width=1.5)),
          text=lbls[tonicas_idx], hovertemplate="%{text}<extra>T\u00f3nica</extra>")
      if (length(picos_idx) > 0 && !all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(
          x=xs[picos_idx], y=f0_rel[picos_idx], type="scatter", mode="markers", name="Pico",
          marker=list(symbol="circle-open", color="darkred", size=13, line=list(color="darkred",width=2)),
          text=lbls[picos_idx], hovertemplate="%{text}<extra>Pico</extra>")
      if (!all(is.na(int_rel)))
        p <- p %>% plotly::add_trace(
          x=xs, y=int_rel, type="scatter", mode="lines+markers", name="Intensidad",
          line=list(color="#2E7D32", width=2, dash="dash"), marker=list(color="#2E7D32", size=6, symbol="square"),
          text=lbls, hovertemplate="%{text} \u2014 Int: %{y:.1f}<extra></extra>")
      if (!all(is.na(trans_rel)))
        p <- p %>% plotly::add_trace(
          x=xs, y=trans_rel, type="bar", name="Transici\u00f3n", yaxis="y2",
          marker=list(color="#6A1B9A", opacity=0.35),
          text=lbls, hovertemplate="%{text} \u2014 Trans: %{y:.1f}<extra></extra>")
      p <- p %>% plotly::add_segments(
        x=min(xs)-0.3, xend=max(xs)+0.3, y=100, yend=100,
        line=list(color="grey", width=1, dash="dot"), showlegend=FALSE, hoverinfo="skip")
      # Línea de referencia en 100 también para el eje de transición (y2)
      p <- p %>% plotly::add_segments(
        x=min(xs)-0.3, xend=max(xs)+0.3, y=100, yend=100, yaxis="y2",
        line=list(color="#6A1B9A", width=1, dash="dot"), showlegend=FALSE, hoverinfo="skip")
      y_lab <- "Valor relativo (base=100)"
      p <- p %>% plotly::layout(
        title  = list(text=titulo_ge, font=list(size=12)),
        xaxis  = list(tickmode="array", tickvals=xs, ticktext=lbls, title="Vocal"),
        yaxis  = list(title=y_lab, side="left"),
        yaxis2 = list(title="Transici\u00f3n relativa", overlaying="y", side="right",
                      showgrid=FALSE, zeroline=FALSE),
        barmode = "overlay",
        margin = list(t=35, b=50, l=60, r=60),
        legend = list(orientation="h", y=-0.38),
        hovermode = "x unified"
      ) %>% plotly::config(
        displayModeBar=TRUE,
        modeBarButtonsToRemove=list("zoom2d","pan2d","select2d","lasso2d","zoomIn2d","zoomOut2d","autoScale2d"),
        toImageButtonOptions=list(format="png", filename=paste0("curva_amh_", titulo_ge), width=960, height=440, scale=2)
      )
      return(p)
    }

    p %>% plotly::layout(
      title = list(text=titulo_ge, font=list(size=12)),
      xaxis = list(tickmode="array", tickvals=ph_ge$pos, ticktext=ph_ge$lbl_x, title="Vocal"),
      yaxis = list(title=y_lab),
      margin = list(t=35, b=40, l=55, r=15),
      legend = list(orientation="h", y=-0.3),
      hovermode = "x unified"
    ) %>% plotly::config(
      displayModeBar=TRUE,
      modeBarButtonsToRemove=list("zoom2d","pan2d","select2d","lasso2d","zoomIn2d","zoomOut2d","autoScale2d"),
      toImageButtonOptions=list(format="png", filename=paste0("curva_", metrica, "_", titulo_ge), width=900, height=400, scale=2)
    )
  })

  # Descarga de la curva melódica como PNG (via plotly orca/kaleido o HTML fallback)
  # Helper compartido para regenerar el plot de curva para descarga
  etiq_curva_build_plot <- function(metrica, usar_rel) {
    ips <- ips_etiq()
    pos <- etiq$pos_actual
    if (!is.data.frame(ips) || pos < 1 || pos > nrow(ips)) return(NULL)
    r <- as.list(ips[pos, ])
    fn_c <- as.character(if (!is.null(r$filename)) r$filename else "")
    spk_c <- as.character(if (!is.null(r$hablante)) r$hablante else "")
    gf_c <- suppressWarnings(as.integer(if (!is.null(r$grupo_fonico)) r$grupo_fonico else NA))
    ge_c <- suppressWarnings(as.integer(if (!is.null(r$grupo_entonativo)) r$grupo_entonativo else NA))
    ph <- datos$phones
    if (is.null(ph)) return(NULL)
    ph_ge <- ph[ph$filename == fn_c & ph$hablante == spk_c &
                as.integer(ph$grupo_fonico) == gf_c & as.integer(ph$grupo_entonativo) == ge_c, ]
    if (nrow(ph_ge) == 0 && !is.null(r$inicio) && "centro" %in% colnames(ph)) {
      ph_ge <- ph[ph$filename == fn_c & ph$hablante == spk_c &
                  ph$centro >= as.numeric(r$inicio) - 0.01 & ph$centro <= as.numeric(r$fin) + 0.01, ]
    }
    if (nrow(ph_ge) < 1) return(NULL)
    ph_ge <- ph_ge[order(ph_ge$inicio), ]
    lbl_x <- if ("vocal" %in% colnames(ph_ge)) as.character(ph_ge$vocal) else
              if ("etiqueta" %in% colnames(ph_ge)) as.character(ph_ge$etiqueta) else as.character(seq_len(nrow(ph_ge)))
    lbl_x[is.na(lbl_x)|lbl_x==""] <- as.character(seq_len(nrow(ph_ge)))[is.na(lbl_x)|lbl_x==""]
    ph_ge$pos <- seq_len(nrow(ph_ge)); ph_ge$lbl_x <- lbl_x
    palabras_raw <- r$palabras_grupo
    titulo_ge <- if (!is.null(palabras_raw) && !is.na(palabras_raw) && nchar(as.character(palabras_raw))>0)
                   as.character(palabras_raw) else paste0("GF",gf_c,"/GE",ge_c)
    rel100 <- function(v) {
      v <- as.numeric(v); base <- v[which(!is.na(v) & v!=0)[1]]
      if (length(base)==0||is.na(base)||base==0) return(rep(NA_real_,length(v)))
      round(v/base*100,2)
    }
    if (metrica == "todos_amh") {
      xs <- ph_ge$pos; lbls <- ph_ge$lbl_x
      f0_col <- if ("f0_media_hz" %in% colnames(ph_ge)) "f0_media_hz" else
                if ("f0_media_st" %in% colnames(ph_ge)) "f0_media_st" else NULL
      f0_rel <- if (!is.null(f0_col)) rel100(ph_ge[[f0_col]]) else rep(NA_real_,nrow(ph_ge))
      f0_lab <- if (!is.null(f0_col) && f0_col=="f0_media_hz") "F0 Hz" else "F0 St"
      int_rel <- if ("int_media" %in% colnames(ph_ge)) rel100(ph_ge$int_media) else rep(NA_real_,nrow(ph_ge))
      trans_raw <- if ("tiempo_transicion_anterior" %in% colnames(ph_ge) && any(!is.na(ph_ge$tiempo_transicion_anterior)))
                     ph_ge$tiempo_transicion_anterior*1000
                   else if ("tiempo_transicion_posterior" %in% colnames(ph_ge) && any(!is.na(ph_ge$tiempo_transicion_posterior))) {
                     v <- ph_ge$tiempo_transicion_posterior * 1000
                     v[length(v)] <- NA
                     v
                   } else if ("centro" %in% colnames(ph_ge) && nrow(ph_ge)>=2)
                     c(NA, diff(as.numeric(ph_ge$centro)))*1000
                   else rep(NA_real_,nrow(ph_ge))
      trans_raw[!is.na(trans_raw) & trans_raw <= 0] <- NA
      trans_rel <- rel100(trans_raw)
      trans_rel[!is.na(trans_rel) & trans_rel > 400] <- NA
      tonicas_idx <- if ("tonica_gramatical" %in% colnames(ph_ge))
        which(!is.na(ph_ge$tonica_gramatical) & ph_ge$tonica_gramatical == "s\u00ed") else integer(0)
      p <- plotly::plot_ly()
      if (!all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(x=xs, y=f0_rel, type="scatter", mode="lines+markers", name=f0_lab,
          line=list(color="#1565C0",width=2.5), marker=list(color="#1565C0",size=7), text=lbls,
          hovertemplate=paste0("%{text} \u2014 ",f0_lab,": %{y:.1f}<extra></extra>"))
      if (length(tonicas_idx)>0 && !all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(x=xs[tonicas_idx], y=f0_rel[tonicas_idx],
          type="scatter", mode="markers", name="T\u00f3nica",
          marker=list(symbol="triangle-up",color="gold",size=13,line=list(color="#333",width=1.5)),
          text=lbls[tonicas_idx], hovertemplate="%{text}<extra>T\u00f3nica</extra>")
      if (!all(is.na(int_rel)))
        p <- p %>% plotly::add_trace(x=xs, y=int_rel, type="scatter", mode="lines+markers", name="Intensidad",
          line=list(color="#2E7D32",width=2,dash="dash"), marker=list(color="#2E7D32",size=6,symbol="square"),
          text=lbls, hovertemplate="%{text} \u2014 Int: %{y:.1f}<extra></extra>")
      if (!all(is.na(trans_rel)))
        p <- p %>% plotly::add_trace(x=xs, y=trans_rel, type="bar", name="Transici\u00f3n", yaxis="y2",
          marker=list(color="#6A1B9A",opacity=0.35), text=lbls,
          hovertemplate="%{text} \u2014 Trans: %{y:.1f}<extra></extra>")
      p <- p %>%
        plotly::add_segments(x=min(xs)-0.3, xend=max(xs)+0.3, y=100, yend=100,
          line=list(color="grey",width=1,dash="dot"), showlegend=FALSE, hoverinfo="skip") %>%
        plotly::add_segments(x=min(xs)-0.3, xend=max(xs)+0.3, y=100, yend=100, yaxis="y2",
          line=list(color="#6A1B9A",width=1,dash="dot"), showlegend=FALSE, hoverinfo="skip")
      p %>% plotly::layout(
        title=list(text=titulo_ge,font=list(size=14)),
        xaxis=list(tickmode="array",tickvals=xs,ticktext=lbls,title="Vocal"),
        yaxis=list(title="Valor relativo (base=100)",side="left"),
        yaxis2=list(title="Transici\u00f3n relativa",overlaying="y",side="right",showgrid=FALSE,zeroline=FALSE),
        barmode="overlay", margin=list(t=50,b=60,l=70,r=70),
        legend=list(orientation="h",y=-0.4), hovermode="x unified")
    } else {
      f0_col <- if ("f0_media_hz" %in% colnames(ph_ge)) "f0_media_hz" else
                if ("f0_media_st" %in% colnames(ph_ge)) "f0_media_st" else NULL
      y_raw <- if (!is.null(f0_col)) as.numeric(ph_ge[[f0_col]]) else rep(0,nrow(ph_ge))
      y_vals <- if (usar_rel) rel100(y_raw) else y_raw
      y_lab <- if (usar_rel) "F0 (base=100)" else if (!is.null(f0_col)&&f0_col=="f0_media_hz") "F0 (Hz)" else "F0 (St)"
      p <- plotly::plot_ly() %>%
        plotly::add_trace(x=ph_ge$pos, y=y_vals, type="scatter", mode="lines+markers",
          line=list(color="#1565C0",width=2.5), marker=list(color="#1565C0",size=7),
          text=ph_ge$lbl_x, name=y_lab)
      if (usar_rel)
        p <- p %>% plotly::add_segments(x=min(ph_ge$pos)-0.3, xend=max(ph_ge$pos)+0.3, y=100, yend=100,
          line=list(color="grey",width=1,dash="dot"), showlegend=FALSE, hoverinfo="skip")
      p %>% plotly::layout(title=list(text=titulo_ge,font=list(size=14)),
        xaxis=list(title="Vocal"), yaxis=list(title=y_lab), margin=list(t=50,b=50,l=60,r=20))
    }
  }

  # Nombre base para ficheros de descarga
  etiq_curva_nombre_base <- function() {
    metrica <- if (!is.null(input$etiq_curva_metrica)) input$etiq_curva_metrica else "curva"
    ips <- ips_etiq(); pos <- etiq$pos_actual
    suf <- if (!is.null(ips) && !is.null(pos) && pos>=1 && pos<=nrow(ips)) {
      r <- as.list(ips[pos,]); pw <- r$palabras_grupo
      if (!is.null(pw) && !is.na(pw) && nchar(as.character(pw))>0)
        gsub("[^a-zA-Z0-9_]","_",substr(as.character(pw),1,30))
      else paste0("GF",r$grupo_fonico,"_GE",r$grupo_entonativo)
    } else "ge"
    paste0("curva_", metrica, "_", suf)
  }

  # Descarga HTML
  output$etiq_curva_descargar_html <- downloadHandler(
    filename = function() paste0(etiq_curva_nombre_base(), ".html"),
    content  = function(file) {
      usar_rel <- isTRUE(input$etiq_curva_rel100) && input$etiq_curva_metrica != "todos_amh"
      p <- etiq_curva_build_plot(input$etiq_curva_metrica, usar_rel)
      if (is.null(p)) { writeLines("Sin datos", file); return() }
      htmlwidgets::saveWidget(p, file, selfcontained = TRUE, libdir = NULL)
    }
  )

  # Descarga PNG (requiere kaleido o webshot2; si falla, avisa)
  output$etiq_curva_descargar_png <- downloadHandler(
    filename = function() paste0(etiq_curva_nombre_base(), ".png"),
    content  = function(file) {
      metrica  <- input$etiq_curva_metrica
      usar_rel <- isTRUE(input$etiq_curva_rel100) && metrica != "todos_amh"
      es_amh   <- metrica == "todos_amh"
      # 300 dpi para AMH (todos los valores); 150 dpi para métricas individuales
      # plotly::save_image usa 96 ppp base: scale = dpi/96
      # Para 300 dpi: scale = 300/96 ≈ 3.125 → redondeamos a 3.125
      # Dimensiones físicas: 10in × 4.5in @ 300dpi = 3000×1350px; @ 150dpi = 1440×648px
      if (es_amh) {
        w_px <- 3000L; h_px <- 1350L; escala <- 3.125; dpi_gg <- 300
      } else {
        w_px <- 1440L; h_px  <- 648L; escala <- 1.5;   dpi_gg <- 150
      }
      p <- etiq_curva_build_plot(metrica, usar_rel)
      if (is.null(p)) { png(file, w_px, h_px, res = dpi_gg); dev.off(); return() }
      tryCatch({
        # Intentar con kaleido (plotly::save_image)
        plotly::save_image(p, file, width = w_px, height = h_px, scale = escala)
      }, error = function(e1) {
        tryCatch({
          # Fallback: webshot2
          tmp_html <- tempfile(fileext = ".html")
          htmlwidgets::saveWidget(p, tmp_html, selfcontained = TRUE)
          webshot2::webshot(tmp_html, file,
            vwidth = if (es_amh) 1200L else 960L,
            vheight = if (es_amh) 540L  else 440L,
            zoom    = if (es_amh) 2.5   else 1.5,
            delay   = 0.5)
        }, error = function(e2) {
          # Último recurso: ggplot estático
          df_plot <- tryCatch({
            ips <- ips_etiq(); pos <- etiq$pos_actual
            r <- as.list(ips[pos,])
            ph <- datos$phones
            ph_ge <- ph[ph$filename==as.character(r$filename) & ph$hablante==as.character(r$hablante) &
                        as.integer(ph$grupo_fonico)==as.integer(r$grupo_fonico) &
                        as.integer(ph$grupo_entonativo)==as.integer(r$grupo_entonativo), ]
            ph_ge[order(ph_ge$inicio), ]
          }, error = function(e) NULL)
          if (!is.null(df_plot) && nrow(df_plot) > 0 && "f0_media_hz" %in% colnames(df_plot)) {
            df_plot$pos <- seq_len(nrow(df_plot))
            gg <- ggplot2::ggplot(df_plot, ggplot2::aes(x = pos, y = f0_media_hz)) +
              ggplot2::geom_line(color = "#1565C0", linewidth = 1) +
              ggplot2::geom_point(color = "#1565C0", size = 3) +
              ggplot2::theme_minimal() + ggplot2::labs(y = "F0 (Hz)", x = "Vocal")
            ggplot2::ggsave(file, gg, width = 10, height = 4.5, dpi = dpi_gg)
          } else {
            png(file, w_px, h_px, res = dpi_gg)
            plot.new(); text(0.5, 0.5, "Sin datos F0", cex = 2); dev.off()
          }
        })
      })
    }
  )

  # Checkboxes para acto de habla (5 filas anteriores, mismo archivo)
    # Checkboxes para acto de habla (5 filas anteriores, mismo archivo)
  output$etiq_checkboxes_acto <- renderUI({
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
    pos <- etiq$pos_actual
    
    # Restrict to same file
    current_fn <- ips$filename[pos]
    same_file_idx <- which(ips$filename == current_fn)
    pos_in_file <- which(same_file_idx == pos)
    
    if (length(pos_in_file) == 0 || pos_in_file <= 1) return(helpText("No hay GEs anteriores en este archivo."))
    
    rango_prev_local <- max(1, pos_in_file - 5):(pos_in_file - 1)
    rango_prev <- same_file_idx[rango_prev_local]
    sub_prev <- ips[rango_prev, ]
    
    checks <- lapply(seq_len(nrow(sub_prev)), function(i) {
      r <- sub_prev[i, ]
      palabras <- if ("palabras_grupo" %in% colnames(r)) r$palabras_grupo else ""
      spk_lbl  <- if ("hablante" %in% colnames(r) && !is.na(r$hablante)) paste0("[", r$hablante, "] ") else ""
      label_txt <- paste0(spk_lbl, "GF", r$grupo_fonico, "/GE", r$grupo_entonativo, ": ",
                          substr(palabras, 1, 45))
      checkboxInput(paste0("etiq_acto_check_", rango_prev[i]), label_txt, value = FALSE)
    })
    
    tagList(
      checks,
      actionButton("etiq_confirmar_acto", " Confirmar acto", icon = icon("check"), class = "btn-primary btn-sm")
    )
  })
  
  # Confirmar acto de habla
  observeEvent(input$etiq_confirmar_acto, {
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$anotaciones)
    pos <- etiq$pos_actual
    fila_actual_orig <- ips$fila_original[pos]
    
    # Recoger qué anteriores están marcados
    rango_prev <- max(1, pos - 5):(pos - 1)
    filas_marcadas <- c()
    for (rp in rango_prev) {
      val <- input[[paste0("etiq_acto_check_", rp)]]
      if (!is.null(val) && val) {
        filas_marcadas <- c(filas_marcadas, ips$fila_original[rp])
      }
    }
    
    # Incrementar contador de actos
    etiq$acto_counter <- etiq$acto_counter + 1
    acto_id <- etiq$acto_counter
    
    # Asignar acto a filas anteriores marcadas
    if (length(filas_marcadas) > 0) {
      etiq$anotaciones$acto_id[filas_marcadas] <- acto_id
      etiq$anotaciones$acto_tipo[filas_marcadas] <- "anterior"
    }
    
    # Asignar acto a fila actual
    etiq$anotaciones$acto_id[fila_actual_orig] <- acto_id
    etiq$anotaciones$acto_tipo[fila_actual_orig] <- "único"
    
    showNotification(paste0("Acto #", acto_id, " creado con ", 
                            1 + length(filas_marcadas), " GE(s)"), type = "message")
    
    # Auto-guardar etiquetado
    tryCatch(guardar_etiquetado_persistente(), error = function(e) NULL)
  })
  
  # Info del acto actual
  output$etiq_acto_info <- renderText({
    req(etiq$anotaciones)
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
    fila_orig <- ips$fila_original[etiq$pos_actual]
    anot <- etiq$anotaciones[fila_orig, ]
    if (is.na(anot$acto_id)) {
      "Este GE aún no tiene acto asignado."
    } else {
      filas_acto <- which(etiq$anotaciones$acto_id == anot$acto_id)
      n_ges <- length(filas_acto)
      paste0("Acto #", anot$acto_id, " — ", n_ges, " GE(s) — Emoción: ", anot$emocion_manual)
    }
  })
  
  # Registrar emoción al pulsar emoji
  observeEvent(input$etiq_emocion, {
    req(etiq$anotaciones)
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
    fila_orig <- ips$fila_original[etiq$pos_actual]
    
    emocion <- input$etiq_emocion
    
    # Si tiene acto, asignar emoción a todo el acto
    acto_id <- etiq$anotaciones$acto_id[fila_orig]
    if (!is.na(acto_id)) {
      filas_acto <- which(etiq$anotaciones$acto_id == acto_id)
      etiq$anotaciones$emocion_manual[filas_acto] <- emocion
    } else {
      etiq$anotaciones$emocion_manual[fila_orig] <- emocion
    }
    
    session$sendCustomMessage("updateEmojiSelection", emocion)
    
    # Auto-guardar etiquetado
    tryCatch(guardar_etiquetado_persistente(), error = function(e) NULL)
  })
  
  # Al cambiar de posición, actualizar el emoji seleccionado
  observe({
    req(etiq$anotaciones)
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
    fila_orig <- ips$fila_original[etiq$pos_actual]
