  # Escuchar acto completo
  observeEvent(input$etiq_play_acto, {
    req(etiq$anotaciones, datos$ips_resumen)
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
    fila_orig <- ips$fila_original[etiq$pos_actual]
    
    # Determinar rango del acto
    acto_id <- etiq$anotaciones$acto_id[fila_orig]
    if (!is.na(acto_id)) {
      filas_acto <- which(etiq$anotaciones$acto_id == acto_id)
      ips_acto <- datos$ips_resumen[filas_acto, ]
    } else {
      ips_acto <- datos$ips_resumen[fila_orig, ]
    }
    
    t_inicio <- min(ips_acto$inicio, na.rm = TRUE) - 0.1
    t_fin <- max(ips_acto$fin, na.rm = TRUE) + 0.1
    t_inicio <- max(0, t_inicio)
    fn <- ips_acto$filename[1]
    
    wav_path <- buscar_wav(fn)
    if (is.null(wav_path)) {
      showNotification("No se encontró archivo de audio", type = "warning")
      return()
    }
    
    b64 <- generar_audio_b64(wav_path, t_inicio, t_fin)
    if (is.null(b64)) {
      showNotification("Error generando audio", type = "warning")
      return()
    }
    
    output$etiq_audio_player <- renderUI({
      tags$audio(
        src = paste0("data:audio/wav;base64,", b64),
        type = "audio/wav", controls = TRUE, autoplay = TRUE,
        style = "width: 100%; margin-top: 5px;"
      )
    })
  })
  
  # Ver gráfico modal (praatpicture)
  observeEvent(input$etiq_ver_grafico, {
    req(etiq$anotaciones, datos$ips_resumen, praatpicture_disponible)
    ips <- ips_etiq()
    req(nrow(ips) > 0, etiq$pos_actual <= nrow(ips))
    fila_orig <- ips$fila_original[etiq$pos_actual]
    
    acto_id <- etiq$anotaciones$acto_id[fila_orig]
    if (!is.na(acto_id)) {
      filas_acto <- which(etiq$anotaciones$acto_id == acto_id)
      ips_acto <- datos$ips_resumen[filas_acto, ]
    } else {
      ips_acto <- datos$ips_resumen[fila_orig, ]
    }
    
    t_inicio <- min(ips_acto$inicio, na.rm = TRUE) - 0.1
    t_fin <- max(ips_acto$fin, na.rm = TRUE) + 0.1
    t_inicio <- max(0, t_inicio)
    fn <- ips_acto$filename[1]
    
    wav_path <- buscar_wav(fn)
    tg_path <- buscar_tg(fn)
    
    if (is.null(wav_path) || is.null(tg_path)) {
      showNotification("Faltan archivos WAV/TextGrid", type = "warning")
      return()
    }
    
    showModal(modalDialog(
      title = paste0("Praatpicture — Acto ", ifelse(is.na(acto_id), "(sin acto)", paste0("#", acto_id))),
      size = "l", easyClose = TRUE,
      plotOutput("etiq_modal_praatpicture", height = "500px")
    ))
    
    # Hablante del acto actual (para filtrar tiers praatpicture)
    hablante_etiq <- if (!is.null(ips_acto$hablante) && length(ips_acto$hablante) > 0)
                       ips_acto$hablante[1] else NULL

    output$etiq_modal_praatpicture <- renderPlot({
      tmp_dir <- tempfile(pattern = "etiq_pp_")
      dir.create(tmp_dir, showWarnings = FALSE)
      tmp_wav <- file.path(tmp_dir, "audio.wav")
      tmp_tg  <- file.path(tmp_dir, "audio.TextGrid")
      file.copy(wav_path, tmp_wav, overwrite = TRUE)
      file.copy(tg_path,  tmp_tg,  overwrite = TRUE)
      on.exit(unlink(tmp_dir, recursive = TRUE), add = TRUE)

      # Seleccionar solo tiers phones/words del hablante del acto
      tiers_sel <- seleccionar_tiers_hablante(tmp_tg, hablante_etiq)

      tryCatch({
        call_args <- list(
          sound = tmp_wav, start = t_inicio, end = t_fin,
          frames = c("sound", "spectrogram", "pitch", "TextGrid"),
          proportion = c(25, 40, 15, 20),
          tg_file = tmp_tg,
          pitch_plotType = "draw", pitch_scale = "semitones",
          pitch_semitonesRe = 1, pitch_color = "blue",
          mainTitle = paste0("Acto \u2014 ", round(t_inicio, 2), "s a ", round(t_fin, 2), "s")
        )
        if (!is.null(tiers_sel) && length(tiers_sel) > 0) {
          call_args$tg_tiers     <- tiers_sel
          call_args$tg_focusTier <- tiers_sel[1]
        }
        do.call(praatpicture::praatpicture, call_args)
      }, error = function(e) {
        plot.new(); text(0.5, 0.5, paste("Error:", e$message), col = "red", cex = 1.2)
      })
    })
  })
  
  # Guardado automático cada 10 segundos
  observe({
    invalidateLater(10000, session)
    req(etiq$anotaciones)
    
    # Crear directorio de backup
    if (is.null(etiq$backup_dir)) {
      etiq$backup_dir <- file.path(getwd(), "backup_etiquetado")
      dir.create(etiq$backup_dir, recursive = TRUE, showWarnings = FALSE)
    }
    
    timestamp <- format(Sys.time(), "%Y%m%d_%H%M%S")
    backup_file <- file.path(etiq$backup_dir, 
                             paste0("analisis_", timestamp, ".rds"))
    
    obj <- list(
      anotaciones = etiq$anotaciones,
      acto_counter = etiq$acto_counter,
      pos_actual = etiq$pos_actual,
      timestamp = Sys.time()
    )
    
    tryCatch({
      saveRDS(obj, backup_file)
      etiq$ultimo_guardado <- format(Sys.time(), "%H:%M:%S")
      
      # Mantener solo últimos 50 backups
      backups <- sort(list.files(etiq$backup_dir, full.names = TRUE), decreasing = TRUE)
      if (length(backups) > 50) file.remove(backups[51:length(backups)])
    }, error = function(e) NULL)
  })
  
  output$etiq_ultimo_guardado <- renderText({
    if (is.null(etiq$ultimo_guardado)) return("")
    paste0("Último backup: ", etiq$ultimo_guardado)
  })
  
  # Descargar anotaciones
  output$etiq_descargar_rds <- downloadHandler(
