  # ========================================
  # AUTO-DETECCIÓN DE EMOCIONES DESDE CORPUS
  # ========================================
  
  observeEvent(input$btn_autoemo, {
  req(datos$calculado, datos$ips_resumen, etiq$anotaciones)

  tipo <- input$autoemo_tipo
  ips  <- datos$ips_resumen
  ann  <- etiq$anotaciones
  n_detectados <- 0
  n_total      <- nrow(ips)

  # ── Guarda de resincronización: etiq$anotaciones puede haberse desincronizado
  # de datos$ips_resumen si los GEs se recalcularon sin disparar datos$calculado.
  if (nrow(ann) != n_total) {
    n_ann <- nrow(ann)
    if (n_ann > n_total) {
      # Recortar filas sobrantes
      ann <- ann[seq_len(n_total), , drop = FALSE]
    } else {
      # Rellenar con filas NA y emocion_manual = "neutro"
      extra      <- n_total - n_ann
      ann_extra  <- ann[rep(NA_integer_, extra), , drop = FALSE]
      rownames(ann_extra) <- NULL
      if ("emocion_manual" %in% colnames(ann_extra))
        ann_extra$emocion_manual <- "neutro"
      ann <- rbind(ann, ann_extra)
      rownames(ann) <- NULL
    }
  }

  tryCatch({

    if (tipo == "emofilm") {
      emofilm_map <- c("ans"="miedo","dis"="asco","gio"="alegría","rab"="ira","tri"="tristeza")

      for (i in seq_len(n_total)) {
        fn <- tolower(ips$filename[i])
        emo_detected <- NA_character_
        for (code in names(emofilm_map)) {
          if (grepl(paste0("(^|[_\\-])", code), fn)) {
            emo_detected <- emofilm_map[[code]]; break
          }
        }
        if (!is.na(emo_detected)) {
          ann$emocion_manual[i] <- emo_detected
          n_detectados <- n_detectados + 1
        }
      }

      if (!is.null(metadatos$hablantes)) {
        for (fn_orig in unique(ips$filename)) {
          fn_low <- tolower(fn_orig)
          gender <- if (grepl("^f[_\\-]", fn_low)) "femenino" else
                    if (grepl("^m[_\\-]", fn_low)) "masculino" else NA_character_
          if (!is.na(gender)) {
            habs <- unique(ips$hablante[ips$filename == fn_orig])
            for (h in habs) {
              idx <- which(metadatos$hablantes$hablante == h)
              if (length(idx) > 0 && "sexo" %in% colnames(metadatos$hablantes))
                metadatos$hablantes$sexo[idx] <- gender
            }
          }
        }
      }

    } else if (tipo == "emospanish") {
      emospanish_map <- c(
        "alegria"="alegría","tristeza"="tristeza","ira"="ira","miedo"="miedo",
        "asco"="asco","sorpresa"="sorpresa","neutro"="neutro","enfado"="ira",
        "rabia"="ira","felicidad"="alegría","happy"="alegría","sad"="tristeza",
        "anger"="ira","fear"="miedo","disgust"="asco","surprise"="sorpresa","neutral"="neutro"
      )
      buscar_emo_en_cadena <- function(cadena) {
        parts <- unlist(strsplit(cadena, "[_\\-]"))
        for (p in parts) {
          p_low <- gsub("[^a-záéíóúñü]", "", tolower(p))
          if (p_low %in% names(emospanish_map)) return(emospanish_map[[p_low]])
        }
        return(NA_character_)
      }
      for (i in seq_len(n_total)) {
        emo_detected <- buscar_emo_en_cadena(ips$filename[i])
        if (is.na(emo_detected) && "hablante" %in% colnames(ips))
          emo_detected <- buscar_emo_en_cadena(ips$hablante[i])
        if (!is.na(emo_detected)) {
          ann$emocion_manual[i] <- emo_detected
          n_detectados <- n_detectados + 1
        }
      }

    } else if (tipo == "excel_tiempos") {
      req(input$autoemo_excel)
      ext    <- tools::file_ext(input$autoemo_excel$name)
      df_emo <- tryCatch({
        if (tolower(ext) == "xlsx") {
          if (!requireNamespace("readxl", quietly=TRUE)) {
            showNotification("Instala 'readxl': install.packages('readxl')", type="error"); return()
          }
          # Leer cabecera para detectar posición de columnas de tiempo
          hdr <- suppressMessages(readxl::read_excel(input$autoemo_excel$datapath, n_max = 0))
          # Siempre forzar texto en las columnas inicio/fin (y sus variantes)
          # para preservar el formato "MM:SS,d" exacto que escribe el usuario
          time_col_names <- c("inicio","fin","start","end","tmin","tmax","t_inicio","t_fin","xmin","xmax")
          col_types_vec <- rep("guess", ncol(hdr))
          for (j in seq_along(colnames(hdr))) {
            if (tolower(colnames(hdr)[j]) %in% time_col_names)
              col_types_vec[j] <- "text"
          }
          readxl::read_excel(input$autoemo_excel$datapath, col_types = col_types_vec)
        } else {
          read.csv(input$autoemo_excel$datapath, stringsAsFactors=FALSE, encoding="UTF-8")
        }
      }, error = function(e) {
        showNotification(paste("Error leyendo archivo:", e$message), type="error"); NULL
      })
      req(!is.null(df_emo))

      cols_req <- c("inicio","fin","emocion","filename")
      cols_alt <- list(
        inicio   = c("start","tmin","t_inicio","xmin"),
        fin      = c("end","tmax","t_fin","xmax"),
        emocion  = c("emotion","label","etiqueta"),
        filename = c("file","archivo","nombre","name")
      )
      for (col in cols_req) {
        if (!col %in% colnames(df_emo)) {
          alt_found <- intersect(tolower(colnames(df_emo)), cols_alt[[col]])
          if (length(alt_found) > 0)
            colnames(df_emo)[tolower(colnames(df_emo)) == alt_found[1]] <- col
        }
      }
      if (!all(cols_req %in% colnames(df_emo))) {
        showNotification(paste0("Columnas requeridas: filename, inicio, fin, emocion. Encontradas: ",
          paste(colnames(df_emo), collapse=", ")), type="error", duration=15)
        return()
      }

      # Parsear tiempos: soportar todos los formatos que readxl puede producir
      # readxl con celdas de tiempo MM:SS puede devolver:
      #   - numeric (fracción de día: 0.004731...)
      #   - difftime / hms (segundos desde medianoche)
      #   - POSIXct (fecha+hora con ancla 1899-12-31)
      #   - character ("06:48,8", "06:48.8", "1899-12-31 00:06:48", "0.00473...")
      parse_tiempo_mmss <- function(x) {
        # difftime / hms: as.numeric da segundos directamente
        if (inherits(x, "difftime")) return(as.numeric(x, units = "secs"))
        # POSIXct (readxl ancla 1899-12-31)
        if (inherits(x, "POSIXct") || inherits(x, "POSIXt")) {
          return(as.numeric(format(x, "%H")) * 3600 +
                 as.numeric(format(x, "%M")) * 60 +
                 as.numeric(format(x, "%OS")))
        }
        # Numeric: distinguir fracción de día (<2) de segundos (>=2)
        if (is.numeric(x)) {
          return(ifelse(!is.na(x) & x < 2, x * 86400, x))
        }
        # Character / factor: normalizar y parsear
        x <- as.character(x)
        sapply(x, function(v) {
          if (is.na(v) || trimws(v) == "") return(NA_real_)
          v2 <- gsub(",", ".", trimws(v))
          # "408.8 secs" o "408 secs" — as.character(difftime) produce esto
          m_secs <- regmatches(v2, regexpr("^([0-9]+\\.?[0-9]*)\\s*secs?$", v2))
          if (length(m_secs) > 0)
            return(suppressWarnings(as.numeric(sub("\\s*secs?$","",m_secs))))
          # Formato MM:SS.d
          if (grepl("^\\d+:\\d+(\\.\\d+)?$", v2)) {
            p <- strsplit(v2, ":")[[1]]
            return(as.numeric(p[1]) * 60 + as.numeric(p[2]))
          }
          # Formato HH:MM:SS.d
          if (grepl("^\\d+:\\d+:\\d+(\\.\\d+)?$", v2)) {
            p <- strsplit(v2, ":")[[1]]
            return(as.numeric(p[1]) * 3600 + as.numeric(p[2]) * 60 + as.numeric(p[3]))
          }
          # "1899-12-31 HH:MM:SS" de POSIXct→character
          m_dt <- regmatches(v2, regexpr("\\d+:\\d+:\\d+(\\.\\d+)?", v2))
          if (length(m_dt) > 0) {
            p <- strsplit(m_dt, ":")[[1]]
            return(as.numeric(p[1]) * 3600 + as.numeric(p[2]) * 60 + as.numeric(p[3]))
          }
          # Numérico puro (fracción de día o segundos)
          n <- suppressWarnings(as.numeric(v2))
          if (!is.na(n)) return(if (n < 2) n * 86400 else n)
          NA_real_
        }, USE.NAMES = FALSE)
      }

      df_emo$inicio <- parse_tiempo_mmss(df_emo$inicio)
      df_emo$fin    <- parse_tiempo_mmss(df_emo$fin)

      # Diagnóstico: cuántas filas tienen tiempos válidos vs vacías
      n_con_tiempo  <- sum(!is.na(df_emo$inicio) & !is.na(df_emo$fin))
      n_sin_tiempo  <- sum(is.na(df_emo$inicio) | is.na(df_emo$fin))
      n_con_emocion <- sum(!is.na(df_emo$emocion) & trimws(as.character(df_emo$emocion)) != "", na.rm=TRUE)
      if (n_con_tiempo > 0) {
        ej <- sprintf("%.1fs\u2013%.1fs", df_emo$inicio[which(!is.na(df_emo$inicio))[1]],
                                          df_emo$fin[which(!is.na(df_emo$fin))[1]])
        showNotification(paste0("Excel le\u00eddo: ", n_con_tiempo, " filas con tiempo (",
          n_sin_tiempo, " sin tiempo), ", n_con_emocion, " con emoci\u00f3n. Ej: ", ej),
          type="message", duration=6)
      }

      # Filtrar filas sin tiempos válidos
      df_emo <- df_emo[!is.na(df_emo$inicio) & !is.na(df_emo$fin), ]
      if (nrow(df_emo) == 0) {
        showNotification("No se encontraron filas con tiempos v\u00e1lidos en el Excel.", type = "error", duration = 10)
        return()
      }

      emo_norm_map <- c(
        "alegria"="alegría","alegría"="alegría","tristeza"="tristeza",
        "ira"="ira","enfado"="ira","rabia"="ira","miedo"="miedo","fear"="miedo",
        "asco"="asco","disgust"="asco","sorpresa"="sorpresa","surprise"="sorpresa",
        "neutro"="neutro","neutral"="neutro","felicidad"="alegría","happy"="alegría",
        "sad"="tristeza","anger"="ira"
      )
      df_emo$emocion_norm <- emo_norm_map[gsub("[^a-záéíóúñü]","",tolower(df_emo$emocion))]

      # Normalizar filename para matching: sin extensión, sin espacios, minúsculas
      norm_fn <- function(x) tolower(trimws(tools::file_path_sans_ext(as.character(x))))
      df_emo$filename_norm <- norm_fn(df_emo$filename)

      tolerancia <- 0.05
      for (i in seq_len(n_total)) {
        t_ini_ip <- ips$inicio[i]; t_fin_ip <- ips$fin[i]
        ip_fn_norm <- norm_fn(ips$filename[i])
        match_idx <- which(
          !is.na(df_emo$inicio) & !is.na(df_emo$fin) &
          df_emo$fin    >= (t_ini_ip - tolerancia) &
          df_emo$inicio <= (t_fin_ip  + tolerancia) &
          df_emo$filename_norm == ip_fn_norm
        )
        if (length(match_idx) == 0) next
        if (length(match_idx) > 1) {
          solaps    <- sapply(match_idx, function(m) min(df_emo$fin[m],t_fin_ip) - max(df_emo$inicio[m],t_ini_ip))
          match_idx <- match_idx[which.max(solaps)]
        }
        emo_excel <- df_emo$emocion_norm[match_idx]
        if (!is.na(emo_excel)) {
          ann$emocion_manual[i] <- emo_excel
          n_detectados <- n_detectados + 1
        }
      }

    } else if (tipo == "series") {
      series_map <- c(
        "alegría"="alegría","alegria"="alegría","tristeza"="tristeza","ira"="ira",
        "miedo"="miedo","asco"="asco","sorpresa"="sorpresa","neutro"="neutro",
        "enfado"="ira","rabia"="ira","felicidad"="alegría","desprecio"="asco",
        "happy"="alegría","sad"="tristeza","anger"="ira","fear"="miedo",
        "disgust"="asco","surprise"="sorpresa","neutral"="neutro","contempt"="asco",
        "happiness"="alegría","sadness"="tristeza"
      )
      if ("palabras_grupo" %in% colnames(ips)) {
        for (i in seq_len(n_total)) {
          txt <- ips$palabras_grupo[i]
          if (is.na(txt) || !grepl("\\[.+\\]\\s*$", txt)) next
          m <- regmatches(txt, regexpr("\\[([^\\]]+)\\]\\s*$", txt))
          if (length(m) > 0) {
            emo_raw    <- tolower(gsub("\\[|\\]|\\s*$","",m))
            emo_mapped <- series_map[emo_raw]
            if (!is.na(emo_mapped)) {
              ann$emocion_manual[i]  <- emo_mapped
              ips$palabras_grupo[i]  <- trimws(sub("\\s*\\[([^\\]]+)\\]\\s*$","",txt))
              n_detectados <- n_detectados + 1
            }
          }
        }
        datos$ips_resumen <- corregir_semitones_si_necesario(ips)
      }
      if (!is.null(datos$words) && "etiqueta" %in% colnames(datos$words)) {
        wd <- datos$words
        for (j in grep("\\[.+\\]\\s*$", wd$etiqueta)) {
          m_w <- regmatches(wd$etiqueta[j], regexpr("\\[([^\\]]+)\\]\\s*$", wd$etiqueta[j]))
          if (length(m_w) > 0) wd$etiqueta[j] <- trimws(sub("\\s*\\[([^\\]]+)\\]\\s*$","",wd$etiqueta[j]))
        }
        datos$words <- wd
      }
      if (!is.null(datos$phones) && "palabra" %in% colnames(datos$phones)) {
        ph <- datos$phones
        for (j in grep("\\[.+\\]", ph$palabra))
          ph$palabra[j] <- trimws(gsub("\\[([^\\]]+)\\]","",ph$palabra[j]))
        datos$phones <- ph
      }

    } else if (tipo == "importar_audio") {
      # ---- Verificaciones previas ----
      if (!"emocion_audio" %in% colnames(ips)) {
        showNotification("La columna 'emocion_audio' no existe. Ejecuta primero el reconocimiento acústico.",
                         type="error", duration=10)
        return()
      }
      tiene_audio   <- !is.na(ips$emocion_audio) & ips$emocion_audio != "" & ips$emocion_audio != "no_wav"
      n_disponibles <- sum(tiene_audio)
      if (n_disponibles == 0) {
        showNotification("No hay ningún GE con reconocimiento acústico disponible.", type="warning")
        return()
      }

      sobreescribir  <- isTRUE(input$autoemo_audio_sobreescribir)
      ya_etiquetados <- !is.na(ann$emocion_manual) & ann$emocion_manual != "" & ann$emocion_manual != "neutro"
      n_afectados    <- if (sobreescribir) n_disponibles else sum(tiene_audio & !ya_etiquetados)

      audio_norm_map <- c(
        # emo2vec (chino + inglés)
        "too_short"      = NA,
        "中立/neutral"   = "neutro",   "neutral"    = "neutro",
        "其他/other"     = NA,         "other"      = NA,
        "厌恶/disgusted" = "asco",     "disgusted"  = "asco",
        "吃惊/surprised" = "sorpresa", "surprised"  = "sorpresa",
        "开心/happy"     = "alegría",  "happy"      = "alegría",
        "恐惧/fearful"   = "miedo",    "fearful"    = "miedo",
        "生气/angry"     = "ira",      "angry"      = "ira",
        "难过/sad"       = "tristeza", "sad"        = "tristeza",
        # variantes de otros modelos
        "alegria"="alegría","alegría"="alegría","happiness"="alegría","joy"="alegría",
        "tristeza"="tristeza","sadness"="tristeza",
        "ira"="ira","anger"="ira","enfado"="ira","rabia"="ira",
        "miedo"="miedo","fear"="miedo",
        "asco"="asco","disgust"="asco",
        "sorpresa"="sorpresa","surprise"="sorpresa",
        "neutro"="neutro","desprecio"="asco","contempt"="asco"
      )

      msg <- paste0(
        "¿Está seguro de querer importar el reconocimiento automático de emociones acústicas?\n\n",
        "• GEs con emocion_audio disponible: ", n_disponibles, "\n",
        "• GEs que se modificarán: ", n_afectados,
        if (!sobreescribir) " (solo los que no tienen etiqueta manual)"
        else " (incluidos los ya etiquetados manualmente)",
        "\n\nEsta acción ",
        if (sobreescribir) "SOBREESCRIBIRÁ" else "no modificará",
        " las etiquetas manuales existentes."
      )
      showModal(modalDialog(
        title     = tags$span(icon("exclamation-triangle"), " Confirmar importación"),
        size      = "m",
        easyClose = FALSE,
        p(style = "white-space:pre-wrap;font-size:0.95em;", msg),
        if (sobreescribir)
          div(class="alert alert-danger", style="margin-top:10px;",
              icon("warning"), " Atención: las etiquetas manuales existentes serán reemplazadas.")
        else
          div(class="alert alert-info", style="margin-top:10px;",
              icon("info-circle"), " Solo se asignarán emociones a GEs sin etiqueta manual previa."),
        footer = tagList(
          modalButton("Cancelar"),
          actionButton("btn_confirmar_importar_audio", "Sí, importar",
                       class="btn-warning", icon=icon("check"))
        )
      ))

      # Guardar estado y salir — la escritura ocurre en btn_confirmar_importar_audio
      import_audio_state$tiene_audio    <- tiene_audio
      import_audio_state$sobreescribir  <- sobreescribir
      import_audio_state$ya_etiquetados <- ya_etiquetados
      import_audio_state$audio_norm_map <- audio_norm_map
      return()   # <-- salida limpia: NO cae al bloque de guardado de abajo

    } # ---- fin if/else if ----

    # ============================================================
    # Guardado común a todos los tipos EXCEPTO importar_audio
    # (que sale por return() antes de llegar aquí)
    # ============================================================
    etiq$anotaciones <- ann
    # Propagar emocion_manual a ips_resumen (defensivo: ajustar longitud si hay desincronía residual)
    if (!is.null(datos$ips_resumen) && "emocion_manual" %in% colnames(ann)) {
      n_ips   <- nrow(datos$ips_resumen)
      emo_vec <- ann$emocion_manual
      if (length(emo_vec) > n_ips) {
        emo_vec <- emo_vec[seq_len(n_ips)]
      } else if (length(emo_vec) < n_ips) {
        emo_vec <- c(emo_vec, rep("neutro", n_ips - length(emo_vec)))
      }
      datos$ips_resumen$emocion_manual <- emo_vec
    }
    datos$etiquetado_completado <- TRUE
    updateCheckboxInput(session, "etiq_completado_check", value = TRUE)
    # Guardar siempre todos los archivos: auto_guardar queda bloqueada cuando el
    # análisis fue cargado desde almacenamiento (cargado_desde_storage = TRUE),
    # por lo que se llama directamente a las funciones de guardado completo.
    tryCatch(guardar_etiquetado_persistente(), error = function(e) NULL)
    guardar_todos_por_archivo(notificar_cada = FALSE)

    emociones_detectadas <- table(ann$emocion_manual[ann$emocion_manual != "neutro"])
    resumen <- paste0(
      "\u2714 Detectadas: ", n_detectados, " / ", n_total, " GEs\n",
      paste(names(emociones_detectadas), ": ", emociones_detectadas, collapse="\n")
    )
    output$autoemo_resultado <- renderText(resumen)
    showNotification(paste0("Auto-detección completada: ", n_detectados, "/", n_total, " emociones asignadas"),
                     type="message", duration=8)
    log_event("AUTO_EMOCION", paste0(tipo, ": ", n_detectados, "/", n_total))

  }, error = function(e) {
    showNotification(paste("Error en auto-detección:", e$message), type="error")
  })
})
  
  # Estado temporal para la importación de emocion_audio
import_audio_state <- reactiveValues(
  tiene_audio    = NULL,
  sobreescribir  = FALSE,
  ya_etiquetados = NULL,
  audio_norm_map = NULL
)

# Ejecutar importación tras confirmación
observeEvent(input$btn_confirmar_importar_audio, {
  removeModal()
  req(datos$calculado, datos$ips_resumen, etiq$anotaciones)
  req(!is.null(import_audio_state$tiene_audio))

  ips          <- datos$ips_resumen
  ann          <- etiq$anotaciones
  tiene_audio  <- import_audio_state$tiene_audio
  sobreescribir <- import_audio_state$sobreescribir
  ya_etiquetados <- import_audio_state$ya_etiquetados
  audio_norm_map <- import_audio_state$audio_norm_map
  n_detectados  <- 0

  for (i in seq_len(nrow(ips))) {
    if (!tiene_audio[i]) next
    if (!sobreescribir && ya_etiquetados[i]) next

emo_raw  <- tolower(trimws(ips$emocion_audio[i]))
# Buscar primero la etiqueta completa (con chino/barra), luego versión limpia como fallback
emo_norm <- if (!is.na(audio_norm_map[emo_raw])) audio_norm_map[emo_raw] else
            audio_norm_map[gsub("[^a-záéíóúñü]", "", emo_raw)]

    if (!is.na(emo_norm)) {
      ann$emocion_manual[i] <- emo_norm
      n_detectados <- n_detectados + 1
    }
  }

  etiq$anotaciones <- ann
  datos$etiquetado_completado <- TRUE
  updateCheckboxInput(session, "etiq_completado_check", value = TRUE)

  auto_guardar("Importación emocion_audio")
  tryCatch(guardar_etiquetado_persistente(), error = function(e) NULL)

  emociones_detectadas <- table(ann$emocion_manual[ann$emocion_manual != "neutro"])
  resumen <- paste0(
    "\u2714 Importadas: ", n_detectados, " emociones acústicas\n",
    paste(names(emociones_detectadas), ": ", emociones_detectadas, collapse = "\n")
  )
  output$autoemo_resultado <- renderText(resumen)

  showNotification(
    paste0("Importación completada: ", n_detectados, " emociones acústicas asignadas"),
    type = "message", duration = 8)
  log_event("AUTO_EMOCION", paste0("importar_audio: ", n_detectados, "/", nrow(ips)))
})
  
  # Observer: etiquetado completado checkbox
  observeEvent(input$etiq_completado_check, {
    datos$etiquetado_completado <- input$etiq_completado_check
    if (input$etiq_completado_check) {
      log_event("ETIQUETADO_MARCADO_COMPLETO")
    } else {
      log_event("ETIQUETADO_DESMARCADO_COMPLETO")
    }
    auto_guardar("Etiquetado completado toggle")
  }, ignoreInit = TRUE)

  # ─────────────────────────────────────────────────────────────────────────────
  # Helper: generar phones aproximados para palabras sin cobertura fonética
  #
  # words_df  : data.frame con columnas inicio, fin, etiqueta (tiempo absoluto)
  # phones_df : data.frame con columnas inicio, fin, etiqueta (tiempo absoluto);
  #             puede ser NULL o vacío
  # pitch_fn  : data.frame con columnas tiempo, f0 (filtrado al archivo); puede
  #             ser NULL para usar distribución equitativa
  #
  # Devuelve data.frame con columnas inicio, fin, etiqueta (tiempo absoluto) de
  # los phones aproximados que FALTAN (no incluye los existentes).
  # El atributo "n_aprox" indica cuántos phones se generaron por aproximación.
  # ─────────────────────────────────────────────────────────────────────────────
  # Distribuye una secuencia de phones IPA en el intervalo [t1, t2].
  # Si hay datos de F0/intensidad los usa para ajustar la frontera
  # entre zonas sonoras (→ fonemas sonoros) y sordas (→ fonemas sordos).
  # Devuelve data.frame con inicio, fin, etiqueta (tiempo absoluto).
  alinear_phones_ipa <- function(ipa_df, t1, t2, pitch_fn = NULL, int_fn = NULL) {
    n_ph <- nrow(ipa_df)
    if (n_ph == 0) return(data.frame(inicio=numeric(0), fin=numeric(0),
                                     etiqueta=character(0), stringsAsFactors=FALSE))
    dur <- t2 - t1
    # Duraciones base proporcionales a los pesos
    peso_total <- sum(ipa_df$peso)
    if (peso_total == 0) peso_total <- n_ph
    durs <- ipa_df$peso / peso_total * dur

    # Ajuste por F0: los fonemas sonoros deben coincidir con frames sonorizados
    # y los sordos con frames sordos.
    if (!is.null(pitch_fn) && nrow(pitch_fn) > 0) {
      pts <- pitch_fn[pitch_fn$tiempo >= t1 & pitch_fn$tiempo <= t2, ]
      if (nrow(pts) >= 2L) {
        n_frames  <- nrow(pts)
        is_voiced <- !is.na(pts$f0) & pts$f0 > 0
        voiced_ratio <- mean(is_voiced)      # proporción sonora del intervalo
        # Suma de pesos sonoros vs sordos
        w_son  <- sum(ipa_df$peso[ipa_df$sonoro],  na.rm=TRUE)
        w_sord <- sum(ipa_df$peso[!ipa_df$sonoro], na.rm=TRUE)
        # Si hay desequilibrio entre la señal y los pesos, escalar
        target_son  <- dur * voiced_ratio
        target_sord <- dur * (1 - voiced_ratio)
        if (w_son > 0 && target_son > 0)
          durs[ipa_df$sonoro]  <- ipa_df$peso[ipa_df$sonoro]  / w_son  * target_son
        if (w_sord > 0 && target_sord > 0)
          durs[!ipa_df$sonoro] <- ipa_df$peso[!ipa_df$sonoro] / w_sord * target_sord
        # Renormalizar para que la suma exactamente cubra [t1,t2]
        durs <- durs / sum(durs) * dur
      }
    }

    # Construir intervalos sin solapamiento
    resultado <- data.frame(inicio=numeric(n_ph), fin=numeric(n_ph),
                            etiqueta=ipa_df$phone, stringsAsFactors=FALSE)
    cursor <- t1
    for (k in seq_len(n_ph)) {
      resultado$inicio[k] <- cursor
      resultado$fin[k]    <- cursor + durs[k]
      cursor <- resultado$fin[k]
    }
    # Forzar exactitud en los límites
    resultado$fin[n_ph] <- t2
    resultado
  }

  generar_phones_aprox_para_sin_cobertura <- function(words_df, phones_df,
                                                       pitch_fn = NULL, int_fn = NULL,
                                                       variedad = "neutro") {
    resultado <- data.frame(inicio=numeric(0), fin=numeric(0), etiqueta=character(0),
                            stringsAsFactors=FALSE)
    n_aprox <- 0L

    if (is.null(words_df) || nrow(words_df) == 0) {
      attr(resultado, "n_aprox") <- n_aprox
      return(resultado)
    }

    etiq_col <- if ("etiqueta" %in% colnames(words_df)) "etiqueta" else "text"

    for (i in seq_len(nrow(words_df))) {
      t1   <- words_df$inicio[i]
      t2   <- words_df$fin[i]
      word <- words_df[[etiq_col]][i]
      if (is.na(word) || nchar(trimws(word)) == 0 || is.na(t1) || is.na(t2) || t2 <= t1) next

      # ¿Ya hay phones reales que se solapan con esta palabra?
      if (!is.null(phones_df) && nrow(phones_df) > 0) {
        overlap <- phones_df[phones_df$inicio < t2 & phones_df$fin > t1, ]
        if (nrow(overlap) > 0) next
      }

      # Transcripción IPA completa (consonantes + vocales)
      ipa_df <- tryCatch(texto_a_ipa_es(word, variedad = variedad),
                         error = function(e) data.frame(phone=character(0), peso=numeric(0),
                                                        sonoro=logical(0), stringsAsFactors=FALSE))
      if (nrow(ipa_df) == 0) next

      # Filtrar pitch/intensidad al rango de esta palabra
      pit_w <- if (!is.null(pitch_fn) && nrow(pitch_fn) > 0)
        pitch_fn[pitch_fn$tiempo >= t1 & pitch_fn$tiempo <= t2, ] else NULL
      int_w <- if (!is.null(int_fn) && nrow(int_fn) > 0)
        int_fn[int_fn$tiempo >= t1 & int_fn$tiempo <= t2, ] else NULL

      phones_pal <- alinear_phones_ipa(ipa_df, t1, t2,
                                       pitch_fn = pit_w, int_fn = int_w)
      if (nrow(phones_pal) == 0) next

      # Evitar solapamiento con phones ya añadidos
      if (nrow(resultado) > 0) {
        phones_pal$inicio <- pmax(phones_pal$inicio,
                                   resultado$fin[nrow(resultado)] + 1e-4)
        phones_pal <- phones_pal[phones_pal$fin > phones_pal$inicio + 0.001, ]
      }
      if (nrow(phones_pal) == 0) next

      resultado <- rbind(resultado, data.frame(
        inicio   = phones_pal$inicio,
        fin      = phones_pal$fin,
        etiqueta = phones_pal$etiqueta,
        stringsAsFactors = FALSE
      ))
      n_aprox <- n_aprox + nrow(phones_pal)
    }

    if (nrow(resultado) > 0) resultado <- resultado[order(resultado$inicio), ]
    attr(resultado, "n_aprox") <- n_aprox
    resultado
  }

  # ─────────────────────────────────────────────────────────────────────────────
  # Helper: generar words y phones aproximados desde texto con timestamps
  # (para TextGrid de Whisper)
  #
  # segs_df: data.frame con columnas inicio, fin, texto (segmentos/utterances)
  # pitch_fn: data.frame con tiempo, f0 (puede ser NULL)
  #
  # Devuelve lista con:
  #   $words  : data.frame xmin, xmax, text (relativo a tmax del audio)
  #   $phones : data.frame xmin, xmax, text (relativo a tmax del audio)
  #   $n_aprox: número de phones aproximados generados
  # ─────────────────────────────────────────────────────────────────────────────
  generar_words_phones_whisper <- function(segs_df, pitch_fn = NULL, int_fn = NULL,
                                            variedad = "neutro") {
    words_out  <- data.frame(xmin=numeric(0), xmax=numeric(0), text=character(0),
                             stringsAsFactors=FALSE)
    phones_out <- data.frame(xmin=numeric(0), xmax=numeric(0), text=character(0),
                             stringsAsFactors=FALSE)
    n_aprox    <- 0L

    for (i in seq_len(nrow(segs_df))) {
      t1  <- segs_df$inicio[i]
      t2  <- segs_df$fin[i]
      txt <- trimws(as.character(segs_df$texto[i]))
      if (is.na(t1) || is.na(t2) || t2 <= t1 || nchar(txt) == 0) next

      # Dividir en palabras y distribuir uniformemente dentro del segmento
      # (Whisper solo da timestamps de segmento, no de palabra)
      pals <- strsplit(txt, "\\s+")[[1]]
      pals <- pals[nchar(trimws(pals)) > 0]
      if (length(pals) == 0) next

      # Peso proporcional de cada palabra según su longitud en phones IPA
      ipa_pals <- lapply(pals, function(p)
        tryCatch(texto_a_ipa_es(p, variedad=variedad),
                 error = function(e) data.frame(phone=character(0), peso=numeric(0),
                                                sonoro=logical(0), stringsAsFactors=FALSE)))
      pesos_pal <- vapply(ipa_pals, function(d) max(sum(d$peso), 0.1), numeric(1))
      dur_s     <- t2 - t1
      durs_pal  <- pesos_pal / sum(pesos_pal) * dur_s

      cursor_pal <- t1
      for (j in seq_along(pals)) {
        wt1 <- cursor_pal
        wt2 <- cursor_pal + durs_pal[j]
        if (nrow(words_out) > 0) wt1 <- max(wt1, words_out$xmax[nrow(words_out)] + 1e-4)
        if (wt2 <= wt1) { cursor_pal <- wt2; next }

        words_out <- rbind(words_out, data.frame(xmin=wt1, xmax=wt2,
                                                  text=pals[j], stringsAsFactors=FALSE))

        # Phones de esta palabra via IPA + alineación F0
        ipa_pal <- ipa_pals[[j]]
        if (nrow(ipa_pal) > 0) {
          pit_w <- if (!is.null(pitch_fn) && nrow(pitch_fn) > 0)
            pitch_fn[pitch_fn$tiempo >= wt1 & pitch_fn$tiempo <= wt2, ] else NULL
          int_w <- if (!is.null(int_fn) && nrow(int_fn) > 0)
            int_fn[int_fn$tiempo >= wt1 & int_fn$tiempo <= wt2, ] else NULL

          ph_pal <- alinear_phones_ipa(ipa_pal, wt1, wt2,
                                       pitch_fn = pit_w, int_fn = int_w)
          if (nrow(ph_pal) > 0) {
            if (nrow(phones_out) > 0)
              ph_pal$inicio <- pmax(ph_pal$inicio,
                                    phones_out$xmax[nrow(phones_out)] + 1e-4)
            ph_pal <- ph_pal[ph_pal$fin > ph_pal$inicio + 0.001, ]
            if (nrow(ph_pal) > 0) {
              phones_out <- rbind(phones_out, data.frame(
                xmin = ph_pal$inicio,
                xmax = ph_pal$fin,
                text = ph_pal$etiqueta,
                stringsAsFactors = FALSE
              ))
              n_aprox <- n_aprox + nrow(ph_pal)
            }
          }
        }
        cursor_pal <- wt2
      }
    }

    list(words=words_out, phones=phones_out, n_aprox=n_aprox)
  }

  # Exportar audios de actos etiquetados
  observeEvent(input$etiq_exportar_audios, {
    req(etiq$anotaciones, datos$ips_resumen, datos$phones)
    
    actos_unicos <- unique(na.omit(etiq$anotaciones$acto_id))
    if (length(actos_unicos) == 0) {
      showNotification("No hay actos etiquetados aún", type = "warning")
      return()
    }
    
    # Crear carpeta de salida
    out_dir <- file.path(getwd(), "audios_emocion")
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
    
    withProgress(message = "Exportando audios...", value = 0, {
      n_actos <- length(actos_unicos)
      
      for (k in seq_along(actos_unicos)) {
        acto_id <- actos_unicos[k]
        filas <- which(etiq$anotaciones$acto_id == acto_id)
        ips_acto <- datos$ips_resumen[filas, ]
        emocion <- etiq$anotaciones$emocion_manual[filas[1]]
        
        t_inicio <- min(ips_acto$inicio, na.rm = TRUE)
        t_fin <- max(ips_acto$fin, na.rm = TRUE)
        fn <- ips_acto$filename[1]
        
        wav_path <- buscar_wav(fn)
        tg_path <- buscar_tg(fn)
        
        nombre_base <- paste0(emocion, "_acto", acto_id)
        
        # Guardar wav
        if (!is.null(wav_path)) {
          guardar_segmento_wav(wav_path, t_inicio, t_fin, 
                               file.path(out_dir, paste0(nombre_base, ".wav")))
        }
        
        # Crear TextGrid del acto
        if (!is.null(tg_path)) {
          tryCatch({
            # Extraer phones y words del acto
            phones_acto <- datos$phones[datos$phones$filename == fn &
                                          datos$phones$inicio >= t_inicio &
                                          datos$phones$fin <= t_fin, ]
            
            palabras_texto <- paste(ips_acto$palabras_grupo, collapse = " ")
            
            # Escribir TextGrid simple
            tg_out <- file.path(out_dir, paste0(nombre_base, ".TextGrid"))
            dur <- t_fin - t_inicio
            
            # Construir tiers
            # Tier 1: Texto del acto
            # Tier 2: Palabras
            # Tier 3: Phones (real + aproximados para palabras sin cobertura)

            # Words del acto desde datos$words (tienen timestamps reales)
            words_acto <- if (!is.null(datos$words) && nrow(datos$words) > 0)
              datos$words[datos$words$filename == fn &
                            datos$words$inicio >= t_inicio &
                            datos$words$fin    <= t_fin, ]
            else data.frame()

            # Pitch filtrado para este archivo (para mejorar posicionamiento)
            pitch_fn_acto <- if (!is.null(datos$pitch) && nrow(datos$pitch) > 0 &&
                                   "archivo_origen" %in% colnames(datos$pitch))
              datos$pitch[datos$pitch$archivo_origen == fn, ]
            else NULL

            # Agrupar phones reales por palabra para tier de palabras
            words_intervals <- data.frame()
            if (nrow(phones_acto) > 0) {
              for (pal in unique(phones_acto$palabra_idx)) {
                ph_pal <- phones_acto[phones_acto$palabra_idx == pal & !is.na(phones_acto$palabra_idx), ]
                if (nrow(ph_pal) > 0) {
                  words_intervals <- rbind(words_intervals, data.frame(
                    xmin = min(ph_pal$inicio) - t_inicio,
                    xmax = max(ph_pal$fin) - t_inicio,
                    text = ph_pal$palabra[1],
                    stringsAsFactors = FALSE
                  ))
                }
              }
            }
            # Añadir palabras de datos$words que no están cubiertas por phones reales
            if (nrow(words_acto) > 0) {
              etiq_col_w <- if ("etiqueta" %in% colnames(words_acto)) "etiqueta" else "text"
              for (wi in seq_len(nrow(words_acto))) {
                wt1 <- words_acto$inicio[wi]
                wt2 <- words_acto$fin[wi]
                ya_cubierta <- nrow(words_intervals) > 0 &&
                  any(words_intervals$xmin + t_inicio < wt2 &
                        words_intervals$xmax + t_inicio > wt1)
                if (!ya_cubierta) {
                  words_intervals <- rbind(words_intervals, data.frame(
                    xmin = wt1 - t_inicio,
                    xmax = wt2 - t_inicio,
                    text = words_acto[[etiq_col_w]][wi],
                    stringsAsFactors = FALSE
                  ))
                }
              }
              if (nrow(words_intervals) > 0)
                words_intervals <- words_intervals[order(words_intervals$xmin), ]
            }

            phones_intervals <- data.frame(
              xmin = phones_acto$inicio - t_inicio,
              xmax = phones_acto$fin - t_inicio,
              text = phones_acto$etiqueta,
              stringsAsFactors = FALSE
            )

            # Completar phones aproximados para palabras sin cobertura
            phones_aprox <- generar_phones_aprox_para_sin_cobertura(
              words_df  = words_acto,
              phones_df = phones_acto,
              pitch_fn  = pitch_fn_acto
            )
            n_phones_aprox <- attr(phones_aprox, "n_aprox")
            if (nrow(phones_aprox) > 0) {
              phones_intervals <- rbind(
                phones_intervals,
                data.frame(xmin = phones_aprox$inicio - t_inicio,
                           xmax = phones_aprox$fin    - t_inicio,
                           text = phones_aprox$etiqueta,
                           stringsAsFactors = FALSE)
              )
              phones_intervals <- phones_intervals[order(phones_intervals$xmin), ]
            }
            
            # Escribir TextGrid manualmente
            lines <- c(
              'File type = "ooTextFile"',
              'Object class = "TextGrid"',
              '',
              paste0('xmin = 0'),
              paste0('xmax = ', dur),
              'tiers? <exists>',
              'size = 3',
              'item []:')
            
            # Helper para escribir un tier
            write_tier <- function(idx, name, intervals, dur) {
              l <- c(
                paste0('    item [', idx, ']:'),
                '        class = "IntervalTier"',
                paste0('        name = "', name, '"'),
                '        xmin = 0',
                paste0('        xmax = ', dur),
                paste0('        intervals: size = ', max(1, nrow(intervals)))
              )
              if (nrow(intervals) == 0) {
                l <- c(l,
                  '        intervals [1]:',
                  '            xmin = 0',
                  paste0('            xmax = ', dur),
                  '            text = ""')
              } else {
                for (j in 1:nrow(intervals)) {
                  l <- c(l,
                    paste0('        intervals [', j, ']:'),
                    paste0('            xmin = ', intervals$xmin[j]),
                    paste0('            xmax = ', intervals$xmax[j]),
                    paste0('            text = "', gsub('"', '\\\\"', intervals$text[j]), '"'))
                }
              }
              l
            }
            
            # Tier 1: Acto completo
            acto_tier <- data.frame(xmin = 0, xmax = dur, text = palabras_texto, stringsAsFactors = FALSE)
            lines <- c(lines, write_tier(1, "acto", acto_tier, dur))
            
            # Tier 2: Palabras
            if (nrow(words_intervals) > 0) {
              words_intervals$xmin <- pmax(0, words_intervals$xmin)
              words_intervals$xmax <- pmin(dur, words_intervals$xmax)
            }
            lines <- c(lines, write_tier(2, "palabras", words_intervals, dur))
            
            # Tier 3: Phones
            if (nrow(phones_intervals) > 0) {
              phones_intervals$xmin <- pmax(0, phones_intervals$xmin)
              phones_intervals$xmax <- pmin(dur, phones_intervals$xmax)
            }
            lines <- c(lines, write_tier(3, "phones", phones_intervals, dur))

            writeLines(lines, tg_out)

            if (!is.null(n_phones_aprox) && n_phones_aprox > 0) {
              warning(paste0("Acto ", acto_id, ": ", n_phones_aprox,
                             " phone(s) generados por aproximación. Revise el TextGrid."))
            }

          }, error = function(e) {
            warning("Error creando TextGrid para acto ", acto_id, ": ", e$message)
          })
        }

        incProgress(k / n_actos, detail = paste0("Acto ", k, "/", n_actos))
      }
    })
    
    showNotification(paste0("Exportados ", length(actos_unicos), " actos en: ", out_dir), 
                     type = "message", duration = 15)
  })

  # Exportar audio y TextGrid del acto actual
  observeEvent(input$etiq_exportar_acto_actual, {
    req(etiq$anotaciones, datos$ips_resumen, datos$phones)
    pos <- etiq$pos_actual
    ips <- ips_etiq()
    req(is.data.frame(ips), pos >= 1, pos <= nrow(ips))

    # IMPORTANTE: pos es el índice en ips_etiq() (vista filtrada).
    # etiq$anotaciones está indexado por fila_original del ips_resumen completo.
    # Necesitamos la fila original del GE actual.
    fila_orig <- if ("fila_original" %in% colnames(ips)) ips$fila_original[pos] else pos

    acto_id <- etiq$anotaciones$acto_id[fila_orig]
    if (is.null(acto_id) || is.na(acto_id)) {
      showNotification("El GE actual no tiene acto asignado.", type = "warning"); return()
    }

    # Modal "procesando"
    showModal(modalDialog(
      title = tagList(icon("spinner", class="fa-spin"), " Exportando acto..."),
      paste0("Exportando acto ", acto_id, ". Por favor espera."),
      easyClose = FALSE, footer = NULL
    ))
    on.exit(removeModal(), add = TRUE)

    # Buscar todas las filas del acto en las anotaciones
    filas_ann <- which(etiq$anotaciones$acto_id == acto_id)
    # Mapear a filas de ips_resumen usando fila_original si existe
    if ("fila_original" %in% colnames(ips)) {
      # Filas de ips_etiq que corresponden a esas anotaciones
      ips_acto <- datos$ips_resumen[filas_ann, ]
    } else {
      ips_acto <- datos$ips_resumen[filas_ann, ]
    }
    emocion  <- etiq$anotaciones$emocion_manual[filas_ann[1]]
    if (is.null(emocion) || is.na(emocion) || emocion == "") emocion <- "sin_emocion"

    t_inicio <- min(ips_acto$inicio, na.rm = TRUE)
    t_fin    <- max(ips_acto$fin,    na.rm = TRUE)
    fn       <- ips_acto$filename[1]

    wav_path <- buscar_wav(fn)
    tg_path  <- buscar_tg(fn)

    out_dir <- file.path(getwd(), "audios_emocion")
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)

    nombre_base <- paste0(emocion, "_acto", acto_id)
    exportados  <- character(0)

    # Guardar WAV
    if (!is.null(wav_path)) {
      wav_out <- file.path(out_dir, paste0(nombre_base, ".wav"))
      guardar_segmento_wav(wav_path, t_inicio, t_fin, wav_out)
      exportados <- c(exportados, basename(wav_out))
    } else {
      showNotification(paste0("No se encontr\u00f3 audio para: ", fn), type = "warning")
    }

    # Crear TextGrid
    if (!is.null(tg_path)) {
      tryCatch({
        phones_acto <- datos$phones[datos$phones$filename == fn &
                                      datos$phones$inicio >= t_inicio &
                                      datos$phones$fin    <= t_fin, ]
        palabras_texto <- paste(ips_acto$palabras_grupo, collapse = " ")
        tg_out <- file.path(out_dir, paste0(nombre_base, ".TextGrid"))
        dur    <- t_fin - t_inicio

        write_tier_local <- function(idx, name, intervals, dur) {
          l <- c(
            paste0('    item [', idx, ']:'),
            '        class = "IntervalTier"',
            paste0('        name = "', name, '"'),
            '        xmin = 0',
            paste0('        xmax = ', dur),
            paste0('        intervals: size = ', max(1L, nrow(intervals)))
          )
          if (nrow(intervals) == 0) {
            l <- c(l, '        intervals [1]:', '            xmin = 0',
                   paste0('            xmax = ', dur), '            text = ""')
          } else {
            for (j in seq_len(nrow(intervals)))
              l <- c(l,
                paste0('        intervals [', j, ']:'),
                paste0('            xmin = ', intervals$xmin[j]),
                paste0('            xmax = ', intervals$xmax[j]),
                paste0('            text = "', gsub('"', '\\\\"', intervals$text[j]), '"'))
          }
          l
        }

        # Words del acto desde datos$words (timestamps reales)
        words_acto_curr <- if (!is.null(datos$words) && nrow(datos$words) > 0)
          datos$words[datos$words$filename == fn &
                        datos$words$inicio >= t_inicio &
                        datos$words$fin    <= t_fin, ]
        else data.frame()

        # Pitch filtrado para este archivo
        pitch_fn_curr <- if (!is.null(datos$pitch) && nrow(datos$pitch) > 0 &&
                               "archivo_origen" %in% colnames(datos$pitch))
          datos$pitch[datos$pitch$archivo_origen == fn, ]
        else NULL

        words_intervals <- data.frame()
        if (nrow(phones_acto) > 0) {
          for (pal in unique(phones_acto$palabra_idx)) {
            ph_pal <- phones_acto[!is.na(phones_acto$palabra_idx) & phones_acto$palabra_idx == pal, ]
            if (nrow(ph_pal) > 0)
              words_intervals <- rbind(words_intervals, data.frame(
                xmin = min(ph_pal$inicio) - t_inicio,
                xmax = max(ph_pal$fin)    - t_inicio,
                text = ph_pal$palabra[1], stringsAsFactors = FALSE))
          }
        }
        # Añadir palabras de datos$words sin cobertura de phones reales
        if (nrow(words_acto_curr) > 0) {
          etiq_col_wc <- if ("etiqueta" %in% colnames(words_acto_curr)) "etiqueta" else "text"
          for (wi in seq_len(nrow(words_acto_curr))) {
            wt1 <- words_acto_curr$inicio[wi]
            wt2 <- words_acto_curr$fin[wi]
            ya_cubierta <- nrow(words_intervals) > 0 &&
              any(words_intervals$xmin + t_inicio < wt2 &
                    words_intervals$xmax + t_inicio > wt1)
            if (!ya_cubierta) {
              words_intervals <- rbind(words_intervals, data.frame(
                xmin = wt1 - t_inicio,
                xmax = wt2 - t_inicio,
                text = words_acto_curr[[etiq_col_wc]][wi],
                stringsAsFactors = FALSE
              ))
            }
          }
          if (nrow(words_intervals) > 0)
            words_intervals <- words_intervals[order(words_intervals$xmin), ]
        }

        phones_intervals <- if (nrow(phones_acto) > 0)
          data.frame(xmin = phones_acto$inicio - t_inicio,
                     xmax = phones_acto$fin    - t_inicio,
                     text = phones_acto$etiqueta, stringsAsFactors = FALSE)
        else data.frame(xmin=numeric(0), xmax=numeric(0), text=character(0))

        # Completar phones aproximados para palabras sin cobertura
        phones_aprox_curr <- generar_phones_aprox_para_sin_cobertura(
          words_df  = words_acto_curr,
          phones_df = phones_acto,
          pitch_fn  = pitch_fn_curr
        )
        n_aprox_curr <- attr(phones_aprox_curr, "n_aprox")
        if (nrow(phones_aprox_curr) > 0) {
          phones_intervals <- rbind(
            phones_intervals,
            data.frame(xmin = phones_aprox_curr$inicio - t_inicio,
                       xmax = phones_aprox_curr$fin    - t_inicio,
                       text = phones_aprox_curr$etiqueta,
                       stringsAsFactors = FALSE)
          )
          phones_intervals <- phones_intervals[order(phones_intervals$xmin), ]
        }

        # Recortar a [0, dur]
        clip <- function(df) { df$xmin <- pmax(0,df$xmin); df$xmax <- pmin(dur,df$xmax); df }
        words_intervals  <- clip(words_intervals)
        phones_intervals <- clip(phones_intervals)

        acto_tier <- data.frame(xmin=0, xmax=dur, text=palabras_texto, stringsAsFactors=FALSE)
        hdr <- c('File type = "ooTextFile"', 'Object class = "TextGrid"', '',
                 'xmin = 0', paste0('xmax = ', dur), 'tiers? <exists>', 'size = 3', 'item []:')
        writeLines(
          c(hdr,
            write_tier_local(1, "acto",     acto_tier,       dur),
            write_tier_local(2, "palabras", words_intervals, dur),
            write_tier_local(3, "phones",   phones_intervals, dur)),
          tg_out)
        exportados <- c(exportados, basename(tg_out))

        if (!is.null(n_aprox_curr) && n_aprox_curr > 0) {
          showNotification(
            paste0("\u26a0\ufe0f ", n_aprox_curr, " phone(s) generados por aproximaci\u00f3n. ",
                   "Revise el TextGrid en Praat."),
            type = "warning", duration = 8)
        }
      }, error = function(e) {
        showNotification(paste("Error creando TextGrid:", e$message), type = "warning")
      })
    }

    if (length(exportados) > 0) {
      showModal(modalDialog(
        title = tagList(icon("check-circle", class="text-success"), " Acto exportado"),
        tags$p(paste0("Acto ", acto_id, " \u2014 \u201c", emocion, "\u201d")),
        tags$p(paste0("Archivos en: ", out_dir)),
        tags$ul(lapply(exportados, tags$li)),
        easyClose = TRUE, footer = modalButton("Cerrar")
      ))
    }
  })
  
  # ========================================
  # TAB: CONFIGURACIÓN MELÓDICA (display outputs)
  # ========================================
  output$melodica_tobi_sig        <- renderText({ as.character(input$tobi_umbral_significativo) })
  output$melodica_tobi_ext        <- renderText({ as.character(input$tobi_umbral_extralto) })
  output$melodica_tobi_bajo       <- renderText({ as.character(input$tobi_tercio_bajo) })
  output$melodica_tobi_alto       <- renderText({ as.character(input$tobi_tercio_alto) })
  output$melodica_amh_asc_fuerte  <- renderText({ as.character(input$amh_ascenso_fuerte) })
  output$melodica_amh_asc_mod     <- renderText({ as.character(input$amh_ascenso_moderado) })
  output$melodica_amh_asc_leve    <- renderText({ as.character(input$amh_ascenso_leve) })
  output$melodica_amh_asc_min     <- renderText({ as.character(input$amh_ascenso_minimo) })
  output$melodica_amh_desc_mod    <- renderText({ as.character(input$amh_descenso_moderado) })
  output$melodica_amh_desc_fuerte <- renderText({ as.character(input$amh_descenso_fuerte) })
  output$melodica_amh_enfasis     <- renderText({ as.character(input$amh_enfasis_pct) })
  output$melodica_amh_circunflejo <- renderText({ as.character(input$amh_circunflejo_pct) })

  # ========================================
  # VALIDACIÓN POR JUECES
  # ========================================
  
  # ── Estado reactivo de validación ─────────────────────────────────────────────
val <- reactiveValues(
  muestra           = NULL,   # data.frame con los GEs de la evaluación activa
  validaciones      = NULL,   # data.frame con las respuestas del juez actual
  pos_actual        = 1L,
  ultimo_guardado   = NULL,
  evaluacion_nombre = NULL,   # nombre de la evaluación activa (ej: "evaluacion1")
  evaluacion_fecha  = NULL,   # fecha de creación de la evaluación
  evaluacion_n      = NULL    # N de GEs de la evaluación
)

# ── Generar muestra desde ips_resumen ─────────────────────────────────────────
# ── UI: selector de evaluaciones existentes ──────────────────────────────────
output$val_selector_evaluacion <- renderUI({
  archivos <- list.files(lasp_val_evaluaciones, pattern = "\\.rds$", full.names = FALSE)
  if (length(archivos) == 0) {
    return(helpText("No hay evaluaciones guardadas aún."))
  }
  nombres <- tools::file_path_sans_ext(archivos)
  # Añadir info de N y fecha desde metadata
  labels <- sapply(nombres, function(nm) {
    path <- file.path(lasp_val_evaluaciones, paste0(nm, ".rds"))
    tryCatch({
      obj <- readRDS(path)
      paste0(nm, " — ", obj$n_ges, " GEs — ", format(obj$fecha_creacion, "%d/%m/%Y"))
    }, error = function(e) nm)
  })
  selectInput("val_sel_evaluacion_existente", "Seleccionar evaluación:",
              choices = setNames(nombres, labels))
})

# ── Cargar evaluación seleccionada ───────────────────────────────────────────
observeEvent(input$val_cargar_evaluacion_sel, {
  req(input$val_sel_evaluacion_existente)
  path <- file.path(lasp_val_evaluaciones,
                    paste0(input$val_sel_evaluacion_existente, ".rds"))
  tryCatch({
    obj <- readRDS(path)
    val$muestra           <- obj$muestra
    val$evaluacion_nombre <- obj$nombre
    val$evaluacion_fecha  <- obj$fecha_creacion
    val$evaluacion_n      <- obj$n_ges
    val$validaciones      <- NULL  # se cargará al iniciar como juez
    val$pos_actual        <- 1L
    showNotification(paste0("Evaluación '", obj$nombre, "' cargada (", obj$n_ges, " GEs)."),
                     type = "message")
  }, error = function(e) {
    showNotification(paste("Error al cargar evaluación:", e$message), type = "error")
  })
})

# ── Crear nueva evaluación ────────────────────────────────────────────────────
observeEvent(input$val_crear_evaluacion, {
  req(datos$calculado, datos$ips_resumen)
  
  nombre_eval <- trimws(input$val_nombre_evaluacion)
  if (nchar(nombre_eval) == 0) {
    showNotification("Introduce un nombre para la evaluación.", type = "error"); return()
  }
  nombre_eval <- gsub("[^a-zA-Z0-9_-]", "_", nombre_eval)
  
  # Comprobar si ya existe una evaluación con ese nombre y distinto N
  path_existente <- file.path(lasp_val_evaluaciones, paste0(nombre_eval, ".rds"))
  if (file.exists(path_existente)) {
    obj_existente <- tryCatch(readRDS(path_existente), error = function(e) NULL)
    if (!is.null(obj_existente) && obj_existente$n_ges != input$val_n_muestras) {
      showModal(modalDialog(
        title = tagList(icon("exclamation-triangle", style="color:orange"), 
                        " La evaluación ya existe con N diferente"),
        p("La evaluación '", strong(nombre_eval), "' ya existe con ", 
          strong(obj_existente$n_ges), " GEs."),
        p("Si continúas se creará una nueva evaluación (los jueces anteriores ya no podrán continuar la misma)."),
        footer = tagList(
          modalButton("Cancelar"),
          actionButton("val_confirmar_nueva_eval", "Crear nueva evaluación igualmente",
                       class = "btn-warning")
        )
      ))
      # Guardar parámetros pendientes para usar tras confirmación
      val$evaluacion_nombre <- nombre_eval
      return()
    } else if (!is.null(obj_existente)) {
      # Mismo nombre y mismo N: cargar la existente
      val$muestra           <- obj_existente$muestra
      val$evaluacion_nombre <- obj_existente$nombre
      val$evaluacion_fecha  <- obj_existente$fecha_creacion
      val$evaluacion_n      <- obj_existente$n_ges
      val$validaciones      <- NULL
      val$pos_actual        <- 1L
      showNotification(paste0("Evaluación '", nombre_eval, "' ya existe con ese N. Cargada."),
                       type = "message")
      return()
    }
  }
  
  crear_evaluacion_interna(nombre_eval, input$val_n_muestras)
})

observeEvent(input$val_confirmar_nueva_eval, {
  removeModal()
  req(val$evaluacion_nombre)
  nombre_eval <- paste0(val$evaluacion_nombre, "_", format(Sys.time(), "%Y%m%d%H%M%S"))
  crear_evaluacion_interna(nombre_eval, input$val_n_muestras)
})

# ── Función interna: construir y guardar una evaluación ──────────────────────
crear_evaluacion_interna <- function(nombre_eval, n_deseado) {
  ips <- datos$ips_resumen
  
  # Obtener emocion_manual: primero desde ips, si no desde etiq$anotaciones
  if (!"emocion_manual" %in% colnames(ips) ||
      all(is.na(ips$emocion_manual) | ips$emocion_manual == "")) {
    if (!is.null(etiq$anotaciones) && "emocion_manual" %in% colnames(etiq$anotaciones) &&
        nrow(etiq$anotaciones) == nrow(ips)) {
      ips$emocion_manual <- etiq$anotaciones$emocion_manual
    }
  }
  
  # Filtro de duración: entre 1 y 3 segundos
  if (all(c("inicio", "fin") %in% colnames(ips))) {
    ips$duracion_ge <- ips$fin - ips$inicio
    ips_filtrado <- ips[!is.na(ips$duracion_ge) & ips$duracion_ge >= 1 & ips$duracion_ge <= 3, ]
  } else {
    ips_filtrado <- ips
  }
  
  # Solo GEs con emoción manual asignada
  ips_emo <- ips_filtrado[!is.na(ips_filtrado$emocion_manual) & ips_filtrado$emocion_manual != "", ]
  
  if (nrow(ips_emo) == 0) {
    showNotification("No hay GEs con emoción manual asignada y duración entre 1 y 3 s.", type = "error")
    return()
  }
  
  tabla_emo <- table(ips_emo$emocion_manual)
n_por_emo <- sapply(names(tabla_emo), function(emo) {
  n_disp <- as.integer(tabla_emo[emo])
  min(n_deseado, n_disp)   # intentar n_deseado por emoción; si no hay suficientes, todos los disponibles
})
  
# n_deseado_real ya no es el total sino el total resultante
n_deseado_real <- sum(n_por_emo)
  desglose <- paste(names(n_por_emo), n_por_emo, sep = ":", collapse = ", ")
  
  # Semilla fija basada en el nombre (reproducible)
  set.seed(sum(utf8ToInt(nombre_eval)))
  filas_sel <- c()
  for (emo in names(n_por_emo)) {
    candidatos <- which(ips_emo$emocion_manual == emo)
    n_sel      <- min(n_por_emo[emo], length(candidatos))
    if (n_sel > 0) filas_sel <- c(filas_sel, sample(candidatos, n_sel))
  }
  muestra_ordenada <- ips_emo[sample(filas_sel), ]  # orden aleatorio
  set.seed(NULL)  # restaurar aleatoriedad
  
  muestra_df <- data.frame(
    muestra_idx      = seq_len(nrow(muestra_ordenada)),
    filename         = muestra_ordenada$filename,
    hablante         = muestra_ordenada$hablante,
    grupo_fonico     = muestra_ordenada$grupo_fonico,
    grupo_entonativo = muestra_ordenada$grupo_entonativo,
    palabras_grupo   = muestra_ordenada$palabras_grupo,
    inicio           = muestra_ordenada$inicio,
    fin              = muestra_ordenada$fin,
    duracion_ge      = if ("duracion_ge" %in% colnames(muestra_ordenada)) muestra_ordenada$duracion_ge else NA_real_,
    emocion_original = muestra_ordenada$emocion_manual,
    stringsAsFactors = FALSE
  )
  
  obj_eval <- list(
    nombre        = nombre_eval,
    muestra       = muestra_df,
    n_ges         = nrow(muestra_df),
    fecha_creacion = Sys.time(),
    n_solicitado  = n_deseado
  )
  
  path_eval <- file.path(lasp_val_evaluaciones, paste0(nombre_eval, ".rds"))
  tryCatch({
    saveRDS(obj_eval, path_eval)
    val$muestra           <- muestra_df
    val$evaluacion_nombre <- nombre_eval
    val$evaluacion_fecha  <- obj_eval$fecha_creacion
    val$evaluacion_n      <- nrow(muestra_df)
    val$validaciones      <- NULL
    val$pos_actual        <- 1L
    showNotification(
      paste0("✔ Evaluación '", nombre_eval, "' — ", nrow(muestra_df), " GEs (", desglose, ")."),
      type = "message")
  }, error = function(e) {
    showNotification(paste("Error guardando evaluación:", e$message), type = "error")
  })
}

# ── Iniciar como juez (carga o crea respuestas para este juez) ───────────────
observeEvent(input$val_iniciar_como_juez, {
  req(val$muestra, val$evaluacion_nombre)
  nombre_juez <- trimws(input$val_nombre_juez)
  if (nchar(nombre_juez) == 0) {
    showNotification("Introduce el nombre del juez.", type = "error"); return()
  }
  nombre_juez <- gsub("[^a-zA-Z0-9_-]", "_", nombre_juez)
  
  path_juez <- file.path(lasp_val_jueces,
    paste0(val$evaluacion_nombre, "_", nombre_juez, ".rds"))
  
  if (file.exists(path_juez)) {
    tryCatch({
      obj <- readRDS(path_juez)
      val$validaciones <- obj$validaciones
      val$pos_actual   <- min(obj$pos_actual, nrow(val$muestra))
      n_hecho <- sum(!is.na(val$validaciones$emocion_juez))
      showNotification(
        paste0("Continuando evaluación de ", nombre_juez, " (", n_hecho, "/",
               nrow(val$validaciones), " ya evaluados)."),
        type = "message")
    }, error = function(e) {
      showNotification(paste("Error cargando respuestas del juez:", e$message), type = "error")
    })
  } else {
    val$validaciones <- data.frame(
      muestra_idx  = seq_len(nrow(val$muestra)),
      juez         = rep(nombre_juez, nrow(val$muestra)),
      emocion_juez = rep(NA_character_, nrow(val$muestra)),
      likert       = rep(NA_integer_,   nrow(val$muestra)),
      stringsAsFactors = FALSE
    )
    val$pos_actual <- 1L
    showNotification(
      paste0("Juez '", nombre_juez, "' iniciado en evaluación '",
             val$evaluacion_nombre, "' (", nrow(val$muestra), " GEs)."),
      type = "message")
  }
})

# ── Selector de jueces existentes para la evaluaci\u00f3n cargada \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
output$val_jueces_existentes_ui <- renderUI({
  if (is.null(val$evaluacion_nombre)) {
    return(helpText(icon("info-circle"), " Carga o crea una evaluaci\u00f3n primero."))
  }
  patron <- paste0("^", val$evaluacion_nombre, "_.*\\.rds$")
  archivos <- list.files(lasp_val_jueces, pattern = patron)
  if (length(archivos) == 0) {
    return(helpText(icon("user-plus"), " A\u00fan no hay jueces. Escribe un nombre y pulsa Iniciar."))
  }
  nombres_jueces <- gsub(paste0("^", val$evaluacion_nombre, "_|\\.rds$"), "", archivos)
  labels <- sapply(nombres_jueces, function(nm) {
    path <- file.path(lasp_val_jueces, paste0(val$evaluacion_nombre, "_", nm, ".rds"))
    tryCatch({
      obj <- readRDS(path)
      n_total <- nrow(obj$validaciones)
      n_hecho <- sum(!is.na(obj$validaciones$emocion_juez))
      pct <- round(n_hecho / n_total * 100)
      icon_e <- if (n_hecho == n_total) "\u2714\ufe0f" else "\u23f3"
      paste0(icon_e, " ", nm, "  (", n_hecho, "/", n_total, " \u2014 ", pct, "%)")
    }, error = function(e) nm)
  })
  tagList(
    tags$label("Jueces existentes \u2014 haz clic para seleccionar:", class = "control-label",
               style = "font-size:12px; color:#555;"),
    tags$div(style = "background:#f0f4ff; border-radius:6px; padding:6px 10px; margin-bottom:6px;",
      lapply(seq_along(nombres_jueces), function(i) {
        nm <- nombres_jueces[i]
        tags$div(style = "margin:2px 0;",
          tags$a(href = "#", style = "font-size:13px; color:#0066cc; text-decoration:none;",
            onclick = paste0("Shiny.setInputValue('val_seleccionar_juez', '", nm, "', {priority:'event'}); return false;"),
            labels[i]
          )
        )
      })
    )
  )
})

