# ── Audio ─────────────────────────────────────────────────────────────────────
observeEvent(input$val_play_audio, {
  req(val$muestra, val$pos_actual <= nrow(val$muestra))
  m <- val$muestra[val$pos_actual, ]

  wav_path <- buscar_wav(m$filename)
  if (is.null(wav_path)) {
    showNotification("Audio no disponible.", type = "warning")
    return()
  }

  t_ini <- max(0, m$inicio - 0.1)
  t_end <- m$fin + 0.1
  b64   <- generar_audio_b64(wav_path, t_ini, t_end)

  if (is.null(b64)) {
    showNotification("Error generando audio.", type = "warning")
    return()
  }

  output$val_audio_player <- renderUI({
    tags$audio(
      src      = paste0("data:audio/wav;base64,", b64),
      type     = "audio/wav",
      controls = TRUE,
      autoplay = TRUE,
      style    = "width: 100%; margin-top: 5px;"
    )
  })
})

