# ── Descarga manual ───────────────────────────────────────────────────────────
output$val_descargar_rds <- downloadHandler(
  filename = function() {
    nombre_juez <- gsub("[^a-zA-Z0-9_-]", "_", trimws(input$val_nombre_juez))
    paste0(val$evaluacion_nombre, "_", nombre_juez, ".rds")
  },
  content = function(file) {
    req(val$validaciones, val$muestra, val$evaluacion_nombre)
    nombre_juez <- gsub("[^a-zA-Z0-9_-]", "_", trimws(input$val_nombre_juez))
    obj <- list(
      muestra           = val$muestra,
      validaciones      = val$validaciones,
      pos_actual        = val$pos_actual,
      juez              = nombre_juez,
      evaluacion_nombre = val$evaluacion_nombre,
      timestamp         = Sys.time()
    )
    # Guardar también en carpeta local
    path_juez <- file.path(lasp_val_jueces,
      paste0(val$evaluacion_nombre, "_", nombre_juez, ".rds"))
    tryCatch(saveRDS(obj, path_juez), error = function(e) NULL)
    saveRDS(obj, file)
  }
)
  
  # ========================================
  # METADATOS
  # ========================================
  
  output$meta_selector_archivo <- renderUI({
    req(datos$calculado)
    fns <- c()
    if (!is.null(datos$phones)) fns <- unique(datos$phones$filename)
    else if (!is.null(datos$ips_resumen)) fns <- unique(datos$ips_resumen$filename)
    selectInput("meta_archivo_sel", "Archivo:", choices = sort(fns))
  })
  
  output$meta_selector_hablante <- renderUI({
    req(datos$calculado)
    habs <- c()
    if (!is.null(datos$phones)) habs <- unique(datos$phones$hablante)
    else if (!is.null(datos$ips_resumen)) habs <- unique(datos$ips_resumen$hablante)
    selectInput("meta_hablante_sel", "Hablante:", choices = sort(habs))
  })
  
  observeEvent(input$meta_guardar_archivo, {
    req(input$meta_archivo_sel)
    fn <- input$meta_archivo_sel
    new_row <- data.frame(filename = fn, genero = input$meta_genero, pais = input$meta_pais,
                          ciudad = input$meta_ciudad, duracion_archivo = input$meta_duracion_archivo,
                          n_hablantes = input$meta_n_hablantes, contexto = input$meta_contexto,
                          notas = input$meta_notas_archivo, stringsAsFactors = FALSE)
    existing <- metadatos$archivos
    if (fn %in% existing$filename) {
      existing <- existing[existing$filename != fn, ]
    }
    metadatos$archivos <- rbind(existing, new_row)
    
    # Propagar género a dataframes
    for (dfname in c("phones", "words", "ips_resumen", "gfs_resumen")) {
      df <- datos[[dfname]]
      if (!is.null(df) && "filename" %in% colnames(df)) {
        if (!"genero" %in% colnames(df)) df$genero <- NA_character_
        df$genero[df$filename == fn] <- input$meta_genero
        datos[[dfname]] <- df
      }
    }
    showNotification(paste0("Metadatos guardados para: ", fn), type = "message")
  })
  
  observeEvent(input$meta_guardar_hablante, {
    req(input$meta_hablante_sel)
    hab <- input$meta_hablante_sel
    new_row <- data.frame(hablante = hab, edad = input$meta_edad, sexo = input$meta_sexo,
                          nivel = input$meta_nivel, profesion = input$meta_profesion,
                          l1 = input$meta_l1, origen = input$meta_origen,
                          edad_adq = input$meta_edad_adq, notas = input$meta_notas_hablante,
                          stringsAsFactors = FALSE)
    existing <- metadatos$hablantes
    if (hab %in% existing$hablante) {
      existing <- existing[existing$hablante != hab, ]
    }
    metadatos$hablantes <- rbind(existing, new_row)
    
    # Propagar a dataframes
    for (dfname in c("phones", "words", "ips_resumen", "gfs_resumen")) {
      df <- datos[[dfname]]
      if (!is.null(df) && "hablante" %in% colnames(df)) {
        for (col in c("edad", "sexo", "nivel", "l1", "origen")) {
          if (!col %in% colnames(df)) df[[col]] <- NA
          df[[col]][df$hablante == hab] <- new_row[[col]]
        }
        datos[[dfname]] <- df
      }
    }
    showNotification(paste0("Metadatos guardados para: ", hab), type = "message")
  })
  
  output$meta_tabla_archivos <- renderDT({
    req(nrow(metadatos$archivos) > 0)
    datatable(metadatos$archivos, options = list(scrollX = TRUE, pageLength = 5), rownames = FALSE)
  })
  
  output$meta_tabla_hablantes <- renderDT({
    req(nrow(metadatos$hablantes) > 0)
    datatable(metadatos$hablantes, options = list(scrollX = TRUE, pageLength = 5), rownames = FALSE)
  })
  
  # Importar/Exportar metadatos
  observeEvent(input$meta_importar_archivos, {
    req(input$meta_importar_archivos)
    df <- tryCatch(read.csv(input$meta_importar_archivos$datapath, stringsAsFactors = FALSE), error = function(e) NULL)
    if (!is.null(df) && "filename" %in% colnames(df)) {
      metadatos$archivos <- df
      showNotification("Metadatos de archivos importados", type = "message")
    }
  })
  
  observeEvent(input$meta_importar_hablantes, {
    req(input$meta_importar_hablantes)
    df <- tryCatch(read.csv(input$meta_importar_hablantes$datapath, stringsAsFactors = FALSE), error = function(e) NULL)
    if (!is.null(df) && "hablante" %in% colnames(df)) {
      metadatos$hablantes <- df
      showNotification("Metadatos de hablantes importados", type = "message")
    }
  })
  
  observeEvent(input$meta_importar_rds, {
    req(input$meta_importar_rds)
    obj <- tryCatch(readRDS(input$meta_importar_rds$datapath), error = function(e) NULL)
    if (!is.null(obj) && "archivos" %in% names(obj)) {
      metadatos$archivos <- obj$archivos
      metadatos$hablantes <- obj$hablantes
      showNotification("Metadatos completos importados", type = "message")
    }
  })
  
  output$meta_exportar_archivos <- downloadHandler(
    filename = function() paste0("metadatos_archivos_", Sys.Date(), ".csv"),
    content = function(file) write.csv(metadatos$archivos, file, row.names = FALSE)
  )
  output$meta_exportar_hablantes <- downloadHandler(
    filename = function() paste0("metadatos_hablantes_", Sys.Date(), ".csv"),
    content = function(file) write.csv(metadatos$hablantes, file, row.names = FALSE)
  )
  output$meta_exportar_rds <- downloadHandler(
    filename = function() paste0("metadatos_", Sys.Date(), ".rds"),
    content = function(file) saveRDS(list(archivos = metadatos$archivos, hablantes = metadatos$hablantes), file)
  )
  
  # ========================================
  # CONSENSO INTER-JUECES
  # ========================================
  
  observeEvent(input$cons_archivos_jueces, {
    req(input$cons_archivos_jueces)
    files <- input$cons_archivos_jueces
    jueces <- list()
    for (i in seq_len(nrow(files))) {
      tryCatch({
        obj <- readRDS(files$datapath[i])
        if ("validaciones" %in% names(obj)) {
          nombre <- if (!is.null(obj$juez)) obj$juez else paste0("Juez_", i)
          jueces[[nombre]] <- obj$validaciones
        }
      }, error = function(e) NULL)
    }
    consenso$jueces_data <- jueces
    showNotification(paste0("Cargados ", length(jueces), " jueces: ", paste(names(jueces), collapse = ", ")), type = "message")
  })
  
  observeEvent(input$cons_etiquetado_original, {
    req(input$cons_etiquetado_original)
    tryCatch({
      obj <- readRDS(input$cons_etiquetado_original$datapath)
      if ("anotaciones" %in% names(obj)) consenso$etiquetado_orig <- obj
      showNotification("Etiquetado original cargado", type = "message")
    }, error = function(e) showNotification(paste("Error:", e$message), type = "error"))
  })
  
  observeEvent(input$cons_calcular, {
    req(length(consenso$jueces_data) >= 1)
    
    jueces <- consenso$jueces_data
    nombres_jueces <- names(jueces)
    
    # Construir matriz: filas = muestra_idx, columnas = jueces
    # Usar muestra_idx (sistema nuevo) con fallback a acto_id (sistema antiguo)
    get_id_col <- function(df) {
      if ("muestra_idx" %in% colnames(df)) return("muestra_idx")
      if ("acto_id"    %in% colnames(df)) return("acto_id")
      return(NULL)
    }
    
    all_ids <- unique(unlist(lapply(jueces, function(j) {
      col <- get_id_col(j)
      if (is.null(col)) seq_len(nrow(j)) else j[[col]]
    })))
    all_ids <- sort(all_ids[!is.na(all_ids)])
    
    mat <- data.frame(ge_id = all_ids, stringsAsFactors = FALSE)
    
    # Informacion de cada GE (texto, emocion_original) desde evaluacion_base si disponible
    if (!is.null(consenso$evaluacion_base)) {
      base <- consenso$evaluacion_base
      base_map_texto  <- setNames(base$palabras_grupo,   base$muestra_idx)
      base_map_emorig <- setNames(base$emocion_original, base$muestra_idx)
      mat$texto          <- base_map_texto[as.character(all_ids)]
      mat$emocion_invest <- base_map_emorig[as.character(all_ids)]
    }
    
    for (nm in nombres_jueces) {
      j <- jueces[[nm]]
      col <- get_id_col(j)
      ids_j <- if (is.null(col)) seq_len(nrow(j)) else j[[col]]
      emo_map <- setNames(j$emocion_juez, ids_j)
      mat[[nm]] <- emo_map[as.character(all_ids)]
    }
    
    # Investigador desde etiquetado importado manualmente (opcional, complementa base)
    if (!is.null(consenso$etiquetado_orig)) {
      anot <- consenso$etiquetado_orig$anotaciones
      col_id <- if ("muestra_idx" %in% colnames(anot)) "muestra_idx"
                else if ("acto_id" %in% colnames(anot)) "acto_id" else NULL
      if (!is.null(col_id)) {
        anot_u <- anot[!duplicated(anot[[col_id]]) & !is.na(anot[[col_id]]), ]
        emo_inv <- setNames(anot_u$emocion_manual, anot_u[[col_id]])
        mat[["Investigador"]] <- emo_inv[as.character(all_ids)]
        nombres_jueces <- c("Investigador", nombres_jueces)
      }
    } else if (!is.null(mat$emocion_invest)) {
      # Usar emocion_original de la evaluacion_base como referencia del investigador
      mat[["Investigador"]] <- mat$emocion_invest
      nombres_jueces <- c("Investigador", nombres_jueces)
    }
    
    # Estadisticas de completitud
    completitud <- sapply(nombres_jueces, function(nm) {
      vals <- mat[[nm]]
      n_eval <- sum(!is.na(vals))
      paste0(n_eval, "/", length(vals))
    })
    
    resultados <- list()
    resultados$n_ges      <- length(all_ids)
    resultados$n_jueces   <- length(nombres_jueces)
    resultados$nombres    <- nombres_jueces
    resultados$completitud <- completitud
    resultados$matriz     <- mat
    
    # Cohen's kappa por pares (solo GEs evaluados por AMBOS)
    kappas <- data.frame()
    if (length(nombres_jueces) >= 2 && requireNamespace("irr", quietly = TRUE)) {
      for (i in 1:(length(nombres_jueces) - 1)) {
        for (j_ in (i + 1):length(nombres_jueces)) {
          nm_i <- nombres_jueces[i]; nm_j <- nombres_jueces[j_]
          if (!nm_i %in% colnames(mat) || !nm_j %in% colnames(mat)) next
          datos_par <- mat[, c(nm_i, nm_j), drop = FALSE]
          datos_par <- datos_par[complete.cases(datos_par), ]
          if (nrow(datos_par) >= 5) {
            tryCatch({
              k <- irr::kappa2(datos_par)
              kappas <- rbind(kappas, data.frame(
                Juez_1 = nm_i, Juez_2 = nm_j,
                Kappa = round(k$value, 3), p_valor = round(k$p.value, 4),
                N_comun = nrow(datos_par), stringsAsFactors = FALSE))
            }, error = function(e) NULL)
          }
        }
      }
    }
    resultados$kappas <- kappas
    
    # Fleiss kappa: solo filas completas para todos los jueces
    if (length(nombres_jueces) >= 3 && requireNamespace("irr", quietly = TRUE)) {
      mat_j <- mat[, nombres_jueces, drop = FALSE]
      mat_complete <- mat_j[complete.cases(mat_j), ]
      resultados$n_completos <- nrow(mat_complete)
      if (nrow(mat_complete) >= 5) {
        tryCatch({
          fk <- irr::kappam.fleiss(mat_complete)
          resultados$fleiss_kappa <- round(fk$value, 3)
          resultados$fleiss_p <- round(fk$p.value, 4)
        }, error = function(e) { resultados$fleiss_kappa <- NA })
      }
    }
    
    # Krippendorff alpha: maneja NAs nativamente
    if (requireNamespace("irr", quietly = TRUE) && length(nombres_jueces) >= 2) {
      mat_j <- mat[, nombres_jueces, drop = FALSE]
      mat_t <- t(as.matrix(mat_j))
      tryCatch({
        ka <- irr::kripp.alpha(mat_t, method = "nominal")
        resultados$kripp_alpha <- round(ka$value, 3)
      }, error = function(e) { resultados$kripp_alpha <- NA })
    }
    
    # Acuerdo por GE: incluye TODOS los GEs con al menos 2 evaluaciones
    acuerdo_ges <- data.frame()
    mat_j <- mat[, nombres_jueces, drop = FALSE]
    for (r in seq_len(nrow(mat_j))) {
      vals <- unlist(mat_j[r, ])
      vals <- vals[!is.na(vals)]
      if (length(vals) >= 2) {
        tab <- table(vals)
        texto_ge <- if (!is.null(mat$texto)) mat$texto[r] else NA
        emo_inv  <- if ("Investigador" %in% nombres_jueces) mat[["Investigador"]][r] else NA
        acuerdo_ges <- rbind(acuerdo_ges, data.frame(
          ge_id          = mat$ge_id[r],
          texto          = if (!is.na(texto_ge)) substr(texto_ge, 1, 40) else "",
          emocion_invest = emo_inv,
          emocion_moda   = names(tab)[which.max(tab)],
          n_evaluado     = length(vals),
          n_acuerdo      = max(tab),
          pct_acuerdo    = round(max(tab) / length(vals) * 100, 1),
          pendiente      = (length(vals) < length(nombres_jueces)),
          stringsAsFactors = FALSE
        ))
      }
    }
    resultados$acuerdo_por_acto <- acuerdo_ges
    
    consenso$resultados <- resultados
    n_eval <- nrow(acuerdo_ges)
    n_pend <- if (nrow(acuerdo_ges) > 0) sum(acuerdo_ges$pendiente) else 0
    showNotification(
      paste0("Acuerdo calculado: ", n_eval, " GEs con >=2 evaluaciones (",
             n_pend, " aun incompletos)"),
      type = "message", duration = 6)
  })
  
  output$cons_resumen_acuerdo <- renderUI({
    req(consenso$resultados)
    r <- consenso$resultados
    
    # Tabla de completitud por juez
    comp_rows <- lapply(names(r$completitud), function(nm) {
      tags$tr(tags$td(nm), tags$td(r$completitud[[nm]]))
    })
    
    items <- list(
      tags$h5("Completitud por evaluador"),
      tags$div(style = "overflow-x:auto;",
        tags$table(class = "table table-sm table-bordered", style = "font-size:13px; width:auto;",
          tags$thead(tags$tr(tags$th("Evaluador"), tags$th("Evaluados/Total"))),
          tags$tbody(comp_rows)
        )
      ),
      tags$p(tags$strong("GEs con >=2 evaluaciones: "), r$n_actos,
             if (!is.null(r$n_completos)) paste0(" | GEs completos (todos los jueces): ", r$n_completos) else "")
    )
    
    if (nrow(r$kappas) > 0) {
      items <- c(items, list(
        tags$h5("Cohen's kappa (por pares)"),
        tags$div(style = "overflow-x: auto;",
          tags$table(class = "table table-sm table-bordered", style = "font-size: 13px;",
            tags$thead(tags$tr(tags$th("Juez 1"), tags$th("Juez 2"), tags$th("κ"), tags$th("p"), tags$th("N"))),
            tags$tbody(
              lapply(1:nrow(r$kappas), function(i) {
                k <- r$kappas[i, ]
                interp <- if (k$Kappa >= 0.81) "Casi perfecto"
                          else if (k$Kappa >= 0.61) "Sustancial"
                          else if (k$Kappa >= 0.41) "Moderado"
                          else if (k$Kappa >= 0.21) "Débil"
                          else "Pobre"
                tags$tr(tags$td(k$Juez_1), tags$td(k$Juez_2),
                        tags$td(paste0(k$Kappa, " (", interp, ")")),
                        tags$td(k$p_valor), tags$td(k$N))
              })
            )
          )
        )
      ))
    }
    
    if (!is.null(r$fleiss_kappa) && !is.na(r$fleiss_kappa)) {
      items <- c(items, list(tags$p(tags$strong("Fleiss' κ (global): "), r$fleiss_kappa, " (p=", r$fleiss_p, ")")))
    }
    if (!is.null(r$kripp_alpha) && !is.na(r$kripp_alpha)) {
      items <- c(items, list(tags$p(tags$strong("Krippendorff's α: "), r$kripp_alpha)))
    }
    
    tagList(items)
  })
  
  output$cons_plot_acuerdo_emocion <- renderPlot({
    req(consenso$resultados, consenso$resultados$acuerdo_por_acto)
    adf <- consenso$resultados$acuerdo_por_acto
    if (nrow(adf) == 0) return(NULL)
    
    resumen <- aggregate(pct_acuerdo ~ emocion_moda, data = adf, FUN = mean)
    colnames(resumen) <- c("emocion", "acuerdo_medio")
    resumen$n <- as.numeric(table(adf$emocion_moda)[resumen$emocion])
    resumen <- resumen[order(-resumen$acuerdo_medio), ]
    
    ggplot(resumen, aes(x = reorder(emocion, acuerdo_medio), y = acuerdo_medio, fill = emocion)) +
      geom_col(width = 0.7) +
      geom_text(aes(label = paste0(round(acuerdo_medio, 1), "% (n=", n, ")")), hjust = -0.1, size = 3.5) +
      coord_flip() + theme_minimal(base_size = 13) +
      scale_y_continuous(limits = c(0, 110)) +
      labs(title = "Acuerdo medio por emoción", x = "", y = "% acuerdo") +
      theme(legend.position = "none")
  })
  
  output$cons_matrices_confusion <- renderUI({ NULL })  # Placeholder, expandable
  
  output$cons_tabla_consenso <- renderDT({
    req(consenso$resultados)
    adf <- consenso$resultados$acuerdo_por_acto
    if (nrow(adf) == 0) return(datatable(adf))
    # Formatear columna pendiente
    adf$estado <- ifelse(adf$pendiente, "⏳ Incompleto", "✔ Completo")
    cols_show <- intersect(c("ge_id", "texto", "emocion_invest", "emocion_moda",
                              "n_evaluado", "pct_acuerdo", "estado"), colnames(adf))
    datatable(
      adf[, cols_show, drop = FALSE],
      options = list(scrollX = TRUE, pageLength = 20),
      rownames = FALSE,
      filter = "top"
    ) |> formatStyle(
      "estado",
      backgroundColor = styleEqual(
        c("⏳ Incompleto", "✔ Completo"),
        c("#fff8e1", "#f0fff4")
      )
    ) |> formatStyle(
      "pct_acuerdo",
      background = styleColorBar(c(0, 100), "#90caf9"),
      backgroundSize = "100% 80%",
      backgroundRepeat = "no-repeat",
      backgroundPosition = "center"
    )
  })
  
  # Generar consenso final
  observeEvent(input$cons_generar_consenso, {
    req(consenso$resultados)
    adf <- consenso$resultados$acuerdo_por_acto
    metodo <- input$cons_metodo_consenso
    
    if (metodo == "mayoria") {
      adf$emocion_consenso <- adf$emocion_moda
      adf$validado <- TRUE
    } else {
      umbral <- if (metodo == "umbral60") 60 else 75
      adf$emocion_consenso <- ifelse(adf$pct_acuerdo >= umbral, adf$emocion_moda, NA)
      adf$validado <- adf$pct_acuerdo >= umbral
    }
    
    consenso$consenso_final <- adf
    n_val <- sum(adf$validado)
    showNotification(paste0("Consenso generado: ", n_val, "/", nrow(adf), " actos validados"), type = "message")
  })
  
  output$cons_descargar_rds <- downloadHandler(
    filename = function() paste0("consenso_jueces_", Sys.Date(), ".rds"),
    content = function(file) {
      saveRDS(list(
        resultados = consenso$resultados,
        consenso_final = consenso$consenso_final,
        timestamp = Sys.time()
      ), file)
    }
  )
  
  output$cons_exportar_csv <- downloadHandler(
    filename = function() paste0("consenso_jueces_", Sys.Date(), ".csv"),
    content = function(file) {
      req(consenso$consenso_final)
      write.csv(consenso$consenso_final, file, row.names = FALSE)
    }
  )

  # En SERVER, nuevos outputs:
output$cons_selector_evaluacion_carpeta <- renderUI({
  evals <- tools::file_path_sans_ext(
    list.files(lasp_val_evaluaciones, pattern = "\\.rds$"))
  if (length(evals) == 0) return(helpText("No hay evaluaciones guardadas."))
  selectInput("cons_eval_carpeta", "Evaluación:", choices = evals)
})

output$cons_jueces_disponibles <- renderUI({
  req(input$cons_eval_carpeta)
  patron <- paste0("^", input$cons_eval_carpeta, "_.*\\.rds$")
  archivos <- list.files(lasp_val_jueces, pattern = patron)
  if (length(archivos) == 0) return(helpText("No hay jueces para esta evaluación."))
  jueces <- gsub(paste0("^", input$cons_eval_carpeta, "_|\\.rds$"), "", archivos)
  checkboxGroupInput("cons_jueces_sel", "Jueces disponibles:", choices = jueces, selected = jueces)
})

observeEvent(input$cons_cargar_desde_carpeta, {
  req(input$cons_eval_carpeta)
  jueces_sel <- input$cons_jueces_sel
  if (is.null(jueces_sel) || length(jueces_sel) == 0) {
    showNotification("Selecciona al menos un juez.", type = "warning"); return()
  }
  jueces <- list()
  for (nm in jueces_sel) {
    path <- file.path(lasp_val_jueces,
      paste0(input$cons_eval_carpeta, "_", nm, ".rds"))
    tryCatch({
      obj <- readRDS(path)
      if ("validaciones" %in% names(obj)) {
        jueces[[nm]] <- obj$validaciones
      }
    }, error = function(e) NULL)
  }
  if (length(jueces) == 0) {
    showNotification("No se pudo cargar ningun archivo de juez.", type = "error"); return()
  }
  # Cargar tambien la evaluacion base para tener emocion_original del investigador
  path_eval <- file.path(lasp_val_evaluaciones, paste0(input$cons_eval_carpeta, ".rds"))
  if (file.exists(path_eval)) {
    tryCatch({
      obj_eval <- readRDS(path_eval)
      consenso$evaluacion_base <- obj_eval$muestra  # muestra con emocion_original
    }, error = function(e) NULL)
  }
  consenso$jueces_data <- jueces
  n_total <- if (!is.null(jueces[[1]])) nrow(jueces[[1]]) else "?"
  pendientes <- sapply(jueces, function(j) sum(is.na(j$emocion_juez)))
  msg <- paste0(length(jueces), " juez/ces cargados (", n_total, " GEs). ",
    "Pendientes: ", paste(names(pendientes), pendientes, sep="=", collapse=", "))
  showNotification(msg, type = "message", duration = 8)
})
  
  # ========================================
  # GENERAR INFORME
  # ========================================
  
  informe <- reactiveValues(
    html_content = NULL,
    graficos_paths = list(),
    informe_dir = NULL,
    ejemplos_ids = character(0)  # IDs de GEs usados en los ejemplos (para ZIP de clips)
  )
  
  # Dataset reactivo según selección
  inf_data <- reactive({
    req(datos$calculado)
    df <- switch(input$inf_dataset,
      "ips" = datos$ips_resumen,
      "gfs" = datos$gfs_resumen,
      "phones" = datos$phones,
      "words" = datos$words,
      "actos" = {
        # Use shared function or cached version
        if (!is.null(datos$actos_resumen)) datos$actos_resumen
        else construir_actos_resumen()
      },
      datos$ips_resumen
    )
    
    # Corregir semitones aquí, garantizando que cualquier dato (nuevo o cargado
    # de disco con ref=100) salga ya corregido antes de llegar al informe
    if (!is.null(df) && nrow(df) > 0) {
      df <- corregir_semitones_si_necesario(df)
    }
    
  # Excluir tier anonimizar
  if ("hablante" %in% colnames(df)) {
    df <- df[tolower(trimws(df$hablante)) != "anonimizar", ]
  }
    # Compute velocidad_habla on-the-fly if missing (for backward compat)
    if (!"velocidad_habla" %in% colnames(df) && 
        all(c("num_vocales", "duracion") %in% colnames(df))) {
      df$velocidad_habla <- ifelse(df$duracion > 0, df$num_vocales / df$duracion, NA_real_)
    }
    # Compute intensidad_media_grupo on-the-fly if missing (unify across datasets)
    if (!"intensidad_media_grupo" %in% colnames(df)) {
      if ("int_media" %in% colnames(df)) df$intensidad_media_grupo <- df$int_media
      else if ("intensidad_media_gf" %in% colnames(df)) df$intensidad_media_grupo <- df$intensidad_media_gf
      else if ("intensidad_media" %in% colnames(df)) df$intensidad_media_grupo <- df$intensidad_media
    }
    # Compute transicion_media on-the-fly from phones if missing
    if (!"transicion_media" %in% colnames(df) && !is.null(datos$phones) && 
        "tiempo_transicion_anterior" %in% colnames(datos$phones)) {
      # Match by id_ge or by filename+hablante+grupo_fonico+grupo_entonativo
      phones <- datos$phones
      if ("id_grupo" %in% colnames(phones)) {
        trans_agg <- aggregate(phones$tiempo_transicion_anterior, 
                               by = list(id_grupo = phones$id_grupo), FUN = mean, na.rm = TRUE)
        colnames(trans_agg) <- c("id_grupo", "transicion_media")
        if ("id_ge" %in% colnames(df)) {
          df <- merge(df, trans_agg, by.x = "id_ge", by.y = "id_grupo", all.x = TRUE, sort = FALSE)
        }
      }
    }
    df
  })
  
  # Filtro de género discursivo
  output$inf_filtro_genero <- renderUI({
    df <- inf_data()
    req(df)
    if (!"genero" %in% colnames(df)) return(NULL)
    gens <- sort(unique(na.omit(df$genero)))
    if (length(gens) == 0) return(NULL)
    checkboxGroupInput("inf_generos", "Géneros discursivos:", choices = gens, selected = gens, inline = TRUE)
  })
  
  # Forzar actualización del checkbox de géneros cuando cambian los datos cargados
  # (Shiny puede mantener el valor previo del input aunque el renderUI lo recree)
  observe({
    req(datos$calculado)
    df <- inf_data()
    req(df, "genero" %in% colnames(df))
    gens <- sort(unique(na.omit(df$genero[df$genero != ""])))
    if (length(gens) > 0) {
      updateCheckboxGroupInput(session, "inf_generos", choices = gens, selected = gens)
    }
  })
  
  # Filtro de hablante — selectInput multiple for scalability
  output$inf_filtro_hablante <- renderUI({
    df <- inf_data()
    req(df, "hablante" %in% colnames(df))
    habs <- sort(unique(df$hablante))
    if (length(habs) <= 1) return(NULL)
    selectInput("inf_hablantes", "Hablantes:", choices = habs, selected = habs, multiple = TRUE,
                selectize = TRUE)
  })
  
  # Filtro de filename — selectInput multiple for scalability (up to 300 files)
  output$inf_filtro_filename <- renderUI({
    df <- inf_data()
    req(df, "filename" %in% colnames(df))
    fns <- sort(unique(df$filename))
    if (length(fns) <= 1) return(NULL)
    selectInput("inf_filenames", paste0("Archivos (", length(fns), " disponibles):"),
                choices = fns, selected = fns, multiple = TRUE, selectize = TRUE)
  })
  
  # Variables numéricas — collapsible with better defaults
  output$inf_sel_vars_num <- renderUI({
    df <- inf_data()
    req(df)
    cols_num <- names(df)[sapply(df, is.numeric)]
    # Excluir IDs y columnas técnicas
    excluir <- c("grupo_fonico", "grupo_entonativo", "palabra_idx", "posicion_en_grupo",
                 "total_vocales_grupo", "distancia_a_final", "vocales_hasta_fin_ge")
    cols_num <- setdiff(cols_num, excluir)
    # Defaults según especificación: Duración, Intensidad, Rango F0, inflexion_pct, transicion_media, velocidad
    presel <- intersect(c("duracion", "duracion_grupo", "dur_grupo", "dur_ge", "duration",
                          "int_media", "intensidad_media_grupo",
                          "rango_f0_grupo_st", "f0_rango_st",
                          "inflexion_final_pct", "inflexion_pct",
                          "transicion_media", "tiempo_transicion_anterior",
                          "velocidad_habla"), cols_num)
    if (length(presel) == 0) presel <- head(cols_num, 5)
    checkboxGroupInput("inf_vars_num", NULL, choices = cols_num, selected = presel)
  })
  
  # Select all / deselect all variables
  observeEvent(input$inf_vars_select_all, {
    df <- inf_data()
    req(df)
    cols_num <- names(df)[sapply(df, is.numeric)]
    excluir <- c("grupo_fonico", "grupo_entonativo", "palabra_idx", "posicion_en_grupo",
                 "total_vocales_grupo", "distancia_a_final", "vocales_hasta_fin_ge")
    cols_num <- setdiff(cols_num, excluir)
    updateCheckboxGroupInput(session, "inf_vars_num", selected = cols_num)
  })
  observeEvent(input$inf_vars_deselect_all, {
    updateCheckboxGroupInput(session, "inf_vars_num", selected = character(0))
  })
  
  # Update outlier factor default when method changes
  observeEvent(input$inf_outlier_metodo, {
    defaults <- c("iqr" = 1.5, "pct" = 5, "sd" = 2.5)
    new_val <- defaults[input$inf_outlier_metodo]
    if (!is.null(new_val)) updateNumericInput(session, "inf_outlier_factor", value = as.numeric(new_val))
  })
  
  # ==== FILTRO VARIABLE ====
  # Helper: get categorical columns from dataset
  inf_get_cat_cols <- reactive({
    df <- inf_data()
    req(df)
    cols_cat <- names(df)[sapply(df, function(x) is.character(x) || is.factor(x))]
    excluir <- c("id_ge", "id_gf", "id_grupo", "id_completo", "palabras_grupo", "palabras_gf",
                 "estructuras_vocales_ge", "clausula_global_id")
