    if ("sentimiento" %in% colnames(df)) emo_cols <- c(emo_cols, "sentimiento")
    if ("emocion_texto" %in% colnames(df)) emo_cols <- c(emo_cols, "emocion_texto")
    if ("emocion_audio" %in% colnames(df)) emo_cols <- c(emo_cols, "emocion_audio")
    if ("sent_label" %in% colnames(df)) emo_cols <- c(emo_cols, "sent_label")
    if ("emo_texto_label" %in% colnames(df)) emo_cols <- c(emo_cols, "emo_texto_label")
    if ("emo_audio_label" %in% colnames(df)) emo_cols <- c(emo_cols, "emo_audio_label")
    if (!"emocion_manual" %in% colnames(df) && !is.null(etiq$anotaciones) && 
        "emocion_manual" %in% colnames(etiq$anotaciones)) {
      emo_cols <- c(emo_cols, "emocion_manual (etiquetado)")
