  # Variable dependiente para regresión
  # Helper: get columns available for dependent variables (includes etiquetado)
  inf_get_dep_cols <- function(tipo = "all") {
    df <- inf_data()
    req(df)
    if (tipo == "num") {
      cols <- names(df)[sapply(df, is.numeric)]
    } else {
      cols <- names(df)[sapply(df, function(x) is.numeric(x) || is.character(x) || is.factor(x))]
    }
    # Add emocion_manual from etiquetado if not already present
    if (!"emocion_manual" %in% cols) {
      if (!is.null(etiq$anotaciones) && "emocion_manual" %in% colnames(etiq$anotaciones)) {
        cols <- c("emocion_manual", cols)
      }
    }
    # Add sentiment/emotion columns if available in etiquetado
    for (ecol in c("sent_label", "emo_texto_label", "emo_audio_label")) {
      if (!ecol %in% cols && !is.null(etiq$anotaciones) && ecol %in% colnames(etiq$anotaciones)) {
        cols <- c(ecol, cols)
      }
    }
    cols
  }
  
  # Determine current grouping variable for default selection
  inf_default_dep_var <- function(cols) {
    grp <- input$inf_var_grupo
    if (!is.null(grp) && grp != "ninguna") {
      grp_clean <- if (grp == "emocion_manual (etiquetado)") "emocion_manual" else grp
      if (grp_clean %in% cols) return(grp_clean)
    }
    cols[1]
  }
  
