  # Variable dependiente para árbol de decisión — default to grouping var
  output$inf_var_dependiente_tree <- renderUI({
    cols_all <- inf_get_dep_cols("all")
    sel <- inf_default_dep_var(cols_all)
    selectInput("inf_var_dep_tree", "Var. a predecir (Árbol):", choices = cols_all, selected = sel)
  })
  
  # Datos filtrados para el informe
  inf_data_filtrado <- reactive({
    df <- inf_data()
    req(df)
    
    # Merge emocion_manual from etiquetado if needed (for filter or group)
    needs_emo_manual <- FALSE
    if (!is.null(input$inf_var_filtro) && input$inf_var_filtro == "emocion_manual (etiquetado)") needs_emo_manual <- TRUE
    if (!is.null(input$inf_var_grupo) && any(input$inf_var_grupo == "emocion_manual (etiquetado)")) needs_emo_manual <- TRUE
    if (needs_emo_manual) {
      if (!"emocion_manual" %in% colnames(df) && !is.null(etiq$anotaciones) && 
          "emocion_manual" %in% colnames(etiq$anotaciones) && nrow(etiq$anotaciones) == nrow(df)) {
        df$emocion_manual <- etiq$anotaciones$emocion_manual
      }
    }
    
    # ---- Determinar variables de agrupación (necesario antes de los filtros base) ----
    vars_grupo_sel <- input$inf_var_grupo
    vars_grupo_sel <- if (!is.null(vars_grupo_sel)) vars_grupo_sel[vars_grupo_sel != "ninguna"] else character(0)
    # Resolver nombres reales para la comparación
    vars_grupo_real_names <- vapply(vars_grupo_sel, function(v) {
      if (v == "emocion_manual (etiquetado)") "emocion_manual" else v
    }, character(1), USE.NAMES = FALSE)
    
    # Filtrar por género discursivo
    # Solo filtrar si el usuario ha desmarcado explícitamente algún género:
    # si inf_generos contiene TODOS los géneros disponibles en los datos, no hace falta filtrar.
    # IMPORTANTE: NO aplicar este filtro si "genero" es variable de agrupación o filtro,
    # porque se filtrará mediante los checkboxes propios de agrupación/filtro.
    genero_gestionado <- "genero" %in% vars_grupo_real_names ||
      (!is.null(input$inf_var_filtro) && input$inf_var_filtro == "genero")
    if (!genero_gestionado && "genero" %in% colnames(df) && !is.null(input$inf_generos) && length(input$inf_generos) > 0) {
      gens_en_datos <- unique(na.omit(df$genero[df$genero != ""]))
      gens_desmarcados <- setdiff(gens_en_datos, input$inf_generos)
      if (length(gens_desmarcados) > 0) {
        # El usuario ha desmarcado géneros explícitamente: respetar su selección
        df <- df[!is.na(df$genero) & df$genero %in% input$inf_generos, ]
      }
      # Si no ha desmarcado nada (o si inf_generos tiene géneros que no están en datos), no filtrar
    }
    # Filtrar hablante — NO filtrar si hablante es variable de agrupación
    if (!"hablante" %in% vars_grupo_real_names &&
        "hablante" %in% colnames(df) && !is.null(input$inf_hablantes)) {
      df <- df[df$hablante %in% input$inf_hablantes, ]
    }
    # Filtrar filename — NO filtrar si filename es variable de agrupación
    if (!"filename" %in% vars_grupo_real_names &&
        "filename" %in% colnames(df) && !is.null(input$inf_filenames)) {
      df <- df[df$filename %in% input$inf_filenames, ]
    }
    
    # ---- Aplicar variable de FILTRO ----
    var_filtro <- input$inf_var_filtro
    if (!is.null(var_filtro) && var_filtro != "ninguna") {
      actual_filtro <- if (var_filtro == "emocion_manual (etiquetado)") "emocion_manual" else var_filtro
      if (actual_filtro %in% colnames(df) && !is.null(input$inf_valores_filtro)) {
        df <- df[!is.na(df[[actual_filtro]]) & df[[actual_filtro]] %in% input$inf_valores_filtro, ]
      }
    }
    
    # ---- Aplicar variable de AGRUPACIÓN (filtrar categorías seleccionadas) ----
    # vars_grupo_sel ya está definido arriba (antes de los filtros base)
    if (length(vars_grupo_sel) == 1) {
      actual_grupo <- if (vars_grupo_sel == "emocion_manual (etiquetado)") "emocion_manual" else vars_grupo_sel
      # Usar el ID dinámico correcto (inf_valores_grupo_VARNAME)
      vid_sg <- paste0("inf_valores_grupo_", gsub("[^a-zA-Z0-9]", "_", vars_grupo_sel))
      vals_sg <- input[[vid_sg]]
      if (actual_grupo %in% colnames(df) && !is.null(vals_sg)) {
        df <- df[!is.na(df[[actual_grupo]]) & df[[actual_grupo]] %in% vals_sg, ]
      }
    } else if (length(vars_grupo_sel) > 1) {
      # Multiple variables: excluir NAs/vacíos y filtrar por categorías seleccionadas
      for (i_vg in seq_along(vars_grupo_sel)) {
        vg_raw <- vars_grupo_sel[i_vg]
        actual_vg <- if (vg_raw == "emocion_manual (etiquetado)") "emocion_manual" else vg_raw
        if (actual_vg %in% colnames(df)) {
          df <- df[!is.na(df[[actual_vg]]) & trimws(as.character(df[[actual_vg]])) != "", ]
          # Filtrar por categorías seleccionadas en los checkboxes dinámicos
          vid_mg <- paste0("inf_valores_grupo_", gsub("[^a-zA-Z0-9]", "_", vg_raw))
          vals_mg <- input[[vid_mg]]
          if (!is.null(vals_mg) && length(vals_mg) > 0) {
            df <- df[df[[actual_vg]] %in% vals_mg, ]
          }
        }
      }
    }
    
    # Solo datos validados
    if (isTRUE(input$inf_solo_validados) && !is.null(consenso$consenso_final)) {
      actos_val <- consenso$consenso_final$acto_id[consenso$consenso_final$validado]
      if ("id_ge" %in% colnames(df) && !is.null(etiq$anotaciones)) {
        filas_val <- etiq$anotaciones$fila_ip[etiq$anotaciones$acto_id %in% actos_val]
        df <- df[seq_len(nrow(df)) %in% filas_val, ]
      }
    }
    # Filtrar outliers — applied to ALL selected numeric vars BEFORE report
    if (isTRUE(input$inf_filtrar_outliers) && !is.null(input$inf_vars_num)) {
      metodo <- if (!is.null(input$inf_outlier_metodo)) input$inf_outlier_metodo else "iqr"
      factor_val <- if (!is.null(input$inf_outlier_factor)) input$inf_outlier_factor else 1.5
      por_grupo <- isTRUE(input$inf_outlier_por_grupo)
      
      # Determine grouping for per-group filtering (supports multi-variable: use first valid)
      var_grupo_raw <- input$inf_var_grupo
      vars_grp_raw <- if (!is.null(var_grupo_raw)) var_grupo_raw[var_grupo_raw != "ninguna"] else character(0)
      grp_col <- NULL
      if (por_grupo && length(vars_grp_raw) > 0) {
        # Use first variable that exists in df for outlier filtering
        for (vg in vars_grp_raw) {
          cand <- if (vg == "emocion_manual (etiquetado)") "emocion_manual" else vg
          if (cand %in% colnames(df)) { grp_col <- cand; break }
        }
      }
      
      # Helper: get outlier mask for a numeric vector
      get_inlier_mask <- function(x) {
        valid <- !is.na(x)
        mask <- rep(TRUE, length(x))
        if (sum(valid) < 5) return(mask)
        
        if (metodo == "iqr") {
          q1 <- quantile(x[valid], 0.25)
          q3 <- quantile(x[valid], 0.75)
          iqr <- q3 - q1
          lower <- q1 - factor_val * iqr
          upper <- q3 + factor_val * iqr
          mask[valid] <- x[valid] >= lower & x[valid] <= upper
        } else if (metodo == "pct") {
          pct_low <- factor_val / 100  # factor_val used as percentile
          pct_high <- 1 - pct_low
          lower <- quantile(x[valid], pct_low)
          upper <- quantile(x[valid], pct_high)
          mask[valid] <- x[valid] >= lower & x[valid] <= upper
        } else {  # sd
          mu <- mean(x[valid])
          sd_v <- sd(x[valid])
          if (!is.na(sd_v) && sd_v > 0) {
            mask[valid] <- x[valid] >= (mu - factor_val * sd_v) & x[valid] <= (mu + factor_val * sd_v)
          }
        }
        mask
      }
      
      n_antes <- nrow(df)
      keep <- rep(TRUE, nrow(df))
      
      for (v in input$inf_vars_num) {
        if (!v %in% colnames(df) || !is.numeric(df[[v]])) next
        
        if (!is.null(grp_col)) {
          # Filter within each group separately
          for (g in unique(na.omit(df[[grp_col]]))) {
            idx_g <- which(!is.na(df[[grp_col]]) & df[[grp_col]] == g)
            if (length(idx_g) < 5) next
            mask_g <- get_inlier_mask(df[[v]][idx_g])
            keep[idx_g] <- keep[idx_g] & mask_g
          }
        } else {
          # Filter globally
          mask <- get_inlier_mask(df[[v]])
          keep <- keep & mask
        }
      }
      
      df <- df[keep, ]
    }
    df
  })
  
  # ---- GENERAR INFORME ----
  observeEvent(input$inf_generar, {
    req(datos$calculado)
    df <- inf_data_filtrado()
    if ("filename" %in% colnames(df) && "inicio" %in% colnames(df)) {
  df <- df[order(df$filename, df$inicio, na.last = TRUE), ]
  rownames(df) <- NULL  # resetear índices para que idx_fila sea coherente
}
    req(nrow(df) > 0)
    
    vars_num <- input$inf_vars_num
    # Resolve filter and group variables
    var_filtro_raw <- input$inf_var_filtro
    var_filtro <- if (!is.null(var_filtro_raw) && var_filtro_raw != "ninguna") {
      if (var_filtro_raw == "emocion_manual (etiquetado)") "emocion_manual" else var_filtro_raw
    } else NULL
    
    # ---- Variables de agrupación (ahora pueden ser múltiples) ----
    var_grupo_raw <- input$inf_var_grupo
    vars_grupo_raw <- if (!is.null(var_grupo_raw)) var_grupo_raw[var_grupo_raw != "ninguna"] else character(0)
    
    # Resolver nombres reales de cada variable de agrupación
    vars_grupo_real <- vapply(vars_grupo_raw, function(v) {
      if (v == "emocion_manual (etiquetado)") "emocion_manual" else v
    }, character(1))
    
    # Merging de emocion_manual si es necesaria
    for (vg in vars_grupo_real) {
      if (vg == "emocion_manual" && !vg %in% colnames(df) &&
          !is.null(etiq$anotaciones) && "emocion_manual" %in% colnames(etiq$anotaciones) &&
          nrow(etiq$anotaciones) == nrow(df)) {
        df$emocion_manual <- etiq$anotaciones$emocion_manual
      }
    }
    
    # Crear columna sintética combinada si hay más de una variable
    sep_grupo <- if (!is.null(input$inf_grupo_sep) && nchar(trimws(input$inf_grupo_sep)) > 0)
      input$inf_grupo_sep else " · "
    mostrar_marginals <- isTRUE(input$inf_mostrar_marginals)
    
    if (length(vars_grupo_real) > 1) {
      # Construir la columna combinada PRIMERO (antes de filtrar)
      cols_ok <- intersect(vars_grupo_real, colnames(df))
      if (length(cols_ok) >= 2) {
        df$grupo_combinado <- apply(df[, cols_ok, drop = FALSE], 1, function(row) {
          paste(row, collapse = sep_grupo)
        })
        var_cat <- "grupo_combinado"
        # Filtrar por valores seleccionados con máscara conjunta (AND entre variables,
        # no secuencial: evita eliminar categorías válidas de una variable por culpa de otra)
        mask <- rep(TRUE, nrow(df))
        for (i_gr in seq_along(vars_grupo_real)) {
          vg <- vars_grupo_real[i_gr]           # nombre real de columna
          vg_raw <- vars_grupo_raw[i_gr]        # nombre tal como aparece en input
          vid <- paste0("inf_valores_grupo_", gsub("[^a-zA-Z0-9]", "_", vg_raw))
          vals_sel <- input[[vid]]
          if (!is.null(vals_sel) && length(vals_sel) > 0 && vg %in% colnames(df)) {
            mask <- mask & (!is.na(df[[vg]]) & df[[vg]] %in% vals_sel)
          }
        }
        df <- df[mask, ]
        # Advertir si hay demasiadas combinaciones
        n_combis <- length(unique(na.omit(df$grupo_combinado)))
        if (n_combis > 20) {
          showNotification(
            paste0("⚠ ", n_combis, " combinaciones activas. ",
                   "Considera reducir variables o categorías seleccionadas."),
            type = "warning", duration = 10)
        }
      } else {
        var_cat <- if (length(cols_ok) == 1) cols_ok[1] else NULL
      }
      var_grupo <- var_cat
    } else if (length(vars_grupo_real) == 1) {
      var_grupo <- vars_grupo_real[1]
      # Filtrar por valores seleccionados
      vid <- paste0("inf_valores_grupo_", gsub("[^a-zA-Z0-9]", "_", vars_grupo_raw[1]))
      vals_sel <- input[[vid]]
      if (!is.null(vals_sel) && var_grupo %in% colnames(df)) {
        df <- df[!is.na(df[[var_grupo]]) & df[[var_grupo]] %in% vals_sel, ]
      }
      var_cat <- var_grupo
    } else {
      var_grupo <- NULL
      var_cat <- NULL
    }
    
    modo_comp <- if (!is.null(input$inf_modo_comparacion)) input$inf_modo_comparacion else "entre_grupos"
    secciones <- input$inf_secciones
    usar_gamm      <- isTRUE(input$inf_gamm_activar)
    gamm_familia   <- if (!is.null(input$inf_gamm_familia)) input$inf_gamm_familia else "gaussian"
    gamm_usar_re   <- isTRUE(input$inf_gamm_usar_re)
    gamm_re_vars   <- if (!is.null(input$inf_gamm_re_vars)) input$inf_gamm_re_vars else character(0)
    
    # Example config
    ej_n <- if (!is.null(input$inf_ej_n)) input$inf_ej_n else 2
    ej_min_dur <- if (!is.null(input$inf_ej_min_dur)) input$inf_ej_min_dur else 0
    ej_min_pal <- if (!is.null(input$inf_ej_min_palabras)) input$inf_ej_min_palabras else 2
    ej_max_dur <- if (!is.null(input$inf_ej_max_dur)) input$inf_ej_max_dur else Inf
    ej_max_pal <- if (!is.null(input$inf_ej_max_palabras)) input$inf_ej_max_palabras else Inf
    ej_direccion <- if (!is.null(input$inf_ej_direccion)) input$inf_ej_direccion else "ambos"
    ej_ubicacion <- if (!is.null(input$inf_ej_ubicacion)) input$inf_ej_ubicacion else "final"
    ej_acento    <- if (!is.null(input$inf_ej_acento)) input$inf_ej_acento else "todos"
    
    # Merge etiquetado columns into df if needed for grouping var or correlation section
    etiq_cols_needed <- c(var_cat)  # RF, ANOVA, tree all use var_cat as dep var
    if ("correlacion_emociones" %in% secciones || "ejemplos" %in% secciones) {
      etiq_cols_needed <- c(etiq_cols_needed, "emocion_manual", "sentimiento", "emocion_texto", "emocion_audio",
                            "sent_label", "emo_texto_label", "emo_audio_label")
    }
    if (!is.null(etiq$anotaciones) && nrow(etiq$anotaciones) == nrow(df)) {
      for (ecol in c("emocion_manual", "sent_label", "emo_texto_label", "emo_audio_label")) {
        if (ecol %in% etiq_cols_needed && !ecol %in% colnames(df) && ecol %in% colnames(etiq$anotaciones)) {
          df[[ecol]] <- etiq$anotaciones[[ecol]]
        }
      }
    }
    
    if (is.null(vars_num) || length(vars_num) == 0) {
      showNotification("Selecciona al menos una variable numérica", type = "warning")
      return()
    }
    
    # Z-score normalization by speaker
    usar_z <- isTRUE(input$inf_normalizar_z)
    medias_orig <- list()  # Store original means per var per group for annotation
    if (usar_z && "hablante" %in% colnames(df)) {
      for (v in vars_num) {
        if (v %in% colnames(df) && is.numeric(df[[v]])) {
          # Store original means per group (for display alongside Z)
          if (!is.null(var_cat) && var_cat %in% colnames(df)) {
            medias_orig[[v]] <- tapply(df[[v]], df[[var_cat]], function(x) round(mean(x, na.rm=TRUE), 2))
          }
          # Compute Z by speaker
          df[[paste0(v, "_orig")]] <- df[[v]]  # keep original
          spk_means <- tapply(df[[v]], df$hablante, mean, na.rm = TRUE)
          spk_sds <- tapply(df[[v]], df$hablante, sd, na.rm = TRUE)
          for (s in names(spk_means)) {
            idx_s <- which(df$hablante == s)
            if (!is.na(spk_sds[s]) && spk_sds[s] > 0) {
              df[[v]][idx_s] <- (df[[v]][idx_s] - spk_means[s]) / spk_sds[s]
            } else {
              df[[v]][idx_s] <- 0
            }
          }
        }
      }
    }
    
    withProgress(message = "Generando informe...", value = 0, {
      inf_dir <- file.path(getwd(), "informes")
      dir.create(inf_dir, recursive = TRUE, showWarnings = FALSE)
      timestamp <- format(Sys.time(), "%Y%m%d_%H%M%S")
      graf_dir <- file.path(inf_dir, paste0("graficos_", timestamp))
      dir.create(graf_dir, showWarnings = FALSE)
      
      informe$informe_dir <- inf_dir
      informe$graficos_paths <- list()
      informe$ejemplos_ids <- character(0)  # reset IDs para ZIP de clips
      dpi_val <- input$inf_dpi
      
      html <- c(
        '<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8">',
        '<style>',
        'body { font-family: "Segoe UI", Arial, sans-serif; max-width: 1000px; margin: 0 auto; padding: 20px; color: #333; line-height: 1.6; }',
        'h1 { color: #2c3e50; border-bottom: 3px solid #3498db; padding-bottom: 10px; }',
        'h2 { color: #2980b9; border-bottom: 1px solid #bdc3c7; padding-bottom: 5px; margin-top: 30px; }',
        'h3 { color: #27ae60; margin-top: 20px; }',
        'table { border-collapse: collapse; width: 100%; margin: 15px 0; font-size: 13px; }',
        'th { background-color: #3498db; color: white; padding: 8px 12px; text-align: left; }',
        'td { padding: 6px 12px; border-bottom: 1px solid #ecf0f1; }',
        'tr:nth-child(even) { background-color: #f8f9fa; }',
        'img { max-width: 100%; border: 1px solid #ddd; border-radius: 4px; margin: 10px 0; }',
        '.meta { color: #7f8c8d; font-size: 12px; margin-bottom: 20px; }',
        '.stat-box { background: #f0f7ff; border-left: 4px solid #3498db; padding: 10px 15px; margin: 10px 0; }',
        '.warning-box { background: #fff3cd; border-left: 4px solid #ffc107; padding: 10px 15px; margin: 10px 0; }',
        'pre { background: #f8f9fa; padding: 10px; border-radius: 4px; overflow-x: auto; font-size: 12px; }',
        '.ejemplo-bloque { border: 1px solid #ccc; border-radius: 8px; padding: 15px; margin: 15px 0; background: #fafafa; }',
        '.ejemplo-titulo { font-size: 1.1em; font-weight: bold; margin-bottom: 10px; }',
        '.ctx-fila { padding: 4px 8px; font-size: 0.9em; border-bottom: 1px solid #eee; display: flex; align-items: center; }',
        '.ctx-fila-actual { background-color: #fff3cd; font-weight: bold; border: 2px solid #ffc107; border-radius: 4px; padding: 6px 8px; }',
        '.ctx-fila-contexto { color: #666; }',
        '.ctx-emojis { min-width: 60px; text-align: center; font-size: 1.1em; margin-right: 6px; }',
        '.ctx-texto { flex: 1; }',
        '.ctx-hablante { min-width: 80px; font-size: 0.8em; color: #888; }',
        '.ctx-amh { min-width: 40px; font-size: 0.8em; color: #555; text-align: center; }',
        '.ctx-contrast { min-width: 120px; font-size: 0.85em; margin: 0 4px; white-space: nowrap; }',
        '.prosodic-legend { background: #fff7ed; padding: 10px; border-radius: 6px; margin: 10px 0; font-size: 0.85em; columns: 2; }',
        '.prosodic-legend div { margin: 2px 0; break-inside: avoid; }',
        '</style></head><body>'
      )
      
      # Initialize figure and table counters
      fig_num <- 0
      tab_num <- 0
      
      html <- c(html,
        paste0('<h1>', htmltools::htmlEscape(input$inf_titulo), '</h1>'),
        paste0('<p class="meta">Autor: ', htmltools::htmlEscape(input$inf_autor),
               ' | Generado: ', format(Sys.time(), "%d/%m/%Y %H:%M"),
               ' | Dataset: ', input$inf_dataset,
               ' | N = ', nrow(df), ' observaciones</p>')
      )
      if (!is.null(var_cat)) {
        html <- c(html, paste0('<p class="meta">Variable de agrupación: <strong>', var_cat, 
                                '</strong> — Categorías: ', paste(unique(na.omit(df[[var_cat]])), collapse = ", "), '</p>'))
      }
      if (!is.null(var_filtro) && var_filtro %in% colnames(df)) {
        vals_filtro <- if (!is.null(input$inf_valores_filtro)) paste(input$inf_valores_filtro, collapse = ", ") else "todos"
        html <- c(html, paste0('<p class="meta">Filtro aplicado: <strong>', var_filtro, 
                                '</strong> = ', vals_filtro, '</p>'))
      }
      if (usar_z) {
        html <- c(html, '<div class="stat-box" style="background:#fff3cd;border-color:#ffc107;">',
                  '<strong>\U0001F4CA Valores Z (normalizados por hablante)</strong> — ',
                  'Las variables numéricas se expresan como puntuaciones Z respecto a la media del hablante. ',
                  'Se indica la media original entre paréntesis.</div>')
      }
      if (isTRUE(input$inf_filtrar_outliers)) {
        metodo_out <- if (!is.null(input$inf_outlier_metodo)) input$inf_outlier_metodo else "iqr"
        factor_out <- if (!is.null(input$inf_outlier_factor)) input$inf_outlier_factor else 1.5
        metodo_label <- switch(metodo_out,
          "iqr" = paste0("IQR \u00d7", factor_out),
          "pct" = paste0("Percentiles ", factor_out, "-", 100 - factor_out),
          "sd" = paste0("\u00b1", factor_out, " DE"),
          paste0("IQR \u00d71.5"))
        por_grupo_label <- if (isTRUE(input$inf_outlier_por_grupo)) " (por grupo)" else " (global)"
        # Count how many were removed
        n_total <- nrow(inf_data())  # before filtering
        n_actual <- nrow(df)
        n_removed <- max(0, n_total - n_actual)
        html <- c(html, paste0('<div class="stat-box" style="background:#fce4ec;border-color:#e91e63;">',
                  '<strong>\U0001F9F9 Outliers filtrados:</strong> ', metodo_label, por_grupo_label,
                  ' — ', n_removed, ' observaciones eliminadas (', round(n_removed/max(1,n_total)*100, 1), '%).',
                  '</div>'))
      }
      if (!is.null(var_cat)) {
        html <- c(html, paste0('<p class="meta">Modo de comparación: <strong>', 
                                if (modo_comp == "entre_grupos") "Entre grupos (overlay)" else "Por grupo (separado)", '</strong></p>'))
      }
      
      graf_counter <- 0
      save_and_embed <- function(plot_expr, nombre, ancho = 8, alto = 5, envir = parent.frame()) {
        graf_counter <<- graf_counter + 1
        fname <- paste0(sprintf("%02d", graf_counter), "_", nombre, ".png")
        fpath <- file.path(graf_dir, fname)
        err_msg <- NULL
        png(fpath, width = ancho, height = alto, units = "in", res = dpi_val)
        tryCatch(eval(plot_expr, envir = envir), error = function(e) {
          err_msg <<- e$message
          plot.new(); text(0.5, 0.5, paste("Error:", e$message), col = "red", cex=0.8)
        })
        dev.off()
        informe$graficos_paths[[fname]] <- fpath
        raw_b <- readBin(fpath, "raw", file.info(fpath)$size)
        b64 <- base64enc::base64encode(raw_b)
        img_tag <- paste0('<img src="data:image/png;base64,', b64, '" alt="', htmltools::htmlEscape(nombre), '">')
        if (!is.null(err_msg)) {
          paste0('<div class="warning-box"><strong>Error en gráfico ', htmltools::htmlEscape(nombre), ':</strong> ',
                 htmltools::htmlEscape(err_msg), '</div>', img_tag)
        } else {
          img_tag
        }
      }
      
      df_to_html <- function(d, max_rows = 50) {
        if (is.null(d) || !is.data.frame(d) || ncol(d) == 0) return('<p class="meta"><em>Sin datos disponibles.</em></p>')
        if (nrow(d) == 0) return(paste0('<table><thead><tr>', paste0('<th>', htmltools::htmlEscape(colnames(d)), '</th>', collapse = ''), '</tr></thead><tbody><tr><td colspan="', ncol(d), '" style="text-align:center;color:#999;">Sin observaciones</td></tr></tbody></table>'))
        if (nrow(d) > max_rows) d <- head(d, max_rows)
        nums <- sapply(d, is.numeric)
        d[nums] <- lapply(d[nums], function(x) round(x, 3))
        header <- paste0('<th>', htmltools::htmlEscape(colnames(d)), '</th>', collapse = '')
        rows <- apply(d, 1, function(r) {
          paste0('<td>', htmltools::htmlEscape(as.character(r)), '</td>', collapse = '')
        })
        if (length(rows) == 0) rows <- character(0)
        paste0('<table><thead><tr>', header, '</tr></thead><tbody>',
               paste0('<tr>', rows, '</tr>', collapse = ''), '</tbody></table>')
      }
      
      # ---- Función reutilizable: generar ejemplos extremos para una variable ----
      # Groups by grp_col categories (numbered), selects top/bottom n_ej per category
      # Renders melodic curves directly (avoids quote/eval scoping issues)
      generar_ejemplos_extremos <- function(v, df_ej, n_ej, min_dur, min_pal,
                                             construir_contexto_fn, phones_all = NULL,
                                             grp_col = NULL, max_dur = Inf, max_pal = Inf,
                                             direccion = "ambos", filtro_acento = "todos") {
        if (!v %in% colnames(df_ej) || !is.numeric(df_ej[[v]])) return("")
        
        media_global <- mean(df_ej[[v]], na.rm = TRUE)
        
        # Filter eligible rows
        eligible <- !is.na(df_ej[[v]])
        if (min_dur > 0 && "duracion" %in% colnames(df_ej))
          eligible <- eligible & !is.na(df_ej$duracion) & df_ej$duracion >= min_dur
        if (is.finite(max_dur) && "duracion" %in% colnames(df_ej))
          eligible <- eligible & !is.na(df_ej$duracion) & df_ej$duracion <= max_dur
        if (min_pal > 0 && "num_palabras" %in% colnames(df_ej))
          eligible <- eligible & !is.na(df_ej$num_palabras) & df_ej$num_palabras >= min_pal
        if (is.finite(max_pal) && "num_palabras" %in% colnames(df_ej))
          eligible <- eligible & !is.na(df_ej$num_palabras) & df_ej$num_palabras <= max_pal
        # Filtro por acento de la última palabra (usa columna precalculada si existe)
        if (!is.null(filtro_acento) && filtro_acento != "todos" && "acento_final" %in% colnames(df_ej)) {
          tipos_ok <- switch(filtro_acento,
            "llana"     = "llana",
            "aguda"     = "aguda",
            "esdrujula" = c("esdrújula", "sobresdrújula"),
            "atona"     = c("átona", "atona", "monosílabo"),
            character(0)
          )
          if (length(tipos_ok) > 0)
            eligible <- eligible & !is.na(df_ej$acento_final) & df_ej$acento_final %in% tipos_ok
        }
        
        # Determine categories
        if (!is.null(grp_col) && grp_col %in% colnames(df_ej)) {
          categorias <- sort(unique(na.omit(df_ej[[grp_col]][eligible])))
          categorias <- categorias[categorias != ""]
        } else {
          categorias <- NULL
        }
        
        # Helper: render melodic curve directly to PNG and return base64 img tag
        # Modo de curva melódica en ejemplos: "st", "hz", o "amh"
        ej_curva_modo_val <- if (!is.null(input$inf_ej_curva_modo)) input$inf_ej_curva_modo else "st"
        mostrar_curva_ej <- if (!is.null(input$inf_ej_mostrar_curva)) isTRUE(input$inf_ej_mostrar_curva) else TRUE
        
render_curva <- function(ge_id, titulo, color_line, fn_filter = NULL) {
          if (!mostrar_curva_ej) return("")
          if (is.null(phones_all) || is.null(ge_id) || is.na(ge_id)) return("")
          if (!"id_grupo" %in% colnames(phones_all)) return("")
          if (!is.null(fn_filter) && nchar(fn_filter) > 0 && "filename" %in% colnames(phones_all)) {
            ph_ge <- phones_all[phones_all$id_grupo == ge_id & phones_all$filename == fn_filter, ]
          } else {
            ph_ge <- phones_all[phones_all$id_grupo == ge_id, ]
          }
          if (nrow(ph_ge) < 2) return("")
          ph_ge <- ph_ge[order(ph_ge$inicio), ]
          # Deduplicar por posición en el grupo (clave funcional, no por igualdad de filas)
          if ("id_completo" %in% colnames(ph_ge) && any(!is.na(ph_ge$id_completo))) {
            ph_ge <- ph_ge[!duplicated(ph_ge$id_completo), ]
          } else if ("posicion_en_grupo" %in% colnames(ph_ge) && any(!is.na(ph_ge$posicion_en_grupo))) {
            ph_ge <- ph_ge[!duplicated(ph_ge$posicion_en_grupo), ]
          }
          
          # ---- Seleccionar columna de F0 según modo ----
          if (ej_curva_modo_val == "hz") {
            f0_col <- if ("f0_media_hz" %in% colnames(ph_ge)) "f0_media_hz" else "f0_media_st"
          } else {
            f0_col <- if ("f0_media_st" %in% colnames(ph_ge)) "f0_media_st" else "f0_media_hz"
          }
          ph_plot <- ph_ge[!is.na(ph_ge[[f0_col]]), ]
          if (nrow(ph_plot) < 2) return("")
          
          graf_counter <<- graf_counter + 1
          fname <- paste0(sprintf("%02d", graf_counter), "_curva_ej_", v, "_", graf_counter, ".png")
          fpath <- file.path(graf_dir, fname)
          fig_num <<- fig_num + 1
          
          ph_plot$pos <- seq_len(nrow(ph_plot))
          f0_raw <- ph_plot[[f0_col]]
          
          # ---- Etiquetas eje X: solo la vocal (con fallback a posición si es NA/vacío) ----
vocal_lbl <- if ("vocal" %in% colnames(ph_plot)) ph_plot$vocal else if ("etiqueta" %in% colnames(ph_plot)) ph_plot$etiqueta else as.character(ph_plot$pos)          
  vocal_lbl[is.na(vocal_lbl) | vocal_lbl == ""] <- as.character(ph_plot$pos[is.na(vocal_lbl) | vocal_lbl == ""])
          
          # Marcadores comunes (tónicas y picos)
          tonicas_idx <- if ("tonica_gramatical" %in% colnames(ph_plot))
            which(!is.na(ph_plot$tonica_gramatical) & ph_plot$tonica_gramatical == "sí") else integer(0)
          picos_idx <- if ("es_pico_grupo" %in% colnames(ph_plot))
            which(!is.na(ph_plot$es_pico_grupo) & ph_plot$es_pico_grupo == TRUE) else integer(0)
          
          tryCatch({
            png(fpath, width = 8, height = 4.5, units = "in", res = dpi_val)
            
            if (ej_curva_modo_val %in% c("amh", "aph")) {
              # ---- Modo AMH/APH: primera vocal = 100, escala Hz proporcional ----
              f0_hz_amh <- if ("f0_media_hz" %in% colnames(ph_plot)) {
                ph_plot$f0_media_hz
              } else {
                2^(f0_raw / 12)
              }
              f0_hz_amh[f0_hz_amh <= 0 | is.na(f0_hz_amh)] <- NA
              base_hz <- f0_hz_amh[!is.na(f0_hz_amh)][1]
              f0_amh <- if (!is.null(base_hz) && !is.na(base_hz) && base_hz > 0) {
                (f0_hz_amh / base_hz) * 100
              } else rep(100, length(f0_hz_amh))
              # Filtro Hz_porcentual máximo
              hz_pct_max_val <- if (!is.null(input$inf_hz_pct_max) && is.numeric(input$inf_hz_pct_max)) input$inf_hz_pct_max else 300
              f0_amh[!is.na(f0_amh) & f0_amh > hz_pct_max_val] <- NA

              p <- ggplot(data.frame(pos = ph_plot$pos, f0 = f0_amh), aes(x = pos, y = f0)) +
                geom_hline(yintercept = 100, linetype = "dashed", color = "grey60", alpha = 0.4) +
                geom_line(color = "#1565C0", linewidth = 1.3) +
                geom_point(color = "#1565C0", size = 2.5)

              if (ej_curva_modo_val == "aph") {
                # Intensidad APH base 100
                int_amh <- rep(NA_real_, nrow(ph_plot))
                if ("int_media" %in% colnames(ph_plot)) {
                  int_raw <- ph_plot$int_media
                  int_valid <- int_raw[!is.na(int_raw) & int_raw > 0]
                  base_int <- if (length(int_valid) > 0) int_valid[1] else NA
                  if (!is.na(base_int) && base_int > 0)
                    int_amh <- ifelse(is.na(int_raw) | int_raw <= 0, NA, (int_raw / base_int) * 100)
                }

                # Transición intervocálica APH (vocal 1 queda NA → no se dibuja)
                trans_amh <- rep(NA_real_, nrow(ph_plot))
                if ("tiempo_transicion_anterior" %in% colnames(ph_plot)) {
                  t_raw <- ph_plot$tiempo_transicion_anterior
                  t_para_media <- t_raw[-1]
                  t_med <- mean(t_para_media[!is.na(t_para_media) & t_para_media > 0], na.rm = TRUE)
                  if (!is.na(t_med) && t_med > 0)
                    trans_amh[-1] <- (t_raw[-1] / t_med) * 100
                }

                # Intensidad (VERDE)
                if (any(!is.na(int_amh))) {
                  df_int <- data.frame(pos = ph_plot$pos, int = int_amh)
                  p <- p +
                    geom_line(data = df_int, aes(x = pos, y = int),
                               color = "#2e7d32", linetype = "dashed", linewidth = 0.9, alpha = 0.8) +
                    geom_point(data = df_int, aes(x = pos, y = int),
                                color = "#2e7d32", shape = 15, size = 2, alpha = 0.8)
                }

                # Transiciones (barras)
                idx_trans <- which(!is.na(trans_amh) & trans_amh > 0)
                if (length(idx_trans) > 0) {
                  df_trans <- data.frame(pos = ph_plot$pos[idx_trans], trans = trans_amh[idx_trans])
                  p <- p + geom_bar(data = df_trans, aes(x = pos, y = trans), stat = "identity",
                                     fill = "#555555", alpha = 0.18, width = 0.35)
                }
              }

              # Tónicas
              if (length(tonicas_idx) > 0) {
                df_ton <- data.frame(pos = tonicas_idx, f0 = f0_amh[tonicas_idx])
                p <- p +
                  geom_point(data = df_ton, aes(x = pos, y = f0), shape = 17, size = 4, color = "gold3") +
                  geom_point(data = df_ton, aes(x = pos, y = f0), shape = 2,  size = 4, color = "black", stroke = 0.6)
              }

              # Picos
              if (length(picos_idx) > 0) {
                df_pico <- data.frame(pos = picos_idx, f0 = f0_amh[picos_idx])
                p <- p +
                  geom_point(data = df_pico, aes(x = pos, y = f0),
                              shape = 21, size = 4, fill = "white", color = "darkred", stroke = 1.5)
              }

              caption_txt <- if (ej_curva_modo_val == "aph")
                "— Pitch (azul)   ―― Intensidad (verde)   ▮ Transición   ▲ Tónica   ● Pico"
              else
                "— Pitch (azul)   ▲ Tónica   ● Pico"
              y_lab_amh <- if (ej_curva_modo_val == "aph") "APH (1ª vocal = 100)" else "AMH (1ª vocal = 100)"

              p <- p +
                scale_x_continuous(breaks = ph_plot$pos, labels = vocal_lbl) +
                theme_minimal(base_size = 11) +
                theme(
                  axis.text.x  = element_text(size = 9),
                  plot.caption = element_text(size = 8, color = "grey50")
                ) +
                labs(x = NULL, y = y_lab_amh, title = titulo, caption = caption_txt)
              
            } else {
              # ---- Modo Hz o St ----
              y_lab <- if (ej_curva_modo_val == "hz") "F0 (Hz)" else "F0 (St)"
              
              p <- ggplot(data.frame(pos = ph_plot$pos, f0 = f0_raw), aes(x = pos, y = f0)) +
                geom_line(color = "#1565C0", linewidth = 1.2) +
                geom_point(color = "#1565C0", size = 2.5)
              
              if (length(tonicas_idx) > 0) {
                df_ton <- data.frame(pos = tonicas_idx, f0 = f0_raw[tonicas_idx])
                p <- p +
                  geom_point(data = df_ton, aes(x = pos, y = f0), shape = 17, size = 4, color = "gold3") +
                  geom_point(data = df_ton, aes(x = pos, y = f0), shape = 2,  size = 4, color = "black", stroke = 0.6)
              }
              if (length(picos_idx) > 0) {
                df_pico <- data.frame(pos = picos_idx, f0 = f0_raw[picos_idx])
                p <- p +
                  geom_point(data = df_pico, aes(x = pos, y = f0),
                              shape = 21, size = 4, fill = "white", color = "darkred", stroke = 1.5)
              }
              
              p <- p +
                scale_x_continuous(breaks = ph_plot$pos, labels = vocal_lbl) +
                theme_minimal(base_size = 11) +
                theme(axis.text.x = element_text(size = 9)) +
                labs(x = NULL, y = y_lab, title = titulo)
            }
            
            print(p)
            dev.off()
            
            informe$graficos_paths[[fname]] <- fpath
            if (!is.null(ge_id) && !is.na(ge_id) && nchar(ge_id) > 0) {
              informe$ejemplos_ids <- unique(c(informe$ejemplos_ids, as.character(ge_id)))
            }
            raw_b <- readBin(fpath, "raw", file.info(fpath)$size)
            b64 <- base64enc::base64encode(raw_b)
            paste0('<img src="data:image/png;base64,', b64, '" alt="', htmltools::htmlEscape(titulo), '">')
          }, error = function(e) {
            tryCatch(dev.off(), error = function(e2) NULL)
            ""
          })
}
        
        # Helper: build HTML for a list of example indices
        build_examples_html <- function(indices, color, arrow) {
          ej_parts <- c()
          for (i in seq_along(indices)) {
            idx <- indices[i]
            fila <- df_ej[idx, , drop = FALSE]
            val_display <- round(df_ej[[v]][idx], 3)
            fn <- if ("filename" %in% colnames(fila)) as.character(fila$filename) else ""
            spk <- if ("hablante" %in% colnames(fila)) as.character(fila$hablante) else ""
            txt_val <- if ("palabras_grupo" %in% colnames(fila) && !is.na(fila$palabras_grupo)) as.character(fila$palabras_grupo)
                   else if ("texto" %in% colnames(fila) && !is.na(fila$texto)) as.character(fila$texto) else ""
            
            info_parts <- c(paste0("<strong>", v, "=", val_display, "</strong>"))
            if ("duracion" %in% colnames(fila) && !is.na(fila$duracion))
              info_parts <- c(info_parts, paste0("Dur=", round(fila$duracion, 2), "s"))
            if ("num_palabras" %in% colnames(fila) && !is.na(fila$num_palabras))
              info_parts <- c(info_parts, paste0(fila$num_palabras, " pal"))
            if ("amh_patron" %in% colnames(fila) && !is.na(fila$amh_patron))
              info_parts <- c(info_parts, as.character(fila$amh_patron))
            
            same_file_idx <- which(df_ej$filename == fn)
            n_context <- if (length(same_file_idx) <= 15) length(same_file_idx) else 5
            
            ej_parts <- c(ej_parts, paste0(
              '<div class="ejemplo-bloque" style="border-left:4px solid ', color, ';">',
              '<div class="ejemplo-titulo">', arrow, ' Ej. ', i, ' [', spk, ' \u2014 ', fn, ']: ',
              '<span style="font-weight:normal;color:#666;font-size:0.9em;">', paste(info_parts, collapse = " | "), '</span></div>',
              construir_contexto_fn(idx, n_contexto = n_context),
              '</div>'
            ))
            
            # Melodic curve (direct render — no quote/eval scope issue)
            if (!is.null(phones_all) && "id_ge" %in% colnames(fila) && !is.na(fila$id_ge)) {
              curva <- render_curva(as.character(fila$id_ge), paste0("Curva: ", txt_val), color, fn_filter = fn)
              if (nchar(curva) > 0) ej_parts <- c(ej_parts, curva)
            }
          }
          ej_parts
        }
        
        # Helper: get indices ordered by value from a pool
        get_ordered_idx <- function(idx_pool, dir) {
          if (length(idx_pool) < 1) return(integer(0))
          idx_pool[order(df_ej[[v]][idx_pool], decreasing = (dir == "high"))]
        }
        
        ej_html <- c()
        
        if (!is.null(categorias) && length(categorias) > 0) {
          # ---- Calcular media por categoría (sobre filas elegibles) ----
          cat_means_all <- sapply(categorias, function(cat) {
            idx_cat <- which(eligible & !is.na(df_ej[[grp_col]]) & df_ej[[grp_col]] == cat)
            if (length(idx_cat) == 0) return(NA_real_)
            mean(df_ej[[v]][idx_cat], na.rm = TRUE)
          })
          names(cat_means_all) <- categorias
          cat_means_valid <- cat_means_all[!is.na(cat_means_all)]

          # ---- Selección por media de categoría ----
          run_direction <- function(dir, color, arrow, titulo_dir) {
            if (length(cat_means_valid) == 0) return(c())
            best_cat  <- if (dir == "high") names(which.max(cat_means_valid)) else names(which.min(cat_means_valid))
            best_mean <- cat_means_valid[best_cat]
            idx_cat   <- which(eligible & !is.na(df_ej[[grp_col]]) & df_ej[[grp_col]] == best_cat)
            ordered_idx <- get_ordered_idx(idx_cat, dir)
            selected_idx <- head(ordered_idx, n_ej)
            if (length(selected_idx) == 0) return(c())

            out <- paste0('<h5 style="color:', color, ';">', arrow, ' ', titulo_dir,
                          ' de ', htmltools::htmlEscape(v),
                          ' \u2014 categor\u00eda: <span style="background:#eee;padding:2px 6px;border-radius:3px;">',
                          htmltools::htmlEscape(best_cat), '</span>',
                          ' <span style="font-size:0.8em;color:#888;">(media cat.=', round(best_mean, 3), ')</span></h5>')
            parts <- c()
            for (i in seq_along(selected_idx)) {
              idx  <- selected_idx[i]
              fila <- df_ej[idx, , drop = FALSE]
              val_display <- round(df_ej[[v]][idx], 3)
              dif_media   <- round(df_ej[[v]][idx] - media_global, 3)
              dif_label   <- if (dif_media > 0) paste0("+", dif_media) else as.character(dif_media)
              fn  <- if ("filename"       %in% colnames(fila)) as.character(fila$filename) else ""
              spk <- if ("hablante"       %in% colnames(fila)) as.character(fila$hablante) else ""
              txt <- if ("palabras_grupo" %in% colnames(fila) && !is.na(fila$palabras_grupo)) as.character(fila$palabras_grupo)
                     else if ("texto"     %in% colnames(fila) && !is.na(fila$texto)) as.character(fila$texto) else ""
              info_p <- c(paste0("<strong>", v, "=", val_display, "</strong>"),
                          paste0("\u0394media=", dif_label),
                          paste0("<em style='color:#888;'>#", i, " en ", htmltools::htmlEscape(best_cat),
                                 " (", length(idx_cat), " disp.)</em>"))
              if ("duracion"    %in% colnames(fila) && !is.na(fila$duracion))
                info_p <- c(info_p, paste0("Dur=", round(fila$duracion, 2), "s"))
              if ("num_palabras" %in% colnames(fila) && !is.na(fila$num_palabras))
                info_p <- c(info_p, paste0(fila$num_palabras, " pal"))
              if ("amh_patron"   %in% colnames(fila) && !is.na(fila$amh_patron))
                info_p <- c(info_p, as.character(fila$amh_patron))
              same_file_idx <- which(df_ej$filename == fn)
              n_context <- if (length(same_file_idx) <= 15) length(same_file_idx) else 5
              parts <- c(parts, paste0(
                '<div class="ejemplo-bloque" style="border-left:4px solid ', color, ';">',
                '<div class="ejemplo-titulo">', arrow, ' [',
                '<span style="background:#eee;padding:1px 5px;border-radius:3px;font-size:0.85em;">',
                htmltools::htmlEscape(best_cat), '</span>',
                ' ', spk, ' \u2014 ', fn, ']: ',
                '<span style="font-weight:normal;color:#666;font-size:0.9em;">',
                paste(info_p, collapse = " | "), '</span></div>',
                construir_contexto_fn(idx, n_contexto = n_context),
                '</div>'
              ))
              if (!is.null(phones_all) && "id_ge" %in% colnames(fila) && !is.na(fila$id_ge)) {
                curva <- render_curva(as.character(fila$id_ge), paste0("Curva: ", txt), color, fn_filter = fn)
                if (nchar(curva) > 0) parts <- c(parts, curva)
              }
            }
            c(out, parts)
          }

          # ---- Ejemplo central: categoría cuya media es más cercana a la mediana global ----
          run_central <- function() {
            if (length(cat_means_valid) == 0) return(c())
            mediana_global <- median(df_ej[[v]][eligible], na.rm = TRUE)
            central_cat  <- names(cat_means_valid)[which.min(abs(cat_means_valid - mediana_global))]
            central_mean <- cat_means_valid[central_cat]
            idx_cat <- which(eligible & !is.na(df_ej[[grp_col]]) & df_ej[[grp_col]] == central_cat)
            if (length(idx_cat) == 0) return(c())
            closest_idx <- idx_cat[which.min(abs(df_ej[[v]][idx_cat] - central_mean))]
            color_c <- "#2e7d32"
            fila <- df_ej[closest_idx, , drop = FALSE]
            val_display <- round(df_ej[[v]][closest_idx], 3)
            fn  <- if ("filename"       %in% colnames(fila)) as.character(fila$filename) else ""
            spk <- if ("hablante"       %in% colnames(fila)) as.character(fila$hablante) else ""
            txt <- if ("palabras_grupo" %in% colnames(fila) && !is.na(fila$palabras_grupo)) as.character(fila$palabras_grupo)
                   else if ("texto"     %in% colnames(fila) && !is.na(fila$texto)) as.character(fila$texto) else ""
            info_p <- c(paste0("<strong>", v, "=", val_display, "</strong>"),
                        paste0("mediana global=", round(mediana_global, 3)),
                        paste0("<em style='color:#888;'>m\u00e1s central en ", htmltools::htmlEscape(central_cat), "</em>"))
            if ("duracion"    %in% colnames(fila) && !is.na(fila$duracion))
              info_p <- c(info_p, paste0("Dur=", round(fila$duracion, 2), "s"))
            if ("num_palabras" %in% colnames(fila) && !is.na(fila$num_palabras))
              info_p <- c(info_p, paste0(fila$num_palabras, " pal"))
            if ("amh_patron"   %in% colnames(fila) && !is.na(fila$amh_patron))
              info_p <- c(info_p, as.character(fila$amh_patron))
            same_file_idx <- which(df_ej$filename == fn)
            n_context <- if (length(same_file_idx) <= 15) length(same_file_idx) else 5
            out <- paste0('<h5 style="color:', color_c, ';">\u25c6 Valor central de ',
                          htmltools::htmlEscape(v),
                          ' \u2014 categor\u00eda: <span style="background:#eee;padding:2px 6px;border-radius:3px;">',
                          htmltools::htmlEscape(central_cat), '</span>',
                          ' <span style="font-size:0.8em;color:#888;">(media cat.=', round(central_mean, 3),
                          ', mediana global=', round(mediana_global, 3), ')</span></h5>')
            part <- paste0(
              '<div class="ejemplo-bloque" style="border-left:4px solid ', color_c, ';">',
              '<div class="ejemplo-titulo">\u25c6 [',
              '<span style="background:#eee;padding:1px 5px;border-radius:3px;font-size:0.85em;">',
              htmltools::htmlEscape(central_cat), '</span>',
              ' ', spk, ' \u2014 ', fn, ']: ',
              '<span style="font-weight:normal;color:#666;font-size:0.9em;">',
              paste(info_p, collapse = " | "), '</span></div>',
              construir_contexto_fn(closest_idx, n_contexto = n_context),
              '</div>'
            )
            curva_c <- ""
            if (!is.null(phones_all) && "id_ge" %in% colnames(fila) && !is.na(fila$id_ge))
              curva_c <- render_curva(as.character(fila$id_ge), paste0("Curva: ", txt), color_c, fn_filter = fn)
            c(out, part, if (nchar(curva_c) > 0) curva_c else character(0))
          }

          if (direccion %in% c("ambos", "max"))
            ej_html <- c(ej_html, run_direction("high", "#c62828", "\U00002B06\U0000FE0F", "Valores m\u00e1s altos"))
          if (direccion %in% c("ambos", "min"))
            ej_html <- c(ej_html, run_direction("low",  "#1565C0", "\U00002B07\U0000FE0F", "Valores m\u00e1s bajos"))
          ej_html <- c(ej_html, run_central())
          
        } else {
          # ---- Global (sin agrupacion) ----
          idx_all <- which(eligible)
          if (length(idx_all) >= 2) {
            if (direccion %in% c("ambos", "max")) {
              idx_high <- get_ordered_idx(idx_all, "high")[seq_len(min(n_ej, length(idx_all)))]
              ej_html <- c(ej_html,
                paste0('<h4 style="color:#c62828;">\U00002B06\U0000FE0F Valores altos de ', v, '</h4>'),
                build_examples_html(idx_high, "#c62828", "\U00002B06\U0000FE0F"))
            }
            if (direccion %in% c("ambos", "min")) {
              idx_low <- get_ordered_idx(idx_all, "low")[seq_len(min(n_ej, length(idx_all)))]
              ej_html <- c(ej_html,
                paste0('<h4 style="color:#1565C0;">\U00002B07\U0000FE0F Valores bajos de ', v, '</h4>'),
                build_examples_html(idx_low, "#1565C0", "\U00002B07\U0000FE0F"))
            }
            # Ejemplo central (global): el más cercano a la mediana
            mediana_g <- median(df_ej[[v]][idx_all], na.rm = TRUE)
            idx_central_g <- idx_all[which.min(abs(df_ej[[v]][idx_all] - mediana_g))]
            ej_html <- c(ej_html,
              paste0('<h4 style="color:#2e7d32;">\u25c6 Valor central de ', v,
                     ' <span style="font-size:0.8em;color:#888;">(mediana=', round(mediana_g, 3), ')</span></h4>'),
              build_examples_html(idx_central_g, "#2e7d32", "\u25c6"))
          }
        }
        paste(ej_html, collapse = "\n")
      }
      
      # ---- Setup context builder for examples (used by both inline and final) ----
      phones_all_ej <- datos$phones
      
      # Reference stats for prosodic emojis
      rango_media_ref <- if ("rango_f0_grupo_st" %in% colnames(df)) mean(df$rango_f0_grupo_st, na.rm = TRUE) else NA
      rango_sd_ref <- if ("rango_f0_grupo_st" %in% colnames(df)) sd(df$rango_f0_grupo_st, na.rm = TRUE) else NA
      dur_media_ref <- if ("duracion" %in% colnames(df)) mean(df$duracion, na.rm = TRUE) else NA
      dur_sd_ref <- if ("duracion" %in% colnames(df)) sd(df$duracion, na.rm = TRUE) else NA
      vel_vals_ref <- if ("velocidad_habla" %in% colnames(df)) df$velocidad_habla else NULL
      vel_media_ref <- if (!is.null(vel_vals_ref)) mean(vel_vals_ref, na.rm = TRUE) else NA
      vel_sd_ref <- if (!is.null(vel_vals_ref)) sd(vel_vals_ref, na.rm = TRUE) else NA
      int_media_ref <- if ("intensidad_media_grupo" %in% colnames(df)) mean(df$intensidad_media_grupo, na.rm = TRUE) else NA
      int_sd_ref <- if ("intensidad_media_grupo" %in% colnames(df)) sd(df$intensidad_media_grupo, na.rm = TRUE) else NA
      
      emo_emoji_map <- c(
        "alegr\u00eda" = "\U0001F60A", "tristeza" = "\U0001F622", "sorpresa" = "\U0001F62E",
        "miedo" = "\U0001F628", "ira" = "\U0001F620", "enfado" = "\U0001F620",
        "neutro" = "\U0001F610", "asco" = "\U0001F922",
        "desprecio" = "\U0001F612", "indiferencia" = "\U0001F611"
      )
      
      # Prosodic emoji builder
      prosodic_emojis_fn <- function(fila) {
        emojis <- c()
        if ("rango_f0_grupo_st" %in% colnames(fila) && !is.na(rango_media_ref) && !is.na(rango_sd_ref)) {
          val <- fila$rango_f0_grupo_st
          if (!is.na(val)) {
            if (val > rango_media_ref + rango_sd_ref) emojis <- c(emojis, "\U0001F3BB")
            else if (val < rango_media_ref - rango_sd_ref) emojis <- c(emojis, "\U0001F3B7")
          }
        }
        if ("velocidad_habla" %in% colnames(fila) && !is.na(vel_media_ref) && !is.na(vel_sd_ref)) {
          vel <- fila$velocidad_habla
          if (!is.na(vel)) {
            if (vel > vel_media_ref + vel_sd_ref) emojis <- c(emojis, "\U0001F680")
            else if (vel < vel_media_ref - vel_sd_ref) emojis <- c(emojis, "\U0001F422")
          }
        }
        if ("intensidad_media_grupo" %in% colnames(fila) && !is.na(int_media_ref) && !is.na(int_sd_ref)) {
          int_val <- fila$intensidad_media_grupo
          if (!is.na(int_val)) {
            if (int_val > int_media_ref + int_sd_ref) emojis <- c(emojis, "\U0001F50A")
            else if (int_val < int_media_ref - int_sd_ref) emojis <- c(emojis, "\U0001F507")
          }
        }
        if ("inflexion_final_pct" %in% colnames(fila)) {
          pct <- fila$inflexion_final_pct
          if (!is.na(pct)) {
            if (pct > 10) emojis <- c(emojis, "\U00002B06\U0000FE0F")
            else if (pct < -10) emojis <- c(emojis, "\U00002B07\U0000FE0F")
          }
        }
        if ("duracion" %in% colnames(fila) && !is.na(dur_media_ref) && !is.na(dur_sd_ref)) {
          dur <- fila$duracion
          if (!is.na(dur)) {
            if (dur > dur_media_ref + dur_sd_ref) emojis <- c(emojis, "\U0001F570\U0000FE0F")
            else if (dur < dur_media_ref - dur_sd_ref) emojis <- c(emojis, "\U000023F1\U0000FE0F")
          }
        }
        paste(emojis, collapse = "")
      }
      
      # Context builder function (reusable)
construir_contexto_html <- function(idx_fila, n_contexto = 5) {
  fila_actual <- df[idx_fila, , drop = FALSE]
  fn_actual <- if ("filename" %in% colnames(fila_actual)) fila_actual$filename else NA
  
  if (!is.na(fn_actual) && "filename" %in% colnames(df) && "inicio" %in% colnames(df)) {
    
    # Todos los GEs del mismo archivo, ordenados por tiempo de inicio
    same_file_idx <- which(df$filename == fn_actual)
    orden_temporal <- same_file_idx[order(df$inicio[same_file_idx])]
    
    # Posición del GE actual dentro del orden temporal
    pos_in_file <- which(orden_temporal == idx_fila)
    if (length(pos_in_file) == 0) pos_in_file <- 1
    
    # Ventana de ±n_contexto en orden temporal
    rango_inicio <- max(1, pos_in_file - n_contexto)
    rango_fin    <- min(length(orden_temporal), pos_in_file + n_contexto)
    indices_mostrar <- orden_temporal[rango_inicio:rango_fin]
    
  } else {
    # Fallback sin tiempo: ventana simple por posición
    rango_inicio <- max(1, idx_fila - n_contexto)
    rango_fin    <- min(nrow(df), idx_fila + n_contexto)
    indices_mostrar <- rango_inicio:rango_fin
  }
  
  filas_html <- c()
  for (r in indices_mostrar) {
    fila <- df[r, , drop = FALSE]
    txt <- if ("palabras_grupo" %in% colnames(fila) && !is.na(fila$palabras_grupo)) fila$palabras_grupo
           else if ("texto" %in% colnames(fila) && !is.na(fila$texto)) fila$texto else ""
    spk  <- if ("hablante" %in% colnames(fila)) fila$hablante else ""
    amh  <- if ("amh_patron" %in% colnames(fila) && !is.na(fila$amh_patron)) fila$amh_patron else ""
    t_ini <- if ("inicio" %in% colnames(fila) && !is.na(fila$inicio)) 
               paste0(floor(fila$inicio / 60), ":", sprintf("%05.2f", fila$inicio %% 60))
             else ""
    emo  <- if ("emocion_manual" %in% colnames(fila) && !is.na(fila$emocion_manual)) fila$emocion_manual else "neutro"
    emo_icon <- if (emo %in% names(emo_emoji_map)) emo_emoji_map[emo] else "\U0001F610"
    
    # Etiquetas de contraste (sentimiento, emocion_texto, emocion_audio)
    contrast_parts <- c()
    if ("sentimiento" %in% colnames(fila) && !is.na(fila$sentimiento) && fila$sentimiento != "")
      contrast_parts <- c(contrast_parts, paste0('<span style="background:#e8f5e9;padding:1px 4px;border-radius:3px;font-size:0.75em;">S:', fila$sentimiento, '</span>'))
    if ("emocion_texto" %in% colnames(fila) && !is.na(fila$emocion_texto) && fila$emocion_texto != "")
      contrast_parts <- c(contrast_parts, paste0('<span style="background:#e3f2fd;padding:1px 4px;border-radius:3px;font-size:0.75em;">T:', fila$emocion_texto, '</span>'))
    if ("emocion_audio" %in% colnames(fila) && !is.na(fila$emocion_audio) && fila$emocion_audio != "" && fila$emocion_audio != "no_wav")
      contrast_parts <- c(contrast_parts, paste0('<span style="background:#fce4ec;padding:1px 4px;border-radius:3px;font-size:0.75em;">A:', fila$emocion_audio, '</span>'))
    contrast_html <- if (length(contrast_parts) > 0) paste0('<span class="ctx-contrast">', paste(contrast_parts, collapse=" "), '</span>') else ""
    
    pros     <- prosodic_emojis_fn(fila)
    es_actual <- (r == idx_fila)
    clase    <- if (es_actual) "ctx-fila ctx-fila-actual" else "ctx-fila ctx-fila-contexto"
    
    # Color diferenciador por hablante (borde izquierdo)
    # Asignar un color por posición en la lista de hablantes del archivo
    habs_archivo <- if (!is.na(fn_actual)) unique(df$hablante[df$filename == fn_actual]) else character(0)
    idx_hab <- match(spk, habs_archivo)
    colores_hablante <- c("#3498db","#e74c3c","#27ae60","#f39c12","#9b59b6","#1abc9c","#e67e22","#2c3e50")
    color_hab <- if (!is.na(idx_hab) && length(habs_archivo) > 1) colores_hablante[(idx_hab - 1) %% length(colores_hablante) + 1] else "transparent"
    borde_hab <- if (length(habs_archivo) > 1) paste0("border-left: 4px solid ", color_hab, ";") else ""
    
    filas_html <- c(filas_html, paste0(
      '<div class="', clase, '" style="', borde_hab, '">',
      '<span style="min-width:55px;font-size:0.75em;color:#999;margin-right:4px;">', t_ini, '</span>',
      '<span class="ctx-emojis">', emo_icon, pros, '</span>',
      '<span class="ctx-hablante" style="color:', color_hab, ';font-weight:bold;">[', htmltools::htmlEscape(spk), ']</span>',
      '<span class="ctx-texto">', htmltools::htmlEscape(txt), '</span>',
      contrast_html,
      '<span class="ctx-amh">', amh, '</span>',
      '</div>'
    ))
  }
  paste(filas_html, collapse = "\n")
}
      
      # ============================================================
      # COMENTARIOS: IA o verbose
      # ============================================================
      comentario_modo <- if (!is.null(input$inf_comentarios_modo)) input$inf_comentarios_modo else "ninguno"
      ia_api_key <- if (!is.null(input$inf_ia_api_key)) trimws(input$inf_ia_api_key) else ""
      ia_provider <- if (!is.null(input$inf_ia_provider)) input$inf_ia_provider else "anthropic"
      ia_model <- if (!is.null(input$inf_ia_model)) input$inf_ia_model else "claude-sonnet-4-6"
      
      # CSS para bloques de comentario
      html <- c(html, '<style>',
        '.comentario-ia { background: #e8f4f8; border-left: 4px solid #17a2b8; padding: 12px 18px; margin: 15px 0; border-radius: 4px; font-size: 0.95em; line-height: 1.7; }',
        '.comentario-ia h4 { color: #17a2b8; margin-top: 0; font-size: 1em; }',
        '.analisis-detallado { background: #f5f0ff; border-left: 4px solid #6f42c1; padding: 12px 18px; margin: 15px 0; border-radius: 4px; font-size: 0.93em; line-height: 1.6; white-space: pre-wrap; font-family: "Segoe UI", Arial, sans-serif; }',
        '.analisis-detallado h4 { color: #6f42c1; margin-top: 0; font-size: 1em; }',
        '</style>')
      
      # Función: llamar API de IA
      call_ai_api <- function(prompt, seccion_name = "") {
        if (!requireNamespace("httr", quietly = TRUE) || !requireNamespace("jsonlite", quietly = TRUE)) {
          return("[Instalar paquetes httr y jsonlite: install.packages(c('httr', 'jsonlite'))]")
        }
        tryCatch({
          if (ia_provider == "anthropic") {
            resp <- httr::POST(
              "https://api.anthropic.com/v1/messages",
              httr::add_headers(
                "x-api-key" = ia_api_key,
                "anthropic-version" = "2023-06-01",
                "content-type" = "application/json"
              ),
              body = jsonlite::toJSON(list(
                model = ia_model,
                max_tokens = 1500,
                messages = list(list(role = "user", content = prompt))
              ), auto_unbox = TRUE),
              encode = "raw"
            )
            if (httr::status_code(resp) == 200) {
              content <- jsonlite::fromJSON(httr::content(resp, "text", encoding = "UTF-8"))
              return(content$content[[1]]$text)
            } else {
              return(paste0("[Error API Anthropic: ", httr::status_code(resp), "]"))
            }
          } else {
            resp <- httr::POST(
              "https://api.openai.com/v1/chat/completions",
              httr::add_headers(
                "Authorization" = paste("Bearer", ia_api_key),
                "Content-Type" = "application/json"
              ),
              body = jsonlite::toJSON(list(
                model = ia_model,
                max_tokens = 1500,
                messages = list(list(role = "user", content = prompt))
              ), auto_unbox = TRUE),
              encode = "raw"
            )
            if (httr::status_code(resp) == 200) {
              content <- jsonlite::fromJSON(httr::content(resp, "text", encoding = "UTF-8"))
              return(content$choices[[1]]$message$content)
            } else {
              return(paste0("[Error API OpenAI: ", httr::status_code(resp), "]"))
            }
          }
        }, error = function(e) paste0("[Error conexión: ", e$message, "]"))
      }
      
      # Función: generar bloque de comentario según modo
      generar_comentario <- function(seccion_name, datos_texto, contexto = "") {
        if (comentario_modo == "ninguno") return("")
        
        info_filtro <- ""
        if (!is.null(var_filtro)) info_filtro <- paste0("Filtro aplicado: ", var_filtro, " = ", paste(input$inf_valores_filtro, collapse = ", "), ". ")
        if (!is.null(var_cat)) info_filtro <- paste0(info_filtro, "Agrupación por: ", var_cat, ". ")
        
        if (comentario_modo == "ia" && nchar(ia_api_key) > 0) {
          prompt <- paste0(
            "Eres un experto en fonética, prosodia y análisis del habla. Analiza los siguientes resultados de la sección '",
            seccion_name, "' de un informe de análisis prosódico. ", info_filtro,
            "Proporciona una interpretación detallada y pormenorizada en español, señalando patrones relevantes, ",
            "diferencias significativas entre grupos (si los hay), implicaciones lingüísticas y posibles explicaciones prosódicas. ",
            "Sé específico con los números y valores. No uses formato markdown. ",
            if (nchar(contexto) > 0) paste0("Contexto adicional: ", contexto, ". ") else "",
            "\n\nDatos:\n", datos_texto
          )
          resp <- call_ai_api(prompt, seccion_name)
          return(paste0('<div class="comentario-ia"><h4>\U0001F916 Interpretación IA (', seccion_name, ')</h4>', 
                         htmltools::htmlEscape(resp), '</div>'))
        } else if (comentario_modo == "verbose") {
          return(paste0(
            '<div class="analisis-detallado"><h4>\U0001F4CA Análisis detallado: ', seccion_name, '</h4>',
            info_filtro,
            '\n\n', htmltools::htmlEscape(datos_texto), '</div>'
          ))
        }
        ""
      }
      
      # Helper: resumir un dataframe de estadísticos en texto
      df_to_text <- function(d) {
        if (is.null(d) || nrow(d) == 0) return("Sin datos.")
        lines <- c()
        for (i in 1:nrow(d)) {
          vals <- sapply(colnames(d), function(col) {
            v <- d[[col]][i]
            if (is.numeric(v)) paste0(col, "=", round(v, 3))
            else paste0(col, "=", as.character(v))
          })
          lines <- c(lines, paste(vals, collapse = ", "))
        }
        paste(lines, collapse = "\n")
      }
      
      seccion_num <- 0  # Initialize section counter
      
      incProgress(0.05, detail = "Corpus...")
      if ("corpus" %in% secciones) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Descripción del Corpus</h2>'))
        
        # Gather counts from all data sources using the same filter context (filename, hablante)
        fns_in_df <- unique(df$filename[!is.na(df$filename)])
        spks_in_df <- unique(df$hablante[!is.na(df$hablante)])
        
        n_archivos <- length(fns_in_df)
        n_hablantes <- length(spks_in_df)
        n_ges <- nrow(df)
        
        n_gfs <- 0
        if (!is.null(datos$gfs_resumen) && nrow(datos$gfs_resumen) > 0) {
          gfs_f <- datos$gfs_resumen[datos$gfs_resumen$filename %in% fns_in_df & datos$gfs_resumen$hablante %in% spks_in_df, ]
          n_gfs <- nrow(gfs_f)
        }
        
        n_palabras <- 0
        if (!is.null(datos$words) && nrow(datos$words) > 0) {
          wd_f <- datos$words[datos$words$filename %in% fns_in_df & datos$words$hablante %in% spks_in_df, ]
          n_palabras <- nrow(wd_f)
        }
        
        n_vocales <- 0
        if (!is.null(datos$phones) && nrow(datos$phones) > 0) {
          ph_f <- datos$phones[datos$phones$filename %in% fns_in_df & datos$phones$hablante %in% spks_in_df, ]
          n_vocales <- nrow(ph_f)
        }
        
        n_clausulas <- 0
        if (!is.null(datos$clausulas) && nrow(datos$clausulas) > 0) {
          cl_f <- datos$clausulas[datos$clausulas$filename %in% fns_in_df & datos$clausulas$hablante %in% spks_in_df, ]
          n_clausulas <- nrow(cl_f)
        }
        
        corpus_df <- data.frame(
          Elemento = c("Archivos", "Hablantes", "Vocales (phones)", "Palabras (words)", 
                       "Grupos fónicos", "Grupos entonativos", "Cláusulas entonativas"),
          N = c(n_archivos, n_hablantes, n_vocales, n_palabras, n_gfs, n_ges, n_clausulas),
          stringsAsFactors = FALSE
        )
        html <- c(html, '<h3>Resumen global</h3>', df_to_html(corpus_df))
        
        # Grouped breakdown if var_cat is set
        if (!is.null(var_cat) && var_cat %in% colnames(df)) {
          html <- c(html, paste0('<h3>Desglose por ', var_cat, '</h3>'))
          
          cats <- sort(unique(na.omit(df[[var_cat]])))
          corpus_by_cat <- data.frame()
          
          # Helper: contar filas de una tabla que caen (temporalmente) dentro de los GEs de df_c
          # Estrategia: para cada filename+hablante, construir unión de intervalos [inicio,fin]
          # de los GEs de la categoría, y contar filas de 'tab' cuyo 'inicio' cae en alguno de ellos.
          contar_por_ges <- function(tab, df_c, col_inicio = "inicio") {
            if (is.null(tab) || nrow(tab) == 0 || !col_inicio %in% colnames(tab)) return(0L)
            if (!all(c("filename", "hablante", "inicio", "fin") %in% colnames(df_c))) return(0L)
            total <- 0L
            for (fn_h in unique(paste(df_c$filename, df_c$hablante, sep = "|||"))) {
              parts   <- strsplit(fn_h, "|||", fixed = TRUE)[[1]]
              fn_v    <- parts[1]; spk_v <- parts[2]
              ge_rows <- df_c[df_c$filename == fn_v & df_c$hablante == spk_v, ]
              if (nrow(ge_rows) == 0) next
              tab_fh  <- tab[tab$filename == fn_v & tab$hablante == spk_v, ]
              if (nrow(tab_fh) == 0) next
              t_ini   <- tab_fh[[col_inicio]]
              # Contar cada fila cuyo inicio cae dentro de algún [inicio,fin] de GE
              in_any  <- vapply(t_ini, function(t) {
                any(!is.na(ge_rows$inicio) & !is.na(ge_rows$fin) &
                    t >= ge_rows$inicio & t <= ge_rows$fin)
              }, logical(1))
              total <- total + sum(in_any, na.rm = TRUE)
            }
            total
          }
          
          for (cat_val in cats) {
            df_c    <- df[!is.na(df[[var_cat]]) & df[[var_cat]] == cat_val, ]
            c_fns   <- unique(df_c$filename)
            c_spks  <- unique(df_c$hablante)
            c_n_ges <- nrow(df_c)
            
            # GFs: contar GFs únicos cuyos GEs pertenecen a esta categoría
            # (un GF puede contener GEs de distintas categorías — contamos los que tienen ≥1 GE aquí)
            c_gfs <- 0L
            if (!is.null(datos$gfs_resumen) && nrow(datos$gfs_resumen) > 0 &&
                all(c("filename","hablante","grupo_fonico") %in% colnames(df_c)) &&
                all(c("filename","hablante","grupo_fonico") %in% colnames(datos$gfs_resumen))) {
              gf_keys_c <- unique(paste(df_c$filename, df_c$hablante, df_c$grupo_fonico, sep = "|||"))
              gf_keys_all <- paste(datos$gfs_resumen$filename, datos$gfs_resumen$hablante,
                                   datos$gfs_resumen$grupo_fonico, sep = "|||")
              c_gfs <- sum(gf_keys_all %in% gf_keys_c)
            }
            
            # Phones/vocales: cruce temporal con GEs de esta categoría
            c_voc <- contar_por_ges(datos$phones, df_c)
            
            # Words/palabras: cruce temporal
            c_pal <- contar_por_ges(datos$words, df_c)
            
            # Cláusulas: cruce temporal
            c_cl <- 0L
            if (!is.null(datos$clausulas) && nrow(datos$clausulas) > 0) {
              # clausulas puede tener 'inicio' directamente o derivarlo de ips
              if ("inicio" %in% colnames(datos$clausulas)) {
                c_cl <- contar_por_ges(datos$clausulas, df_c)
              } else if ("clausula_id" %in% colnames(df_c)) {
                # Alternativa: contar cláusulas únicas referenciadas en df_c
                c_cl <- length(unique(na.omit(df_c$clausula_id)))
              }
            }
            
            corpus_by_cat <- bind_rows(corpus_by_cat, data.frame(
              Grupo = cat_val, Archivos = length(c_fns), Hablantes = length(c_spks),
              Vocales = c_voc, Palabras = c_pal, GFs = c_gfs, GEs = c_n_ges,
              stringsAsFactors = FALSE
            ))
          }
          html <- c(html, df_to_html(corpus_by_cat))
          
          # Bar chart: % de GEs por categoría
          tryCatch({
            img_corpus <- save_and_embed(quote({
              library(ggplot2)
              df_ges <- corpus_by_cat[, c("Grupo", "GEs")]
              df_ges$Pct <- df_ges$GEs / sum(df_ges$GEs, na.rm=TRUE) * 100
              df_ges$Grupo <- factor(df_ges$Grupo, levels=df_ges$Grupo[order(-df_ges$Pct)])
              n_cats_dist <- nrow(df_ges)
              pal_dist <- colorRampPalette(RColorBrewer::brewer.pal(min(8L, max(3L, n_cats_dist)), "Set2"))(n_cats_dist)
              p <- ggplot(df_ges, aes(x=Grupo, y=Pct, fill=Grupo)) +
                geom_bar(stat="identity", width=0.65, show.legend=FALSE) +
                geom_text(aes(label=sprintf("%.1f%%
(n=%d)", Pct, GEs)),
                          vjust=-0.3, size=3.2) +
                scale_fill_manual(values = pal_dist) +
                scale_y_continuous(expand=expansion(mult=c(0, 0.12)), labels=function(x) paste0(x, "%")) +
                theme_minimal(base_size=11) +
                labs(title=paste0("Distribución de GEs por ", var_cat),
                     x=var_cat, y="% de GEs") +
                theme(axis.text.x=element_text(angle=45, hjust=1),
                      panel.grid.major.x=element_blank())
              print(p)
            }), "corpus_por_categoria", ancho=10, alto=6)
            html <- c(html, img_corpus)
            fig_num <- fig_num + 1
            html <- c(html, paste0('<p class="meta"><em>Figura ', fig_num, '. Distribución del corpus por categoría.</em></p>'))
          }, error = function(e) {
            html <<- c(html, paste0('<p class="warning-box">Error generando gráfico: ', e$message, '</p>'))
          })
        }
      }
      
      # ================================================================
      # WRAPPER: modo "por_grupo" vs "entre_grupos"
      # En modo "por_grupo", iteramos sobre cada categoría y generamos
      # las secciones restantes para cada una por separado.
      # En modo "entre_grupos", iteramos una sola vez con todos los datos.
      # ================================================================
      df_full <- df  # Save full dataset
      var_cat_orig <- var_cat
      # seccion_num continues from corpus section (not reset here)
      
      if (!is.null(var_cat) && modo_comp == "por_grupo" && var_cat %in% colnames(df)) {
        grupos_iter <- sort(unique(na.omit(df[[var_cat]])))
        grupos_iter <- grupos_iter[grupos_iter != ""]
      } else {
        grupos_iter <- list(NULL)  # Single iteration
      }
      
      for (grupo_actual in grupos_iter) {
        if (!is.null(grupo_actual)) {
          # Mode: por_grupo — filter to this group, disable inner grouping
          df <- df_full[!is.na(df_full[[var_cat_orig]]) & df_full[[var_cat_orig]] == grupo_actual, ]
          var_cat <- NULL  # No inner grouping within a single group
          seccion_num <- 0  # Reset section numbering for each group
          if (nrow(df) == 0) next
          html <- c(html, paste0('<h2 style="background:#2c3e50;color:white;padding:12px 20px;border-radius:6px;margin-top:40px;">',
                                  '\U0001F539 ', htmltools::htmlEscape(as.character(grupo_actual)), 
                                  ' <span style="font-size:0.7em;font-weight:normal;">(n=', nrow(df), ')</span></h2>'))
        } else {
          # Mode: entre_grupos — use full data, keep var_cat for comparisons
          df <- df_full
          var_cat <- var_cat_orig
        }
      
      incProgress(0.1, detail = "Descriptiva...")
      if ("descriptiva" %in% secciones) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Estadística Descriptiva', 
          if (usar_z) ' <span style="font-size:0.7em;">(valores Z por hablante + valores originales)</span>' else '', '</h2>'))
        
        if (usar_z && !is.null(var_cat) && var_cat %in% colnames(df)) {
          # Z-mode with grouping: show combined table Z + original per group (the useful view)
          html <- c(html, paste0('<h3>Comparativa por ', var_cat, ' (Z + original)</h3>'))
          html <- c(html, '<p>La media Z indica cuánto se desvía cada categoría de la media individual de cada hablante. ',
                    'La media original muestra el valor absoluto en la unidad real.</p>')
          
          grupos_desc <- sort(unique(na.omit(df[[var_cat]])))
          
          # Build a combined table: Variable | grupo1_Z | grupo1_orig | grupo2_Z | grupo2_orig | ...
          combined_rows <- lapply(vars_num, function(v) {
            row <- data.frame(Variable = v, stringsAsFactors = FALSE)
            v_orig <- paste0(v, "_orig")
            for (g in grupos_desc) {
              df_g <- df[!is.na(df[[var_cat]]) & df[[var_cat]] == g, ]
              xz <- df_g[[v]][!is.na(df_g[[v]])]
              xo <- if (v_orig %in% colnames(df_g)) df_g[[v_orig]][!is.na(df_g[[v_orig]])] else numeric(0)
              row[[paste0(g, "_Z")]] <- if (length(xz) > 0) round(mean(xz), 3) else NA
              row[[paste0(g, "_orig")]] <- if (length(xo) > 0) round(mean(xo), 2) else NA
              row[[paste0(g, "_n")]] <- length(xz)
            }
            row
          })
          combined_df <- do.call(rbind, combined_rows)
          tab_num <- tab_num + 1
          html <- c(html, df_to_html(combined_df),
            paste0('<p class="meta"><em>Tabla ', tab_num, '. Comparativa Z y valores originales por ', var_cat, 
                   '. Z>0 indica valor superior a la media del hablante.</em></p>'))
          
          # Also show per-group detail tables
          for (g in grupos_desc) {
            df_g <- df[!is.na(df[[var_cat]]) & df[[var_cat]] == g, ]
            desc_g <- lapply(vars_num, function(v) {
              x <- df_g[[v]]; x <- x[!is.na(x)]
              v_orig <- paste0(v, "_orig")
              xo <- if (v_orig %in% colnames(df_g)) df_g[[v_orig]][!is.na(df_g[[v_orig]])] else numeric(0)
              data.frame(Variable=v, N=length(x), 
                         Media_Z=if(length(x)>0) round(mean(x),3) else NA, 
                         DE_Z=if(length(x)>0) round(sd(x),3) else NA,
                         Media_orig=if(length(xo)>0) round(mean(xo),2) else NA,
                         DE_orig=if(length(xo)>0) round(sd(xo),2) else NA,
                         Mediana_orig=if(length(xo)>0) round(median(xo),2) else NA,
                         stringsAsFactors=FALSE)
            })
            tab_num <- tab_num + 1
            html <- c(html, paste0('<h4>', htmltools::htmlEscape(g), ' (n=', nrow(df_g), ')</h4>'),
              df_to_html(tryCatch(do.call(rbind, Filter(Negate(is.null), desc_g)), error = function(e) data.frame(Error=paste('Error al construir tabla:', e$message), stringsAsFactors=FALSE))),
              paste0('<p class="meta"><em>Tabla ', tab_num, '. Descriptiva para ', g, '.</em></p>'))
          }
        } else {
          # Standard descriptive (no Z or no grouping)
          desc_list <- lapply(vars_num, function(v) {
            x <- df[[v]]; x <- x[!is.na(x)]
            row <- if (length(x) == 0) data.frame(Variable=v, N=0, Media=NA, DE=NA, Min=NA, Q1=NA, Mediana=NA, Q3=NA, Max=NA)
                   else data.frame(Variable=v, N=length(x), Media=round(mean(x),3), DE=round(sd(x),3), Min=round(min(x),3),
                       Q1=round(quantile(x,0.25),3), Mediana=round(median(x),3), Q3=round(quantile(x,0.75),3), Max=round(max(x),3), stringsAsFactors=FALSE)
            row
          })
          desc_df <- do.call(rbind, desc_list)
          tab_num <- tab_num + 1
          html <- c(html, '<h3>Resumen global</h3>', df_to_html(desc_df),
            paste0('<p class="meta"><em>Tabla ', tab_num, '. Estadística descriptiva global (N=', nrow(df), ').</em></p>'))
          if (!is.null(var_cat) && var_cat %in% colnames(df)) {
            html <- c(html, paste0('<h3>Descriptiva por ', var_cat, '</h3>'))
            for (g in unique(na.omit(df[[var_cat]]))) {
              df_g <- df[df[[var_cat]] == g & !is.na(df[[var_cat]]), ]
              desc_g <- lapply(vars_num, function(v) {
                x <- df_g[[v]]; x <- x[!is.na(x)]
                if (length(x)==0) return(data.frame(Variable=v,N=0,Media=NA,DE=NA))
                data.frame(Variable=v, N=length(x), Media=round(mean(x),3), DE=round(sd(x),3), Mediana=round(median(x),3), stringsAsFactors=FALSE)
              })
              tab_num <- tab_num + 1
              html <- c(html, paste0('<h4>', htmltools::htmlEscape(g), ' (n=', nrow(df_g), ')</h4>'), 
                df_to_html(tryCatch(do.call(rbind, Filter(Negate(is.null), desc_g)), error = function(e) data.frame(Error=paste('Error al construir tabla:', e$message), stringsAsFactors=FALSE))),
                paste0('<p class="meta"><em>Tabla ', tab_num, '. Descriptiva para ', g, ' (n=', nrow(df_g), ').</em></p>'))
            }
          }
        }
        # Comentario descriptiva
        if (comentario_modo != "ninguno") {
          desc_text <- ""
          if (usar_z && !is.null(var_cat) && var_cat %in% colnames(df)) {
            desc_text <- paste0("Valores Z normalizados por hablante. N=", nrow(df), ".\n")
            for (g in sort(unique(na.omit(df[[var_cat]])))) {
              df_g <- df[!is.na(df[[var_cat]]) & df[[var_cat]] == g, ]
              desc_text <- paste0(desc_text, "\nGrupo '", g, "' (n=", nrow(df_g), "):\n")
              for (v in vars_num) {
                xz <- df_g[[v]][!is.na(df_g[[v]])]
                v_orig <- paste0(v, "_orig")
                xo <- if (v_orig %in% colnames(df_g)) df_g[[v_orig]][!is.na(df_g[[v_orig]])] else numeric(0)
                if (length(xz) > 0) {
                  desc_text <- paste0(desc_text, v, ": Z=", round(mean(xz),2))
                  if (length(xo) > 0) desc_text <- paste0(desc_text, " (orig=", round(mean(xo),2), ")")
                  desc_text <- paste0(desc_text, ". ")
                }
              }
            }
          } else {
            if (exists("desc_df")) desc_text <- df_to_text(desc_df) else desc_text <- paste0("N=", nrow(df), ".\n")
            if (!is.null(var_cat) && var_cat %in% colnames(df)) {
              for (g in unique(na.omit(df[[var_cat]]))) {
                df_g <- df[df[[var_cat]] == g & !is.na(df[[var_cat]]), ]
                desc_text <- paste0(desc_text, "\n\nGrupo '", g, "' (n=", nrow(df_g), "):\n")
                for (v in vars_num) {
                  x <- df_g[[v]][!is.na(df_g[[v]])]
                  if (length(x) > 0) desc_text <- paste0(desc_text, v, ": M=", round(mean(x),2), ", DE=", round(sd(x),2), ", Md=", round(median(x),2), ". ")
                }
              }
            }
          }
          html <- c(html, generar_comentario("Estadística descriptiva", desc_text))
        }
      }

      incProgress(0.05, detail = "Léxico...")
      if ("lexico" %in% secciones) {
        if (is.null(datos$words) || nrow(datos$words) == 0) {
          seccion_num <- seccion_num + 1
          html <- c(html, paste0('<h2>', seccion_num, '. Análisis Léxico</h2>'),
                    '<p class="meta"><em>No hay datos de palabras (tier de words) en este análisis; sección omitida.</em></p>')
        } else {
          seccion_num <- seccion_num + 1
          html <- c(html, paste0('<h2>', seccion_num, '. Análisis Léxico</h2>'))

          # ---- Opciones (con valores por defecto) ----
          lex_forma    <- if (!is.null(input$inf_lex_forma)) input$inf_lex_forma else "etiqueta"
          lex_excl_sw  <- if (!is.null(input$inf_lex_stopwords)) isTRUE(input$inf_lex_stopwords) else TRUE
          lex_top      <- if (!is.null(input$inf_lex_top)) max(5L, as.integer(input$inf_lex_top)) else 25L
          lex_ng_n     <- if (!is.null(input$inf_lex_ng_n)) max(2L, as.integer(input$inf_lex_ng_n)) else 2L
          lex_ng_top   <- if (!is.null(input$inf_lex_ng_top)) max(5L, as.integer(input$inf_lex_ng_top)) else 15L
          lex_nube_on  <- if (!is.null(input$inf_lex_nube)) isTRUE(input$inf_lex_nube) else TRUE
          lex_nube_top <- if (!is.null(input$inf_lex_nube_top)) max(20L, as.integer(input$inf_lex_nube_top)) else 80L
          lex_porgrupo <- if (!is.null(input$inf_lex_por_grupo)) isTRUE(input$inf_lex_por_grupo) else TRUE
          forma_lbl    <- if (lex_forma == "lemma") "lema (UDPipe)" else "forma de superficie"

          # ---- Restringir words al ámbito del informe (mismos archivos y hablantes que df) ----
          w_scope    <- datos$words
          fns_scope  <- unique(df$filename[!is.na(df$filename)])
          spks_scope <- unique(df$hablante[!is.na(df$hablante)])
          if ("filename" %in% colnames(w_scope) && length(fns_scope) > 0)
            w_scope <- w_scope[!is.na(w_scope$filename) & w_scope$filename %in% fns_scope, ]
          if ("hablante" %in% colnames(w_scope) && length(spks_scope) > 0)
            w_scope <- w_scope[!is.na(w_scope$hablante) & w_scope$hablante %in% spks_scope, ]

          # ---- Helper local: tabla de n-gramas a partir de tokens ----
          ngrams_tab <- function(toks, n, top) {
            if (length(toks) < n) return(NULL)
            idx <- seq_len(length(toks) - n + 1L)
            ng  <- vapply(idx, function(i) paste(toks[i:(i + n - 1L)], collapse = " "), character(1))
            if (!length(ng)) return(NULL)
            fr  <- sort(table(ng), decreasing = TRUE); fr <- head(fr, top); tot <- length(ng)
            data.frame(Ngrama = names(fr), Frec = as.integer(fr),
                       Pct = round(as.numeric(fr) / tot * 100, 2), stringsAsFactors = FALSE)
          }

          if (is.null(w_scope) || nrow(w_scope) == 0) {
            html <- c(html, '<p class="meta"><em>No hay palabras para los archivos/hablantes del ámbito del informe.</em></p>')
          } else {
            # ===== 1) GLOBAL: frecuencia + TTR =====
            toks_glob <- get_lexico_tokens(w_scope, forma = lex_forma, excluir_sw = lex_excl_sw)
            n_tok  <- length(toks_glob)
            n_type <- length(unique(toks_glob))
            ttr_glob <- if (n_tok > 0) round(calc_ttr(toks_glob) * 100, 1) else NA_real_

            html <- c(html, '<h3>Frecuencia y diversidad léxica (global)</h3>',
                      paste0('<p class="meta">Análisis sobre la <strong>', forma_lbl, '</strong>, ',
                             if (lex_excl_sw) "excluyendo" else "incluyendo", ' palabras vacías. Total: <strong>',
                             n_tok, '</strong> tokens / <strong>', n_type, '</strong> types. TTR global: <strong>',
                             if (!is.na(ttr_glob)) paste0(ttr_glob, '%') else '—', '</strong>.</p>'))

            freq_glob_df <- NULL
            if (n_tok > 0) {
              fr <- head(sort(table(toks_glob), decreasing = TRUE), lex_top)
              freq_glob_df <- data.frame(Rango = seq_along(fr), Palabra = names(fr),
                                         Frec = as.integer(fr),
                                         Pct = round(as.numeric(fr) / n_tok * 100, 2),
                                         PorMil = round(as.numeric(fr) / n_tok * 1000, 2),
                                         stringsAsFactors = FALSE)
              html <- c(html, df_to_html(freq_glob_df, max_rows = lex_top))
            }

            # ===== 2) GLOBAL: n-gramas (bigramas por defecto) =====
            toks_glob_ng <- get_lexico_tokens(w_scope, forma = "etiqueta", excluir_sw = lex_excl_sw)
            ng_glob_df <- ngrams_tab(toks_glob_ng, lex_ng_n, lex_ng_top)
            html <- c(html, paste0('<h3>', lex_ng_n, '-gramas más frecuentes (global)</h3>'))
            if (!is.null(ng_glob_df)) html <- c(html, df_to_html(ng_glob_df, max_rows = lex_ng_top))
            else html <- c(html, '<p class="meta"><em>Tokens insuficientes para n-gramas.</em></p>')

            # ===== 3) NUBE DE PALABRAS (estática, PNG) =====
            if (lex_nube_on && n_tok > 0) {
              if (requireNamespace("ggwordcloud", quietly = TRUE)) {
                fr_wc  <- sort(table(toks_glob), decreasing = TRUE)
                top_wc <- min(lex_nube_top, length(fr_wc))
                df_wc  <- data.frame(word = names(fr_wc)[seq_len(top_wc)],
                                     freq = as.integer(fr_wc)[seq_len(top_wc)],
                                     stringsAsFactors = FALSE)
                # Guarda defensiva: gridtext (geom_text_wordcloud) interpreta marcado;
                # descartar cualquier token residual con <, > o & evita que rompa el informe.
                df_wc <- df_wc[!grepl("[<>&]", df_wc$word), , drop = FALSE]
                html <- c(html, '<h3>Nube de palabras (global)</h3>',
                  save_and_embed(quote({
                    set.seed(42)
                    pal <- rep(c("#0C447C", "#2563eb", "#1D9E75", "#378ADD", "#BA7517"),
                               length.out = nrow(df_wc))
                    print(
                      ggplot2::ggplot(df_wc,
                        ggplot2::aes(label = word, size = freq,
                                     color = factor(seq_len(nrow(df_wc))))) +
                        ggwordcloud::geom_text_wordcloud(rm_outside = TRUE) +
                        ggplot2::scale_size_area(max_size = 18) +
                        ggplot2::scale_color_manual(values = pal, guide = "none") +
                        ggplot2::theme_minimal()
                    )
                  }), nombre = "lexico_nube", ancho = 8, alto = 5))
              } else {
                html <- c(html, '<p class="meta"><em>Nube omitida: instala el paquete ggwordcloud (install.packages("ggwordcloud")).</em></p>')
              }
            }

            # ===== 4) DESGLOSE POR GRUPO (si var_cat es de nivel archivo/hablante) =====
            por_grupo_text <- ""
            if (lex_porgrupo && !is.null(var_cat) && var_cat %in% colnames(df) &&
                all(c("filename", "hablante") %in% colnames(w_scope))) {
              cols_key <- unique(c("filename", "hablante", var_cat))
              key_df <- as.data.frame(df[!is.na(df[[var_cat]]), cols_key, drop = FALSE])
              key_df <- key_df[!duplicated(key_df), , drop = FALSE]
              kv         <- paste(key_df$filename, key_df$hablante, sep = "\r")
              split_vals <- split(as.character(key_df[[var_cat]]), kv)
              es_unico   <- length(split_vals) > 0 &&
                            all(vapply(split_vals, function(z) length(unique(z)) == 1L, logical(1)))

              if (!es_unico) {
                html <- c(html, paste0('<p class="meta"><em>Desglose léxico por grupo no disponible para «',
                          htmltools::htmlEscape(var_cat),
                          '»: es una variable a nivel de grupo entonativo, no de archivo/hablante.</em></p>'))
              } else {
                lookup <- setNames(vapply(split_vals, function(z) unique(z)[1], character(1)),
                                   names(split_vals))
                wk <- paste(w_scope$filename, w_scope$hablante, sep = "\r")
                w_scope$.grupo_lex <- lookup[wk]
                grupos_lex <- sort(unique(w_scope$.grupo_lex[!is.na(w_scope$.grupo_lex)]))
                if (length(grupos_lex) > 0) {
                  html <- c(html, paste0('<h3>Léxico por grupo (', htmltools::htmlEscape(var_cat), ')</h3>'))
                  ttr_rows <- list()
                  for (g in grupos_lex) {
                    w_g  <- w_scope[!is.na(w_scope$.grupo_lex) & w_scope$.grupo_lex == g, ]
                    t_g  <- get_lexico_tokens(w_g, forma = lex_forma, excluir_sw = lex_excl_sw)
                    if (length(t_g) == 0) next
                    t_gn  <- get_lexico_tokens(w_g, forma = "etiqueta", excluir_sw = lex_excl_sw)
                    ttr_g <- round(calc_ttr(t_g) * 100, 1)
                    ttr_rows[[length(ttr_rows) + 1]] <- data.frame(
                      Grupo = g, Tokens = length(t_g), Types = length(unique(t_g)),
                      TTR_pct = ttr_g, stringsAsFactors = FALSE)
                    ng_g <- ngrams_tab(t_gn, lex_ng_n, lex_ng_top)
                    html <- c(html, paste0('<h4>Grupo: ', htmltools::htmlEscape(g), ' — ',
                              length(t_g), ' tokens, TTR ', ttr_g, '%</h4>'))
                    if (!is.null(ng_g)) html <- c(html, df_to_html(ng_g, max_rows = lex_ng_top))
                    por_grupo_text <- paste0(por_grupo_text, "\nGrupo '", g, "': ", length(t_g),
                      " tokens, TTR ", ttr_g, "%. ", lex_ng_n, "-gramas top: ",
                      if (!is.null(ng_g)) paste(head(ng_g$Ngrama, 5), collapse = "; ") else "n/d", ".")
                  }
                  if (length(ttr_rows) > 0) {
                    ttr_tab <- do.call(rbind, ttr_rows)
                    html <- c(html, '<h4>Diversidad léxica (TTR) por grupo</h4>', df_to_html(ttr_tab))
                  }
                }
              }
            }

            # ===== 5) Texto para IA + comentario =====
            lex_text <- paste0(
              "Forma analizada: ", forma_lbl, ". Palabras vacías ",
              if (lex_excl_sw) "excluidas" else "incluidas", ".\n",
              "Tokens totales: ", n_tok, "; types: ", n_type, "; TTR global: ",
              if (!is.na(ttr_glob)) paste0(ttr_glob, "%") else "n/d", ".\n\n",
              "Palabras más frecuentes:\n",
              if (!is.null(freq_glob_df)) df_to_text(freq_glob_df) else "n/d", "\n\n",
              lex_ng_n, "-gramas más frecuentes (global):\n",
              if (!is.null(ng_glob_df)) df_to_text(ng_glob_df) else "n/d",
              if (nchar(por_grupo_text) > 0) paste0("\n\nResumen léxico por grupo:", por_grupo_text) else ""
            )
            html <- c(html, generar_comentario("Análisis léxico", lex_text))
          }
        }
      }

      incProgress(0.2, detail = "Boxplots...")
      # Figure and table counters already initialized above

      if ("boxplots" %in% secciones) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Boxplots y estadística inferencial</h2>'))
        var_idx <- 0
        for (v in vars_num) {
          var_idx <- var_idx + 1
          v_label <- if (usar_z) paste0(v, " (Z)") else v
          html <- c(html, paste0('<h3>', seccion_num, '.', var_idx, '. ', v_label, '</h3>'))
          
          # Show original means per group when Z-scores are active
          if (usar_z && !is.null(medias_orig[[v]]) && !is.null(var_cat)) {
            orig_parts <- paste(sapply(names(medias_orig[[v]]), function(g) {
              paste0(g, "=", medias_orig[[v]][g])
            }), collapse = " | ")
            html <- c(html, paste0('<div class="stat-box" style="background:#fffde7;border-color:#fdd835;font-size:0.9em;">',
                      '<strong>Media original:</strong> ', orig_parts, '</div>'))
          }
          
          if (!is.null(var_cat) && var_cat %in% colnames(df)) {
            # Compute statistical test
            test_label     <- ""
            kw_posthoc_html <- ""
            tryCatch({
              df_test <- df[!is.na(df[[var_cat]]) & !is.na(df[[v]]), ]
              df_test[[var_cat]] <- droplevels(as.factor(df_test[[var_cat]]))
              if (nlevels(df_test[[var_cat]]) >= 2 && nrow(df_test) > 5) {
                grupos <- split(df_test[[v]], df_test[[var_cat]])
                grupos <- grupos[sapply(grupos, length) > 0]
                if (length(grupos) >= 2) {
                  norm_ok <- all(sapply(grupos, function(g) {
                    if (length(g) < 3 || length(g) > 5000) return(FALSE)
                    tryCatch(shapiro.test(g)$p.value > 0.05, error = function(e) FALSE)
                  }))
                  if (norm_ok) {
                    aov_res <- summary(aov(as.formula(paste0("`",v,"` ~ `",var_cat,"`")), data = df_test))
                    p_val <- aov_res[[1]]["Pr(>F)"][[1]][1]
                    f_val <- aov_res[[1]]["F value"][[1]][1]
                    sig <- if (p_val < 0.001) "***" else if (p_val < 0.01) "**" else if (p_val < 0.05) "*" else "n.s."
                    test_label <- paste0("ANOVA: F=", round(f_val, 2), ", p=", format.pval(p_val, digits = 3), " ", sig)
                  } else {
                    kw_res <- kruskal.test(as.formula(paste0("`",v,"` ~ `",var_cat,"`")), data = df_test)
                    p_val <- kw_res$p.value
                    sig <- if (p_val < 0.001) "***" else if (p_val < 0.01) "**" else if (p_val < 0.05) "*" else "n.s."
                    test_label <- paste0("Kruskal-Wallis: H=", round(kw_res$statistic, 2), ", gl=", kw_res$parameter, ", p=", format.pval(p_val, digits = 3), " ", sig)
                    if (!is.na(p_val) && p_val < 0.05) {
                      tryCatch({
                        ph_bp <- pairwise.wilcox.test(df_test[[v]], df_test[[var_cat]],
                                                       p.adjust.method = "holm", exact = FALSE)
                        p_mat_bp  <- ph_bp$p.value
                        rn_bp     <- rownames(p_mat_bp)
                        cn_bp     <- colnames(p_mat_bp)
                        sig_bp    <- which(p_mat_bp < 0.05, arr.ind = TRUE)
                        if (nrow(sig_bp) > 0) {
                          ph_pairs <- apply(sig_bp, 1, function(r) {
                            paste0(rn_bp[r[1]], " vs ", cn_bp[r[2]], " (p=", format.pval(p_mat_bp[r[1],r[2]], 2), ")")
                          })
                          kw_posthoc_html <- paste0('<div style="font-size:11px; margin-top:2px; color:#1a5276;">',
                            '<em>Post-hoc Holm:</em> ', paste(ph_pairs, collapse=" &nbsp;|&nbsp; "), '</div>')
                        } else {
                          kw_posthoc_html <- '<div style="font-size:11px; color:#888;"><em>Post-hoc Holm: ningún par significativo</em></div>'
                        }
                      }, error = function(e) {})
                    }
                  }
                }
              }
            }, error = function(e) {})

            # Show test result as highlighted box
            if (nchar(test_label) > 0) {
              html <- c(html, paste0('<div class="stat-box">', test_label, '</div>'))
              if (nchar(kw_posthoc_html) > 0) {
                html <- c(html, kw_posthoc_html)
              }
            }
            
            fig_num <- fig_num + 1
            img_html <- save_and_embed(quote({
              df_plot <- df[!is.na(df[[var_cat]]) & !is.na(df[[v]]), ]
              y_label <- if (usar_z) paste0(v, " (Z)") else v
              p <- ggplot(df_plot, aes(x=.data[[var_cat]], y=.data[[v]], fill=.data[[var_cat]])) +
                geom_boxplot(outlier.size=1, alpha=0.7) +
                stat_summary(fun=mean, geom="point", shape=18, size=3, color="black") +
                theme_minimal(base_size=13) + coord_flip() +
                labs(title=paste0(v," por ",var_cat), x=var_cat, y=y_label) +
                theme(legend.position="none")
              if (usar_z) {
                p <- p + geom_hline(yintercept=0, linetype="dashed", alpha=0.4, color="red")
                # Annotate with original means
                v_orig <- paste0(v, "_orig")
                if (v_orig %in% colnames(df_plot)) {
                  orig_means <- aggregate(df_plot[[v_orig]], by=list(df_plot[[var_cat]]), FUN=mean, na.rm=TRUE)
                  z_means <- aggregate(df_plot[[v]], by=list(df_plot[[var_cat]]), FUN=mean, na.rm=TRUE)
                  colnames(orig_means) <- c("cat", "orig"); colnames(z_means) <- c("cat", "z")
                  ann_df <- merge(z_means, orig_means)
                  ann_df$label <- paste0("(", round(ann_df$orig, 1), ")")
                  p <- p + geom_text(data=ann_df, aes(x=cat, y=z, label=label), 
                                     inherit.aes=FALSE, hjust=-0.3, size=3, color="#555")
                }
              }
              print(p)
            }), paste0("boxplot_", v))
            html <- c(html, img_html, paste0('<p class="meta"><em>Figura ', fig_num, '. Boxplot de ', v, ' por ', var_cat, 
                     '. El rombo negro indica la media', 
                     if (usar_z) '; entre paréntesis, la media en unidad original. Línea roja = media del hablante (Z=0)' else '',
                     '.</em></p>'))
          } else {
            fig_num <- fig_num + 1
            img_html <- save_and_embed(quote({
              if ("hablante" %in% colnames(df)) {
                p <- ggplot(df[!is.na(df[[v]]),], aes(x=hablante, y=.data[[v]], fill=hablante)) +
                  geom_boxplot(alpha=0.8) + coord_flip() + theme_minimal(base_size=13) + theme(legend.position="none") +
                  labs(title=paste0(v," por hablante"))
                print(p)
              } else {
                p <- ggplot(df[!is.na(df[[v]]),], aes(y=.data[[v]])) +
                  geom_boxplot(fill="#3498db", alpha=0.7) + theme_minimal(base_size=13) + labs(title=v)
                print(p)
              }
            }), paste0("boxplot_", v))
            html <- c(html, img_html, paste0('<p class="meta"><em>Figura ', fig_num, '. Distribución de ', v, '.</em></p>'))
          }
          
          # ---- GAMM por variable ----
          if (usar_gamm) {
            # Validaciones previas (una vez por informe, al procesar la primera variable)
            if (v == vars_num[1]) {
              if (is.null(var_cat) || !var_cat %in% colnames(df))
                html <- c(html, '<div class="warning-box">\u26a0\ufe0f GAMM: selecciona una <strong>Variable de agrupaci\u00f3n</strong> para ajustar el modelo.</div>')
              else if (!requireNamespace("mgcv", quietly = TRUE))
                html <- c(html, '<div class="warning-box">\u26a0\ufe0f GAMM: instala <code>mgcv</code> con <code>install.packages("mgcv")</code>.</div>')
            }
            if (!is.null(var_cat) && var_cat %in% colnames(df) &&
                requireNamespace("mgcv", quietly = TRUE)) {
              tryCatch({
                # ── Preparar df ──────────────────────────────────────────────
                df_gamm <- df[!is.na(df[[v]]) & !is.na(df[[var_cat]]), ]
                if (gamm_familia == "Gamma")
                  df_gamm <- df_gamm[!is.na(df_gamm[[v]]) & df_gamm[[v]] > 0, ]
                
                # ── Construir efectos aleatorios ──────────────────────────────
                re_terms <- character(0)
                re_label <- character(0)   # etiquetas legibles para la caption
                
                if (gamm_usar_re && length(gamm_re_vars) > 0) {
                  for (re_var in gamm_re_vars) {
                    if (re_var == "filename:hablante (ID \u00fanico)") {
                      # Crear columna compuesta
                      if (all(c("filename", "hablante") %in% colnames(df_gamm))) {
                        df_gamm$.re_spk <- paste0(df_gamm$filename, ":", df_gamm$hablante)
                        re_terms  <- c(re_terms, "s(.re_spk, bs = 're')")
                        re_label  <- c(re_label, "filename:hablante")
                      }
                    } else if (re_var %in% colnames(df_gamm)) {
                      # Columna ya existente — crear alias sin caracteres especiales
                      safe_name <- paste0(".re_", make.names(re_var))
                      df_gamm[[safe_name]] <- df_gamm[[re_var]]
                      re_terms <- c(re_terms, paste0("s(", safe_name, ", bs = 're')"))
                      re_label <- c(re_label, re_var)
                    }
                  }
                }
                
                # ── Comprobaciones m\u00ednimas ──────────────────────────────────
                n_levels_fixed <- length(unique(na.omit(df_gamm[[var_cat]])))
                ok_run <- nrow(df_gamm) >= 10 && n_levels_fixed >= 2
                
                # Para cada RE: extraer nombre de columna (hasta la primera coma) y verificar niveles
                re_info <- list()
                for (re_t in re_terms) {
                  re_col <- trimws(sub("^s\\(([^,]+),.*$", "\\1", re_t))
                  n_lev  <- if (re_col %in% colnames(df_gamm))
                               length(unique(na.omit(df_gamm[[re_col]])))
                             else 0L
                  re_info[[re_col]] <- n_lev
                  if (n_lev < 3) ok_run <- FALSE
                }
                
                if (!ok_run) {
                  re_pieces <- vapply(names(re_info),
                                      function(k) paste0(k, "=", re_info[[k]]),
                                      character(1))
                  info_txt <- paste0("n=", nrow(df_gamm),
                    if (length(re_pieces) > 0)
                      paste0(", niveles RE: ", paste(re_pieces, collapse = "; "))
                    else "")
                  html <- c(html, paste0(
                    '<div class="warning-box">GAMM omitido para <em>', v,
                    '</em>: datos insuficientes (', info_txt, ').</div>'))
                } else {
                  # ── Convertir columnas RE a factor (mgcv bs='re' lo requiere) ──
                  re_col_names <- trimws(sub("^s\\(([^,]+),.*$", "\\1", re_terms))
                  for (rc in re_col_names) {
                    if (rc %in% colnames(df_gamm) && !is.factor(df_gamm[[rc]]))
                      df_gamm[[rc]] <- factor(df_gamm[[rc]])
                  }
                  if (var_cat %in% colnames(df_gamm) && !is.factor(df_gamm[[var_cat]]))
                    df_gamm[[var_cat]] <- factor(df_gamm[[var_cat]])
                  
                  # ── F\u00f3rmula ───────────────────────────────────────────────
                  formula_str <- paste0("`", v, "` ~ `", var_cat, "`")
                  if (length(re_terms) > 0)
                    formula_str <- paste0(formula_str, " + ", paste(re_terms, collapse = " + "))
                  formula_gamm <- as.formula(formula_str)
                  
                  familia_obj  <- if (gamm_familia == "Gamma") Gamma(link = "log") else gaussian()
                  mod_gamm     <- mgcv::gam(formula_gamm, data = df_gamm,
                                            family = familia_obj, method = "REML")
                  s_mod  <- summary(mod_gamm)
                  r2_adj <- round(s_mod$r.sq, 3)
                  dev_ex <- round(s_mod$dev.expl * 100, 1)
                  
                  # ── Caja de resumen ───────────────────────────────────────
                  re_describe <- if (length(re_label) > 0)
                    paste0(" | RE: ", paste(re_label, collapse = ", "))
                  else " (sin efecto aleatorio)"
                  html <- c(html, paste0(
                    '<div class="stat-box" style="background:#f0fff4;border-color:#2e7d32;">',
                    '<strong>GAMM (', gamm_familia, '):</strong>',
                    ' R\u00b2 ajust.=', r2_adj,
                    ' | Dev. expl.=', dev_ex, '%',
                    ' | n=', nrow(df_gamm),
                    re_describe,
                    '</div>'
                  ))
                  
                  # ── Tabla de coeficientes ─────────────────────────────────
                  re_caption <- if (length(re_label) > 0)
                    paste0(" + s(", paste(re_label, collapse = ") + s("), ")")
                  else ""
                  
                  ptab_raw <- s_mod$p.table
                  if (!is.null(ptab_raw) && is.matrix(ptab_raw) && nrow(ptab_raw) > 0 &&
                      !is.null(rownames(ptab_raw)) && length(rownames(ptab_raw)) == nrow(ptab_raw)) {
                    coef_mat <- tryCatch(round(ptab_raw, 4), error = function(e) ptab_raw)
                    coef_tab <- as.data.frame(coef_mat, stringsAsFactors = FALSE)
                    coef_tab$Termino <- rownames(coef_tab)
                    pval_col <- intersect(c("Pr(>|t|)", "Pr(>|z|)"), colnames(coef_tab))[1]
                    if (!is.na(pval_col)) {
                      coef_tab$Signif <- ifelse(coef_tab[[pval_col]] < 0.001, "***",
                                         ifelse(coef_tab[[pval_col]] < 0.01,  "**",
                                         ifelse(coef_tab[[pval_col]] < 0.05,  "*",
                                         ifelse(coef_tab[[pval_col]] < 0.1,   ".", "n.s."))))
                      keep_cols <- intersect(c("Termino", "Estimate", "Std. Error",
                                               "t value", "z value", pval_col, "Signif"),
                                             colnames(coef_tab))
                      coef_tab <- coef_tab[, keep_cols, drop = FALSE]
                    }
                    tab_num <- tab_num + 1
                    html <- c(html,
                      paste0('<h5>Coeficientes GAMM \u2014 ', v, '</h5>'),
                      df_to_html(coef_tab),
                      paste0('<p class="meta"><em>Tabla ', tab_num,
                             '. GAMM: ', v, ' ~ ', var_cat, re_caption,
                             '. Familia: ', gamm_familia, '. n=', nrow(df_gamm), '.</em></p>'))
                  } else {
                    html <- c(html, paste0(
                      '<p class="meta"><em>GAMM para ', v,
                      ': modelo ajustado pero sin coeficientes param\u00e9tricos (p.table vac\u00eda).',
                      ' F\u00f3rmula: ', deparse(formula_gamm), '.</em></p>'))
                  }
                  
                  # ── Gr\u00e1fico ggeffects ──────────────────────────────────────
                  if (requireNamespace("ggeffects", quietly = TRUE)) {
                    fig_num  <- fig_num + 1
                    eff_data <- tryCatch(
                      as.data.frame(ggeffects::ggpredict(mod_gamm, terms = var_cat)),
                      error = function(e) NULL
                    )
                    if (!is.null(eff_data)) {
                      # Usar environment() para que save_and_embed resuelva eff_data, v, var_cat
                      # en el entorno actual, sin necesidad de local() ni quote()
                      eff_local     <- eff_data
                      v_local       <- v
                      var_cat_local <- var_cat
                      cur_env       <- environment()
                      img_gamm <- save_and_embed(quote({
                        p_eff <- ggplot2::ggplot(eff_local,
                                   ggplot2::aes(x = x, y = predicted,
                                                ymin = conf.low, ymax = conf.high)) +
                          ggplot2::geom_point(size = 3, color = "#2e7d32") +
                          ggplot2::geom_errorbar(width = 0.25, color = "#2e7d32") +
                          ggplot2::theme_minimal(base_size = 13) +
                          ggplot2::labs(
                            title = paste0("Efecto estimado de ", var_cat_local, " sobre ", v_local),
                            x     = var_cat_local,
                            y     = paste0(v_local, " (predicho \u00b1 IC 95%)")
                          ) +
                          ggplot2::theme(axis.text.x = ggplot2::element_text(angle = 30, hjust = 1))
                        print(p_eff)
                      }), paste0("gamm_eff_", v_local), envir = cur_env)
                      html <- c(html, img_gamm,
                        paste0('<p class="meta"><em>Figura ', fig_num,
                               '. ggeffects: efecto de ', var_cat_local,
                               ' sobre ', v_local, '.</em></p>'))
                    }
                  }
                }  # end ok_run
              }, error = function(e) {
                html <<- c(html, paste0(
                  '<div class="warning-box">GAMM error en <em>', v,
                  '</em>: ', htmltools::htmlEscape(e$message), '</div>'))
              })
            }  # end var_cat ok + mgcv ok
          }
          # Inline examples for this variable (if placement = por_variable)
          if ("ejemplos" %in% secciones && ej_ubicacion == "por_variable") {
            html <- c(html, generar_ejemplos_extremos(v, df, ej_n, ej_min_dur, ej_min_pal,
                                                       construir_contexto_html, phones_all_ej, grp_col = var_cat,
                                                       max_dur = ej_max_dur, max_pal = ej_max_pal, direccion = ej_direccion,
                                                       filtro_acento = ej_acento))
          }
        }
        # Comentario boxplots
        if (comentario_modo != "ninguno" && !is.null(var_cat) && var_cat %in% colnames(df)) {
          bp_text <- paste0("Boxplots de ", length(vars_num), " variables por ", var_cat, ".\n")
          for (v in vars_num) {
            bp_text <- paste0(bp_text, "\n", v, ":\n")
            for (g in sort(unique(na.omit(df[[var_cat]])))) {
              x <- df[[v]][!is.na(df[[v]]) & !is.na(df[[var_cat]]) & df[[var_cat]] == g]
              if (length(x) > 0) bp_text <- paste0(bp_text, "  ", g, ": Md=", round(median(x),2), 
                " [Q1=", round(quantile(x,0.25),2), " - Q3=", round(quantile(x,0.75),2), "], n=", length(x), "\n")
            }
            tryCatch({
              df_t <- df[!is.na(df[[var_cat]]) & !is.na(df[[v]]), ]
              df_t[[var_cat]] <- droplevels(as.factor(df_t[[var_cat]]))
              if (nlevels(df_t[[var_cat]]) >= 2) {
                kw <- kruskal.test(as.formula(paste0("`",v,"` ~ `",var_cat,"`")), data=df_t)
                sig <- if (kw$p.value < 0.001) "***" else if (kw$p.value < 0.01) "**" else if (kw$p.value < 0.05) "*" else "n.s."
                bp_text <- paste0(bp_text, "  KW: H=", round(kw$statistic,2), ", p=", format.pval(kw$p.value,3), " ", sig, "\n")
              }
            }, error = function(e) {})
          }
          html <- c(html, generar_comentario("Boxplots y tests estadísticos", bp_text))
        }
      }
      
      incProgress(0.5, detail = "Heatmap...")
      if ("heatmap" %in% secciones && length(vars_num) >= 2) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Heatmap de Correlaciones</h2>'))
        img_html <- save_and_embed(quote({
          mat <- df[, vars_num, drop=FALSE]; mat <- mat[complete.cases(mat), ]
          if (nrow(mat) > 2) {
            cor_mat <- cor(mat, use="pairwise.complete.obs")
            cor_df <- data.frame(Var1=rep(rownames(cor_mat),ncol(cor_mat)),
                                  Var2=rep(colnames(cor_mat),each=nrow(cor_mat)),
                                  value=as.vector(cor_mat), stringsAsFactors=FALSE)
            p <- ggplot(cor_df, aes(x=Var1,y=Var2,fill=value)) + geom_tile(color="white") +
              geom_text(aes(label=round(value,2)), size=3) +
              scale_fill_gradient2(low="#e74c3c",mid="white",high="#2980b9",midpoint=0,limits=c(-1,1)) +
              theme_minimal(base_size=12) + theme(axis.text.x=element_text(angle=45,hjust=1)) +
              labs(title="Correlaciones entre variables", x="", y="", fill="r")
            print(p)
          } else { plot.new(); text(0.5,0.5,"Datos insuficientes") }
        }), "heatmap_correlaciones", ancho=max(6,length(vars_num)*1.2), alto=max(5,length(vars_num)*1.0))
        fig_num <- fig_num + 1
        html <- c(html, img_html, paste0('<p class="meta"><em>Figura ', fig_num, '. Heatmap de correlaciones entre variables numéricas.</em></p>'))
        # Comentario heatmap
        if (comentario_modo != "ninguno") {
          hm_text <- "Correlaciones entre variables prosódicas:\n"
          tryCatch({
            mat <- df[, vars_num, drop=FALSE]; mat <- mat[complete.cases(mat), ]
            if (nrow(mat) > 2) {
              cor_mat <- cor(mat, use="pairwise.complete.obs")
              # Top correlaciones
              cor_pairs <- data.frame()
              for (i in 1:(ncol(cor_mat)-1)) for (j in (i+1):ncol(cor_mat)) {
                cor_pairs <- rbind(cor_pairs, data.frame(V1=colnames(cor_mat)[i], V2=colnames(cor_mat)[j], r=round(cor_mat[i,j],3)))
              }
              cor_pairs <- cor_pairs[order(-abs(cor_pairs$r)), ]
              hm_text <- paste0(hm_text, "Top correlaciones (abs(r)>0.3):\n")
              for (k in 1:min(15, nrow(cor_pairs))) {
                if (abs(cor_pairs$r[k]) > 0.3) hm_text <- paste0(hm_text, "  ", cor_pairs$V1[k], " ~ ", cor_pairs$V2[k], ": r=", cor_pairs$r[k], "\n")
              }
            }
          }, error = function(e) {})
          html <- c(html, generar_comentario("Heatmap de correlaciones", hm_text))
        }
      }
      
      incProgress(0.6, detail = "ANOVA...")
      if ("anova" %in% secciones && !is.null(var_cat) && var_cat %in% colnames(df)) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. ANOVA / Kruskal-Wallis</h2>'))
        html <- c(html, paste0('<div class="stat-box"><strong>Variable de agrupación:</strong> ', var_cat, '</div>'))
        
        anova_var_idx <- 0
        anova_summary_text <- ""
        for (var_dep_a in vars_num) {
          df_a <- df[!is.na(df[[var_dep_a]]) & !is.na(df[[var_cat]]), ]
          df_a[[var_cat]] <- droplevels(as.factor(df_a[[var_cat]]))
          if (nrow(df_a) <= 5 || nlevels(df_a[[var_cat]]) < 2) next
          
          anova_var_idx <- anova_var_idx + 1
          html <- c(html, paste0('<h3>', seccion_num, '.', anova_var_idx, '. ', var_dep_a, '</h3>'))
          
          grupos <- split(df_a[[var_dep_a]], df_a[[var_cat]])
          grupos <- grupos[sapply(grupos, length) > 0]
          if (length(grupos) < 2) next
          
          tryCatch({
            norm_ok <- all(sapply(grupos, function(g) {
              if (length(g)<3||length(g)>5000) return(FALSE)
              tryCatch(shapiro.test(g)$p.value>0.05, error=function(e)FALSE)
            }))
            if (norm_ok) {
              aov_result <- aov(as.formula(paste0("`",var_dep_a,"` ~ `",var_cat,"`")), data=df_a)
              aov_summary <- summary(aov_result)
              p_val <- aov_summary[[1]]["Pr(>F)"][[1]][1]
              f_val <- aov_summary[[1]]["F value"][[1]][1]
              sig <- if (p_val < 0.001) "***" else if (p_val < 0.01) "**" else if (p_val < 0.05) "*" else "n.s."
              html <- c(html, paste0('<div class="stat-box">ANOVA: F=', round(f_val,2), ', p=', format.pval(p_val,3), ' ', sig, '</div>'))
              anova_summary_text <- paste0(anova_summary_text, var_dep_a, ": F=", round(f_val,2), " p=", format.pval(p_val,3), " ", sig, "\n")
              if (!is.na(p_val) && p_val < 0.05) {
                tukey <- TukeyHSD(aov_result)
                html <- c(html, '<pre style="font-size:11px;">', paste(capture.output(tukey), collapse="\n"), '</pre>')
              }
            } else {
              kw <- kruskal.test(as.formula(paste0("`",var_dep_a,"` ~ `",var_cat,"`")), data=df_a)
              sig <- if (kw$p.value < 0.001) "***" else if (kw$p.value < 0.01) "**" else if (kw$p.value < 0.05) "*" else "n.s."
              html <- c(html, paste0('<div class="stat-box">Kruskal-Wallis: H=', round(kw$statistic,2), ', gl=', kw$parameter, ', p=', format.pval(kw$p.value,3), ' ', sig, '</div>'))
              anova_summary_text <- paste0(anova_summary_text, var_dep_a, ": KW H=", round(kw$statistic,2), " p=", format.pval(kw$p.value,3), " ", sig, "\n")
              if (!is.na(kw$p.value) && kw$p.value < 0.05) {
                tryCatch({
                  ph <- pairwise.wilcox.test(df_a[[var_dep_a]], df_a[[var_cat]],
                                             p.adjust.method = "holm", exact = FALSE)
                  p_mat  <- ph$p.value
                  rn_ph  <- rownames(p_mat)
                  cn_ph  <- colnames(p_mat)
                  # Tabla HTML de p-valores ajustados
                  tbl_ph <- '<table class="table table-sm table-bordered" style="font-size:11px; margin-top:4px;"><thead><tr><th>vs.</th>'
                  for (g in cn_ph) tbl_ph <- paste0(tbl_ph, '<th>', g, '</th>')
                  tbl_ph <- paste0(tbl_ph, '</tr></thead><tbody>')
                  for (i in seq_along(rn_ph)) {
                    tbl_ph <- paste0(tbl_ph, '<tr><td><strong>', rn_ph[i], '</strong></td>')
                    for (j in seq_along(cn_ph)) {
                      pv <- p_mat[i, j]
                      if (is.na(pv)) {
                        tbl_ph <- paste0(tbl_ph, '<td style="color:#aaa;">—</td>')
                      } else {
                        sig_ph  <- if (pv < 0.001) "***" else if (pv < 0.01) "**" else if (pv < 0.05) "*" else "n.s."
                        bg_ph   <- if (pv < 0.05) ' style="background:#d4edda;"' else ""
                        tbl_ph  <- paste0(tbl_ph, '<td', bg_ph, '>', format.pval(pv, digits=3), ' ', sig_ph, '</td>')
                      }
                    }
                    tbl_ph <- paste0(tbl_ph, '</tr>')
                  }
                  tbl_ph <- paste0(tbl_ph, '</tbody></table>')
                  html <- c(html, paste0('<div style="margin-top:4px;"><em>Post-hoc: Wilcoxon por pares, corrección Holm</em>', tbl_ph, '</div>'))
                  sig_idx <- which(p_mat < 0.05, arr.ind = TRUE)
                  if (nrow(sig_idx) > 0) {
                    ph_lines <- apply(sig_idx, 1, function(r) paste0(rn_ph[r[1]], " vs ", cn_ph[r[2]], ": p=", format.pval(p_mat[r[1],r[2]], 3)))
                    anova_summary_text <- paste0(anova_summary_text, "  Post-hoc sig.: ", paste(ph_lines, collapse="; "), "\n")
                  }
                }, error = function(e) {
                  html <<- c(html, paste0('<div class="warning-box">Post-hoc no disponible: ', e$message, '</div>'))
                })
              }
            }
          }, error = function(e) { html <<- c(html, paste0('<div class="warning-box">Error: ', e$message, '</div>')) })
        }
        # Comentario ANOVA
        if (comentario_modo != "ninguno") {
          html <- c(html, generar_comentario("ANOVA / Kruskal-Wallis", paste0("Tests de ", length(vars_num), " variables ~ ", var_cat, ":\n", anova_summary_text)))
        }
      }
      
      incProgress(0.7, detail = "Regresión...")
      if ("regresion" %in% secciones && length(vars_num) >= 2) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Regresión Lineal Múltiple</h2>'))
        # For each numeric var: predict it from the others + var_cat
        reg_var_idx <- 0
        for (var_dep_r in vars_num) {
          predictores <- setdiff(vars_num, var_dep_r)
          if (!is.null(var_cat) && var_cat %in% colnames(df)) predictores <- c(predictores, var_cat)
          predictores <- intersect(predictores, colnames(df))
          if (length(predictores) == 0) next
          
          df_r <- df[, c(var_dep_r, predictores), drop=FALSE]; df_r <- df_r[complete.cases(df_r), ]
          if (nrow(df_r) <= length(predictores)+2) next
          
          tryCatch({
            lm_model <- lm(as.formula(paste0("`",var_dep_r,"` ~ ", paste0("`",predictores,"`", collapse=" + "))), data=df_r)
            lm_summary <- summary(lm_model)
            if (lm_summary$r.squared < 0.05) next  # Skip trivial models
            
            reg_var_idx <- reg_var_idx + 1
            html <- c(html, paste0('<h3>', seccion_num, '.', reg_var_idx, '. ', var_dep_r, '</h3>'))
            
            # Coefficients table with rounded values and predictor names
            coef_df <- as.data.frame(lm_summary$coefficients)
            coef_df$Predictor <- rownames(coef_df)
            pval_col_lm <- "Pr(>|t|)"
            if (pval_col_lm %in% colnames(coef_df)) {
              coef_df$Signif. <- ifelse(coef_df[[pval_col_lm]] < 0.001, "***",
                                 ifelse(coef_df[[pval_col_lm]] < 0.01,  "**",
                                 ifelse(coef_df[[pval_col_lm]] < 0.05,  "*",
                                 ifelse(coef_df[[pval_col_lm]] < 0.1,   ".",  "n.s."))))
            }
            keep_lm <- intersect(c("Predictor", "Estimate", "Std. Error", "t value", pval_col_lm, "Signif."), colnames(coef_df))
            coef_df <- coef_df[, keep_lm, drop = FALSE]
            nums_lm <- sapply(coef_df, is.numeric)
            coef_df[nums_lm] <- lapply(coef_df[nums_lm], function(x) round(x, 4))
            html <- c(html, paste0('<div class="stat-box">R² = ', round(lm_summary$r.squared,4),
                     ' | R² adj = ', round(lm_summary$adj.r.squared,4),
                     ' | F = ', round(lm_summary$fstatistic[1],2),
                     ' | p = ', format.pval(pf(lm_summary$fstatistic[1], lm_summary$fstatistic[2], lm_summary$fstatistic[3], lower.tail=FALSE), 3),
                     '</div>'))
            tab_num <- tab_num + 1
            html <- c(html, df_to_html(coef_df),
                      paste0('<p class="meta"><em>Tabla ', tab_num, '. Coeficientes de regresión para ', var_dep_r, '.</em></p>'))
          }, error = function(e) {})
        }
        if (reg_var_idx == 0) html <- c(html, '<div class="warning-box">Ningún modelo de regresión significativo (R² > 0.05).</div>')
      }
      
      incProgress(0.85, detail = "Random Forest...")
      if ("randomforest" %in% secciones && !is.null(var_cat) && var_cat %in% colnames(df)) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Random Forest</h2>'))
        var_dep_rf <- var_cat
        predictores_rf <- intersect(vars_num, colnames(df))
        if (length(predictores_rf) > 0 && requireNamespace("randomForest", quietly=TRUE)) {
          df_rf <- df[, c(var_dep_rf, predictores_rf), drop=FALSE]
          for (col in colnames(df_rf)) { if (is.character(df_rf[[col]])) df_rf[[col]] <- factor(df_rf[[col]]) }
          df_rf <- df_rf[complete.cases(df_rf), ]
          for (col in colnames(df_rf)) { if (is.factor(df_rf[[col]])) df_rf[[col]] <- droplevels(df_rf[[col]]) }
          if (nrow(df_rf) > 10) {
            tryCatch({
              rf_model <- randomForest::randomForest(as.formula(paste0("`",var_dep_rf,"` ~ .")), data=df_rf, ntree=input$inf_rf_ntree, importance=TRUE)
              tipo <- if (is.factor(df_rf[[var_dep_rf]])) "clasificación" else "regresión"
              html <- c(html, paste0('<div class="stat-box"><strong>Tipo:</strong> ',tipo,
                                      ' | <strong>Predice:</strong> ', var_dep_rf,
                                      ' | <strong>Predictores:</strong> ', paste(predictores_rf, collapse=", "), '</div>'))
              img_html <- save_and_embed(quote({
                imp <- randomForest::importance(rf_model)
                imp_df <- data.frame(Variable=rownames(imp), Importancia=imp[,1], stringsAsFactors=FALSE)
                imp_df <- imp_df[order(-imp_df$Importancia), ]
                p <- ggplot(head(imp_df,20), aes(x=reorder(Variable,Importancia),y=Importancia)) +
                  geom_col(fill="#27ae60",width=0.7) + coord_flip() + theme_minimal(base_size=13) +
                  labs(title=paste0("Importancia de variables para predecir ", var_dep_rf), x="", y="Importancia")
                print(p)
              }), "rf_importancia")
              fig_num <- fig_num + 1
              html <- c(html, '<h3>Importancia de variables</h3>', img_html,
                paste0('<p class="meta"><em>Figura ', fig_num, '. Importancia de variables (RF) para predecir ', var_dep_rf, '.</em></p>'))
              if (tipo=="clasificación") {
                tab_num <- tab_num + 1
                conf_df <- as.data.frame(rf_model$confusion)
                conf_df <- cbind(Clase = rownames(conf_df), conf_df)
                rownames(conf_df) <- NULL
                conf_df[] <- lapply(conf_df, function(x) if (is.numeric(x)) round(x, 3) else x)
                html <- c(html, '<h3>Matriz de confusión</h3>', df_to_html(conf_df),
                  paste0('<p class="meta"><em>Tabla ', tab_num, '. Matriz de confusión del RF.</em></p>'))
              }
            }, error=function(e) { html <<- c(html, paste0('<div class="warning-box">Error RF: ', e$message, '</div>')) })
          }
        }
        # Comentario RF
        if (comentario_modo != "ninguno") {
          rf_text <- paste0("Random Forest para predecir ", var_dep_rf, ".\nPredictores: ", paste(predictores_rf, collapse=", "), "\n")
          tryCatch({
            if (exists("rf_model")) {
              imp <- randomForest::importance(rf_model)
              imp_df <- data.frame(Variable=rownames(imp), Importancia=round(imp[,1],2), stringsAsFactors=FALSE)
              imp_df <- imp_df[order(-imp_df$Importancia), ]
              rf_text <- paste0(rf_text, "Variables más importantes:\n", df_to_text(head(imp_df, 10)))
              if (is.factor(df_rf[[var_dep_rf]])) {
                rf_text <- paste0(rf_text, "\n\nMatriz de confusión:\n", paste(capture.output(rf_model$confusion), collapse="\n"))
              }
            }
          }, error = function(e) {})
          html <- c(html, generar_comentario("Random Forest", rf_text))
        }
      }
      
      # ---- SECCIÓN: Árbol de decisión ----
      if ("arbol_decision" %in% secciones && !is.null(var_cat) && var_cat %in% colnames(df)) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Árbol de Decisión</h2>'))
        var_dep_tree <- var_cat
        maxdepth_tree <- input$inf_tree_maxdepth
        if (is.null(maxdepth_tree) || is.na(maxdepth_tree)) maxdepth_tree <- 4
        
        predictores_tree <- intersect(vars_num, colnames(df))
        
        if (length(predictores_tree) > 0) {
          df_tree <- df[, c(var_dep_tree, predictores_tree), drop = FALSE]
          for (col in colnames(df_tree)) { if (is.character(df_tree[[col]])) df_tree[[col]] <- factor(df_tree[[col]]) }
          df_tree <- df_tree[complete.cases(df_tree), ]
          for (col in colnames(df_tree)) { if (is.factor(df_tree[[col]])) df_tree[[col]] <- droplevels(df_tree[[col]]) }
          for (col in colnames(df_tree)) { if (is.numeric(df_tree[[col]])) df_tree[[col]] <- round(df_tree[[col]], 2) }
          
          if (nrow(df_tree) > 10 && nlevels(df_tree[[var_dep_tree]]) >= 2) {
            tryCatch({
              if (requireNamespace("partykit", quietly = TRUE)) {
                formula_tree <- as.formula(paste0("`", var_dep_tree, "` ~ ", 
                                 paste0("`", predictores_tree, "`", collapse = " + ")))
                ct_model <- partykit::ctree(formula_tree, data = df_tree,
                                            control = partykit::ctree_control(maxdepth = maxdepth_tree))
                
                cats_tree <- levels(df_tree[[var_dep_tree]])
                n_cats <- length(cats_tree)
                # Set2 solo tiene 8 colores: interpolar para cubrir todas las categorías
                # (con 18 grupos, brewer.pal(8,...)[1:18] dejaba 10 colores en NA).
                paleta <- colorRampPalette(
                  RColorBrewer::brewer.pal(min(8L, max(3L, n_cats)), "Set2")
                )(n_cats)
                
                html <- c(html, paste0('<div class="stat-box"><strong>Predice:</strong> ', var_dep_tree,
                                        ' | <strong>Profundidad:</strong> ', maxdepth_tree,
                                        ' | <strong>Categorías:</strong> ', paste(cats_tree, collapse=", "), '</div>'))
                
                use_ggparty <- requireNamespace("ggparty", quietly = TRUE)
                
                img_html <- save_and_embed(quote({
                  if (use_ggparty) {
                    p <- ggparty::ggparty(ct_model) +
                      ggparty::geom_edge() +
                      ggparty::geom_edge_label(size = 3.5) +
                      ggparty::geom_node_splitvar(size = 4) +
                      ggparty::geom_node_plot(gglist = list(
                        geom_bar(aes(x = "", fill = .data[[var_dep_tree]]), position = "fill"),
                        theme_minimal(base_size = 9),
                        scale_fill_manual(values = setNames(paleta, cats_tree)),
                        scale_y_continuous(labels = function(x) paste0(round(x*100),"%")),
                        labs(x = NULL, y = NULL)
                      ), shared_axis_labels = TRUE, ids = "terminal") +
                      theme(legend.position = "bottom",
                            legend.text = element_text(size = 11),
                            legend.title = element_text(size = 12, face = "bold"),
                            legend.key.size = unit(0.6, "cm"),
                            plot.margin = margin(5, 5, 40, 5)) +
                      guides(fill = guide_legend(title = var_dep_tree,
                                                 nrow = max(1L, ceiling(n_cats / 9))))
                    print(p)
                  } else {
                    plot(ct_model, main = paste0("Árbol: ", var_dep_tree), tp_args = list(round = 2))
                  }
                }), "arbol_decision", ancho = 14, alto = 10)
                fig_num <- fig_num + 1
                
                leyenda_html <- '<div style="background:#f8f9fa;padding:10px;border-radius:6px;margin:10px 0;text-align:center;"><strong>Leyenda:</strong> '
                for (i in seq_along(cats_tree)) {
                  leyenda_html <- paste0(leyenda_html, 
                    '<span style="display:inline-block;width:16px;height:16px;background:', paleta[i], 
                    ';border-radius:3px;margin:0 4px;vertical-align:middle;"></span> ', 
                    htmltools::htmlEscape(cats_tree[i]), '&nbsp;&nbsp;')
                }
                leyenda_html <- paste0(leyenda_html, '</div>')
                
                html <- c(html, img_html, leyenda_html,
                  paste0('<p class="meta"><em>Figura ', fig_num, 
                    '. Árbol de decisión condicional para ', var_dep_tree, '. Profundidad: ', maxdepth_tree, '.</em></p>'))
                
              } else {
                html <- c(html, '<div class="warning-box">Paquete partykit no disponible. install.packages("partykit")</div>')
              }
            }, error = function(e) {
              html <<- c(html, paste0('<div class="warning-box">Error Árbol: ', e$message, '</div>'))
            })
          } else {
            html <- c(html, '<div class="warning-box">Datos insuficientes para árbol de decisión.</div>')
          }
        }
      }
      
      # ---- SECCIÓN: Correlación entre etiquetados emocionales ----
      if ("correlacion_emociones" %in% secciones) {
        seccion_num <- seccion_num + 1; html <- c(html, paste0('<h2>', seccion_num, '. Correlación entre Etiquetados Emocionales</h2>'))
        
        # Collect available emotion columns (real names in ips_resumen)
        emo_cols_avail <- c()
        df_emo <- df
        
        # emocion_manual (may come from etiquetado)
        if ("emocion_manual" %in% colnames(df_emo)) {
          emo_cols_avail <- c(emo_cols_avail, "emocion_manual")
        } else if (!is.null(etiq$anotaciones) && "emocion_manual" %in% colnames(etiq$anotaciones) && 
                   nrow(etiq$anotaciones) == nrow(df_emo)) {
          df_emo$emocion_manual <- etiq$anotaciones$emocion_manual
          emo_cols_avail <- c(emo_cols_avail, "emocion_manual")
        }
        # sentimiento (pysentimiento) - column in ips_resumen
        if ("sentimiento" %in% colnames(df_emo)) {
          emo_cols_avail <- c(emo_cols_avail, "sentimiento")
        } else if ("sent_label" %in% colnames(df_emo)) {
          emo_cols_avail <- c(emo_cols_avail, "sent_label")
        }
        # emocion_audio (emotion2vec) - column in ips_resumen
        if ("emocion_audio" %in% colnames(df_emo)) {
          emo_cols_avail <- c(emo_cols_avail, "emocion_audio")
        } else if ("emo_audio_label" %in% colnames(df_emo)) {
          emo_cols_avail <- c(emo_cols_avail, "emo_audio_label")
        }
        # emocion_texto (pysentimiento emotions) - column in ips_resumen
        if ("emocion_texto" %in% colnames(df_emo)) {
          emo_cols_avail <- c(emo_cols_avail, "emocion_texto")
        } else if ("emo_texto_label" %in% colnames(df_emo)) {
          emo_cols_avail <- c(emo_cols_avail, "emo_texto_label")
        }
        # Filter out columns with all empty/NA values
        emo_cols_avail <- emo_cols_avail[sapply(emo_cols_avail, function(col) {
          vals <- df_emo[[col]]
          sum(!is.na(vals) & vals != "" & vals != "no_wav", na.rm = TRUE) > 0
        })]
        
        if (length(emo_cols_avail) >= 2) {
          html <- c(html, paste0('<div class="stat-box"><strong>Etiquetados disponibles:</strong> ', 
                                  paste(emo_cols_avail, collapse = ", "), '</div>'))
          
          # Specific pairwise comparisons: manual vs each automatic classifier
          pares <- list()
          if ("emocion_manual" %in% emo_cols_avail) {
            for (auto_col in setdiff(emo_cols_avail, "emocion_manual")) {
              pares <- c(pares, list(c("emocion_manual", auto_col)))
            }
          }
          # If no manual, do all pairwise
          if (length(pares) == 0) pares <- combn(emo_cols_avail, 2, simplify = FALSE)
          
          for (par in pares) {
            col1 <- par[1]; col2 <- par[2]
            html <- c(html, paste0('<h3>', col1, ' vs ', col2, '</h3>'))
            
            df_pair <- df_emo[!is.na(df_emo[[col1]]) & !is.na(df_emo[[col2]]) & 
                               df_emo[[col1]] != "" & df_emo[[col2]] != "", ]
            
            if (nrow(df_pair) > 5) {
              # Contingency table
              tbl <- table(df_pair[[col1]], df_pair[[col2]])
              tab_num <- tab_num + 1
              tbl_mat <- as.data.frame.matrix(tbl)
              tbl_mat <- cbind(setNames(data.frame(rownames(tbl_mat), stringsAsFactors=FALSE), col1), tbl_mat)
              html <- c(html, paste0('<h4>Tabla de contingencia</h4>'), df_to_html(tbl_mat),
                paste0('<p class="meta"><em>Tabla ', tab_num, '. Contingencia: ', col1, ' vs ', col2, '.</em></p>'))
              
              # Chi-square test
              tryCatch({
                chi_res <- chisq.test(tbl, simulate.p.value = (min(dim(tbl)) < 2 || any(tbl < 5)))
                sig <- if (chi_res$p.value < 0.001) "***" else if (chi_res$p.value < 0.01) "**" else if (chi_res$p.value < 0.05) "*" else "n.s."
                html <- c(html, '<h4>Test Chi-cuadrado</h4>',
                          paste0('<div class="stat-box">X² = ', round(chi_res$statistic, 3),
                                 ', df = ', chi_res$parameter,
                                 ', p = ', format.pval(chi_res$p.value, digits = 4), ' ', sig, '</div>'))
              }, error = function(e) {
                html <<- c(html, paste0('<div class="warning-box">Error chi²: ', e$message, '</div>'))
              })
              
              # Cramér's V (effect size)
              tryCatch({
                n_obs <- sum(tbl)
                chi_stat <- chisq.test(tbl, simulate.p.value = FALSE)$statistic
                k <- min(nrow(tbl), ncol(tbl))
                cramers_v <- sqrt(chi_stat / (n_obs * (k - 1)))
                interp <- if (cramers_v < 0.1) "muy débil" else if (cramers_v < 0.3) "débil" else if (cramers_v < 0.5) "moderada" else "fuerte"
                html <- c(html, paste0('<div class="stat-box"><strong>V de Cramér:</strong> ', 
                                        round(cramers_v, 4), ' (asociación ', interp, ')</div>'))
              }, error = function(e) {})
              
              # Heatmap of contingency
              img_html <- save_and_embed(quote({
                tbl_df <- as.data.frame(tbl)
                colnames(tbl_df) <- c("Var1", "Var2", "Freq")
                p <- ggplot(tbl_df, aes(x = Var1, y = Var2, fill = Freq)) +
                  geom_tile(color = "white") +
                  geom_text(aes(label = Freq), size = 3.5) +
                  scale_fill_gradient(low = "white", high = "#3498db") +
                  theme_minimal(base_size = 12) +
                  theme(axis.text.x = element_text(angle = 45, hjust = 1)) +
                  labs(title = paste0(col1, " vs ", col2), x = col1, y = col2, fill = "N")
                print(p)
              }), paste0("corr_emo_", col1, "_", col2), ancho = 7, alto = 6)
              fig_num <- fig_num + 1
              html <- c(html, img_html, paste0('<p class="meta"><em>Figura ', fig_num, 
                '. Heatmap de contingencia: ', col1, ' vs ', col2, '.</em></p>'))
              
              # Cohen's Kappa if same categories
              if (length(intersect(unique(df_pair[[col1]]), unique(df_pair[[col2]]))) >= 2) {
                tryCatch({
                  if (requireNamespace("irr", quietly = TRUE)) {
                    kappa_res <- irr::kappa2(data.frame(a = df_pair[[col1]], b = df_pair[[col2]]))
                    html <- c(html, paste0('<div class="stat-box"><strong>Kappa de Cohen:</strong> ', 
                                            round(kappa_res$value, 4), ' (p=', format.pval(kappa_res$p.value, digits = 4), ')</div>'))
                  }
                }, error = function(e) {})
              }
              
            } else {
              html <- c(html, '<div class="warning-box">Datos insuficientes para esta comparación.</div>')
            }
          }
        } else {
          html <- c(html, '<div class="warning-box">Se requieren al menos 2 tipos de etiquetado emocional (manual, sentimiento, wav2vecR, texto). Disponibles: ', 
                    paste(emo_cols_avail, collapse = ", "), '</div>')
        }
      }
      
      # ---- SECCIÓN: Espacio prosódico emocional ----
      if ("espacio_prosodico" %in% secciones) {
        seccion_num <- seccion_num + 1
        html <- c(html, paste0('<h2>', seccion_num, '. Espacio Prosódico Emocional</h2>'))
        
        ep_min_n      <- if (!is.null(input$inf_ep_min_n)) input$inf_ep_min_n else 5
        ep_z_hab      <- if (!is.null(input$inf_ep_z_hablante)) isTRUE(input$inf_ep_z_hablante) else TRUE
        ep_pca        <- if (!is.null(input$inf_ep_pca)) isTRUE(input$inf_ep_pca) else TRUE
        ep_heatmap    <- if (!is.null(input$inf_ep_heatmap)) isTRUE(input$inf_ep_heatmap) else TRUE
        ep_radar      <- isTRUE(input$inf_ep_radar)
        ep_distancias <- if (!is.null(input$inf_ep_distancias)) isTRUE(input$inf_ep_distancias) else TRUE
        
        # Mapa de planificación discursiva (0-5)
        planif_map <- c(
          "conversaciones" = 0, "entrevistas" = 1, "interpretacion" = 3,
          "series" = 4, "peliculas" = 5,
          "conversacion" = 0, "entrevista" = 1, "pelicula" = 5, "serie" = 4
        )
        
        # Verificar columnas necesarias
        tiene_emocion <- "emocion_manual" %in% colnames(df) &&
                         any(!is.na(df$emocion_manual) & df$emocion_manual != "" & df$emocion_manual != "neutro", na.rm=TRUE)
        tiene_genero  <- "genero" %in% colnames(df) && length(unique(na.omit(df$genero))) >= 2
        vars_ep <- intersect(vars_num, colnames(df))
        vars_ep <- vars_ep[sapply(vars_ep, function(v) is.numeric(df[[v]]) && sum(!is.na(df[[v]])) > 10)]
        
        if (!tiene_emocion) {
          html <- c(html, '<div class="warning-box">\u26A0 Se requiere etiquetado emocional (emocion_manual) con al menos una emoción distinta de neutro.</div>')
        } else if (!tiene_genero) {
          html <- c(html, '<div class="warning-box">\u26A0 Se requieren al menos 2 géneros discursivos en el dataset (columna <code>genero</code>).</div>')
        } else if (length(vars_ep) < 2) {
          html <- c(html, '<div class="warning-box">\u26A0 Se necesitan al menos 2 variables numéricas seleccionadas.</div>')
        } else {
          
          # --- Construir df de trabajo ---
          df_ep <- df[!is.na(df$emocion_manual) & df$emocion_manual != "" &
                      !is.na(df$genero) & df$genero != "", ]
          df_ep <- df_ep[df_ep$emocion_manual != "neutro", ]
          
          # Normalización Z por hablante (sobre variables originales o ya-Z)
          if (ep_z_hab && "hablante" %in% colnames(df_ep) && !usar_z) {
            for (v in vars_ep) {
              spk_m <- tapply(df_ep[[v]], df_ep$hablante, mean, na.rm=TRUE)
              spk_s <- tapply(df_ep[[v]], df_ep$hablante, sd, na.rm=TRUE)
              for (s in names(spk_m)) {
                idx_s <- which(df_ep$hablante == s)
                if (!is.na(spk_s[s]) && spk_s[s] > 0) {
                  df_ep[[v]][idx_s] <- (df_ep[[v]][idx_s] - spk_m[s]) / spk_s[s]
                } else {
                  df_ep[[v]][idx_s] <- 0
                }
              }
            }
          }
          
          # Etiqueta combinada emocion×genero
          df_ep$emo_gen <- paste0(df_ep$emocion_manual, "\n[", df_ep$genero, "]")
          df_ep$emo_gen_flat <- paste0(df_ep$emocion_manual, "_", gsub(" ", "_", df_ep$genero))
          
          # Añadir puntuación de planificación
          df_ep$planificacion <- planif_map[tolower(trimws(df_ep$genero))]
          df_ep$planificacion[is.na(df_ep$planificacion)] <- 2  # fallback: planificación media
          
          # Filtrar combinaciones con n mínimo
          conteos <- table(df_ep$emo_gen_flat)
          combos_validos <- names(conteos[conteos >= ep_min_n])
          df_ep_f <- df_ep[df_ep$emo_gen_flat %in% combos_validos, ]
          
          n_combos <- length(combos_validos)
          n_total_ep <- nrow(df_ep_f)
          
          html <- c(html, paste0(
            '<div class="stat-box">',
            '<strong>Configuración:</strong> ',
            n_combos, ' combinaciones emoción×género válidas (n\u2265', ep_min_n, ') | ',
            n_total_ep, ' GEs | ',
            length(vars_ep), ' variables prosódicas',
            if (ep_z_hab && !usar_z) ' | Normalización Z por hablante activada' else '',
            '</div>'
          ))
          
          if (n_combos < 2) {
            html <- c(html, paste0('<div class="warning-box">Insuficientes combinaciones válidas (n\u2265', ep_min_n, '). Reduce el mínimo o añade más datos.</div>'))
          } else {
            
            # Paleta de colores por emoción
            emo_colores <- c(
              "alegría"="#F4D03F", "alegria"="#F4D03F",
              "tristeza"="#5DADE2", "ira"="#E74C3C", "enfado"="#E74C3C",
              "miedo"="#8E44AD", "asco"="#27AE60", "sorpresa"="#E67E22",
              "neutro"="#95A5A6"
            )
            
            # --- Calcular perfiles medios por combinación ---
            perfiles <- do.call(rbind, lapply(combos_validos, function(combo) {
              sub_df <- df_ep_f[df_ep_f$emo_gen_flat == combo, ]
              row <- data.frame(
                combo      = combo,
                emocion    = sub_df$emocion_manual[1],
                genero     = sub_df$genero[1],
                planif     = sub_df$planificacion[1],
                n          = nrow(sub_df),
                stringsAsFactors = FALSE
              )
              for (v in vars_ep) {
                row[[v]] <- mean(sub_df[[v]], na.rm=TRUE)
              }
              row
            }))
            
            # ---- HEATMAP DE PERFILES MEDIOS ----
            if (ep_heatmap && nrow(perfiles) >= 2) {
              tryCatch({
                img_heat <- save_and_embed(quote({
                  library(ggplot2)
                  # Preparar datos long para heatmap
                  vars_plot <- intersect(vars_ep, colnames(perfiles))
                  # Estandarizar columnas numéricas del perfil (Z entre combinaciones)
                  mat_vals <- as.matrix(perfiles[, vars_plot, drop=FALSE])
                  mat_z <- apply(mat_vals, 2, function(x) {
                    s <- sd(x, na.rm=TRUE); m <- mean(x, na.rm=TRUE)
                    if (!is.na(s) && s > 0) (x - m)/s else rep(0, length(x))
                  })
                  df_heat <- data.frame(
                    combo = rep(perfiles$combo, length(vars_plot)),
                    variable = rep(vars_plot, each=nrow(perfiles)),
                    z = as.vector(mat_z),
                    emocion = rep(perfiles$emocion, length(vars_plot)),
                    genero = rep(perfiles$genero, length(vars_plot)),
                    planif = rep(perfiles$planif, length(vars_plot)),
                    stringsAsFactors = FALSE
                  )
                  # Ordenar combos por planificación y luego emoción
                  orden_combos <- perfiles$combo[order(perfiles$planif, perfiles$emocion)]
                  df_heat$combo <- factor(df_heat$combo, levels=orden_combos)
                  # Parámetros adaptativos según número de combinaciones
                  n_c <- length(unique(df_heat$combo))
                  tile_size  <- if (n_c > 15) 0 else 0.3          # sin borde entre celdas si hay muchas
                  txt_size   <- if (n_c > 20) 1.8 else if (n_c > 12) 2.2 else 2.8
                  ax_y_size  <- if (n_c > 20) 6.5 else if (n_c > 12) 7.5 else 9
                  mostrar_txt <- n_c <= 30  # suprimir valores numéricos si hay demasiadas filas
                  p <- ggplot(df_heat, aes(x=variable, y=combo, fill=z)) +
                    geom_tile(color=if(tile_size>0) "white" else NA, linewidth=tile_size) +
                    { if (mostrar_txt) geom_text(aes(label=sprintf("%.1f", z)), size=txt_size, color="black") else NULL } +
                    scale_fill_gradient2(low="#3498db", mid="white", high="#e74c3c",
                                         midpoint=0, name="Z") +
                    theme_minimal(base_size=9) +
                    theme(
                      axis.text.x = element_text(angle=40, hjust=1, size=8),
                      axis.text.y = element_text(size=ax_y_size, lineheight=0.85),
                      panel.grid  = element_blank(),
                      plot.subtitle = element_text(size=7.5),
                      legend.key.height = unit(0.5, "cm")
                    ) +
                    labs(title="Perfiles prosódicos medios por emoción × género",
                         subtitle="Valores Z entre combinaciones (azul=bajo, rojo=alto) | ordenado por planificación (0→5)",
                         x="Variable prosódica", y=NULL)
                  print(p)
                }), "ep_heatmap_perfiles",
                ancho = max(7, length(vars_ep) * 1.1),
                alto  = max(4, n_combos * 0.38 + 2))
                fig_num <- fig_num + 1
                html <- c(html, '<h3>Heatmap de perfiles prosódicos medios</h3>', img_heat,
                  paste0('<p class="meta"><em>Figura ', fig_num, '. Cada fila es una combinación emoción×género ordenada por grado de planificación discursiva (conversación=0 ... película=5). ',
                         'El color indica si esa variable está por encima (rojo) o por debajo (azul) de la media global de todas las combinaciones. ',
                         'Combinaciones con color similar tienen perfiles prosódicos parecidos.</em></p>'))
              }, error=function(e) {
                html <<- c(html, paste0('<div class="warning-box">Error heatmap perfiles: ', htmltools::htmlEscape(e$message), '</div>'))
              })
            }
            
            # ---- PCA ----
            
            if (ep_pca && nrow(df_ep_f) >= 10 && length(vars_ep) >= 2) {
              # --- Cálculo PCA fuera de tryCatch para que los errores sean visibles ---
              mat_pca_full <- df_ep_f[, intersect(vars_ep, colnames(df_ep_f)), drop=FALSE]
              cols_ok <- sapply(mat_pca_full, function(x) sum(!is.na(x)) >= max(10, nrow(mat_pca_full)*0.5))
              vars_pca_ok <- vars_ep[cols_ok]
              if (length(vars_pca_ok) < 2) vars_pca_ok <- vars_ep
              mat_pca <- mat_pca_full[, intersect(vars_pca_ok, colnames(mat_pca_full)), drop=FALSE]
              filas_ok <- complete.cases(mat_pca)
              mat_pca <- mat_pca[filas_ok, , drop=FALSE]
              df_pca_meta <- df_ep_f[filas_ok, ]
              
              html <- c(html, paste0(
                '<div class="stat-box" style="font-size:0.85em;">',
                '<strong>PCA diagnóstico:</strong> ',
                nrow(df_ep_f), ' GEs entrada | ',
                length(vars_pca_ok), '/', length(vars_ep), ' variables válidas (',
                paste(vars_pca_ok, collapse=", "), ') | ',
                sum(filas_ok), ' filas completas para PCA',
                '</div>'
              ))
              
              if (nrow(mat_pca) < 10 || ncol(mat_pca) < 2) {
                html <- c(html, paste0(
                  '<div class="warning-box">PCA no ejecutado: solo ', nrow(mat_pca),
                  ' filas completas y ', ncol(mat_pca), ' variables válidas.</div>'
                ))
              } else {
                  pca_res <- prcomp(mat_pca, center=TRUE, scale.=TRUE)
                  var_exp <- round(summary(pca_res)$importance[2, 1:min(4, ncol(mat_pca))] * 100, 1)
                  
                  
                  df_pca_plot <- data.frame(
                    PC1 = pca_res$x[,1],
                    PC2 = pca_res$x[,2],
                    emocion = df_pca_meta$emocion_manual,
                    genero  = df_pca_meta$genero,
                    planif  = df_pca_meta$planificacion,
                    combo   = df_pca_meta$emo_gen_flat,
                    stringsAsFactors = FALSE
                  )
                  
                  # Tabla varianza explicada
                  tab_var <- data.frame(
                    Componente = paste0("PC", seq_along(var_exp)),
                    Varianza_explicada_pct = var_exp,
                    stringsAsFactors = FALSE
                  )
                  tab_num <- tab_num + 1
                  html <- c(html, '<h3>Análisis de Componentes Principales (PCA)</h3>',
                    df_to_html(tab_var),
                    paste0('<p class="meta"><em>Tabla ', tab_num, '. Varianza explicada por cada componente principal.</em></p>'))
                  
                  # Loadings tabla
                  loadings_df <- as.data.frame(pca_res$rotation[, 1:min(3, ncol(pca_res$rotation))])
                  loadings_df <- cbind(Variable=rownames(loadings_df), round(loadings_df, 3))
                  rownames(loadings_df) <- NULL
                  tab_num <- tab_num + 1
                  html <- c(html, '<h4>Loadings (contribución de cada variable a los componentes)</h4>',
                    df_to_html(loadings_df),
                    paste0('<p class="meta"><em>Tabla ', tab_num, '. Loadings del PCA.</em></p>'))
                  
                  # --- Pre-calcular todo lo necesario para los gráficos ---
                  pca_centroides <- aggregate(cbind(PC1, PC2) ~ combo + emocion + genero + planif,
                                              data=df_pca_plot, FUN=mean)
                  pca_pts        <- df_pca_plot
                  pca_ve         <- var_exp
                  
                  paleta_emo <- c("alegría"="#F4D03F","alegria"="#F4D03F","tristeza"="#5DADE2",
                                  "ira"="#E74C3C","enfado"="#E74C3C","miedo"="#8E44AD",
                                  "asco"="#27AE60","sorpresa"="#E67E22","neutro"="#95A5A6")
                  emos_u  <- unique(df_pca_plot$emocion)
                  cols_e  <- paleta_emo[emos_u]; cols_e[is.na(cols_e)] <- "#999999"; names(cols_e) <- emos_u
                  gens_u  <- unique(df_pca_plot$genero)
                  shps_g  <- c(16,17,15,18,8,3,4,10,12)[seq_along(gens_u)]; names(shps_g) <- gens_u
                  
                  ld_df <- as.data.frame(pca_res$rotation[, 1:2])
                  ld_df$variable <- rownames(ld_df)
                  escala_bp <- max(abs(range(pca_res$x[, 1:2]))) * 0.45
                  ld_df$PC1s <- ld_df$PC1 * escala_bp
                  ld_df$PC2s <- ld_df$PC2 * escala_bp
                  
                  
                  # --- Scatter PCA: función local que genera y devuelve el PNG embebido ---
                  img_pca <- local({
                    cx   <- pca_centroides
                    pts  <- pca_pts
                    ve   <- pca_ve
                    ce   <- cols_e
                    sg   <- shps_g
                    graf_counter <<- graf_counter + 1
                    fname <- file.path(graf_dir, sprintf("%02d_ep_pca_scatter.png", graf_counter))
                    n_c  <- nrow(cx)
                    lbl_size <- if (n_c > 18) 2.0 else if (n_c > 10) 2.4 else 2.8
                    pt_size  <- if (n_c > 18) 3.2 else 4.0
                    # Zoom fijo: mostrar solo puntos dentro de ±3 SD del centroide
                    x_med <- median(pts$PC1, na.rm=TRUE)
                    y_med <- median(pts$PC2, na.rm=TRUE)
                    x_sd  <- sd(pts$PC1, na.rm=TRUE)
                    y_sd  <- sd(pts$PC2, na.rm=TRUE)
                    x_lim <- c(x_med - 2.5*x_sd, x_med + 2.5*x_sd)
                    y_lim <- c(y_med - 2.5*y_sd, y_med + 2.5*y_sd)
                    xr <- diff(x_lim); yr <- diff(y_lim)
                    cx$lbl_y <- cx$PC2 + ifelse(cx$PC2 >= y_med, yr*0.06, -yr*0.06)
                    cx$hjust <- ifelse(cx$PC1 >= x_med, 0, 1)
                    # Puntos dentro del zoom (para stat_density2d)
                    pts_zoom <- pts[pts$PC1 >= x_lim[1] & pts$PC1 <= x_lim[2] &
                                    pts$PC2 >= y_lim[1] & pts$PC2 <= y_lim[2], ]
                    p <- ggplot2::ggplot(pts_zoom, ggplot2::aes(x=PC1, y=PC2, color=emocion, shape=genero)) +
                      ggplot2::stat_density_2d(ggplot2::aes(fill=emocion),
                                              geom="polygon", alpha=0.06, color=NA, bins=8) +
                      ggplot2::geom_point(alpha=0.25, size=0.8) +
                      ggplot2::geom_point(data=cx, ggplot2::aes(x=PC1, y=PC2, color=emocion, shape=genero),
                                         size=pt_size, stroke=1.5) +
                      ggplot2::geom_text(data=cx,
                                        ggplot2::aes(x=PC1, y=lbl_y, label=paste0(emocion, " [", genero, "]"),
                                                     color=emocion, hjust=hjust),
                                        size=lbl_size, fontface="italic", show.legend=FALSE) +
                      ggplot2::scale_color_manual(values=ce, name="Emoción") +
                      ggplot2::scale_fill_manual(values=ce, guide="none") +
                      ggplot2::scale_shape_manual(values=sg, name="Género") +
                      ggplot2::coord_cartesian(xlim=x_lim, ylim=y_lim) +
                      ggplot2::theme_minimal(base_size=10) +
                      ggplot2::labs(title="Espacio prosódico emocional (PCA)",
                                   subtitle=paste0("PC1=", ve[1], "% | PC2=", ve[2], "% | zoom ±2.5 SD | contornos de densidad por emoción"),
                                   x=paste0("PC1 (", ve[1], "%)"), y=paste0("PC2 (", ve[2], "%)")) +
                      ggplot2::theme(legend.position="right")
                    png(fname, width=11, height=8, units="in", res=300)
                    print(p)
                    dev.off()
                    informe$graficos_paths[[basename(fname)]] <- fname
                    raw_b <- readBin(fname, "raw", file.info(fname)$size)
                    paste0('<img src="data:image/png;base64,', base64enc::base64encode(raw_b), '" alt="PCA scatter">')
                  })
                  fig_num <- fig_num + 1
                  html <- c(html, img_pca,
                    paste0('<p class="meta"><em>Figura ', fig_num, '. Espacio PCA. Puntos grandes = centroides por emoción×género.</em></p>'))
                  
                  
                  # --- Biplot ---
                  img_biplot <- local({
                    cx  <- pca_centroides
                    ld  <- ld_df
                    ve  <- pca_ve
                    ce  <- cols_e
                    sg  <- shps_g
                    graf_counter <<- graf_counter + 1
                    fname <- file.path(graf_dir, sprintf("%02d_ep_pca_biplot.png", graf_counter))
                    n_c  <- nrow(cx)
                    lbl_sz <- if (n_c > 18) 1.9 else if (n_c > 10) 2.3 else 2.7
                    pt_sz  <- if (n_c > 18) 3.0 else 3.8
                    todos_x <- c(cx$PC1, ld$PC1s); todos_y <- c(cx$PC2, ld$PC2s)
                    xr <- diff(range(todos_x, na.rm=TRUE)); yr <- diff(range(todos_y, na.rm=TRUE))
                    cx$lbl_x <- cx$PC1 + ifelse(cx$PC1 >= 0, xr*0.04, -xr*0.04)
                    cx$lbl_y <- cx$PC2 + ifelse(cx$PC2 >= 0, yr*0.05, -yr*0.05)
                    cx$hjust <- ifelse(cx$PC1 >= 0, 0, 1)
                    ld$lbl_x <- ld$PC1s + ifelse(ld$PC1s >= 0, xr*0.04, -xr*0.04)
                    ld$lbl_y <- ld$PC2s + ifelse(ld$PC2s >= 0, yr*0.04, -yr*0.04)
                    ld$hjust <- ifelse(ld$PC1s >= 0, 0, 1)
                    p2 <- ggplot2::ggplot() +
                      ggplot2::geom_hline(yintercept=0, color="#ecf0f1", linewidth=0.4) +
                      ggplot2::geom_vline(xintercept=0, color="#ecf0f1", linewidth=0.4) +
                      ggplot2::geom_segment(data=ld, ggplot2::aes(x=0, y=0, xend=PC1s, yend=PC2s),
                                           arrow=grid::arrow(length=grid::unit(0.20,"cm"), type="closed"),
                                           color="#7f8c8d", linewidth=0.7) +
                      ggplot2::geom_text(data=ld, ggplot2::aes(x=lbl_x, y=lbl_y, label=variable, hjust=hjust),
                                        size=2.7, color="#2c3e50", fontface="bold") +
                      ggplot2::geom_point(data=cx, ggplot2::aes(x=PC1, y=PC2, color=emocion, shape=genero), size=pt_sz, stroke=1.1) +
                      ggplot2::geom_text(data=cx, ggplot2::aes(x=lbl_x, y=lbl_y, label=paste0(emocion, " [", genero, "]"), color=emocion, hjust=hjust),
                                        size=lbl_sz, fontface="italic", show.legend=FALSE) +
                      ggplot2::scale_color_manual(values=ce, name="Emoción") +
                      ggplot2::scale_shape_manual(values=sg, name="Género") +
                      ggplot2::theme_minimal(base_size=10) +
                      ggplot2::theme(legend.text=ggplot2::element_text(size=8), panel.grid.minor=ggplot2::element_blank()) +
                      ggplot2::labs(title="Biplot PCA", subtitle="Flechas = dirección de cada variable prosódica",
                                   x=paste0("PC1 (", ve[1], "%)"), y=paste0("PC2 (", ve[2], "%)"))
                    png(fname, width=11, height=8, units="in", res=300)
                    print(p2)
                    dev.off()
                    informe$graficos_paths[[basename(fname)]] <- fname
                    raw_b <- readBin(fname, "raw", file.info(fname)$size)
                    paste0('<img src="data:image/png;base64,', base64enc::base64encode(raw_b), '" alt="PCA biplot">')
                  })
                  fig_num <- fig_num + 1
                  html <- c(html, img_biplot,
                    paste0('<p class="meta"><em>Figura ', fig_num, '. Biplot PCA: flechas = variables prosódicas, puntos = centroides emoción×género.</em></p>'))
                  
                  
              } # fin else filas suficientes
            } # fin if ep_pca
            
            # ---- RADAR / SPIDER PLOT ----
            if (ep_radar && n_combos >= 2 && length(vars_ep) >= 3) {
              tryCatch({
                img_radar <- save_and_embed(quote({
                  library(ggplot2)
                  # Normalizar perfiles al rango [0,1] para radar
                  vars_plot <- intersect(vars_ep, colnames(perfiles))
                  mat_r <- as.matrix(perfiles[, vars_plot, drop=FALSE])
                  mat_norm <- apply(mat_r, 2, function(x) {
                    rng <- range(x, na.rm=TRUE)
                    if (diff(rng) > 0) (x - rng[1]) / diff(rng) else rep(0.5, length(x))
                  })
                  # Construir coordenadas polares manualmente
                  n_vars <- length(vars_plot)
                  angulos <- seq(0, 2*pi, length.out=n_vars+1)[-(n_vars+1)]
                  df_radar_all <- do.call(rbind, lapply(seq_len(nrow(perfiles)), function(i) {
                    vals <- c(mat_norm[i,], mat_norm[i,1])  # cerrar polígono
                    angs <- c(angulos, angulos[1])
                    data.frame(
                      x = vals * cos(angs),
                      y = vals * sin(angs),
                      combo   = perfiles$combo[i],
                      emocion = perfiles$emocion[i],
                      genero  = perfiles$genero[i],
                      planif  = perfiles$planif[i],
                      stringsAsFactors = FALSE
                    )
                  }))
                  # Ejes
                  df_ejes <- data.frame(
                    x = cos(angulos), y = sin(angulos),
                    label = vars_plot, stringsAsFactors=FALSE
                  )
                  emociones_unicas <- unique(perfiles$emocion)
                  paleta <- c("alegría"="#F4D03F","alegria"="#F4D03F","tristeza"="#5DADE2",
                              "ira"="#E74C3C","enfado"="#E74C3C","miedo"="#8E44AD",
                              "asco"="#27AE60","sorpresa"="#E67E22","neutro"="#95A5A6")
                  cols_uso <- paleta[emociones_unicas]; cols_uso[is.na(cols_uso)] <- "#999999"
                  names(cols_uso) <- emociones_unicas
                  
                  p <- ggplot(df_radar_all, aes(x=x, y=y, color=emocion, linetype=genero, group=combo)) +
                    geom_polygon(aes(fill=emocion), alpha=0.08) +
                    geom_path(linewidth=0.7) +
                    geom_segment(data=df_ejes, aes(x=0, y=0, xend=x*1.05, yend=y*1.05),
                                 color="#bdc3c7", linewidth=0.4, inherit.aes=FALSE) +
                    geom_text(data=df_ejes, aes(x=x*1.18, y=y*1.18, label=label),
                              size=2.8, color="#2c3e50", inherit.aes=FALSE) +
                    scale_color_manual(values=cols_uso, name="Emoción") +
                    scale_fill_manual(values=cols_uso, name="Emoción") +
                    coord_fixed() +
                    theme_void(base_size=10) +
                    labs(title="Radar de perfiles prosódicos por emoción × género",
                         subtitle="Valores normalizados [0-1] | cada línea = una combinación emoción×género") +
                    theme(legend.position="right")
                  print(p)
                }), "ep_radar", ancho=10, alto=8)
                fig_num <- fig_num + 1
                html <- c(html, '<h3>Radar de perfiles prosódicos</h3>', img_radar,
                  paste0('<p class="meta"><em>Figura ', fig_num, '. Cada polígono representa el perfil prosódico medio normalizado de una combinación emoción×género. ',
                         'Polígonos con forma similar indican realizaciones prosódicas parecidas independientemente de la emoción o el género.</em></p>'))
              }, error=function(e) {
                html <<- c(html, paste0('<div class="warning-box">Error radar: ', htmltools::htmlEscape(e$message), '</div>'))
              })
            }
            
            # ---- MATRIZ DE DISTANCIAS ----
            if (ep_distancias && nrow(perfiles) >= 2 && length(vars_ep) >= 2) {
              tryCatch({
                vars_dist <- intersect(vars_ep, colnames(perfiles))
                mat_dist_in <- as.matrix(perfiles[, vars_dist, drop=FALSE])
                # Estandarizar antes de calcular distancias
                mat_dist_in <- scale(mat_dist_in)
                dist_mat <- as.matrix(dist(mat_dist_in, method="euclidean"))
                rownames(dist_mat) <- perfiles$combo
                colnames(dist_mat) <- perfiles$combo
                dist_df <- as.data.frame(round(dist_mat, 3))
                dist_df <- cbind(Combinación=rownames(dist_df), dist_df)
                rownames(dist_df) <- NULL
                tab_num <- tab_num + 1
                html <- c(html, '<h3>Matriz de distancias entre perfiles prosódicos</h3>',
                  df_to_html(dist_df),
                  paste0('<p class="meta"><em>Tabla ', tab_num, '. Distancia euclidiana entre perfiles prosódicos medios estandarizados. ',
                         'Valores cercanos a 0 = perfiles similares. Por ejemplo, si "miedo_conversaciones" y "alegría_peliculas" tienen distancia baja, ',
                         'sus realizaciones prosódicas son parecidas.</em></p>'))
                
                # Heatmap de distancias
                img_dist <- save_and_embed(quote({
                  library(ggplot2)
                  dist_long <- reshape2::melt(dist_mat)
                  colnames(dist_long) <- c("Var1", "Var2", "distancia")
                  # Ordenar por planificación
                  orden <- perfiles$combo[order(perfiles$planif, perfiles$emocion)]
                  dist_long$Var1 <- factor(dist_long$Var1, levels=orden)
                  dist_long$Var2 <- factor(dist_long$Var2, levels=orden)
                  n_c2 <- length(unique(dist_long$Var1))
                  ax_sz2   <- if (n_c2 > 20) 5.5 else if (n_c2 > 12) 6.5 else 8
                  txt_sz2  <- if (n_c2 > 20) 1.6 else if (n_c2 > 12) 2.0 else 2.6
                  tile_brd <- if (n_c2 > 15) NA else "white"
                  mostrar2 <- n_c2 <= 30
                  p <- ggplot(dist_long, aes(x=Var1, y=Var2, fill=distancia)) +
                    geom_tile(color=tile_brd) +
                    { if (mostrar2) geom_text(aes(label=sprintf("%.1f", distancia)), size=txt_sz2) else NULL } +
                    scale_fill_gradient(low="#1a9641", high="#f7f7f7", name="Dist.") +
                    theme_minimal(base_size=8) +
                    theme(axis.text.x = element_text(angle=50, hjust=1, size=ax_sz2),
                          axis.text.y = element_text(size=ax_sz2, lineheight=0.85),
                          panel.grid  = element_blank(),
                          legend.key.height = unit(0.5,"cm")) +
                    labs(title="Distancias entre perfiles prosódicos (emoción × género)",
                         subtitle="Verde=similar, blanco=diferente | ordenado por planificación",
                         x="", y="")
                  print(p)
                }), "ep_distancias_heatmap",
                ancho = max(6, n_combos * 0.52 + 2),
                alto  = max(5, n_combos * 0.52 + 1.5))
                fig_num <- fig_num + 1
                html <- c(html, img_dist,
                  paste0('<p class="meta"><em>Figura ', fig_num, '. Heatmap de distancias: verde intenso = combinaciones con perfil prosódico muy similar.</em></p>'))
              }, error=function(e) {
                html <<- c(html, paste0('<div class="warning-box">Error distancias: ', htmltools::htmlEscape(e$message), '</div>'))
              })
            }
            
            # ---- Comentario IA ----
            if (comentario_modo != "ninguno") {
              ep_text <- paste0(
                "Análisis del espacio prosódico emocional.\nVariables: ", paste(vars_ep, collapse=", "),
                "\nCombinaciones válidas (n>=", ep_min_n, "): ", n_combos,
                "\nGéneros: ", paste(sort(unique(df_ep_f$genero)), collapse=", "),
                "\nEmociones: ", paste(sort(unique(df_ep_f$emocion_manual)), collapse=", "),
                "\nPlanificación (0=conversación, 5=película): ",
                paste(paste0(sort(unique(df_ep_f$genero)), "=", 
                             planif_map[tolower(sort(unique(df_ep_f$genero)))]), collapse=", ")
              )
              if (nrow(perfiles) >= 2) {
                vars_dist2 <- intersect(vars_ep, colnames(perfiles))
                for (v in vars_dist2) {
                  top2 <- perfiles$combo[order(-perfiles[[v]])][1:min(2, nrow(perfiles))]
                  ep_text <- paste0(ep_text, "\n", v, ": máximo en ", paste(top2, collapse=" > "))
                }
              }
              html <- c(html, generar_comentario("Espacio prosódico emocional", ep_text))
            }
            
          } # fin n_combos >= 2
        } # fin tiene_emocion && tiene_genero && vars_ep >= 2
      } # fin espacio_prosodico
      
      # ---- SECCIÓN: Ejemplos extremos por variable ----
      if ("ejemplos" %in% secciones && ej_ubicacion == "final") {
        seccion_num <- seccion_num + 1
        html <- c(html, paste0('<h2>', seccion_num, '. Ejemplos: valores extremos por variable</h2>'))
        
        # Leyenda
        html <- c(html, '<div class="prosodic-legend">
          <div><strong>Emociones:</strong> \U0001F60A Alegr\u00eda | \U0001F622 Tristeza | \U0001F62E Sorpresa | \U0001F628 Miedo | \U0001F620 Enfado | \U0001F610 Neutro</div>
          <div><strong>Rango tonal:</strong> \U0001F3BB Amplio | \U0001F3B7 Reducido</div>
          <div><strong>Velocidad:</strong> \U0001F422 Lenta | \U0001F680 R\u00e1pida</div>
          <div><strong>Intensidad:</strong> \U0001F50A Alta | \U0001F507 Baja</div>
          <div><strong>Inflexión:</strong> \U00002B06\U0000FE0F Ascendente | \U00002B07\U0000FE0F Descendente</div>
          <div><strong>Duraci\u00f3n:</strong> \U0001F570\U0000FE0F Larga | \U000023F1\U0000FE0F Corta</div>
          <div><strong>Contraste:</strong> <span style="background:#e8f5e9;padding:1px 4px;border-radius:3px;">S:</span> Sentimiento | <span style="background:#e3f2fd;padding:1px 4px;border-radius:3px;">T:</span> Emoci\u00f3n texto | <span style="background:#fce4ec;padding:1px 4px;border-radius:3px;">A:</span> Emoci\u00f3n audio</div>
          <div><strong>Borde rojo:</strong> valor alto | <strong>Borde azul:</strong> valor bajo</div>
        </div>')
        
        html <- c(html, paste0('<p>Se muestran los <strong>', ej_n, '</strong> GEs con valores m\u00e1s altos y m\u00e1s bajos de cada variable',
                  if (ej_min_dur > 0) paste0(' (duraci\u00f3n \u2265 ', ej_min_dur, 's)') else '',
                  if (ej_min_pal > 0) paste0(' (palabras \u2265 ', ej_min_pal, ')') else '',
                  ', con contexto y curva mel\u00f3dica.</p>'))
        
        for (v in vars_num) {
          if (!v %in% colnames(df) || !is.numeric(df[[v]])) next
          html <- c(html, paste0('<h3>', v, '</h3>'))
          html <- c(html, generar_ejemplos_extremos(v, df, ej_n, ej_min_dur, ej_min_pal,
                                                     construir_contexto_html, phones_all_ej, grp_col = var_cat,
                                                     max_dur = ej_max_dur, max_pal = ej_max_pal, direccion = ej_direccion,
                                                     filtro_acento = ej_acento))
        }
        
        # Comentario
        if (comentario_modo != "ninguno") {
          ej_text <- paste0("Ejemplos extremos de ", length(vars_num), " variables. ",
                            ej_n, " ejemplos altos + ", ej_n, " bajos por variable.\n")
          for (v in vars_num) {
            if (v %in% colnames(df) && is.numeric(df[[v]])) {
              vals <- df[[v]][!is.na(df[[v]])]
              if (length(vals) > 0) {
                ej_text <- paste0(ej_text, v, ": rango [", round(min(vals),2), " - ", round(max(vals),2), 
                                  "], media=", round(mean(vals),2), "\n")
              }
            }
          }
          html <- c(html, generar_comentario("Ejemplos extremos", ej_text))
        }
      }
      if ("curvas_melodicas" %in% secciones) {
        seccion_num <- seccion_num + 1
        html <- c(html, paste0('<h2>', seccion_num, '. Curvas melódicas por patrón</h2>'))
        
        sistema <- input$inf_curva_sistema  # "amh" o "tobi"
        col_patron <- if (sistema == "amh") "amh_patron" else "tobi_nuclear"
        max_patrones <- input$inf_curva_max_patrones
        ej_por_patron <- input$inf_curva_ejemplos_por_patron
        normalizar <- isTRUE(input$inf_curva_normalizar)
        
        if (col_patron %in% colnames(df) && !is.null(datos$phones)) {
          phones_all <- datos$phones
          
          # Get pattern counts
          patron_tab <- table(df[[col_patron]][!is.na(df[[col_patron]]) & df[[col_patron]] != ""])
          patron_tab <- sort(patron_tab, decreasing = TRUE)
          patrones <- names(patron_tab)[seq_len(min(max_patrones, length(patron_tab)))]
          
          html <- c(html, paste0('<p>Sistema: <strong>', toupper(sistema), '</strong> | Patrones: ', length(patrones),
                                  ' | Ejemplos por patrón: ', ej_por_patron,
                                  if (normalizar) ' | F0 normalizado (base 100)' else ' | F0 en semitonos', '</p>'))
          
          for (pat in patrones) {
            ge_pat <- df[!is.na(df[[col_patron]]) & df[[col_patron]] == pat, ]
            if (nrow(ge_pat) == 0) next
            
            n_ej <- min(ej_por_patron, nrow(ge_pat))
            ge_sample <- ge_pat[sample(nrow(ge_pat), n_ej), , drop = FALSE]
            
            # For each example, get phones and draw curve
            tryCatch({
              img_html <- save_and_embed(quote({
                library(ggplot2)
                all_pitch <- data.frame()
                all_int <- data.frame()
                all_trans <- data.frame()
                all_markers <- data.frame()  # tónicas y picos
                
                for (k in 1:nrow(ge_sample)) {
                  ge_row <- ge_sample[k, ]
                  ph <- phones_all[phones_all$filename == ge_row$filename & 
                                     phones_all$hablante == ge_row$hablante &
                                     phones_all$grupo_fonico == ge_row$grupo_fonico &
                                     phones_all$grupo_entonativo == ge_row$grupo_entonativo, ]
                  ph <- ph[order(ph$inicio), ]
                  if (nrow(ph) == 0) next
                  
                  # F0 — siempre usamos Hz como base para normalización AMH:
                  # Hz > 0 siempre → f0_norm nunca puede ser negativo
                  ph_valid_st  <- ph[!is.na(ph$f0_media_st), ]
                  ph_valid_hz  <- ph[!is.na(ph$f0_media_hz) & ph$f0_media_hz > 0, ]
                  # Usar la intersección de filas válidas en ambas columnas si es posible
                  if (nrow(ph_valid_hz) >= 2) {
                    ph_valid <- ph_valid_hz
                    f0_hz_base <- ph_valid$f0_media_hz
                    base_f0_hz <- f0_hz_base[1]
                    f0_norm <- (f0_hz_base / base_f0_hz) * 100
                  } else if (nrow(ph_valid_st) >= 2) {
                    ph_valid <- ph_valid_st
                    # Convertir St → Hz proporcional para evitar negativos
                    f0_hz_approx <- 2^(ph_valid$f0_media_st / 12)
                    base_hz_approx <- f0_hz_approx[1]
                    f0_norm <- if (base_hz_approx > 0) (f0_hz_approx / base_hz_approx) * 100 else f0_hz_approx
                  } else { next }
                  if (nrow(ph_valid) == 0) next
                  
                  # Intensidad normalizada base 100 — proporción lineal sobre base positiva
                  int_norm <- rep(NA, nrow(ph_valid))
                  if ("int_media" %in% colnames(ph_valid)) {
                    int_raw <- ph_valid$int_media
                    base_int <- int_raw[!is.na(int_raw) & int_raw > 0]
                    base_int <- if (length(base_int) > 0) base_int[1] else NA
                    if (!is.na(base_int) && base_int > 0)
                      int_norm <- ifelse(is.na(int_raw) | int_raw <= 0, NA, (int_raw / base_int) * 100)
                  }
                  
                  # Transiciones normalizadas base 100
                  trans_norm <- rep(NA, nrow(ph_valid))
                  if ("tiempo_transicion_anterior" %in% colnames(ph_valid)) {
                    trans_raw <- ph_valid$tiempo_transicion_anterior
                    trans_mean <- mean(trans_raw, na.rm = TRUE)
                    if (!is.na(trans_mean) && trans_mean > 0) trans_norm <- (trans_raw / trans_mean) * 100
                  }
                  
                  etiq <- ph_valid$etiqueta
                  palabra <- if ("palabra" %in% colnames(ph_valid)) ph_valid$palabra else rep("", nrow(ph_valid))
                  # Etiqueta de dos líneas: vocal + (palabra) si es distinta
                  etiq_full <- mapply(function(e, p) {
                    if (is.na(p) || p == "" || p == e) e
                    else paste0(e, "\n(", p, ")")
                  }, etiq, palabra, USE.NAMES = FALSE)
                  
                  # Incremento % entre vocales
                  inc_pct <- c(NA, round(diff(f0_norm) / head(f0_norm, -1) * 100, 1))
                  # Etiqueta con incremento (tercera línea)
                  etiq_label <- etiq_full
                  has_inc <- !is.na(inc_pct) & inc_pct != 0
                  etiq_label[has_inc] <- paste0(etiq_full[has_inc], "\n",
                    ifelse(inc_pct[has_inc] > 0, "+", ""), round(inc_pct[has_inc], 1), "%")
                  
                  label <- if ("palabras_grupo" %in% colnames(ge_row) && !is.na(ge_row$palabras_grupo)) 
                    substr(ge_row$palabras_grupo, 1, 35) else paste0("Ej.", k)
                  
                  pos <- seq_along(f0_norm)
                  
                  # Pitch
                  all_pitch <- rbind(all_pitch, data.frame(
                    pos = pos, valor = f0_norm, etiq = etiq_label, ejemplo = label, stringsAsFactors = FALSE))
                  
                  # Intensidad
                  if (any(!is.na(int_norm))) {
                    all_int <- rbind(all_int, data.frame(
                      pos = pos, valor = int_norm, ejemplo = label, stringsAsFactors = FALSE))
                  }
                  
                  # Transiciones (barras)
                  trans_valid <- !is.na(trans_norm) & trans_norm > 0
                  if (any(trans_valid)) {
                    all_trans <- rbind(all_trans, data.frame(
                      pos = pos[trans_valid], valor = trans_norm[trans_valid], ejemplo = label, stringsAsFactors = FALSE))
                  }
                  
                  # Marcadores: tónicas
                  if ("tonica_gramatical" %in% colnames(ph_valid)) {
                    idx_ton <- which(!is.na(ph_valid$tonica_gramatical) & ph_valid$tonica_gramatical == "sí")
                    if (length(idx_ton) > 0) {
                      all_markers <- rbind(all_markers, data.frame(
                        pos = idx_ton, valor = f0_norm[idx_ton], tipo = "Tónica",
                        etiq = paste0("TÓNICA: ", etiq_full[idx_ton]),
                        ejemplo = label, stringsAsFactors = FALSE))
                    }
                  }
                  
                  # Marcadores: picos tonales
                  if ("es_pico_grupo" %in% colnames(ph_valid)) {
                    idx_pico <- which(!is.na(ph_valid$es_pico_grupo) & ph_valid$es_pico_grupo == TRUE)
                    if (length(idx_pico) > 0) {
                      all_markers <- rbind(all_markers, data.frame(
                        pos = idx_pico, valor = f0_norm[idx_pico], tipo = "Pico grupo",
                        etiq = paste0("PICO: ", etiq_full[idx_pico]),
                        ejemplo = label, stringsAsFactors = FALSE))
                    }
                  }
                  if ("es_pico_palabra" %in% colnames(ph_valid)) {
                    idx_pp <- which(!is.na(ph_valid$es_pico_palabra) & ph_valid$es_pico_palabra == TRUE &
                                      !(seq_len(nrow(ph_valid)) %in% which(!is.na(ph_valid$es_pico_grupo) & ph_valid$es_pico_grupo)))
                    if (length(idx_pp) > 0) {
                      all_markers <- rbind(all_markers, data.frame(
                        pos = idx_pp, valor = f0_norm[idx_pp], tipo = "Pico palabra",
                        etiq = paste0("pico: ", etiq_full[idx_pp]),
                        ejemplo = label, stringsAsFactors = FALSE))
                    }
                  }
                }
                
                if (nrow(all_pitch) > 0) {
                  p <- ggplot()
                  
                  # Transiciones como barras grises (vocal 1 excluida = NA)
                  if (nrow(all_trans) > 0) {
                    p <- p + geom_bar(data = all_trans, aes(x = pos, y = valor),
                                       stat = "identity", alpha = 0.18, width = 0.35,
                                       fill = "#555555", show.legend = FALSE)
                  }
                  
                  # Intensidad (línea VERDE punteada)
                  if (nrow(all_int) > 0) {
                    p <- p + geom_line(data = all_int, aes(x = pos, y = valor, group = ejemplo),
                                        color = "#2e7d32", linetype = "dashed", linewidth = 0.9, alpha = 0.8) +
                      geom_point(data = all_int, aes(x = pos, y = valor),
                                  color = "#2e7d32", shape = 15, size = 2, alpha = 0.8)
                  }
                  
                  # Pitch (línea AZUL principal)
                  p <- p + geom_line(data = all_pitch, aes(x = pos, y = valor, color = ejemplo, group = ejemplo),
                                      linewidth = 1.3) +
                    geom_point(data = all_pitch, aes(x = pos, y = valor, color = ejemplo), size = 2.5) +
                    scale_color_brewer(palette = "Blues", direction = -1)
                  
                  # Etiquetas vocales + palabra (dos líneas)
                  p <- p + geom_text(data = all_pitch, aes(x = pos, y = valor, label = etiq, color = ejemplo),
                                      vjust = -1.2, size = 2.0, show.legend = FALSE, lineheight = 0.82)
                  
                  # Marcadores tónicas — triángulo más pequeño (size 4)
                  tonicas <- all_markers[all_markers$tipo == "Tónica", ]
                  if (nrow(tonicas) > 0) {
                    p <- p + geom_point(data = tonicas, aes(x = pos, y = valor),
                                         shape = 17, size = 4, color = "gold3", show.legend = FALSE) +
                      geom_point(data = tonicas, aes(x = pos, y = valor),
                                  shape = 2, size = 4, color = "black", stroke = 0.6, show.legend = FALSE)
                  }
                  
                  # Marcadores picos grupo — círculo con borde rojo (shape 21, renderiza bien)
                  picos_g <- all_markers[all_markers$tipo == "Pico grupo", ]
                  if (nrow(picos_g) > 0) {
                    p <- p + geom_point(data = picos_g, aes(x = pos, y = valor),
                                         shape = 21, size = 3.5, fill = "white",
                                         color = "darkred", stroke = 1.5, show.legend = FALSE)
                  }
                  
                  # Picos palabra (diamante naranja)
                  picos_p <- all_markers[all_markers$tipo == "Pico palabra", ]
                  if (nrow(picos_p) > 0) {
                    p <- p + geom_point(data = picos_p, aes(x = pos, y = valor),
                                         shape = 23, size = 3, fill = "orange",
                                         color = "darkorange3", stroke = 1, show.legend = FALSE)
                  }
                  
                  # Base 100 reference
                  p <- p + geom_hline(yintercept = 100, linetype = "dashed", alpha = 0.3, color = "grey50")
                  
                  # Leyenda descriptiva (caption en lugar de annotate para mayor compatibilidad)
                  p <- p + theme_minimal(base_size = 12) +
                    labs(title = paste0("Patrón ", pat, " (n=", nrow(ge_pat), ")"),
                         x = NULL, y = "Normalizado (base 100 = 1ª vocal)",
                         color = "Ejemplo",
                         caption = "— Pitch (azul)   ―― Intensidad (verde)   ▮ Transición   ▲ Tónica   ● Pico grupo   ◆ Pico palabra") +
                    theme(legend.position = "bottom", plot.title = element_text(face = "bold"),
                          plot.caption = element_text(size = 8, color = "grey50"),
                          axis.text.x = element_text(size = 8, lineheight = 0.82))
                  
                  print(p)
                } else {
                  plot.new(); text(0.5, 0.5, paste("Sin datos para", pat))
                }
              }), paste0("curva_", sistema, "_", gsub("[^a-zA-Z0-9]", "", pat)), ancho = 11, alto = 7)
              
              fig_num <- fig_num + 1
              html <- c(html, paste0('<h3>', pat, ' (n=', nrow(ge_pat), ')</h3>'), img_html,
                paste0('<p class="meta"><em>Figura ', fig_num, '. Curva melódica para patrón ', pat, 
                       ' (', toupper(sistema), ', n=', nrow(ge_pat), ').</em></p>'))
            }, error = function(e) {
              html <<- c(html, paste0('<div class="warning-box">Error curva ', pat, ': ', e$message, '</div>'))
            })
          }
          
          # If grouping variable: show pattern distribution per group
          if (!is.null(var_cat) && var_cat %in% colnames(df)) {
            tryCatch({
              img_dist <- save_and_embed(quote({
                df_pat <- df[!is.na(df[[col_patron]]) & df[[col_patron]] %in% patrones & !is.na(df[[var_cat]]), ]
                if (nrow(df_pat) > 0) {
                  # Set2 solo da 8 colores: interpolar para cubrir todas las categorías de var_cat
                  n_g   <- length(unique(as.character(df_pat[[var_cat]])))
                  pal_g <- colorRampPalette(
                    RColorBrewer::brewer.pal(min(8L, max(3L, n_g)), "Set2"))(n_g)
                  p <- ggplot(df_pat, aes(x = .data[[col_patron]], fill = .data[[var_cat]])) +
                    geom_bar(position = "dodge") +
                    theme_minimal(base_size = 12) +
                    labs(title = paste0("Distribución de patrones ", toupper(sistema), " por ", var_cat),
                         x = "Patrón", y = "Frecuencia", fill = var_cat) +
                    theme(axis.text.x = element_text(angle = 45, hjust = 1), legend.position = "bottom") +
                    scale_fill_manual(values = pal_g)
                  print(p)
                }
              }), paste0("dist_patrones_", sistema), ancho = 10, alto = 6)
              fig_num <- fig_num + 1
              html <- c(html, '<h3>Distribución de patrones por grupo</h3>', img_dist,
                paste0('<p class="meta"><em>Figura ', fig_num, '. Distribución de patrones ', toupper(sistema), ' por ', var_cat, '.</em></p>'))
            }, error = function(e) {
              html <<- c(html, paste0('<div class="warning-box">Error distribución: ', e$message, '</div>'))
            })
          }
        } else {
          html <- c(html, paste0('<div class="warning-box">Columna ', col_patron, ' no disponible. Recalcular datos.</div>'))
        }
        # Comentario curvas melódicas
        if (comentario_modo != "ninguno" && col_patron %in% colnames(df)) {
          curva_text <- paste0("Distribución de patrones melódicos (", toupper(sistema), "):\n")
          pat_tab <- sort(table(df[[col_patron]][!is.na(df[[col_patron]]) & df[[col_patron]] != ""]), decreasing = TRUE)
          for (p_name in names(pat_tab)) {
            curva_text <- paste0(curva_text, "  ", p_name, ": ", pat_tab[p_name], " (", round(pat_tab[p_name]/sum(pat_tab)*100,1), "%)\n")
          }
          if (!is.null(var_cat) && var_cat %in% colnames(df)) {
            curva_text <- paste0(curva_text, "\nDistribución cruzada patrones x ", var_cat, ":\n")
            cross_tab <- table(df[[col_patron]], df[[var_cat]])
            curva_text <- paste0(curva_text, paste(capture.output(cross_tab), collapse = "\n"))
          }
          html <- c(html, generar_comentario("Curvas melódicas por patrón", curva_text))
        }
      }
      
      } # ---- END for (grupo_actual in grupos_iter) ----
      
      # ============================================================
      # SECCIÓN: Corolario de Hidalgo Navarro (fuera del bucle de grupos)
      # ============================================================
      if ("corolario_hidalgo" %in% secciones) {
        seccion_num <- seccion_num + 1
        html <- c(html, paste0('<h2>', seccion_num, '. Corolario de Hidalgo Navarro</h2>'))

        cl_inf <- datos$clausulas
        var_cor <- if (!is.null(input$inf_corolario_var_grupo)) input$inf_corolario_var_grupo else "filename"

        if (!is.null(cl_inf) && nrow(cl_inf) > 0) {

          # ── Propagar variable de agrupación si no está en cl_inf ──────────
          if (!var_cor %in% colnames(cl_inf)) {
            ips_aux <- datos$ips_resumen
            if (!is.null(ips_aux) && var_cor %in% colnames(ips_aux)) {
              cl_inf <- left_join(cl_inf,
                ips_aux %>% select(filename, hablante, all_of(var_cor)) %>% distinct(),
                by = c("filename", "hablante"))
            }
          }

          if (var_cor %in% colnames(cl_inf)) {

            # ── Calcular variables por cláusula ───────────────────────────
            # Jerarquía: la cláusula agrupa >1 GE (estructura interna subordinada)
            cl_inf$cumple_jerarquia <- as.integer(!is.na(cl_inf$n_ge) & cl_inf$n_ge > 1)
            # Contorno: tres categorías (declinación / inclinación / suspensión)
            cl_inf$contorno <- dplyr::case_when(
              !is.na(cl_inf$tipo) & cl_inf$tipo == "descendente" ~ "Declinación",
              !is.na(cl_inf$tipo) & cl_inf$tipo == "ascendente"  ~ "Inclinación",
              !is.na(cl_inf$tipo) & cl_inf$tipo == "plana"       ~ "Suspensión",
              TRUE ~ NA_character_
            )
            # Recursividad GLOBAL: número de cláusulas por hablante/archivo
            n_cl_global <- nrow(cl_inf)
            n_hablantes_con_varias <- cl_inf %>%
              group_by(filename, hablante) %>% summarise(n = n(), .groups = "drop") %>%
              filter(n > 1) %>% nrow()
            n_hablantes_total <- cl_inf %>%
              select(filename, hablante) %>% distinct() %>% nrow()
            pct_rec_global <- round(n_hablantes_con_varias / max(n_hablantes_total, 1) * 100, 1)

            # ── Resumen por categoría ─────────────────────────────────────
            resumen_cor <- cl_inf %>%
              rename(.cat = all_of(var_cor)) %>%
              filter(!is.na(.cat)) %>%
              group_by(.cat) %>%
              summarise(
                n_clausulas      = n(),
                n_jerarquia      = sum(cumple_jerarquia, na.rm = TRUE),
                pct_jerarquia    = round(n_jerarquia / n_clausulas * 100, 1),
                ge_medio         = round(mean(n_ge, na.rm = TRUE), 2),
                n_declinacion    = sum(contorno == "Declinación", na.rm = TRUE),
                n_inclinacion    = sum(contorno == "Inclinación", na.rm = TRUE),
                n_suspension     = sum(contorno == "Suspensión",  na.rm = TRUE),
                pct_declinacion  = round(n_declinacion / n_clausulas * 100, 1),
                pct_inclinacion  = round(n_inclinacion / n_clausulas * 100, 1),
                pct_suspension   = round(n_suspension  / n_clausulas * 100, 1),
                .groups = "drop"
              ) %>%
              arrange(desc(n_clausulas)) %>%
              rename(categoria = .cat)

            overall_cor <- data.frame(
              categoria       = "TOTAL",
              n_clausulas     = nrow(cl_inf),
              n_jerarquia     = sum(cl_inf$cumple_jerarquia, na.rm = TRUE),
              pct_jerarquia   = round(sum(cl_inf$cumple_jerarquia, na.rm = TRUE) / nrow(cl_inf) * 100, 1),
              ge_medio        = round(mean(cl_inf$n_ge, na.rm = TRUE), 2),
              n_declinacion   = sum(cl_inf$contorno == "Declinación", na.rm = TRUE),
              n_inclinacion   = sum(cl_inf$contorno == "Inclinación", na.rm = TRUE),
              n_suspension    = sum(cl_inf$contorno == "Suspensión",  na.rm = TRUE),
              pct_declinacion = round(sum(cl_inf$contorno == "Declinación", na.rm=TRUE) / nrow(cl_inf) * 100, 1),
              pct_inclinacion = round(sum(cl_inf$contorno == "Inclinación", na.rm=TRUE) / nrow(cl_inf) * 100, 1),
              pct_suspension  = round(sum(cl_inf$contorno == "Suspensión",  na.rm=TRUE) / nrow(cl_inf) * 100, 1),
              stringsAsFactors = FALSE
            )

            resumen_total <- bind_rows(resumen_cor, overall_cor)

            # ── Introducción con definiciones ──────────────────────────────
            html <- c(html, paste0(
              '<p>Esta sección evalúa el cumplimiento de los tres principios supraentonativos ',
              'de Hidalgo Navarro (2006) sobre las <strong>', n_cl_global, ' cláusulas</strong> ',
              'detectadas, agrupadas por <em>', htmltools::htmlEscape(var_cor), '</em>.</p>',
              '<ul>',
              '<li><strong>Jerarquía:</strong> una cláusula es jerárquica cuando contiene más de un ',
              'grupo entonativo (GE). Indica que la unidad tonal está internamente articulada en ',
              'subestructuras subordinadas. Se mide como % de cláusulas con &gt;1 GE, y se informa ',
              'también el número medio de GEs por cláusula.</li>',
              '<li><strong>Contorno tonal (declinación / inclinación / suspensión):</strong> el contorno ',
              'de la cláusula refleja la dirección global de la F0. <em>Declinación</em> (pendiente ',
              'descendente) es el patrón canónico del enunciado declarativo. <em>Inclinación</em> ',
              '(ascendente) aparece en preguntas o énfasis. <em>Suspensión</em> (contorno plano) ',
              'indica continuidad o énfasis sostenido.</li>',
              '<li><strong>Recursividad:</strong> principio estructural global — se cumple cuando un ',
              'hablante/archivo produce más de una cláusula, lo que permite la organización ',
              'supraentonativa jerárquica. En este corpus el <strong>', pct_rec_global, '%</strong> ',
              'de los hablantes/archivos presenta más de una cláusula (',
              n_hablantes_con_varias, ' de ', n_hablantes_total, ').</li>',
              '</ul>'))

            # ── Tabla HTML ────────────────────────────────────────────────
            html <- c(html, '<h3>Tabla de frecuencias y porcentajes por categoría</h3>')
            # Cabecera con grupos de columnas
            html <- c(html, paste0(
              '<table border="1" cellpadding="5" cellspacing="0" ',
              'style="border-collapse:collapse;font-size:0.88em;width:100%;">',
              '<thead>',
              '<tr style="background:#2c3e50;color:white;text-align:center;">',
              '<th rowspan="2">Categoría<br>(', htmltools::htmlEscape(var_cor), ')</th>',
              '<th rowspan="2">N<br>cláusulas</th>',
              '<th colspan="2" style="background:#3498DB;">Jerarquía</th>',
              '<th colspan="1" style="background:#3498DB;">GEs/cláusula</th>',
              '<th colspan="2" style="background:#e74c3c;">Declinación</th>',
              '<th colspan="2" style="background:#e67e22;">Inclinación</th>',
              '<th colspan="2" style="background:#8e44ad;">Suspensión</th>',
              '</tr>',
              '<tr style="background:#ecf0f1;font-size:0.85em;text-align:center;">',
              '<th style="background:#d6eaf8;">n</th><th style="background:#d6eaf8;">%</th>',
              '<th style="background:#d6eaf8;">media</th>',
              '<th style="background:#fadbd8;">n</th><th style="background:#fadbd8;">%</th>',
              '<th style="background:#fdebd0;">n</th><th style="background:#fdebd0;">%</th>',
              '<th style="background:#e8daef;">n</th><th style="background:#e8daef;">%</th>',
              '</tr>',
              '</thead><tbody>'))
            for (ri in seq_len(nrow(resumen_total))) {
              is_total <- resumen_total$categoria[ri] == "TOTAL"
              row_style <- if (is_total) ' style="background:#f0f0f0;font-weight:bold;"' else ''
              html <- c(html, paste0('<tr', row_style, '>',
                '<td>', htmltools::htmlEscape(as.character(resumen_total$categoria[ri])), '</td>',
                '<td style="text-align:center;">', resumen_total$n_clausulas[ri], '</td>',
                '<td style="text-align:center;">', resumen_total$n_jerarquia[ri], '</td>',
                '<td style="text-align:center;">', resumen_total$pct_jerarquia[ri], '%</td>',
                '<td style="text-align:center;">', resumen_total$ge_medio[ri], '</td>',
                '<td style="text-align:center;">', resumen_total$n_declinacion[ri], '</td>',
                '<td style="text-align:center;">', resumen_total$pct_declinacion[ri], '%</td>',
                '<td style="text-align:center;">', resumen_total$n_inclinacion[ri], '</td>',
                '<td style="text-align:center;">', resumen_total$pct_inclinacion[ri], '%</td>',
                '<td style="text-align:center;">', resumen_total$n_suspension[ri], '</td>',
                '<td style="text-align:center;">', resumen_total$pct_suspension[ri], '%</td>',
                '</tr>'))
            }
            html <- c(html, '</tbody></table>')

            # ── Gráfico 1: jerarquía y contorno por categoría ─────────────
            tryCatch({
              # datos para gráfico: jerarquía + 3 contornos
              resumen_long_local <- resumen_cor %>%
                select(categoria,
                       "Jerarquía (%)"    = pct_jerarquia,
                       "Declinación (%)"  = pct_declinacion,
                       "Inclinación (%)"  = pct_inclinacion,
                       "Suspensión (%)"   = pct_suspension) %>%
                tidyr::pivot_longer(-categoria, names_to = "variable", values_to = "porcentaje")

              graf_counter <<- graf_counter + 1
              fname_cor <- paste0(sprintf("%02d", graf_counter), "_corolario_barras.png")
              fpath_cor <- file.path(graf_dir, fname_cor)
              png(fpath_cor, width = 11, height = 6, units = "in", res = dpi_val)
              p_cor <- ggplot(resumen_long_local,
                              aes(x = categoria, y = porcentaje, fill = variable)) +
                geom_col(position = "dodge", color = "white", width = 0.72) +
                geom_hline(yintercept = 70, linetype = "dashed", color = "#27ae60", linewidth = 0.5) +
                geom_hline(yintercept = 40, linetype = "dashed", color = "#e6ac00", linewidth = 0.5) +
                scale_fill_manual(values = c(
                  "Jerarquía (%)"   = "#3498DB",
                  "Declinación (%)" = "#e74c3c",
                  "Inclinación (%)" = "#e67e22",
                  "Suspensión (%)"  = "#8e44ad")) +
                scale_y_continuous(limits = c(0, 105),
                                   labels = function(x) paste0(x, "%")) +
                labs(title = paste0("Corolario de Hidalgo Navarro por ", var_cor),
                     subtitle = "Líneas: 70% (verde) y 40% (amarillo) como referencias de cumplimiento",
                     x = NULL, y = "Porcentaje de cláusulas", fill = NULL) +
                theme_minimal(base_size = 12) +
                theme(axis.text.x = element_text(angle = 35, hjust = 1),
                      legend.position = "bottom")
              print(p_cor)
              dev.off()
              informe$graficos_paths[[fname_cor]] <- fpath_cor
              raw_b_cor <- readBin(fpath_cor, "raw", file.info(fpath_cor)$size)
              b64_cor   <- base64enc::base64encode(raw_b_cor)
              fig_num <- fig_num + 1
              html <- c(html,
                '<h3>Visualización por categoría</h3>',
                paste0('<img src="data:image/png;base64,', b64_cor, '" alt="corolario_barras">'),
                paste0('<p class="meta"><em>Figura ', fig_num,
                  '. Porcentaje de cláusulas que cumplen jerarquía y cada tipo de contorno, ',
                  'por categoría de <em>', htmltools::htmlEscape(var_cor), '</em>.</em></p>'))
            }, error = function(e) {
              tryCatch(dev.off(), error = function(e2) NULL)
              html <<- c(html, paste0('<div class="warning-box">Error gráfico corolario: ',
                                      htmltools::htmlEscape(e$message), '</div>'))
            })

            # ── Gráfico 2: distribución de contornos apilada 100 % ────────
            tryCatch({
              contorno_long <- resumen_cor %>%
                select(categoria, Declinación = n_declinacion,
                       Inclinación = n_inclinacion, Suspensión = n_suspension) %>%
                tidyr::pivot_longer(-categoria, names_to = "contorno", values_to = "n") %>%
                group_by(categoria) %>%
                mutate(pct = round(n / sum(n) * 100, 1)) %>% ungroup()

              graf_counter <<- graf_counter + 1
              fname_cor2 <- paste0(sprintf("%02d", graf_counter), "_corolario_contorno.png")
              fpath_cor2 <- file.path(graf_dir, fname_cor2)
              png(fpath_cor2, width = 9, height = 5, units = "in", res = dpi_val)
              p_cor2 <- ggplot(contorno_long,
                               aes(x = categoria, y = pct, fill = contorno)) +
                geom_col(position = "stack", color = "white", width = 0.6) +
                geom_text(aes(label = ifelse(pct >= 5, paste0(pct, "%"), "")),
                          position = position_stack(vjust = 0.5),
                          size = 2, color = "white", fontface = "bold") +
                scale_fill_manual(values = c(
                  "Declinación" = "#e74c3c",
                  "Inclinación" = "#e67e22",
                  "Suspensión"  = "#8e44ad")) +
                scale_y_continuous(labels = function(x) paste0(x, "%")) +
                labs(title = "Distribución de contornos tonales por categoría",
                     subtitle = "Barras al 100% — declinación / inclinación / suspensión",
                     x = NULL, y = "% de cláusulas", fill = "Contorno") +
                theme_minimal(base_size = 12) +
                theme(axis.text.x = element_text(angle = 35, hjust = 1),
                      legend.position = "bottom")
              print(p_cor2)
              dev.off()
              informe$graficos_paths[[fname_cor2]] <- fpath_cor2
              raw_b2 <- readBin(fpath_cor2, "raw", file.info(fpath_cor2)$size)
              b64_2  <- base64enc::base64encode(raw_b2)
              fig_num <- fig_num + 1
              html <- c(html,
                paste0('<img src="data:image/png;base64,', b64_2, '" alt="corolario_contorno">'),
                paste0('<p class="meta"><em>Figura ', fig_num,
                  '. Distribución relativa (100%) de los tres tipos de contorno tonal por categoría.</em></p>'))
            }, error = function(e) {
              tryCatch(dev.off(), error = function(e2) NULL)
              html <<- c(html, paste0('<div class="warning-box">Error gráfico contorno: ',
                                      htmltools::htmlEscape(e$message), '</div>'))
            })

            # ── Tests estadísticos ────────────────────────────────────────
            if (nrow(resumen_cor) >= 2) {
              html <- c(html, '<h3>Análisis estadístico</h3>')

              # Función auxiliar que ejecuta chi-cuadrado/Fisher y devuelve HTML
              hacer_test_chi <- function(tbl, nombre_var, etiq_cumple = NULL) {
                col_sums <- colSums(tbl)
                if (any(col_sums == 0) || nrow(tbl) < 2 || ncol(tbl) < 2) return(NULL)
                exp_vals <- tryCatch(chisq.test(tbl, correct = FALSE)$expected,
                                     error = function(e) NULL)
                usar_fisher <- !is.null(exp_vals) && any(exp_vals < 5) && all(dim(tbl) == c(2, 2))
                if (usar_fisher) {
                  res  <- tryCatch(fisher.test(tbl), error = function(e) NULL)
                  tnm  <- "Fisher"
                  pval <- if (!is.null(res)) res$p.value else NA_real_
                  stt  <- if (!is.null(res) && !is.null(res$estimate))
                            paste0("OR = ", round(res$estimate, 3)) else "n/a"
                  std_res <- NULL
                } else {
                  res  <- tryCatch(chisq.test(tbl, correct = FALSE), error = function(e) NULL)
                  tnm  <- "χ²"
                  pval <- if (!is.null(res)) res$p.value else NA_real_
                  stt  <- if (!is.null(res))
                            paste0("χ²(", res$parameter, ") = ", round(res$statistic, 3)) else "n/a"
                  std_res <- if (!is.null(res)) res$stdres else NULL
                }
                p_str   <- if (!is.na(pval)) format.pval(pval, digits = 3, eps = .001) else "n/a"
                sig_str <- if (!is.na(pval)) {
                  if      (pval < .001) " ***" else if (pval < .01) " **"
                  else if (pval < .05)  " *"   else " (n.s.)"
                } else ""
                col_p <- if (!is.na(pval) && pval < .05) "#c0392b" else "#555"
                out <- paste0('<strong>', nombre_var, '</strong> (', tnm, '): ',
                  stt, ' — <em>p</em> = <span style="color:', col_p, ';">',
                  p_str, sig_str, '</span>')
                if (!is.null(std_res)) {
                  res_df  <- as.data.frame(std_res)
                  colnames(res_df) <- c("Cat", "Nivel", "z")
                  res_df$z <- round(res_df$z, 2)
                  res_sig <- res_df[abs(res_df$z) > 1.96, ]
                  # En tablas 2 columnas, eliminar celdas espejo: quedarse con 1 fila por categoría
                  # (la de mayor |z|, que siempre coincide con ambas al ser simétricas)
                  if (ncol(tbl) == 2 && nrow(res_sig) > 0) {
                    res_sig <- res_sig %>%
                      group_by(Cat) %>%
                      slice_max(order_by = z, n = 1, with_ties = FALSE) %>%
                      ungroup() %>% as.data.frame()
                  }
                  if (nrow(res_sig) > 0) {
                    out <- paste0(out, '<br><em style="font-size:0.9em;">',
                      'Residuos |z| &gt; 1.96 (celdas que más contribuyen a la diferencia):</em><br>')
                    for (rk in seq_len(nrow(res_sig))) {
                      lbl <- if (!is.null(etiq_cumple)) {
                        lvl <- as.character(res_sig$Nivel[rk])
                        if (lvl == "1" || lvl == "Cumple") "cumple jerarquía"
                        else if (lvl == "0" || lvl == "No cumple") "NO cumple jerarquía"
                        else lvl
                      } else as.character(res_sig$Nivel[rk])
                      sentido <- if (res_sig$z[rk] > 0) "más frecuente de lo esperado" else "menos frecuente de lo esperado"
                      col_r <- if (res_sig$z[rk] > 0) "#1a6b1a" else "#b03a2e"
                      out <- paste0(out, '&nbsp;&nbsp;<span style="color:', col_r, ';">',
                        htmltools::htmlEscape(as.character(res_sig$Cat[rk])),
                        ' [', lbl, ']: z = ', res_sig$z[rk], ' → ', sentido, '</span><br>')
                    }
                  } else {
                    out <- paste0(out, '<br><em style="font-size:0.9em;">',
                      'No hay celdas con residuo |z| &gt; 1.96: las diferencias son pequeñas.</em><br>')
                  }
                }
                out
              }

              # Función auxiliar: interpreta en prosa los residuos de un test
              # Devuelve un string HTML con una o dos frases contextualizadas
              interpretar_residuos <- function(res_df_sig, tipo_var, resumen_cor_local, overall_cor_local, var_cor_local) {
                if (is.null(res_df_sig) || nrow(res_df_sig) == 0) {
                  return('<p style="color:#555;font-style:italic;">Las diferencias entre categorías son pequeñas y no permiten identificar ninguna categoría que destaque de forma clara.</p>')
                }
                parrafos <- character(0)
                cats_vistas <- character(0)
                for (rk in seq_len(nrow(res_df_sig))) {
                  cat_k  <- as.character(res_df_sig$Cat[rk])
                  niv_k  <- as.character(res_df_sig$Nivel[rk])
                  z_k    <- res_df_sig$z[rk]
                  if (cat_k %in% cats_vistas) next
                  cats_vistas <- c(cats_vistas, cat_k)
                  # Buscar porcentajes reales de esta categoría
                  fila_res <- resumen_cor_local[resumen_cor_local$categoria == cat_k, ]
                  if (nrow(fila_res) == 0) next
                  if (tipo_var == "jerarquia") {
                    pct_k  <- fila_res$pct_jerarquia[1]
                    ge_k   <- fila_res$ge_medio[1]
                    global_pct <- overall_cor_local$pct_jerarquia
                    niv_k <- as.character(res_df_sig$Nivel[rk])
                    # z positivo en "cumple" → más jerarquía; z positivo en "no cumple" → menos jerarquía
                    mas_jerarquia <- (z_k > 0 && (niv_k == "Cumple" || niv_k == "1")) ||
                                     (z_k < 0 && (niv_k == "No cumple" || niv_k == "0"))
                    if (mas_jerarquia) {
                      parrafos <- c(parrafos, paste0(
                        '<p><strong>', htmltools::htmlEscape(cat_k), '</strong> presenta una ',
                        'proporción de cláusulas jerárquicas (<em>',
                        pct_k, '%</em>) significativamente <strong>superior a la media del corpus (',
                        global_pct, '%)</strong>. Las cláusulas en este archivo o grupo contienen, ',
                        'de media, <em>', ge_k, ' GEs</em>, lo que indica una mayor articulación ',
                        'interna de las unidades supraentonativas: más grupos entonativos se encadenan ',
                        'bajo una misma cláusula prosódica.</p>'))
                    } else {
                      parrafos <- c(parrafos, paste0(
                        '<p><strong>', htmltools::htmlEscape(cat_k), '</strong> presenta una ',
                        'proporción de cláusulas jerárquicas (<em>',
                        pct_k, '%</em>) significativamente <strong>inferior a la media del corpus (',
                        global_pct, '%)</strong>. Esto significa que en este archivo o grupo ',
                        'las cláusulas tienden a contener un único grupo entonativo (sin subestructura ',
                        'tonal interna), con una media de <em>', ge_k, ' GE por cláusula</em>. ',
                        'Prosódicamente, las unidades supraentonativas son más simples o menos articuladas.</p>'))
                    }
                  } else if (tipo_var == "contorno") {
                    tipo_contorno <- niv_k
                    pct_tipo <- switch(tipo_contorno,
                      "Declinación" = fila_res$pct_declinacion[1],
                      "Inclinación" = fila_res$pct_inclinacion[1],
                      "Suspensión"  = fila_res$pct_suspension[1],
                      NA)
                    if (!is.na(pct_tipo)) {
                      if (z_k > 0) {
                        desc_dir <- switch(tipo_contorno,
                          "Declinación" = "un predominio de contornos descendentes, coherente con el patrón declarativo canónico del corolario",
                          "Inclinación" = "un predominio de contornos ascendentes, más propio de enunciados interrogativos o enfáticos",
                          "Suspensión"  = "un predominio de contornos planos o sostenidos, característico de la continuidad temática o del énfasis")
                        parrafos <- c(parrafos, paste0(
                          '<p><strong>', htmltools::htmlEscape(cat_k), '</strong> muestra ',
                          desc_dir, ' (<em>', pct_tipo, '%</em> de sus cláusulas), ',
                          'por encima de lo esperable si la distribución fuera homogénea entre archivos.</p>'))
                      } else {
                        desc_def <- switch(tipo_contorno,
                          "Declinación" = "menor presencia de contornos descendentes de lo esperable",
                          "Inclinación" = "menor presencia de contornos ascendentes de lo esperable",
                          "Suspensión"  = "menor presencia de contornos planos de lo esperable")
                        parrafos <- c(parrafos, paste0(
                          '<p><strong>', htmltools::htmlEscape(cat_k), '</strong> presenta ',
                          desc_def, ' (<em>', pct_tipo, '%</em> de sus cláusulas), ',
                          'lo que sugiere que sus unidades supraentonativas se distribuyen de forma ',
                          'distinta a la del resto del corpus.</p>'))
                      }
                    }
                  } else if (tipo_var == "declinacion") {
                    pct_dec_k  <- fila_res$pct_declinacion[1]
                    global_dec <- overall_cor_local$pct_declinacion
                    niv_k_dec  <- as.character(res_df_sig$Nivel[rk])
                    mas_declinacion <- (z_k > 0 && niv_k_dec == "Declinación") ||
                                       (z_k < 0 && niv_k_dec == "No declinación")
                    if (mas_declinacion) {
                      parrafos <- c(parrafos, paste0(
                        '<p><strong>', htmltools::htmlEscape(cat_k), '</strong> presenta una ',
                        'proporción de cláusulas con declinación (<em>', pct_dec_k, '%</em>) ',
                        '<strong>superior a la media del corpus (', global_dec, '%)</strong>. ',
                        'Este archivo o grupo se ajusta con mayor regularidad al patrón ',
                        'declarativo canónico del corolario de Hidalgo Navarro, en el que ',
                        'el contorno tonal de la cláusula es descendente.</p>'))
                    } else {
                      parrafos <- c(parrafos, paste0(
                        '<p><strong>', htmltools::htmlEscape(cat_k), '</strong> presenta una ',
                        'proporción de cláusulas con declinación (<em>', pct_dec_k, '%</em>) ',
                        '<strong>inferior a la media del corpus (', global_dec, '%)</strong>. ',
                        'El patrón declarativo descendente es menos frecuente aquí: ',
                        'las cláusulas tienden a resolverse con contornos ascendentes (inclinación) ',
                        'o planos (suspensión), lo que puede indicar mayor presencia de ',
                        'enunciados suspendidos, interrogativos o enfáticos.</p>'))
                    }
                  }
                }
                if (length(parrafos) == 0) return("")
                paste(parrafos, collapse = "\n")
              }

              # ── Test 1: Jerarquía ──────────────────────────────────────
              html <- c(html, paste0(
                '<h4>Principio de jerarquía</h4>',
                '<p>La jerarquía mide en qué proporción las cláusulas están internamente ',
                'articuladas en más de un GE. Una cláusula con un solo GE es la unidad ',
                'mínima; con dos o más, los grupos entonativos se subordinan y encadenan ',
                'dentro de ella. El test comprueba si esa proporción es la misma en todas ',
                'las categorías de <em>', htmltools::htmlEscape(var_cor), '</em> ',
                '(H₀: homogeneidad) o si alguna destaca por producir estructuras ',
                'sistemáticamente más simples o más complejas.</p>'))
              tryCatch({
                cl_j <- cl_inf %>%
                  rename(.c = all_of(var_cor)) %>%
                  filter(!is.na(.c), !is.na(cumple_jerarquia)) %>%
                  mutate(lbl = factor(cumple_jerarquia, levels = c(0,1),
                                      labels = c("No cumple","Cumple")))
                tbl_j <- table(cl_j$.c, cl_j$lbl)
                res_j_html <- hacer_test_chi(tbl_j, "Jerarquía", etiq_cumple = TRUE)
                # Residuos para interpretación
                res_j_obj <- tryCatch(chisq.test(tbl_j, correct = FALSE), error = function(e) NULL)
                if (!is.null(res_j_html)) {
                  html <- c(html, paste0('<p>', res_j_html, '</p>'))
                  if (!is.null(res_j_obj) && !is.null(res_j_obj$stdres)) {
                    res_j_df <- as.data.frame(res_j_obj$stdres)
                    colnames(res_j_df) <- c("Cat","Nivel","z")
                    res_j_df$z <- round(res_j_df$z, 2)
                    res_j_sig <- res_j_df[abs(res_j_df$z) > 1.96 &
                                          (res_j_df$Nivel == "No cumple" | res_j_df$Nivel == "0"), ]
                    # Tomar las filas de "no cumple" para identificar la categoría desviada
                    res_j_sig2 <- res_j_df[abs(res_j_df$z) > 1.96, ]
                    html <- c(html, interpretar_residuos(res_j_sig2, "jerarquia", resumen_cor, overall_cor, var_cor))
                  }
                } else {
                  html <- c(html, '<p><em>Test no aplicable (varianza cero o n insuficiente).</em></p>')
                }
              }, error = function(e) {
                html <<- c(html, paste0('<p>Error: ', htmltools::htmlEscape(e$message), '</p>'))
              })

              # ── Test 2: Distribución de contornos (3 tipos) ───────────
              html <- c(html, paste0(
                '<h4>Distribución de contornos tonales</h4>',
                '<p>Cada cláusula recibe un contorno global según la pendiente de su F0: ',
                '<strong>declinación</strong> (descendente, patrón canónico declarativo), ',
                '<strong>inclinación</strong> (ascendente, interrogativo o enfático) o ',
                '<strong>suspensión</strong> (plano, continuidad o énfasis sostenido). ',
                'El test contrasta si la distribución de estos tres tipos es la misma en ',
                'todas las categorías o si alguna se inclina sistemáticamente hacia un patrón.</p>'))
              tryCatch({
                cl_c <- cl_inf %>%
                  rename(.c = all_of(var_cor)) %>%
                  filter(!is.na(.c), !is.na(contorno))
                tbl_c <- table(cl_c$.c, cl_c$contorno)
                res_c_html <- hacer_test_chi(tbl_c, "Contorno tonal (3 tipos)")
                res_c_obj  <- tryCatch(chisq.test(tbl_c, correct = FALSE), error = function(e) NULL)
                if (!is.null(res_c_html)) {
                  html <- c(html, paste0('<p>', res_c_html, '</p>'))
                  if (!is.null(res_c_obj) && !is.null(res_c_obj$stdres)) {
                    res_c_df  <- as.data.frame(res_c_obj$stdres)
                    colnames(res_c_df) <- c("Cat","Nivel","z")
                    res_c_df$z <- round(res_c_df$z, 2)
                    res_c_sig <- res_c_df[abs(res_c_df$z) > 1.96, ]
                    html <- c(html, interpretar_residuos(res_c_sig, "contorno", resumen_cor, overall_cor, var_cor))
                  }
                } else {
                  html <- c(html, '<p><em>Test no aplicable.</em></p>')
                }
              }, error = function(e) {
                html <<- c(html, paste0('<p>Error: ', htmltools::htmlEscape(e$message), '</p>'))
              })

              # ── Test 3: Declinación vs. no-declinación ────────────────
              html <- c(html, paste0(
                '<h4>Declinación (contraste binario)</h4>',
                '<p>La declinación es el contorno esperado en el enunciado declarativo neutro. ',
                'Este test binario (declinación / no-declinación) comprueba directamente si ',
                'alguna categoría produce este patrón canónico con una frecuencia ',
                'significativamente distinta al resto del corpus.</p>'))
              tryCatch({
                cl_inf$es_declinacion <- as.integer(cl_inf$contorno == "Declinación")
                cl_d <- cl_inf %>%
                  rename(.c = all_of(var_cor)) %>%
                  filter(!is.na(.c), !is.na(es_declinacion)) %>%
                  mutate(lbl = factor(es_declinacion, levels = c(0,1),
                                      labels = c("No declinación","Declinación")))
                tbl_d <- table(cl_d$.c, cl_d$lbl)
                res_d_html <- hacer_test_chi(tbl_d, "Declinación")
                res_d_obj  <- tryCatch(chisq.test(tbl_d, correct = FALSE), error = function(e) NULL)
                if (!is.null(res_d_html)) {
                  html <- c(html, paste0('<p>', res_d_html, '</p>'))
                  if (!is.null(res_d_obj) && !is.null(res_d_obj$stdres)) {
                    res_d_df  <- as.data.frame(res_d_obj$stdres)
                    colnames(res_d_df) <- c("Cat","Nivel","z")
                    res_d_df$z <- round(res_d_df$z, 2)
                    # Tomar solo la celda "Declinación" para no repetir
                    res_d_sig <- res_d_df[abs(res_d_df$z) > 1.96 & res_d_df$Nivel == "Declinación", ]
                    html <- c(html, interpretar_residuos(res_d_sig, "declinacion", resumen_cor, overall_cor, var_cor))
                  }
                } else {
                  html <- c(html, '<p><em>Test no aplicable.</em></p>')
                }
              }, error = function(e) {
                html <<- c(html, paste0('<p>Error: ', htmltools::htmlEscape(e$message), '</p>'))
              })

              html <- c(html, paste0(
                '<p class="meta"><em>',
                '*** p &lt; .001, ** p &lt; .01, * p &lt; .05, n.s. = no significativo. ',
                'Se usa test exacto de Fisher cuando n esperado &lt; 5 en alguna celda (tabla 2×2).',
                '</em></p>'))
            } else {
              html <- c(html, '<p class="meta"><em>Solo una categoría disponible: test estadístico no aplicable.</em></p>')
            }

          } else {
            html <- c(html, paste0(
              '<div class="warning-box">La variable <em>', htmltools::htmlEscape(var_cor),
              '</em> no está disponible en los datos de cláusulas.</div>'))
          }
        } else {
          html <- c(html, '<div class="warning-box">No hay datos de cláusulas. Recalcula el análisis prosódico.</div>')
        }
      }
      
      incProgress(0.95, detail = "Finalizando...")
      html <- c(html, '<hr>', paste0('<p class="meta">LASP v5.0 | ', format(Sys.time(), "%d/%m/%Y %H:%M:%S"), '</p>'), '</body></html>')
      
      html_content <- paste(html, collapse = "\n")
      informe$html_content <- html_content
      
      html_path <- file.path(inf_dir, paste0("informe_", timestamp, ".html"))
      writeLines(html_content, html_path, useBytes = TRUE)
      
      # ---- Exportar a DOCX usando pandoc desde HTML ----
      if ("docx" %in% input$inf_formatos) {
        tryCatch({
          pandoc_bin <- rmarkdown::pandoc_exec()
          if (!is.null(pandoc_bin) && nchar(pandoc_bin) > 0 && file.exists(pandoc_bin)) {
            docx_path <- file.path(inf_dir, paste0("informe_", timestamp, ".docx"))
            system2(pandoc_bin, args = c(
              shQuote(html_path), "-f", "html", "-t", "docx",
              "-o", shQuote(docx_path),
              "--standalone"
            ), stdout = TRUE, stderr = TRUE)
            if (file.exists(docx_path)) {
              showNotification("Word (.docx) generado correctamente", type = "message", duration = 5)
            } else {
              showNotification("Error generando .docx", type = "warning")
            }
          } else {
            showNotification("Pandoc no encontrado. Instalar: install.packages('rmarkdown')", type = "warning")
          }
        }, error = function(e) showNotification(paste("Error Word:", e$message), type = "warning"))
      }
      
      # ---- Exportar a PDF ----
      if ("pdf" %in% input$inf_formatos) {
        tryCatch({
          pdf_path <- file.path(inf_dir, paste0("informe_", timestamp, ".pdf"))
          pdf_ok <- FALSE
          html_uri <- paste0("file://", normalizePath(html_path))
          
          # Detectar Chrome/Chromium en el sistema
          chrome_bin <- NULL
          chrome_candidates <- c(
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
            "/Applications/Chromium.app/Contents/MacOS/Chromium",
            "/Applications/Brave Browser.app/Contents/MacOS/Brave Browser",
            Sys.which("google-chrome"), Sys.which("chromium-browser"), Sys.which("chromium"),
            "C:/Program Files/Google/Chrome/Application/chrome.exe",
            "C:/Program Files (x86)/Google/Chrome/Application/chrome.exe"
          )
          for (cb in chrome_candidates) {
            if (nchar(cb) > 0 && file.exists(cb)) { chrome_bin <- cb; break }
          }
          
          # Método 1: Chrome/Chromium headless --print-to-pdf (sin dependencias extra)
          if (!pdf_ok && !is.null(chrome_bin)) {
            tryCatch({
              # Copy HTML to temp dir (no spaces in path) for Chrome compatibility
              tmp_dir <- tempdir()
              tmp_html <- file.path(tmp_dir, paste0("informe_", timestamp, ".html"))
              tmp_pdf <- file.path(tmp_dir, paste0("informe_", timestamp, ".pdf"))
              file.copy(html_path, tmp_html, overwrite = TRUE)
              # Also copy any image files referenced
              img_files <- list.files(graf_dir, full.names = TRUE)
              if (length(img_files) > 0) file.copy(img_files, tmp_dir, overwrite = TRUE)
              
              tmp_uri <- paste0("file://", tmp_html)
              # Build command as single string to handle spaces in Chrome path
              cmd <- paste(
                shQuote(chrome_bin),
                "--headless", "--disable-gpu", "--no-sandbox", "--run-all-compositor-stages-before-draw",
                paste0("--print-to-pdf=", tmp_pdf),
                "--print-to-pdf-no-header",
                shQuote(tmp_uri)
              )
              system(cmd, ignore.stdout = TRUE, ignore.stderr = TRUE, timeout = 60)
              
              if (file.exists(tmp_pdf) && file.info(tmp_pdf)$size > 500) {
                file.copy(tmp_pdf, pdf_path, overwrite = TRUE)
                pdf_ok <- TRUE
              }
              # Cleanup
              unlink(c(tmp_html, tmp_pdf), force = TRUE)
            }, error = function(e) {})
          }
          
          # Método 2: pagedown::chrome_print (configurando la ruta de Chrome)
          if (!pdf_ok && requireNamespace("pagedown", quietly = TRUE)) {
            tryCatch({
              if (!is.null(chrome_bin)) {
                Sys.setenv(CHROMOTE_CHROME = chrome_bin)
                Sys.setenv(PAGEDOWN_CHROME = chrome_bin)
              }
              pagedown::chrome_print(html_path, output = pdf_path, wait = 60, timeout = 60, verbose = 0)
              if (file.exists(pdf_path) && file.info(pdf_path)$size > 500) pdf_ok <- TRUE
            }, error = function(e) {})
          }
          
          # Método 3: wkhtmltopdf
          if (!pdf_ok) {
            wk_bin <- Sys.which("wkhtmltopdf")
            if (nchar(wk_bin) > 0) {
              system2(wk_bin, args = c(
                "--encoding", "UTF-8", "--page-size", "A4",
                "--margin-top", "15mm", "--margin-bottom", "15mm",
                "--margin-left", "15mm", "--margin-right", "15mm",
                "--enable-local-file-access",
                shQuote(html_path), shQuote(pdf_path)
              ), stdout = TRUE, stderr = TRUE)
              if (file.exists(pdf_path) && file.info(pdf_path)$size > 500) pdf_ok <- TRUE
            }
          }
          
          if (pdf_ok) {
            showNotification("PDF generado correctamente", type = "message", duration = 5)
          } else {
            showNotification(
              paste0("No se pudo generar PDF. ",
                     if (is.null(chrome_bin)) "Google Chrome no detectado. Instalar Chrome resuelve el problema."
                     else "Chrome detectado pero falló. Intente: install.packages('pagedown')"),
              type = "warning", duration = 15)
          }
        }, error = function(e) showNotification(paste("Error PDF:", e$message), type = "warning"))
      }
      
      incProgress(1, detail = "¡Completado!")
      showNotification(paste0("Informe generado en: ", inf_dir), type = "message", duration = 10)
    })
  })
  
  # Preview HTML
  output$inf_preview_html <- renderUI({
    req(informe$html_content)
    tags$iframe(srcdoc = informe$html_content,
      style = "width: 100%; height: 700px; border: 1px solid #ddd; border-radius: 4px;",
      sandbox = "allow-same-origin")
  })
  
  # Botones de descarga dinámicos
  output$inf_descargas <- renderUI({
    req(informe$informe_dir)
    inf_dir <- informe$informe_dir
    archivos <- list.files(inf_dir, pattern = "^informe_.*\\.(html|docx|pdf)$", full.names = FALSE)
    archivos <- sort(archivos, decreasing = TRUE)
    if (length(archivos) == 0) return(NULL)
    archivos <- head(archivos, 6)
    btns <- lapply(archivos, function(f) {
      ext <- tools::file_ext(f)
      icono <- switch(ext, "html"="globe", "docx"="file-word", "pdf"="file-pdf", "file")
      color <- switch(ext, "html"="btn-outline-primary", "docx"="btn-outline-info", "pdf"="btn-outline-danger", "btn-outline-secondary")
      downloadButton(paste0("inf_dl_", gsub("[^a-zA-Z0-9]","_",f)), paste0(" ",f), class=paste("btn-sm",color), icon=icon(icono))
    })
    tagList(hr(), h5("Descargas disponibles:"), btns)
  })
  
  # Handlers dinámicos para descarga
  observe({
    req(informe$informe_dir)
    inf_dir <- informe$informe_dir
    archivos <- list.files(inf_dir, pattern = "^informe_.*\\.(html|docx|pdf)$", full.names = TRUE)
    for (fpath in archivos) {
      local({
        local_path <- fpath; local_name <- basename(fpath)
        output_id <- paste0("inf_dl_", gsub("[^a-zA-Z0-9]","_",local_name))
        output[[output_id]] <- downloadHandler(filename=function() local_name, content=function(file) file.copy(local_path, file))
      })
    }
  })
  
  # ---- ZIP de clips de ejemplos (PraatPicture + audio + TextGrid) ----
  output$inf_descargas_clips <- renderUI({
    req(informe$ejemplos_ids, length(informe$ejemplos_ids) > 0)
    hay_pp  <- isTRUE(input$inf_ej_praatpicture)  && praatpicture_disponible
    hay_wav <- isTRUE(input$inf_ej_audio_clip)     && tuneR_disponible
    hay_tg  <- isTRUE(input$inf_ej_textgrid_clip)
    if (!hay_pp && !hay_wav && !hay_tg) return(NULL)
    tagList(
      hr(),
      h5(icon("file-archive"), " Archivos de ejemplos:"),
      helpText(paste0(length(informe$ejemplos_ids), " grupos entonativos con curva melódica.")),
      downloadButton("inf_dl_clips_zip", 
                     paste0(" Descargar clips (", length(informe$ejemplos_ids), " GEs) .zip"),
                     class = "btn-info btn-block btn-sm")
    )
  })
  
  output$inf_dl_clips_zip <- downloadHandler(
    filename = function() paste0("informe_clips_", format(Sys.time(), "%Y%m%d_%H%M"), ".zip"),
    content  = function(file) {
      req(datos$ips_resumen, length(informe$ejemplos_ids) > 0)
      
      hay_pp  <- isTRUE(input$inf_ej_praatpicture)  && praatpicture_disponible
      hay_wav <- isTRUE(input$inf_ej_audio_clip)     && tuneR_disponible
      hay_tg  <- isTRUE(input$inf_ej_textgrid_clip)
      
      tmp_dir <- file.path(tempdir(), paste0("clips_informe_", format(Sys.time(), "%H%M%S")))
      dir.create(tmp_dir, showWarnings = FALSE)
      
      ips_all <- datos$ips_resumen
      phones_d <- datos$phones
      
      withProgress(message = "Generando clips de ejemplos...", value = 0, {
        ids <- informe$ejemplos_ids
        for (k in seq_along(ids)) {
          id_ge <- ids[k]
          ip <- ips_all[ips_all$id_ge == id_ge, ]
          if (nrow(ip) == 0) next
          ip <- ip[1, ]
          
          base_name <- paste0(ip$hablante, "_ge", ip$grupo_entonativo, 
                              "_", gsub("[^a-zA-Z0-9]", "", id_ge))
          
          # Buscar wav y textgrid
          fn <- ip$filename
          wav_path_e <- NULL
          for (nombre in names(datos_audio$wavs)) {
            if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
              wav_path_e <- datos_audio$wavs[[nombre]]; break
            }
          }
          if (is.null(wav_path_e) && length(datos_audio$wavs) == 1) wav_path_e <- datos_audio$wavs[[1]]
          
          tg_path_e <- NULL
          for (nombre in names(datos_textgrid$tgs)) {
            if (grepl(nombre, fn, fixed = TRUE) || grepl(fn, nombre, fixed = TRUE)) {
              tg_path_e <- datos_textgrid$tgs[[nombre]]; break
            }
          }
          if (is.null(tg_path_e) && length(datos_textgrid$tgs) == 1) tg_path_e <- datos_textgrid$tgs[[1]]
          
          t_ini <- max(0, ip$inicio - 0.1)
          t_fin <- ip$fin + 0.1
          
          # PraatPicture
          if (hay_pp && !is.null(wav_path_e) && !is.null(tg_path_e) &&
              file.exists(wav_path_e) && file.exists(tg_path_e)) {
            tryCatch({
              generar_praatpicture_ge(wav_path_e, tg_path_e, t_ini, t_fin,
                                      titulo = id_ge,
                                      output_file = file.path(tmp_dir, paste0(base_name, "_praatpicture.png")),
                                      hablante = ip$hablante)
            }, error = function(e) warning("PraatPicture error ", id_ge, ": ", e$message))
          }
          
          # Audio clip
          if (hay_wav && !is.null(wav_path_e) && file.exists(wav_path_e)) {
            tryCatch({
              library(tuneR)
              wav_full <- readWave(wav_path_e)
              sr <- wav_full@samp.rate
              from_s <- max(1L, round(t_ini * sr))
              to_s   <- min(length(wav_full@left), round(t_fin * sr))
              if (wav_full@stereo) {
                seg <- Wave(left  = wav_full@left[from_s:to_s],
                            right = wav_full@right[from_s:to_s],
                            samp.rate = sr, bit = wav_full@bit)
              } else {
                seg <- Wave(left = wav_full@left[from_s:to_s], samp.rate = sr, bit = wav_full@bit)
              }
              writeWave(seg, file.path(tmp_dir, paste0(base_name, ".wav")))
            }, error = function(e) warning("Audio clip error ", id_ge, ": ", e$message))
          }
          
          # TextGrid (palabras + phones)
          if (hay_tg) {
            tryCatch({
              vocales_ge <- phones_d[phones_d$filename == ip$filename &
                                       phones_d$hablante == ip$hablante &
                                       phones_d$grupo_entonativo == ip$grupo_entonativo, ]
              vocales_ge <- vocales_ge[order(vocales_ge$inicio), ]
              if (nrow(vocales_ge) > 0) {
                tg_offset <- t_ini
                t_fin_tg  <- t_fin - tg_offset
                # Tier palabras (words) derivado de vocales
                palabras_df <- data.frame(palabra=character(0), w_tmin=numeric(0), w_tmax=numeric(0))
                if ("palabra" %in% colnames(vocales_ge)) {
                  rle_p <- rle(vocales_ge$palabra)
                  end_i <- cumsum(rle_p$lengths)
                  sta_i <- c(1, head(end_i, -1) + 1)
                  for (ri in seq_along(rle_p$values)) {
                    pt <- rle_p$values[ri]
                    if (is.na(pt) || pt == "") next
                    vr <- vocales_ge[sta_i[ri]:end_i[ri], ]
                    palabras_df <- rbind(palabras_df, data.frame(
                      palabra = pt,
                      w_tmin  = min(vr$tmin, na.rm = TRUE),
                      w_tmax  = max(vr$tmax, na.rm = TRUE)))
                  }
                }
                tg_content <- paste0(
                  "File type = \"ooTextFile\"\nObject class = \"TextGrid\"\n\n",
                  "xmin = 0\nxmax = ", format(t_fin_tg, scientific=FALSE), "\n",
                  "tiers? <exists>\nsize = 2\nitem []:\n")
                # Tier 1: phones (vocales)
                tg_content <- paste0(tg_content,
                  "    item [1]:\n        class = \"IntervalTier\"\n",
                  "        name = \"phones\"\n        xmin = 0\n",
                  "        xmax = ", format(t_fin_tg, scientific=FALSE), "\n",
                  "        intervals: size = ", nrow(vocales_ge), "\n")
                for (vi in seq_len(nrow(vocales_ge))) {
                  tg_content <- paste0(tg_content,
                    "        intervals [", vi, "]:\n",
                    "            xmin = ", format(vocales_ge$tmin[vi] - tg_offset, scientific=FALSE), "\n",
                    "            xmax = ", format(vocales_ge$tmax[vi] - tg_offset, scientific=FALSE), "\n",
                    "            text = \"", vocales_ge$etiqueta[vi], "\"\n")
                }
                # Tier 2: words
                if (nrow(palabras_df) > 0) {
                  tg_content <- paste0(tg_content,
                    "    item [2]:\n        class = \"IntervalTier\"\n",
                    "        name = \"words\"\n        xmin = 0\n",
                    "        xmax = ", format(t_fin_tg, scientific=FALSE), "\n",
                    "        intervals: size = ", nrow(palabras_df), "\n")
                  for (wi in seq_len(nrow(palabras_df))) {
                    tg_content <- paste0(tg_content,
                      "        intervals [", wi, "]:\n",
                      "            xmin = ", format(palabras_df$w_tmin[wi] - tg_offset, scientific=FALSE), "\n",
                      "            xmax = ", format(palabras_df$w_tmax[wi] - tg_offset, scientific=FALSE), "\n",
                      "            text = \"", palabras_df$palabra[wi], "\"\n")
                  }
                } else {
                  tg_content <- paste0(tg_content,
                    "    item [2]:\n        class = \"IntervalTier\"\n",
                    "        name = \"words\"\n        xmin = 0\n",
                    "        xmax = ", format(t_fin_tg, scientific=FALSE), "\n",
                    "        intervals: size = 1\n",
                    "        intervals [1]:\n            xmin = 0\n",
                    "            xmax = ", format(t_fin_tg, scientific=FALSE), "\n",
                    "            text = \"\"\n")
                }
                writeLines(tg_content, file.path(tmp_dir, paste0(base_name, ".TextGrid")))
              }
            }, error = function(e) warning("TextGrid error ", id_ge, ": ", e$message))
          }
          
          incProgress(1 / length(ids))
        }
      })
      
      # Comprimir
      archivos_clip <- list.files(tmp_dir, full.names = TRUE)
      if (length(archivos_clip) > 0) {
        zip(file, files = archivos_clip, flags = "-j")
      } else {
        # ZIP vacío de emergencia
        writeLines("Sin archivos generados", file.path(tmp_dir, "README.txt"))
        zip(file, files = file.path(tmp_dir, "README.txt"), flags = "-j")
      }
      unlink(tmp_dir, recursive = TRUE)
    }
  )

  # ============================================================
  # MÓDULO TRANSCRIPCIÓN AUTOMÁTICA (whisper R/torch + MPS)
  # ============================================================

  # Estado reactivo del módulo
  transcr_datos              <- reactiveVal(NULL)   # data.frame con segmentos
  transcr_audio_seleccionado <- reactiveVal(NULL)   # ruta al WAV cargado
  transcr_audio_offset       <- reactiveVal(0)      # start del segmento seleccionado
  rv_fragmento_ruta          <- reactiveVal(NULL)   # fragmento WAV pre-extraído
  rv_tg_cache                <- reactiveVal(list()) # TextGrids generados: nombre → ruta temp

  # Estado de progreso (columna izquierda)
  output$transcr_estado_ui <- renderUI({
    d <- transcr_datos()
    if (is.null(d)) return(NULL)
    div(style = "margin-top:8px; font-size:12px; color:#1e3a5f;",
        icon("check-circle", style = "color:green;"),
        paste0(" ", nrow(d), " segmento(s) transcritos"))
  })

  # Estado del fragmento extraído
  output$transcr_fragmento_estado <- renderUI({
    frag <- rv_fragmento_ruta()
    if (is.null(frag)) return(NULL)
    div(style = "margin-top:5px; font-size:11px; color:#059669; font-weight:600;",
        icon("check-circle"),
        paste0(" ", frag$name),
        tags$a(style = "margin-left:8px; color:#dc2626; cursor:pointer; font-weight:normal;",
               onclick = "Shiny.setInputValue('transcr_limpiar_fragmento', Math.random())",
               icon("times"), " Quitar")
    )
  })

  # Extracción explícita del fragmento
  observeEvent(input$transcr_extraer_fragmento, {
    req(input$transcr_wav_files)
    t_desde  <- max(0, suppressWarnings(as.numeric(input$transcr_desde)))
    t_hasta  <- suppressWarnings(as.numeric(input$transcr_hasta))
    if (is.na(t_desde) || is.na(t_hasta) || t_hasta <= t_desde) {
      showNotification("'Hasta' debe ser mayor que 'Desde'.", type = "error"); return()
    }
    duracion <- t_hasta - t_desde
    ruta     <- input$transcr_wav_files$datapath[1]
    nombre   <- input$transcr_wav_files$name[1]
    tmp      <- tempfile(fileext = ".wav")
    exito    <- FALSE

    withProgress(message = "Extrayendo fragmento...", value = 0.5, {
      # Opción 1: tuneR
      if (requireNamespace("tuneR", quietly = TRUE)) {
        tryCatch({
          wave <- tuneR::readWave(ruta, from = t_desde, to = t_hasta, units = "seconds")
          tuneR::writeWave(wave, tmp)
          if (file.exists(tmp) && file.size(tmp) > 0) exito <- TRUE
        }, error = function(e) {})
      }
      # Opción 2: ffmpeg
      if (!exito) {
        ffmpeg_bin <- Sys.which("ffmpeg")
        if (nchar(ffmpeg_bin) == 0) ffmpeg_bin <- "/usr/local/bin/ffmpeg"
        if (file.exists(ffmpeg_bin)) {
          system2(ffmpeg_bin,
            c("-y", "-ss", as.character(t_desde), "-t", as.character(duracion),
              "-i", ruta, "-ar", "16000", "-ac", "1", tmp),
            stdout = FALSE, stderr = FALSE)
          if (file.exists(tmp) && file.size(tmp) > 0) exito <- TRUE
        }
      }
    })

    if (exito) {
      nom_frag <- paste0(tools::file_path_sans_ext(nombre),
                         "_", t_desde, "s-", t_hasta, "s.wav")
      rv_fragmento_ruta(list(path = tmp, name = nom_frag,
                             desde = t_desde, hasta = t_hasta))
      showNotification(
        paste0("Fragmento listo: ", round(duracion, 1), "s  [", t_desde, "→", t_hasta, "]"),
        type = "message", duration = 5)
    } else {
      rv_fragmento_ruta(NULL)
      showNotification(
        "No se pudo extraer el fragmento. Instala 'tuneR' o verifica que ffmpeg está disponible.",
        type = "error", duration = 8)
    }
  })

  observeEvent(input$transcr_limpiar_fragmento, {
    rv_fragmento_ruta(NULL)
  })

  # Panel derecho: tabla o placeholder — renderUI evita el problema DT+conditionalPanel
  output$transcr_panel_contenido <- renderUI({
    d <- transcr_datos()
    if (is.null(d) || nrow(d) == 0) {
      return(div(style = "text-align:center; padding:30px; color:#64748b;",
                 icon("microphone", style = "font-size:2.5em; opacity:0.3;"),
                 br(), br(),
                 tags$small("Carga archivos de audio y pulsa 'Transcribir' para comenzar.")))
    }
    tagList(
      div(style = "margin-bottom:6px;", uiOutput("transcr_audio_player_ui")),
      DTOutput("transcr_tabla"),
      tags$hr(style = "margin:6px 0;"),
      fluidRow(
        column(4,
          textInput("transcr_tg_carpeta", "Carpeta destino TextGrid:",
                    value = "", placeholder = "/ruta/a/carpeta/")),
        column(4,
          div(style = "padding-top:22px;",
              downloadButton("transcr_descargar_tg", "Generar TextGrid",
                             class = "btn-success btn-block"))),
        column(4,
          div(style = "padding-top:22px;",
              actionButton("transcr_usar_en_analisis",
                           tagList(icon("arrow-right"), " Usar en an\u00e1lisis"),
                           class = "btn-primary btn-block")))
      ),
      tags$hr(style = "margin:4px 0;"),
      fluidRow(
        column(12,
          actionButton("transcr_diarizar_btn",
                       tagList(icon("users"), " Diarizar (asignar hablantes con pyannote)"),
                       class = "btn-outline-secondary btn-sm btn-block"),
          helpText(style = "font-size:0.78em; margin-top:3px;",
                   icon("info-circle"),
                   " Usa pyannote.audio con MPS. Requiere token HuggingFace y haber aceptado los modelos de pyannote en su web.")
        )
      )
    )
  })

  # Transcripción al pulsar botón
  observeEvent(input$transcr_iniciar, {
    # Si hay fragmento pre-extraído, usarlo; si no, usar archivos subidos
    frag <- rv_fragmento_ruta()
    if (!is.null(frag)) {
      files <- data.frame(
        name     = frag$name,
        datapath = frag$path,
        stringsAsFactors = FALSE
      )
    } else {
      req(input$transcr_wav_files)
      files <- input$transcr_wav_files
    }
    backend   <- input$transcr_backend
    modelo_id <- input$transcr_modelo
    idioma    <- input$transcr_idioma          # "es", "ca", "auto", ...
    hab_def   <- trimws(input$transcr_hablante_def)
    if (nchar(hab_def) == 0) hab_def <- "H1"

    # ── Helper: convierte timestamps tipo "HH:MM:SS.mmm" o segundos a segundos ──
    parse_tiempo <- function(x) {
      if (is.numeric(x)) return(as.numeric(x))
      x <- as.character(x)
      parts <- strsplit(x, ":")[[1]]
      if (length(parts) == 3) {
        as.numeric(parts[1]) * 3600 + as.numeric(parts[2]) * 60 + as.numeric(parts[3])
      } else {
        suppressWarnings(as.numeric(x))
      }
    }

    # ── Helper: convierte WAV/MP3 a WAV 16kHz mono (necesario para audio.whisper) ──
    preparar_wav16 <- function(ruta_orig) {
      ext <- tolower(tools::file_ext(ruta_orig))
      if (ext == "wav") {
        # Verificar si ya es 16kHz — si no, convertir
        tryCatch({
          if (requireNamespace("tuneR", quietly = TRUE)) {
            info <- tuneR::readWave(ruta_orig, header = TRUE)
            if (info$sample.rate == 16000) return(ruta_orig)
          }
        }, error = function(e) {})
      }
      # Convertir con av si está disponible
      if (requireNamespace("av", quietly = TRUE)) {
        tmp <- tempfile(fileext = ".wav")
        av::av_audio_convert(ruta_orig, output = tmp, format = "wav",
                             sample_rate = 16000, channels = 1)
        return(tmp)
      }
      ruta_orig  # fallback: intentar con el original
    }

    if (backend == "audio.whisper") {
      # ══════════════════════════════════════════════════════════
      # BACKEND 1: audio.whisper (whisper.cpp + Metal)
      # ══════════════════════════════════════════════════════════
      if (!requireNamespace("audio.whisper", quietly = TRUE)) {
        showNotification(
          "Instala audio.whisper: remotes::install_github('bnosac/audio.whisper', ref='0.4.1')",
          type = "error", duration = 10)
        return()
      }
      usar_gpu   <- isTRUE(input$transcr_gpu)
      n_threads  <- max(1L, as.integer(input$transcr_threads))
      idioma_aw  <- if (idioma == "auto") "auto" else idioma

      withProgress(message = "Cargando modelo (audio.whisper)...", value = 0, {
        tryCatch({
          incProgress(0.05, detail = paste0("Cargando '", modelo_id, "'..."))
          modelo_aw <- audio.whisper::whisper(modelo_id, use_gpu = usar_gpu)

          todos <- lapply(seq_len(nrow(files)), function(i) {
            incProgress(i / nrow(files), detail = paste("Transcribiendo:", files$name[i]))
            ruta_orig <- files$datapath[i]
            nombre    <- tools::file_path_sans_ext(files$name[i])
            ruta_wav  <- preparar_wav16(ruta_orig)

            res <- tryCatch(
              predict(modelo_aw, newdata = ruta_wav,
                      language  = idioma_aw,
                      n_threads = n_threads,
                      trace     = FALSE),
              error = function(e) {
                showNotification(paste0("Error en ", files$name[i], ": ", e$message),
                                 type = "warning", duration = 5)
                NULL
              }
            )
            if (is.null(res)) return(NULL)

            # audio.whisper devuelve $data con columnas: segment, from, to, text
            segs <- res$data
            if (is.null(segs) || !is.data.frame(segs) || nrow(segs) == 0) {
              segs <- data.frame(from = "00:00:00.000", to = NA_character_,
                                 text = "", stringsAsFactors = FALSE)
            }
            data.frame(
              archivo  = nombre,
              ruta_wav = ruta_orig,
              hablante = hab_def,
              inicio   = round(sapply(segs$from, parse_tiempo), 3),
              fin      = round(sapply(segs$to,   parse_tiempo), 3),
              texto    = trimws(as.character(segs$text)),
              stringsAsFactors = FALSE
            )
          })

        }, error = function(e) {
          showNotification(paste("Error:", e$message), type = "error", duration = 8)
          todos <<- list()
        })
      })

    } else if (backend == "whisperx") {
      # ══════════════════════════════════════════════════════════
      # BACKEND 3: WhisperX (transcripción + diarización, Python)
      # ══════════════════════════════════════════════════════════
      diarizar   <- isTRUE(input$transcr_wx_diarizar)
      hf_token   <- trimws(input$transcr_hf_token)
      device_wx  <- input$transcr_wx_device
      idioma_wx  <- if (idioma == "auto") "None" else paste0('"', idioma, '"')
      min_spk    <- suppressWarnings(as.integer(input$transcr_wx_min_spk))
      max_spk    <- suppressWarnings(as.integer(input$transcr_wx_max_spk))

      if (diarizar && nchar(hf_token) == 0) {
        showNotification(
          "La diarización requiere un Token HuggingFace. Introdúcelo o desactiva la diarización.",
          type = "error", duration = 8)
        return()
      }

      # ── Buscar Python con whisperx ─────────────────────────────
      python_bin <- NULL
      py_cands <- c(.python_venv_path, .python_sys_candidates)
      for (py in py_cands[nchar(py_cands) > 0]) {
        chk <- tryCatch(
          system2(py, c("-c", shQuote("import whisperx; print('OK')")),
                  stdout = TRUE, stderr = FALSE),
          error = function(e) ""
        )
        if (isTRUE(grepl("OK", paste(chk, collapse = "")))) {
          python_bin <- py; break
        }
      }
      if (is.null(python_bin)) {
        showNotification(
          "whisperx no encontrado. Instala con: pip install whisperx  (ver Referencia → Dependencias Python)",
          type = "error", duration = 10)
        return()
      }

      # ── compute_type según dispositivo ────────────────────────
      compute_type <- if (device_wx == "cuda") "float16" else "float32"

      withProgress(message = "WhisperX: transcribiendo...", value = 0, {
        tryCatch({
          todos <- lapply(seq_len(nrow(files)), function(i) {
            incProgress(i / nrow(files),
                        detail = paste0(files$name[i], " (", i, "/", nrow(files), ")"))
            ruta_orig <- files$datapath[i]
            nombre    <- tools::file_path_sans_ext(files$name[i])

            # ── Construir script Python temporal ─────────────────
            lang_arg <- if (idioma != "auto") paste0('language="', idioma, '", ') else ""

            py_script <- sprintf(
'import whisperx, json, sys, warnings
warnings.filterwarnings("ignore")

audio_file = %s
device = %s

# whisperx usa CTranslate2 para transcribir, que NO soporta MPS.
# Usamos cpu para transcripcion y el device original para alineacion/diarizacion.
device_transcr = "cpu" if device == "mps" else device
compute_type_transcr = "int8" if device_transcr == "cpu" else %s

try:
    model = whisperx.load_model(%s, device_transcr, compute_type=compute_type_transcr)
    audio = whisperx.load_audio(audio_file)
    result = model.transcribe(audio, %sbatch_size=4)
except Exception as e:
    sys.stderr.write("TRANSCR_ERROR: " + str(e) + "\\n")
    print("WXJSON:[]")
    sys.exit(1)

try:
    model_a, metadata = whisperx.load_align_model(
        language_code=result["language"], device=device)
    result = whisperx.align(result["segments"], model_a, metadata,
                            audio, device, return_char_alignments=False)
except Exception as e:
    sys.stderr.write("ALIGN_ERROR: " + str(e) + "\\n")

# Extraer solo los campos necesarios (sin words-level timestamps)
# para reducir el tamaño del JSON y acelerar el parseo en R
segs_raw = result.get("segments", [])
segs_slim = [{"start": s.get("start"), "end": s.get("end"),
              "text": s.get("text", "")}
             for s in segs_raw]
print("WXJSON:" + json.dumps(segs_slim, ensure_ascii=False))
',
              deparse(ruta_orig),
              deparse(device_wx),
              deparse(compute_type),
              deparse(modelo_id),
              lang_arg
            )

            script_path <- tempfile(fileext = ".py")
            writeLines(py_script, script_path)
            on.exit(unlink(script_path), add = TRUE)

            stderr_tmp <- tempfile()
            raw_out <- tryCatch(
              system2(python_bin, script_path,
                      stdout = TRUE, stderr = stderr_tmp),
              error = function(e) {
                showNotification(paste0("Error lanzando Python: ", e$message),
                                 type = "warning"); NULL
              }
            )

            # Mostrar errores de Python como notificación de diagnóstico
            if (file.exists(stderr_tmp)) {
              err_lines <- readLines(stderr_tmp, warn = FALSE)
              # Filtrar líneas de advertencia menores (UserWarning, FutureWarning...)
              err_relevante <- err_lines[!grepl("^\\s*(warnings\\.warn|UserWarning|FutureWarning|/.*\\.py:\\d)", err_lines)]
              err_txt <- paste(err_relevante, collapse = "\n")
              if (nchar(trimws(err_txt)) > 0)
                showNotification(
                  tagList(tags$strong(paste0("WhisperX — ", files$name[i])), tags$br(),
                          tags$small(substr(err_txt, 1, 600))),
                  type = "error", duration = 20)
              unlink(stderr_tmp)
            }

            if (is.null(raw_out) || length(raw_out) == 0) return(NULL)

            # Buscar la línea marcada con prefijo WXJSON:
            json_line <- sub("^WXJSON:", "",
                             tail(grep("^WXJSON:", raw_out, value = TRUE), 1))
            if (nchar(json_line) == 0) return(NULL)

            segs <- tryCatch(
              jsonlite::fromJSON(json_line, simplifyDataFrame = TRUE),
              error = function(e) NULL
            )
            if (is.null(segs) || !is.data.frame(segs) || nrow(segs) == 0) return(NULL)

            data.frame(
              archivo  = nombre,
              ruta_wav = ruta_orig,
              hablante = rep(hab_def, nrow(segs)),
              inicio   = round(as.numeric(segs$start), 3),
              fin      = round(as.numeric(segs$end),   3),
              texto    = trimws(as.character(segs$text)),
              stringsAsFactors = FALSE
            )
          })
        }, error = function(e) {
          showNotification(paste("Error WhisperX:", e$message), type = "error", duration = 8)
          todos <<- list()
        })
      })

      # ── Post-proceso: diarización con pyannote standalone ─────────
      if (diarizar && length(Filter(Negate(is.null), todos)) > 0) {
        py_diar_bin <- NULL
        for (py in c(.python_venv_path, python_bin, .python_sys_candidates)) {
          if (is.null(py) || nchar(py) == 0 || !file.exists(py)) next
          chk <- tryCatch(
            system2(py, c("-c", shQuote("from pyannote.audio import Pipeline; print('OK')")),
                    stdout = TRUE, stderr = FALSE),
            error = function(e) "")
          if (isTRUE(grepl("OK", paste(chk, collapse = "")))) { py_diar_bin <- py; break }
        }
        if (is.null(py_diar_bin)) {
          showNotification(
            "pyannote.audio no encontrado. La transcripción se guarda sin diarización.",
            type = "warning", duration = 8)
        } else {
          spk_args_wx <- paste0(
            if (!is.na(min_spk)) paste0("min_speakers=", min_spk, ", ") else "",
            if (!is.na(max_spk)) paste0("max_speakers=", max_spk)       else ""
          )
          spk_args_wx  <- sub(",\\s*$", "", trimws(spk_args_wx))
          kwargs_str_wx <- if (nchar(spk_args_wx) > 0) paste0(", ", spk_args_wx) else ""

          withProgress(message = "Diarizando con pyannote...", value = 0, {
            todos <- lapply(seq_along(todos), function(i) {
              df <- todos[[i]]
              if (is.null(df) || nrow(df) == 0) return(df)
              fn        <- df$archivo[1]
              ruta_orig <- df$ruta_wav[1]
              incProgress(i / length(todos),
                          detail = paste0("(", i, "/", length(todos), ") ", fn))

              py_diar <- sprintf(
'import json, sys, warnings, torch, torchaudio, subprocess, os, tempfile
warnings.filterwarnings("ignore")
from pyannote.audio import Pipeline

pipeline = Pipeline.from_pretrained(
    "pyannote/speaker-diarization-3.1",
    use_auth_token=%s)
try:
    pipeline.to(torch.device(%s))
except Exception as e:
    sys.stderr.write("Fallback to cpu: " + str(e) + "\\n")
    pipeline.to(torch.device("cpu"))

_src = %s
_tmp = tempfile.mktemp(suffix=".wav")
subprocess.run(
    ["ffmpeg", "-y", "-i", _src, "-ar", "16000", "-ac", "1", "-c:a", "pcm_s16le", _tmp],
    stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
_wav = _tmp if os.path.exists(_tmp) and os.path.getsize(_tmp) > 0 else _src

_waveform, _sr = torchaudio.load(_wav)
if _waveform.shape[0] > 1:
    _waveform = _waveform.mean(dim=0, keepdim=True)
if _sr != 16000:
    _waveform = torchaudio.functional.resample(_waveform, _sr, 16000)
    _sr = 16000
_audio_dict = {"waveform": _waveform, "sample_rate": _sr}

diarization = pipeline(_audio_dict%s)
# Extraer Annotation con itertracks — compatible con todas las versiones de pyannote
_ann = None
try:
    from pyannote.core import Annotation as _Annotation
    if isinstance(diarization, _Annotation):
        _ann = diarization
    else:
        _obj_attrs = list(vars(diarization).keys()) if hasattr(diarization, "__dict__") else []
        _all_attrs = _obj_attrs + [a for a in ["diarization","annotation","output","result"] if a not in _obj_attrs]
        for _attr in _all_attrs:
            _val = getattr(diarization, _attr, None)
            if _val is not None and (isinstance(_val, _Annotation) or hasattr(_val, "itertracks")):
                _ann = _val
                break
except Exception as _ie:
    sys.stderr.write("pyannote extract error: " + str(_ie) + "\\n")
segs = []
if _ann is None:
    _dbg = str(list(vars(diarization).keys()) if hasattr(diarization, "__dict__") else dir(diarization))[:400]
    sys.stderr.write("ERROR pyannote: Annotation no encontrada. Tipo=" + str(type(diarization)) + " Attrs=" + _dbg + "\\n")
else:
    for turn, _, speaker in _ann.itertracks(yield_label=True):
        segs.append({"start": round(turn.start, 3),
                     "end":   round(turn.end,   3),
                     "speaker": speaker})
print("DIARJSON:" + json.dumps(segs))
',
                deparse(hf_token),
                deparse(device_wx),
                deparse(ruta_orig),
                kwargs_str_wx
              )

              sc_path <- tempfile(fileext = ".py")
              writeLines(py_diar, sc_path)
              se_tmp <- tempfile()
              raw_diar <- tryCatch(
                system2(py_diar_bin, sc_path, stdout = TRUE, stderr = se_tmp),
                error = function(e) NULL
              )
              unlink(sc_path)

              if (file.exists(se_tmp)) {
                err_lines <- readLines(se_tmp, warn = FALSE)
                err_rel   <- err_lines[!grepl("UserWarning|FutureWarning|/.*\\.py:\\d|warnings\\.warn", err_lines)]
                err_txt   <- paste(err_rel, collapse = "\n")
                if (nchar(trimws(err_txt)) > 0)
                  showNotification(
                    tagList(tags$strong(paste0("pyannote — ", fn)), tags$br(),
                            tags$small(substr(err_txt, 1, 600))),
                    type = "warning", duration = 15)
                unlink(se_tmp)
              }

              if (is.null(raw_diar) || length(raw_diar) == 0) return(df)
              json_line <- sub("^DIARJSON:", "",
                               tail(grep("^DIARJSON:", raw_diar, value = TRUE), 1))
              if (nchar(json_line) == 0) return(df)
              diar <- tryCatch(
                jsonlite::fromJSON(json_line, simplifyDataFrame = TRUE),
                error = function(e) NULL
              )
              if (is.null(diar) || nrow(diar) == 0) return(df)

              # Asignar hablante por máximo solapamiento temporal
              for (j in seq_len(nrow(df))) {
                t_s <- df$inicio[j]; t_e <- df$fin[j]
                overlaps <- pmax(0, pmin(t_e, diar$end) - pmax(t_s, diar$start))
                best <- which.max(overlaps)
                if (length(best) > 0 && overlaps[best] > 0)
                  df$hablante[j] <- diar$speaker[best]
              }
              df
            })
          })
        }
      }

    } else {
      # ══════════════════════════════════════════════════════════
      # BACKEND 2: whisper (torch / MPS)
      # ══════════════════════════════════════════════════════════
      if (!requireNamespace("whisper", quietly = TRUE)) {
        showNotification(
          "Instala el paquete 'whisper': install.packages('whisper')",
          type = "error", duration = 8)
        return()
      }
      device_sel <- input$transcr_device
      idioma_wh  <- if (idioma == "auto") NULL else idioma

      withProgress(message = "Cargando modelo (whisper/torch)...", value = 0, {
        tryCatch({
          incProgress(0.05, detail = paste0("Cargando '", modelo_id, "' en ", device_sel, "..."))
          pipe <- whisper::whisper_pipeline(
            model   = modelo_id,
            device  = device_sel,
            verbose = TRUE
          )

          todos <- lapply(seq_len(nrow(files)), function(i) {
            incProgress(i / nrow(files), detail = paste("Transcribiendo:", files$name[i]))
            ruta_wav <- files$datapath[i]
            nombre   <- tools::file_path_sans_ext(files$name[i])

            res <- tryCatch(
              pipe$transcribe(ruta_wav, language = idioma_wh, timestamps = TRUE),
              error = function(e) {
                showNotification(paste0("Error en ", files$name[i], ": ", e$message),
                                 type = "warning", duration = 5)
                NULL
              }
            )
            if (is.null(res)) return(NULL)

            segs <- res$segments
            if (is.null(segs) || !is.data.frame(segs) || nrow(segs) == 0) {
              segs <- data.frame(
                start = 0, end = NA_real_,
                text  = if (is.character(res$text) && length(res$text) > 0) res$text[1] else "",
                stringsAsFactors = FALSE
              )
            }
            data.frame(
              archivo  = nombre,
              ruta_wav = ruta_wav,
              hablante = hab_def,
              inicio   = round(as.numeric(segs$start), 3),
              fin      = round(as.numeric(segs$end),   3),
              texto    = trimws(segs$text),
              stringsAsFactors = FALSE
            )
          })

        }, error = function(e) {
          showNotification(paste("Error:", e$message), type = "error", duration = 8)
          todos <<- list()
        })
      })
    }

    # Consolidar resultados (común a ambos backends)
    df_final <- do.call(rbind, Filter(Negate(is.null), todos))
    if (!is.null(df_final) && nrow(df_final) > 0) {
      transcr_datos(df_final)
      transcr_audio_seleccionado(files$datapath[1])
      showNotification(paste0(nrow(df_final), " segmentos transcritos"),
                       type = "message", duration = 4)
    } else {
      showNotification("No se obtuvieron segmentos", type = "warning")
    }
  })

  # Tabla editable de segmentos
  output$transcr_tabla <- renderDT({
    d <- transcr_datos()
    req(!is.null(d) && nrow(d) > 0)
    # Mostrar columnas editables (hablante, texto) y de solo lectura (tiempo)
    datatable(
      d[, c("archivo", "hablante", "inicio", "fin", "texto")],
      selection  = "single",
      editable   = list(target = "cell", disable = list(columns = c(0, 2, 3))),
      options    = list(
        scrollX    = TRUE,
        pageLength = 25,
        deferRender = TRUE,
        columnDefs = list(
          list(width = "40%", targets = 4),
          # Truncar texto largo en la vista (el valor completo se mantiene para editar)
          list(
            targets = 4,
            render  = JS(
              "function(data, type, row) {",
              "  if (type === 'display' && data && data.length > 90) {",
              "    return '<span title=\"' + data.replace(/\"/g, '&quot;') + '\">' + data.substring(0, 90) + '\u2026</span>';",
              "  }",
              "  return data;",
              "}"
            )
          )
        )
      ),
      rownames = FALSE
    )
  }, server = FALSE)

  # Edición de celdas (hablante o texto)
  # ============================================================
  # DIARIZACIÓN POST-TRANSCRIPCIÓN (pyannote.audio + MPS)
  # ============================================================

  # Abrir modal con opciones de diarización
  observeEvent(input$transcr_diarizar_btn, {
    req(!is.null(transcr_datos()), nrow(transcr_datos()) > 0)
    fns <- sort(unique(transcr_datos()$archivo))
    showModal(modalDialog(
      title = tagList(icon("users"), " Diarizar con pyannote.audio"),
      size  = "m",
      easyClose = FALSE,
      tagList(
        p(style = "font-size:0.9em; color:#555;",
          "Ejecuta ", tags$strong("pyannote/speaker-diarization-3.1"),
          " sobre el audio original y asigna hablantes a los segmentos transcritos ",
          "por solapamiento de tiempos. Usa ", tags$strong("MPS"), " en Apple Silicon."),
        hr(),
        passwordInput("diar_hf_token",
          label = tagList(icon("key"), " Token HuggingFace:"),
          value = isolate(input$transcr_hf_token),
          placeholder = "hf_xxxxxxxxxxxxxxxxxxxx"),
        fluidRow(
          column(6, selectInput("diar_device", "Dispositivo:",
            choices = c("MPS (Apple Silicon)" = "mps", "CPU" = "cpu", "CUDA" = "cuda"),
            selected = "mps")),
          column(3, numericInput("diar_min_spk", "Mín. hablantes:",
            value = NA_integer_, min = 1, max = 20)),
          column(3, numericInput("diar_max_spk", "Máx. hablantes:",
            value = NA_integer_, min = 1, max = 20))
        ),
        if (length(fns) > 1)
          selectInput("diar_archivo", "Archivo a diarizar:",
            choices = c("Todos" = "__todos__", setNames(fns, fns)),
            selected = "__todos__"),
        div(class = "alert alert-info", style = "font-size:0.82em; margin-top:8px;",
          icon("clock"), " La primera vez descarga modelos (~300 MB). ",
          "Para un audio de 40 min espera 2–5 min en MPS.")
      ),
      footer = tagList(
        modalButton("Cancelar"),
        actionButton("diar_confirmar",
          tagList(icon("play"), " Diarizar"),
          class = "btn-success")
      )
    ))
  })

  # Ejecutar diarización al confirmar
  observeEvent(input$diar_confirmar, {
    removeModal()
    req(!is.null(transcr_datos()), nrow(transcr_datos()) > 0)

    hf_token  <- trimws(input$diar_hf_token)
    device_d  <- input$diar_device
    min_spk   <- suppressWarnings(as.integer(input$diar_min_spk))
    max_spk   <- suppressWarnings(as.integer(input$diar_max_spk))
    arch_sel  <- if (!is.null(input$diar_archivo)) input$diar_archivo else "__todos__"

    if (nchar(hf_token) == 0) {
      showNotification("Introduce tu token HuggingFace para usar pyannote.", type = "error"); return()
    }

    # ── Feedback inmediato ────────────────────────────────────────
    showNotification(
      tagList(icon("circle-notch", class = "fa-spin"), " Buscando entorno Python con pyannote..."),
      type = "message", duration = NULL, id = "notif_diar_prep"
    )

    # ── Buscar Python con pyannote ────────────────────────────────
    python_bin <- NULL
    for (py in c(.python_venv_path, .python_sys_candidates)) {
      if (nchar(py) == 0 || !file.exists(py)) next
      chk <- tryCatch(
        system2(py, c("-c", shQuote("from pyannote.audio import Pipeline; print('OK')")),
                stdout = TRUE, stderr = FALSE),
        error = function(e) "")
      if (isTRUE(grepl("OK", paste(chk, collapse = "")))) { python_bin <- py; break }
    }
    if (is.null(python_bin)) {
      removeNotification("notif_diar_prep")
      showNotification(
        "pyannote.audio no encontrado. Instala con: pip install pyannote.audio",
        type = "error", duration = 10); return()
    }
    removeNotification("notif_diar_prep")

    # ── Determinar archivos WAV a procesar ───────────────────────
    d <- transcr_datos()
    fns_proc <- if (arch_sel == "__todos__") unique(d$archivo) else arch_sel

    withProgress(message = "Diarizando con pyannote...", value = 0, {
      for (fn in fns_proc) {
        incProgress(1 / length(fns_proc),
                    detail = paste0("(", which(fns_proc == fn), "/", length(fns_proc), ") ",
                                    fn, " — cargando modelo y procesando..."))

        # Localizar WAV subido por el usuario
        wav_files <- input$transcr_wav_files
        if (is.null(wav_files)) {
          showNotification("No se encontró el archivo de audio en memoria.", type = "warning"); next
        }
        match_i <- which(tools::file_path_sans_ext(wav_files$name) == fn)
        if (length(match_i) == 0) {
          showNotification(paste0("No se localizó el WAV para '", fn, "'"), type = "warning"); next
        }
        ruta_wav <- wav_files$datapath[match_i[1]]

        spk_args <- paste0(
          if (!is.na(min_spk)) paste0("min_speakers=", min_spk, ", ") else "",
          if (!is.na(max_spk)) paste0("max_speakers=", max_spk)      else ""
        )
        spk_args <- sub(",\\s*$", "", trimws(spk_args))
        kwargs_str <- if (nchar(spk_args) > 0) paste0(", ", spk_args) else ""

        py_script <- sprintf(
'import json, sys, warnings, torch, torchaudio, subprocess, os, tempfile
warnings.filterwarnings("ignore")
from pyannote.audio import Pipeline

pipeline = Pipeline.from_pretrained(
    "pyannote/speaker-diarization-3.1",
    use_auth_token=%s)
try:
    pipeline.to(torch.device(%s))
except Exception as e:
    sys.stderr.write("Fallback to cpu: " + str(e) + "\\n")
    pipeline.to(torch.device("cpu"))

# Convertir a WAV 16kHz PCM con ffmpeg para asegurar formato limpio
_src = %s
_tmp = tempfile.mktemp(suffix=".wav")
subprocess.run(
    ["ffmpeg", "-y", "-i", _src, "-ar", "16000", "-ac", "1", "-c:a", "pcm_s16le", _tmp],
    stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
_wav = _tmp if os.path.exists(_tmp) and os.path.getsize(_tmp) > 0 else _src

# Cargar con torchaudio (evita AudioDecoder/torchcodec que puede no estar instalado)
_waveform, _sr = torchaudio.load(_wav)
if _waveform.shape[0] > 1:
    _waveform = _waveform.mean(dim=0, keepdim=True)
if _sr != 16000:
    _waveform = torchaudio.functional.resample(_waveform, _sr, 16000)
    _sr = 16000
_audio_dict = {"waveform": _waveform, "sample_rate": _sr}

diarization = pipeline(_audio_dict%s)
# Extraer Annotation con itertracks — compatible con todas las versiones de pyannote
_ann = None
try:
    from pyannote.core import Annotation as _Annotation
    if isinstance(diarization, _Annotation):
        _ann = diarization
    else:
        _obj_attrs = list(vars(diarization).keys()) if hasattr(diarization, "__dict__") else []
        _all_attrs = _obj_attrs + [a for a in ["diarization","annotation","output","result"] if a not in _obj_attrs]
        for _attr in _all_attrs:
            _val = getattr(diarization, _attr, None)
            if _val is not None and (isinstance(_val, _Annotation) or hasattr(_val, "itertracks")):
                _ann = _val
                break
except Exception as _ie:
    sys.stderr.write("pyannote extract error: " + str(_ie) + "\\n")
segs = []
if _ann is None:
    _dbg = str(list(vars(diarization).keys()) if hasattr(diarization, "__dict__") else dir(diarization))[:400]
    sys.stderr.write("ERROR pyannote: Annotation no encontrada. Tipo=" + str(type(diarization)) + " Attrs=" + _dbg + "\\n")
else:
    for turn, _, speaker in _ann.itertracks(yield_label=True):
        segs.append({"start": round(turn.start, 3),
                     "end":   round(turn.end,   3),
                     "speaker": speaker})
print("DIARJSON:" + json.dumps(segs))
',
          deparse(hf_token),
          deparse(device_d),
          deparse(ruta_wav),
          kwargs_str
        )

        script_path <- tempfile(fileext = ".py")
        writeLines(py_script, script_path)
        stderr_tmp  <- tempfile()

        raw_out <- tryCatch(
          system2(python_bin, script_path, stdout = TRUE, stderr = stderr_tmp),
          error = function(e) NULL
        )
        unlink(script_path)

        if (file.exists(stderr_tmp)) {
          err_lines <- readLines(stderr_tmp, warn = FALSE)
          err_rel   <- err_lines[!grepl("UserWarning|FutureWarning|/.*\\.py:\\d|warnings\\.warn", err_lines)]
          err_txt   <- paste(err_rel, collapse = "\n")
          if (nchar(trimws(err_txt)) > 0)
            showNotification(
              tagList(tags$strong(paste0("pyannote — ", fn)), tags$br(),
                      tags$small(substr(err_txt, 1, 2000))),
              type = "error", duration = 30)
          unlink(stderr_tmp)
        }

        if (is.null(raw_out) || length(raw_out) == 0) next
        json_line <- sub("^DIARJSON:", "",
                         tail(grep("^DIARJSON:", raw_out, value = TRUE), 1))
        if (nchar(json_line) == 0) next

        diar <- tryCatch(
          jsonlite::fromJSON(json_line, simplifyDataFrame = TRUE),
          error = function(e) NULL
        )
        if (is.null(diar) || nrow(diar) == 0) next

        # ── Asignar hablante por máximo solapamiento temporal ────
        idx_fn <- which(d$archivo == fn)
        for (i in idx_fn) {
          t_s <- d$inicio[i]; t_e <- d$fin[i]
          overlaps <- pmax(0, pmin(t_e, diar$end) - pmax(t_s, diar$start))
          best <- which.max(overlaps)
          if (length(best) > 0 && overlaps[best] > 0)
            d$hablante[i] <- diar$speaker[best]
        }
        showNotification(
          paste0("\u2714 Diarización completada para '", fn, "': ",
                 length(unique(diar$speaker)), " hablante(s) detectado(s)"),
          type = "message", duration = 5)
      }
    })

    transcr_datos(d)
  })

  observeEvent(input$transcr_tabla_cell_edit, {
    info <- input$transcr_tabla_cell_edit
    d    <- transcr_datos()
    req(!is.null(d))
    col_names <- c("archivo", "hablante", "inicio", "fin", "texto")
    col_name  <- col_names[info$col + 1]
    d[info$row, col_name] <- info$value
    transcr_datos(d)
  })

  # Al seleccionar fila: reproducir segmento
  observeEvent(input$transcr_tabla_rows_selected, {
    d   <- transcr_datos()
    sel <- input$transcr_tabla_rows_selected
    req(!is.null(d), length(sel) > 0)
