  # Generar y descargar TextGrid
  output$transcr_descargar_tg <- downloadHandler(
    filename = function() {
      d <- transcr_datos()
      if (is.null(d)) return("transcripcion.TextGrid")
      archivos_unicos <- unique(d$archivo)
      if (length(archivos_unicos) == 1)
        paste0(archivos_unicos[1], ".TextGrid")
      else
        paste0("transcripcion_", format(Sys.time(), "%Y%m%d_%H%M"), ".TextGrid")
    },
    content = function(file) {
      d <- transcr_datos()
      req(!is.null(d) && nrow(d) > 0)

      # Para simplificar: generar un TextGrid por archivo, exportar el primero
      # (si hay varios archivos se recomienda usar el botón por separado)
      archivo_sel <- unique(d$archivo)[1]
      d_sel <- d[d$archivo == archivo_sel, ]
      hablantes <- unique(d_sel$hablante)

      tmax <- max(d_sel$fin, na.rm = TRUE)

      # Helper para escribir un tier de intervalos en formato ooTextFile
      wt_whisper <- function(idx, name, intervals_df, tmax_val) {
        # intervals_df: data.frame con xmin, xmax, text
        # Rellena huecos con intervalos vacíos para cubrir [0, tmax_val]
        times_all <- sort(unique(c(0, intervals_df$xmin, intervals_df$xmax, tmax_val)))
        n_int <- length(times_all) - 1L
        l <- c(
          paste0('    item [', idx, ']:'),
          '        class = "IntervalTier"',
          paste0('        name = "', name, '"'),
          '        xmin = 0',
          paste0('        xmax = ', tmax_val),
          paste0('        intervals: size = ', n_int)
        )
        for (ii in seq_len(n_int)) {
          t1 <- times_all[ii]; t2 <- times_all[ii + 1L]
          mr <- which(abs(intervals_df$xmin - t1) < 1e-4 & abs(intervals_df$xmax - t2) < 1e-4)
          lbl <- if (length(mr) > 0) gsub('"', '""', intervals_df$text[mr[1]], fixed=TRUE) else ""
          l <- c(l,
            paste0('        intervals [', ii, ']:'),
            paste0('            xmin = ', t1),
            paste0('            xmax = ', t2),
            paste0('            text = "', lbl, '"'))
        }
        l
      }

      # Construir TextGrid con 3 tiers por hablante: utterances, words, phones
      # (phones siempre aproximados cuando vienen de Whisper)
      n_tiers <- length(hablantes) * 3L
      lines <- c(
        'File type = "ooTextFile"',
        'Object class = "TextGrid"',
        '',
        'xmin = 0',
        paste0('xmax = ', tmax),
        'tiers? <exists>',
        paste0('size = ', n_tiers),
        'item []:'
      )

      n_phones_whisper_total <- 0L

      for (ti in seq_along(hablantes)) {
        hab      <- hablantes[ti]
        segs_hab <- d_sel[d_sel$hablante == hab, ]
        segs_hab <- segs_hab[order(segs_hab$inicio), ]

        # ── Tier utterances ────────────────────────────────────────────────
        utt_df <- data.frame(
          xmin = segs_hab$inicio,
          xmax = segs_hab$fin,
          text = segs_hab$texto,
          stringsAsFactors = FALSE
        )
        tier_utt_idx <- (ti - 1L) * 3L + 1L
        tier_utt_name <- if (length(hablantes) == 1) "utterances" else paste0(hab, " - utterances")
        lines <- c(lines, wt_whisper(tier_utt_idx, tier_utt_name, utt_df, tmax))

        # ── Generar words y phones aproximados ────────────────────────────
        wp <- generar_words_phones_whisper(segs_hab, pitch_fn = NULL)
        n_phones_whisper_total <- n_phones_whisper_total + wp$n_aprox

        # ── Tier words ────────────────────────────────────────────────────
        tier_wrd_idx  <- (ti - 1L) * 3L + 2L
        tier_wrd_name <- if (length(hablantes) == 1) "words" else paste0(hab, " - words")
        lines <- c(lines, wt_whisper(tier_wrd_idx, tier_wrd_name, wp$words, tmax))

        # ── Tier phones ───────────────────────────────────────────────────
        tier_ph_idx  <- (ti - 1L) * 3L + 3L
        tier_ph_name <- if (length(hablantes) == 1) "phones" else paste0(hab, " - phones")
        lines <- c(lines, wt_whisper(tier_ph_idx, tier_ph_name, wp$phones, tmax))
      }

      writeLines(lines, file, useBytes = FALSE)

      # Guardar copia en temp de sesión para que "Usar en análisis" la encuentre
      # aunque el usuario no haya especificado carpeta destino
      tg_tmp <- tempfile(fileext = ".TextGrid")
      file.copy(file, tg_tmp, overwrite = TRUE)
      cache <- rv_tg_cache()
      cache[[archivo_sel]] <- tg_tmp
      rv_tg_cache(cache)

      # Aviso: phones siempre son aproximados en transcripciones Whisper
      if (n_phones_whisper_total > 0) {
        showNotification(
          tagList(
            tags$strong("\u26a0\ufe0f TextGrid generado con phones aproximados"),
            tags$br(),
            paste0(n_phones_whisper_total, " phone(s) distribuidos autom\u00e1ticamente ",
                   "a partir de las palabras transcritas. "),
            tags$em("Revise y corrija el TextGrid en Praat antes de usar el tier de phones.")
          ),
          type = "warning", duration = 12
        )
      }

      # Guardar también en carpeta destino si se especificó
      carpeta_dest <- trimws(isolate(input$transcr_tg_carpeta))
      if (nchar(carpeta_dest) > 0 && dir.exists(carpeta_dest)) {
        destino <- file.path(carpeta_dest, paste0(archivo_sel, ".TextGrid"))
        file.copy(file, destino, overwrite = TRUE)
        showNotification(paste0("TextGrid guardado en: ", destino),
                         type = "message", duration = 5)
      }
    }
  )

  # Botón "Usar en análisis": genera TextGrid si hace falta, registra WAV+TG y navega
  observeEvent(input$transcr_usar_en_analisis, {
    d <- transcr_datos()
    req(!is.null(d) && nrow(d) > 0)

    tg_cache     <- rv_tg_cache()
    carpeta_dest <- trimws(input$transcr_tg_carpeta)
    frag         <- rv_fragmento_ruta()

    if ("ruta_wav" %in% colnames(d)) {
      pares <- unique(d[, c("archivo", "ruta_wav")])
    } else {
      pares <- data.frame(archivo = unique(d$archivo), ruta_wav = NA_character_,
                          stringsAsFactors = FALSE)
    }

    # Helper local: genera líneas de TextGrid desde segmentos de un archivo
    gen_tg_lines <- function(d_sel) {
      hablantes <- unique(d_sel$hablante)
      tmax      <- max(d_sel$fin, na.rm = TRUE)
      wt_fn <- function(idx, name, intervals_df, tmax_val) {
        times_all <- sort(unique(c(0, intervals_df$xmin, intervals_df$xmax, tmax_val)))
        n_int <- length(times_all) - 1L
        l <- c(paste0('    item [', idx, ']:'),
               '        class = "IntervalTier"',
               paste0('        name = "', name, '"'),
               '        xmin = 0',
               paste0('        xmax = ', tmax_val),
               paste0('        intervals: size = ', n_int))
        for (ii in seq_len(n_int)) {
          t1 <- times_all[ii]; t2 <- times_all[ii + 1L]
          mr  <- which(abs(intervals_df$xmin - t1) < 1e-4 & abs(intervals_df$xmax - t2) < 1e-4)
          lbl <- if (length(mr) > 0) gsub('"', '""', intervals_df$text[mr[1]], fixed = TRUE) else ""
          l <- c(l, paste0('        intervals [', ii, ']:'),
                    paste0('            xmin = ', t1),
                    paste0('            xmax = ', t2),
                    paste0('            text = "', lbl, '"'))
        }
        l
      }
      n_tiers <- length(hablantes) * 3L
      lines <- c('File type = "ooTextFile"', 'Object class = "TextGrid"', '',
                 'xmin = 0', paste0('xmax = ', tmax),
                 'tiers? <exists>', paste0('size = ', n_tiers), 'item []:')
      for (ti in seq_along(hablantes)) {
        hab      <- hablantes[ti]
        segs_hab <- d_sel[d_sel$hablante == hab, ]
        segs_hab <- segs_hab[order(segs_hab$inicio), ]
        utt_df   <- data.frame(xmin = segs_hab$inicio, xmax = segs_hab$fin,
                               text = segs_hab$texto, stringsAsFactors = FALSE)
        pfx <- if (length(hablantes) == 1) "" else paste0(hab, " - ")
        lines <- c(lines,
          wt_fn((ti-1L)*3L+1L, paste0(pfx,"utterances"), utt_df, tmax))
        wp    <- generar_words_phones_whisper(segs_hab, pitch_fn = NULL)
        lines <- c(lines,
          wt_fn((ti-1L)*3L+2L, paste0(pfx,"words"),  wp$words,  tmax),
          wt_fn((ti-1L)*3L+3L, paste0(pfx,"phones"), wp$phones, tmax))
      }
      lines
    }

    n_wav_ok <- 0L
    n_tg_ok  <- 0L

    for (i in seq_len(nrow(pares))) {
      nombre   <- pares$archivo[i]
      ruta_wav <- pares$ruta_wav[i]

      # ── Registrar WAV ──────────────────────────────────────────────
      if (!is.na(ruta_wav) && file.exists(ruta_wav)) {
        datos_audio$wavs[[nombre]] <- ruta_wav
        n_wav_ok <- n_wav_ok + 1L
      } else if (!is.null(frag) && file.exists(frag$path)) {
        datos_audio$wavs[[nombre]] <- frag$path
        n_wav_ok <- n_wav_ok + 1L
      } else if (!is.null(input$transcr_wav_files)) {
        mi <- which(tools::file_path_sans_ext(input$transcr_wav_files$name) == nombre)
        if (length(mi) > 0) {
          datos_audio$wavs[[nombre]] <- input$transcr_wav_files$datapath[mi[1]]
          n_wav_ok <- n_wav_ok + 1L
        }
      }

      # ── Localizar o generar TextGrid ───────────────────────────────
      tg_path <- NULL
      if (!is.null(tg_cache[[nombre]]) && file.exists(tg_cache[[nombre]])) {
        tg_path <- tg_cache[[nombre]]
      } else if (nchar(carpeta_dest) > 0 && dir.exists(carpeta_dest)) {
        ruta_cand <- file.path(carpeta_dest, paste0(nombre, ".TextGrid"))
        if (file.exists(ruta_cand)) tg_path <- ruta_cand
      }

      # Si no existe en ningún sitio: generarlo automáticamente
      if (is.null(tg_path)) {
        d_sel <- d[d$archivo == nombre, ]
        tg_tmp <- tryCatch({
          tmp <- tempfile(fileext = ".TextGrid")
          writeLines(gen_tg_lines(d_sel), tmp, useBytes = FALSE)
          tmp
        }, error = function(e) NULL)
        if (!is.null(tg_tmp) && file.exists(tg_tmp)) {
          tg_cache[[nombre]] <- tg_tmp
          rv_tg_cache(tg_cache)
          tg_path <- tg_tmp
        }
      }

      if (!is.null(tg_path)) {
        datos_textgrid$tgs[[nombre]] <- tg_path
        n_tg_ok <- n_tg_ok + 1L
      }
    }

    # Pre-cargar pm_archivos para que Parselmouth los encuentre sin subir archivos
    for (i in seq_len(nrow(pares))) {
      nombre   <- pares$archivo[i]
      ruta_wav <- pares$ruta_wav[i]
      if (!is.na(ruta_wav) && file.exists(ruta_wav))
        pm_archivos$wavs[[nombre]] <- ruta_wav
      tg_reg <- datos_textgrid$tgs[[nombre]]
      if (!is.null(tg_reg) && file.exists(tg_reg))
        pm_archivos$tgs[[nombre]] <- tg_reg
    }
    updateRadioButtons(session, "crear_modo", selected = "parselmouth")

    showNotification(
      tagList(
        icon("check-circle"), " ",
        tags$b(paste0(n_wav_ok, " audio(s) y ", n_tg_ok, " TextGrid(s) listos.")),
        tags$br(),
        tags$small("Configura los par\u00e1metros de pitch y pulsa \u2018Ejecutar Parselmouth\u2019.")
      ),
      type = "message", duration = 8)

    updateNavbarPage(session, "navbar_principal", selected = "tab_crear")
  })

  # ── Módulo Léxico ────────────────────────────────────────────────────────

  # Helper: obtener tokens limpios desde datos$words con filtros
  get_lexico_tokens <- function(df, archivo = "__todos__", hablante = "__todos__",
                                 forma = "etiqueta", excluir_sw = FALSE) {
    if (is.null(df) || nrow(df) == 0) return(character(0))
    if (archivo  != "__todos__" && "filename" %in% colnames(df))
      df <- df[!is.na(df$filename) & df$filename == archivo, ]
    if (hablante != "__todos__" && "hablante" %in% colnames(df))
      df <- df[!is.na(df$hablante) & df$hablante == hablante, ]
    col <- if (forma == "lemma" && "lemma" %in% colnames(df)) "lemma" else "etiqueta"
    if (!col %in% colnames(df) && "etiqueta" %in% colnames(df)) col <- "etiqueta"
    if (!col %in% colnames(df)) return(character(0))
    toks <- tolower(as.character(df[[col]]))
    toks <- toks[!is.na(toks) & nchar(toks) > 0]
    toks <- toks[!grepl("^[[:punct:][:space:]]+$", toks)]
    # Descartar tokens no léxicos de ASR/alineación (WhisperX/MFA): <unk>, <eps>,
    # <s>, </s>, <sil>... y los marcadores de silencio sin corchetes (sp, spn, sil).
    # Además de no ser palabras, los corchetes angulares rompen gridtext en la nube.
    toks <- toks[!grepl("^<.*>$", toks)]
    toks <- toks[!toks %in% c("sp", "spn", "sil")]
    if (excluir_sw && requireNamespace("stopwords", quietly = TRUE))
      toks <- toks[!toks %in% stopwords::stopwords("es")]
    toks
  }

  # Helper: Type-Token Ratio
  calc_ttr <- function(toks) {
    if (length(toks) == 0) return(NA_real_)
    length(unique(toks)) / length(toks)
  }

  # Helper: Log-Likelihood G2 (Dunning 1993) + Log Ratio (Hardie)
  calc_keyness_df <- function(toks_a, toks_b) {
    if (length(toks_a) == 0 || length(toks_b) == 0) return(NULL)
    total_a <- length(toks_a); total_b <- length(toks_b)
    fa <- table(toks_a); fb <- table(toks_b)
    all_w <- union(names(fa), names(fb))
    res <- lapply(all_w, function(w) {
      o11 <- if (!is.na(fa[w])) as.integer(fa[w]) else 0L
      o21 <- if (!is.na(fb[w])) as.integer(fb[w]) else 0L
      o12 <- total_a - o11; o22 <- total_b - o21
      N   <- total_a + total_b
      E11 <- (o11+o12)*(o11+o21)/N; E12 <- (o11+o12)*(o12+o22)/N
      E21 <- (o21+o22)*(o11+o21)/N; E22 <- (o21+o22)*(o12+o22)/N
      Ov  <- c(o11, o12, o21, o22); Ev <- c(E11, E12, E21, E22)
      G2  <- 2 * sum(ifelse(Ov > 0 & Ev > 0, Ov * log(Ov/Ev), 0))
      signo <- if ((o11/total_a) >= (o21/total_b)) 1 else -1
      lr  <- log2(((o11 + 0.5)/total_a) / ((o21 + 0.5)/total_b))
      pv  <- pchisq(G2, df = 1, lower.tail = FALSE)
      data.frame(palabra = w, freq_A = o11, freq_B = o21,
                 por_mil_A = round(o11/total_a*1000, 2),
                 por_mil_B = round(o21/total_b*1000, 2),
                 LL = round(G2 * signo, 3),
                 log_ratio = round(lr, 3),
                 p_valor   = signif(pv, 3),
                 stringsAsFactors = FALSE)
