  # ── Colocaciones (MI, t-score, LL) ──────────────────────────────────────
  rv_coloc <- reactiveVal(NULL)

  # Función: extraer todos los pares (nodo, colocado) dentro de ventana ±W
  calc_coloc <- function(toks, ventana = 2L, min_freq = 2L, excluir_sw = FALSE) {
    if (length(toks) < 2) return(NULL)
    N <- length(toks)

    # Frecuencias individuales (unigramas)
    freq1 <- table(toks)

    # Recoger todos los pares dentro de la ventana
    pares <- list()
    for (i in seq_len(N)) {
      nodo <- toks[i]
      rng  <- setdiff(seq(max(1L, i - ventana), min(N, i + ventana)), i)
      for (j in rng) {
        col <- toks[j]
        key <- paste(nodo, col, sep = "\t")
        pares[[key]] <- (pares[[key]] %||% 0L) + 1L
      }
    }
    if (length(pares) == 0) return(NULL)

    total_pares <- sum(unlist(pares))   # N de co-ocurrencias observadas

    res <- lapply(names(pares), function(key) {
      parts <- strsplit(key, "\t", fixed = TRUE)[[1]]
      nodo <- parts[1]; col <- parts[2]
      O11  <- pares[[key]]
      if (O11 < min_freq) return(NULL)
      if (nodo == col) return(NULL)   # excluir auto-colocaciones

      # Frecuencias marginales (ajustadas a espacio de co-ocurrencias)
      fA   <- as.integer(freq1[nodo]); if (is.na(fA)) fA <- 0L
      fB   <- as.integer(freq1[col]);  if (is.na(fB)) fB <- 0L
      E11  <- (fA * fB) / N   # esperada bajo independencia

      # MI = log2(O / E)
      MI <- if (E11 > 0) log2(O11 / E11) else NA_real_

      # t-score = (O - E) / sqrt(O)
      tscore <- if (O11 > 0) (O11 - E11) / sqrt(O11) else NA_real_

      # Log-Likelihood G2 (2x2: nodo+col, nodo+!col, !nodo+col, !nodo+!col)
      O12 <- fA - O11; O21 <- fB - O11
      O22 <- N - O11 - O12 - O21
      Ov  <- c(O11, max(0,O12), max(0,O21), max(0,O22))
      R1  <- Ov[1]+Ov[2]; R2 <- Ov[3]+Ov[4]
      C1  <- Ov[1]+Ov[3]; C2 <- Ov[2]+Ov[4]
      NN  <- sum(Ov)
      Ev  <- c(R1*C1/NN, R1*C2/NN, R2*C1/NN, R2*C2/NN)
      G2  <- 2 * sum(ifelse(Ov > 0 & Ev > 0, Ov * log(Ov/Ev), 0))

      data.frame(nodo = nodo, colocado = col, freq = O11,
                 MI = round(MI, 3), t_score = round(tscore, 3),
                 LL = round(G2, 3), stringsAsFactors = FALSE)
    })

    res_df <- do.call(rbind, Filter(Negate(is.null), res))
    if (is.null(res_df) || nrow(res_df) == 0) return(NULL)
    res_df
  }

  # Operador nulo-coalescente (si no está ya definido en el scope)
  `%||%` <- function(a, b) if (!is.null(a)) a else b

  observeEvent(input$lex_col_calcular, {
    req(datos$words)
    toks <- get_lexico_tokens(datos$words,
      archivo    = input$lex_col_archivo,
      hablante   = input$lex_col_hablante,
      forma      = "etiqueta",
      excluir_sw = isTRUE(input$lex_col_stopwords))
    if (length(toks) < 3) {
      showNotification("Corpus demasiado pequeño para calcular colocaciones.", type = "warning")
      return()
    }
    ventana  <- max(1L, as.integer(input$lex_col_ventana))
    min_freq <- max(1L, as.integer(input$lex_col_min_freq))
    top      <- max(10L, as.integer(input$lex_col_top))
    metrica  <- input$lex_col_metrica

    withProgress(message = "Calculando colocaciones...", value = 0.4, {
      resultado <- tryCatch(
        calc_coloc(toks, ventana = ventana, min_freq = min_freq),
        error = function(e) { showNotification(paste("Error:", e$message), type = "error"); NULL }
      )
    })
    if (!is.null(resultado)) {
      resultado <- resultado[order(resultado[[metrica]], decreasing = TRUE, na.last = TRUE), ]
      rv_coloc(head(resultado, top))
    } else {
      showNotification("No se encontraron colocaciones con esos filtros.", type = "warning")
    }
  })

