  # Vista filtrada de ips_resumen para este módulo
  ips_varcustom <- reactive({
    req(datos$calculado, datos$ips_resumen)
    ips <- datos$ips_resumen
    if ("hablante" %in% colnames(ips))
      ips <- ips[tolower(trimws(ips$hablante)) != "anonimizar", ]
    if (!is.null(input$vc_archivo) && input$vc_archivo != "__todos__")
      ips <- ips[ips$filename == input$vc_archivo, ]
    if (!is.null(input$vc_hablante) && input$vc_hablante != "__todos__")
      ips <- ips[ips$hablante == input$vc_hablante, ]
    if (nrow(ips) == 0) return(ips)
    if ("inicio" %in% colnames(ips))
      ips <- ips[order(ips$filename, ips$inicio), ]
    ips$fila_original <- match(ips$id_ge, datos$ips_resumen$id_ge)
    if (all(is.na(ips$fila_original))) ips$fila_original <- seq_len(nrow(ips))
    ips
  })

  observeEvent(input$vc_archivo,  { varlab$pos_actual <- 1L }, ignoreInit = TRUE)
  observeEvent(input$vc_hablante, { varlab$pos_actual <- 1L }, ignoreInit = TRUE)

  # Inicializar tabla de anotaciones cuando llegan datos procesados
  observeEvent(datos$calculado, {
    req(datos$calculado, datos$ips_resumen, nrow(datos$ips_resumen) > 0)
    n <- nrow(datos$ips_resumen)
    id_ge_col <- if ("id_ge" %in% colnames(datos$ips_resumen))
      datos$ips_resumen$id_ge else paste0("GE_", seq_len(n))
    df_base <- data.frame(
      fila_ip  = seq_len(n),
      id_ge    = id_ge_col,
      filename = datos$ips_resumen$filename,
      hablante = if ("hablante" %in% colnames(datos$ips_resumen))
        datos$ips_resumen$hablante else NA_character_,
      stringsAsFactors = FALSE
    )
    for (v in rv_vardefs()) {
      col <- paste0("vc_", v$id)
      if (!col %in% colnames(df_base)) df_base[[col]] <- NA_character_
    }
    varlab$anotaciones <- df_base
    varlab$pos_actual  <- 1L
  })

  # Helper: persiste los valores actuales de los campos en varlab$anotaciones
  save_vc_current <- function() {
    if (is.null(varlab$anotaciones)) return()
    ips <- tryCatch(isolate(ips_varcustom()), error = function(e) NULL)
    if (is.null(ips) || nrow(ips) == 0) return()
    pos <- varlab$pos_actual
    if (pos < 1L || pos > nrow(ips)) return()
    fila_orig <- ips$fila_original[pos]
    for (v in rv_vardefs()) {
      col <- paste0("vc_", v$id)
      val <- isolate(input[[paste0("vc_val_", v$id)]])
      if (!is.null(val) && col %in% colnames(varlab$anotaciones))
        varlab$anotaciones[fila_orig, col] <- as.character(val)
    }
  }

  # Navegación
  observeEvent(input$vc_next, {
    save_vc_current()
    ips <- ips_varcustom()
    if (varlab$pos_actual < nrow(ips)) varlab$pos_actual <- varlab$pos_actual + 1L
  })
  observeEvent(input$vc_prev, {
    save_vc_current()
    if (varlab$pos_actual > 1L) varlab$pos_actual <- varlab$pos_actual - 1L
  })

