    anotaciones <- isolate(varlab$anotaciones)
    campos <- lapply(vars, function(v) {
      col        <- paste0("vc_", v$id)
      val_actual <- if (!is.null(anotaciones) && col %in% colnames(anotaciones) &&
                        !is.na(anotaciones[fila_orig, col]))
        anotaciones[fila_orig, col] else NULL
      campo <- if (v$tipo == "categorias" && length(v$categorias) > 0) {
        radioButtons(paste0("vc_val_", v$id), label = NULL,
          choices  = v$categorias,
          selected = if (!is.null(val_actual)) val_actual else character(0),
          inline   = length(v$categorias) <= 5)
      } else if (v$tipo == "numeric") {
        numericInput(paste0("vc_val_", v$id), label = NULL,
          value = if (!is.null(val_actual)) suppressWarnings(as.numeric(val_actual)) else NA,
          min = NA, step = 0.1, width = "180px")
      } else {
        textInput(paste0("vc_val_", v$id), label = NULL,
          value = if (!is.null(val_actual)) val_actual else "")
      }
      nivel_label <- switch(v$nivel,
        "GE" = "Grupo entonativo", "GF" = "Grupo fónico",
        "palabra" = "Palabra", "phone" = "Phone", v$nivel)
      div(class = "mb-3 p-3",
        style = "background:#f8faff; border-radius:8px; border-left:3px solid #2563eb;",
        div(class = "fw-bold mb-2",
          icon("tag"), " ", v$nombre,
          span(class = "badge bg-secondary ms-2", style = "font-size:0.7em;", nivel_label)),
        campo
      )
    })
    tagList(campos)
  })

  # Lista de variables en el sidebar
  output$vc_lista_variables <- renderUI({
    vars <- rv_vardefs()
    if (length(vars) == 0)
      return(div(class = "text-muted", style = "font-size:13px;",
                 "Aún no hay variables definidas."))
    lapply(vars, function(v) {
      tipo_icon <- switch(v$tipo,
        "categorias" = icon("list"),
        "numeric"    = icon("hashtag"),
        icon("font"))
      div(class = "d-flex align-items-center justify-content-between mb-1 p-1",
        style = "background:#f0f4ff; border-radius:6px;",
        div(tipo_icon,
          tags$small(class = "ms-1 fw-bold", v$nombre),
          tags$small(class = "text-muted ms-1", paste0("(", v$nivel, ")"))),
        div(
          actionButton(paste0("vc_edit_", v$id), "", icon = icon("pencil"),
            class = "btn-sm btn-outline-secondary me-1",
            style = "padding:2px 6px; font-size:11px; line-height:1.2;"),
          actionButton(paste0("vc_del_", v$id), "", icon = icon("trash"),
            class = "btn-sm btn-outline-danger",
            style = "padding:2px 6px; font-size:11px; line-height:1.2;")
        )
      )
    })
  })

  # Modal: nueva variable
  observeEvent(input$vc_nueva_var_btn, {
    rv_vc_edit_id(NULL)
    showModal(modalDialog(
      title  = tagList(icon("plus-circle"), " Nueva variable"),
      size   = "m", easyClose = TRUE,
      footer = tagList(
        modalButton("Cancelar"),
        actionButton("vc_modal_guardar", tagList(icon("save"), " Guardar"),
                     class = "btn-primary")
      ),
      textInput("vc_modal_nombre", "Nombre de la variable:",
                placeholder = "ej. Humor, Modalidad, Entonación..."),
      selectInput("vc_modal_nivel", "Nivel de análisis:",
        choices  = c("Grupo entonativo" = "GE", "Grupo fónico" = "GF",
                     "Palabra" = "palabra", "Phone" = "phone"),
        selected = "GE"),
      radioButtons("vc_modal_tipo", "Tipo de campo:",
        choices  = c("Categorías (radio)" = "categorias",
                     "Valor numérico"     = "numeric",
                     "Texto libre"             = "libre"),
        selected = "categorias"),
      textAreaInput("vc_modal_cats",
        "Categorías (una por línea — solo para tipo 'Categorías'):",
        placeholder = "sí\nno\nindeterminado", rows = 5)
    ))
  })

  # Guardar variable (nueva o editada)
  observeEvent(input$vc_modal_guardar, ignoreInit = TRUE, {
    nombre <- trimws(input$vc_modal_nombre %||% "")
    if (nchar(nombre) == 0) {
      showNotification("El nombre no puede estar vacío.", type = "warning"); return()
    }
    cats <- if (identical(input$vc_modal_tipo, "categorias")) {
      cs <- trimws(strsplit(input$vc_modal_cats %||% "", "\n")[[1]])
      cs[nchar(cs) > 0]
    } else character(0)
    if (identical(input$vc_modal_tipo, "categorias") && length(cats) == 0) {
      showNotification("Define al menos una categoría.", type = "warning"); return()
    }
    vars    <- rv_vardefs()
    edit_id <- rv_vc_edit_id()
    if (is.null(edit_id)) {
      if (length(vars) >= 10) {
        showNotification("Máximo 10 variables alcanzado.", type = "warning"); return()
      }
      nuevo_id <- paste0("v", as.character(as.integer(Sys.time())))
      nueva_var <- list(id = nuevo_id, nombre = nombre,
                        nivel = input$vc_modal_nivel,
                        tipo  = input$vc_modal_tipo,
                        categorias = cats)
      vars <- c(vars, list(nueva_var))
      if (!is.null(varlab$anotaciones))
        varlab$anotaciones[[paste0("vc_", nuevo_id)]] <- NA_character_
    } else {
      idx <- which(vapply(vars, `[[`, character(1), "id") == edit_id)
      if (length(idx) == 1) {
        vars[[idx]]$nombre     <- nombre
        vars[[idx]]$nivel      <- input$vc_modal_nivel
        vars[[idx]]$tipo       <- input$vc_modal_tipo
        vars[[idx]]$categorias <- cats
      }
    }
    rv_vardefs(vars)
    removeModal()
    showNotification(paste0("Variable ‘", nombre, "’ guardada."), type = "message")
  })

  # Observadores de guardado inmediato, editar y eliminar (registrados una sola vez por ID)
  vc_obs_ids_save <- character(0)
  vc_obs_ids_edit <- character(0)
  vc_obs_ids_del  <- character(0)

  observe({
    vars    <- rv_vardefs()
    all_ids <- vapply(vars, `[[`, character(1), "id")

    # Observer de guardado: dispara al instante cuando el usuario cambia un campo
    for (vid in setdiff(all_ids, vc_obs_ids_save)) {
      local({
        v_id <- vid
        col  <- paste0("vc_", v_id)
        observeEvent(input[[paste0("vc_val_", v_id)]], {
          req(varlab$anotaciones)
          ips <- tryCatch(isolate(ips_varcustom()), error = function(e) NULL)
          if (is.null(ips) || nrow(ips) == 0) return()
          pos       <- isolate(varlab$pos_actual)
          if (pos < 1L || pos > nrow(ips)) return()
          fila_orig <- ips$fila_original[pos]
          val       <- input[[paste0("vc_val_", v_id)]]
          if (!is.null(val) && length(val) > 0 && !is.na(fila_orig) &&
              col %in% colnames(varlab$anotaciones))
            varlab$anotaciones[fila_orig, col] <- as.character(val[1])
        }, ignoreInit = TRUE, ignoreNULL = TRUE)
      })
      vc_obs_ids_save <<- c(vc_obs_ids_save, vid)
    }

    for (vid in setdiff(all_ids, vc_obs_ids_edit)) {
      local({
        v_id <- vid
        observeEvent(input[[paste0("vc_edit_", v_id)]], {
          rv_vc_edit_id(v_id)
          v <- Filter(function(x) x$id == v_id, rv_vardefs())
          if (length(v) == 0) return()
          v <- v[[1]]
          showModal(modalDialog(
            title  = tagList(icon("pencil"), paste0(" Editar: ", v$nombre)),
            size   = "m", easyClose = TRUE,
            footer = tagList(
              modalButton("Cancelar"),
              actionButton("vc_modal_guardar", tagList(icon("save"), " Guardar"),
                           class = "btn-primary")
            ),
            textInput("vc_modal_nombre", "Nombre:", value = v$nombre),
            selectInput("vc_modal_nivel", "Nivel:",
              choices  = c("Grupo entonativo" = "GE", "Grupo fónico" = "GF",
                           "Palabra" = "palabra", "Phone" = "phone"),
              selected = v$nivel),
            radioButtons("vc_modal_tipo", "Tipo:",
              choices  = c("Categorías (radio)" = "categorias",
                           "Valor numérico"     = "numeric",
                           "Texto libre"             = "libre"),
              selected = v$tipo),
            textAreaInput("vc_modal_cats",
              "Categorías (una por línea — solo para tipo 'Categorías'):",
              value = paste(v$categorias, collapse = "\n"), rows = 5)
          ))
        }, ignoreInit = TRUE)
      })
      vc_obs_ids_edit <<- c(vc_obs_ids_edit, vid)
    }
    for (vid in setdiff(all_ids, vc_obs_ids_del)) {
      local({
        v_id <- vid
        observeEvent(input[[paste0("vc_del_", v_id)]], {
          vars_cur <- rv_vardefs()
          vars_cur <- Filter(function(x) x$id != v_id, vars_cur)
          rv_vardefs(vars_cur)
          showNotification("Variable eliminada.", type = "message")
        }, ignoreInit = TRUE)
      })
      vc_obs_ids_del <<- c(vc_obs_ids_del, vid)
    }
  })

  # Progreso de anotación
  output$vc_progreso_txt <- renderText({
    vars <- rv_vardefs()
    if (length(vars) == 0 || is.null(varlab$anotaciones))
      return("Sin variables definidas")
    n_total <- nrow(varlab$anotaciones)
    cols <- paste0("vc_", vapply(vars, `[[`, character(1), "id"))
    cols <- cols[cols %in% colnames(varlab$anotaciones)]
    if (length(cols) == 0) return(paste0("0 / ", n_total, " GEs anotados"))
    n_anot <- sum(apply(varlab$anotaciones[, cols, drop = FALSE], 1,
      function(row) any(!is.na(row) & nchar(as.character(row)) > 0)))
    paste0(n_anot, " / ", n_total, " GEs anotados")
  })

  # Audio del GE actual
  observeEvent(input$vc_play_ge, {
    ips <- ips_varcustom()
    req(nrow(ips) > 0, varlab$pos_actual <= nrow(ips))
    r        <- ips[varlab$pos_actual, ]
    t_inicio <- max(0, as.numeric(r$inicio) - 0.05)
    t_fin    <- as.numeric(r$fin) + 0.05
    wav_path <- buscar_wav(r$filename)
    if (is.null(wav_path)) {
      showNotification("No se encontró archivo de audio.", type = "warning"); return()
    }
    b64 <- generar_audio_b64(wav_path, t_inicio, t_fin)
    if (is.null(b64)) {
      showNotification("Error generando fragmento de audio.", type = "warning"); return()
    }
    output$vc_audio_player <- renderUI({
      tags$audio(src = paste0("data:audio/wav;base64,", b64),
        type = "audio/wav", controls = TRUE, autoplay = TRUE,
        style = "width:100%; margin-top:5px;")
    })
  })

  # Curva melódica del GE actual (misma lógica que etiq_curva_melodica)
  output$vc_curva_melodica <- renderPlotly({
    req(datos$phones)
    ips <- ips_varcustom()
    req(is.data.frame(ips), nrow(ips) > 0)
    pos_actual <- varlab$pos_actual
    if (is.null(pos_actual) || pos_actual < 1 || pos_actual > nrow(ips))
      return(plotly::plot_ly())
    r <- as.list(ips[pos_actual, ])

    fn_c  <- as.character(if (!is.null(r$filename))        r$filename        else "")
    spk_c <- as.character(if (!is.null(r$hablante))        r$hablante        else "")
    gf_c  <- suppressWarnings(as.integer(if (!is.null(r$grupo_fonico))      r$grupo_fonico      else NA))
    ge_c  <- suppressWarnings(as.integer(if (!is.null(r$grupo_entonativo))  r$grupo_entonativo  else NA))
    if (fn_c == "" || is.na(gf_c) || is.na(ge_c))
      return(plotly::plot_ly() %>% plotly::layout(title = "Sin datos de GE"))

    ph <- datos$phones
    cols_ok <- all(c("filename", "hablante", "grupo_fonico", "grupo_entonativo") %in% colnames(ph))
    if (!cols_ok) return(plotly::plot_ly() %>% plotly::layout(title = "Sin columnas requeridas en phones"))

    ph_ge <- ph[ph$filename == fn_c & ph$hablante == spk_c &
                as.integer(ph$grupo_fonico) == gf_c & as.integer(ph$grupo_entonativo) == ge_c, ]
    if (nrow(ph_ge) == 0 && !is.null(r$inicio) && !is.null(r$fin) && "centro" %in% colnames(ph)) {
      t0 <- as.numeric(r$inicio); t1 <- as.numeric(r$fin)
      ph_ge <- ph[ph$filename == fn_c & ph$hablante == spk_c &
                  ph$centro >= t0 - 0.01 & ph$centro <= t1 + 0.01, ]
    }
    if (nrow(ph_ge) < 1)
      return(plotly::plot_ly() %>% plotly::layout(
        annotations = list(list(text = "Este GE no tiene datos de phones.",
          x = 0.5, y = 0.5, xref = "paper", yref = "paper", showarrow = FALSE,
          font = list(size = 13, color = "grey")))))
    ph_ge <- ph_ge[order(ph_ge$inicio), ]

    lbl_x <- if ("vocal"    %in% colnames(ph_ge)) as.character(ph_ge$vocal) else
              if ("etiqueta" %in% colnames(ph_ge)) as.character(ph_ge$etiqueta) else
              as.character(seq_len(nrow(ph_ge)))
    lbl_x[is.na(lbl_x) | lbl_x == ""] <- as.character(seq_len(nrow(ph_ge)))[is.na(lbl_x) | lbl_x == ""]
    ph_ge$pos   <- seq_len(nrow(ph_ge))
    ph_ge$lbl_x <- lbl_x

    metrica  <- if (!is.null(input$vc_curva_metrica)) input$vc_curva_metrica else "f0"
    usar_rel <- isTRUE(input$vc_curva_rel100) && metrica != "todos_amh"

    palabras_raw <- r$palabras_grupo
    titulo_ge <- if (!is.null(palabras_raw) && length(palabras_raw) == 1 &&
                     !is.na(palabras_raw) && nchar(as.character(palabras_raw)) > 0)
                   as.character(palabras_raw) else paste0("GF", gf_c, "/GE", ge_c)

    empty_msg <- function(msg) plotly::plot_ly() %>% plotly::layout(
      annotations = list(list(text = msg, x = 0.5, y = 0.5, xref = "paper", yref = "paper",
                              showarrow = FALSE, font = list(size = 13, color = "grey"))))

    rel100 <- function(v) {
      v <- as.numeric(v)
      base <- v[which(!is.na(v) & v != 0)[1]]
      if (length(base) == 0 || is.na(base) || base == 0) return(rep(NA_real_, length(v)))
      round(v / base * 100, 2)
    }

    # ---- F0 ----
    if (metrica == "f0") {
      f0_col <- if ("f0_media_hz" %in% colnames(ph_ge)) "f0_media_hz" else
                if ("f0_media_st" %in% colnames(ph_ge)) "f0_media_st" else NULL
      if (is.null(f0_col)) return(empty_msg("Sin columna F0 en phones."))
      ph_plot <- ph_ge[!is.na(ph_ge[[f0_col]]) & ph_ge[[f0_col]] > 0, ]
      if (nrow(ph_plot) < 2) return(empty_msg("Sin valores F0 válidos."))
      y_raw  <- as.numeric(ph_plot[[f0_col]])
      y_vals <- if (usar_rel) rel100(y_raw) else y_raw
      y_lab  <- if (usar_rel) "F0 (base=100)" else if (f0_col == "f0_media_hz") "F0 (Hz)" else "F0 (St)"
      color_line <- "#1565C0"
      tonicas_idx <- if ("tonica_gramatical" %in% colnames(ph_plot))
        which(!is.na(ph_plot$tonica_gramatical) & ph_plot$tonica_gramatical == "sí") else integer(0)
      picos_idx <- if ("es_pico_grupo" %in% colnames(ph_plot))
        which(!is.na(ph_plot$es_pico_grupo) & ph_plot$es_pico_grupo == TRUE) else integer(0)
      p <- plotly::plot_ly() %>%
        plotly::add_trace(x = ph_plot$pos, y = y_vals, type = "scatter", mode = "lines+markers",
          line = list(color = color_line, width = 2.5), marker = list(color = color_line, size = 7),
          text = ph_plot$lbl_x, hovertemplate = "%{text}: %{y:.1f}<extra></extra>", name = y_lab)
      if (length(tonicas_idx) > 0)
        p <- p %>% plotly::add_trace(x = ph_plot$pos[tonicas_idx], y = y_vals[tonicas_idx],
          type = "scatter", mode = "markers",
          marker = list(symbol = "triangle-up", color = "gold", size = 12,
                        line = list(color = "black", width = 1.5)),
          text = ph_plot$lbl_x[tonicas_idx], hovertemplate = "%{text}<extra>Tónica</extra>",
          name = "Tónica")
      if (length(picos_idx) > 0)
        p <- p %>% plotly::add_trace(x = ph_plot$pos[picos_idx], y = y_vals[picos_idx],
          type = "scatter", mode = "markers",
          marker = list(symbol = "circle-open", color = "darkred", size = 12,
                        line = list(color = "darkred", width = 2)),
          text = ph_plot$lbl_x[picos_idx], hovertemplate = "%{text}<extra>Pico</extra>",
          name = "Pico")
      if (usar_rel)
        p <- p %>% plotly::add_segments(
          x = min(ph_plot$pos) - 0.3, xend = max(ph_plot$pos) + 0.3, y = 100, yend = 100,
          line = list(color = "grey", width = 1, dash = "dot"),
          showlegend = FALSE, hoverinfo = "skip")

    # ---- Intensidad ----
    } else if (metrica == "intensidad") {
      int_col <- if ("int_media" %in% colnames(ph_ge)) "int_media" else NULL
      if (is.null(int_col)) return(empty_msg("Sin columna de intensidad (int_media) en phones."))
      ph_plot <- ph_ge[!is.na(ph_ge[[int_col]]) & ph_ge[[int_col]] > 0, ]
      if (nrow(ph_plot) < 2) return(empty_msg("Sin valores de intensidad válidos."))
      y_raw  <- as.numeric(ph_plot[[int_col]])
      y_vals <- if (usar_rel) rel100(y_raw) else y_raw
      y_lab  <- if (usar_rel) "Intensidad (base=100)" else "Intensidad (dB)"
      color_line <- "#2E7D32"
      p <- plotly::plot_ly() %>%
        plotly::add_trace(x = ph_plot$pos, y = y_vals, type = "scatter", mode = "lines+markers",
          line = list(color = color_line, width = 2.5), marker = list(color = color_line, size = 7),
          text = ph_plot$lbl_x, hovertemplate = "%{text}: %{y:.1f}<extra></extra>", name = y_lab)
      if (usar_rel)
        p <- p %>% plotly::add_segments(
          x = min(ph_plot$pos) - 0.3, xend = max(ph_plot$pos) + 0.3, y = 100, yend = 100,
          line = list(color = "grey", width = 1, dash = "dot"),
          showlegend = FALSE, hoverinfo = "skip")

    # ---- Transición ----
    } else if (metrica == "transicion") {
      if ("tiempo_transicion_anterior" %in% colnames(ph_ge) &&
          any(!is.na(ph_ge$tiempo_transicion_anterior))) {
        trans_col  <- "tiempo_transicion_anterior"; y_lab_base <- "Transición anterior"
      } else if ("tiempo_transicion_posterior" %in% colnames(ph_ge) &&
                 any(!is.na(ph_ge$tiempo_transicion_posterior))) {
        trans_col  <- "tiempo_transicion_posterior"; y_lab_base <- "Transición posterior"
      } else if ("centro" %in% colnames(ph_ge) && nrow(ph_ge) >= 2) {
        ph_ge$tiempo_transicion_calculada <- c(NA, diff(as.numeric(ph_ge$centro)))
        trans_col  <- "tiempo_transicion_calculada"; y_lab_base <- "Intervalo entre centros"
      } else {
        return(empty_msg("Sin datos de transición entre vocales."))
      }
      ph_plot <- ph_ge[!is.na(ph_ge[[trans_col]]), ]
      if (nrow(ph_plot) < 2) return(empty_msg("Insuficientes datos de transición."))
      y_raw  <- as.numeric(ph_plot[[trans_col]]) * 1000
      y_vals <- if (usar_rel) rel100(y_raw) else y_raw
      y_lab  <- if (usar_rel) paste0(y_lab_base, " (base=100)") else paste0(y_lab_base, " (ms)")
      color_line <- "#6A1B9A"
      p <- plotly::plot_ly() %>%
        plotly::add_trace(x = ph_plot$pos, y = y_vals, type = "bar",
          marker = list(color = color_line, opacity = 0.75),
          text = ph_plot$lbl_x, hovertemplate = "%{text}: %{y:.1f}<extra></extra>", name = y_lab)
      if (usar_rel)
        p <- p %>% plotly::add_segments(
          x = min(ph_plot$pos) - 0.3, xend = max(ph_plot$pos) + 0.3, y = 100, yend = 100,
          line = list(color = "grey", width = 1, dash = "dot"),
          showlegend = FALSE, hoverinfo = "skip")

    # ---- Todos (AMH): F0 + Intensidad + Transición relativizados ----
    } else {
      f0_col  <- if ("f0_media_hz" %in% colnames(ph_ge)) "f0_media_hz" else
                 if ("f0_media_st" %in% colnames(ph_ge)) "f0_media_st" else NULL
      f0_rel  <- if (!is.null(f0_col)) rel100(ph_ge[[f0_col]]) else rep(NA_real_, nrow(ph_ge))
      f0_lab  <- if (!is.null(f0_col) && f0_col == "f0_media_hz") "F0 Hz" else "F0 St"
      int_rel <- if ("int_media" %in% colnames(ph_ge)) rel100(ph_ge$int_media) else rep(NA_real_, nrow(ph_ge))
      trans_raw <- if ("tiempo_transicion_anterior" %in% colnames(ph_ge) &&
                       any(!is.na(ph_ge$tiempo_transicion_anterior)))
                     ph_ge$tiempo_transicion_anterior * 1000
                   else if ("tiempo_transicion_posterior" %in% colnames(ph_ge) &&
                            any(!is.na(ph_ge$tiempo_transicion_posterior))) {
                     v <- ph_ge$tiempo_transicion_posterior * 1000; v[length(v)] <- NA; v
                   } else if ("centro" %in% colnames(ph_ge) && nrow(ph_ge) >= 2)
                     c(NA, diff(as.numeric(ph_ge$centro))) * 1000
                   else rep(NA_real_, nrow(ph_ge))
      trans_raw[!is.na(trans_raw) & trans_raw <= 0] <- NA
      trans_rel <- rel100(trans_raw)
      trans_rel[!is.na(trans_rel) & trans_rel > 400] <- NA
      if (all(is.na(f0_rel)) && all(is.na(int_rel)) && all(is.na(trans_rel)))
        return(empty_msg("Sin datos disponibles para vista AMH."))
      xs   <- ph_ge$pos; lbls <- ph_ge$lbl_x
      tonicas_idx <- if ("tonica_gramatical" %in% colnames(ph_ge))
        which(!is.na(ph_ge$tonica_gramatical) & ph_ge$tonica_gramatical == "sí") else integer(0)
      picos_idx <- if ("es_pico_grupo" %in% colnames(ph_ge))
        which(!is.na(ph_ge$es_pico_grupo) & ph_ge$es_pico_grupo == TRUE) else integer(0)
      p <- plotly::plot_ly()
      if (!all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(x = xs, y = f0_rel, type = "scatter",
          mode = "lines+markers", name = f0_lab,
          line = list(color = "#1565C0", width = 2.5), marker = list(color = "#1565C0", size = 7),
          text = lbls, hovertemplate = paste0("%{text} — ", f0_lab, ": %{y:.1f}<extra></extra>"))
      if (length(tonicas_idx) > 0 && !all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(x = xs[tonicas_idx], y = f0_rel[tonicas_idx],
          type = "scatter", mode = "markers", name = "Tónica",
          marker = list(symbol = "triangle-up", color = "gold", size = 13,
                        line = list(color = "#333", width = 1.5)),
          text = lbls[tonicas_idx], hovertemplate = "%{text}<extra>Tónica</extra>")
      if (length(picos_idx) > 0 && !all(is.na(f0_rel)))
        p <- p %>% plotly::add_trace(x = xs[picos_idx], y = f0_rel[picos_idx],
          type = "scatter", mode = "markers", name = "Pico",
          marker = list(symbol = "circle-open", color = "darkred", size = 13,
                        line = list(color = "darkred", width = 2)),
          text = lbls[picos_idx], hovertemplate = "%{text}<extra>Pico</extra>")
      if (!all(is.na(int_rel)))
        p <- p %>% plotly::add_trace(x = xs, y = int_rel, type = "scatter",
          mode = "lines+markers", name = "Intensidad",
          line = list(color = "#2E7D32", width = 2, dash = "dash"),
          marker = list(color = "#2E7D32", size = 6, symbol = "square"),
          text = lbls, hovertemplate = "%{text} — Int: %{y:.1f}<extra></extra>")
      if (!all(is.na(trans_rel)))
        p <- p %>% plotly::add_trace(x = xs, y = trans_rel, type = "bar",
          name = "Transición", yaxis = "y2",
          marker = list(color = "#6A1B9A", opacity = 0.35),
          text = lbls, hovertemplate = "%{text} — Trans: %{y:.1f}<extra></extra>")
      p <- p %>%
        plotly::add_segments(x = min(xs) - 0.3, xend = max(xs) + 0.3, y = 100, yend = 100,
          line = list(color = "grey", width = 1, dash = "dot"),
          showlegend = FALSE, hoverinfo = "skip") %>%
        plotly::add_segments(x = min(xs) - 0.3, xend = max(xs) + 0.3, y = 100, yend = 100,
          yaxis = "y2",
          line = list(color = "#6A1B9A", width = 1, dash = "dot"),
          showlegend = FALSE, hoverinfo = "skip")
      p <- p %>% plotly::layout(
        title   = list(text = titulo_ge, font = list(size = 12)),
        xaxis   = list(tickmode = "array", tickvals = xs, ticktext = lbls, title = "Vocal"),
        yaxis   = list(title = "Valor relativo (base=100)", side = "left"),
        yaxis2  = list(title = "Transición relativa", overlaying = "y", side = "right",
                       showgrid = FALSE, zeroline = FALSE),
        barmode = "overlay",
        margin  = list(t = 35, b = 50, l = 60, r = 60),
        legend  = list(orientation = "h", y = -0.38),
        hovermode = "x unified"
      ) %>% plotly::config(
        displayModeBar = TRUE,
        modeBarButtonsToRemove = list("zoom2d", "pan2d", "select2d", "lasso2d",
                                      "zoomIn2d", "zoomOut2d", "autoScale2d"),
        toImageButtonOptions = list(format = "png", filename = paste0("curva_amh_vc_", titulo_ge),
                                    width = 960, height = 440, scale = 2))
      return(p)
    }

    p %>% plotly::layout(
      title     = list(text = titulo_ge, font = list(size = 12)),
      xaxis     = list(tickmode = "array", tickvals = ph_ge$pos, ticktext = ph_ge$lbl_x,
                       title = "Vocal"),
      yaxis     = list(title = y_lab),
      margin    = list(t = 35, b = 40, l = 55, r = 15),
      legend    = list(orientation = "h", y = -0.3),
      hovermode = "x unified"
    ) %>% plotly::config(
      displayModeBar = TRUE,
      modeBarButtonsToRemove = list("zoom2d", "pan2d", "select2d", "lasso2d",
                                    "zoomIn2d", "zoomOut2d", "autoScale2d"),
      toImageButtonOptions = list(format = "png", filename = paste0("curva_vc_", metrica, "_", titulo_ge),
                                  width = 900, height = 400, scale = 2))
  })

  # Tabla de GEs cercanos con anotaciones
  output$vc_tabla_contexto <- renderUI({
    ips <- ips_varcustom()
    req(nrow(ips) > 0, varlab$pos_actual <= nrow(ips))
    pos        <- varlab$pos_actual
    current_fn <- ips$filename[pos]
    same_idx   <- which(ips$filename == current_fn)
    if ("inicio" %in% colnames(ips))
      same_idx <- same_idx[order(ips$inicio[same_idx])]
    pos_local <- which(same_idx == pos)
    if (length(pos_local) == 0) { same_idx <- pos; pos_local <- 1L }
    rango   <- same_idx[max(1L, pos_local - 5L):min(length(same_idx), pos_local + 5L)]
    sub_ips <- ips[rango, ]
    vars    <- rv_vardefs()
    filas_html <- lapply(seq_len(nrow(sub_ips)), function(i) {
      r         <- sub_ips[i, ]
      es_actual <- (rango[i] == pos)
      clase     <- if (es_actual) "fila-actual" else ""
      palabras  <- if ("palabras_grupo" %in% colnames(r)) r$palabras_grupo else ""
      amh       <- if ("amh_patron" %in% colnames(r)) r$amh_patron else ""
      t_ini     <- if ("inicio" %in% colnames(r) && !is.na(r$inicio))
        paste0(floor(r$inicio/60), ":", sprintf("%05.2f", r$inicio %% 60)) else ""
      fila_orig <- r$fila_original
      badges_html <- ""
      if (!is.null(varlab$anotaciones) && !is.null(fila_orig) && !is.na(fila_orig) &&
          fila_orig <= nrow(varlab$anotaciones)) {
        bs <- vapply(vars, function(v) {
          col <- paste0("vc_", v$id)
          val <- varlab$anotaciones[fila_orig, col]
          if (!is.null(val) && !is.na(val) && nchar(as.character(val)) > 0)
            paste0('<span class="badge bg-primary me-1" style="font-size:0.7em;">',
                   v$nombre, ": ", val, "</span>")
          else ""
        }, character(1))
        badges_html <- paste(bs[nchar(bs) > 0], collapse = "")
      }
      tags$tr(class = clase,
        tags$td(style = "padding:4px 8px;white-space:nowrap;font-size:11px;color:#999;", t_ini),
        tags$td(style = "padding:4px 8px;white-space:nowrap;",
                paste0("GF", r$grupo_fonico, "/GE", r$grupo_entonativo)),
        tags$td(style = "padding:4px 8px;", r$hablante),
        tags$td(style = "padding:4px 8px;max-width:280px;", palabras),
        tags$td(style = "padding:4px 8px;", amh),
        tags$td(style = "padding:4px 8px;", HTML(badges_html))
      )
    })
    tags$div(
      tags$small(class = "text-muted", paste0("Archivo: ", current_fn)),
      tags$table(class = "table table-sm table-bordered", style = "font-size:13px;",
        tags$thead(tags$tr(
          tags$th("Tiempo"), tags$th("GF/GE"), tags$th("Hablante"),
          tags$th("Palabras"), tags$th("AMH"), tags$th("Anotaciones")
        )),
        tags$tbody(filas_html)
      )
    )
  })

  # Autoguardado cada 10 s
  observe({
    invalidateLater(10000, session)
    req(varlab$anotaciones)
    if (is.null(varlab$backup_dir)) {
      varlab$backup_dir <- file.path(getwd(), "backup_varcustom")
      dir.create(varlab$backup_dir, recursive = TRUE, showWarnings = FALSE)
    }
    ts    <- format(Sys.time(), "%Y%m%d_%H%M%S")
    bfile <- file.path(varlab$backup_dir, paste0("varcustom_", ts, ".rds"))
    tryCatch({
      saveRDS(list(anotaciones = varlab$anotaciones, vardefs = rv_vardefs(),
                   pos_actual = varlab$pos_actual, timestamp = Sys.time()), bfile)
      varlab$ultimo_guardado <- format(Sys.time(), "%H:%M:%S")
      backups <- sort(list.files(varlab$backup_dir, full.names = TRUE), decreasing = TRUE)
      if (length(backups) > 50) file.remove(backups[51:length(backups)])
    }, error = function(e) NULL)
  })

  # Limpiar anotaciones (con confirmación)
  observeEvent(input$vc_reset_btn, {
    showModal(modalDialog(
      title = tagList(icon("exclamation-triangle"), " Confirmar reset"),
      "¿Eliminar TODAS las anotaciones de variables personalizadas? Esta acción no se puede deshacer.",
      footer = tagList(
        modalButton("Cancelar"),
        actionButton("vc_reset_confirmar", "Sí, eliminar todo", class = "btn-danger")
      )
    ))
  })

  observeEvent(input$vc_reset_confirmar, {
    req(varlab$anotaciones)
    cols <- paste0("vc_", vapply(rv_vardefs(), `[[`, character(1), "id"))
    for (col in cols[cols %in% colnames(varlab$anotaciones)])
      varlab$anotaciones[[col]] <- NA_character_
    removeModal()
    showNotification("Anotaciones eliminadas.", type = "warning")
  })

  # Exportar CSV con nombres de variable legibles
  output$vc_descargar_csv <- downloadHandler(
    filename = function()
      paste0("variables_personalizadas_", format(Sys.time(), "%Y%m%d_%H%M"), ".csv"),
    content = function(file) {
      req(varlab$anotaciones)
      df   <- varlab$anotaciones
      vars <- rv_vardefs()
      for (v in vars) {
        col_old <- paste0("vc_", v$id)
        if (col_old %in% colnames(df))
          colnames(df)[colnames(df) == col_old] <- v$nombre
      }
      write.csv(df, file, row.names = FALSE)
    }
  )

}

# ========================================
# EJECUTAR APP
# ========================================
shinyApp(ui = ui, server = server)